INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (225, 10, 4713, 'Rail Baltica', 'Kritizē JV un ministriju pretošanos atbildībai par Rail Baltica — apzināta projekta sabotāža', 'Spilgti izgaismojas Jaunā Vienotība pretošanās uzdevumiem un atbildībai, kas ir saprotama kā apzināta projekta sabotāža.', 0.9, 'Tiešs uzbrukums valdošajai JV par Rail Baltica vadības trūkumu — izmeklēšanas komisijas kontekstā', 0.9, 'https://x.com/AndrisKulbergs/status/2034184765021012358', '2026-03-18 08:26:55', '2026-04-01 20:12:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (233, 30, 4726, 'Valsts pārvalde', 'Valsts funkciju samazināšana jābūve motivēta ar principiem, ne konkrētiem iestāžu nosaukumiem — izdevumu pozīcijas pamatojums neeksistē ārpus konteksta', 'Svarīgāk par konkrētu funkciju vai iestāžu nosaukšanu ir saprast motivāciju un principus, pēc kādiem tas notiks.', 0.8, 'Filozofiska pieeja valsts samazinasanai — MMN kodola pozicija', 0.7, 'https://x.com/JazepsBasko/status/2038206061673365699', '2026-03-29 10:46:07', '2026-04-01 20:12:52', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (235, 30, 4727, 'Valsts pārvalde', 'Šorienu Latvijas ministri ir nekompetenti — «trīsdimensionāls čatdzīpītijs bez interneta pieslēguma»', 'Kas ir ministrs šodienas Latvijā? Kaut kāds trīsdimensionāls čatdžipitijs bez interneta pieslēguma.', 0.8, 'Asu kritika par valdības ministru kompetencem', 0.6, 'https://x.com/JazepsBasko/status/2037901651424546986', '2026-03-28 14:36:30', '2026-04-01 20:13:03', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (237, 30, 4725, 'Pašvaldības', 'Ātrgatās šoseja ir labāks ieguldījums nekā Rail Baltica — dod labumu no pirmā pabeigta kilometra', 'Ātrgaitas šoseja būtu izmantojama un nestu labumu no pirmā pabeigta kilometra.', 0.75, 'Konkrēts infrastruktūras projektu salīdzinājums — pret Rail Baltica', 0.6, 'https://x.com/JazepsBasko/status/2038321765164679479', '2026-03-29 18:25:53', '2026-04-01 20:13:04', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (239, 30, 4723, 'Koalīcija un partijas', 'Aicina pāreju uz nākamo politiskās apziņas līmeni — brīvība un individuāla atbildība pret valsts kontroli', 'Tas, uz ko es aicinu, ir pariesana nākamajā politiskās apzinās līmenī.', 0.8, 'MMN filozofiska pamatteze — libertraarisms vs valsts kontrole', 0.7, 'https://x.com/JazepsBasko/status/2039038479183585788', '2026-03-31 17:53:51', '2026-04-01 20:13:04', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (240, 30, 4732, 'Tieslietas', 'Iebilst pret Satversmes tiesas klusēšanu par pozitīvu likumdevēju — tas ved valsti uz morālu un finansiālu bankrotu', 'Tāda pieeja jebkuru valsti ved uz morālu un finansiālu bankrotu.', 0.8, 'Pretstaavis tiesas aktivismam — MMN pozīcija par politiskās parvaldiibas robežām', 0.7, 'https://x.com/JazepsBasko/status/2033940124984074703', '2026-03-17 16:14:49', '2026-04-01 20:13:04', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (310, 30, 5475, 'Vēlēšanas', 'MMN reitings pieaudzis par 2,1pp, JV nokrities par 2,4pp — MMN aug, JV krīt', 'Kopš iepriekšējā mērījuma mūsu reitings ir pieaudzis par 2,1 procentpunktu, kamēr JV tas nokrities par 2,4 procentpunktiem', 0.95, 'Konkrēti SKDS aptauju dati par reitingu izmaiņām', 0.9, 'https://x.com/JazepsBasko/status/2039805487206543393', '2026-04-02 00:00:00', '2026-04-03 10:30:43', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (419, 30, 6244, 'Sociālā politika', 'Latvija ir nabadzīgāka nekā jebkad — sabiedrības labklājību mēra ar brīvprātīgo aktivitāšu iespējamību, ne ērtībām', 'MĒS ESAM TIK NABAGI, KĀ VĒL NEKAD IEPRIEKŠ', 0.85, 'MMN biedra spēcīgs sociālais naratīvs', 0.75, 'https://x.com/JazepsBasko/status/2040313656437625264', '2026-04-04 00:00:00', '2026-04-04 11:39:18', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (1601, 57, 7740, 'Sabiedriskie mediji', 'Primārā avota (Stoltenberga grāmatas) analīzes nosaukšana par dezinformāciju apdraud Latvijas dezinformācijas cīņas leģitimitāti', 'Nosaukt autentiska primārā avota analīzi par dezinformāciju nozīmē likt uz spēles visu, ko Latvija ir uzbūvējusi dezinformācijas cīņā', 0.8, 'RT Pietiek — sistēmisks arguments par dezinformācijas jēdziena inflāciju', 0.8, 'https://x.com/Lato_Lapsa/status/2041120804037886048', '2026-04-06 15:40:13', '2026-04-06 16:03:35', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (1602, 57, 7739, 'Koalīcija un partijas', 'JV virzītā iepirkumu reforma palielina korupcijas risku', NULL, 0.7, 'RT Pietiek par iepirkumu reformu — sistemātiska JV kritikas turpināšana', 0.7, 'https://x.com/Lato_Lapsa/status/2041120818961224046', '2026-04-06 15:40:13', '2026-04-06 16:03:46', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (1603, 57, 7669, 'Valsts pārvalde', 'Kritizē ministri par nekompetenci un aroganci — pieprasa skaidrojumu par solidarizēšanos ar uzbrukumu upuriem', 'Glupais un arogantais ministres izstrādājums varētu paskaidrot - kā izpaužas solidarizēšanās ar uzbrukumu upuriem', 0.7, 'Tieša, nesaudzīga amatpersonas kritika', 0.7, 'https://x.com/Lato_Lapsa/status/2041010360019267757', '2026-04-06 11:03:15', '2026-04-06 16:03:46', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (1604, 57, 7668, 'Tieslietas', 'Komunistu kolaborantiem un viņu ģimenēm jāliedz pieeja nacionālā mantojuma pasākumiem — Taurupes piemērs', 'Komunistu kolaboranti un to mājsaimnieces nesaprot - kāpēc viņu sugai Taurupes pasākumā ieeja bija liegta', 0.7, 'Asa pozīcija par vēsturisko taisnīgumu — kolaborantu izslēgšana no nacionālajiem pasākumiem', 0.7, 'https://x.com/Lato_Lapsa/status/2041014262571667787', '2026-04-06 11:03:15', '2026-04-06 16:03:46', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (1605, 57, 7673, 'Imigrācija', 'Pret pilsonības piešķiršanu par talantu vai slavu — bīstams precedents tirgoties ar pilsonību', 'Šī pāri rindai piešķiršana rada bīstamu precedentu. Ja mēs sākam tirgoties vai dāļāt pilsonību par talantu, slavu vai pareizu politisko pozīciju', 0.7, 'RT ar apstiprinošu kontekstu — principiāla pozīcija par pilsonības vērtību', 0.7, 'https://x.com/Lato_Lapsa/status/2040886220985688354', '2026-04-05 20:16:07', '2026-04-06 16:03:46', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (6831, 57, 13189, 'Tieslietas', 'Skeptisks, ka Ģenerālprokuratūra rīkosies pret prokurori Santu Bergu — ''vārna knābs vārnai acī''', 'Jau ilgāk nekā mēnesi Ģenerālprokuratūrā tiek lemts, ko iesākt ar bēdīgi slaveno Armīna Meistera un mentu zaņķa prokurori Santu Bergu. Domājat - šis būs tas gadījums, kad vārna knābs vārnai acī?', 0.75, 'Lapsa retoriski jautā vai ĢP rīkosies pret savu prokurori, implikācija ir, ka ĢP aizsargā savējos. Skaidra pozīcija par tieslietu sistēmas problēmām.', 0.5, 'https://x.com/Lato_Lapsa/status/2041897362495312148', '2026-04-08 00:00:00', '2026-04-09 16:30:55', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (6840, 30, 4731, 'Koalīcija un partijas', 'Apgalvo, ka MMN atgriezīs Latvijā īstu politiku, kritizējot esošos politiķus kā birokrātiskus ierēdņus', '@partijaMMN atgriezīs Latvijā politiku. Pēdējos gados ar politiku saprot tādu kā vairāku saimniecības daļas vadītāju sanāksmi', 0.85, 'Baško tiešā runā TV raidījumā pauda MMN pozīciju un kritizēja esošo politisko klasi kā tehnokrātisko ierēdniecību.', 0.7, 'https://x.com/JazepsBasko/status/2034140240122941853', '2026-03-18 05:30:00', '2026-04-09 16:31:33', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (6841, 30, 4733, 'Vēlēšanas', 'Iebilst pret pašreizējo plusiņu/svītrojumu vēlēšanu sistēmu, uzskatot to par neefektīvu un partiju iekšējās demokrātijas graujošu', 'Plusiņi un svītrojumi faktiski bremzē partiju sarakstu sistēmas galveno pozitīvo aspektu, proti, partijas spēju demokrātiski iekšienē sagatavot savu labāko komandu parlamentam', 0.85, 'Baško savā Twitter ierakstā detalizēti argumentē pret plusiņu/svītrojumu sistēmu Saeimas vēlēšanās.', 0.7, 'https://x.com/JazepsBasko/status/2031062184785272916', '2026-03-09 17:38:54', '2026-04-09 16:31:45', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (6844, 57, 6368, 'Koalīcija un partijas', 'Kritizē Bražu par Šlesera iesaistīšanu Stoltenberga skandāla apdzēšanā — pārmet politisku manipulāciju', 'Pat šo politisko mūmiju nabaga Braže sazvanījusi. Nez kas tai apsolīts - ka nevajadzēs sēdēt par robežbūves sabotēšanu?', 0.65, 'Lapsa apgalvo, ka Braže sazvanīja Šleseru (apzīmētu kā ''politisko mūmiju'') lai apklusinātu viņu par robežbūves sabotāžu, liekot domāt par politisku vienošanos.', 0.5, 'https://x.com/Lato_Lapsa/status/2040415925111804214', '2026-04-04 00:00:00', '2026-04-09 16:31:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7059, 30, 4720, 'Koalīcija un partijas', 'Ziņo par aktīvu MMN organizatorisko darbu - piecas darba grupu sapulces vienā dienā, norādot ka partija aug', 'Šodien liela diena @partijaMMN organizācijā. Vienas dienas laikā piecas darba grupu sapulces. Mēs augam.', 0.85, 'Baško tieši apraksta MMN partijas celtniecības procesu un uzsvēra, ka partija aug.', 0.7, 'https://x.com/JazepsBasko/status/2039401650025030024', '2026-04-01 00:00:00', '2026-04-09 16:51:19', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7060, 30, 4729, 'Ārpolitika', 'Atbalsta Orbāna un patriotu kustības "Budapest Proclamation" - prourbānisku ģeopolitisku dokumentu', 'A historic turning point for Europe! Appeal to the Peoples of Europe: The Patriots'' Budapest Proclamation', 0.7, 'Baško retwitoja Orbāna aicinājumu par patriotu kustību Eiropā. Šis ir nozīmīgs signāls par ģeopolitisko orientāciju, taču RT bez komentāra.', 0.7, 'https://x.com/JazepsBasko/status/2036316403351908701', '2026-03-24 05:37:18', '2026-04-09 16:51:31', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7061, 30, 4734, 'Vēlēšanas', 'Partija MMN vēlēšanās cer iegūt 51 Saeimas vietu un plāno sadarboties ar vēlēšanu sistēmas maiņas atbalstītājiem', 'Partija "Mēs mainām noteikumus" cer uz 51 vietu Saeimā, un domubiedri būs vēlēšanu sistēmas maiņas atbalstītāji', 0.8, 'Baško retwitoja LR Ziņas informāciju par MMN vēlēšanu mērķiem - 51 vieta = vairākums.', 0.8, 'https://x.com/JazepsBasko/status/2030913615553786281', '2026-03-09 07:48:33', '2026-04-09 16:51:31', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7074, 30, 13852, 'Vēlēšanas', 'Aicina kandidātus uz amatiem uzņemties atbildību jau pieteikšanās brīdī, nevis tikai pēc ievēlēšanas', 'Atbildības uzņemšanās nesākas tad, kad iegūst amatu. Tā sākas brīdī, kad jūs piesakāties uz konkursu par amatu', 0.5, 'Vispārīgs pilsoniskais aicinājums, netieši saistīts ar MMN platformu, bet bez konkrēta politiskā priekšlikuma.', 0.4, 'https://x.com/JazepsBasko/status/2042330357853524175', '2026-04-09 19:54:36', '2026-04-10 11:09:20', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7078, 57, 13910, 'Koalīcija un partijas', 'Uzskata, ka Vienotība un Rinkēvičs nesaprot situāciju ar prokuroru Neikenu', 'Tiešām kāds domāja, ka "Vienotības" vēzim un tā @edgarsrinkevics ir kaut mazākā nojēga - kas tas Neikens tāds?', 0.6, 'Sarkastiska piezīme par Vienotības un prezidenta Rinkēviča informētību par prokuratūras lietām. Nostāja par konkrētu politisku struktūru kompetenci.', 0.4, 'https://x.com/Lato_Lapsa/status/2042464409994264710', '2026-04-10 00:00:00', '2026-04-10 12:39:43', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7079, 57, 13912, 'Tieslietas', 'Neuzticas jaunajam ģenerālprokuroram — uzskata ka tas neuzlabos tiesiskumu', 'Iesaku izlasīt tiem, kuri cerēja, ka līdz gļēvā noziedznieka Stukāna vietā nāks ģenerālprokurors, kurš rūpēsies par tiesiskumu un likuma varu', 0.85, 'Skaidri noraida jaunā ģenerālprokurora spēju uzlabot tiesiskumu Latvijā. Tieša turpinājuma pozīcija viņa ilglaicīgajai prokuratūras kritikai.', 0.8, 'https://x.com/Lato_Lapsa/status/2042464209246556213', '2026-04-10 00:00:00', '2026-04-10 12:40:21', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7080, 57, 13905, 'Tieslietas', 'Prokurors Aļeksējevs nav kompetents — nespēj izskaidrot savu apsūdzību Levita-Vonsoviča lietā', 'Prokuratūras āksts un apkaunojums, kurš pats neko nezina, neko nevar izskaidrot, neko nespēj aprēķināt', 0.85, 'Tieša un personiska pozīcija pret konkrētu prokuroru un jauno ģenerālprokuroru Meisteru. Turpina Lapsas kritiku par prokuratūras kompetenci.', 0.7, 'https://x.com/Lato_Lapsa/status/2042469624470478932', '2026-04-10 00:00:00', '2026-04-10 12:40:21', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7081, 57, 13903, 'Valsts pārvalde', 'Salīdzina mūsdienu pārvaldes aizstāvjus ar tiem, kas 1949.g. 25. martā aplaudēja staļiniskajām represijām', 'Šitas ir no tiem, kuri arī 1949.gada 26.martā aplaudēja staļiniskajiem bendēm un vēstīja - valsts pārvaldīšana ir sarežģīta lieta', 0.7, 'Spēcīga retoriska pozīcija — valsts pārvaldes aizstāvji tiek salīdzināti ar komunistu kolaborantiem. Nostāja par pārvaldes attaisnojuma retoriku.', 0.5, 'https://x.com/Lato_Lapsa/status/2042485192930079162', '2026-04-10 00:00:00', '2026-04-10 12:40:21', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7318, 57, 14551, 'Aizsardzība un drošība', 'Kritizē aizsardzības ministra Sprūda iepirkumu politiku — dārgas konservbundžas, modernajam karam nederīga ekipējums un investīcijas kazarmu betonā nepasargās Latvijas karavīrus', 'Interesanti - tieši kā (ņemot vērā, ka krievi ukraiņus iznīcina akurāt tāpat) Latvijas karavīrus pasargās koruptā Sprūda un kompānijas sapirktās dārgās konservbundžas, pārējā modernajam karam nederīgā draza un investīcijas kazarmu betonā?', 0.75, 'Lapsa savā balsī kritizē Sprūda vadīto AM iepirkumu prioritātes — uzskata ka tās neatbilst mūsdienu kara realitātēm (atsauce uz Ukrainas pieredzi). Saskan ar iepriekšējām pozīcijām par AM vadības kritiku.', 0.75, 'https://x.com/Lato_Lapsa/status/2042938544985891138', '2026-04-11 00:00:00', '2026-04-11 21:24:50', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7342, 57, 14938, 'Koalīcija un partijas', 'Pieprasa atbildību no Baibas Bražes par nomelnošanu un formas tērpa ļaunprātīgu izmantošanu — apsūdz Vienotību bezatbildībā', '"Vienotības" vēža nekauņas ir nosprieduši, ka viņiem šajā valstī ir atļauts viss. Būs jāatbild, @Braze_Baiba. Gan par stulbu nomelnošanu, gan par formas tērpa izmantošanu.', 0.8, 'Tiešs pirmās personas izteikums, kurā Lapsa draud ar sekām Bražei. Skaidra pozīcija pret Vienotību un konkrēti pārmetumi.', 0.6, 'https://x.com/Lato_Lapsa/status/2043276956825715119', '2026-04-12 00:00:00', '2026-04-12 22:21:10', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7343, 57, 14875, 'Koalīcija un partijas', 'Salīdzina Vienotību ar parazītu — ķirmi, pelējuma sēni un vēzi, kas pieķeras saimniekam', 'Ķirmis grib būt kopā ar koku. Pelējuma sēne grib būt kopā ar ievārījumu. Vienotības vēzis grib būt kopā ar ungāru tautu.', 0.7, 'Metaforiska bet nepārprotama Vienotības kritika. Konteksts ar ungāru tautu norāda uz ārpolitikas dimensiju (iespējams Ungārijas/Orbāna konteksts), bet galvenais fokuss ir partijas kritika.', 0.5, 'https://x.com/Lato_Lapsa/status/2043292757419000139', '2026-04-12 00:00:00', '2026-04-12 22:21:10', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7344, 57, 14866, 'Sabiedriskie mediji', 'Pieprasa LTV Ziņām publicēt pilnu ombuda atbildi — apšauba sabiedrisko mediju gatavību pildīt savus pienākumus', 'Būs jāpalūdz ltvzinas, lai nopublicē pilnu ombuda atbildi uz manu iesniegumu. Un kā domājat - vai "sabiedriskā" medija zūzenas kaut pirkstu pakustinās, lai izdarītu tām uzdoto?', 0.8, 'Lapsa pirmajā personā pieprasa informācijas publiskošanu un retoriski apšauba LTV gatavību rīkoties. Turpina iepriekšējo kritisko līniju pret sabiedriskajiem medijiem.', 0.7, 'https://x.com/Lato_Lapsa/status/2043364114919985424', '2026-04-12 00:00:00', '2026-04-12 22:21:10', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7345, 57, 14867, 'Sabiedriskie mediji', 'Apšauba LTV Ziņu dienesta vadītājas Ivetas Elksnes godīgumu — norāda ka viņai ir ko slēpt', 'Vai Jūs šeit saskatāt "sabiedriskās" Latvijas Televīzijas Ziņu dienesta vadītājas godīgas un atklātas atbildes uz uzdotajiem jautājumiem? Un kā domājat - kas šai Ivetai Elksnei ir slēpjams?', 0.75, 'Tiešs retoriskais jautājums ar skaidru implikāciju — Elksne nav godīga un slēpj informāciju. Papildina iepriekšējo pozīciju par LTV neatkarību.', 0.6, 'https://x.com/Lato_Lapsa/status/2043363629752279407', '2026-04-12 00:00:00', '2026-04-12 22:21:10', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7347, 57, 15128, 'Transports', 'Kritizē Progresīvo vadīto Satiksmes ministriju par taksometru reformu — paredz, ka sistēma nebūs ne vienota, ne caurskatāma, ne funkcionējoša', 'Kad progresīvo sarkanās sērgas vadītā Satiksmes ministrija sola, ka tā izveidos vienotu un caurskatāmu taksometru pārvadājumu sistēmu, pilnīgi drošas ir trīs lietas. Pirmā - sistēma nebūs vienota. Otrā - sistēma nebūs caurskatāma. Un trešā - sistēma nedarbosies.', 0.75, 'Tiešs sarkastisks komentārs par konkrētu ministrijas politiku. Skaidra pozīcija pret Progresīvo vadīto reformu, bet izteikts kā sarkasms, nevis formāls politisks arguments.', 0.5, 'https://x.com/Lato_Lapsa/status/2043562465661735162', '2026-04-13 05:30:34', '2026-04-13 09:00:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7348, 57, 15132, 'Vēlēšanas', 'Netieši brīdina par vēlēšanu manipulācijas risku Latvijā — salīdzina Vienotību ar Ungārijas Fidesz un norāda uz administratīvā resursa ļaunprātīgu izmantošanu', 'Ungārijas Vienotība ar visu savu administratīvo resursu, ar saviem balsu skaitītājiem un ar savām sabiedrisko mediju prostitūtām nav spējusi nozagt vēlēšanas. Atcerieties to oktobrī.', 0.7, 'Lapsa paralēli vilk starp Ungārijas Fidesz un Latvijas Vienotību, norādot uz administratīvo resursu, mediju kontroli. Atcerieties to oktobrī — skaidra atsauce uz Latvijas vēlēšanām. Pozīcija ir netieša, bet skaidri nolasāma.', 0.8, 'https://x.com/Lato_Lapsa/status/2043411038301806773', '2026-04-12 00:00:00', '2026-04-13 09:00:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7349, 57, 15120, 'Sabiedriskie mediji', 'Kritizē sabiedrisko mediju par PM Siliņas aplamības slēpšanu — ombuda atzinums apstiprina, ka medijs slepus laboja interviju', 'Ombuda atzinums: premjerministre intervijā pasaka aplamību, bet sabiedriskais medijs teikto slepus labo un maldina sabiedrību', 0.8, 'Lapsa citē ombuda atzinumu kā pierādījumu savai ilgstošajai pozīcijai par sabiedrisko mediju neobjektivitāti. Konkrēts gadījums ar autoritatīvu avotu (ombuds). Saskan ar iepriekšējām pozīcijām (claims 7344, 7345).', 0.7, 'https://x.com/Lato_Lapsa/status/2043568028990771302', '2026-04-13 05:52:40', '2026-04-13 09:00:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7350, 57, 15127, 'Sabiedriskie mediji', 'Atbalsta sabiedrisko mediju restrukturizāciju neatkarības nodrošināšanai — kritizē pašreizējos LTV propagandonus par selektīvu ziņošanu', 'Klausoties Latvijas sabiedrisko mediju propagandonu skaļajā līksmībā, varu derēt, ka viņiem garām paslīdējuši divi zīmīgi punkti no Ungārijas vēlēšanu uzvarētāja priekšvēlēšanu solījumiem: tiks atlaists valsts televīzias preses dienests, bet pati valsts televīzija un radio tiks restrukturēti, lai nodrošinātu to neatkarību.', 0.65, 'Lapsa izmanto Ungārijas kontekstu, lai netiešā veidā paustu atbalstu sabiedrisko mediju restrukturizācijai arī Latvijā. Pozīcija ir netieša — viņš apraksta Ungārijas solījumus kā pozitīvu piemēru, bet tieši nesaka ka Latvijai jādara tāpat. Confidence zemāks nekā tiešam paziņojumam.', 0.7, 'https://x.com/Lato_Lapsa/status/2043563326295228729', '2026-04-13 05:33:59', '2026-04-13 09:00:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7351, 57, 15125, 'Korupcija un KNAB', 'Norāda uz sistēmisku korupciju Latvijas policijā — uzskata, ka simtiem korumpētu bijušo policistu joprojām strādā sistēmā', 'Kā Jūs domājat - cik vēl simti šādu rosļikovu (ja kāds aizmirsis, kungs ir izbijis policists) klusiņām sēž Latvijas ruku, grišinu un jašinu mentu zaņķī un gaida savu laiku?', 0.6, 'Retoriskais jautājums, bet pozīcija ir skaidra — Lapsa uzskata, ka Latvijas policijā ir sistēmiska korupcija. Nav konkrēts politikas priekšlikums, tāpēc confidence un salience zemāki.', 0.5, 'https://x.com/Lato_Lapsa/status/2043565376273838366', '2026-04-13 05:42:07', '2026-04-13 09:00:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7399, 57, 15736, 'Tieslietas', 'Iesniedz ģenerālprokuroram materiālus par JV braucienu uz Komo ezeru — uzskata par iespējamu likumpārkāpumu', 'Mans šīrīta iesniegums ģenerālprokuroram Meisteram par Vienotības braucienu uz Komo ezeru.', 0.8, 'Tiešs paziņojums par konkrētu darbību — iesniegums ģenerālprokuroram. Norāda uz pozīciju, ka JV brauciens varētu būt likumpārkāpums.', 0.6, 'https://x.com/Lato_Lapsa/status/2043921699855331504', '2026-04-14 05:18:02', '2026-04-14 10:20:22', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7400, 57, 15748, 'Koalīcija un partijas', 'Kritizē JV politiķu saņemtās dāvanas — raksta iesniegumus par korupciju', 'jātērē savs laiks, lai uzrakstītu dažus iesniegumus par šiem Vienotības vēža agonējošajiem politsprāgoņām un viņu saņemto dāvaniņu', 0.7, 'Pirmās personas paziņojums par konkrētu darbību — iesniegumu rakstīšana. Pozīcija: JV politiķi ir korupti.', 0.5, 'https://x.com/Lato_Lapsa/status/2043855099601076395', '2026-04-14 00:53:23', '2026-04-14 10:20:22', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7416, 30, 15723, 'Koalīcija un partijas', 'Konservatīvajiem jāapvienojas respektējot domas dažādību, nevis uzspiest viena lēmēja vērtības — tas ir MMN pieeja', 'Atstājot domas manevra un domas attīstības izlabošanās iespēju arī savā domubiedru pulciņā, konservatīviem ir vislielākās izredzes pulcināt gana lielu savējo loku', 0.7, 'MMN ģenerālsekretāra stratēģiskais izklāsts par konservatīvo apvienošanos. Norāda uz MMN pieeju — ne dogmatisms, bet brīvības telpa.', 0.5, 'https://x.com/JazepsBasko/status/2043930139226952191', '2026-04-14 05:51:34', '2026-04-14 10:27:59', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7419, 57, 16061, 'Koalīcija un partijas', 'Sarkastiski kritizē partijas (JV) ētikas standartus — turpina Itālijas semināra skandāla kontekstā', 'Palīdzēsim partijai ievērot visaugstākos ētikas standartus bez neaizrīšanās, neapvemšanās un siekalošanās.', 0.6, 'Sarkastisks oriģināls tvīts par partijas ētiku. Partija nav nosaukta tieši, bet konteksts (apkārtējie RT par JV/KNAB/Itāliju) norāda uz JV. Confidence 0.6 jo partija nav eksplicīti nosaukta.', 0.5, 'https://x.com/Lato_Lapsa/status/2044109740469276796', '2026-04-14 00:00:00', '2026-04-15 00:05:01', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7456, 57, 16155, 'Tieslietas', 'Kritizē prokuratūru par izlikšanos, ka nav saņēmusi iesniegumu par Komo ezera braucienu — apsūdz par tiesībsargājošo iestāžu pasivitāti', 'Meistera prokuratūra jau kopš vakardienas cenšas izlikties, ka nav saņēmusi iesniegumu par Komo ezera braucienu', 0.9, 'Tiešs Lapsas tvīts ar konkrētu apsūdzību pret prokuratūru', 0.8, 'https://x.com/Lato_Lapsa/status/2044314435167134020', '2026-04-15 00:00:00', '2026-04-15 10:30:37', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7479, 57, 16641, 'Tieslietas', 'Apsūdz Jaunās Vienotības un IT karteļa sadarbību kārtējā miljona izsaimniekošanā', 'Vienotības vēzis roku rokā ar IT karteli atkal ir kārtējo miljonu nozadzis un izpļekarējis', 0.8, 'Tiešs apsūdzējums par korupciju IT iepirkumos', 0.7, 'https://x.com/Lato_Lapsa/status/2044644042575602003', '2026-04-16 00:00:00', '2026-04-16 09:40:20', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (7505, 30, 16567, 'Koalīcija un partijas', 'Aicina politikas jaunienacej us nākt ar savu kļūdu labojumu - ja neuzskata situāciju par savu vainu, tad politika nējiet', 'Vai tas, kas ar Latviju ir noticis un notiek kopš 2009. gada, nav jūsu vaina? Ja atbilde ir ne, tad politika neejiet.', 0.75, 'Filozofiska pozicija par politisko atbildibu', 0.55, 'https://x.com/JazepsBasko/status/2044530063488532988', '2026-04-15 21:35:27', '2026-04-16 09:47:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10970, 30, 20573, 'Vēlēšanas', 'Uzskata, ka 30 gadu proporcionālā sistēma ar plusiņiem un mīnusiem sistemātiski pavājina partijas — nekas cits no tās nav gaidāms', 'Trīsdesmit gadus "stiprinām" partiju sistēmu un partijas kļūst arvien švakākas, jo ar plusiņiem un mīnusiem nekas cits nav gaidāms', 0.85, 'Paplašina esošo Baško pozīciju (claim 6841) ar vēsturisku perspektīvu — nav tikai procedurāla kritika, bet strukturāls arguments par 30 gadu sekām. Saistīts ar MMN zīmoga retoriku par sistēmas maiņu.', 0.7, 'https://x.com/JazepsBasko/status/2044874498919342480', '2026-04-16 20:24:07', '2026-04-17 11:01:05', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10971, 57, 20637, 'Koalīcija un partijas', 'Sarkastiski izsmej JV un sabiedroto politiķus (Celmiņš, Lāce, Moika, Čurika) — dēvē par "sarkano varzu" un jautā vai tiem jau traucas reanimācijas brigādes', 'Nez, pie visiem mikiem celmiņiem, agnesēm lācēm, inesēm moikām, lindām čurikām un pārējās sarkanās varzas jau traucas reanimācijas brigādes?', 0.7, 'Lapsas paša tvīts ar skaidru personisku viedokli — sarkastiski norāda uz politiķu grupu kā politisku pretinieku, izmantojot pejoratīvu apzīmējumu "sarkanā varza". Pozīcija ir kritika, ne tikai ziņu nodošana.', 0.5, 'https://x.com/Lato_Lapsa/status/2044826937776918905', '2026-04-16 17:15:07', '2026-04-17 11:01:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10972, 57, 20621, 'Tieslietas', 'Apsūdz policiju un prokuratūru par Vaļagina slepkavības lietas noklusēšanu — dēvē tiesībsargājošās iestādes par "mentu zaņķi"', 'Kārtējās mentu zaņķa spēlītes: kāpēc policija un prokuratūra mēģina noklusēt, ka aiz restēm aizdomās par Vaļagina slepkav[ību]', 0.75, 'RT no Lapsas paša Pietiek.com portāla — Lapsa ir redaktors, tāpēc Pietiek saturu var traktēt kā viņa pozīciju. Skaidra kritika tiesībsargājošām iestādēm, turpina esošo pozīciju par sistēmisku korupciju policijā (claim 7351).', 0.7, 'https://x.com/Lato_Lapsa/status/2045043665521856744', '2026-04-17 00:00:00', '2026-04-17 11:01:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10973, 57, 20622, 'Tieslietas', 'Uzskata ka Alvim Hermanim nekas nesanāks — pauž skepsi par tiesvedības iznākumu režisora lietā', 'Lato Lapsa: kāpēc Alvim Hermanim nekas nesanāks', 0.65, 'RT no Lapsas paša Pietiek.com portāla ar virsrakstu, kas tieši attiecina uz Lapsu kā autoru. Tvīta teksts kopā ar raksta virsrakstu skaidri pauž Lapsas skeptisku pozīciju par tiesas iznākumu Alvja Hermaņa lietā. bez pilna raksta satura konkrētais arguments nav zināms, bet skepses virziens ir skaidrs.', 0.4, 'https://x.com/Lato_Lapsa/status/2045043638955126933', '2026-04-17 00:00:00', '2026-04-17 11:01:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10974, 57, 20633, 'Koalīcija un partijas', 'Kritizē Progresīvo pārstāvja iecelšanu Saeimas Tautsaimniecības komisijas vadītāja amatā — dēvē par "idiotu"', 'Un šis progresīvo idiots tagad ielikts vadīt Saeimas Tautsaimniecības komisiju.', 0.75, 'Lapsas paša tvīts ar skaidru personisku nosodījumu Progresīvo pārstāvja iecelšanai atbildīgā Saeimas amatā. Pozīcija: neatbalsta šo iecelšanu. Asais tonis ("idiots") ir raksturīga Lapsas retorika, bet skaidri pauž noraidošu viedokli.', 0.5, 'https://x.com/Lato_Lapsa/status/2044833770184826967', '2026-04-16 17:42:16', '2026-04-17 11:01:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10975, 57, 20619, 'Imigrācija', 'Apgalvo ka cilvēki baidās no migrācijas jautājumiem, bet viņiem liek klusēt — kritizē publisko diskursa ierobežošanu par migrāciju', 'Cilvēkiem ir bail, bet mums liek turēt muti migrantu jautājumos', 0.7, 'RT no Lapsas paša Pietiek.com portāla. Raksta virsraksts skaidri pauž pozīciju: pastāv spiediens klusēt par migrantu jautājumiem, kas ir nepamatots, jo cilvēkiem ir reāls uztraukums. Pozīcija ir pret publiskās debates ierobežošanu.', 0.7, 'https://x.com/Lato_Lapsa/status/2045043791174713808', '2026-04-17 00:00:00', '2026-04-17 11:01:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (10976, 57, 20620, 'Tieslietas', 'Uzskata ka aizliegums nosaukt lietas īstajos vārdos aizsargā zagļus un prokuratūru — pret cenzūru tiesvedības kontekstā', 'Aizliegums saukt lietas īstajos vārdos ir tikai veids, kā aizsargāt zagli un prokuratūru', 0.8, 'RT no Lapsas paša Pietiek.com portāla ar skaidru tēzi virsrakstā. Pozīcija: vārda brīvības ierobežojumi tiesvedības kontekstā kalpo likumpārkāpēju aizsardzībai. Turpina esošo pozīciju par prokuratūras pasivitāti (claims 7456, 7351, 7351).', 0.7, 'https://x.com/Lato_Lapsa/status/2045043683972563358', '2026-04-17 00:00:00', '2026-04-17 11:01:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11098, 57, 21419, 'Aizsardzība un drošība', 'Apsūdz NBS ģenerāli par virsnieka goda noniecināšanu, lai politiski aizsegtu Bražes formas tērpa skandālu — pieprasa papildu jautājumus un noskaidrošanu', 'Nu tak nevarētu būt, ka ģenerālis uzspļauj virsnieka godam un glābj "Vienotības" stulbenes ādu, vai ne? Bet… kā domājat - vai nevajadzētu vēl ko pajautāt un noprecizēt?', 0.75, 'Sarkastisks, bet skaidrs apgalvojums — Lapsa apsūdz NBS augstāko vadību (ģenerāli) par politisku iejaukšanos un virsnieka ētikas pārkāpšanu, lai aizstāvētu Vienotības politiķi (Bražu). Tas ir atsevišķa pozīcija no eksistējošās Bražes kritikas — šī attiecas uz armijas vadības līdzdalību, nevis uz pašu Bražu. Confidence 0.75 jo formulējums sarkastisks/jautājuma formā, nevis tiešs apgalvojums.', 0.75, 'https://x.com/Lato_Lapsa/status/2045361008948990426', '2026-04-18 00:00:00', '2026-04-18 11:11:29', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11111, 30, 21392, 'Vēlēšanas', 'Vēlēšanu sistēmas maiņa nesīs pozitīvas pārmaiņas — pretstatā valsts radio vēstījumam, kas, pēc Baško domām, raksturo to negatīvi', 'Pretēji tam, ko stāsta valsts radio - vēlēšanu sistēmas maiņa nesīs pozitīvas pārmaiņas', 0.6, 'Tvīts ir partijas MMN konta retvīts ar tiešu Baško citējumu (norāde ''Jāzeps Baško par vēlēšanu sistēmas maiņu''); pozīcija ir pirmpersonas, lai gan citējums ir nogriezts. Pozīcija saskan ar viņa jau eksistējošajām pozīcijām par 30 gadu proporcionālās sistēmas reformu, bet papildina jaunu elementu — kritiku par sabiedrisko mediju (LSM/LR) vēstījumu šajā tēmā. Pazemināta confidence dēļ truncated content.', 0.7, 'https://x.com/JazepsBasko/status/2045222773967007905', '2026-04-17 19:28:02', '2026-04-18 11:13:07', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11127, 15, 21909, 'ES politika', 'Atbalsta Albānijas ES integrācijas ceļu un novērtē Albānijas ieguldījumu Baltijas jūras reģiona drošībā caur dalību NATO daudznacionālajā kaujas grupā', 'Latvia values Albania''s contribution to security in the Baltic Sea region by participation in NATO MNB, while 🇱🇻 contributes to KFOR. We support Albania''s EU integration path.', 0.85, 'Tiešs pirmās personas paziņojums (We support / Latvia values). Divas saistītas pozīcijas: (1) atbalsts Albānijas pievienošanās procesam ES, (2) Latvijas KFOR ieguldījuma apstiprinājums kā savstarpēja drošības partnerība. Klasiska ES paplašināšanās pozīcija.', 0.6, 'https://x.com/Braze_Baiba/status/2045764638243983493', '2026-04-19 00:00:00', '2026-04-19 13:50:59', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11129, 57, 21936, 'Aizsardzība un drošība', 'Sarkastiski liek ģenerālmajoram nožēlot ''pretimnākšanu'' Bražes skandālā un pārdomāt Latvijas armijas virsnieka godu', 'Vai Jums nešķiet, ka nabaga ģenerālmajoram nāksies sākt nožēlot savu "pretimnākšanu"? Un varbūt šo to pārdomāt par tēmu "Latvijas armijas virsnieka gods"?', 0.7, 'Turpinājums 2026-04-18 kritikai par NBS ģenerāli, kurš politiski aizsegja Bražes formas tērpa skandālu. Šis ir sarkastisks papildinājums ar jaunu akcentu uz virsnieka goda jautājumu — publiska morālas nolādēšanas pozīcija, ne tikai atkārtojums.', 0.6, 'https://x.com/Lato_Lapsa/status/2045737086511165912', '2026-04-19 00:00:00', '2026-04-19 13:51:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11130, 57, 21938, 'Sabiedriskie mediji', 'Apsūdz sabiedriskā medija darbiniekus neizglītotībā un latviešu valodas nezināšanā — dēvē par ''parazītiem''', 'šie jau atkal ir neizglītotie parazīti no "sabiedriskā" medija, kuri pat savu dzimto valodu nejēdz', 0.75, 'Lapsa tieši kritizē sabiedriskā medija profesionālo līmeni un valodas kompetenci, izmantojot ''parazītu'' metaforu. Tā ir viņa regulāra pozīcija par sabiedriskā medija kvalitāti un uzticamību.', 0.6, 'https://x.com/Lato_Lapsa/status/2045716391920124324', '2026-04-19 00:00:00', '2026-04-19 13:51:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11131, 57, 21934, 'Izglītība', 'Apsūdz Latvijas skolas (~600 skolas) par slinkumu vai bailēm izplatīt informāciju par grāmatu ''Pret likteni stāvēdami'' — norāda uz skolotāju bailēm no ''cekas'' rājiena', 'Nu, labi, biedrenes učenes, kam vai nu slinkums, vai vienkārši bailes no šīs nesaprotamās strēlnieku tēmas - ka tik nedabū rājienu no cekas… Iztiksim bez Jūsu starpniecības.', 0.7, 'Lapsa personīgi vadīja kampaņu, lai piegādātu grāmatas skolām, un publiski apsūdz skolu administrāciju par ignorēšanu. Šī ir pozīcija par izglītības sistēmas attieksmi pret latviešu strēlnieku vēstures tēmu un skolotāju politisko bailīgumu — ne tikai kampaņas paziņojums.', 0.5, 'https://x.com/Lato_Lapsa/status/2045749371388543453', '2026-04-19 00:00:00', '2026-04-19 13:51:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11139, 57, 22174, 'Koalīcija un partijas', 'Apsūdz Vienotības ministru Hosamu Abu Meri par nodokļu maksātāju naudas izmantošanu privātam braucienam uz Kipru — dēvē par likumīgu zagšanu', 'Un tātad - treknais "Vienotības" Hosams Lindu Meri par nodokļu maksātāju naudu aizlidinājās uz Kipru un atpakaļ, divas dienas papildus tur jauki atpūtās, bet tas, ko viņš tur īsti (ne)darīja, esot ierobežotas pieejamības informācija. Tā arī notiek likumīgā zagšana.', 0.85, 'Tieša publiska apsūdzība konkrētam JV ministram par nodokļu maksātāju naudas ļaunprātīgu izmantošanu. Saskan ar Lapsas esošo tēmu par JV/Vienotības korupciju (Komo ezera brauciens, Itālijas seminārs), bet ir jauna specifiska apsūdzība pret citu ministru.', 0.7, 'https://x.com/Lato_Lapsa/status/2045819639851061393', '2026-04-19 00:00:00', '2026-04-19 21:46:48', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11141, 15, 22127, 'Ārpolitika', 'Apstiprina, ka Latvija ir gatava piedalīties starptautiskajā misijā Hormuza jūras šaurumā; novērtē Türkiye kā tuvu NATO sabiedroto un tās ieguldījumu Baltijas drošībā jūrā un gaisā', 'Türkiye is our close ally @NATO. We value Türkiye''s contribution to the Baltic security at sea and in the air. And Latvia is ready to contribute to the international mission for the Strait of Hormuz.', 0.85, 'Tikšanās ar Türkiye ārlietu ministru Hakanu Fidanu ADF2026 ietvaros. Divu daļu pozīcija: (1) Türkiye kā NATO sabiedrotā novērtēšana Baltijas drošības kontekstā un (2) Latvijas apņemšanās pievienoties Hormuza šauruma starptautiskajai misijai. Pozīcija 11126 jau fiksē atvērta Hormuza šauruma atbalstu, bet šis izteikums ir konkrētāks — Latvijas gatavība militāri piedalīties.', 0.75, 'https://x.com/Braze_Baiba/status/2045884376374734853', '2026-04-19 00:00:00', '2026-04-19 21:47:30', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11142, 15, 22129, 'Ukraina un Krievija', 'Paziņo, ka Latvija neizsniegs pārlidojuma atļaujas uz 9. maija kara propagandas pasākumu Maskavā, kamēr Krievijas Federācija veic agresiju Ukrainā; norāda, ka Eiropā 2. Pasaules kara upurus piemin 8. maijā', 'Latvijas nostāja ir skaidra: kamēr KF veic agresiju Ukrainā, neatvieglosim ceļu uz kara propagandas pasākumiem tur. Tāpēc uz 9.maija kara propagandas šovu Maskavā, tāpat kā iepriekš, pārlidojuma atļaujas neizsniegsim.', 0.95, 'Skaidra ārlietu ministres administratīvā pozīcija — pārlidojuma atļauju atteikums uz Maskavas 9. maija parādi. Pozīcija saskan ar iepriekšējo nostāju (claim 11014 — Krievija nedrīkst saņemt ''sarkano paklāju''). Salience augsta, jo tā ir konkrēta valsts darbība, ne vien retorika.', 0.8, 'https://x.com/Braze_Baiba/status/2045842886122500295', '2026-04-19 00:00:00', '2026-04-19 21:47:31', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11143, 15, 22131, 'Ukraina un Krievija', 'TVP World intervijā apstiprina, ka spēcīgāka Ukraina kaujas laukā nodrošina lielākas izredzes uz ilgstošu mieru, un ka Ukraina turpinās aizstāvēt savu suverenitāti', 'A stronger Ukraine on the battlefield gives us a better chance for lasting peace', 0.8, 'Divi RT no TVP World (dok 22131, 22132) ar tiešiem Bražes citātiem no intervijas. Konsolidēts viens pozīcijas ieraksts, jo runa ir par vienu un to pašu interviju. Uzskats: militārais atbalsts Ukrainai = ceļš uz mieru (peace through strength). Saskan ar claim 10945 un 11099 — apņemšanās turpināt militāro atbalstu.', 0.7, 'https://x.com/Braze_Baiba/status/2045837081507754050', '2026-04-19 00:00:00', '2026-04-19 21:47:31', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11157, 15, 22392, 'Ukraina un Krievija', 'Uzsver, ka Krievijas ekonomika vājinās un ka Krievija sistemātiski manipulē ar datiem, lai maldinātu Ukrainas sabiedrotos par ekonomijas noturību pret karu un sankcijām', 'Russia systematically manipulates data to fool Ukraine’s allies into believing its economy has withstood the strain of its war spending and sanctions. RU official data already paints an alarming picture for the Kremlin', 0.75, 'Ārlietu ministre pārpublicē FT rakstu ar tiešu citātu, signalizējot politisko pozīciju — uzsver, ka sankcijas strādā un Krievijas ekonomiskā noturība ir pārspīlēta. Tas atbalsta viņas jau paustās nostājas par sankciju pastiprināšanu (claim 11010) un neatlaidīgu atbalstu Ukrainai.', 0.7, 'https://x.com/Braze_Baiba/status/2046109287714349328', '2026-04-20 00:00:00', '2026-04-20 16:16:07', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11161, 57, 22442, 'Koalīcija un partijas', 'Apsūdz Progresīvos un Vienotību par Latvijas nogrūšanu par Eiropas nabadzīgāko nomali — sarkastiski komentē Progresīvo deputāta Staķa partijas maiņas plānus', 'glumais Tumes Staķis jau skatās pēc jaunas partijas, ja reiz tik drosmīgi kritizē savu “Progresīvo” sarkano šļuru, kura kopā ar “Vienotības” vēzi padarījusi Latviju par Eiropas nabadzīgāko nomali', 0.75, 'Skaidra politiskā pozīcija — apsūdz abas valdošās partijas (Progresīvie, Vienotība) par Latvijas ekonomisko stāvokli. Turpina Lapsa agrāk pausto nostāju par Vienotību kā ''vēzi/parazītu'', paplašinot uz Progresīvajiem.', 0.6, 'https://x.com/Lato_Lapsa/status/2046173548578763036', '2026-04-20 00:00:00', '2026-04-20 16:16:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11162, 57, 22438, 'Tieslietas', 'Sarkastiski izsmej prokuroru Neikenu par rurālu pasākumu apmeklēšanu bez mediju uzmanības — netieši apsūdz par darbību tikai kameru priekšā', 'Neikens? Kāds vēl Neikens? Braukt uz kaut kādu čuhņu, kad pat ceriņi nezied? Tribīnē uzlīst nevarēs? Televīzijas nebūs? Da ejiet jūs!', 0.6, 'Turpina Lapsa iepriekšējo kritiku par prokuroru Neikenu (skat. 2026-04 esošo pozīciju par Rinkēviča/JV nekompetenci Neikena jautājumā). Šeit sarkastiski apsūdz Neikenu par egocentrismu un mediju meklēšanu, netieši apšaubot viņa profesionālismu.', 0.5, 'https://x.com/Lato_Lapsa/status/2046195529676149125', '2026-04-20 00:00:00', '2026-04-20 16:16:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11163, 57, 22439, 'Tieslietas', 'Apsūdz ģenerālprokuroru Meisteru divkāršos standartos — selektīva taisnība atkarībā no klientu identitātes', 'Viens likums, viena taisnība visiem? Hehe, noteica Meisters - Stukānam bija savi īpašie klienti, man savi.', 0.8, 'Konkrēta sistēmiska apsūdzība — apgalvo ka ģenerālprokurors Meisters turpina priekšteča Stukāna selektīvās taisnības praksi ar ''saviem īpašajiem klientiem''. Tiešs citāts, skaidra pozīcija par tiesībsargājošo iestāžu korupciju. Saskan ar Lapsa iepriekšējām pozīcijām par neuzticību ģenerālprokuroram un sistēmisko korupciju.', 0.75, 'https://x.com/Lato_Lapsa/status/2046189820079223127', '2026-04-20 00:00:00', '2026-04-20 16:16:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11183, 57, 22790, 'Sociālā politika', 'Sarkastiski noraida Stambulas konvenciju kā nevajadzīgu likumprojektu', 'Sekos iesnu izskaušanas likumprojekts un lapu krišanas izskaušanas likumprojekts… Kur tad Stambulas konvencija, āksti?', 0.65, 'Stambulas konvencijas kritika — varētu būt arī Tieslietas (juridiskais instruments) vai Koalīcija un partijas. Izvēlējos Sociālā politika, jo konvencija attiecas uz vardarbību pret sievietēm. Lapsa sarkastiski salīdzina Stambulas konvenciju ar ''iesnu izskaušanas likumprojektu'' — norāda, ka tā ir nelietderīga vai simbolisks likumdošanas žests.', 0.6, 'https://x.com/Lato_Lapsa/status/2046542772610462081', '2026-04-21 00:00:00', '2026-04-21 15:35:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11184, 57, 22784, 'Budžets un finanses', 'Apsūdz augsta ranga politiķi par degvielas, siltuma un pārtikas cenu pieaugumu', 'Degvielas, siltuma, pārtikas cenas jau salauzis… Titulētais caurkritušais oberis.', 0.55, 'Lapsa sarkastiski dēvē kādu titulētu (amata) politiķi par ''caurkritušu oberi'' (neveiksmīgu viesmīli), apsūdzot par ekonomisko situāciju — degvielas, siltuma, pārtikas cenu pieaugumu. Konkrētā adresāta identitāte nav viennozīmīgi noteicama no pašas ziņas konteksta, bet pozīcija ir skaidra: valdošā politika ir sabojājusi dzīves dārdzību.', 0.6, 'https://x.com/Lato_Lapsa/status/2046556982035787909', '2026-04-21 00:00:00', '2026-04-21 15:35:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11197, 15, 22723, 'Budžets un finanses', 'Atbalsta Latvijas pievienošanos NASA Artemis memorandam par sadarbību kosmosā — paver iespējas zinātniekiem, uzņēmējiem, studentiem', 'Šodien @dacemelbarde Latvijas vārdā parakstīja pievienošanos @NASAArtemis memorandam par sadarbību kosmosā. Tas paver jaunas iespējas mūsu zinātniekiem, uzņēmējiem, studentiem.', 0.85, 'Braže tieši savā tvītā pozitīvi komentē Latvijas pievienošanos Artemis Accords — tiešs politiskā kursa apstiprinājums Latvijas kosmosa politikai un starptautiskai zinātnes sadarbībai.', 0.55, 'https://x.com/Braze_Baiba/status/2046307704105541994', '2026-04-20 19:19:09', '2026-04-21 15:37:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11198, 15, 22718, 'Aizsardzība un drošība', 'Amplificē NATO pozīciju, ka NATO paliek kodolieroču alianse, kamēr eksistē kodolieroči — atturēšana kā miera un agresijas novēršanas pamats', 'As long as nuclear weapons exist, #NATO will remain a #nuclear alliance. The fundamental purpose of NATO''s nuclear capability is to preserve peace, prevent coercion, and deter aggression.', 0.55, 'Braže publicē citātu pēdiņās (varbūt no NATO vai ģenerālsekretāra paziņojuma) bez pievienotā komentāra. Amplifikācija ir nepārprotama atbalsta izpausme ārlietu ministrei, bet nav pilnīgi skaidrs, vai tas ir viņas pašas formulējums. Pazemināta ticamība tieši šā ambiguitāte dēļ.', 0.7, 'https://x.com/Braze_Baiba/status/2046545639484317900', '2026-04-21 00:00:00', '2026-04-21 15:37:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11217, 15, 23085, 'Ukraina un Krievija', 'Paziņo par Latvijas valdības apstiprinātu 1,2 miljonu EUR vērtu elektroenerģijas ģeneratoru piegādi Ukrainas Čerņihivas reģionam, lai nodrošinātu noturību un elektroenerģijas piegādi civilajām iestādēm, ko bojājuši Krievijas triecieni', 'Latvia''s government has approved supplies of electricity generators to Ukraine, total value 1.2 million EUR. They will be donated to Chernihiv region to ensure resilience and supply of electricity to civilian institutions, damaged by Russian strikes.', 0.85, 'Pirmās personas paziņojums no ārlietu ministres par konkrētu Latvijas valdības lēmumu — humanitārā/enerģētikas palīdzība Ukrainai ar konkrētu summu un saņēmēju. Atbilst iepriekšējai pozīcijas līnijai (turpināt militāro un humanitāro atbalstu Ukrainai).', 0.75, 'https://x.com/Braze_Baiba/status/2046578065459839013', '2026-04-21 00:00:00', '2026-04-21 20:56:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11218, 57, 23136, 'Rail Baltica', 'Pauž skepsi par Rail Baltica pabeigšanas termiņu — dēvē to par iluzoru un netieši norāda, ka termiņa sakritība ar kaut ko citu ir apzināta', 'Viens termiņš ar Rail Baltica iluzoro pabeigšanu - tas tā kā speciāli?', 0.65, 'Tvīts ir īss un ironisks, bet skaidri pauž pozīciju, ka Rail Baltica pabeigšanas termiņš nav reāls (iluzors) un sakritība ar citu termiņu šķiet apzināta. Lapsa turpina savu pastāvīgo kritiku pret valdības lielajiem infrastruktūras projektiem.', 0.75, 'https://x.com/Lato_Lapsa/status/2046635102298337444', '2026-04-21 00:00:00', '2026-04-21 20:57:07', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11244, 15, 23378, 'Ukraina un Krievija', 'Krievijai nav militāras kapacitātes uzbrukt NATO valstīm, tostarp Baltijai — visi Krievijas spēki ir vērsti pret Ukrainu; jāturpina vājināt Krieviju un kāpināt sankciju spiedienu', 'Krievija jaunus militārus uzbrukumus nevar atļauties, tāpēc ir jāturpina vājināt Krieviju un jākāpināt sankciju spiedienu', 0.9, 'Skaidra pozīcija intervijā LETA — balstīta uz Latvijas un sabiedroto izlūkdienestu datiem. Braže argumentē ar konkrētiem skaitļiem (1,3 milj zaudējumi, 130 mljrd USD sankciju izmaksas, 15% inflācija). Pozīcija atšķiras no Igaunijas ministra Cahknas un Lietuvas premjeres Ruginienes — Braže vairāk akcentē Krievijas vājumu.', 0.9, 'https://www.la.lv/krievija-jaunus-militarus-uzbrukumus-nevar-atlauties-visi-speki-versti-pret-ukrainu-uzskata-arlietu-ministre', '2026-04-22 00:00:00', '2026-04-22 17:54:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11245, 15, 23359, 'Ukraina un Krievija', 'Krievija konsekventi īsteno dezinformācijas kampaņas pret Baltijas valstīm, lai grautu NATO sabiedroto uzticību aizsardzības spējām un mazinātu atbalstu Ukrainai', 'Krievija jebkuru publiskajā vidē izskanējušo informāciju vai viedokli var nolemt izmantot melu un propagandas radīšanai. Taču Krievijai dezinformācijas kampaņām nav obligāti nepieciešami fakti', 0.85, 'Atsevišķa pozīcija par informatīvo telpu — Braže piemin konkrētu kampaņu par Baltijas valstu gaisa telpas izmantošanu dronu uzbrukumos Krievijai. Papildina, nevis dublē militārās kapacitātes tēmu.', 0.7, 'https://nra.lv/baltija/519432-krievijai-nav-kapacitates-uzbrukumam-baltijas-valstim.htm', '2026-04-22 00:00:00', '2026-04-22 17:54:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11246, 15, 23399, 'Ukraina un Krievija', 'Atbalsta ES virzību uz diviem svarīgiem drošības lēmumiem — 90 miljardu EUR aizdevumu Ukrainas steidzamām finanšu un kaujas vajadzībām un 20. sankciju paketi pret Krieviju; spiediens turpināsies līdz kara apturēšanai', '90 billion EUR loan to meet Ukraine''s urgent financial and battlefield needs. 20th sanctions package against Russia. Pressure will continue until its war is stopped.', 0.9, 'Tiešs tvīts pirmajā personā par ES lēmumiem — skaidra atbalsta pozīcija konkrētam finanšu instrumentam un sankciju paketei.', 0.85, 'https://x.com/Braze_Baiba/status/2046933853726560749', '2026-04-22 00:00:00', '2026-04-22 17:54:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11247, 15, 23400, 'Ārpolitika', 'Paplašina Latvijas un Azerbaidžānas divpusējās attiecības — paraksta memorandu par sadarbību konsulārajos jautājumos; atbalsta Armēnijas un Azerbaidžānas miera procesu', 'A valuable meeting in Baku with Foreign Minister of Azerbaijan @Bayramov_Jeyhun to discuss growing our bilateral trade, peace process w Armenia, support for Ukraine, relations with EU.', 0.8, 'Tiešs tvīts par ministru tikšanos Baku ar konkrētu rezultātu — parakstīts memorands par konsulāro sadarbību. Atbalsta Armēnijas-Azerbaidžānas miera procesu ir pozīcija, ne tikai ceremonialitāte.', 0.55, 'https://x.com/Braze_Baiba/status/2046910396510904704', '2026-04-22 00:00:00', '2026-04-22 17:54:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11286, 57, 23776, 'Aizsardzība un drošība', 'Asi kritizē aizsardzības ministru Andri Sprūdu — viņa skaidrojumus par to, kāpēc Aizsardzības ministriju pamet jau otrais valsts sekretārs, raksturo kā melus, lietojot retoriku par ''Kremļa ietekmes aģentu''.', 'Ir parasti meli, ir stulbi meli, un tad vēl ir kremļa ietekmes aģenta Sprūda skaidrojumi, kāpēc Aizsardzības ministriju pamet jau otrs valsts sekretārs.', 0.8, 'Lapsas paša tvīts ar pievienotu tekstu (nav bare retweet). Tieša pirmās personas asa kritika pret sēdošo aizsardzības ministru Sprūdu — viņa publiskos skaidrojumus par 2. valsts sekretāra aiziešanu raksturo kā melus, lietojot frāzi ''Kremļa ietekmes aģents''. Tematika: aizsardzības ministrijas vadības krīze.', 0.85, 'https://x.com/Lato_Lapsa/status/2047000088027824537', '2026-04-22 00:00:00', '2026-04-23 00:07:13', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11289, 15, 23752, 'Ārpolitika', 'Turpina divpusējās attiecības ar Azerbaidžānu — tiekas Baku ar ārlietu ministru Bairamovu', 'Vērtīga tikšanās Baku ar Azerbaidžānas ārlietu ministru Džeihunu Bairamovu, kurā apspriedām…', 0.6, 'MFA konta retvīts satur Bražes tiešu citātu kā ārlietu ministrei. Citāts ir pirmajā personā un apstiprina tikšanās faktu ar Azerbaidžānas kolēģi. Saturiski vājš (teksts nogriezts pie "apspriedām…"), tāpēc zema pārliecība un vidēja salience — tas ir darbības/tikšanās ieraksts, ne pilnīga politikas pozīcija. Šķirams no pārējiem 5 retvītiem, kuros Braže netiek citēta.', 0.5, 'https://x.com/Braze_Baiba/status/2047017561171145167', '2026-04-22 00:00:00', '2026-04-23 00:07:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11299, 15, 24036, 'Ārpolitika', 'Uzsāk divpusējās attiecības ar jauno Ungārijas ārlietu ministra amata kandidāti Anitu Orbán — pārrunā ES un NATO sadarbību un Ukrainas atbalsta progresu', 'An in-depth first call with Hungary''s Foreign Minister-designate Anita Orbán. We discussed strengthening bilateral relations, exchange of visits, cooperation in the EU and NATO, and making progress on key decisions on support for Ukraine.', 0.8, 'Tieša Bražes pirmpersonas ziņa par divpusēju sarunu ar Ungārijas jauno ārlietu ministra amata kandidāti. Izteikums iezīmē četrus sarunas tematus: divpusējās attiecības, vizītes, ES/NATO sadarbība, Ukrainas atbalsts. Kontekstā ar iepriekšējām Ungārijas un ES diskusijām par Ukrainas atbalstu — dialoga turpināšana ir politiska pozīcija.', 0.6, 'https://x.com/Braze_Baiba/status/2047236977901072453', '2026-04-23 00:00:00', '2026-04-23 13:59:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11300, 15, 24039, 'Ārpolitika', 'Paziņo par Latvijas iekļūšanu ES valstu sarakstā, kas drīkst eksportēt olas un gaļas produktus uz Singapūru — piesaka to kā diplomātisko sasniegumu pēc Singapūras ministra vizītes Latvijā', 'Pavisam neilgi pēc Singapūras ministra vizītes Latvijā esam saņēmuši lielisku ziņu mūsu pārtikas ražotajiem- no aprīļa Latvija ir starp ES valstīm, kuras drīkst eksportēt olas un gaļas produktus uz Singapūru', 0.85, 'Bražes pirmpersonas paziņojums par konkrētu divpusējo tirdzniecības rezultātu — Latvijas pievienošanos ES eksportētāju sarakstam uz Singapūru pēc Singapūras ministra vizītes. Tas ir konkrēts ārpolitiskais/tirdzniecības sasniegums, ne tikai ceremoniāls paziņojums.', 0.5, 'https://x.com/Braze_Baiba/status/2047202612122919140', '2026-04-23 00:00:00', '2026-04-23 13:59:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (11328, 57, 24103, 'Budžets un finanses', 'Kritizē Čakšu (Vienotība) un koalīcijas fiskālo politiku, norādot, ka Latvijas valsts parāds pagājušogad palielinājies par 1,4 miljardiem eiro.', 'Finanšu pratību citiem cilvēkiem māca Čakša no "Vienotības" vēža, kurš pagājušogad ir rijis zefīriņus tā, ka Latvijas parāds palielinājies par 1,4 miljardiem eiro…', 0.6, 'Lato pirmajā personā publicē sarkastisku kritiku par Čakšas finanšu pratības lekcijām un norāda uz valsts parāda pieaugumu par 1,4 miljardiem eiro. Substance: iebilst pret esošo fiskālo politiku / parāda pieaugumu. Tonis polemisks, bet pozīcija konkrēta — opozīcija pret koalīcijas budžeta pārvaldību.', 0.6, 'https://x.com/Lato_Lapsa/status/2047226893930213805', '2026-04-23 00:00:00', '2026-04-23 19:26:29', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14315, 182, 26285, 'Koalīcija un partijas', 'Kritizē Progresīvos (PRO) kā morāli kompromitētu partiju: apgalvo, ka PRO ļāva Magņicka sarakstā iekļautā oligarha kabatas partijām atgriezties valdībā, ka PRO iepriekš sadarbojies ar APar ("nauda nesmird"), un ka PRO koalīcijas partneri JV vairāk atbalstījuši Krieviju nekā LPV.', 'Atcerēsimies, ka tieši pateicoties PRO Latvijas valdībā atgriezās Magņicka sarakstā iekļautā oligarha kabatas partijas. ... PRO draugi no JV sadarbojušies un atbalstījuši Krieviju vairāk nekā LPV.', 0.75, 'Otto Ozols pirmajā personā formulē politisku kritiku par Progresīvajiem, izmantojot trīskāršu retorisko "Atcerēsimies, ka..." konstrukciju. Visi trīs apgalvojumi veido vienotu argumentu, ka PRO koalīcijas izvēles ir morāli problemātiskas (oligarhu partiju leģitimēšana, sadarbība ar APar, JV-Krievijas saiknes). Tas ir Otto paša pozīcija, nevis citēšana — viņš pats izsaka spriedumu. Tēma "Koalīcija un partijas" jo fokuss ir uz partiju savstarpējām attiecībām un koalīcijas leģitimitāti.', 0.6, 'https://x.com/OttoOzols/status/2048340980189856219', '2026-04-26 00:00:00', '2026-04-26 14:24:28', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14316, 15, 26353, 'Ukraina un Krievija', 'Atzīmē Černobiļas 40. gadadienu — uzsver, ka Krievija turpina radīt nopietnu kodoldrošības risku okupētajā Zaporižjas AES', 'As we commemorate the victims and survivors of Chornobyl, Russia continues to poses a grave risk to nuclear security in occupied Zaporizhzhia.', 0.85, 'Pirmās personas tvīts (nav RT) — ārlietu ministre savieno Černobiļas vēsturisko traģēdiju ar pašreizējo Krievijas radīto kodoldraudu Zaporižjas AES. Skaidra pozīcija: Krievija = aktīvs kodoldrošības risks Ukrainā.', 0.7, 'https://x.com/Braze_Baiba/status/2048146705279783265', '2026-04-26 00:00:00', '2026-04-26 15:00:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14324, 57, 26413, 'Koalīcija un partijas', 'Brīdina, ka Progresīvie ir ''sarkanā sērga'', kas iznīcinās visu valsti, ja vēlētāji to pieļaus', 'Progresīvo sarkanā sērga. Ja ļausiet, viņi to izdarīs ar visu valsti.', 0.7, 'Lapsas paša īsais īsziņas formāta tvīts (nav RT) ar tiešu vēsturisko salīdzinājumu — Progresīvie kā ''sarkanā sērga'' (atsauce uz padomju represiju retoriku). Aicina vēlētājus nepieļaut viņu turpmāku ietekmi. Atšķirīgs no agrākām pretenzijām (Staķa partijas maiņa 04-20, Tautsaimniecības komisija 04-16, Satiksmes ministrijas reforma 04-13) — tas ir vispārinājums, ne konkrēts incidents.', 0.55, 'https://x.com/Lato_Lapsa/status/2048063557141402008', '2026-04-25 00:00:00', '2026-04-26 15:02:18', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14326, 182, 26439, 'Degviela un enerģētika', 'Iesaka Latvijai un ES ieviest Izraēlas modeļa degvielas cenu regulējumu — 95. markas benzīna maksimālo mazumtirdzniecības cenu ar publisku, matemātisku formulu piesaistītu globālajai naftas cenai, lai novērstu degvielas tirgotāju un biržas spekulantu manipulācijas.', 'Vai Latvijā un ES kopumā arī varētu darboties līdzīga sistēma, lai lielās degvielas kompānijas un biržas spekulanti mūs neapzagtu katru reizi, iebraucot uzpildīt auto?', 0.7, 'Otto detalizēti aprakstā Izraēlas regulēto degvielas cenu modeli un retoriskā jautājumā formulē priekšlikumu Latvijai/ES ieviest analogu sistēmu. Pozīcija ir konkrēta (formulas-bāzēta cenu regulēšana 95. benzīnam), bet izteikta kā jautājums, tāpēc vidēja confidence.', 0.7, 'https://x.com/OttoOzols/status/2047681962882601118', '2026-04-23 00:00:00', '2026-04-26 15:02:44', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14327, 182, 26445, 'Valsts pārvalde', 'Kritizē Latvijas politiķu nesamērīgos VIP zonas tēriņus un kontrastē tos ar Somijas egalitāro praksi, kur eks-prezidents Niinistö publiski apsēdās uz trepēm pasākumā, kad nebija brīvu vietu — apgalvo, ka VIPošanās Latvijā nav pieņemama.', 'Tā tas notiek sabiedrībās, kur VIPošanās nav ne saprotama, ne pieņemama', 0.8, 'Otto skaidri kritizē Latvijas politiķu nesaprātīgos un nesamērīgos tēriņus VIP zonās un piedāvā Somijas modeli kā kontrastu. Pozīcija ir tieša un argumentēta ar konkrētu piemēru.', 0.6, 'https://x.com/OttoOzols/status/2046235623564914724', '2026-04-23 00:00:00', '2026-04-26 15:02:44', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14328, 182, 26434, 'Koalīcija un partijas', 'Kritizē Progresīvo Šuvajeva paziņojumu PRO kongresā par nesadarbošanos ar Šleseru kā liekulīgu — atgādina, ka PRO un Vienotība pirms vēlēšanām skaļi solīja nekad nesēdēt vienā valdībā ar Lembergu un ZZS, taču tagad to dara.', 'Progresīvie kopā ar Vienotību pirms vēlēšanām skaļi solīja, ka NEKAD, NEKĀDĀ GADĪJUMĀ nesēdēs vienā valdībā ar Lembergu un ZZS.', 0.85, 'Otto izceļ konkrētu Šuvajeva izteikumu PRO kongresā un kontrastē ar PRO/Vienotības pirmsvēlēšanu solījumu par ZZS. Atšķiras no esošā claim 14315 (vispārīga PRO morāla kritika par Magņicki/APar/JV-Krievija), jo fokusējas uz konkrētu jaunu Šuvajeva izteikumu un Šlesers/Lembergs/ZZS solījumu.', 0.7, 'https://x.com/OttoOzols/status/2048354015855931860', '2026-04-23 00:00:00', '2026-04-26 15:02:44', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14348, 15, 26996, 'Ukraina un Krievija', 'Iekļauj Latvijas nevēlamo personu sarakstā 3 Krievijas pilsoņus (Mihailu Švidkoju, Anastasiju Karnejevu, Jekaterinu Vinokurovu) saistībā ar Krievijas pārstāvniecību Venēcijas biennālē — aizliegums ieceļot uz nenoteiktu laiku saskaņā ar Imigrācijas likuma 61. panta 2. daļu', 'Esmu lēmusi LR nevēlamo personu (persona non grata) sarakstā iekļaut 3 KF pilsoņus un aizliegt Mihailam Švidkojam, Anastasijai Karnejevai, Jekaterinai Vinokurovai ieceļot 🇱🇻 uz nenoteiktu laiku, saskaņā ar Imigrācijas likuma 61.p. 2.d.', 0.95, 'Konkrēts ministra lēmums, izteikts pirmajā personā (''Esmu lēmusi''). Realizē iepriekš pausto principiālo nostāju (claim #11014, ka Krievija nedrīkst saņemt ''sarkano paklāju'' Venēcijas biennālē) ar tiešu administratīvu darbību. LETA un PMO ir trešo pušu pārstāstījumi tā paša lēmuma — saglabāju Bražes pašas X paziņojumu kā autoritatīvāko avotu.', 0.85, 'https://x.com/Braze_Baiba/status/2048754645883932746', '2026-04-27 00:00:00', '2026-04-27 23:10:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14349, 15, 27004, 'Ukraina un Krievija', 'Kijivas drošības forumā uzsver, ka ES lēmumi par 90 miljardu EUR aizdevumu un 20. sankciju paketi parāda Eiropas vienotību Ukrainas atbalstā; Krievijas karš nesasniedz mērķus un tā kļūst vājāka', 'The decisions on the 90 billion loan and 20th sanctions package show that Europe is united in supporting Ukraine. Russia''s war is going nowhere. It is becoming weaker every day.', 0.9, 'Pirmās personas izteikums Kijivas drošības forumā. Saturīgs paziņojums ar konkrētiem skaitļiem (90 mljrd, 20. sankciju pakete), nevis vispārīgs atbalsts. Saskanīgs ar iepriekšējo claim #11246 par tiem pašiem ES lēmumiem — tas ir paplašinājums, ne pretruna.', 0.8, 'https://x.com/Braze_Baiba/status/2048690572139831358', '2026-04-27 00:00:00', '2026-04-27 23:10:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14353, 182, 27117, 'Ārpolitika', 'Apšauba Spānijas uzticamību kā NATO un ES dalībvalstij — atgādina par Spānijas plašo sadarbību ar Krievijas floti Seūtas ostā 2014.–2015. gadā, kad Krievijas kuģi (t.sk. zemūdene un spiegošanas kuģis Yantar) tur uzņemti vismaz 13 reizes vienlaikus ar Krimas okupāciju, un secina, ka tas sniedza būtisku atbalstu Putina un Asada režīmiem.', 'NATO member state Spain has extensive experience collaborating with the Russian military and intelligence services, providing significant support to criminal regimes. This, of course, inevitably raises serious questions about Spain reliability as an EU and NATO member state.', 0.8, 'Gara X-vītne ar pirmās personas vēsturisku argumentu un noslēguma tēzi par Spānijas neuzticamību NATO. Pozīcija ir skaidri formulēta autora paša balsī, ar konkrētiem datiem (Ceuta osta, 13 piestātnes, Yantar, Novorossiysk). Augsta uzticamība, jo arguments un secinājums ir tieši izteikti.', 0.7, 'https://x.com/OttoOzols/status/2048778178986971216', '2026-04-27 00:00:00', '2026-04-27 23:13:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14373, 30, 26561, 'Vēlēšanas', 'Piedāvā radikāli vienkāršot pārstāvniecības sistēmu — Saeimā 8 deputātus ar procentiem atbilstošu balss svaru, Rīgas domē tikai 30 deputātus, atbildot status quo aizstāvjiem, kuri iebilst pret MMN piedāvāto vēlēšanu kārtību', 'ja Saeimā lēmumu pieņemšanai nevajag 100 gudras galvas, tad varbūt vienkārši ievēlam 8 galvas un piešķiram katrai procentam atbilstošu balss svaru? Un Rīgas domē turpmāk liekam tikai 30 deputātus.', 0.7, 'Skaidra (kaut polemiska/ironiska) pozīcija atbildot kritiķiem par MMN vēlēšanu reformu. Stiprāka kā retorisks izaicinājums nekā gatavs likumprojekts, tāpēc 0.7. Tuvs esošajiem MMN vēlēšanu reformas tematiem.', 0.6, 'https://x.com/JazepsBasko/status/2048642490136232090', '2026-04-27 00:00:00', '2026-04-27 23:19:15', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14374, 30, 26561, 'Valsts pārvalde', 'Kritizē Jaunās VIENOTĪBAS kursu kā ''Lēnāk un paga!'' — apgalvo, ka valsts pārvalde kļuvusi par ''sarunu ar melnu kasti'' ko pārvalda ''sertificēti priesteri'', un prasa demokrātisku pārkārtošanu, lai lēmumu pieņemšana būtu saprotama vēlētājiem', '''Lēnāk un paga!'' ir JAUNĀS VIENOTĪBAS kurss... Demokrātija, kas nav saprotama demosam, nav demokrātija.', 0.8, 'Tieša politiska pozīcija pret valdošo partiju un pārvaldes komplicētību. Tieši nosauc JV. Pamato ar demokrātijas leģitimitātes argumentu.', 0.7, 'https://x.com/JazepsBasko/status/2048642490136232090', '2026-04-27 00:00:00', '2026-04-27 23:19:15', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14375, 30, 26562, 'Koalīcija un partijas', 'Vēlas premjeru, kuram amats nav personīgās karjeras kāpšļa instruments (Taimskvēras bildes, slavenības, starptautisko org. amati, VIP laundži, praivatdžeti) — bet cilvēks, kuram tas viss vai nu jau ir bijis vai nekad nav bijis vajadzīgs un kurš stājas amatā ''aiz atbildības pret dzimteni''', 'Kā būtu, ja premjers būtu cilvēks, kuram tas viss jau ir bijis vai nekad nav bijis vajadzīgs un kurš amatā stājas ar maķenīt augstāku nepiepildīto ambīciju slieksni, piemēram, aiz atbildības pret dzimteni?', 0.7, 'Netieša bet skaidra kritika pret esošo/iepriekšējo premjera profilu (statusa kāpšļa motivācija). Formulējums kā retorisks jautājums, bet ar skaidri izteiktu pretpiedāvājumu — tāpēc nav ''rhetorical question with no stated answer''.', 0.5, 'https://x.com/JazepsBasko/status/2048451822159860018', '2026-04-27 00:00:00', '2026-04-27 23:19:15', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14396, 15, 27571, 'Ukraina un Krievija', 'Apstiprina, ka Latvijas valdība nodod Ukrainas Bruņotajiem spēkiem papildu CVR(T) bruņutehniku un uzsver, ka Latvijas militārais atbalsts Ukrainai 2025. gadā bija 0,3% no IKP — apņemas turpināt nodrošināt, lai Ukraina ir spēcīga kaujas laukā, jo tas tuvina mieru pie sarunu galda.', 'Latvian Government decided to transfer to the Ukrainian Armed Forces additional CVR(T)’s. Latvia’s military support to Ukraine was 0.3% of GDP in ‘25. We’ill continue to ensure that Ukraine is strong on the battlefield as it will bring peace closer at the negotiating table.', 0.9, 'Tiešs pirmās personas paziņojums Braže oficiālajā X kontā (angļu val.) par Latvijas militāro atbalstu Ukrainai — apstiprina papildu CVR(T) bruņutehnikas nodošanu un uzsver 0,3% no IKP rādītāju 2025. gadā. Atkārto Latvijas ārpolitisko līniju: militārs atbalsts Ukrainai = ceļš uz mieru.', 0.85, 'https://x.com/Braze_Baiba/status/2049117833078972896', '2026-04-28 00:00:00', '2026-04-28 23:53:02', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14412, 57, 27799, 'Budžets un finanses', 'Sarkastiski izsmej Latvijas "veiksmes stāsta" naratīvu — salīdzinājumā ar Somijas premjera atalgojumu (~7000 EUR mēnesī) Latvijas situācija izskatās nožēlojama, kaut oficiālie ziņojumi to slavē', 'Padomāt tik, kā šie nabadzīgie somi apskauž Latvijas veiksmes stāstu', 0.55, 'Lapsa pirmpersonas tvīts ar klauna emoji, sarkasms iesietā kontekstā ar Somijas premjeres atalgojuma RT. Pozīcija — Latvijas "veiksmes stāsts" ir mistifikācija, ekonomiskā situācija realitātē atpaliek. Konkrēta politika nav nosaukta, tāpēc salience zems.', 0.4, 'https://x.com/Lato_Lapsa/status/2049348105338814748', '2026-04-29 00:00:00', '2026-04-29 09:28:22', 'position', 57);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14413, 57, 27797, 'Tieslietas', 'Atkārto pozīciju, ka Latvijas tiesībsargājošās iestādes ("mentu zaņķis") ir korumpētas un to pakalpojumus tagad nodokļu maksātāji apmaksā par labu "hiēnu bandai"', 'Mentu zaņķim atkal kreņķis, hiēnu bandai atkal izdevumi mentu zaņķa pakalpojumu apmaksai', 0.6, 'Lapsa pirmpersonas tvīts, atkārto iepriekš pausto "mentu zaņķis" naratīvu (skat. 2026-04-17 par Vaļagina lietu). Pozīcija — policijas/prokuratūras sistēma ir kompromitēta, tās darbība rada papildu izmaksas politiskām elitēm. Konkrēts notikums no t.co linka nav redzams content laukā, tāpēc confidence vidējs.', 0.5, 'https://x.com/Lato_Lapsa/status/2049369390697615556', '2026-04-29 00:00:00', '2026-04-29 09:28:22', 'position', 57);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14417, 15, 27784, 'Ārpolitika', 'Atzinīgi novērtē Saharova prēmijas laureāta Andžeja Počobuta atbrīvošanu pēc 1860 ieslodzījuma dienām un pateicas ASV administrācijai par centieniem; uzsver, ka Lukašenko režīma represijas turpinās un vairāk nekā 800 politieslodzīto joprojām atrodas apcietinājumā.', 'After 1860 days of unjust imprisonment, Polish-Belarusian hero and Sakharov Prize laureate Andrzej Poczobut is released. We commend the efforts of the US administration. Yet repressions and arrests by Lukashenka regime continue, over 800 political prisoners are behind bars.', 0.9, 'Tiešs pirmās personas paziņojums no Bražes oficiālā X konta. Skaidri formulēta divkārša pozīcija: (1) atbalsts ASV diplomātiskajiem centieniem politieslodzīto atbrīvošanā, (2) Lukašenko režīma represiju nosodījums. Salience augsta, jo skar gan ASV-Latvija ārlietu sadarbību, gan ES-Baltkrievijas politiku.', 0.75, 'https://x.com/Braze_Baiba/status/2049361127746773272', '2026-04-29 00:00:00', '2026-04-29 09:31:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14460, 189, 27746, 'Koalīcija un partijas', 'Aicina reorganizēt koalīciju un valdību, ne tikai Satiksmes ministriju', 'ir nepieciešama Satiksmes ministrijas reorganizācija, šī nedēļa pierādījusi, ka arī valdība un koalīcija ir jāreorganizē', 0.85, 'Pūce kā partijas ''Latvijas attīstībai'' valdes priekšsēdētājs publiski paziņo, ka pašreizējā koalīcija un valdība jāreorganizē — kontekstā ar airBaltic aizdevuma strīdu un ZZS-Progresīvo konfliktu. Skaidra politiska pozīcija no opozīcijas (LA nav koalīcijā).', 0.85, 'https://jauns.lv/raksts/zinas/705123-juris-puce-ir-jareorganize-si-koalicija-un-valdiba', '2026-04-16T07:39:15.000000Z', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14461, 189, 28052, 'Budžets un finanses', 'Kritizē valdību par budžeta izstrādes grafika atlikšanu un darba tempa trūkumu', 'MK atlika nākamā gada budžeta izstrādāšanas grafika apstiprināšanu. 5 no 14 grafikā iekļautiem termiņiem jau ir pagājuši. Formālisma uzvaras gājiens.', 0.8, 'Pūce konkrēti kritizē MK sēdē pieņemtu/atliktu lēmumu par budžeta grafiku, norādot uz nokavētiem termiņiem. Tā ir konkrēta opozīcijas pozīcija par valdības darba kvalitāti budžeta procesā.', 0.7, 'https://x.com/pucej/status/2049107690534690866', '2026-04-28T12:45:18+00:00', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14462, 189, 28053, 'Pensijas', 'Aizstāv pensiju 2.līmeni un kritizē iepriekšējo valdību par tā samazinājumu deficīta dēļ', 'kura valdība nespējas savākt budžeta deficītu dēļ nolēma visiem nākotnes pensionāriem nozagt daļu no tā? Varbūt tāpēc populisti jūtas tik droši grābstīties ap 2.līmeni?', 0.75, 'Pūce piekrīt Jurēvica (JV) bažām, ka populisti var sabojāt pensiju 2.līmeni, vienlaicīgi norādot, ka iepriekšējā valdība jau ''nozaga'' daļu no tā budžeta deficīta dēļ. Pozīcija: aizstāv 2.pensiju līmeni kā tādu un kritizē tā mazināšanu.', 0.7, 'https://x.com/pucej/status/2048795814873481383', '2026-04-27T16:06:01+00:00', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14463, 189, 28054, 'Aizsardzība un drošība', 'Kritizē amatpersonas par VDD izmantošanu personisko strīdu risināšanā, kas mazina drošības iestāžu ticamību', 'savu personisko ķibeļu dēļ nekautrējas pagrūst priekšā VDD, lai tie amatpersonu iegribu dēļ tagad taisnojas. Tas mazina valsts drošības iestāžu ticamību daudz daudzreiz svarīgākos jautājumos.', 0.8, 'Pūce skaidri formulē pozīciju, ka VDD izmantošana personisko strīdu risināšanā ir bezatbildīga un grauj drošības iestāžu reputāciju. Konkrēta pozīcija par drošības iestāžu institucionālo neatkarību.', 0.7, 'https://x.com/pucej/status/2048467199887614048', '2026-04-26T18:20:13+00:00', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14464, 189, 28058, 'Budžets un finanses', 'Atbalsta kreditētāju pienākumu reālā laikā ziņot kredītu informāciju kredītbirojiem', 'Risinājums būtu noteikt pienākumu kreditētājiem (visiem, arī bankām) nodot info par izsniegtu kredītu kredîtbirojiem reālajā laikā (nevis pēc dienas) un kredītbirojiem - pienākumu reālā laikā info darīt pieejamu.', 0.85, 'Pūce piedāvā konkrētu policy risinājumu — reālā laika kredītu informācijas apmaiņa starp kreditētājiem un kredītbirojiem. Skaidra pozīcija par finanšu sektora regulējumu.', 0.55, 'https://x.com/pucej/status/2047315186525036995', '2026-04-23T14:02:32+00:00', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14465, 189, 28060, 'Aizsardzība un drošība', 'Kritizē aizsardzības ministru — divi valsts sekretāri pametuši ministriju 3 gados', 'Ministrs tik "labs", ka 3 gadu laikā jau divi valsts sekretāri ir pametuši Aizsardzības ministriju.', 0.7, 'Pūce sarkastiski kritizē aizsardzības ministra darba kvalitāti, norādot uz konkrētu faktu — divi valsts sekretāri pametuši AM 3 gados. Pozīcija ir kritika par ministra vadības spējām, lai gan formulējums sarkastisks.', 0.6, 'https://x.com/pucej/status/2046983001406402823', '2026-04-22T16:02:33+00:00', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14466, 189, 28062, 'Degviela un enerģētika', 'Kritizē Progresīvo partiju par bezdarbību Latvijas atkarības no dabasgāzes mazināšanā', 'Trîs gadus Pro ir valdībā un ar šīs, it kā taču zaļās partijas gādību nav sperts pat viens solis, lai mazinātu Latvijas atkarību no dabasgāzes.', 0.8, 'Pūce skaidri formulē kritiku Progresīvo (Pro) partijai par neizpildītu enerģētikas politikas mērķi — Latvijas atkarības no dabasgāzes mazināšanu. Konkrēta opozīcijas pozīcija par koalīcijas partneru darba rezultātiem.', 0.7, 'https://x.com/pucej/status/2046830035454071211', '2026-04-22T05:54:43+00:00', '2026-04-30 01:44:42', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14517, 189, 28656, 'Degviela un enerģētika', 'Uzsver vēja enerģijas projektu mērogu — divi MK apstiprinātie vēja parki ražotu 17% Latvijas elektrības patēriņa, kopā ar atlikto trešo virs 30%', 'MK otrdien apstiprinātie 2 vēja parku projekti, ja tos beigās uzcels, ražos gadā 1,2 teravatstundas elektrības. Mēroga sajūtai - apmēram 17% Latvijas patēriņa. Tas 1, kuru atlika, ražotu vēl 1 TWh jeb vēl 14%. Kopā - virs 30% no Latvijas patēriņa.', 0.7, 'Pūce ievieto skaitliskā kontekstā MK apstiprinātos vēja parkus, uzsverot to nozīmīgo īpatsvaru LV patēriņā. Implicīts atbalsts vēja enerģijas izvēršanai un kritika par projekta atlikšanu. Saskan ar prior pozīciju par dabasgāzes atkarības mazināšanu (claim no 180d). Conf 0.7 — pozīcija ir izteikta caur skaitļu kontekstualizāciju, ne tieši formulēts atbalsts/iebildums.', 0.7, 'https://x.com/pucej/status/2049838443706941834', '2026-04-30 00:00:00', '2026-04-30 18:56:53', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14518, 189, 28657, 'Pilsētvide', 'Kritizē pilsētas pārvaldību par betona norobežojumu uzstādīšanu, nepārbaudot ugunsdzēsēju piekļuvi; brīdina, ka šādas slikti īstenotas iniciatīvas marginalizē autosatiksmes mierināšanas konceptu', 'Uzlikt betona norobežojumus ielai un tikai tad pārbaudīt, vai ugunsdzēsēju mašīna var izbraukt - “fantastisks” pilsētas pārvaldības piemērs. Cita starpā - arī piemērs, kā vajadzīgu konceptu (autosatiksmes mierināšana) marginalizēt sabiedrībā ar sliktas pārvaldības palīdzību.', 0.85, 'Skaidri formulēta divkārša pozīcija: (1) kritika par konkrēto pārvaldības praksi, (2) atbalsts autosatiksmes mierināšanas konceptam principā. Pūce uzsver, ka slikta īstenošana grauj nepieciešamas politikas idejas leģitimitāti. Tieši formulēts viedoklis, conf 0.85.', 0.5, 'https://x.com/pucej/status/2049807196016271399', '2026-04-30 00:00:00', '2026-04-30 18:56:53', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14519, 189, 28658, 'Pašvaldības', 'Atzīmē, ka ATR (administratīvi teritoriālās reformas) pēdējais solis ir izturējis Satversmes tiesas pārbaudi un atzīts par konstitūcijai atbilstošu', 'Arī pēdējais (vai priekšpēdējais?) ATR solis ir pārbaudīts tiesā un atzīts par Satversmei atbilstošu.', 0.55, 'Īss faktoloģisks paziņojums par ATR juridisko vindikāciju. Pūce kā bijušais VARAM ministrs un ATR arhitekts šajā tvītā implicīti aizstāv reformu, atsaucoties uz tiesas spriedumu kā apstiprinājumu. Pozīcija nav tieši formulēta (nav saka ''es atbalstu ATR''), bet konteksts ir nepārprotams — viņš atzīmē reformas konstit. atbilstību kā pozitīvu rezultātu. Conf 0.55 jo pozīcija ir implicīta, ne tieša.', 0.5, 'https://x.com/pucej/status/2049784443385045134', '2026-04-30 00:00:00', '2026-04-30 18:56:53', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14528, 15, 28563, 'Aizsardzība un drošība', 'Eiropai jāuzņemas lielāka atbildība par savu drošību un aizsardzību, visām ES valstīm būtiski palielinot aizsardzības izdevumus; ASV un transatlantiskā sadarbība paliek neaizstājams Eiropas drošības pamats, ES aizsardzības centieniem jābūt NATO papildinošiem un spējas stiprinošiem.', 'Eiropai uzņemties lielāku atbildību pār savu drošību un aizsardzību, visām ES valstīm būtiski palielinot aizsardzības izdevumus, kur NB8 valstis jau sevi demonstrē kā labu piemēru. Vienlaikus uzsverot, ka ASV un cieša transatlantiskā sadarbība ir neaizstājams Eiropas drošības pamats. ES aizsardzības centieniem tādējādi jābūt papildinošiem un NATO spējas stiprinošiem.', 0.9, 'Pirmās personas pozīcija pēc NB8 ārlietu ministru sanāksmes Kuresārē 29.-30. aprīlī. Delfi tieši atribuē izteikumu Bražei (kvalificēts ar ''akcentēja'' un ''uzsvēra''). Pozīcija sastāv no trim asīm: ES atbildības palielināšana, NATO/ASV pamats, ES kā NATO papildinošs slānis. Saskan ar iepriekšējām pozīcijām (2026-04-22 par ES 90 mld aizdevumu un sankcijām).', 0.85, 'https://www.delfi.lv/46713439/arzemes/120116708/vajuma-paradisana-izaicina-agresiju-par-eiropas-aizsardzibas-stiprinasanu-saka-kallasa', '2026-04-30 00:00:00', '2026-04-30 18:59:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14529, 15, 28563, 'Ukraina un Krievija', 'Jāturpina nepārtraukts spiediens un izolācija pret Krieviju gan politiski starptautiskajās organizācijās, gan lielos sporta un kultūras pasākumos; jāturpina darbs pie 21. sankciju kārtas sagatavošanas pēc 20. kārtas apstiprināšanas.', 'jāturpina nepārtraukts spiediens Krievijai un izolācija gan politiski starptautiskajās organizācijās, gan lielos sporta un kultūras pasākumos, jo tikai tā varam veicināt pārmaiņas un stiprināt globālo drošību', 0.9, 'Tiešs Bražes izteikums pēc NB8 sanāksmes — atbalsts 21. sankciju kārtai un Krievijas izolācijai sporta/kultūras laukā. Pastiprina 2026-04-22 pozīciju par ES 20. sankciju paketi un 2026-04-19 pozīciju par 9. maija parādes pārlidojuma atļaujām. Konsekventa līnija, ne pretruna.', 0.85, 'https://www.delfi.lv/46713439/arzemes/120116708/vajuma-paradisana-izaicina-agresiju-par-eiropas-aizsardzibas-stiprinasanu-saka-kallasa', '2026-04-30 00:00:00', '2026-04-30 18:59:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (14530, 15, 28620, 'ES politika', 'NB8 (Baltijas un Ziemeļvalstu) formāts veido cieši vienotu līdzīgi domājošu sabiedroto kopienu — kopā stiprina drošu un pārtikušu Ziemeļu-Baltijas reģionu, stiprina NATO un saglabā nemainīgu atbalstu Ukrainai.', 'Together, the #NB8 form a community of closest likeminded allies. We build a secure and prosperous Nordic-Baltic region, reinforce a strong NATO, and sustain unwavering support for Ukraine.', 0.85, 'Bražes pati publicēts tvīts (nav RT) angļu valodā pēc NB8 sanāksmes. Skaidra pirmās personas pozīcija par NB8 lomu reģionālajā drošības arhitektūrā. Saturiski papildina pozīciju #1 (aizsardzības atbildība) ar reģionālu satvaru.', 0.7, 'https://x.com/Braze_Baiba/status/2049774985103733193', '2026-04-30 00:00:00', '2026-04-30 18:59:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17778, 15, 28827, 'Ukraina un Krievija', 'Krievijas militārās intervences Āfrikā (Mali, Sahāra) ir cietušas neveiksmi — Kidalas sakāve atklāj Krievijas nespēju stabilizēt Mali un apdraud pro-Krievijas Bamako valdības izdzīvošanu un Krievijas Āfrikas militāro avantūrismu kopumā.', 'How Russia lost its way in the Sahara. The devastating defeat in Kidal has exposed Russia’s failure to stabilise Mali & has called into question the future of its African military adventurism and survival of the pro-Russian government in Bamako', 0.6, 'Brāže pirmajā personā kopīgo FT rakstu ar atzinīgi izceltu fragmentu par Krievijas militāro neveiksmi Sahārā un Mali. Iet gar viņas plašāko naratīvu par Krievijas vājināšanos. Nav tiešas politikas pozīcijas, bet apzināti amplificēts naratīvs no ārlietu ministres puses — tāpēc mērens confidence un salience.', 0.4, 'https://x.com/Braze_Baiba/status/2049889332660519195', '2026-04-30 00:00:00', '2026-05-01 10:24:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17785, 182, 29033, 'Ārpolitika', 'Marxismu kvalificē kā 20. gadsimta bīstamāko ''sazvērestības teoriju un zinātnisku šarlatānismu''; uzskata, ka Markss lika toksiskos ideoloģiskos pamatus, ko sarkanie tirāni izmantoja desmitiem miljonu cilvēku slepkavošanas attaisnošanai. Iebilst pret apgalvojumiem par Marksa zinātnisko ''ieguldījumu'' kā padomju propagandas radīts mīts.', 'the most dangerous conspiracy theory and scientific charlatanism of the 20th century was the doctrine of Marxism itself', 0.85, 'Skaidra pirmās personas ideoloģiska pozīcija publiskā tvītā 1. maijā — atbalsta Marksa mantojuma noraidīšanu kā padomju propagandu; kontekstā ar viņa iepriekšējām antitotalitārisma pozīcijām.', 0.5, 'https://x.com/OttoOzols/status/2050192671126217215', '2026-05-01 00:00:00', '2026-05-01 20:15:10', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17795, 182, 29149, 'Aizsardzība un drošība', 'Apsūdz Vienotību par Zemessardzes novešanu līdz bankrotam pirms 2014. gada Krievijas draudu pīķa — apgalvo, ka aizsardzības budžets bija zem 1% IKP (zemākais Baltijā), katastrofāli trūka formu, ieroču un infrastruktūras, un par to politiski atbildīgi Bražes domu biedru grupējums Vienotībā.', 'Bražes izrādīšanās ar zemessargu formu ir atbaidošs cinisms - tieši viņas pārstāvētā "Vienotība" ir politiski atbildīga par to, ka 2014. gadā, kad Latvijai reāli draudēja Krievijas uzbrukums, Zemessardze bija novesta līdz bankrotam', 0.85, 'Skaidra pirmās personas pozīcija — Ozols tieši uzbrūk Vienotībai/Bražei par vēsturisko aizsardzības finansējuma trūkumu. Konkrēti faktoloģiski apgalvojumi (zem 1% IKP, zemākais Baltijā), nevis vienkārši insināciju.', 0.75, 'https://x.com/OttoOzols/status/2050433051847467074', '2026-05-02 00:00:00', '2026-05-02 09:36:04', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17796, 182, 29149, 'Ārpolitika', 'Apsūdz Baibu Braži par to, ka tā piespiedusi Latvijas valdību piešķirt finansējumu ANO UNRWA aģentūrai, apgalvojot, ka caur šo organizāciju notika HAMAS apgāde un finansēšana, un ka Braže, pēc Ozola apgalvojuma, rīkojusies pretēji Latvijas interesēm (apgalvojums nav neatkarīgi pārbaudīts).', 'kāpēc viņa piespieda Latvijas valdību piešķirt finansējumu ANO Palestīniešu bēgļu aģentūrai (UNRWA ... Pēc Ozola apgalvojuma, Braže rīkojusies pretēji Latvijas interesēm.', 0.8, 'Tieša pirmās personas apsūdzība pret Braži ar konkrētu politikas darbību (UNRWA finansējums) un nopietnu interpretāciju (HAMAS/Kremļa interešu apkalpošana). Pozīcija ir, ka Latvijai nevajadzēja finansēt UNRWA un ka šī izvēle bija ļaunprātīga.', 0.7, 'https://x.com/OttoOzols/status/2050433051847467074', '2026-05-02 00:00:00', '2026-05-02 09:36:05', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17797, 182, 29150, 'Ukraina un Krievija', 'Atbalsta starptautisko uzmanību Krievijas izdarītajai Ukrainas bērnu nolaupīšanai — pateicīgs Žanam Reno par jauno romānu "L''Évasion", kas pievērš uzmanību ~20 000 nolaupīto Ukrainas bērnu "pārizglītošanai" Sibīrijā.', 'Grateful for this support!', 0.6, 'Pozīcija ir netieša — Ozols dalās Reno ziņā un izsaka pateicību par atbalstu. Pirmās personas signāls ir ļoti īss ("Grateful for this support!"), bet kontekstā ir skaidrs, ka viņš atbalsta Ukrainas bērnu nolaupīšanas tematikas redzamību. Vidēja salience, vidēja confidence — tas ir vairāk simboliskas atbalsta žests, ne politikas pozīcija.', 0.5, 'https://x.com/OttoOzols/status/2050310948125045173', '2026-05-01 00:00:00', '2026-05-02 09:36:05', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17808, 15, 29485, 'Sabiedriskie mediji', 'Atbalsta preses brīvību un Latvijas anti-SLAPP likumu, kas aizsargā žurnālistus no apklusināšanas ar tiesvedību', 'Journalism is not a crime. Latvia''s anti-SLAPP law takes effect this month, protecting journalists from being silenced through litigation.', 0.85, 'Tiešs pirmās personas izteikums Pasaules preses brīvības dienā: Brāže formulē divas pozīcijas — (1) kvalitatīva žurnālistika ir demokrātijas, tiesiskuma un cilvēktiesību priekšnoteikums; (2) atbalsta Latvijas anti-SLAPP likumu, kas šomēnes stājas spēkā. Konkrēta normatīvā atsauce + saturīga pozīcija (ne ceremoniāls).', 0.6, 'https://x.com/Braze_Baiba/status/2050883468460957820', '2026-05-03 00:00:00', '2026-05-03 18:35:18', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17814, 15, 29635, 'Ukraina un Krievija', 'Atbalsta stipru, demokrātisku Ukrainu, pilnībā integrētu eiroatlantiskajā kopienā', 'the work continues to support a strong, democratic, Ukraine, fully integrated in the Euroatlantic community. Freedom is never free.', 0.85, 'Pirmās personas paziņojums Latvijas Neatkarības atjaunošanas 36. gadadienā. Braže savieno Latvijas brīvību ar Ukrainas atbalsta nepārtrauktību un Ukrainas integrāciju ES/NATO struktūrās — tas ir konkrēts ārpolitisks pozīcijas atkārtojums (Ukrainas eiroatlantiskā integrācija), nevis tikai svētku sveiciens.', 0.8, 'https://x.com/Braze_Baiba/status/2051243295167140033', '2026-05-04 00:00:00', '2026-05-04 14:48:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17815, 57, 29685, 'Ukraina un Krievija', 'Atzinīgi novērtē Daiņa Īvāna paveikto Atmodas laikā, vienlaikus norādot uz viņa morālajiem kompromisiem; pretstata viņu citiem 4. maija ''varoņiem'', kurus dēvē par ''komunistu mēsliem''', 'atšķirībā no daudziem citiem 4. maija "varoņiem" Dainis Īvāns nebija nekāds komunistu mēsls, un viņa paveiktais ir cieņas vērts', 0.7, 'Pirmās personas vērtējums par Daini Īvānu un 4. maija ''varoņiem'' kā vēsturisku/morālu komentāru. Tēma neskaidra — pārklājas ar Vēlēšanas (4. maija deklarācija) un Kultūra (publiska personība). Izvēlējos Kultūra jo fokuss ir uz personības mantojumu, ne uz politisku procesu. Salience zema, jo nav konkrētas politikas pozīcijas.

[2026-05-04 16:38:04] Operator review 2026-05-04: pārklasificēts no ''Kultūra'' uz ''Ukraina un Krievija'' caur ''vēsturiskā atmiņa'' aliasu — claim ir morāls Atmoda figūras vērtējums + post-Soviet self-image kritika, kas nav Kultūras grupas saturs. Kultūra šajā shēmā = teātris/opera/muzeji/kultūras politika, nevis vēsturiskā/morāla komentārs.', 0.4, 'https://x.com/Lato_Lapsa/status/2051247093856051254', '2026-05-04 00:00:00', '2026-05-04 14:48:38', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17816, 57, 29694, 'Ukraina un Krievija', 'Apgalvo, ka Latvijas neatkarības atjaunošanas dienas (4. maija) oficiālais nosaukums ir ''liekulīgākais un ciniskākais'' no visiem Latvijas svētkiem', 'No visiem Latvijas oficiālajiem svētkiem Latvijas neatkarības atjaunošanas dienas nosaukums ir liekulīgākais un ciniskākais', 0.75, 'Tieša pirmās personas vērtējuma izteiksme par valsts svētku oficiālo nosaukumu. Tēma neskaidra — varētu būt arī Valsts pārvalde vai Vēlēšanas (Atmodas mantojums). Izvēlējos Kultūra, jo fokuss ir uz simbolisko/svētku nosaukumu, ne uz konkrētu pārvaldes vai vēlēšanu jautājumu. Konkrētas politikas pārmaiņas pieprasījums nav formulēts.

[2026-05-04 16:38:04] Operator review 2026-05-04: pārklasificēts no ''Kultūra'' uz ''Ukraina un Krievija'' — claim ir meta-komentārs par 4. maija oficiālā nosaukuma simboliku post-Soviet kontekstā. Tuvākā kanoniskā kategorija ir ''vēsturiskā atmiņa'', kas ievietota zem ''Ukraina un Krievija'' grupas src/topic_map.py.', 0.4, 'https://x.com/Lato_Lapsa/status/2051216836830646379', '2026-05-04 00:00:00', '2026-05-04 14:48:38', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17826, 182, 29719, 'Ukraina un Krievija', 'Atbalsta starptautisko sabiedrības uzmanības pievēršanu Krievijas īstenotajai Ukrainas bērnu nolaupīšanai no pagaidu okupētajām teritorijām — uzsver, ka franču aktieris Žans Reno atzinis šo nodarījumu mērogu un cietsirdību par motivāciju savam jaunajam detektīvromānam.', 'French actor Jean Reno has released a detective novel largely inspired by the tragic accounts of Ukrainian children abducted by Russia from temporarily occupied territories of Ukraine. Reno stated that he was profoundly moved by the sheer scale and cruelty of these actions and felt a compelling need to reflect this reality in his writing', 0.8, 'Tvīts angļu valodā, kurā Ozols pārstāsta un faktiski apstiprina Reno teikto par Krievijas bērnu deportācijām. Lai gan tas ir trešās personas paziņojuma retranslācija, Ozols konsekventi uztur šo tematu (sk. iepriekšējo claim 17797 par to pašu romānu); šī ir patstāvīga publiska pozīcija — pievērst rietumu publikas uzmanību nodarījumam.', 0.6, 'https://x.com/OttoOzols/status/2050975294417186819', '2026-05-03 00:00:00', '2026-05-04 14:51:43', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17830, 57, 29858, 'Ukraina un Krievija', 'Sarkastiski apgalvo, ka Progresīvo deputāta Kleinberga publiskais izteikums (acīmredzot tā ekrānšāviņš) ir "perfekts 4. maija Latvijas Republikas 2026. gada portrets" — kritika par Progresīvo lomu mūsdienu Latvijas valsts ainavā vēsturiskās atmiņas (4. maija Atmodas) kontekstā', 'Progresīvajam Kleinbergam, pašam to negribot, ir sanācis perfekts 4.maija Latvijas Republikas 2026.gada portrets.', 0.6, 'Sarkastiska Lapsas pirmpersonas kritika par Progresīvo (Kleinbergs) un mūsdienu "4. maija Republikas" stāvokli — turpina šodienas vēsturiskās atmiņas naratīvu (sk. claim 17816 par 4. maija nosaukumu kā "liekulīgāko"). Stance pamatota tekstā, taču ekrānšāviņa saturs nav redzams, tāpēc confidence vidēja.', 0.5, 'https://x.com/Lato_Lapsa/status/2051272731488813109', '2026-05-04 00:00:00', '2026-05-04 19:21:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17835, 15, 29983, 'Ukraina un Krievija', 'Krievijas piedāvātais pamiers ir propagandas pasākums, jo Krievija turpina raidīt raķetes un dronus pret Ukrainu; svarīgi ir darbi, ne vārdi.', 'Russia launched missiles and drones at Ukraine, while pretending to offer "ceasefire" for their war propaganda event. […] Actions, not words, matter.', 0.85, 'Skaidra pirmpersonas pozīcija no Latvijas ārlietu ministres — noraida Krievijas pamiera retoriku kā propagandu un atbalsta Ukrainas patiesā pamiera piedāvājumu. Tieša politiska nostāja, ne ceremoniāla.', 0.9, 'https://x.com/Braze_Baiba/status/2051591855628853561', '2026-05-05 00:00:00', '2026-05-05 21:05:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17836, 15, 29984, 'Ārpolitika', 'Latvija stingri nosoda Irānas nelikumīgos un nepamatotos uzbrukumus AAE un atbalsta diplomātiskos centienus deeskalācijai un kuģošanas brīvības nodrošināšanai Persijas līcī.', 'Latvia strongly condemns Iran''s illegal and unjustified attacks against the #UAE and stands in our solidarity with our partners in the Gulf. We fully support diplomatic efforts to ensure de-escalation and safeguard freedom of navigation.', 0.9, 'Ārlietu ministre formulē Latvijas oficiālo nostāju — nosoda Irānas uzbrukumus AAE, atbalsta diplomātisko deeskalāciju un kuģošanas brīvību. Pirmpersonas valsts pozīcija.', 0.7, 'https://x.com/Braze_Baiba/status/2051586657917243756', '2026-05-05 00:00:00', '2026-05-05 21:05:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17837, 15, 29979, 'Ukraina un Krievija', 'Latvija piešķir 100 000 eiro Ukrainas atbalsta fondiem (Save Ukraine, ANO Cilvēktiesību monitoringa misijai un ANO ILC fondam), atbalstot Ukrainas bērnu atgriešanu un Krievijas atbildības veicināšanu.', 'Today Latvia allocated €100,000 to support Ukraine: "Save Ukraine", the UN Human Rights Monitoring Mission, and the UN ILC Fund. […] Latvia supports the return of Ukrainian children and promotes accountability for Russia.', 0.9, 'Konkrēta Latvijas valsts politiskā darbība — finansiāls atbalsts Ukrainai un dalība starptautiskajā koalīcijā. Pirmpersonas paziņojums no ārlietu ministres par valdības lēmumu.', 0.8, 'https://x.com/Braze_Baiba/status/2051686057624690866', '2026-05-05 00:00:00', '2026-05-05 21:05:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17847, 57, 30057, 'Aizsardzība un drošība', 'Apsūdz NBS komandieri Kasparu Pudānu publiskā melošanā par krievu droniem un apgalvo, ka Pudānam vairs nav virsnieka goda — tāds virsnieks agrāk drīzāk būtu sevi nošāvis, nekā parakstījis šādu dokumentu.', 'Ne tik senos laikos virsnieks ar virsnieka godu drīzāk būtu šāvies, nekā parakstītu ko šādu. Taču, protams, kāds @nbskomandieris Kasparam Pudānam pēc publiskās melošanas par krievu dronu sakars ar virsnieka godu…', 0.8, 'Lapsa pirmajā personā, savā paša X kontā, formulē konkrētu apsūdzību NBS komandierim Kasparam Pudānam — par publisku melošanu saistībā ar krievu droniem un par parakstu uz dokumenta, ko atbildīgs virsnieks neparakstītu. Tas saskan ar Lapsa iepriekšējo (2026-04-18) NBS ģenerāļa virsnieka goda kritiku — viena un tā pati tēma, atšķirīgs incidents. Pozīcija ir gan personāla integritātes apsūdzība, gan plašāka institucionāla kritika par NBS vadību.', 0.7, 'https://x.com/Lato_Lapsa/status/2051545786224091401', '2026-05-05 00:00:00', '2026-05-05 21:06:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17848, 182, 30078, 'Koalīcija un partijas', 'Pieprasa, lai JV vadība un deputāts Jurēvičs publiski reaģētu uz pierādīto tieslietu ministres Lībiņas-Egneres apzināto melošanu sabiedrībai; uzskata partijas klusēšanu par demokrātiskās ētikas neveiksmi', 'Te ir runa par tieslietu ministri (!!!), kas būtībā sniedz tīšu nepatiesu liecību.', 0.85, 'Ozols garā Twitter/X tekstā tieši formulē pozīciju, ka JV vadība pieņem ministra apzinātu melošanu sabiedrībai kā pašsaprotamu un ka tas ir nepieņemami. Atsaucas uz LSM/Re:Check pārbaudīto faktu un Jurēviča izvairīšanos atbildēt. Pozīcija ir skaidra un konkrēta — pieprasa atbildību JV partijas līmenī. Topic-izvēle: stance galvenokārt ir par partijas reakciju (vai tās trūkumu), tāpēc Koalīcija un partijas, nevis Tieslietas (kas ir tiesu sistēma) vai Korupcija un KNAB (kas ir specifisks korupcijas konteksts).', 0.7, 'https://x.com/OttoOzols/status/2051639901255340248', '2026-05-05 00:00:00', '2026-05-05 21:07:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17849, 182, 30076, 'Ārpolitika', 'Apgalvo, ka 1990.-1991. gadā Rietumu sabiedrotie (Vācija, Francija, ASV) aktīvi neatbalstīja vai pat aicināja klusēt par Baltijas valstu neatkarības centieniem; uzskata, ka šis vēsturiskais fakts būtu godīgi jāatzīst', 'Tieši cik Rietumu sabiedroto valstu steidza atzīt Baltijas valstu neatkarības atjaunošanu 1990. gadā?', 0.7, 'Ozols 4. maija svinību kontekstā formulē retrospektīvu pozīciju par Rietumu attieksmi 1990.-91. gadā. Citē bijušo Islandes ārlietu ministru Hanibalsonu, Buša 1991. gada Kijevas runu, spāņu El Mundo. Pozīcija nav par tagadnes politiku, bet par vēsturisku interpretāciju — kā Latvijai vajadzētu atcerēties saviem sabiedrotajiem; salience tāpēc vidēja.', 0.5, 'https://x.com/OttoOzols/status/2051679201640501669', '2026-05-05 00:00:00', '2026-05-05 21:07:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17877, 15, 30342, 'Ārpolitika', 'Latvija atbalsta Armēnijas ciešāku partnerību ar ES un aicina izmantot pašreizējo momentumu jēgpilnu reformu īstenošanai', 'Latvia is commited to practically supporting Armenia’s closer partnership with the EU. We must use the current momentum to implement meaningful reforms.', 0.85, 'Pirmās personas paziņojums no Erevānas Dialoga foruma sākumā ārlietu ministres darba vizītes laikā. Konkrēta politikas pozīcija par ES paplašināšanas un Armēnijas reformu atbalstu.', 0.7, 'https://x.com/Braze_Baiba/status/2051943223388410111', '2026-05-06 00:00:00', '2026-05-06 21:19:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17878, 15, 30336, 'Ārpolitika', 'Latvijas un Armēnijas divpusējās attiecības un ES-Armēnijas partnerība padziļinās — momentumu izmantot Armēnijas reformu programmas atbalstam', 'Our bilateral ties and the EU-Armenia partnership are growing deeper. We must use the momentum to support Armenia’s reform agenda.', 0.85, 'Pirmās personas paziņojums pēc tikšanās ar Armēnijas ārlietu ministru Mirzojanu. Atkārto un papildina iepriekšējās dienas pozīciju par Armēnijas-ES partnerību ar konkrētu divpusējās tikšanās kontekstu.', 0.6, 'https://x.com/Braze_Baiba/status/2051998392373403825', '2026-05-06 00:00:00', '2026-05-06 21:19:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17879, 15, 30338, 'Kultūra', 'Atbalsta Krievijas dalības Venēcijas Biennālē izmeklēšanu — Latvijas un partneru spiediens devis rezultātus (žūrija atkāpusies, ES finansējums apturēts)', 'Latvijas un partneru rīcība un spiediens nes rezultātus. Žūrija atkāpusies, ES finansējums apturēts, notiek pārbaude, un arī EK ir daudz neatbildētu jautājumu par to, kā @la_Biennale ir nodrošinājusi Krievijas dalību tajā.', 0.9, 'Skaidra pirmās personas pozīcija par Krievijas izolāciju kultūras telpā. Atsaucas uz konkrētu rezultātu (žūrija, ES finansējums, EK izmeklēšana) — tā nav vispārēja deklarācija.', 0.6, 'https://x.com/Braze_Baiba/status/2051952187438223662', '2026-05-06 00:00:00', '2026-05-06 21:19:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17923, 57, 30745, 'Aizsardzība un drošība', 'Pieprasa atstādināt aizsardzības ministru Andri Sprūdu un ārlietu ministru Edgaru Rinkēviču no amatiem, raksturojot tos kā drošības risku Latvijai pieaugošā kara draudu kontekstā.', 'Ar katru nedēļu karš pienāk tuvāk Latvijai, un katra diena, kuru amatos paliek āksts Sprūds, savtīgais nelietis Rinkēvičs un pārējā varza, briesmas tikai tuvina.', 0.75, 'Tiešs pirmpersonas izteikums Lapsas X kontā — konkrēta prasība atbrīvot abus ministrus, nevis tikai vispārējs uzbrukums. Saistīts ar viņa ilgstošo Sprūda kritiku (sk. 2026-04-22, 2026-04-11 claims). Insinuē, ka viņi pasliktina Latvijas drošību; topic-pamatošanai pietiekami.', 0.7, 'https://x.com/Lato_Lapsa/status/2052273441244405903', '2026-05-07 00:00:00', '2026-05-07 10:24:04', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17924, 57, 30748, 'Tieslietas', 'Apgalvo, ka prokuratūras izmeklēšana Levita-Vonsoviča pasūtījuma lietā ir nekompetenti vadīta — sarkastiski norāda, ka prokurors jau trešo reizi pārraksta apsūdzības variantu.', 'Jaunumi Levita-Vonsoviča pasūtījuma lietā: prokuratūrā sameklētais lielākais kretīns sarakstījis jau trešo apsūdzības variantu.', 0.65, 'Pirmpersonas komentārs par konkrētu lietu, kuras hroniku Lapsa publiski seko (sk. arī viņa 30747 grāmatas 3.+4. sējuma anonsi). Insulta forma, bet substantīvi pauž pozīciju: prokuratūras kompetence šajā lietā ir nepietiekama. Salience vidēja — specifiska lieta, ne sistēmiska reforma.', 0.5, 'https://x.com/Lato_Lapsa/status/2052252460912148676', '2026-05-07 00:00:00', '2026-05-07 10:24:04', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17953, 189, 30992, 'Budžets un finanses', 'Apgalvo, ka pēdējo 4 gadu laikā IKP pieaugumu Latvijā veido galvenokārt valsts budžeta izdevumu pieaugums, un noliedz, ka tas ir aizsardzības izdevumu sekas', 'Pēdējo 4 gadu laikā vienīgā pozīcija, kas IKP augusi ievērojami, ir valsts budžeta izdevumi. Un jau apsteidzoši atbildu - nē, tas tikai ļoti nelielā mērā ir valsts aizsardzības izdevumu pieauguma dēļ.', 0.8, 'Tieša pirmpersonas ekonomiskā analīze ar pre-emptive iebildumu pret iespējamu pretargumentu. Pūce konkrēti raksturo IKP struktūras maiņu un noraida konkrētu skaidrojumu (aizsardzības izdevumi).', 0.75, 'https://x.com/pucej/status/2052303721619419229', '2026-05-07 00:00:00', '2026-05-07 15:54:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17976, 15, 31216, 'Ukraina un Krievija', 'Latvija turpinās piegādāt ieročus, apmācību un visaptverošu palīdzību Ukrainai, lai apmierinātu tās steidzamās kaujas lauka un citas vajadzības — apliecināts NATO NSATU štābā Vīsbādenē', 'Latvia will continue to provide weapons, training, and other comprehensive assistance to meet Ukraine’s urgent battlefield and other needs.', 0.85, 'Pirmās personas tvīts no Brazes konta pēc apmeklējuma NATO Security Assistance and Training for Ukraine (NSATU) štābā Vīsbādenē. Apstiprina Latvijas turpinātu militāro atbalstu Ukrainai konkrētā NATO struktūras kontekstā. Saskan ar iepriekšējām pozīcijām, bet ar jaunu specifiku (Vīsbādenes vizīte, NSATU sadarbība).', 0.8, 'https://x.com/Braze_Baiba/status/2052390490968916218', '2026-05-07 00:00:00', '2026-05-07 20:39:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17994, 15, 31809, 'Ārpolitika', 'Latvija atbalstīs Bahreinas un ASV iesniegto ANO Drošības padomes rezolūcijas projektu par Hormuza jūras šaurumu — Irānas destabilizējošās darbības apdraud kuģošanas drošību un veicina globālu enerģētikas un drošības krīzi.', 'Latvia will support the Bahrain/US #UNSC draft resolution on the Strait of Hormuz. Iran’s destabilising actions undermine maritime security and contribute to a global energy and security crisis.', 0.9, 'Tieša pirmpersonas pozīcija no Braže X profila: Latvija atbalstīs konkrētu Bahreinas/ASV UNSC rezolūcijas projektu par Hormuza šaurumu. Konkrēta jauna nostāja salīdzinot ar #11011 (vispārīgs viedoklis par Irānas destabilizāciju) un #11141 (vispārēja gatavība misijai).', 0.8, 'https://x.com/Braze_Baiba/status/2052796268594724870', '2026-05-08 00:00:00', '2026-05-08 20:48:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17995, 15, 31522, 'Droni', 'Latvija un citas Baltijas valstis nav atļāvušas izmantot savu gaisa telpu Ukrainas droniem pret Krieviju — apgalvojums par pretējo ir Krievijas dezinformācija; visu dronu incidentu cēlonis ir Krievijas karš pret Ukrainu.', 'Uzsvēru, ka Baltijas valstis neļauj izmantot gaisa telpu 🇺🇦 droniem, tā ir KF dezinformācija.', 0.9, 'Pirmpersonas paziņojums sarunā ar Ukrainas ārlietu ministru Sibihu — Braže publiski noraida Krievijas dezinformācijas tēzi par Latvijas/Baltijas gaisa telpas izmantošanu. Konkrēta jauna pretdezinformācijas pozīcija. Doc 31523 ir tas pats izteikums angļu valodā — neģenerēju duplicate, tikai LV versiju.', 0.7, 'https://x.com/Braze_Baiba/status/2052750203732549901', '2026-05-08 00:00:00', '2026-05-08 20:48:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17996, 15, 31528, 'ES politika', 'Līdzīgi domājošo ES sabiedroto formātā Vācijā jāstiprina transatlantiskā sadarbība, Eiropas aizsardzības spējas, atbalsts Ukrainai un ES loma Krievijas ierobežošanā — gatavojoties NATO ministru sanāksmei Zviedrijā un Ankaras samitam.', 'Līdzīgi domājošie sabiedrotie tiekas Vācijā pēc @AussenMinDE un @Antonio_Tajani ielūguma par transatlantisko sadarbību, Eiropas aizsardzības spējām, gatavību NATO ministru sanāksmei Zviedrijā un Samitam Ankarā, atbalstu Ukrainai, ES lomu Krievijas ierobežošanā.', 0.75, 'Pirmpersonas X paziņojums no Braže par dalību ES līdzīgi domājošo formātā Vācijā. Pozīcija saturiski apstiprina jau zināmo Latvijas ārlietu līniju (transatl. sadarbība, ES aizsardzība, atbalsts UA), bet ar konkrētu kontekstu (formāts pirms NATO Zviedrijas un Ankaras samita).', 0.6, 'https://x.com/Braze_Baiba/status/2052691959458779626', '2026-05-08 00:00:00', '2026-05-08 20:48:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17997, 57, 31910, 'Korupcija un KNAB', 'Apšauba Andra Sprūda valsts amatpersonas deklarācijas patiesumu — uzdod publisku jautājumu par ''mistiskā vectēva'' identitāti, norādot, ka deklarētie ģimenes locekļi nesader ar bērnu izcelsmi.', 'Šis ir interesants atjautības uzdevums - ja beztautības progresīvajam Andrim Sprūdam ir šādi deklarēti ģimenes locekļi (mazgadīgie bērni nav jādeklarē), kas ir viņa bērnu vectēvs?', 0.75, 'Lapsa pirmajā personā publiski apšauba valsts amatpersonas (aizsardzības ministra Sprūda) deklarācijas pilnīgumu, izmantojot retorisku jautājumu kā insinuāciju. Tas ir ierasts Lapsas modus operandi — investigatīva korupcijas/integritātes kritika.', 0.65, 'https://x.com/Lato_Lapsa/status/2052765494042607753', '2026-05-08 00:00:00', '2026-05-08 20:48:50', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17998, 57, 31614, 'Sabiedriskie mediji', 'Apsūdz LTV ziņu dienestu (Ivetas Elksnes vadībā) pārkrievošanā un pieprasa atbildības saukšanu.', 'Pārkrievotajam Ivetas Elksnes vadītajam ''sabiedriskās'' televīzijas ziņu dienestam ir ''jānes atbildība''.', 0.8, 'Tieša pirmās personas pozīcija — Lapsa kvalificē LTV ziņu dienestu kā ''pārkrievotu'' un prasa atbildību. Skaidra pozīcija sabiedrisko mediju vadības jautājumā; pēdiņas ap ''sabiedriskās'' un ''jānes atbildība'' ir sarkastiskas, bet pamatpozīcija ir nepārprotama.', 0.7, 'https://x.com/Lato_Lapsa/status/2052656828748550326', '2026-05-08 00:00:00', '2026-05-08 20:48:50', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (17999, 57, 31621, 'Korupcija un KNAB', 'Apsūdz amatpersonu (norāda kā ''Āksts'') dienesta auto izmantošanā personīgām vajadzībām — brauciens uz Rēzekni dronu vietas apmeklēšanas aizsegā, lai nokļūtu mājās.', 'Labrīt, stulbie nodokļu maksātāji. Āksts par Jūsu naudu dienesta auto dodas tūrisma braucienā uz Rēzekni - ''apmeklēt drona nokrišanas vietu''.', 0.7, 'Lapsa pirmajā personā apsūdz neidentificētu amatpersonu valsts resursu (dienesta auto + nodokļu maksātāju nauda) personīgā izmantošanā. Konteksts (drona nokrišanas vieta + Rēzekne) saista ar reālu notikumu, bet konkrētais subjekts vārdā nav nosaukts — tādēļ piesardzīga konfidence.', 0.6, 'https://x.com/Lato_Lapsa/status/2052639185853354026', '2026-05-08 00:00:00', '2026-05-08 20:48:50', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18042, 182, 31915, 'Ukraina un Krievija', 'Iebilst pret krievu kultūras pielīdzināšanu Putinisma režīmam — uzskata, ka māksla un mākslinieki kalpo garam, nevis varai, un Kremļa psihopātu bandas mēģinājumi izmantot krievu kultūru saviem noziedzīgajiem mērķiem nenozīmē, ka kultūra būtu identificējama ar noziedzniekiem.', 'It is crucial not to conflate two fundamentally distinct concepts: Russian culture and Putlerism. The gang of psychopaths in the Kremlin is attempting to exploit the former for their own criminal ends, but that does not mean Russian culture should be equated with criminals.', 0.75, 'Ozola pirmās personas tvīts ar nepārprotamu pozīciju par krievu kultūras un Putinisma režīma nodalīšanu. Skaidrs viedoklis, kas atbilst viņa publiskajai retorikai par Krievijas tēmu.', 0.55, 'https://x.com/OttoOzols/status/2052753351687667987', '2026-05-08 00:00:00', '2026-05-08 21:00:09', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18053, 57, 32231, 'Koalīcija un partijas', 'Apsūdz Aināru Šleseru un viņa politisko nometni (LPV) sabiedrības apzinātā maldināšanā un atgādina Šlesera lomu Parex bankas krīzē — apgalvo, ka šie politiķi uzskata vēlētājus par ''nožēlojamiem idiotiem''.', 'Šlesers… iegrūda Parex…😄 Šie kabatas vaukšķi jēkabsoni uzskata Jūs par nožēlojamiem idiotiem, kuri ņems pretī visnožēlojamākos melus.', 0.65, 'Lapsa pirmajā personā tvītā 09.05. saista Šleseru ar Parex bankas krīzes vēsturisko atbildību un izsaka tiešu politisku apsūdzību par vēlētāju maldināšanu. Sarkastisks tonis, bet pozīcija ir konkrēta — Šlesera nometne pielieto melus.', 0.5, 'https://x.com/Lato_Lapsa/status/2053109313737019551', '2026-05-09 00:00:00', '2026-05-10 07:29:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18054, 15, 32089, 'Kultūra', 'Kultūra nedrīkst kļūt par patvērumu tiem, kuri to iznīcina — Eiropas vērtību aizstāvēšana nozīmē stāvēt kopā ar Ukrainu (viedokļa raksts Kyiv Independent Eiropas dienā).', 'Culture cannot become a shelter for those who destroy it. Defending Europe''s values also means standing with Ukraine.', 0.85, 'Pirmpersonas tvīts, kurā Braže paziņo par savu viedokļa rakstu Kyiv Independent un formulē tā centrālo tēzi. Tematiski paplašina iepriekšējās Venēcijas Biennāles pozīcijas (2026-04-17, 2026-04-27, 2026-05-06) līdz vispārīgam principam par Krievijas izstumšanu no Eiropas kultūras telpas Eiropas dienas kontekstā. Atsevišķs raksts ar publicētu URL — atšķirīgs avots un formulējums no iepriekšējiem Biennāles izteikumiem.', 0.6, 'https://x.com/Braze_Baiba/status/2053074173119877263', '2026-05-09 00:00:00', '2026-05-10 07:29:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18062, 30, 32111, 'Koalīcija un partijas', 'Politiskām idejām nav un nedrīkst būt ''autortiesības'' — idejas politikā jēga rodas tikai tad, ja tās ir brīvi izmantojamas un modificējamas; ja konkurenti pārņem MMN piegājienus, tas tiek vērtēts kā politisks panākums, nevis ''zādzība''.', 'Politikā priekšlikumu autorībai ir nulle nozīmes. Politisku ideju autortiesības nav vispār savietojamas ar demokrātisku politiku, jo idejai politikā jēga ir tikai tad, ja tā ir brīvi izmantojama, brīvi modificējama un brīvi atmetama bez saskaņojuma ar ''autoru''.', 0.85, 'Tvīts ir saturīgs pirmās personas pozicionējums par politisko procesu un MMN stratēģiju — Baško tieši formulē savu pieeju attiecībā uz idejas autorību un definē, kā partija interpretēs panākumu (pat ja idejas pārņem konkurenti). Tā ir reāla, citējama nostāja, ne ceremoniāls saturs.', 0.5, 'https://x.com/JazepsBasko/status/2052990388273627261', '2026-05-09 00:00:00', '2026-05-10 07:30:56', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18084, 189, 32541, 'Aizsardzība un drošība', 'Atbalsta Sprūda atlaišanu no aizsardzības ministra amata, motivējot to galvenokārt ar 3 gadu nesakārtotu darbu Aizsardzības ministrijā, ne tikai ar 2 droniem Rēzeknē; vienlaikus apšauba Siliņas izvēles standartus, norādot uz Kozlovska iekšlietu darbu kā pretrunīgu piemēru', 'Skaidrs, ka @AndrisSpruds bija jāatlaiž. Ne tik daudz par 2 droniem Rēzeknē, cik par 3 nomuļļātiem gadiem Aizsardzības ministrijā. Bet tikai ko labu pēc tādas mērauklas @EvikaSilina saskata, piemēram, Kozlovska darbā? 4 gadi atkal izšķērdēti, bet premjerei viss ok.', 0.9, 'Pirmpersonas pozīcija X tvītā 2026-05-10 plkst. 16:24 — pēc Sprūda atlūguma iesniegšanas. Pūce skaidri atbalsta atlaišanu ("bija jāatlaiž") un norāda iemeslu — 3 gadu nesakārtots darbs ministrijā. Vienlaikus paplašina kritiku uz Kozlovski un Siliņas izvēles kritērijiem. Konsistenti ar iepriekšēju pozīciju #14465 (2026-04-22) par diviem ministrijas pametušajiem valsts sekretāriem — tas ir naturāls eskalācijas turpinājums, ne pretruna.', 0.85, 'https://x.com/pucej/status/2053511415290323019', '2026-05-10 00:00:00', '2026-05-10 23:24:47', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18099, 15, 32855, 'Aizsardzība un drošība', 'Atbalsta Ministru prezidentes Siliņas lēmumu izvirzīt NBS pulkvedi un aizsardzības padomnieku Ukrainā Raivi Melni aizsardzības ministra amatā — kompetentai, mērķtiecīgai AiM vadībai ārpus priekšvēlēšanu retorikas', 'Premjere @EvikaSilina uzskata, ka valsts aizsardzībai nepieciešama cita, profesionāla, pieeja. Viņa ir aicinājusi NBS pulkvedi, aizsardzības padomnieku Ukrainā Raivi Melni, stāties ministra amatā, lai kompetenti, mērķtiecīgi un ārpus priekšvēlēšanu retorikas vadītu AiM.', 0.75, 'Bražes paša X paziņojums 2026-05-10 vakarā pēc Sprūda atkāpšanās — atbalsta Siliņas izvirzīto profesionālo (NBS pulkveža) pieeju, nostājoties pretī progresīvo politiskajām prasībām. Pozicionē Melņa profesionālo profilu kā kontrastu ''priekšvēlēšanu retorikai''.', 0.8, 'https://x.com/Braze_Baiba/status/2053571754493169921', '2026-05-10 00:00:00', '2026-05-11 16:27:02', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18100, 15, 32853, 'Ukraina un Krievija', 'Latvija turpinās atbalstīt Ukrainu, virzīt tās eiroatlantisko integrāciju un ierobežot Krieviju — jo stiprāka Ukraina kaujas laukā, jo stiprāka tās pozīcija sarunu galdā un labākas izredzes uz taisnīgu un ilgstošu mieru', 'The stronger Ukraine is on the battlefield, the stronger its position at the negotiating table and better chances for a just and lasting peace.', 0.85, 'Pašas Bražes X paziņojums pēc tikšanās ar Ukrainas ĀM Sibihu Briselē. Skaidra pozīcija par ''peace through strength'' loģiku — militārā atbalsta turpināšana ir priekšnoteikums diplomātiskajām sarunām.', 0.85, 'https://x.com/Braze_Baiba/status/2053772433316823445', '2026-05-11 00:00:00', '2026-05-11 16:27:02', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18101, 15, 32723, 'Droni', 'Rēzeknē nokritušie Ukrainas droni novirzījušies uz Latviju Krievijas apzinātas elektroniskās karadarbības rezultātā — Krievijai atbildība par dronu nokļūšanu Latvijas teritorijā', 'izmeklēšanā noskaidrots – Ukrainas droni, kas mērķēti Krievijas militārajiem objektiem, apzinātas Krievijas rīcības rezultātā ir novirzīti uz Latviju', 0.8, 'LSM raksts citē Bražes X paziņojumu pēc sarunas ar Ukrainas ĀM Sibihu — Braže publiski apstiprina, ka izmeklēšana piedēvē atbildību Krievijas elektroniskajai karadarbībai, NEVIS Ukrainai. Tas ir pretarguments tiem, kas saistīja dronu incidentu ar Ukrainas vainu.', 0.85, 'https://www.lsm.lv/raksts/zinas/latvija/10.05.2026-ukrainas-arlietu-ministrs-rezekne-nokritusie-droni-novirzijusies-uz-latviju-krievijas-elektroniskas-karadarbibas-del.a646487/?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-10 00:00:00', '2026-05-11 16:27:02', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18104, 72, 32897, 'Koalīcija un partijas', 'Pieprasa pašreizējās Siliņas valdības atkāpšanos un pauž gatavību veidot nacionālās drošības valdību kopā ar Apvienoto sarakstu, ZZS un Jauno Vienotību', 'Valdībai ir jāatkāpjas. Esmu gatava veidot nacionālās drošības valdību. Mēs aicināsim uz sarunu AS, ZZS un JV, lai lemtu par iespējām izveidot rīcībspējīgu valdību.', 0.95, 'NA priekšsēdētājas tiešs paziņojums X tvītu sērijā (1/4) 2026-05-11 pēc Sprūda demisijas. Skaidra pirmās personas pozīcija ar konkrētiem koalīcijas partneru uzaicinājumiem. Apstiprina arī Delfi raksts 32747, kur Indriksone tieši citēta kā runātāja.', 0.95, 'https://x.com/IIndriksone/status/2053752925646627106', '2026-05-11 00:00:00', '2026-05-11 16:27:28', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18107, 189, 32936, 'Koalīcija un partijas', 'Kritizē abas valdības partijas (JV un PRO) par publisku sacensību X-ā par Sprūda atkāpšanās paziņošanu — uzskata, ka tas demonstrē, ka valsts drošība nav koalīcijai patiesā prioritāte.', 'Divas valdības partijas sacenšas, kura ātrāk X-ā paziņos - vai Sprūds ir atlaists vai pats atkāpies. Tad pēc tam strīdas, kurš kuram ir vai nav zvanījis. Tā, acīmredzot, viņi demonstrē to, ka valsts drošība un aizsardzība viņiem ir milzīga prioritāte.', 0.8, 'Pūce kā opozīcijas politiķis (LA) sarkastiski kritizē JV un PRO par publisku komunikācijas sacensību saistībā ar Sprūda demisiju 2026-05-10. Pirmās personas pozīcija ar konkrētu kritikas adresi — koalīcijas darba kultūra. Saistīts ar iepriekšējo claim 2026-05-10 par Sprūda atlaišanu, bet šis ir atsevišķa pozīcija par koalīcijas komunikāciju.', 0.6, 'https://x.com/pucej/status/2053710895218307541', '2026-05-11 00:00:00', '2026-05-11 16:28:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18108, 189, 32937, 'Sabiedriskie mediji', 'Kritizē LTV De facto raidījumu par to, ka kartelī iesaistītā uzņēmuma PLG saiknes ar Progresīvo politiķi Staķi nav atspoguļotas, un pārmet, ka 4 dienās nav lūgts Staķa komentārs.', 'Par ko nebija sižets @ltvdefacto? Par to, ka kartelī ir iesaistīts uzņēmums, kura PLG ir Progresīvo populārākais politiķis un pattijas valdes loceklis Staķis. Cita starpā, sabiedriskais medijs 4 dienu laikā tā arī nav paprasījis viņa komentāru par notikušo.', 0.75, 'Pirmās personas pozīcija — Pūce konkrēti kritizē sabiedrisko mediju (LTV) par redakcionālu izvēli neiekļaut sižetā Staķa (Progresīvie) saistību ar kartelī iesaistītu uzņēmumu kā patiesā labuma guvēju. Divas pozīcijas saplūstas: (1) PSV redakcionālā izvēle, (2) implicītā Staķa korupcijas kritika. Topic = Sabiedriskie mediji (galvenais kritikas adresats). NEEDS_REVIEW: varētu būt arī Korupcija un KNAB jo tiek izvirzīta korupcijas alūzija (PLG karteļa uzņēmumā), bet primārā kritika ir par PSV nepilnīgu sižetu — izvēlējos Sabiedriskie mediji.', 0.6, 'https://x.com/pucej/status/2053567441788141624', '2026-05-10 00:00:00', '2026-05-11 16:28:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18148, 15, 33244, 'Ārpolitika', 'Tuvāka ES–Kanādas sadarbība pret Krievijas un citiem draudiem, Ukrainas atbalstam un savstarpēji izdevīgai ekonomiskai sadarbībai', 'Great to meet Canada''s Foreign minister @AnitaAnandMP again to exchange views on closer EU-Canada cooperation to counter threats from Russia and other challenges, to support Ukraine, and to advance mutually beneficial economic cooperation.', 0.7, 'Diplomātiskās tikšanās readout — Braže pirmajā personā formulē sadarbības prioritātes (ES–Kanāda, pretdarbība Krievijai, Ukrainas atbalsts, ekonomika). Standarta diplomātiska pozīcija bez konkrētiem soļiem, tāpēc confidence 0.7 un salience 0.4 (procedural meeting).', 0.4, 'https://x.com/Braze_Baiba/status/2053868701720494551', '2026-05-11 00:00:00', '2026-05-11 20:23:56', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18149, 15, 33247, 'Ukraina un Krievija', 'Atbalsta ES jaunās sankcijas pret 16 personām un 7 organizācijām, kas atbildīgas par Ukrainas bērnu deportāciju, piespiedu pārvietošanu, pārkrievošanu un nelikumīgu adopciju — ~1,6 miljoni Ukrainas bērnu joprojām Krievijas kontrolē', 'Šodien ES Padomē pieņēmām jaunas sankcijas pret 16 personām un 7 organizācijām, kas atbildīgas par: Ukrainas bērnu deportāciju, piespiedu pārvietošanu, pārkrievošanu un asimilāciju, nelikumīgu adopciju. ~1,6 miljoni bērnu joprojām atrodas Krievijas kontrolē.', 0.9, 'Pirmās personas formulējums (''pieņēmām'') — Braže kā Latvijas ārlietu ministre piedalījās ES Ārlietu padomes lēmumā par sankcijām. Konkrēts politikas akts ar skaitliskiem mērķiem (16+7) un kontekstu (1,6M bērnu). High-salience Ukraina un Krievija tēmas pozīcija.', 0.8, 'https://x.com/Braze_Baiba/status/2053846895835975892', '2026-05-11 00:00:00', '2026-05-11 20:23:56', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18150, 15, 33248, 'Aizsardzība un drošība', 'NATO austrumu flanga atturēšana un aizsardzība jāstiprina caur Latvijas pretgaisa aizsardzības spēju stiprināšanu, NATO klātbūtnes palielināšanu reģionā un gatavošanos NATO samitam Ankarā', 'Vērtīga tikšanās ar NATO Ģenerālsekretāru Marku Ruti par praktiskiem soļiem NATO atturēšanas un aizsardzības stiprināšanai alianses austrumu flangā: Latvijas Pretgaisa aizsardzības spēju stiprināšanu, NATO klātbūtnes palielināšanu reģionā, Gatavošanos NATO samitam Ankarā', 0.85, 'Pirmās personas readout no tikšanās ar NATO ĢS Rutti. Trīs konkrēti aizsardzības prioritāšu punkti — pretgaisa aizsardzība, NATO klātbūtne austrumu flangā, Ankaras samits. Mainstream Latvijas drošības pozīcija, bet konkrēti formulēta.', 0.8, 'https://x.com/Braze_Baiba/status/2053830914832998764', '2026-05-11 00:00:00', '2026-05-11 20:23:56', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18151, 15, 33250, 'Ārpolitika', 'Latvija turpina atbalstīt OHR (Augstā pārstāvja birojs Bosnijā un Hercegovinā) mandātu uzturēt Deitonas miera līgumu; pateicība Christian Schmidt par ieguldījumu B&H drošā nākotnē', 'We thank Christian Schmidt for his commitment and vital contribution to a secure and prosperous future of Bosnia and Herzegovina during his term as the High Representative. Latvia continues to support @OHR_BiH in carrying out their mandate to uphold the Dayton Peace Agreement.', 0.8, 'Pirmās personas (''Latvia continues to support'') pozīcija par Bosnijas un Hercegovinas politiku — atbalsts OHR un Deitonas miera līgumam. Specifiska Rietumbalkānu ārpolitikas pozīcija, retāk Latvijas dienaskārtībā, tāpēc salience 0.5.', 0.5, 'https://x.com/Braze_Baiba/status/2053824962230726871', '2026-05-11 00:00:00', '2026-05-11 20:23:56', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18156, 189, 33269, 'Koalīcija un partijas', 'Apšauba koalīcijas darbspēju pēc Sprūda demisijas — pieprasa premjerei publiski paskaidrot, vai ir balsis Meļņa apstiprināšanai un valdības iniciatīvām (iepirkumu likums, pašvaldību likums)', 'Gribētos dzirdēt no premjeres, kā viņa praktiski iedomājas koalīcijas darbu. Piemēram, vai ir balsis Meļņa apstiprināšanai? Vai ir balsis tām valdibas iniciatīvām, kas jau ir Saeimā vai ir ceļā uz to? Iepirkumu likums? Pašvaldību likums?', 0.8, 'Pirmpersonas pozīcija — retoriski jautājumi, kas faktiski pauž skepsi par koalīcijas balsstiesīgumu pēc Sprūda demisijas un Progresīvo iespējamās izstāšanās. Pūce uzdod jautājumus, lai signalizētu, ka koalīcijai trūkst skaidras balsu majoritātes konkrētiem darbiem.', 0.7, 'https://x.com/pucej/status/2053882633147318745', '2026-05-11 00:00:00', '2026-05-11 20:25:05', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18157, 189, 33270, 'Aizsardzība un drošība', 'Kritizē Aizsardzības ministrijas pārvaldību — uzrāda, ka 1,5 gada laikā ministriju pametuši 74 no 311 ierēdņiem (54 2025.g., 20 2026.g.), un ironizē, ka iestāde vēl spēj funkcionēt', '2025.gadā no AizsM aizgājuši 54 ierēdņi un 2026.gadā jau 20 ierēdņi. Kopā pusotra gada laikā 74 no 311(318). Brinums, ka tā iestāde vēl vispār funkcionē.', 0.9, 'Konkrēti dati ar tiešu kritisku slēdzienu par AizsM pārvaldības problēmām. Plašāka apgalvojuma forma nekā iepriekšējais 2026-04-22 tvīts (kas bija tikai par diviem valsts sekretāriem) — papildina, nepretrunā.', 0.7, 'https://x.com/pucej/status/2053880738395594861', '2026-05-11 00:00:00', '2026-05-11 20:25:06', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18183, 72, 33387, 'Koalīcija un partijas', 'Siliņas valdība nesagāzīsies un nostrādās līdz termiņa beigām, tomēr nespēs pieņemt lielus un būtiskus lēmumus dēļ koalīcijas savstarpējiem strīdiem', 'valdība spēs "nesagāzties" un nostrādāt līdz termiņa beigām, tomēr nespēs pieņemt lielus un būtiskus lēmumus', 0.9, 'Tieša Indriksones prognoze 2026-03-03 par valdības noturību. Saskan ar 2024-12-05 pozīciju, bet pretrunā ar 2026-05-11 šodien pieprasīto Siliņas atkāpšanos – iespējamais kandidāts pretrunai #18104-18106 (no nesagāzīsies/nostrādās līdz termiņam → uz pieprasījumu atkāpties pēc 2 mēnešiem).', 0.9, 'https://www.lsm.lv/raksts/zinas/latvija/03.03.2026-nacionalas-apvienibas-lidere-indriksone-sis-valdibas-lielaka-problema-katrs-strada-par-sevi.a637101/', '2026-03-03 00:00:00', '2026-05-11 23:33:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18216, 15, 33497, 'Ukraina un Krievija', 'Atbalsta Ukrainas bērnu atgriešanas koalīciju un Krievijas darbības kvalificē kā noziegumu pret Ģenocīda konvenciju', 'Russia''s mass kidnapping and deportation of Ukrainian children is a crime under the Genocide Convention. Latvia supports all practical efforts to #BringThemHome', 0.9, 'Tiešs pirmās personas izteikums angļu valodā ar konkrētu juridisku kvalifikāciju un Latvijas atbalstu Kanādas-Ukrainas vadītajai koalīcijai.', 0.7, 'https://x.com/Braze_Baiba/status/2053893233361453118', '2026-05-11 00:00:00', '2026-05-12 12:01:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18217, 15, 32480, 'Droni', 'Apgalvo, ka Krievija apzināti novirzījusi Ukrainas dronus, lai tie nokristu Latvijā', 'Ukrainas droni, kas mērķēti Krievijas militārajiem objektiem, apzinātas Krievijas rīcības rezultātā ir novirzīti uz Latviju, kur nokrita.', 0.85, 'Tiešs pirmās personas izteikums ar konkrētu apgalvojumu par Krievijas apzinātu darbību dronu incidentu kontekstā Latvijā. Atsauce uz Ukrainas ārlietu ministra izmeklēšanu kā pamatojumu.', 0.8, 'https://x.com/Braze_Baiba/status/2053519435118317686', '2026-05-10 00:00:00', '2026-05-12 12:01:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18218, 15, 32482, 'ES politika', 'ES Ārlietu padomē izvirza prioritātes: atbalsts Ukrainai (drošības garantijas, militārā palīdzība, ceļš uz ES), spiediens uz Krieviju un 21. sankciju pakete', 'Support for Ukraine: security guarantees, military aid & progress towards EU; Pressure on Russia & work on the EU''s 21st sanctions package', 0.85, 'Pirmās personas izteikums par konkrētu darba kārtību ES Ārlietu padomē — saturīga politikas pozīcija, ne tikai ceremoniāls anonss (nosauc 21. sankciju paketi un konkrētus mērķus).', 0.75, 'https://x.com/Braze_Baiba/status/2053476135975952788', '2026-05-10 00:00:00', '2026-05-12 12:01:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18219, 15, 32483, 'Aizsardzība un drošība', 'Pateicas drošības dienestiem un Valsts policijai par to, ka Krievijas kara propagandas pasākumi Latvijā nenotika', 'Paldies drošības dienestiem un Valsts policijai par rūpēm par mūsu drošību un sabiedrisko kārtību, lai Krievijas kara propagandas pasākumi Latvijā nenotiktu.', 0.8, 'Pirmās personas pozitīvs vērtējums dienestu rīcībai novērst Krievijas propagandas pasākumus Latvijā — atbalsta šādu preventīvu pieeju.', 0.6, 'https://x.com/Braze_Baiba/status/2053408804583121117', '2026-05-10 00:00:00', '2026-05-12 12:01:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18286, 15, 33845, 'Ukraina un Krievija', 'Apgalvo, ka Ukraina, ASV un Eiropa vēlas mieru, un vienīgais šķērslis mieram ir Putins, kurš vēlas turpināt imperiālistisko karu, lai pakļautu Ukrainu un iznīcinātu tās demokrātiskās institūcijas, identitāti, valodu un kultūru.', 'Ukraine wants peace, the U.S. wants peace, Europe wants peace. The only obstacle to peace is the butcher in kremlin, who wants his imperialistic war to continue to subjugate Ukraine, erase its democratic institutions, identity, language and culture.', 0.9, 'Pirmpersonas X tvīts (angliski) 12.05 09:35 — distinkts no claim 18100 (vispārējs Latvijas atbalsts Ukrainai), jo šeit ir konkrēts retoriskais positionings: nosauc Putinu personīgi par ''butcher in kremlin'' un kā vienīgo miera šķērsli. Stratēģisks ārpolitisks paziņojums ASV–EU–UA ass kontekstā.', 0.75, 'https://x.com/Braze_Baiba/status/2054133238751285419', '2026-05-12 00:00:00', '2026-05-12 20:46:13', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18300, 57, 34201, 'Aizsardzība un drošība', 'Pieprasa atstādināt Aizsardzības ministrijas galveno ierēdni (valsts sekretāra līmenī) — raksturo kā melotāju un pagļēvu bezprincipu konformistu, kuram nav vietas AM vadībā; sarkastiski jautā, kur palicis sabiedrības spiediens.', 'Kur tad sabiedrības spiediens palika?🤡 Protams, visiem viss skaidrs, bet - vai tiešām Aizsardzības ministrijai vajag galveno ierēdni, kurš nule ir prasti melojis sabiedrībai un sevi parādījis kā pagļēvu bezprincipu konformistu?', 0.7, 'Lapsas paša first-party tvīts (nav RT), formulēts retorisku jautājumu veidā, bet ar skaidri pausto pozīciju: AM galvenajam ierēdnim jāatkāpjas / jātiek atstādinātam. Sasaucas ar prior Lapsas claim #11286 (2026-04-22) par AM valsts sekretāru izmaiņām un #17923 (2026-05-07) par Sprūda atstādināšanas pieprasījumu. Konkrētais ierēdnis nav nosaukts vārdā, bet konteksts (AM galvenais ierēdnis, sabiedrības spiediens, nesena publiska melošana) skaidri norāda uz valsts sekretāra līmeņa amatpersonu.', 0.65, 'https://x.com/Lato_Lapsa/status/2054455101331284282', '2026-05-13 00:00:00', '2026-05-13 16:22:19', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18301, 15, 34400, 'Koalīcija un partijas', 'Kritizē Progresīvos, apgalvojot, ka partijas rīcība ir pretēja valsts aizsardzības un drošības pamatinteresēm un ka tā liek savu ego pāri šīm interesēm.', 'Diemžēl t.s. progresīvo rīcība ir pretēja valsts aizsardzības un drošības pamatinteresēm, savus ego liekot tām pāri.', 0.85, 'Pirmā-lica īss tvīts ar konkrētu normatīvu apgalvojumu pret koalīcijas partneri Progresīvajiem. Konteksts: 2026-05-13, dienu pēc Sprūda (PRO) atkāpšanās 10.05 pēc Siliņas (JV) ultimāta. Tvītā izteiktā valorize (''savus ego liekot tām pāri'') norāda uz konkrētu pretenziju, ne ceremoniālu izteikumu. Topic = Koalīcija un partijas, jo pozīcijas ass ir partijas (Progresīvo) novērtējums, ne abstrakta aizsardzības politika.', 0.7, 'https://x.com/Braze_Baiba/status/2054540035983061462', '2026-05-13 00:00:00', '2026-05-13 16:48:19', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18303, 189, 34459, 'Koalīcija un partijas', 'Norāda uz Progresīvo partijas nekonsekvenci — partija publiski paziņoja neuzticību Siliņai, bet ministri Švinka un Lāce paliek valdībā.', 'Progresīvie Siliņai vairs neuzticas, bet Švinka un Lāce turpinās strādāt Siliņas vadītā valdībā.', 0.7, 'Pūce X-ierakstā ar sarkastisku tonālitāti (''tas ir kapitāli'') uzsver, ka PRO partijas oficiālā nostāja (neuzticība) ir pretrunā ar tās ministru rīcību (palikšana amatos). Tā ir konkrēta politiska kritika, kas atšķiras no claim #18107 (kas attiecās uz JV/PRO publisko sacensību par Sprūda paziņošanu) — šeit fokuss ir PRO iekšējā pretruna.', 0.5, 'https://x.com/pucej/status/2054543312426619200', '2026-05-13 00:00:00', '2026-05-13 16:49:03', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18304, 189, 34462, 'Koalīcija un partijas', 'Raksturo Latvijas koalīciju kā de facto neesošu — ''Šrēdingera koalīcija'', kuras dzīvotspēja zūd, līdzko to pārbauda; partneri jau gatavojas ''bērēm''.', 'Latvijai ir gandrīz Šrēdingera koalīcija — kamēr neskatās virsū, nekādi nevar pateikt — dzīva vai mirusi. Ja paskatās, tad gan viss skaidrs. Tagad tikai mirušās koalīcijas partneri atliek bēres.', 0.65, 'Metaforiska, bet konkrēta politiska novērtējuma izteikšana — koalīcija nav darbspējīga. Eskalē 11.05 nostāju (#18156, kur ''apšauba koalīcijas darbspēju'') uz spēcīgāku formulējumu (''mirusi''). Tas nav pretruna ar 18156 — tas ir tās pašas trajektorijas turpinājums un intensifikācija. Saglabāju kā atsevišķu pozīciju, jo 13.05 ir cita diena un cita konteksta intensitāte (pēc tam, kad PRO valde 11.05 lēma par dalību).', 0.55, 'https://x.com/pucej/status/2054506665081245746', '2026-05-13 00:00:00', '2026-05-13 16:49:03', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18322, 189, 34888, 'Koalīcija un partijas', 'Apgalvo, ka Vienotība un Progresīvie ar Siliņas valdības gāšanu ir atdevuši valdību Nacionālajai apvienībai, Apvienotajam sarakstam un ZZS — šīs partijas tagad būs jaunās koalīcijas centrā.', 'Vienotība un Progresīvie kopīgiem spēkiem atdeva valdību Nacionālajai apvienībai, Apvienotajam sarakstam un ZZS (lai kāda tur koalīcija beigās sastiķēsies - šîs partijas būs valdības centrā).', 0.85, 'Tieša pirmās personas analītiska nostāja Pūces X tvītā 2026-05-14 pēc Siliņas demisijas paziņojuma. Skaidri norāda politisko atbildību par koalīcijas sabrukumu — JV un PRO.', 0.8, 'https://x.com/pucej/status/2054833390373720112', '2026-05-14 00:00:00', '2026-05-14 13:37:58', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18323, 189, 34890, 'Koalīcija un partijas', 'Prognozē, ka vēlētāji vainos JV un PRO par Siliņas valdības gāšanu — atsaucas uz vēsturisko pieredzi (Saimnieks, TP), ka partijas, kas vēlēšanu gadā gāž valdību, cieš smagas politiskas sekas.', 'Latvijas vēsturiskā pieredze ir, ka katrs, kas vēlēšanu gadā gāž valdību, dabū smagi ciest par to. Tā izbeidzās Saimnieks, tā izbeidzās TP.', 0.7, 'Pirmās personas politiska analīze ar konkrētu prognozi (JV un PRO būs vēlētāju atbildības centrā). Salience moderēta — vairāk komentārs nekā konkrēta politikas pozīcija, bet pietiekami specifisks lai uzskatītu par publisku nostāju.', 0.55, 'https://x.com/pucej/status/2054562403791102216', '2026-05-13 00:00:00', '2026-05-14 13:37:58', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18364, 30, 34802, 'Valsts pārvalde', 'Atbalsta valsts pasūtīto aptauju/pētījumu centralizāciju vienā iestādē, lai izbeigtu decentralizētus zemas kvalitātes iepirkumus', 'Aizliegt decentralizēti pasūtīt un finansēt "pētījumus"... Tā vietā uzdod vienam valsts kantorītim, kas uzģenerē tādas blēņas pēc pasūtījuma VISIEM un par grašiem.', 0.8, 'Baško kā MMN ģenerālsekretārs piedāvā konkrētu valsts pārvaldes reformu — aizliegt decentralizētus "pētījumu" iepirkumus, centralizēt vienā struktūrā ("Google Forms priekš valsts"). Skaidri formulēts politikas piedāvājums.', 0.5, 'https://x.com/JazepsBasko/status/2054630957857018238', '2026-05-13 00:00:00', '2026-05-14 13:44:53', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18372, 57, 34934, 'Koalīcija un partijas', 'Pauž asu kritiku Evikas Siliņas valdībai kā ''viskremliskākajai un Latvijai visiznīcinošākajai'' un atzinīgi vērtē tās krišanu', 'Ir kritusi viskremliskākā, Latvijai visiznīcinošākā valdība.', 0.7, 'Tieša pirmās personas vērtējuma izteikums par Siliņas valdību. Lai gan īss, formulējums ir tiešs un nepārprotams politisks vērtējums, ne sarkastiska insinuācija — viņš tieši nosaka, ka šī valdība bija viskaitīgākā Latvijai.', 0.6, 'https://x.com/Lato_Lapsa/status/2054844709776904349', '2026-05-14 00:00:00', '2026-05-14 13:47:07', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (18393, 30, 35519, 'Valodu politika', 'Atbalsta latviešu valodas izmantošanu Eirovīzijas dziesmās un kritizē iepriekšējos gadus, kad sūtītas dziesmas svešvalodā', 'Paldies tiem, kas gādāja, lai otro gadu pēc kārtas sūtām dziesmu latviešu valodā. 27. Eirovīzijas konkurss Latvijai, bet tikai trešo reizi dziedam savā valodā. Vai tiešām 24 reizes svešā mēlē bija tā vērtas?', 0.85, 'Tiešs pirmpersonas viedoklis tvītā: atzinīga reakcija par latviešu valodas izvēli un retorisks jautājums, kas kritizē iepriekšējās svešvalodu izvēles. Tas ir konkrēts kultūrpolitisks viedoklis par valsts valodas lomu reprezentācijā, ne ceremoniāls apsveikums.', 0.4, 'https://x.com/JazepsBasko/status/2055024625067626739', '2026-05-15 07:28:41', '2026-05-15 07:50:07', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20180, 189, 35801, 'Koalīcija un partijas', 'Atbalsta īstermiņa valdības izveidi 3 nedēļu laikā ar konkrētu mērķu programmu (5-6 uzdevumi valstij, 2-3 katram ministram 5 mēnešu periodam)', 'Šajos apstākļos īstermiņa valdību 3 nedēļu laikā jāspēj salikt. Ja partijas to nespēj, tad demonstrē savu bezatbildību. Katram ministram 2-3 uzdevumi 5 mēnešu periodam. 5-6 uzdevumi visai valdībai (piemēram, nopirkt pretdronu aizsardzību, uzsākt reālus taupības pasākumus utt).', 0.85, 'Tieša pirmās personas pozīcija par valdības formēšanas tempu un struktūru. Pūce nosauc konkrētus termiņus, uzdevumu skaitu un divus piemērus (pretdronu aizsardzība, taupība).', 0.8, 'https://x.com/pucej/status/2055256599766208600', '2026-05-15 00:00:00', '2026-05-15 22:45:47', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20181, 189, 35801, 'Aizsardzība un drošība', 'Pretdronu aizsardzības iegāde jāiekļauj nākamās valdības 5-6 prioritāšu sarakstā kā piemērs', '5-6 uzdevumi visai valdībai (piemēram, nopirkt pretdronu aizsardzību, uzsākt reālus taupības pasākumus utt).', 0.7, 'Pūce nosauc pretdronu aizsardzību kā konkrētu piemēru valdības prioritātēm — tas ir izteikts politikas atbalsts, kaut piemēra formā. Salience vidēja, jo dronu drošība jau ir notikumu plūsmā.', 0.7, 'https://x.com/pucej/status/2055256599766208600', '2026-05-15 00:00:00', '2026-05-15 22:45:47', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20182, 189, 35803, 'Koalīcija un partijas', 'Atbalsta ātru jaunas valdības izveidi (nevis demisionētā MK turpinājumu vai aizstājēju iecelšanu); noraida ''klibas pīles'' valdības variantu', 'Situācijai atbilstoši būtu ātri izveidot jaunu valdību. Vajadzēs pieņemt ātrus un svarīgus lēmumus un ''klibas pīles'' nederēs.', 0.85, 'Pūce identificē trīs teorētiskos variantus un atklāti izvēlas vienu — ātru jaunas valdības izveidi. ''Klibas pīles'' metaforā netieši noraida tehnisko valdību.', 0.8, 'https://x.com/pucej/status/2055241289654780113', '2026-05-15 00:00:00', '2026-05-15 22:45:47', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20378, 30, 36120, 'Valsts pārvalde', 'Iebilst pret valsts mērķu noteikšanu — apgalvo, ka mērķtiecīga valsts nenovēršami izmanto piespiedu varu pret indivīdiem un upurē cilvēka brīvību birokrātijas labā. Valsts funkcija ir nodrošināt apstākļus indivīdu mērķu sasniegšanai, nevis uzspiest kopīgu mērķi.', 'Valstij nevar būt mērķa. Mērķtiecīga valsts mērķu vārdā izmantos piespiedu varu, lai pakļautu tos, kas neparakstās uz nosprausto mērķi. Mērķtiecīga valsts bez aizturēm upurēs cilvēka brīvību un pašu cilvēku kā radības kroni.', 0.85, 'Pirmā persona, izvērsts ideoloģisks paziņojums ar konkrētu nostāju par valsts dabu — klasiski liberāls/libertāra rakursā. Atbilst Baško iepriekšējām pozīcijām (#239 brīvība pret kontroli, #233 valsts funkciju samazināšana). Salience vidēja-augsta — pamata politiskās filozofijas formulējums, kas saistīts ar MMN platformu.', 0.65, 'https://x.com/JazepsBasko/status/2055363230059614392', '2026-05-15 00:00:00', '2026-05-16 14:47:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20382, 15, 36105, 'Ukraina un Krievija', 'Krievijas armija militāri stagnē Donbasā (no 2022. gada februāra nav ievērojami pavirzījusies); Ukrainai ir momentums un Rietumiem jāpastiprina tās atbalsts', 'Russia is still stuck in Donbas. 🇺🇦 has the momentum, we must step up our support.', 0.85, 'First-party paziņojums Lennart Meri konferencē Tallinā 2026-05-16. Braže novērtē Krievijas militāro neefektivitāti (gliemeža metafora — pavirzīšanās no Avdijivkas līdz Čehijai 4 gados) un aicina rietumvalstis palielināt Ukrainas atbalstu. Konkrēta ārlietu politikas pozīcija ar diviem komponentiem: (1) Krievijas militārā stagnācija, (2) imperatīvs palielināt atbalstu Ukrainai.', 0.7, 'https://x.com/Braze_Baiba/status/2055579132528914500', '2026-05-16 00:00:00', '2026-05-16 14:48:24', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20413, 57, 33907, 'Tieslietas', 'Apsūdz Bunkus slepkavības lietas tiesnesi korupcijā un gatavībā pildīt ''mentu zaņķa saimnieku'' rīkojumus — brīdina, ka rītdien šādas tiesas priekšā var nonākt jebkurš pilsonis.', 'koruptā Bunkus prāvas tiesnese, pildot mentu zaņķa saimnieku vēlmes, ir bijusi gatava uz visu. Vai esat droši, ka rīt šādas tiesas priekšā nenonāksiet arī Jūs?', 0.75, 'Konkrēta apsūdzība — vārdā nenosaukta, bet identificējama Bunkus prāvas tiesnese — par korupciju un tiesas instrumentalizāciju. Atšķiras no #14413 un #10972 (kas runā par tiesībsargājošām iestādēm kopumā un Vaļagina lietu), tā kā šī ir specifiski par konkrēto tiesnesi un Bunkus prāvu. Pozīcija pret tiesu sistēmas neatkarību — tāpēc Tieslietas, ne Korupcija un KNAB.', 0.6, 'https://x.com/Lato_Lapsa/status/2054239405200515322', '2026-05-12 00:00:00', '2026-05-17 02:26:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20414, 57, 33919, 'Sabiedriskie mediji', 'Apgalvo, ka Progresīvo apgalvojums ''par tiem maksā partijas'' ir nekompetents — partijas saņem valsts budžeta finansējumu, un mediji saņem SIF/MAF finansējumu, tādēļ abi ir atkarīgi no valsts naudas.', 'Pastāstiet kāds mucā augušajai progresīvajai pamuļķei par to, kāds ir partiju finansējums no valsts budžeta un kāds ir mediju finansējums no SIF/MAF.', 0.7, 'Konkrēta pozīcija par mediju un partiju valsts finansēšanu — implicīti kritizē SIF/MAF (Sabiedrības integrācijas fonds / Mediju atbalsta fonds) kā mehānismu, kas padara medijus atkarīgus no valsts, un tādēļ apstrīd Progresīvo argumentu par neatkarīgu žurnālistiku. Salience vidēja — atkārtota Lapsas tēze, bet šeit ar konkrētu institūciju nosaukumu.', 0.55, 'https://x.com/Lato_Lapsa/status/2054179518785474655', '2026-05-12 00:00:00', '2026-05-17 02:26:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20415, 57, 33564, 'Tieslietas', 'Apsūdz tiesu, prokuratūru (''Meistera prokuratūra'') un policiju (''mentu zaņķis'') apzinātā ''Hiēnu ģimenes'' (Lembergu) procesa noklusēšanā — apgalvo, ka tiesas liecību ieraksti netiks publiskoti, lai sabiedrība neuzzinātu, kā tiesās klājas ''blēžiem un meļiem''.', 'Hiēnu ģimenes alkatīgāko pārstāvju liecību ieraksta no tiesas šoreiz nebūs. Viņiem tāpat kā Meistera prokuratūras un mentu zaņķim vismazāk ir vajadzīgs, lai sabiedrība uzzinātu, kā tiesās klājas blēžiem un meļiem.', 0.7, 'Konkrēta apsūdzība pret tiesu sistēmu — Lembergu prāva un tās slēgtais raksturs. Atšķiras no #14413 (vispārīga ''mentu zaņķis'' pozīcija) ar to, ka šeit ir konkrēta institūcija (Lembergu prāvas tiesa) un konkrēta darbība (liecību ierakstu neslēgšanai), kā arī ''Meistera prokuratūras'' epitets (atsaucoties uz ģenerālprokuroru Juri Stukānu/Stukāna priekšteci — vēsturiski Aigars Meisters bija ģenerālprokurors). Pozīcija: tiesu sistēma apzināti slēpj informāciju no sabiedrības.', 0.6, 'https://x.com/Lato_Lapsa/status/2054114811508670641', '2026-05-12 00:00:00', '2026-05-17 02:26:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20435, 15, 36485, 'Aizsardzība un drošība', 'Tiekoties ar NATO Apvienoto spēku pavēlniecības Brunsumā komandieri ģenerāli Ingo Gerharcu, uzsvēra nepieciešamību stiprināt NATO Austrumu flanga pretgaisa aizsardzību un NATO līmenī pārņemt Ukrainas aizsardzības inovācijas un ekspertīzi', 'uzsvēru nepieciešamību stiprināt NATO Austrumu flanga pretgaisa aizsardzību, un NATO līmenī pārņemt Ukrainas aizsardzības inovācijas un ekspertīzi', 0.85, 'Tieša pirmās personas pozīcija no Bražes X konta — uzsvars uz NATO līmeņa Ukrainas aizsardzības inovāciju pārņemšanu paplašina iepriekšējo NATO austrumu flanga nostāju (#18150) ar konkrētu jaunu elementu: Ukrainas kara pieredzes institucionālu integrāciju NATO procesos.', 0.75, 'https://x.com/Braze_Baiba/status/2055629379535794511', '2026-05-16 00:00:00', '2026-05-17 02:29:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20436, 15, 35999, 'Ukraina un Krievija', 'Krievija brutāli maldina un vervē citu valstu pilsoņus, tostarp no Tuvo Austrumu un Āfrikas valstīm, savam karam pret Ukrainu — Krievijas spēka un agresijas politika ir globāls drauds, ne tikai Eiropas drošības jautājums', 'Krievijas spēka un agresijas politika nav tikai Eiropas drošības jautājums, bet gan globāls drauds', 0.85, 'Tikšanās ar Jordānijas ārlietu ministru Safadi laikā Braže (citējot LETA, ministres padomnieka Sadovska informāciju) pirmo reizi DB ekstraktoros formulē konkrētu pozīciju par Krievijas pilsoņu vervēšanu no Tuvajiem Austrumiem un Āfrikas — paplašina Krievijas izolācijas naratīvu ar globālu dimensiju (nav iepriekšējās claims par šo aspektu).', 0.7, 'https://nra.lv/politika/521229-edgars-rinkevics-rigas-pili-uznemis-augstus-viesus-no-jordanijas.htm', '2026-05-15 00:00:00', '2026-05-17 02:29:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20437, 15, 35752, 'Ārpolitika', 'Pirmā Jordānijas premjerministra vietnieka un ārlietu ministra vizīte Latvijā vēsturē — parakstīts nodomu protokols par politisko konsultāciju mehānisma izveidi un līgums par vīzu prasības atcelšanu diplomātisko pasu turētājiem; ekonomiskā sadarbība lauksaimniecības, farmācijas un IKT nozarēs', 'Parakstījām nodomu protokolus par mūsu attiecību stiprināšanu. Vienojāmies attīstīt ekonomisko sadarbību lauksaimniecības, farmācijas un IKT nozarēs.', 0.9, 'Konkrēta divpusējās diplomātijas pozīcija — pirmā Jordānijas augsta līmeņa amatpersonas vizīte LV vēsturē, parakstīts pirmais starpvaldību līgums un MoU. Politiskā nostāja par Dienvidaustrumāzijas/Tuvo Austrumu reģiona ekonomisko padziļināšanu.', 0.55, 'https://x.com/Braze_Baiba/status/2055228397693829186', '2026-05-15 00:00:00', '2026-05-17 02:29:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20438, 15, 35648, 'Aizsardzība un drošība', 'Krievijas agresīvā kodolretorika apdraud starptautisko drošību un grauj atbruņošanās centienus — Latvija apņemas sadarboties kodolieroču neizplatīšanā un stiprināt Starptautisko monitoringa sistēmu (IMS)', 'Krievijas agresīvā kodolretorika apdraud starptautisko drošību un grauj atbruņošanās centienus', 0.85, 'Tikšanās ar CTBTO izpildsekretāru Robertu Floidu — pirmā ekstraktētā Bražes pozīcija par konkrētu Krievijas kodolretorikas vērtējumu un LV apņemšanos kodolieroču neizplatīšanas režīmā. Paplašina vispārējo Krievijas spiediena naratīvu ar specifisku kodolieroču politikas dimensiju.', 0.7, 'https://pmo.ee/8471854', '2026-05-15 00:00:00', '2026-05-17 02:29:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20439, 15, 35750, 'Ukraina un Krievija', 'Atbalsta Īpašā tribunāla izveidi Agresijas nozieguma izmeklēšanai pret Ukrainu — Krievijas noziegumi netiks aizmirsti; pieprasīta ANO Drošības padomes sēde 19. maijā pēc Krievijas uzbrukuma Kijivas reģionā 14. maijā', 'Today we established the Special Tribunal for the Crime of Aggression against Ukraine.', 0.9, 'Tieša pirmās personas pozīcija no Bražes X konta par institucionālo soli — Īpašā tribunāla izveidi Agresijas nozieguma izmeklēšanai. Konkrēts institucionālā mehānisma atbalsts, kas nav ekstrahēts iepriekšējās claims (paplašina vispārējo Krievijas atbildības naratīvu).', 0.8, 'https://x.com/Braze_Baiba/status/2055249043639447820', '2026-05-15 00:00:00', '2026-05-17 02:29:16', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20458, 57, 33574, 'Aizsardzība un drošība', 'Apgalvo, ka būs vēl atklājumi par Sprūda un Progresīvo ''saimniekošanu uz valsts drošības finansējuma rēķina''.', 'Un šī ir tikai mazmazītiņa kripatiņa no visa tā, kas nāks dienas gaismā par Sprūda un "progresīvo" saimniekošanu uz valsts drošības finansējuma rēķina.', 0.6, 'Lapsa pievieno komentāru pie kāda iepriekšēja materiāla (saturs nav redzams tweet''ā), apgalvojot, ka tā ir tikai sākums atklājumiem par Sprūda/Progresīvo aizsardzības budžeta nepareizu izmantošanu. Konkrēti faktu apgalvojumi nav norādīti, tāpēc confidence vidēja. Saskan ar #17923 (pieprasa atstādināt Sprūdu) un #17997 (apšauba viņa amatpersonas deklarāciju) — turpina to pašu līniju.', 0.6, 'https://x.com/Lato_Lapsa/status/2054070336719614441', '2026-05-12 00:00:00', '2026-05-17 08:51:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20459, 57, 33288, 'Aizsardzība un drošība', 'Apgalvo, ka gada laikā Andra Sprūda vadītajā Aizsardzības ministrijā nomainījusies sestā daļa darbinieku — netieši apsūdz augstā kadru rotācijā kā vadības problēmā.', 'Gada laikā Sprūda Aizsardzības ministrijā nomainījusies sestā daļa darbinieku. Mja…', 0.75, 'Konkrēts statistisks apgalvojums (1/6 darbinieku gada laikā) ar sarkastisku ''Mja…'' kā implicītu kritiku. Papildina iepriekšējo #11286 (2026-04-22, kur Lapsa kritizēja Sprūda skaidrojumus par AM pametošanu) ar agregētu skaitli. Salience augsta — drošības resora cilvēkresursu stabilitāte ir kodola tēma.', 0.75, 'https://x.com/Lato_Lapsa/status/2053856388628009155', '2026-05-11 00:00:00', '2026-05-17 08:51:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20460, 57, 32967, 'Degviela un enerģētika', 'Apsūdz iepriekšējo ekonomikas ministri (''panikā kritušo muļķi'') par ''astronomiskām summām'' par gāzi, ko iedzīvotāji samaksāja viņas amatā.', 'Vai pastāstīt, kādas astronomiskas summas par gāzi Jūs samaksājāt šīs ekonomikas ministres amatā panikā kritušās muļķes dēļ?', 0.6, 'Retorisks jautājums, kas funkcionāli ir apsūdzība — Lapsa apgalvo, ka ekonomikas ministres lēmumi izraisīja augstas gāzes cenas iedzīvotājiem. Ministre nav nosaukta vārdā, bet kontekstā (panika+gāze) visdrīzāk Ilze Indriksone (NA, ekonomikas ministre 2023). Atšķiras no #11184 (kas runā par cenu pieaugumu kopumā) ar konkrētu adresātu un produktu (gāze). Confidence vidēja vārda neminēšanas dēļ.', 0.55, 'https://x.com/Lato_Lapsa/status/2053772530377269509', '2026-05-11 00:00:00', '2026-05-17 08:51:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20461, 57, 32558, 'Aizsardzība un drošība', 'Noraida Sprūda atkāpšanās pamatojumu kā melus — apgalvo, ka ''komunisti melo vienmēr'', tādējādi nepieņemot viņa pasniegto motivāciju (pasargāt armiju no politiskas kampaņas).', '"Es atkāpjos no aizsardzības ministra amata, lai pasargātu Latvijas armiju no ieraušanas politiskā kampaņā," teica Andris Sprūds. Nekas jauns. Komunisti melo vienmēr. Vienmēr.', 0.8, 'Tieša cita Sprūda izteikuma noraidīšana ar apgalvojumu, ka tas ir meli. Lapsa pieprasa, ka īstais atkāpšanās iemesls ir cits, ne pasniegtais. Saskan ar viņa ilgstošo līniju pret Sprūdu (#17923 atstādināšanas pieprasījums, #11286 kritika par kadru rotāciju). Augsta confidence — citāts un komentārs ir tieši izteikti.', 0.7, 'https://x.com/Lato_Lapsa/status/2053513915645010206', '2026-05-10 00:00:00', '2026-05-17 08:51:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20462, 15, 35246, 'Ukraina un Krievija', 'Nosoda Krievijas atkārtotos uzbrukumus ANO Humanitārās palīdzības organizācijas (OCHA) personālam Ukrainā — kvalificē tos kā cinisku un aukstasinīgu slepkavības mēģinājumu (#RussiaIsATerroristState)', 'Jau otro reizi Krievija uzbrukusi ANO Humanitārās palīdzības organizācijas personālam. Russia again has attacked the UN workers @OCHA_Ukraine fulfilling its mandate. Cynical and cold blooded attempt at murder. #RussiaIsATerroristState', 0.9, 'Tiešs ārlietu ministres tvīts ar konkrētu pozīcijas paziņojumu par Krievijas uzbrukumiem ANO humanitārajiem darbiniekiem — jauna tēma, kas nav citos esošajos claim. Tags #RussiaIsATerroristState pasvītro pozīciju.', 0.7, 'https://x.com/Braze_Baiba/status/2054948467240259669', '2026-05-14 00:00:00', '2026-05-17 08:51:14', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20479, 182, 36521, 'Aizsardzība un drošība', 'Apsūdz ASV prezidentu Trampu NATO faktiskā demontāžā un apgalvo, ka Trampa rīcība ir geopolitiska dāvana Ķīnai un Krievijai — iespējama konflikta ar Ķīnu gadījumā ASV spēki būs traģiski novājināti.', 'Has Trump received the Communist Party''s highest medal in China? Experts point out that he has done a massive favour to the geopolitical interests of China and Russia - effectively dismantling the Western world''s strongest defence alliance - NATO.', 0.8, 'Tiešs pirmās personas apgalvojums tvītā 16.05. Skaidra nostāja — Trampa politika apdraud NATO un kalpo Pekinai+Maskavai. Saskanīgs ar Ozola iepriekšējām ASV/NATO/Krievija temām (#14353 Spānija, #17795 Vienotības aizsardzības budžets). Tvīts angliski, bet nostāja ir nepārprotama.', 0.85, 'https://x.com/OttoOzols/status/2055622297239625960', '2026-05-16 00:00:00', '2026-05-17 08:52:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20480, 182, 35859, 'Ukraina un Krievija', 'Satīriski apgalvo, ka Putins faktiski iznīcina Krieviju, turpinot Ļeņina (kuru sauc par 20. gs. izcilāko rusofobu) krievu tautas nicināšanas mantojumu — Mauzoleja saglabāšana sirdī Maskavas ir simbols šim turpinājumam.', 'Putin continues to glorify this mass murderer and hater of the Russian people. Just like Lenin before him, he serves forces that loathe both Russians and Russia itself', 0.65, 'Tvīts izmanto satīrisku inversiju ("Putins ir Šrēdera aģents"), bet pamatpozīcija — Putins iznīcina Krieviju, Ļeņina rusofobiskā mantojuma pārmantošana — ir nopietna un atbilst Ozola iepriekšējām pozīcijām (saskan ar #33945 Stubb retvīta domu "Putin broke Russia"). Pazemināta confidence dēļ satīriskās formas, bet nostāja ir patiesa, ne empātisks piesaucens.', 0.6, 'https://x.com/OttoOzols/status/2055261754779726160', '2026-05-15 00:00:00', '2026-05-17 08:52:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20481, 182, 35371, 'Korupcija un KNAB', 'Apsūdz KNAB selektīvā politiskā kalpošanā Vienotības (JV) interesēm — apgalvo, ka KNAB neaiztika ZZS, kamēr tā bija Siliņas valdībai izdevīga, un "brīnumainā kārtā pamodās" tikai pēc PRO valdības gāšanas; piesauc arī Kaimiņa lietu kā piemēru, kur KNAB apsūdzība "izčākstēja" pēc tam, kad Kaimiņš nobalsoja par Kariņa valdības apstiprināšanu.', 'Brīnumainais KNAB. Jauna politiskā cirka izrāde. Kamēr komunistu kolaboranta Lemberga kabatas partija ZZS bija valdībā un bija izdevīga Evikas Siliņas kabinetam, tikmēr KNAB viņus neaiztika.', 0.85, 'Garš tiešs pirmās personas analītisks tvīts 14.05. Konkrēta apsūdzība institūcijai (KNAB) ar specifiskām vēsturiskām atsaucēm (ZZS izmeklēšanas timing, Kaimiņa lieta + Kariņa valdības balsojums, Ukrainas KNAB analogijas piemērs). Saskan ar Ozola iepriekšējām JV-kritiskām pozīcijām (#17848 Lībiņa-Egnere, #14315 PRO+oligarhi). Salience augsta — institucionālā uzticība korupcijas apkarošanai ir kodola tēma.', 0.8, 'https://x.com/OttoOzols/status/2054913299658015087', '2026-05-14 00:00:00', '2026-05-17 08:52:49', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20503, 30, 36981, 'Koalīcija un partijas', 'Politiskās partijas uzdevums ir piedāvāt nevis "labākos" risinājumus, bet ideoloģijai atbilstošus risinājumus — pretstatā tehnokrātijas idejai.', 'Politiskas partijas uzdevums ir nevis piedāvāt visus labākos risinājumus visām problēmām, bet piedāvāt paredzamai ideoloģijai atbilstošus risinājumus.', 0.85, 'Baško pirmās personas izteikta nostāja par to, kāda funkcija ir politiskām partijām — noraida tehnokrātisku pieeju un apgalvo, ka risinājuma "labums" ir atkarīgs no vērtībām (ideoloģijas). Kora analoģija pastiprina arī sekundāru tēzi — deputātam jāseko partijas līnijai ("jāzina, vai dziedi tenorā vai soprānā"). Tā ir konkrēta MMN politiskās filozofijas pozīcija.', 0.5, 'https://x.com/JazepsBasko/status/2055977457447018511', '2026-05-17 00:00:00', '2026-05-17 18:59:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20506, 15, 36752, 'Ārpolitika', 'Padziļināt Latvijas un Filipīnu divpusējās attiecības — tirdzniecību, sadarbību ANO un ES–ASEAN partnerību.', 'Tiekoties ar Filipīnu Republikas ārlietu ministri Terēzu P. Lazaro, mēs apspriedām nākamos soļus divpusējo attiecību un tirdzniecības, sadarbības ANO, kā arī ES un ASEAN partnerības padziļināšanā.', 0.75, 'Braže tieši formulē Latvijas ārpolitikas virzienu — divpusējās attiecības un ES–ASEAN sadarbības padziļināšana ar Filipīnām. Tas ir konkrēts ārpolitisks akcents (Indo-Pacific reģions, multilaterāli formāti), nevis vienkārša ceremoniālā vizītes pieminēšana. Salience mērena, jo Filipīnas nav core partneris, bet ASEAN konteksts paplašina politikas tvērumu.', 0.45, 'https://x.com/Braze_Baiba/status/2055656786611294558', '2026-05-16 00:00:00', '2026-05-18 12:10:14', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20511, 189, 36792, 'Koalīcija un partijas', 'Atbalsta Valsts prezidenta argumentāciju premjera kandidāta izvēlē un aicina Apvienoto sarakstu (Andri Kulbergu) ātri uzņemties valdības veidošanas atbildību, jo Latvija smagajos apstākļos ilgi nedrīkst palikt bez valdības.', 'Kopumā prezidenta argumentācija kandidāta izvēlē ļoti loģiska. Liela atbildība tagad @AndrisKulbergs un @Apvienotais_ , jo Latvija šajos smagajos apstākļos nedrīkst ilgi būt bez valdības.', 0.8, 'Tieša pirmās personas pozīcija divos saistītos elementos: (1) prezidenta loģikas atbalstīšana kandidāta izvēlē, (2) aicinājums AS/Kulbergam uzņemties atbildību par ātru valdības izveidi. Saglabā tā paša naratīva trajektoriju kā #20180 (3 nedēļas) un #20182 (noraida klibo pīli), bet pievieno konkrētu reakciju uz prezidenta nominēto kandidātu — jauna informācija, nav tiešs dublikāts.', 0.7, 'https://x.com/pucej/status/2055662674487173310', '2026-05-16 00:00:00', '2026-05-18 12:11:05', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20512, 182, 37029, 'Koalīcija un partijas', 'Apgalvo, ka E. Siliņas valdības "krišana" pēc dronu incidenta ir iestudēts priekšvēlēšanu PR farss — JV politbirojs un Progresīvie izmantoja dronu nokrišanu kā ērtu ieganstu, lai pirms vēlēšanām atbrīvotos no nepopulārās valdības saistīšanas (melošana, izšķērdība, nekompetence); kritizē, ka pieprasīt Sprūda atbildību par incidentu, kāds notiek arī Lietuvā/Igaunijā/Somijā, ir neadekvāta reakcija; uzskata, ka Siliņai tagad veido mocekles tēlu, bet PRO atgriežas pie populisma bazūnēm; saukā JV par "prokremlisko".', 'E. Siliņas valdības "krišana" ir iestudēts farss. Dronu nokrišana bija nevis patiesais iemesls, bet gan apzināti dramatizēts iegansts.', 0.85, 'Substantiāls pirmā loka tvīts ar konkrētu nostāju par valdības krīzi: (1) noliedz oficiālo iemeslu (dronu incidents kā cēlonis), (2) izvirza alternatīvu skaidrojumu (priekšvēlēšanu PR aprēķins), (3) konkrēti norāda atbildīgos aktierus (JV politbirojs, Siliņa personīgi, PRO vadība), (4) saukā vienu pusi par "prokremlisko". Konsekvents ar #17848, #14315, #17795 — esošā Ozola anti-JV/anti-PRO retorikas līnija.', 0.75, 'https://x.com/OttoOzols/status/2056026978046660649', '2026-05-17 00:00:00', '2026-05-18 12:11:18', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20515, 57, 37022, 'Korupcija un KNAB', 'Apsūdz JV/Progresīvo politiķus Linkaitu, Briškenu un Švinku liela mēroga publisko līdzekļu izšķērdēšanā un izzagšanas atbalstīšanā (simtu miljonu/miljardu līmenī); netieši apsūdz Švinku ostas novešanā bankrotā.', 'Vienotības un progresīvo vaukšķu skatījumā Loginovs, loģiski, ir izsmiekla vērts - kur nu tādam ar Linkaitiem, Briškeniem un Švinkām līdzināties. Ne simtus miljonu, ne miljardus nav izpļekarējis un izzagt palīdzējis, pat ne ostu līdz bankrotam nav novedis. Nožēlojamais amatieris.', 0.65, 'Sarkastiskā formā formulēta konkrēta apsūdzība — Lapsa salīdzina Loginovu pret trim nosauktiem politiķiem (Linkaits/Briškens/Švinka) un pretstatā uzskaita konkrētus pārkāpumus: ''izpļekarējis simtus miljonu/miljardus'', ''izzagt palīdzējis'', ''ostu līdz bankrotam novedis''. Sarkasms šeit nav par konkrētas politikas neesamību — tas ir tikai retoriskais ietvars konkrētai apsūdzībai par lielu mēroga finanšu pārkāpumiem. Konfidence 0.65, jo formulējums ir sarkastisks/netiešs (nevis tieša prasība pēc izmeklēšanas), bet apsūdzības saturs ir konkrēts.', 0.55, 'https://x.com/Lato_Lapsa/status/2055987512468807722', '2026-05-17 00:00:00', '2026-05-18 12:12:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20537, 15, 37596, 'Ukraina un Krievija', 'Noliedz Krievijas Ārējās izlūkošanas dienesta (SVR) apgalvojumus, ka Latvija atļauj izmantot savu teritoriju vai gaisa telpu uzbrukumiem Krievijas teritorijā — kvalificē tos kā Krievijas dezinformācijas kampaņu un norāda, ka Krievijas pārstāvjiem fakts skaidrots jau vairākkārt.', 'Krievija atkal melo. Šoreiz dezinformācijas kampaņu pret Latviju īsteno Krievijas Ārējās izlūkošanas dienests (SVR). FAKTS: Latvija neļauj izmantot savu gaisa telpu uzbrukumiem Krievijas teritorijā. Tas Krievijas pārstāvjiem ir skaidrots jau vairākkārt.', 0.9, 'Tieša pirmpersonas citāta pozīcija NRA rakstā, atkārtota arī ārlietu ministres X kontā (#37657 EN versija) un MFA kontā @Arlietas. Pozīcija saskan ar #17995 (2026-05-08 par Ukrainas droniem), bet ir atsevišķs reaģējošs paziņojums uz konkrētu SVR dezinformācijas kampaņu 19.05 — nav pretrunā, ir kontinuitāte. Atkārtots arī premjeres Siliņas un prezidenta Rinkēviča paziņojumos tajā pašā dienā.', 0.8, 'https://nra.lv/latvija/521475-krievijas-izlukdienests-draud-latvijai-ar-atriebibu.htm', '2026-05-19 00:00:00', '2026-05-19 13:08:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20551, 189, 37739, 'Aizsardzība un drošība', 'Apšauba Valsts prezidenta Preiļos pausto aicinājumu apzināt slimnīcu un uzņemšanas nodaļu izvietojumu — apgalvo, ka NBS un civilās aizsardzības institūcijas šo informāciju jau labi zina, tāpēc prezidenta paziņojums ir nesaprotams vai lieks.', 'Es esmu dziļi pārliecināts, ka NBS un civilās aizsardzības institūcijas to ļoti labi zina. Ko ar šo prezidents gribēja teikt?', 0.55, 'Pūce tieši formulē pozīciju ar pirmās personas apliecinājumu ("Es esmu dziļi pārliecināts") par to, ka civilās aizsardzības infrastruktūras kartēšana jau ir veikta — ar tam sekojošu retorisku jautājumu, kas implicē kritiku par Valsts prezidenta paziņojumu kā uninformētu vai lieku. Pozīcija ir skaidra, bet salience vidēja (procedūras kritika, ne pamatpolitikas pavērsiens). Saglabājams kā opozīcijas politiķa skepse par Valsts prezidenta lomu drošības jautājumos.', 0.4, 'https://x.com/pucej/status/2056425999231856758', '2026-05-18 00:00:00', '2026-05-19 13:14:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20568, 30, 37680, 'Valsts pārvalde', 'Apgalvo, ka demokrātija, varas decentralizācija un vārda brīvība ir vienīgais mehānisms, kas spēj novērst sabiedrības iznīcināšanu caur uzspiestu viengalvainību — bez tiem Latvija beigsies.', 'Bez demokrātijas, bez vārda brīvības mēs beigsimies. Mēs, tas ir, Latvija. Tāpēc ka uzspiestai viengalvainībai vajag tikai vienu stabu, kurā ieskriet un nosisties.', 0.8, 'Garš pirmās personas esejas tipa ieraksts ar skaidru politisku tēzi — demokrātijas, decentralizācijas un vārda brīvības aizstāvība kā eksistenciāla prioritāte. Atklāti definēta nostāja, nevis retorisks jautājums. Topic ''Valsts pārvalde'' atspoguļo demokrātiskās iekārtas/decentralizācijas asis. NEEDS_REVIEW: alternatīvs topics varētu būt ''Sabiedriskie mediji'' (informācijas telpas konteksts) vai ''Tieslietas'' (vārda brīvība kā tiesība), bet Baško pamatakcents ir uz varas struktūru — decentralizācija un demokrātija.', 0.6, 'https://x.com/JazepsBasko/status/2056471150562328917', '2026-05-19 13:01:13', '2026-05-19 13:22:20', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20569, 30, 37681, 'Valodu politika', 'Iebilst pret Latvijas politiķiem, kas par valsts politiku publiski runā angliski savā zemē — vērtē tos kā mazvērtīgus, līdzvērtīgus tiem, kas runā krieviski; uzskata, ka tādi cilvēki nedrīkst būt suverēnas Latvijas pārvaldē.', 'Politiķi, kas par savas valsts politiku savā zemē publiski runā angliski, ir tādi paši pāķi, kā tie, kas to dara krieviski. Ar tādu mazvērtību sirgstošajiem nav jābūt tuvumā suverēnas Latvijas pārvaldei.', 0.85, 'Skaidri formulēta pirmās personas pozīcija par valodas lietojumu publiskajā politiskajā telpā. Saskanīga ar Baško iepriekšējo Valodu politika claim #18393 (atbalsta latviešu valodu Eirovīzijā). Asas formas vērtējums (''pāķi'', ''mazvērtība'') — bet politiska substance ir skaidra: latviešu valodas primārs publisko diskursu.', 0.6, 'https://x.com/JazepsBasko/status/2056311851109978386', '2026-05-19 13:01:13', '2026-05-19 13:22:20', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20577, 15, 37670, 'Ārpolitika', 'Tiekoties ar ANO ģenerālsekretāra amata kandidāti Rebeku Grinšpanu, uzsver ANO Statūtu pamatprincipu aizstāvības fundamentālo nozīmi, ANO sistēmas reformēšanu un tās efektīvas pārvaldības nodrošināšanu.', 'I emphasised the fundamental importance of defending the core principles of the UN Charter, reforming the UN system and ensuring its efficient management.', 0.75, 'Pirmās personas paziņojums tvītā par tikšanos ar ANO ģenerālsekretāra amata kandidāti — Braže formulē trīs prioritātes ANO darbam: Statūtu pamatprincipu aizstāvība, sistēmas reforma, efektīva pārvaldība. Nostāja ir samērā vispārīga (ne konkrēta politikas izvēle), tāpēc confidence 0.75.', 0.5, 'https://x.com/Braze_Baiba/status/2056342586541973819', '2026-05-18 00:00:00', '2026-05-19 14:45:07', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20579, 15, 38241, 'Ārpolitika', 'Vizītes laikā ar Somijas parlamenta priekšsēdētāju Jussi Halla-aho Rīgā apstiprina Latvijas un Somijas kā tuvu un uzticamu sabiedroto saikni — kopīgi aizstāvam ES un NATO Austrumu flangu un esam līderi Ukrainas pašaizsardzības atbalstā.', 'Latvia and Finland are close and trusted allies. Together, we defend the Eastern Flank of the EU and NATO, and lead support for Ukraine''s self-defence.', 0.8, 'Pirmpersonas tvīts no @Braze_Baiba (nav RT, nav x_mention) ar konkrētu divpusējās vizītes apstiprinājumu un pozīcijas formulējumu par ES/NATO austrumu flanga kopaizsardzību un Ukrainas atbalstu. Salience vidēja — divpusēja vizīte ir standarta diplomātiska darbība, taču Halla-aho ir Somijas parlamenta priekšsēdētājs (augstākais starptautiskais postenis vizītē Latvijā), un Somija ir jauna NATO dalībvalsts ar ievērojamu Baltijas reģiona drošības iesaisti.', 0.55, 'https://x.com/Braze_Baiba/status/2056702929852153990', '2026-05-19 00:00:00', '2026-05-19 16:09:43', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20581, 204, 38311, 'Aizsardzība un drošība', 'Apstiprina, ka NBS ir pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības, un pastāvīgi monitorē gaisa telpu kopā ar NATO sabiedrotajiem.', 'Esam pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības.', 0.85, 'NBS oficiālā @Latvijas_armija ziņa 19.05.2026 09:04 par aktīvu apdraudējumu Latgalē. Institucionāla pirmpersonas pozīcija (organization + first_party slot). Skaidri formulēta operatīvā doktrīna: pretgaisa aizsardzība pastiprināta uz austrumu robežas, NATO patrulēšanas misija aktivizēta. Šī ir konkrēta politikas/operacionāla nostāja, ne tikai brīdinājums.', 0.85, 'https://x.com/Latvijas_armija/status/2056662162303574408', '2026-05-19 00:00:00', '2026-05-19 16:10:11', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20582, 204, 38317, 'Droni', 'Apstiprina, ka 17. maijā viens bezpilota lidaparāts ielidoja Latvijas gaisa telpā un no tās izlidoja; NBS publisko hronoloģisku informāciju par incidentu un atzīst šādu gadījumu atkārtošanās iespēju, kamēr norisinās Krievijas agresija Ukrainā.', 'Nacionālie bruņotie spēki apstiprina, ka Latvijas gaisa telpā ielidoja un no tās izlidoja viens bezpilota lidaparāts.', 0.9, 'NBS oficiālā retrospekīvā ziņa par 17.05.2026 incidentu. Tieša institucionāla atzīšana, ka UAV ir šķērsojis Latvijas gaisa telpu — kalibrēta, faktiska atzīšana, ne spekulācija. Pozīcija arī par incidenta atkārtošanās iespēju kontekstā ar Krievijas agresiju Ukrainā.', 0.9, 'https://x.com/Latvijas_armija/status/2055916095106609611', '2026-05-17 00:00:00', '2026-05-19 16:10:12', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20583, 204, 38316, 'Droni', 'NBS Sauszemes spēku Mehanizētajā kājnieku brigādē mācībās ''Crystal Arrow 2026'' iekļauj gaisa un sauszemes dronus kā līdzekļus izlūkošanai, kaujas atbalstam un risku samazināšanai.', 'Mācībās tika izmantoti gan gaisa, gan sauszemes droni, kas palīdz ātrāk iegūt informāciju, samazināt riskus un efektīvāk atbalstīt karavīrus uzdevumu izpildē.', 0.8, 'NBS oficiālā ziņa par ''Crystal Arrow 2026'' mācībām. Tieša institucionāla nostāja par dronu integrāciju mācībās — operatīvā prakse, ne tikai komunikācija. Apstiprina, ka NBS aktīvi attīsta dronu lietošanas spējas (gan gaisa, gan sauszemes), kas ir konkrēta militārās modernizācijas pieeja.', 0.7, 'https://x.com/Latvijas_armija/status/2056620914540679560', '2026-05-19 00:00:00', '2026-05-19 16:10:12', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20586, 189, 38267, 'Aizsardzība un drošība', 'Norāda, ka Latgales un Vidzemes dronu incidenti parāda joprojām neizdarīto darbu aizsardzības un citos resoros — gan praktiskajā aizsardzībā, gan komunikācijā ar iedzīvotājiem; apliecina līdzjūtību skartajiem iedzīvotājiem.', 'Jūtu līdzi Latgales un nu jau arī Vidzemes iedzīvotājiem - incidenti ar droniem satrauc un rada apdraudējuma sajūtu. Tas parāda tos darbus, kas vēl jāveic aizsardzības un citiem resoriem gan praktiskajā aizsardzības darbā, gan arī komunikācijā ar iedzîvotājiem.', 0.8, 'Pirmās personas pozīcija — Pūce raksturo Latgales un Vidzemes dronu incidentus kā pierādījumu, ka aizsardzības resoram (un citiem) joprojām ir veicami uzdevumi gan praktiski, gan komunikācijas ziņā. Substantīva kritika ar konkrētu kontekstu (incidentu reģioni, divi darbu virzieni). Iet vienā līnijā ar #20551 (Rinkēviča Preiļu paziņojuma apšaubīšana) un #20181 (pretdronu iegāde kā 5-6 prioritāšu piemērs), bet šeit fokusē uz komunikācijas trūkumu un praktisko apdraudējumu, nevis iestāžu kompetences strīdu — atšķirīgs leņķis, nav dublikāts.', 0.7, 'https://x.com/pucej/status/2056704404653318149', '2026-05-19 00:00:00', '2026-05-19 16:10:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20595, 15, 38406, 'Ārpolitika', 'Padziļina Latvijas un Kanādas aizsardzības un ekonomisko partnerību kā uzticami NATO sabiedrotie un nodrošina pastāvīgu atbalstu Ukrainai; Kanādas ārlietu ministres Anitas Anandes vizīte Rīgā apstiprina Latvijas-Kanādas stratēģisko sasaisti.', 'Canada is Latvia’s trusted #NATO ally and friend. We are deepening our defence and economic partnership, and ensuring steadfast support for Ukraine.', 0.85, 'Pirmā persona Braže tvīts par Kanādas ārlietu ministres Anitas Anandes vizīti Rīgā. Skaidri formulē politisku nostāju par divpusējās aizsardzības partnerības padziļināšanu un Ukrainas atbalsta turpināšanu. Atšķiras no rīta klastera (SVR dezinformācija, ANO Statūti, LV-Somija) — jauns divpusējās diplomātijas klasteris ar Kanādu.', 0.7, 'https://x.com/Braze_Baiba/status/2056726072306053472', '2026-05-19 00:00:00', '2026-05-19 20:50:27', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20596, 204, 38543, 'Ukraina un Krievija', 'Apliecina, ka Latvija nav atvērusi savu gaisa telpu Ukrainas droniem triecieniem pret Krieviju un nav atļāvusi Ukrainas bruņotajiem spēkiem veikt triecienus no Latvijas teritorijas, taču turpina sniegt maksimālu atbalstu Ukrainas bruņotajiem spēkiem un mācīties no labākajiem dronu pielietošanas ekspertiem.', 'Latvija nav atvērusi savu gaisa telpu Ukrainas droniem, lai veiktu triecienus pret krieviju, taču Latvija turpina sniegt maksimālu atbalstu Ukrainas bruņotajiem spēkiem. Latvija nav atļāvusi Ukrainas bruņotajiem spēkiem veikt triecienus pa krieviju no mūsu teritorijas, taču Latvija turpinās mācīties no pasaulē labākajiem ekspertiem dronu pielietošanā savas valsts aizsardzībā.', 0.9, 'NBS oficiālais X konts (@Latvijas_armija) 19.05.2026 publicē institucionālu paziņojumu kontekstā ar Krievijas dezinformāciju par Baltijas valstīm. Tiešs pirmpersonas doktrināls formulējums (1) gaisa telpas neatvēršanas robežas Ukrainas triecieniem pret Krieviju un (2) turpinātas militārās apmācības/atbalsta saglabāšanas. Tas papildina agrāk šodien saglabātos claims #20581 (pretgaisa stiprinājums austrumos) un #20582 (17.05 drons) ar atsevišķu ārpolitisko/doktrinālo dimensiju.', 0.85, 'https://x.com/Latvijas_armija/status/2056730796140995058', '2026-05-19 00:00:00', '2026-05-19 20:50:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20611, 204, 38935, 'Aizsardzība un drošība', 'Brīdina par iespējamu gaisa telpas apdraudējumu Ludzas, Krāslavas un Rēzeknes novados; apstiprina, ka NBS kopā ar NATO sabiedrotajiem pastāvīgi monitorē gaisa telpu un ir pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības; instruē iedzīvotājus meklēt patvērumu telpās un ievērot divu sienu principu.', 'Esam pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības.', 0.9, 'Pirmā lietotāja oficiāls NBS institucionāls paziņojums @Latvijas_armija kontā 2026-05-20 par otro pēc kārtas iespējamo gaisa telpas apdraudējumu Latgalē. Saturs apstiprina iepriekš 19.05 deklarēto doktrīnu (pretgaisa pastiprināšana + NATO koordinācija), bet jauns datums un jauns ģeogrāfiskais areāls (Ludza/Krāslava/Rēzekne) padara to par patstāvīgu pozīciju, nevis dublikātu. Speaker = institūcija; claim_type=position, speaker_id NULL.', 0.8, 'https://x.com/Latvijas_armija/status/2056986893896622385', '2026-05-20 00:00:00', '2026-05-20 20:35:01', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20612, 204, 38568, 'Aizsardzība un drošība', 'NBS Štāba bataljona karavīri mācībās "Zibens 2026" Rīgā trenē sakaru spējas pilsētvidē — gan profesionālie, gan VAD karavīri mācās izvērst sakaru sistēmas kaujas apstākļos un komunicēt ar iedzīvotājiem urbanā vidē.', NULL, 0.7, 'LSM reportāža par NBS pašu izziņotu mācību "Zibens 2026" — institucionālā pozīcija par prioritātēm (urbāno sakaru spēju attīstība, VAD integrācija mācībās). Trešās puses žurnālistiska reportāža, bet NBS ir kā oficiālais avots/informētājs un mācība atspoguļo NBS doktrinālo izvēli. Vidēja salience (operacionāla mācība, ne politikas paziņojums).', 0.5, 'https://www.lsm.lv/raksts/zinas/latvija/20.05.2026-atru-un-drosu-sazinu-vajag-visur-nbs-staba-bataljona-karaviri-riga-trene-sakaru-spejas.a648035/?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-20 00:00:00', '2026-05-20 20:35:01', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20615, 15, 38693, 'Aizsardzība un drošība', 'Pateicas Kanādai par 64 miljonu eiro investīciju militārās infrastruktūras attīstībā Latvijā — uzsver, ka šādas sabiedroto investīcijas stiprina NATO austrumu flanga drošību un spēju ātri reaģēt reģionā.', 'Ārlietu ministre @AnitaAnandMP paziņoja, ka Kanāda investēs 64 miljonus eiro militārās infrastruktūras attīstībā Latvijā. Investīcijas stiprina NATO austrumu flanga drošību un sabiedroto spēju ātri reaģēt reģionā', 0.85, 'Pirmpersonu tvīts (Bražes konts, autora pateicība). Konkrēta jauna pozīcija — 64 miljonu eiro Kanādas investīcija militārajā infrastruktūrā Latvijā. Atšķiras no #20595 (19.05), kas runā par vispārējo Latvijas-Kanādas partnerības padziļināšanu Anandes vizītes laikā; šī ir specifiska finansiāla saistība, kas paziņota nākamajā dienā.', 0.75, 'https://x.com/Braze_Baiba/status/2057071924384072097', '2026-05-20 00:00:00', '2026-05-20 20:35:32', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20659, 182, 38851, 'Ārpolitika', 'Apsūdz vairākus partijas ''Progresīvie'' biedrus ''brīvas Palestīnas'' jeb HAMAS valsts idejas sludināšanā un raksturo šādu valsti kā Talibānas/Irānas tipa satelītu, kurā paši Progresīvo sludinātie principi tiktu apspiesti — pamatā minot reālus spīdzinātus, izvarotus un pazemotus cilvēkus.', 'Te jāpiebilst, ka ideju par HAMAS ''valsti'' jeb "brīvu Palestīnu" sludina arī vairāki partijas "Progresīvie" biedri. Atgādinu, ka šādās ''valstīs'' visas "Progresīvo" sludinātās idejas tiktu iemīcītas zemē', 0.75, 'Ozols pirmajā personā (''atgādinu'') izteic savu nostāju par konkrētu politisku grupu (Progresīvie) un to ārpolitisko pozīciju attiecībā uz Palestīnu/HAMAS. Skaidra polemiska pozīcija, nevis tikai Rušdi citāta retranslācija.', 0.6, 'https://x.com/OttoOzols/status/2057127972901941679', '2026-05-20 00:00:00', '2026-05-20 20:54:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20688, 15, 39342, 'Ārpolitika', 'Nosoda pazemojošo un cilvēka cieņu aizskarošo izturēšanos pret Ašdodā aizturētajiem flotiles aktīvistiem kā nepieņemamu un cilvēktiesību un starptautisko tiesību normu pārkāpumu — pieprasa aizturēto atbrīvošanu un drošu atgriešanos.', 'The humiliating and degrading treatment of detainees, as seen in the footage from Ashdod, is unacceptable and violates human rights and international law standards. The detained activists must be released and their safe return ensured.', 0.85, 'Tiešs pirmās personas izteikums tvītā. Brāže kā ārlietu ministre formulē konkrētu pozīciju: (1) izturēšanās kvalificēta kā cilvēktiesību un starptautisko tiesību pārkāpums, (2) prasība atbrīvot un nodrošināt drošu atgriešanos. Skaidrs nosodījums + rīcības aicinājums.', 0.55, 'https://x.com/Braze_Baiba/status/2057336278274769372', '2026-05-21 00:00:00', '2026-05-21 15:04:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20689, 15, 39340, 'Droni', 'Latvijas Nacionālā drošības padome brīdina, ka dronu incidenti Latvijas gaisa telpā var atkārtoties, kamēr Krievija turpina agresiju pret Ukrainu; pateicas NATO sabiedrotajiem par atbalstu un atspēko Krievijas naidīgo dezinformāciju.', 'Latvia''s National Security Council met to consult on the drone incidents in our airspace. It warned that such incidents can repeat as Russia continues aggression against Ukraine, thanked NATO Allies for support, and refuted Russia''s hostile disinformation.', 0.75, 'Brāže kā ārlietu ministre ziņo par NDP sēdes konkrētajiem secinājumiem un nostāju: (1) incidenti var atkārtoties, jo Krievija turpina karu, (2) pateicība NATO, (3) Krievijas dezinformācijas atspēkojums. Tas ir oficiālas pozīcijas paziņojums. Saistīts ar agrākiem izteikumiem par Rēzeknes droniem (#18101, #18217), bet šis ir jauns NDP sēdes rezultāts 21.05.', 0.8, 'https://x.com/Braze_Baiba/status/2057345575264137236', '2026-05-21 00:00:00', '2026-05-21 15:04:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20690, 15, 39334, 'Aizsardzība un drošība', 'Latvijas prioritātes NATO ārlietu ministru sanāksmē Helsingborgā ir NATO Austrumu flanga stiprināšana, gatavošanās Ankaras samitam un kritiska atbalsta nodrošināšana Ukrainai.', 'Our focus is on reinforcing NATO''s Eastern Flank, preparations for the Ankara Summit, and providing critical support for Ukraine.', 0.65, 'Skaidri formulētas trīs prioritātes NATO ārlietu ministru sanāksmei. Pārklājas ar agrākiem izteikumiem (#18150, #17996), bet šis ir tieši Helsingborgas sanāksmes (21.05) pozīcijas paziņojums — ne vispārīga rīcības līnija, bet konkrētas sanāksmes prioritātes.', 0.7, 'https://x.com/Braze_Baiba/status/2057414541533704470', '2026-05-21 00:00:00', '2026-05-21 15:04:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20694, 189, 39433, 'Budžets un finanses', 'Kritizē jaunās koalīcijas vienošanos par to, ka tā neparedz taupības pasākumus, bet gan paredz izdevumu palielināšanu.', 'Spriežot pēc parakstītās vienošanās, jaunā koalīcija nekādus taupības pasākumus neplāno. Tā vietā sola palielināt izdevumus.', 0.8, 'Tieša pirmpersonas pozīcija, atsaucoties uz parakstīto koalīcijas vienošanos. Skaidri formulēts kritisks komentārs par fiskālo politiku jaunajā koalīcijā. Pūce ir opozīcijā un komentē kā novērotājs ar pretēju nostāju (vēlas taupību).', 0.7, 'https://x.com/pucej/status/2057396351579705527', '2026-05-21 00:00:00', '2026-05-21 15:04:48', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20708, 30, 39370, 'Sabiedriskie mediji', 'Aicina mainīt sabiedriskā radio (Krustpunkti) intervēšanas formātu — politiķiem raidījuma sākumā dot vārdu (līdz 10 min) galvenā vēstījuma pateikšanai, tad jautājumi sekot par dzirdēto; kritizē pašreizējos tabloīdu tipa jautājumus, kas provocē tukšrunu.', 'Sabiedriskā medija klausītājiem tiktu aiztaupīts laiks un nervi, ja intervētāji raidījuma sākumā dotu katram politiķim vārdu pateikt galveno vēstījumu.', 0.7, 'Tvītu pavediena otrais ieraksts ar konkrētu formāta priekšlikumu (10 min galvenajam vēstījumam) — atšķiras no parastās retoriskas kritikas ar pamatā ievietoto procesa risinājumu. Pirmais (39371) ir retoriskā uvertīra.', 0.5, 'https://x.com/JazepsBasko/status/2057189635646709879', '2026-05-20 00:00:00', '2026-05-21 15:07:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20712, 57, 39455, 'Tieslietas', 'Asi kritizē jauno ģenerālprokuroru (Meisteru) — apgalvo, ka tas darbojas autoritārā 1937.gada padomju stilā un uzskata sevi par tiesiskumam nepakļautu.', 'Jaunais ģenerālprokurors Meisters sadomājies, ka dzīvo 1937.gadā un ka visādiem lumpeņiem domātais tiesiskums uz viņu neattiecas.', 0.7, 'Tiešs pirmās personas izteikums ar konkrētu uzbrukumu ģenerālprokuroram, salīdzinot ar 1937.gada padomju represiju gadu. Vienots ar Lapsas iepriekšējām nostājām pret ''Meistera prokuratūru'' (skat. claim no 2026-05-12). Salience 0.55 — atkārtota tēma, kura ir Lapsas centrālā kritika.', 0.55, 'https://x.com/Lato_Lapsa/status/2057400475733852522', '2026-05-21 00:00:00', '2026-05-21 15:11:48', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20713, 15, 39678, 'Ukraina un Krievija', 'Pastiprināt atbalstu Ukrainas pašaizsardzībai pret Krievijas agresiju — NATO ārlietu ministru sanāksmes ietvaros Helsingborgā tikšanās ar Ukrainas ārlietu ministru Andriju Sibihu, lai apspriestu konkrētus soļus atbalsta kāpināšanai.', 'Starting #NATO ministerial in Helsingborg, Sweden, by meeting Ukraine''s Foreign Minister @andrii_sybiha to discuss ramping up support for Ukraine self defence against Russia''s aggression.', 0.75, 'Tieša Bražes pirmās personas paziņojuma daļa — paziņo par bilaterālu tikšanos ar Ukrainas ĀM un tās mērķi (atbalsta kāpināšana Ukrainas pašaizsardzībai). Pozīcija atšķirīga no šodien jau saglabātajiem claim''iem #20690 (Helsingborgas prioritātes) un #20689 (droni) — konkrēti par bilaterālo darba kārtību ar Sibihu. Pārējais tvīta saturs par dronu incidentiem Baltijas gaisa telpā jau aptverts #20689 (2057345575264137236).', 0.75, 'https://x.com/Braze_Baiba/status/2057466277640224963', '2026-05-21 00:00:00', '2026-05-21 19:39:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20725, 15, 40104, 'Aizsardzība un drošība', 'Pēc NATO ārlietu ministru sanāksmes apstiprina, ka sabiedrotie kopīgi stiprina pretdronu spējas un NATO Austrumu flanga aizsardzību; pateicas par atbalstu pret Krievijas dezinformāciju.', 'At today''s @NATO Foreign Ministers meeting, I thanked our allies for the support. Together, we are strengthening counter-drone capabilities and defence of the Eastern Flank.', 0.8, 'Pirmās personas tvīts 2026-05-22 pēc Helsingborgas NATO ĀM sanāksmes. Apstiprina iepriekšējās dienas prioritātes (#20690) kā konkrētus iznākumus — pretdronu spēju stiprināšana un Austrumu flanga aizsardzība. Saturiski pārklājas ar #18150 (Austrumu flanga atturēšana) un #20690, bet ir jauns post-sanāksmes apstiprinājums un piesaistīts konkrētam NATO formātam ar pretdronu fokusu (Latgales 19.05. dronu konteksts).', 0.75, 'https://x.com/Braze_Baiba/status/2057732223881679341', '2026-05-22 00:00:00', '2026-05-22 18:15:25', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20726, 57, 40207, 'Korupcija un KNAB', 'Apsūdz Progresīvo deputātu Mārtiņu Staķi iesaisti ''kafijas kartelī'' un sasaista to ar dārga pulksteņa valkāšanu', 'Par ko metīsies taisnoties progresīvais Mārtiņš Staķis @MStakis - par spīdīgo grabuli uz rokas vai par iesaisti ''kafijas kartelī''? Atbildi Jūs zināt.', 0.75, 'Lapsa retoriskā jautājumā tieši apsūdz PRO deputātu Staķi divos veidos: (1) dārga pulksteņa ("spīdīgais grabulis") valkāšana, (2) iesaiste ''kafijas kartelī''. Pats Lapsa formulē apsūdzību, nevis citē sabiedrības motīvu — tā ir pirmpersonas pozīcija. Implicītā nostāja: Staķis (un PRO plašāk) ir saistīts ar negodīgu komercdarbību un personīgu bagātināšanos.', 0.5, 'https://x.com/Lato_Lapsa/status/2057785441789628764', '2026-05-22 00:00:00', '2026-05-22 18:15:58', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20727, 57, 40215, 'Vēlēšanas', 'Aicina nebalsot par Progresīvajiem — apgalvo, ka Progresīvo politiķi iegūstot dārgus pulksteņus (apgalvojums nav pierādīts) uz nodokļu maksātāju rēķina', 'Normāls komuņaku pulkstenis. Visticamākais, Rolex Submariner. 12-15 000 eiro. Balsojiet par "Progresīvo" sarkano sērgu - viņi visi pie šādiem pulksteņiem uz Jūsu rēķina vēl nav tikuši!', 0.85, 'Lapsa pirmpersonas aicinājums nebalsot par Progresīvajiem (sarkastiski apzīmēti kā "sarkanā sērga" — komunisma paralēle). Apgalvo, ka PRO politiķi izmanto valsts amatus personiskas bagātināšanās nolūkā ("uz Jūsu rēķina"). Konkrēts skaitlis (12-15 000 EUR par Rolex Submariner) un tieša politiskā aicinājums padara šo par skaidri pirmpersonas pozīciju, ne tikai sarkastisku one-liner.', 0.6, 'https://x.com/Lato_Lapsa/status/2057728926365946320', '2026-05-22 00:00:00', '2026-05-22 18:15:58', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20762, 15, 40421, 'Aizsardzība un drošība', 'Vienota un spēcīga NATO ir labākā atbilde Krievijas un citiem draudiem — paziņojums NATO ārlietu ministru sanāksmē Helsingborgā, Zviedrijā.', 'Vienota, spēcīga NATO ir labākā atbilde Krievijas un citiem draudiem', 0.85, 'pmo.ee aģentūras īsraksts ar tiešu attribūciju Braže (JV) NATO ārlietu ministru sanāksmē Helsingborgā 2026-05-22. Pamatpozīcija — NATO vienotības un spēka prioritāte kā atbilde uz Krievijas un citiem apdraudējumiem. Saskaņota ar iepriekšējām nostājām (claim 20690, 20725) par Austrumu flanga stiprināšanu, bet šeit izteikta plašāk un principiāli, nevis ar specifiskām spēju kategorijām. Tiešs citāts pieejams; konfidence 0.85 jo paraphrāzēta apkopojuma raksts, nevis pilna interview transkripcija.', 0.7, 'https://pmo.ee/8476494', '2026-05-22 00:00:00', '2026-05-22 21:16:51', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20778, 189, 40828, 'Koalīcija un partijas', 'Pārmet Vienotībai principu maiņu — kad pirms 2 nedēļām pieprasīja profesionāli aizsardzības ministra postenī, tagad piekrīt Siliņai. Sauc to par liekulību.', 'Tagad der Siliņa. Visi vārdi viņu paziņojumos ir tikai frāzes. Liekulības gadatirgus.', 0.85, 'Skaidra kritika Vienotības principu maiņai aizsardzības ministra atlases jautājumā — pretrunība starp pirms-2-nedēļu prasību pēc profesionāļa un pašreizējo piekrišanu Siliņai. Tieša citāta klātbūtne.', 0.7, 'https://x.com/pucej/status/2058186971088847300', '2026-05-22 00:00:00', '2026-05-23 19:28:59', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20779, 189, 40829, 'Aizsardzība un drošība', 'Kritizē Vienotības rīcību ar pulkvedi Melni — uzskata, ka cienījams profesionālis tika izmantots politiski īstermiņa vajadzībām, kas nestiprina valsti.', 'Cienījams profesionālis tika izmests politiskā laukā, lai nedaudz ar viņu paķircinātos un izmantotu īstermiņa vajadzībām. Tā stipru Latviju neuzbūvēt.', 0.85, 'Skaidra Vienotības rīcības kritika valdības krīzes kontekstā, fokuss uz aizsardzības personālijām (Melnis). Tieša citāta klātbūtne.', 0.65, 'https://x.com/pucej/status/2057896486487146770', '2026-05-21 00:00:00', '2026-05-23 19:28:59', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20785, 15, 41221, 'Ārpolitika', 'Atbalsta Armēnijas un visa reģiona savienojamības, ekonomiskās izaugsmes, labklājības un stabilitātes palielināšanu — pozitīvs un ļoti gaidīts notikums.', 'A positive and very welcome development for Armenia and the whole region to increase connectivity, economic growth, prosperity and stability.', 0.7, 'Pirmās personas paziņojums X par reģionālo savienojamību Armēnijā. Saskan ar iepriekšējām pozīcijām (#17877, #17878 — Latvija atbalsta Armēnijas ciešāku partnerību ar ES). Tvīts īss, bez konkrēta notikuma atsauces, tāpēc salience zema.', 0.4, 'https://x.com/Braze_Baiba/status/2058502885470585188', '2026-05-24 00:00:00', '2026-05-24 16:02:34', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20786, 15, 41222, 'Ukraina un Krievija', 'Nosoda Krievijas šausminošos uzbrukumus Kijivai — balistiskās raķetes un droni pret civilajiem mērķiem, skolām, slimnīcām, tirgiem un bumbu patvertnēm; tas nepārtrauks Ukrainas cīņu par savu nākotni un Latvijas atbalstu Ukrainai.', 'Horrific Russian attacks on Kyiv- ballistic missiles, drones on civilian targets, schools, hospitals, markets, and bomb shelters full of people. It will not stop Ukraine fighting for its future and our support to 🇺🇦.', 0.85, 'Skaidra pirmās personas nosodījuma pozīcija ar tieši citējamu izteikumu. Saskan ar konsekventu nostāju (#20462, #6901, #1575, #11118 — Krievija kā teroristu valsts, nepieciešama Ukrainas atbalsta turpināšana). Atkārtots #RussiaIsATerroristState hešetegs amplifikē #424 pamatnostāju.', 0.6, 'https://x.com/Braze_Baiba/status/2058428196769423737', '2026-05-24 00:00:00', '2026-05-24 16:02:37', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20799, 57, 41296, 'Pensijas', 'Apsūdz Šuvajevu (PRO) finanšu negodprātībā — apgalvo, ka viņš mantojumu nosaucis par pensiju, lai radītu maldīgu naratīvu 2. pensijas līmeņa debatēs.', 'Šitie abi nolēmuši atņemt Sprūdam visstulbākā meļa titulu? Viens melo par karteli un pulksteni, otrs mantojumu uzdod par pensiju…', 0.55, 'Lapsas oriģināls tvīts (nav RT) ar diviem konkrētiem apsūdzējumiem: (1) Stakis — kafijas kartelis un pulkstenis (dublē jau esošo #20726); (2) Šuvajevs — mantojuma maskēšana par pensiju 2. pensijas līmeņa kontekstā. Ekstraktējam tikai jauno Šuvajeva apsūdzību. Sarkasms ietverts (stulbākā meļa titulu, komuņaks), bet konkrēta faktiskā apsūdzība pastāv. Salience 0.4 — viens sarkastisks tvīts, ne padziļināts arguments. Confidence 0.55 — pozīcija ir uzbrukums politiķim, ne paša politikas piedāvājums.', 0.4, 'https://x.com/Lato_Lapsa/status/2058494791751520431', '2026-05-24 00:00:00', '2026-05-24 16:05:34', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20804, 15, 41577, 'Ukraina un Krievija', 'Latvija kopā ar Ukrainu un citiem partneriem sasauks ANO Drošības padomes ārkārtas sēdi (#StandWithUkraine).', 'Latvia with Ukraine and other partners will call an emergency meeting of the @UN Security Council. #StandWithUkraine', 0.85, 'Tieša pirmās personas (ārlietu ministres) paziņojums par konkrētu diplomātisku darbību — Latvijas iniciatīvu sasaukt ANO Drošības padomes ārkārtas sēdi kopā ar Ukrainu un partneriem. Konkrēta darbība, ne ceremoniāls izteikums.', 0.75, 'https://x.com/Braze_Baiba/status/2058571344858562738', '2026-05-24 00:00:00', '2026-05-24 20:13:35', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20818, 15, 42039, 'Aizsardzība un drošība', 'Latvijas apņemšanās pret NATO aliansi balstās kopējās vērtībās, gribā tās aizstāvēt un investīcijās militārajās spējās — uzņem 42 jaunos līderus no NATO Field School.', '#NATO works. Our committment to the Alliance is rooted in our shared values, the will to defend them, and investment in capabilities.', 0.75, 'Pirmpersonas tvīts par NATO Field School uzņemšanu Latvijā. Brāze tieši formulē Latvijas apņemšanos NATO aliansei — trīs pīlāri: kopējās vērtības, griba aizstāvēt, investīcijas spējās. Konsekvents ar viņas iepriekšējām pozīcijām (claim 20762 — vienota NATO kā labākā atbilde draudiem), tāpēc nav pretruna, bet salīdzinoši standarta atkārtojums ar jaunu kontekstu (jaunie līderi).', 0.55, 'https://x.com/Braze_Baiba/status/2058894665990963211', '2026-05-25 00:00:00', '2026-05-25 17:01:52', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20827, 204, 41981, 'Aizsardzība un drošība', 'NBS komandieris Kaspars Pudāns atzīst, ka nopietnāki ieguldījumi Latvijas pretgaisa aizsardzībā uzsākti vien pēdējo gadu laikā.', 'Nopietnāki ieguldījumi Latvijas pretgaisa aizsardzībā ir sākti vien pēdējo gadu laikā', 0.85, 'Komandiera tieša runa Latvijas Radio intervijā; NBS organizācijas slot ar atribūciju Pudānam. Stance ir paskaidrojuma, kāpēc esošās pretgaisa spējas nav nobriedušas — kontekstē Drīdža incidentu un iepriekšējās valdību prioritātes.', 0.8, 'https://www.diena.lv/raksts/latvija/zinas/nbs-komandieris-nopietnaki-ieguldijumi-latvijas-pretgaisa-aizsardziba-sakti-vien-pedejo-gadu-laika-14352273?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-25 00:00:00', '2026-05-25 17:02:48', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20828, 204, 41967, 'Droni', 'NBS komandieris Kaspars Pudāns atzīst, ka pretgaisa aizsardzības vienības izvietotas prioritāri lielāko pilsētu sargāšanai, tāpēc detekcijas nosegums nav vienāds visā teritorijā un līdzīgi incidenti kā Drīdža ezerā ir iespējami.', 'Pretgaisa aizsardzības vienības Latvijā vairāk izvietotas ar domu par lielāko pilsētu sargāšanu, līdz ar to detekcijas nosegums nav visur vienāds un ir iespējami līdzīgi incidenti kā nedēļas nogalē', 0.85, 'Komandiera tieša runa Latvijas Radio intervijā par Drīdža ezera drona incidentu (24.05.). NBS organizācijas slot ar atribūciju Pudānam. Pozīcija publiski apstiprina pretgaisa nosegumu nepilnību perifērijā — saturīga politikas atzīšana, kas saskan ar 41981 ieguldījumu hronoloģijas atzīšanu.', 0.8, 'https://www.lsm.lv/raksts/zinas/latvija/25.05.2026-nbs-komandieris-pretgaisa-aizsardzibas-vienibas-izvietotas-ar-domu-lielako-pilsetu-sargasanai.a648547/?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-25 00:00:00', '2026-05-25 17:02:48', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20837, 10, 42024, 'Transports', 'Satiksmes ministrijas uzticējumu "Jaunajai vienotībai" (nevis AS) pamato ar to, ka neviens cits politiskais spēks šajā jomā neesot bijis vairāk klātesošs gan no finanšu viedokļa, gan lēmumu pieņemšanā kā JV.', 'neviens cits neesot bijis vairāk klātesošs gan no finanšu viedokļa, gan lēmumu pieņemšanā kā JV', 0.8, 'Pirmās personas paskaidrojums Satiksmes ministrijas piešķiršanai JV — žurnālista parafrāzē iekļauts Kulberga arguments. Politoloģiski rezultāts traktējams arī kā ''sods'' JV (Rozenvalds), bet šeit fiksējam Kulberga oficiālo pamatojumu. Otrdienas (25.05) intervijā pēc tikšanās ar prezidentu.', 0.55, 'https://jauns.lv/raksts/zinas/710926-kulbergs-atklaj-ka-partijas-sadalijusas-ministrijas-na-un-as-iegust-nozimigas-ministrijas', '2026-05-25 00:00:00', '2026-05-25 17:04:43', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (20846, 189, 42080, 'Pašvaldības', 'Kritizē Rīgas pašvaldību, jo pašvaldības bērnudārzu noslodze tiek likta augstāk par bērnu interesēm; iebilst pret pašvaldības izvēli neanalizēt, kāpēc tās dārziņi tukši, kamēr privātie pilni', 'Rīgas pašvaldība ies pilnīgi aplamu ceļu - pašvaldības dārziņu nepietiekama noslodze viņiem svarīgāka par bērnu interesēm. Padomāt, kāpēc tā sanāk, ka pašvaldības dārziņi tukši, bet privātie - pilni, - tam vēlmes nav.', 0.85, 'Pirmās personas tiešs izteikums Pūces paša X kontā (@pucej). Konkrēta pozīcija pret Rīgas pašvaldības bērnudārzu politiku — pašvaldības dārziņu noslodze tiek likta augstāk par bērnu vajadzībām, un netiek izvērtēts paradoksāls fakts par tukšiem pašvaldības un pilniem privātajiem dārziņiem.', 0.6, 'https://x.com/pucej/status/2058793029792645181', '2026-05-25 00:00:00', '2026-05-25 17:11:50', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (22994, 15, 42884, 'Koalīcija un partijas', 'Pieņem Jaunās Vienotības uzticību un apņemas turpināt darbu Latvijas drošībai, izaugsmei un cilvēkiem — virziens: eiropeiska, droša, pārticīga, latviska Latvija ar cilvēktiesībām, taisnīgumu un pilsoniskās sabiedrības līdzdalību.', 'Paldies @Jauna_Vienotiba kolēģiem par uzticību! Turpināšu darīt savos spēkos iespējamo Latvijas drošībai, izaugsmei, mūsu cilvēkiem. Eiropeiska, droša, pārticīga, latviska Latvija, kurā cilvēktiesības, taisnīgums, pilsoniskā sabiedrības līdzdalība ir pašsaprotami.', 0.65, 'Pirmās personas paziņojums Kulberga valdības veidošanas kontekstā — Braže publiski pieņem JV partijas atbalstu un apliecina turpinājumu valdībā ar uzskaitītām vērtību prioritātēm. Vērtību kopums (eiropeiska/droša/pārticīga/latviska) ir politiska deklarācija, ne tikai ceremoniāls pateicības tvīts. Salience 0.5, jo konkrētas politikas vietā ir orientācijas vērtības + koalīcijas uzticības aktu.', 0.5, 'https://x.com/Braze_Baiba/status/2059262719153308121', '2026-05-26 00:00:00', '2026-05-26 20:47:28', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (22999, 57, 42991, 'Korupcija un KNAB', 'Apsūdz Andri Šuvajevu (PRO) personīgā labuma gūšanā no nodokļu maksātāju naudas — apgalvo, ka pērn no valsts līdzekļiem izlietoti 89 000 eiro, un netieši apvaino pašreklāmā uz nodokļu maksātāju rēķina.', 'Pērn progresīvo sērgas Šuvajevs no nodokļu maksātāju naudas izrija 89 000 eiro. Bet ne jau šo naudu Ļeņina mazbērns ieguldīs, lai viņa pauri varētu redzēt katrā pieturā…', 0.5, 'Lapsa pirmpersonas tvīts (oriģināls, ne RT) ar konkrētu skaitli (89 000 eiro) un nosauktu adresātu (Šuvajevs, PRO). Pozīcija: opozē Šuvajeva publisko līdzekļu izlietojumu pašreklāmas vajadzībām. Saskan ar Lapsas atkārtoto rakstu kopu par PRO finanšu pārkāpumiem (#20799 par mantojuma slēpšanu, #20515 par PRO/JV izšķērdību). Sarkastiska/aizskaroša leksika (''sērgas'', ''Ļeņina mazbērns'', ''pauri''), bet ar konkrētu policy referenci, tāpēc pārsniedz tīra one-liner sliekšņi. Confidence 0.5 jo tvīta links (t.co/SvIC4ZN1Uq) nav izvērsts — precīzu 89k EUR izlietojuma veidu nevar verificēt no paša tvīta. Salience 0.4 (specifisks politiķis + summa, bet minor procedural kompozits, ne kodola politika).', 0.4, 'https://x.com/Lato_Lapsa/status/2059229383693373578', '2026-05-26 20:42:59', '2026-05-26 20:48:30', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (23008, 30, 42914, 'Valsts pārvalde', 'Iebilst pret pārvaldes balstīšanu uz detalizētiem plāniem un instrukcijām; piedāvā noteikumu maiņu, kas konkrētiem cilvēkiem deva rīcības brīvību un atbildību.', 'Mēs mainīsim noteikumus, piemēram, iekš tā, ka viss nebūs jāapraksta plānos un instrukcijās, jo par lietām būs atbildīgi konkrēti cilvēki.', 0.8, 'Pirmpersonas programmatisks izteikums (Mēs piedāvāsim mainīt... noteikumus) par topošās partijas pamatpieeju. Tieša pozīcija pret plānu/instrukciju multiplicēšanu kā krīzes risinājumu un par atbildības decentralizāciju uz vietējiem cilvēkiem.', 0.6, 'https://x.com/JazepsBasko/status/2059009331652395014', '2026-05-25 00:00:00', '2026-05-26 21:36:09', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (23009, 30, 42914, 'Aizsardzība un drošība', 'Atbalsta jauna Civilās aizsardzības dienesta izveidi — bez ieročiem, ar uz krīzes vietas lēmumu pieņēmējiem, nevis instrukciju rakstītājiem.', 'Drošības darba grupas piedāvājumā figurē Civilās aizsardzības dienests, kuru veidotu nevis instrukciju rakstītāji, bet uz vietas krīzes situācijā atbildību uzņemties un lēmumus pieņemt spējīgi cilvēki bez ieročiem.', 0.8, 'Konkrēts politikas piedāvājums no Baško topošās partijas drošības darba grupas. Atšķirībā no pirmā claim — konkrēta institucionāla forma (CAD), ne vispārējs princips. Salience zemāka, jo formulēts kā piemērs no programmas, ne kā centrālā politiskā kampaņa.', 0.55, 'https://x.com/JazepsBasko/status/2059009331652395014', '2026-05-25 00:00:00', '2026-05-26 21:36:09', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (23020, 57, 42502, 'Budžets un finanses', 'Iebilst pret virspeļņas (windfall profit) jēdziena lietošanu un valsts regulējumu pār iedzīvotāju ienākumiem un patēriņu — apzīmē šādu pieeju kā komunistisku.', 'Viens no komuņaku mīļākajiem vārdiem - virspeļņa. Šādi sarkanie meļņi, kas trekni dzīvo uz Jūsu rēķina, vairāk par visu pasaulē grib regulēt to, ko Jūs darāt, cik Jūs pelnāt, ko Jūs darāt ar savu naudu.', 0.7, 'Lapsa tieši formulē ideoloģisku nostāju pret virspeļņas regulējumu un fiskālu valsts intervenci patērētāju/ražotāju attiecībās; rituāli kvalificē oponentus kā ''komuņakus'', bet pati pozīcija (pret virspeļņas regulējumu) ir skaidri pirmajā personā.', 0.55, 'https://x.com/Lato_Lapsa/status/2058943694410055981', '2026-05-25 00:00:00', '2026-05-26 21:43:22', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (23021, 57, 38463, 'Ārpolitika', 'Apsūdz ārlietu ministri (Baiba Braže, JV) Kremļa paziņojumu pilnā apjomā izplatīšanā — pieprasa netiešu atbildību par krievisku naratīvu publiskošanu.', 'Mēs esam nonākuši tiktāl, ka stulbene ārlietu ministra amatā izplata kremļa paziņojumus pilnā apmērā.', 0.7, 'Konkrēta apsūdzība pret ārlietu ministri (femin. ''stulbene'', amata norāde) par Kremļa paziņojumu izplatīšanu — Braže bija ĀM amatā 19.05.2026; pozīcija ir Lapsas pirmā personā, salience augstāka, jo skar ārpolitikas/ārvalstu informācijas drošības jautājumu.', 0.65, 'https://x.com/Lato_Lapsa/status/2056728003271417999', '2026-05-19 00:00:00', '2026-05-26 21:43:22', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (23022, 57, 37209, 'Korupcija un KNAB', 'Apsūdz Vienotības figūras (Rotbergi) selektīvā sašutumā par korupciju — apgalvo, ka tās sašust par ''desmitiem tūkstošu'' negodprātīgu izmantošanu, vienlaikus klusējot par ''miljardiem'', ko, viņaprāt, radījuši to politiskie partneri un labuma guvēji.', 'Kas ir apbrīnojamākais - tā iekšējā puvuma pakāpe, kas šiem vienotības vēža rotbergiem ļauj bez mazākā mulsuma sašust par bezgala noziedzīgi izmantotiem desmitiem tūkstošu un ne vārdu nepieminēt savu politkompanjonu un labuma guvēju izzagtos miljardus.', 0.6, 'Tipiska Lapsas pozīcija — apsūdz JV politiskās aprindas hipokrīzē korupcijas mērogu izvēlē; nosauc ''rotbergi'' kā JV-saistītus tēlus. Trūkst konkrētas lietas, tāpēc salience vidēja; pozīcija saskan ar #20515 (Linkaits, Briškens, Švinka) miljardu apsūdzību.', 0.55, 'https://x.com/Lato_Lapsa/status/2056082677703274895', '2026-05-17 00:00:00', '2026-05-26 21:43:22', 'position', NULL);
