INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504078, 6, NULL, 'Vēlēšanas', 'Atbalsta: grozīt vēlēšanu zīmju uzglabāšanas termiņu un nodrošināt pēcvēlēšanu audita iespēju. LPV deputātu iniciatīva.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 42, pret 47, atturas 3.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/093A10D81207553EC2258DCD000AFB27?OpenDocument', '2026-04-01 11:16:47', '2026-05-27 15:20:08', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504079, 6, NULL, 'Pašvaldības', 'Atbalsta: jauns likums, kas regulē pašvaldību kapsētu izveidošanu, uzturēšanu un slēgšanu, kapavietu piešķiršanu un uzskaiti, apbedīšanas kārtību, kā arī kapavietas turētāja tiesības un pienākumus — aizstāj iepriekšējo sadrumstaloto regulējumu ar vienotu normatīvo ietvaru.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 75, pret 0, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/839264BA19493481C2258DCD000AFBC5?OpenDocument', '2026-04-01 16:40:15', '2026-05-27 15:20:08', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504080, 6, NULL, 'Tieslietas', 'Atbalsta: madaras Šenbrūnas iecelšana par rajona tiesas tiesnesi.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 85, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/39BCDD98B421A0BFC2258DCD000AFB56?OpenDocument', '2026-04-01 15:11:26', '2026-05-27 15:20:08', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504081, 6, NULL, 'Sociālā politika', 'Atbalsta: aizliedz pilngadīgām personām, kuras atrodas uzraudzības, aprūpes, izglītošanas vai citas profesionālas autoritātes pozīcijā attiecībā pret bērnu, veidot ar šo bērnu intīmas vai seksuāla rakstura attiecības — mērķis ir aizsargāt 16–17 gadus vecus jauniešus no varas pozīcijas izmantošanas.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 74, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/4C9D2B288F4F6C40C2258DCD000AFBA7?OpenDocument', '2026-04-01 16:49:07', '2026-05-27 15:20:08', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504082, 6, NULL, 'Valsts pārvalde', 'Atbalsta: likumprojekta "Grozījums Lauksaimniecības un lauku attīstības likumā" (1248/Lp14) otrreizēja caurlūkošana (2. lasījums). Steidzamā kārtībā pieņemtais grozījums lauksaimniecības un lauku attīstības jomā. Pieņemts ar 79 balsīm par.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 79, pret 8, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/64E6CFC2E82A82EEC2258DCD000AFB75?OpenDocument', '2026-04-01 15:30:17', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504083, 6, NULL, 'Pašvaldības', 'Atbalsta: ievieš būvniecības ieceres realizāciju pa posmiem (var sākt pamatu būvdarbus, kamēr turpinās augšējo stāvu projektēšana), atceļ novecojušo būvkomersantu klasifikācijas sistēmu un vienkāršo militāro objektu būvniecību — ļauj atkāpties no civilajiem būvnormatīviem bez saskaņošanas, lai paātrinātu modulāro būvju izvietošanu.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 69, pret 0, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/CDEF9B23E7A6FC13C2258DCD000AFBAB?OpenDocument', '2026-04-01 17:00:50', '2026-05-27 15:20:09', 'saeima_vote', NULL);
