INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504089, 6, NULL, 'Vide', 'Atbalsta: ievieš obligātu elektronisko smēķēšanas ierīču (e-cigarešu) depozīta sistēmu ar atpakaļpieņemšanu un depozīta maksu, pārņem ES Direktīvas 2024/884 prasības par elektroiekārtu atkritumiem un ES Bateriju regulas 2023/1542 normas, kā arī aktualizē institucionālo regulējumu pēc Enerģētikas un vides aģentūras pievienošanas Valsts vides dienestam.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 69, pret 4, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/FFE36A67EA578A28C2258DCD000AFBA9?OpenDocument', '2026-04-01 16:57:25', '2026-05-27 15:20:09', 'saeima_vote', NULL);
