INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504091, 6, NULL, 'Mežsaimniecība', 'Atbalsta: zZS deputātu (Augulis, Maslovskis, Zemmers, Ceļapīters, Burovs) iniciatīva grozīt Meža likumu - paredzēta nodošanai Tautsaimniecības, agrārās, vides un reģionālās politikas komisijai. Saeima noraidīja jau nodošanas stadijā (par=34, pret=40, atturas=2) - koalīcija (JV/NA/PRO) iebilda pret opozīcijas piedāvāto meža apsaimniekošanas regulējuma izmaiņu virzību.', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 34, pret 40, atturas 2.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/0C639EFC3D6E8E73C2258DCD000AFB29?OpenDocument', '2026-04-01 11:30:28', '2026-05-27 15:20:09', 'saeima_vote', NULL);
