INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504093, 6, NULL, 'Tieslietas', 'Atbalsta: papildina Fizisko personu reģistru ar ziņām par personu apbedīšanu, kremāciju, pārapbedīšanu un urnas pārvietošanu; nosaka kapsētu īpašniekiem un kremācijas pakalpojumu sniedzējiem pienākumu aktualizēt šīs ziņas reģistrā (saistīts ar jauno Kapsētu likumu).', NULL, 1.0, 'Saeimas balsojums 2026-04-01: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 76, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BC932E2C6DAC0099C2258DCD000AFB8C?OpenDocument', '2026-04-01 16:26:22', '2026-05-27 15:20:09', 'saeima_vote', NULL);
