INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504095, 6, NULL, 'Vēlēšanas', 'Atbalsta: paredz 2026. gada Saeimas vēlēšanās balsu skaitīšanu veikt manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un Valsts prezidenta aicinājumu nodrošināt caurspīdīgu vēlēšanu norisi.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 93, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/23D5A329E7A92AA7C2258DC700107956?OpenDocument', '2026-03-26 09:57:55', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504096, 6, NULL, 'Aizsardzība un drošība', 'Atbalsta: pagarina Saeimas parlamentārās izmeklēšanas komisijas par Rīgas centralizētās siltumapgādes sadārdzinājumu un enerģētiskās drošības riskiem darbības termiņu.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 87, pret 1, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/00C2225850416ECAC2258DC700107AD1?OpenDocument', '2026-03-26 16:32:47', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504097, 6, NULL, 'Valsts pārvalde', 'Atbalsta: ievieš jaunu Civilprocesa likuma nodaļu par kopīpašuma dalīšanas lietām tiesā, nosakot prasības pieteikuma saturu, piekritību un kārtību, kā arī paredz tiesas deponēto līdzekļu izmantošanu zemesgrāmatas un Valsts zemes dienesta izdevumu segšanai.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 55, pret 12, atturas 6.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/081308D417311B5AC2258DC700107A09?OpenDocument', '2026-03-26 14:19:45', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504098, 6, NULL, 'Valsts pārvalde', 'Atbalsta: nodod 10 177 pilsoņu kolektīvo iesniegumu par algu atklātību valsts pārvaldē Valsts pārvaldes un pašvaldības komisijai turpmākai izvērtēšanai.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 89, pret 0, atturas 2.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/16936FBF19DB6C04C2258DC700107AD5?OpenDocument', '2026-03-26 16:47:45', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504099, 6, NULL, 'Valsts pārvalde', 'Atbalsta: ievieš detalizētu regulējumu par dzīvokļu kopīpašuma dalīšanu — nosaka atsevišķās lietošanas tiesības uz koplietošanas telpām, jumtu un ārsienām, atceļ pirmpirkuma tiesības autostāvvietu kopīpašumam un paredz kopīgās infrastruktūras lietošanas noteikumus.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 78, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/1F6D0D5DCAFE0F94C2258DC700107A51?OpenDocument', '2026-03-26 15:41:35', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504100, 6, NULL, 'Vide', 'Atbalsta: apstiprina Latvijas pievienošanos 2009. gada Honkongas Starptautiskajai konvencijai par kuģu drošu un videi nekaitīgu pārstrādi, nosakot Satiksmes ministrijas un Valsts vides dienesta atbildību konvencijas saistību izpildē.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 85, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/2ADEE566EAD110E7C2258DC7001079C8?OpenDocument', '2026-03-26 13:46:25', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504101, 6, NULL, 'Izglītība', 'Atbalsta: paredz pedagogiem iespēju brīvprātīgi doties pensijā no 60 gadu vecuma ar 35 gadu darba stāžu; iesniegts pēc aptuveni 12 000 parakstu petīcijas. Saeima noraidīja likumprojekta nodošanu komisijām.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 36, pret 14, atturas 37.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/4B354EEA3B01E136C2258DC70010796E?OpenDocument', '2026-03-26 10:07:26', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504102, 6, NULL, 'Pašvaldības', 'Atbalsta: paredz atcelt nekustamā īpašuma nodokli par primāro dzīvesvietu, argumentējot, ka NĪN ir nodoklis par eksistenci, kas skar katru Latvijas ģimeni.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 54, pret 32, atturas 1.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/53EDAD15D94E0B0BC2258DC700107984?OpenDocument', '2026-03-26 10:16:54', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504103, 6, NULL, 'Aizsardzība un drošība', 'Atbalsta: pārskata radiācijas drošības un kodoldrošības pamatprincipus — nosaka desmit jonizējošā starojuma avotu izmantošanas principus, aizliedz kodoliekārtu un radioaktīvo atkritumu apglabāšanas objektu izvietošanu īpaši aizsargājamās dabas teritorijās un apdzīvotās vietās, kā arī uzdod iestādēm veikt pētniecību radiācijas drošības jomā.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 85, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/5A7F193EF4F19F6DC2258DC700107A86?OpenDocument', '2026-03-26 16:20:33', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504104, 6, NULL, 'Imigrācija', 'Atbalsta: paredz iespēju anulēt termiņuzturēšanās atļauju ārzemniekam, kurš viena kalendāra gada laikā izdarījis trīs administratīvos pārkāpumus sabiedriskās kārtības, pārvaldes vai ceļu satiksmes jomā.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 78, pret 8, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/6A3D5E0BE5402D02C2258DC7001079DD?OpenDocument', '2026-03-26 13:52:42', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504105, 6, NULL, 'Degviela un enerģētika', 'Atbalsta: uz laiku (no 2026. gada 1. aprīļa līdz 30. jūnijam) samazina akcīzes nodokli dīzeļdegvielai par aptuveni 15 % — no 467 uz 396 eiro par 1000 litriem, lai ierobežotu naftas produktu cenu pieauguma ietekmi uz iedzīvotājiem un ekonomiku.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 94, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/736FAFBD8A08BDA7C2258DC7001079AF?OpenDocument', '2026-03-26 12:26:47', '2026-05-27 15:20:09', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504106, 6, NULL, 'Valsts pārvalde', 'Atbalsta: jauns Sporta likums, kas aizstāj 2002. gada likumu — ievieš Valsts sporta fondu privātā finansējuma piesaistei, izveido vienotu Sporta reģistru, modernizē sporta pārvaldības sistēmu un nostiprina bērnu un jauniešu sporta prioritāti.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 83, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/745D4C2FF53F29CFC2258DC7001079F5?OpenDocument', '2026-03-26 14:08:19', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504107, 6, NULL, 'Valsts pārvalde', 'Nebalsoja par: jauns likums, kas nosaka biobanku izveides un darbības nosacījumus — regulē cilvēka bioloģisko paraugu un ar tiem saistīto ģenētisko datu ieguvi, apstrādi, uzglabāšanu un izmantošanu pētniecībai un personalizētai medicīnai, vienlaikus aizsargājot donoru tiesības.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Nebalsoja. Kopējais rezultāts: par 80, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/7A69776D990B068EC2258DC700107A0B?OpenDocument', '2026-03-26 14:30:25', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504108, 6, NULL, 'ES politika', 'Iebilst pret: par Partnerības nolīgumu starp Eiropas Savienību un tās dalībvalstīm, no vienas puses, un Āfrikas, Karību jūras reģiona un Klusā okeāna valstu organizācijas dalībvalstīm, no otras puses (1014/Lp14), 1', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Pret. Kopējais rezultāts: par 76, pret 2, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/80B33FFD254D8C12C2258DC700107A0F?OpenDocument', '2026-03-26 14:38:27', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504109, 6, NULL, 'Valsts pārvalde', 'Atbalsta: daļa no vides likumu paketes — pārstrukturē lēmumu apstrīdēšanas kārtību piesārņojuma novēršanas jomā, nododot Enerģētikas un vides aģentūras funkcijas Valsts vides dienesta ģenerāldirektoram pēc abu iestāžu apvienošanas.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 86, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/8D1084C1BA8B427AC2258DC700107A8E?OpenDocument', '2026-03-26 16:22:43', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504110, 6, NULL, 'Tieslietas', 'Atbalsta: pagarina priekšlikumu iesniegšanas termiņu Kriminālprocesā nodarītā kaitējuma atlīdzināšanas likuma grozījumiem (1019/Lp14) līdz 2026. gada 9. aprīlim.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 79, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/A28B358A469108A5C2258DC700107ACE?OpenDocument', '2026-03-26 16:30:16', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504111, 6, NULL, 'Aizsardzība un drošība', 'Atbalsta: paaugstina valsts aizsardzības finansējuma mērķi no 3% līdz 5% no IKP, sākot ar 2027. gadu, lai paātrinātu Nacionālo bruņoto spēku attīstību saistībā ar ģeopolitiskajām izmaiņām pēc Krievijas iebrukuma Ukrainā.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 83, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/A5094FACC3B8C69CC2258DC700107A57?OpenDocument', '2026-03-26 16:15:44', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504112, 6, NULL, 'Aizsardzība un drošība', 'Atbalsta: grozījumi Iekšējās drošības fonda, Patvēruma, migrācijas un integrācijas fonda un Finansiāla atbalsta instrumenta robežu pārvaldībai un vīzu politikai 2021.–2027. gada plānošanas perioda vadības likum', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 84, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/A5FAC5EE07376402C2258DC7001079F7?OpenDocument', '2026-03-26 14:11:04', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504113, 6, NULL, 'Valsts pārvalde', 'Atbalsta: transponē ES Direktīvu 2024/1619, nosakot kredītiestādēm papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, uzlabojot administratīvo pasākumu piemērošanas mehānismus un nodrošinot efektīvāku uzraudzību.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 86, pret 4, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/AE5B38151FA10F3BC2258DC700107A3A?OpenDocument', '2026-03-26 15:01:11', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504114, 6, NULL, 'Valsts pārvalde', 'Atbalsta: transponē ES Direktīvu 2024/1619 un Direktīvu 2019/2034, nosakot ieguldījumu brokeru sabiedrībām papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, kā arī kapitāla un likviditātes pietiekamības novērtēšanu.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 70, pret 4, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/B0D07835326BF8EFC2258DC700107A42?OpenDocument', '2026-03-26 15:38:42', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504115, 6, NULL, 'Sociālā politika', 'Atbalsta: pilnveido sociālo uzņēmumu regulējumu — pagarina pārskatu iesniegšanas periodu no 2 līdz 3 gadiem, paplašina dividenžu sadales iespējas līdz 50% no peļņas, precizē uzraudzības un ziedojumu nodokļu normas.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 86, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BB879E1A9F539FB2C2258DC7001079F3?OpenDocument', '2026-03-26 13:54:25', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504116, 6, NULL, 'Degviela un enerģētika', 'Atbalsta: nosaka pagaidu pazeminātas akcīzes nodokļa likmes dīzeļdegvielai (396 EUR/1000 l) un citiem naftas produktiem no 2026. gada 1. aprīļa līdz 30. jūnijam, lai ierobežotu degvielas cenu pieauguma ietekmi uz tautsaimniecību enerģētiskās krīzes dēļ.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 84, pret 0, atturas 0.', 0.9, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BC4B9F5E81F86E11C2258DC7001079C2?OpenDocument', '2026-03-26 13:42:15', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504117, 6, NULL, 'Transports', 'Atbalsta: deputātu (Rokpelnis, Brigmanis, Bērziņš, Burovs, Ceļapīters) ierosinātie grozījumi Ceļu satiksmes likumā, nodoti Tautsaimniecības un Aizsardzības komisijām izskatīšanai.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 84, pret 4, atturas 0.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/D1795CF4EDB5F667C2258DC700107986?OpenDocument', '2026-03-26 10:23:32', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504118, 6, NULL, 'Tieslietas', 'Atbalsta: apstiprina Latvijas un Šrilankas divpusējo nolīgumu par notiesāto personu nodošanu soda izciešanai mītnes valstī, lai veicinātu sadarbību krimināltiesību jomā un notiesāto resocializāciju.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 86, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/D43114B7BC97C8FEC2258DC7001079D7?OpenDocument', '2026-03-26 13:47:50', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504119, 6, NULL, 'Aizsardzība un drošība', 'Atbalsta: paaugstina valsts aizsardzības finansējuma mērķi no 3% līdz 5% no IKP, sākot ar 2027. gadu, lai paātrinātu Nacionālo bruņoto spēku attīstību saistībā ar ģeopolitiskajām izmaiņām pēc Krievijas iebrukuma Ukrainā.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 80, pret 0, atturas 0.', 0.9, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/DEE4A3E289BE0ADFC2258DC700107A6B?OpenDocument', '2026-03-26 16:16:11', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504120, 6, NULL, 'Vēlēšanas', 'Atbalsta: nosaka, ka 2026. gada Saeimas vēlēšanās balsu skaitīšana notiek manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un to iespējamo ietekmi uz vēlēšanu procesu.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 93, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E0AE6C695FD53521C2258DC70010795A?OpenDocument', '2026-03-26 09:58:28', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504121, 6, NULL, 'Imigrācija', 'Atbalsta: transponē ES Direktīvu 2024/1233 par vienotu pieteikšanās procedūru trešo valstu valstspiederīgo uzturēšanās un darba atļaujām, kā arī ievieš papildu regulējumu ilgtermiņa vīzu pieteikumu deleģēšanai ārpakalpojumu sniedzējiem.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 79, pret 8, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E0E2275BD9DD2B9AC2258DC700107A11?OpenDocument', '2026-03-26 14:48:57', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504122, 6, NULL, 'Valsts pārvalde', 'Atbalsta: nodod lauku zemes atsavināšanas darījumu piekrišanas kompetenci no novada domes koleģiālā lēmuma uz domes priekšsēdētāju (līdzīgi kā pilsētās), samazinot administratīvo slogu un paātrinot procedūru, nemainot materiāltiesiskos kritērijus zemes iegūšanai.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 83, pret 0, atturas 0.', 0.9, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E6B5A03371BD8579C2258DC700107ABD?OpenDocument', '2026-03-26 16:29:31', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504123, 6, NULL, 'Valsts pārvalde', 'Atbalsta: nosaka kartību jaunizveidotu valsts zinātnisko institūtu (atvasinātu publisku personu) pārvaldībai pēc reorganizācijas -- direktora pienākumu izpildītāja iecelšanu, pilnsapulces sasaukšanu un reģistrāciju. Izslēdz no likuma FEI, BMC un OSI nosaukumus saistībā ar to konsolidāciju EDI un jaunā Nacionālā pētniecības un inovāciju institūta izveidošanu.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 84, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E6C57C427736CA6AC2258DC7001079D9?OpenDocument', '2026-03-26 13:48:47', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504124, 6, NULL, 'Vēlēšanas', 'Atbalsta: paredz pagarināt vēlēšanu zīmju uzglabāšanas termiņu līdz tiesas nolēmuma spēkā stāšanās dienai un noteikt manuālu balsu skaitīšanu visos 2026. gada Saeimas vēlēšanu iecirkņos bez tehnisku palīglīdzekļu starpniecības.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 37, pret 18, atturas 30.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/EF48F5BA1844E681C2258DC700107982?OpenDocument', '2026-03-26 10:10:32', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504125, 6, NULL, 'Ukraina un Krievija', 'Atbalsta: uzdod Ministru kabinetam publicēt to importētāju un eksportētāju sarakstu, kuri turpina veikt darījumus ar Krievijas Federāciju un Baltkrievijas Republiku, lai nodrošinātu sabiedrības informētību par tirdzniecības sakaru uzturēšanu ar agresoru valstīm.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 25, pret 20, atturas 40.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/F83D991816E39EA7C2258DC700107AD3?OpenDocument', '2026-03-26 16:45:02', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504126, 6, NULL, 'Tieslietas', 'Nebalsoja par: lPV iniciatīva aizliegt KNAB darbiniekiem un vadībai dubultpilsonību; noraidīta kā daļa no LPV paketes.', NULL, 1.0, 'Saeimas balsojums 2026-04-16: Jānis Dombrava balsoja Nebalsoja. Kopējais rezultāts: par 23, pret 45, atturas 14.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=5234f1ea-56f0-4bbc-a903-dbc459e19055', '2026-04-16 09:40:27', '2026-05-27 15:20:10', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504127, 10, NULL, 'Vēlēšanas', 'Atbalsta: paredz 2026. gada Saeimas vēlēšanās balsu skaitīšanu veikt manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un Valsts prezidenta aicinājumu nodrošināt caurspīdīgu vēlēšanu norisi.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 93, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/23D5A329E7A92AA7C2258DC700107956?OpenDocument', '2026-03-26 09:57:55', '2026-05-27 15:20:38', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504128, 10, NULL, 'Aizsardzība un drošība', 'Atbalsta: pagarina Saeimas parlamentārās izmeklēšanas komisijas par Rīgas centralizētās siltumapgādes sadārdzinājumu un enerģētiskās drošības riskiem darbības termiņu.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 87, pret 1, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/00C2225850416ECAC2258DC700107AD1?OpenDocument', '2026-03-26 16:32:47', '2026-05-27 15:20:38', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504129, 10, NULL, 'Valsts pārvalde', 'Atbalsta: nodod 10 177 pilsoņu kolektīvo iesniegumu par algu atklātību valsts pārvaldē Valsts pārvaldes un pašvaldības komisijai turpmākai izvērtēšanai.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 89, pret 0, atturas 2.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/16936FBF19DB6C04C2258DC700107AD5?OpenDocument', '2026-03-26 16:47:45', '2026-05-27 15:20:38', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504130, 10, NULL, 'Izglītība', 'Atbalsta: paredz pedagogiem iespēju brīvprātīgi doties pensijā no 60 gadu vecuma ar 35 gadu darba stāžu; iesniegts pēc aptuveni 12 000 parakstu petīcijas. Saeima noraidīja likumprojekta nodošanu komisijām.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 36, pret 14, atturas 37.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/4B354EEA3B01E136C2258DC70010796E?OpenDocument', '2026-03-26 10:07:26', '2026-05-27 15:20:38', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504131, 10, NULL, 'Pašvaldības', 'Nebalsoja par: paredz atcelt nekustamā īpašuma nodokli par primāro dzīvesvietu, argumentējot, ka NĪN ir nodoklis par eksistenci, kas skar katru Latvijas ģimeni.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Nebalsoja. Kopējais rezultāts: par 54, pret 32, atturas 1.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/53EDAD15D94E0B0BC2258DC700107984?OpenDocument', '2026-03-26 10:16:54', '2026-05-27 15:20:38', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504132, 10, NULL, 'Aizsardzība un drošība', 'Atbalsta: pārskata radiācijas drošības un kodoldrošības pamatprincipus — nosaka desmit jonizējošā starojuma avotu izmantošanas principus, aizliedz kodoliekārtu un radioaktīvo atkritumu apglabāšanas objektu izvietošanu īpaši aizsargājamās dabas teritorijās un apdzīvotās vietās, kā arī uzdod iestādēm veikt pētniecību radiācijas drošības jomā.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 85, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/5A7F193EF4F19F6DC2258DC700107A86?OpenDocument', '2026-03-26 16:20:33', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504133, 10, NULL, 'Degviela un enerģētika', 'Atbalsta: uz laiku (no 2026. gada 1. aprīļa līdz 30. jūnijam) samazina akcīzes nodokli dīzeļdegvielai par aptuveni 15 % — no 467 uz 396 eiro par 1000 litriem, lai ierobežotu naftas produktu cenu pieauguma ietekmi uz iedzīvotājiem un ekonomiku.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 94, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/736FAFBD8A08BDA7C2258DC7001079AF?OpenDocument', '2026-03-26 12:26:47', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504134, 10, NULL, 'Valsts pārvalde', 'Atbalsta: jauns likums, kas nosaka biobanku izveides un darbības nosacījumus — regulē cilvēka bioloģisko paraugu un ar tiem saistīto ģenētisko datu ieguvi, apstrādi, uzglabāšanu un izmantošanu pētniecībai un personalizētai medicīnai, vienlaikus aizsargājot donoru tiesības.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 80, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/7A69776D990B068EC2258DC700107A0B?OpenDocument', '2026-03-26 14:30:25', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504135, 10, NULL, 'ES politika', 'Atbalsta: par Partnerības nolīgumu starp Eiropas Savienību un tās dalībvalstīm, no vienas puses, un Āfrikas, Karību jūras reģiona un Klusā okeāna valstu organizācijas dalībvalstīm, no otras puses (1014/Lp14), 1', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 76, pret 2, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/80B33FFD254D8C12C2258DC700107A0F?OpenDocument', '2026-03-26 14:38:27', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504136, 10, NULL, 'Valsts pārvalde', 'Atbalsta: daļa no vides likumu paketes — pārstrukturē lēmumu apstrīdēšanas kārtību piesārņojuma novēršanas jomā, nododot Enerģētikas un vides aģentūras funkcijas Valsts vides dienesta ģenerāldirektoram pēc abu iestāžu apvienošanas.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 86, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/8D1084C1BA8B427AC2258DC700107A8E?OpenDocument', '2026-03-26 16:22:43', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504137, 10, NULL, 'Tieslietas', 'Atbalsta: pagarina priekšlikumu iesniegšanas termiņu Kriminālprocesā nodarītā kaitējuma atlīdzināšanas likuma grozījumiem (1019/Lp14) līdz 2026. gada 9. aprīlim.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 79, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/A28B358A469108A5C2258DC700107ACE?OpenDocument', '2026-03-26 16:30:16', '2026-05-27 15:20:39', 'saeima_vote', NULL);
