INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504139, 10, NULL, 'Valsts pārvalde', 'Nebalsoja par: transponē ES Direktīvu 2024/1619, nosakot kredītiestādēm papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, uzlabojot administratīvo pasākumu piemērošanas mehānismus un nodrošinot efektīvāku uzraudzību.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Nebalsoja. Kopējais rezultāts: par 86, pret 4, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/AE5B38151FA10F3BC2258DC700107A3A?OpenDocument', '2026-03-26 15:01:11', '2026-05-27 15:20:39', 'saeima_vote', NULL);
