INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504141, 10, NULL, 'Aizsardzība un drošība', 'Atbalsta: paaugstina valsts aizsardzības finansējuma mērķi no 3% līdz 5% no IKP, sākot ar 2027. gadu, lai paātrinātu Nacionālo bruņoto spēku attīstību saistībā ar ģeopolitiskajām izmaiņām pēc Krievijas iebrukuma Ukrainā.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 80, pret 0, atturas 0.', 0.9, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/DEE4A3E289BE0ADFC2258DC700107A6B?OpenDocument', '2026-03-26 16:16:11', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504142, 10, NULL, 'Vēlēšanas', 'Atbalsta: nosaka, ka 2026. gada Saeimas vēlēšanās balsu skaitīšana notiek manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un to iespējamo ietekmi uz vēlēšanu procesu.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 93, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E0AE6C695FD53521C2258DC70010795A?OpenDocument', '2026-03-26 09:58:28', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504143, 10, NULL, 'Imigrācija', 'Nebalsoja par: transponē ES Direktīvu 2024/1233 par vienotu pieteikšanās procedūru trešo valstu valstspiederīgo uzturēšanās un darba atļaujām, kā arī ievieš papildu regulējumu ilgtermiņa vīzu pieteikumu deleģēšanai ārpakalpojumu sniedzējiem.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Nebalsoja. Kopējais rezultāts: par 79, pret 8, atturas 1.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E0E2275BD9DD2B9AC2258DC700107A11?OpenDocument', '2026-03-26 14:48:57', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504144, 10, NULL, 'Valsts pārvalde', 'Atbalsta: nodod lauku zemes atsavināšanas darījumu piekrišanas kompetenci no novada domes koleģiālā lēmuma uz domes priekšsēdētāju (līdzīgi kā pilsētās), samazinot administratīvo slogu un paātrinot procedūru, nemainot materiāltiesiskos kritērijus zemes iegūšanai.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 83, pret 0, atturas 0.', 0.9, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E6B5A03371BD8579C2258DC700107ABD?OpenDocument', '2026-03-26 16:29:31', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504145, 10, NULL, 'Vēlēšanas', 'Atbalsta: paredz pagarināt vēlēšanu zīmju uzglabāšanas termiņu līdz tiesas nolēmuma spēkā stāšanās dienai un noteikt manuālu balsu skaitīšanu visos 2026. gada Saeimas vēlēšanu iecirkņos bez tehnisku palīglīdzekļu starpniecības.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 37, pret 18, atturas 30.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/EF48F5BA1844E681C2258DC700107982?OpenDocument', '2026-03-26 10:10:32', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504146, 10, NULL, 'Ukraina un Krievija', 'Atbalsta: uzdod Ministru kabinetam publicēt to importētāju un eksportētāju sarakstu, kuri turpina veikt darījumus ar Krievijas Federāciju un Baltkrievijas Republiku, lai nodrošinātu sabiedrības informētību par tirdzniecības sakaru uzturēšanu ar agresoru valstīm.', NULL, 1.0, 'Saeimas balsojums 2026-03-26: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 25, pret 20, atturas 40.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/F83D991816E39EA7C2258DC700107AD3?OpenDocument', '2026-03-26 16:45:02', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504147, 10, NULL, 'Tieslietas', 'Iebilst pret: lPV iniciatīva aizliegt KNAB darbiniekiem un vadībai dubultpilsonību; noraidīta kā daļa no LPV paketes.', NULL, 1.0, 'Saeimas balsojums 2026-04-16: Andris Kulbergs balsoja Pret. Kopējais rezultāts: par 23, pret 45, atturas 14.', 0.5, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=5234f1ea-56f0-4bbc-a903-dbc459e19055', '2026-04-16 09:40:27', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504148, 10, NULL, 'Izglītība', 'Nebalsoja par: grozījumi Izglītības likumā (1. lasījums, steidzams); paketes daļa ar Augstskolu un Profesionālās izglītības grozījumiem — saskaņo izglītības likumdošanas sistēmu; pieņemts ar 77 par.', NULL, 1.0, 'Saeimas balsojums 2026-04-16: Andris Kulbergs balsoja Nebalsoja. Kopējais rezultāts: par 77, pret 0, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=9a7379a5-7a2c-4c51-ab88-b89cc228a489', '2026-04-16 16:07:37', '2026-05-27 15:20:39', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (504149, 10, NULL, 'Sociālā politika', 'Nebalsoja par: 11 391 pilsoņa kolektīvā iesnieguma par brīvprātīgu 2. pensiju līmeņa kapitāla izņemšanu turpmākā virzība noraidīta (30:15, 27 atturas) — Saeima nepalaiž tālāk pensiju sistēmas atvēršanas ideju, par kuru pilsoniskā sabiedrība bija savākusi parakstus.', NULL, 1.0, 'Saeimas balsojums 2026-05-21: Andris Kulbergs balsoja Nebalsoja. Kopējais rezultāts: par 30, pret 15, atturas 27.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/DFC923F83C633527C2258DFE00405122?OpenDocument', '2026-05-21 14:37:16', '2026-05-27 15:20:40', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520837, 57, 43602, 'Tieslietas', 'Apsūdz Centrālās zemes komisijas vadītāju Mikiņu likuma neievērošanā — apgalvo, ka tādiem ierēdņiem ("komuņakiem") svarīgāka ir "revolucionārā pārliecība" nekā tas, ko atļauj likums.', 'Viena no pamatpazīmēm - viņiem nospļauties uz "ko tur kāds likums neļauj", jo galvenais ir revolucionārā pārliecība.', 0.55, 'Pirmā persona, tieša X publikācija. Substantīvs likumības arguments (ierēdņi rīkojas pretrunā ar likumu) iesaiņots sarkasmā un personiskā apvainojumā ("čurudzeltenais parists"). Pozīcija: likuma pārākums pār ideoloģisko pārliecību publiskā pārvaldē. Salience zema — viena ierēdņa atsevišķs incidents bez konkrēta likumprojekta vai politikas piedāvājuma.', 0.35, 'https://x.com/Lato_Lapsa/status/2059593164017541541', '2026-05-27 17:08:20', '2026-05-27 17:21:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520838, 57, 43585, 'Sabiedriskie mediji', 'Apsūdz sabiedriskā medija žurnālistus ("propagandonus") Siliņas izteikuma falsificēšanā — apgalvo, ka oriģinālā teikta vārds "ideoloģiju", bet medijs to "izlabojis", lai paslēptu premjeres gramatikas kļūdu.', 'Noklausījos oriģinālu. Izrādās, viss ir vēl smieklīgāk - propagandoni atkal ir ķēkšu izlabojuši, tikai šoreiz viņu padarījuši par vēl lielāku muļķi.', 0.65, 'Tieša pirmās personas pozīcija ar konkrētu pierādījumu (apgalvo, ka noklausījies oriģinālu un salīdzinājis ar medija publicēto). Konsekventa ar viņa iepriekšējām claim-ām par LTV/sabiedrisko mediju selektīvu rediģēšanu (sk. #7349, #11130, #17998). Saglabā vienotu tēzi — sabiedriskais medijs slēpj politiķu kļūdas.', 0.55, 'https://x.com/Lato_Lapsa/status/2059636211904393360', '2026-05-27 17:08:18', '2026-05-27 17:21:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520839, 57, 43588, 'Sabiedriskie mediji', 'Sarkastiski izsmej sabiedrisko mediju ("propagandonus") un Siliņu ("stulbo ķēkšu") par gramatiskās kļūdas izteikumu (ideoloģijas locīšana) — apgalvo, ka medijs šoreiz nemēģināja kļūdu izlabot, jo Siliņa vairs nav premjere.', '"Viņu ideoloģija liek pa priekšu sabiedrības intereses, tāpēc atbildīgos amatos viņus nevar laist..." Tikko stulbā ķēkša izlidoja no premjeres amata, "sabiedriskā" medija neimanes un pārējie propagandoni atģida, ka viņiem nemaz nav obligāti jālabo izteiktā kārtējā muļķība.', 0.6, 'Pirmā persona — uzbrukums sabiedriskajam medijam par selektīvu Siliņas izteikumu apstrādi pēc viņas atkāpšanās. Sub-stance: medijs slēpa Siliņas kļūdas, kamēr viņa bija amatā, bet vairs nedara to pēc atkāpšanās. Konsekventa ar viņa medija-kritikas līniju. Personīgais apvainojums ("stulbā ķēkša") ir rāmējums, ne pozīcijas kodols.', 0.5, 'https://x.com/Lato_Lapsa/status/2059623011087429830', '2026-05-27 17:08:18', '2026-05-27 17:21:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520840, 15, 43470, 'Droni', 'Pretdronu aizsardzībai nepieciešama agrīnā brīdināšana, identificēšana un elastīga reakcija; atbildība nevar būt tikai bruņoto spēku pārziņā, jāiesaistās robežsardzei un citiem dienestiem.', 'nepieciešama agrīnā brīdināšana, identificēšana un elastīga reakcija, un atzīmēja, ka atbildība par reaģēšanu nevar būt tikai bruņoto spēku pārziņā, ir jāiesaistās arī robežsardzei un citiem dienestiem', 0.85, 'LA.lv raksts citē Braži tieši Dronu samitā 27.05.2026 — viņa formulē konkrētu starpiestāžu pretdronu pieeju: agrīnā brīdināšana + identificēšana + elastīga reakcija, ar robežsardzes un citu dienestu iesaisti, ne tikai NBS. Konkrēta politikas nostāja, ne ceremoniāls izteikums.', 0.85, 'https://www.la.lv/viens-drons-dazkart-grutak-atrodams-neka-simti-nbs-komandieris-atklaj-problemas-latvijas-gaisa-telpas-aizsdardziba', '2026-05-27 00:00:00', '2026-05-27 17:22:22', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520853, 10, 43473, 'Valsts pārvalde', 'Atsakās pirms Saeimas apstiprinājuma izpaust topošā premjera biroja sastāvu — uzskata, ka par šiem jautājumiem nedrīkst runāt, kamēr balsojums nav noticis: ''Nedrīkst teikt hop, pirms nav apstiprinājuma.''', 'Nedrīkst teikt hop, pirms nav apstiprinājuma.', 0.85, 'Tiešs Kulberga citāts dienā pirms 28.05 Saeimas balsojuma par valdības apstiprināšanu. Procesuāla nostāja — atsakās preempt Saeimas lēmumu, biroja sastāvs ''karājoties gaisā'' līdz apstiprinājumam. Pirmā persona, nepārprotams citāts.', 0.45, 'https://jauns.lv/raksts/zinas/711305-kulbergs-pagaidam-neatklaj-sava-iespejama-biroja-sastavu-premjera-amata', '2026-05-27 00:00:00', '2026-05-27 17:28:08', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520864, 6, 43485, 'Imigrācija', 'Apņemas kā topošais iekšlietu ministrs īstenot stingru imigrācijas politiku Kulberga valdībā', 'Iekšlietu nozarē gaidāmas kardinālas pārmaiņas - stingra imigrācijas politika, iekšlietu dienestu stiprināšana un cilvēku drošība.', 0.85, 'Pirmā persona, pirms 2026-05-28 balsojuma par Kulberga valdību. Konkrēts solījums viņa nākamajā ministra portfelī. Saskan ar viņa ilgstošu nostāju (claims #20664, #18343, #17900, #17901) par stingras imigrācijas politikas nepieciešamību.', 0.85, 'https://x.com/janisdombrava/status/2059581224868344087', '2026-05-27 00:00:00', '2026-05-27 17:37:01', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520865, 6, 43485, 'Aizsardzība un drošība', 'Apņemas kā topošais iekšlietu ministrs stiprināt iekšlietu dienestus un cilvēku drošību', 'Iekšlietu nozarē gaidāmas kardinālas pārmaiņas - stingra imigrācijas politika, iekšlietu dienestu stiprināšana un cilvēku drošība.', 0.8, 'Pirmā persona, pirms 2026-05-28 balsojuma par Kulberga valdību. Iekšlietu dienestu stiprināšana ir konkrēts ministra prioritātes paziņojums. Tematiski izšķiramas no imigrācijas — Aizsardzība un drošība aptver iekšlietu resorus.', 0.75, 'https://x.com/janisdombrava/status/2059581224868344087', '2026-05-27 00:00:00', '2026-05-27 17:37:01', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520869, 57, 43822, 'Sabiedriskie mediji', 'Kritizē sabiedrisko mediju (LSM) par redakcionālās kvalitātes trūkumu — saista 72 miljonu eiro gada finansējumu ar nespēju pareizi uzrakstīt septiņus vārdus; izsmej kā nesamērīgu cenu/kvalitātes attiecību.', '"Sabiedriskais" medijs. 72 miljoni eiro nodokļu maksātāju naudas gadā. Nespēj pat septiņus vārdus pareizi uzrakstīt.', 0.65, 'Pirmpersonas tvīts ar konkrētu kritikas līniju: 72 milj eiro vs gramatikas kļūdas. Klāt klauni-emoji kā sarkastiska pastiprināšana. Nav bare RT, ir Lapsas pašā formulēta nostāja. Saskan ar viņa turpināto LSM-kritikas līniju (sk. #520838, #520839, #20414).', 0.5, 'https://x.com/Lato_Lapsa/status/2059649074567979284', '2026-05-27 00:00:00', '2026-05-27 20:56:05', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520876, 10, 43805, 'Valsts kapitālsabiedrības', 'Paziņo, ka 27.05 pabeidzis PIK Saeimas izmeklēšanas komisijas par Rīgas centralizētās siltumapgādes Gala Ziņojumu; iesniegs to 28.05 Saeimas sēdei, lai paspētu pirms iespējamā apstiprinājuma par MP, kas automātiski atņemtu deputāta mandātu un liegtu ziņojumu nodot plānotajā laikā.', 'TAS IR PAVEIKTS! Visā valdības veidošanas trakumā man bija jāpaspēj vēl pabeigt PIK Siltuma izmeklēšanas komisijas Gala Ziņojums uz rītdienas Saeimas sēdi 28.maijā.', 0.85, 'Pirmpersonas paziņojums no Kulberga X profila — konkrēts, laika štampots pabeigšanas paziņojums par PIK Siltuma izmeklēšanas Gala Ziņojuma iesniegšanu 28.05 Saeimas sēdei. Saskan ar plašu Kulberga PIK Siltuma korpusu (#7426 vada komisijas darbu, #17875 tuvojas ''lielajiem secinājumiem'', #18358 ziņojuma secinājumi). Ne tikai procesuāls — Gala Ziņojuma iesniegšana pirms MP transitio ir substantīva apņemšanās pabeigt sava amata pienākumu. Salience 0.7 — PIK Siltuma ir Kulberga centrālā tēma, Gala Ziņojuma iesniegšana ir milestone.', 0.7, 'https://x.com/AndrisKulbergs/status/2059688818085630032', '2026-05-27 00:00:00', '2026-05-27 20:58:09', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520885, 26, 43918, 'Valsts pārvalde', 'Aicina pirms galīgā lēmuma par Baltijas valstu pāreju uz pastāvīgu vasaras laiku kā jauno standarta laiku rīkot plašāku sabiedrības diskusiju.', 'Pirms galīgā lēmuma pieņemšanas par to, ka Baltijas valstis kā jauno standarta laiku atbalsta pāreju uz pastāvīgu vasaras laiku, ir nepieciešama plašāka diskusija sabiedrībā.', 0.75, 'Skaidra pirmās personas procesuāla nostāja tvītā — pirms Baltijas līmeņa galīgā lēmuma par pastāvīgu vasaras laiku jārīko plašāka publiska diskusija. Saskan ar iepriekšējo claim #20598 (19.05) Baltijas ministru sanāksmē, kur Švinka jau norādīja uz sabiedrības diskusijas nepieciešamību; nav pretrunas, drīzāk procesuāla re-uzsvēršana. Salience zemāka, jo saturiski tā ir jau publiski izteikta nostāja.', 0.4, 'https://x.com/atis_svinka/status/2059709614157906144', '2026-05-27 00:00:00', '2026-05-28 10:22:00', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520926, 6, NULL, 'Valsts pārvalde', 'Atbalsta: saeima ar 66 balsīm pret 25 izteic uzticību Andra Kulberga vadītajam Ministru kabinetam. Vienots balsojums par valdību kā veselumu — atsevišķi ministru apstiprināšanas balsojumi netika rīkoti.', NULL, 1.0, 'Saeimas balsojums 2026-05-28: Jānis Dombrava balsoja Par. Kopējais rezultāts: par 66, pret 25, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/FBEBF33CE9683445C2258E05004F3E94?OpenDocument', '2026-05-28 17:20:31', '2026-05-28 20:41:47', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520937, 72, NULL, 'Valsts pārvalde', 'Atbalsta: saeima ar 66 balsīm pret 25 izteic uzticību Andra Kulberga vadītajam Ministru kabinetam. Vienots balsojums par valdību kā veselumu — atsevišķi ministru apstiprināšanas balsojumi netika rīkoti.', NULL, 1.0, 'Saeimas balsojums 2026-05-28: Ilze Indriksone balsoja Par. Kopējais rezultāts: par 66, pret 25, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/FBEBF33CE9683445C2258E05004F3E94?OpenDocument', '2026-05-28 17:20:31', '2026-05-28 20:41:48', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520961, 10, NULL, 'Valsts pārvalde', 'Atbalsta: saeima ar 66 balsīm pret 25 izteic uzticību Andra Kulberga vadītajam Ministru kabinetam. Vienots balsojums par valdību kā veselumu — atsevišķi ministru apstiprināšanas balsojumi netika rīkoti.', NULL, 1.0, 'Saeimas balsojums 2026-05-28: Andris Kulbergs balsoja Par. Kopējais rezultāts: par 66, pret 25, atturas 0.', 0.7, 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/FBEBF33CE9683445C2258E05004F3E94?OpenDocument', '2026-05-28 17:20:31', '2026-05-28 20:41:49', 'saeima_vote', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520989, 15, 44983, 'Ukraina un Krievija', 'Nosoda Krievijas dronu triecienus pret Rumānijas civiliedzīvotājiem Galacā un uzstāj, ka agresore Krievija jāaptur ar spēcīgām sankcijām un noturīgu atbalstu Ukrainai.', 'We condemn Russian drones striking Romanians, at home, at night. The aggressor Russia must be stopped through mighty sanctions and sustained help to Ukraine.', 0.85, 'Pirmā persona, ministres tvīts 29.05 — konkrēta nostāja: Krievijas dronu uzbrukuma nosodījums Rumānijai (NATO sabiedrotajai) un prasība pēc spēcīgām sankcijām + atbalsta Ukrainai. Saskan ar viņas iepriekšējo līniju, nav pretruna.', 0.85, 'https://x.com/Braze_Baiba/status/2060260173038412067', '2026-05-29 00:00:00', '2026-05-29 18:26:58', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520990, 15, 44975, 'Ukraina un Krievija', 'Apņemas turpināt darbu kopā ar Ukrainas ārlietu ministru par drošu un pārtikušu Eiropu ar pilnībā eiroatlantiskajā kopienā integrētu Ukrainu.', 'it will be my honour and pleasure to continue working with for the future of Europe that is safe, secure and prosperous with Ukraine fully integrated in the Euroatlantic community.', 0.7, 'Pirmā persona, vēstījums Ukrainas ĀM Sibiham pēc atkārtotas iecelšanas amatā. Lai gan kolēģisks, satur konkrētu politisku apņemšanos — Ukrainas pilnīga eiroatlantiskā integrācija. Saskan ar esošajiem #18100/#17814; nav pretruna.', 0.65, 'https://x.com/Braze_Baiba/status/2060335298916000071', '2026-05-29 00:00:00', '2026-05-29 18:26:58', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520991, 6, 44969, 'Valodu politika', 'Kā iekšlietu ministrs ar pirmo rīkojumu uzdod visiem iekšlietu sistēmā strādājošajiem darba pienākumu izpildē un saskarsmē ar iedzīvotājiem un kolēģiem lietot tikai un vienīgi valsts valodu (latviešu).', 'Latvijā valsts valoda ir latviešu! Mans pirmais rīkojums ir uzdot visiem iekšlietu sistēmā strādājošajiem darba pienākumu izpildē un savstarpējā saskarsmē ar iedzīvotājiem un kolēģiem lietot tikai un vienīgi valsts valodu!', 0.95, 'Tiešs pirmās personas rīkojums Dombravas X kontā 29.05. Skaidra valsts valodas politikas nostāja jaunā amatā.', 0.75, 'https://x.com/janisdombrava/status/2060270479621968344', '2026-05-29 00:00:00', '2026-05-29 18:27:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520992, 6, 44921, 'Imigrācija', 'Kā iekšlietu ministrs apņemas likt uzsvaru uz imigrācijas ierobežošanu kā vienu no galvenajām nozares prioritātēm.', NULL, 0.85, 'LSM ziņo par Dombravas LTV intervijā pausto prioritāšu sarakstu; pirmā persona (apņēmies). Saskan ar konsekventu vēsturisko anti-imigrācijas nostāju.', 0.8, 'https://www.lsm.lv/raksts/zinas/latvija/28.05.2026-jauna-iekslietu-ministra-prioritates-ierobezot-imigraciju-stiprinat-iekslietu-dienestus-un-pilnveidot-civilo-aizsardzibu.a649222/?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-29 00:00:00', '2026-05-29 18:27:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (520993, 6, 44921, 'Aizsardzība un drošība', 'Kā iekšlietu ministrs prioritizē iekšlietu dienestu stiprināšanu un civilās aizsardzības pilnveidošanu, kā arī uzskata, ka iekšlietu un aizsardzības dienesti var vairāk sadarboties.', NULL, 0.8, 'LSM ziņo par Dombravas LTV intervijā pausto: iekšlietu dienestu stiprināšana, civilā aizsardzība un ciešāka iekšlietu–aizsardzības dienestu sadarbība. Pirmā persona.', 0.7, 'https://www.lsm.lv/raksts/zinas/latvija/28.05.2026-jauna-iekslietu-ministra-prioritates-ierobezot-imigraciju-stiprinat-iekslietu-dienestus-un-pilnveidot-civilo-aizsardzibu.a649222/?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-29 00:00:00', '2026-05-29 18:27:40', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521004, 10, 45404, 'Budžets un finanses', 'Uzsver, ka bez ekonomikas nebūs drošības — ekonomikas pamatā ir uzņēmēji, kuri pilda budžetu un nodrošina izaugsmi un labklājību sabiedrībai.', 'Ja nav ekonomikas, nebūs drošība... punkts... ekonomika ir uzņēmēji, tie ir budžeta pildītāji, tie nodrošina izaugsmi un labklājību sabiedrībai', 0.75, 'Pirmās personas nostāja tvītā par ekonomikas (uzņēmēju) lomu kā drošības un budžeta pamatu. Atkārto viņa konsekvento ekonomiskās drošības tēzi (sk. #20619, #20170), bet skaidri formulēta kā prioritāte.', 0.6, 'https://x.com/AndrisKulbergs/status/2060351694848868708', '2026-05-29 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521005, 10, 45011, 'Valsts pārvalde', 'Apņemas ierobežotajā laikā darīt visu iespējamo, lai ieviestu citu politisko kultūru Latvijā ar mērāmu rezultātu.', 'Laiks tiešām ir limitēts un darīšu visu, kas manos spēkos, lai ieviestu citu politisko kultūru Latvijā. Ne viss sanāks, ne visu paspēšu, bet 100% darīšu, lai būtu mērāms rezultāts', 0.8, 'Pirmās personas apņemšanās mainīt politisko kultūru ar izmērāmu rezultātu. Konkrēta publiska saistība kā jaunajam premjeram.', 0.6, 'https://x.com/AndrisKulbergs/status/2060314683186242025', '2026-05-29 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521006, 10, 44426, 'Budžets un finanses', 'Uzskata, ka valsts vairs nedrīkst dzīvot uz parāda; ir tikai divi varianti — celt nodokļus vai pelnīt vairāk — un izšķērdībai (nepamatotas naudas balvas, lieki komandējumi un iepirkumi) jāpieliek punkts.', 'Neko nedarīt nav izeja no situācijas', 0.85, 'Skaidra pirmās personas fiskālās politikas nostāja premjera apstiprināšanas runā: pret valsts parāda dzīvesveidu, par izšķērdības izbeigšanu. Konsekventa ar #20540, #20528.', 0.85, 'https://jauns.lv/raksts/zinas/711534-neko-nedarit-nav-izeja-kulbergs-saeima-sola-atru-un-atbildigu-valdibu', '2026-05-28 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521007, 10, 44426, 'Valsts pārvalde', 'Sola, ka viņa vadītā valdība strādās pēc principa ''ātrums un atbildība'' — efektīvi, bez dekoratīviem solījumiem, godīgi skaidrojot arī smagus lēmumus, un jāizbeidz lēmumu nepieņemšanas mode.', 'Gumijas vilkšana tagad neder', 0.8, 'Pirmās personas nostāja par valdības darba stilu un pārvaldes kultūru premjera runā. Distinkta no fiskālās un drošības nostājām.', 0.7, 'https://jauns.lv/raksts/zinas/711534-neko-nedarit-nav-izeja-kulbergs-saeima-sola-atru-un-atbildigu-valdibu', '2026-05-28 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521008, 10, 44426, 'Rail Baltica', 'Apņemas personīgi pievērst lielu uzmanību ar ''airBaltic'', ''Rail Baltica'' un vēlēšanu norisi saistītajiem jautājumiem.', NULL, 0.8, 'Pirmās personas apņemšanās uzņemties premjera līmeņa atbildību par Rail Baltica un airBaltic. Atkārto #20525, #20823, kas stiprina nostājas konsekvenci.', 0.7, 'https://jauns.lv/raksts/zinas/711534-neko-nedarit-nav-izeja-kulbergs-saeima-sola-atru-un-atbildigu-valdibu', '2026-05-28 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521009, 10, 44948, 'Budžets un finanses', 'Kritizē līdzšinējo praksi koncentrēties uz ES fondu apguvi kā pašmērķi un aicina pāriet uz pieeju, kur prioritāte ir Latvijas intereses un ieguldījumu ekonomiskā atdeve; ietaupījumi rodami publiskajos iepirkumos un augstākās ierēdniecības atalgojumā un bonusos.', NULL, 0.8, 'Pirmās personas nostāja preses konferencē par valsts finanšu pārvaldības reformu un ES fondu apguves kritiku. Konkrētāka un atšķirīga no parāda nostājas (44426).', 0.8, 'https://www.la.lv/foto-jaunais-premjers-sirsnigi-pasakas-pieciem-ipasiem-cilvekiem-ja-vini-man-nebutu-palidzejusi-es-nevaretu-uznemties-so-godu', '2026-05-28 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521010, 10, 44948, 'Koalīcija un partijas', 'Uzsver, ka jaunajai valdībai būs stabils vairākums Saeimā, kas ļaus pieņemt lēmumus pārliecinošāk, un darba intensitāte saglabāsies arī vasarā, neizslēdzot ārkārtas Saeimas sēdes būtisku lēmumu virzīšanai.', NULL, 0.7, 'Pirmās personas nostāja par koalīcijas darbaspēju un vasaras darba režīmu, atbildot uz jautājumu par Daugavieša (JV) balsojumu pret. Distinkta no pārvaldes stila nostājas.', 0.55, 'https://www.la.lv/foto-jaunais-premjers-sirsnigi-pasakas-pieciem-ipasiem-cilvekiem-ja-vini-man-nebutu-palidzejusi-es-nevaretu-uznemties-so-godu', '2026-05-28 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521011, 10, 44917, 'Droni', 'Vēlas drīzumā sarīkot valdības izbraukuma sēdi Latgalē, kur pēdējā laikā piedzīvoti vairāki dronu incidenti.', NULL, 0.65, 'Pirmās personas nodoms (paraphrāzēts) sarīkot izbraukuma valdības sēdi Latgalē dronu incidentu kontekstā. NEEDS_REVIEW: temata robeža starp Droni (motivācija — dronu incidenti) un Pašvaldības/reģionālā uzmanība; izvēlējos Droni, jo incidenti ir norādītais iemesls.', 0.5, 'https://www.diena.lv/raksts/latvija/politika/kulbergs-gatavojas-rikot-valdibas-izbraukuma-sedi-latgale-14352497?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-28 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521012, 10, 44908, 'Degviela un enerģētika', 'Aicinās Lietuvas un Igaunijas premjerus pārrunāt iespēju veidot vienotu Baltijas enerģētikas stratēģiju.', NULL, 0.75, 'Pirmās personas nostāja Saeimas energoneatkarības konferencē par kopīgu Baltijas enerģētikas stratēģiju. Skaidri runātājs ir Kulbergs.', 0.7, 'https://pmo.ee/8480549', '2026-05-29 00:00:00', '2026-05-29 18:28:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521028, 10, 44467, 'Korupcija un KNAB', 'Kritizē KNAB par bezdarbību — personīgi iesniedzis tiesībsargājošajās iestādēs iesniegumu izvērtēt amatpersonu bezdarbību, interešu konfliktu, korupcijas riskus un izsaimniekošanu Rīgas siltumapgādes lietā, taču KNAB "neko nekonstatē"; pieprasa, lai KNAB biežāk reāli konstatē pārkāpumus, skatot lietas par miljoniem, nevis par sīkumiem.', 'Es gribētu, ka tiek biežāk lietota frāze "KNAB konstatē", pamatoti skatot lietas par miljoniem nevis par sīkumiem', 0.85, 'Pirmpersonas nostāja tvītā 28.05: Kulbergs pats iesniedzis iesniegumu tiesībsargājošajām iestādēm un publiski kritizē KNAB par bezdarbību lielās lietās. Atšķiras no esošā #520876 (Gala Ziņojuma nodošana) — šī ir jauna kritika par KNAB darbības efektivitāti.', 0.7, 'https://x.com/AndrisKulbergs/status/2059930792843763784', '2026-05-28 00:00:00', '2026-05-29 19:12:22', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521029, 10, 44384, 'Imigrācija', 'Kā premjera Kulberga valdības deklarācijā pausta gatavība pastiprināt imigrantu kontroli, vienlaikus turpinot iepriekš uzņemto kursu drošībā un izglītībā.', NULL, 0.6, 'Valdības deklarācijas saturs, kuru Kulbergs kā MP kandidāts iesniedz Saeimai apstiprināšanai 28.05. Imigrācijas kontroles pastiprināšana ir jauna politikas joma, kas nav segta esošajos claims (#22993 sedza tikai vispārēju drošības stabilizēšanu). Konfidence vidēja, jo formulējums nāk no žurnālista pārstāsta par deklarāciju, ne tiešas citātes.', 0.7, 'https://www.lsm.lv/raksts/zinas/latvija/28.05.2026-turpina-uznemto-kursu-drosiba-un-izglitiba-kareivigi-plani-imigracijas-joma-kur-vedis-kulberga-valdibas-kugis.a649134/?utm_source=rss&utm_campaign=rss&utm_medium=links', '2026-05-28 00:00:00', '2026-05-29 19:12:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521030, 15, 44452, 'Digitālā politika', 'Mākslīgā intelekta, datu analītikas un jauno tehnoloģiju apmācība jāintegrē izglītības sistēmā jau no pamatiem, jo droni un jaunās tehnoloģijas ir izmainījušas kara darbību un citas jomas.', 'Droni ir pilnībā izmainījuši kara darbību, bet arī citas jomas, tāpēc MI, datu analītika, jauno tehnoloģiju apmācības jāintegrē izglītības sistēmā jau no pamatiem.', 0.8, 'Pirmās personas nostāja sava tvīta komentārā par DroneHouse — Braže pauž konkrētu izglītības politikas pozīciju (jauno tehnoloģiju integrācija no pamatiem). Jauna tēma, nepārklājas ar esošajām dronu/aizsardzības pozīcijām, kas fokusējas uz militāro pretdronu aizsardzību.', 0.6, 'https://x.com/Braze_Baiba/status/2059954850624831754', '2026-05-28 00:00:00', '2026-05-29 19:12:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521031, 15, 44449, 'Ārpolitika', 'Turpinot darbu ārlietu ministres amatā jaunajā Kulberga valdībā, prioritātes ir NATO klātbūtne Latvijā, visaptverošs atbalsts Ukrainai, sadarbība ar Baltijas jūras reģiona sabiedrotajiem, ASV un Kanādu, un Latvijas uzņēmēju konkurētspēja ārvalstu tirgos.', 'NATO klātbūtne Latvijā; visaptverošs atbalsts Ukrainai; sadarbība ar sabiedrotajiem Baltijas jūras reģionā, ASV un Kanādā; Latvijas uzņēmēju konkurētspēja ārvalstu tirgos.', 0.85, 'Pirmās personas nostāja — Braže pateicas par uzticību turpināt darbu un nosauc četras konkrētas ārpolitikas prioritātes jaunajā valdībā, kas izveidota 28.05. Atšķiras no esošā claim #22994 (26.05, pirms valdības izveides) ar konkrēto četru punktu prioritāšu sarakstu jaunajā Kulberga valdībā.', 0.85, 'https://x.com/Braze_Baiba/status/2060008578568667571', '2026-05-28 00:00:00', '2026-05-29 19:12:36', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521036, 26, 44461, 'Rail Baltica', 'Atbalsta lēmumu nebūvēt 800 miljonu eiro tiltu pār Daugavu, izvēloties duālā tilta optimizāciju ar būvizmaksām līdz 280 milj. eiro', 'Tiltam pār Daugavu arī tika rasts risinājums un pieņemts spēcīgs lēmums - nebūvēt tiltu par 800 milj Euro. Satiksmes ministrija rosina veikt optimizāciju esošā projekta risinājumiem Duālajam tiltam un noteica kopējās būvizmaksas līdz 280 milj. Euro.', 0.85, 'Švinka kā satiksmes ministrs pirmajā personā formulē konkrētu projekta lēmumu par tilta būvizmaksu optimizāciju. Skaidra politikas nostāja ar konkrētiem skaitļiem.', 0.8, 'https://x.com/atis_svinka/status/2059960335944098187', '2026-05-28 00:00:00', '2026-05-29 19:15:12', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521041, 6, 44436, 'Imigrācija', 'Aicina ieviest Saeimā pieņemtā imigrācijas gala ziņojuma rekomendācijas likumos un iestāžu darbībā', 'Apjomīgais gala ziņojums par problēmām imigrācijas jomā ir pieņemts Saeimā. Tagad ir jāuzsāk darbs pie rekomendāciju ieviešanas likumos un iestāžu darbībā.', 0.75, 'Dombravas pirmās personas tvīts par imigrācijas komisijas gala ziņojuma pieņemšanu Saeimā un nepieciešamību ieviest rekomendācijas. Atšķiras no šodienas ministra prioritāšu pozīcijām (#520992 vispārējā imigrācijas ierobežošana) — šī ir konkrēta nostāja par komisijas ziņojuma ieviešanu likumdošanā.', 0.7, 'https://x.com/janisdombrava/status/2059947531467923698', '2026-05-28 00:00:00', '2026-05-29 19:15:57', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521050, 72, 44401, 'Izglītība', 'Kā jaunā izglītības un zinātnes ministre paredz dot skolu direktoriem un pedagogiem lielākas lemšanas tiesības', NULL, 0.6, 'NRA intervijas virsrakstā Indriksonei tieši attiecināta pozīcija par lielākām lemšanas tiesībām skolu direktoriem un pedagogiem. Pamatteksts ir tikai intervijas anonss (jautājumu uzskaitījums) bez pilnas citātas, jo intervija ir video formātā — tādēļ vidēja konfidence.', 0.6, 'https://nra.lv/neatkariga/intervijas/522131-ilze-indriksone-skolu-direktoriem-un-pedagogiem-bus-lielakas-lemsanas-tiesibas.htm', '2026-05-28 00:00:00', '2026-05-29 19:21:26', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521051, 182, 45542, 'Vēlēšanas', 'Aicina rudens vēlēšanās noraidīt nevis atsevišķus politiķus, bet ikvienu partiju, kas krāpusi vēlētājus, un ieviest Ziemeļeiropas stila neiecietību pret korumpētiem politiķiem („nost no laukuma“, līdz pat tiesāšanai).', 'Noraidīt no laukuma nevis atsevišķus politiskos spēlētājus, bet ikvienu komandu, kas krāpusi vēlētājus.', 0.8, 'Ozola paša pirmās personas opinion tvīts (nav retvīts). Caur hokeja metaforu viņš formulē konkrētu normatīvu nostāju par rudens vēlēšanām: sodīt un izslēgt visas vēlētājus krāpušās partijas, atsaucoties uz Ziemeļeiropas modeli. Tas ir runātāja paša viedoklis, ne empātisks sabiedrības motīva apraksts.', 0.85, 'https://x.com/OttoOzols/status/2060411786986480067', '2026-05-29 00:00:00', '2026-05-29 20:34:54', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521052, 10, 45517, 'Aizsardzība un drošība', 'Pirmajā darba dienā premjera amatā kā pirmo tiekas ar jauno aizsardzības ministru Melni, lai saliktu plānus un turpmākos soļus drošības stiprināšanai; uzsver, ka drošība ir valdības prioritāte, un atzinīgi vērtē Melņa neordināros, ārpus kastes risinājumus.', 'Šīs valdības prioritāte ir drošība, tāpēc kā pirmo satieku jauno aizsardzības ministru Melni, lai saliktu plānus un turpmākos soļus drošības stiprināšanai.', 0.7, 'Konkrēta pirmās darba dienas rīcība un sadarbība ar aizsardzības ministru drošības plānu izstrādei. Vispārējā drošības prioritātes nostāja jau dokumentēta (claim #20170/#20395 u.c.), bet šis ir jauns, datēts pirmās dienas operatīvais solis ar konkrētu ministra atbalstu — tāpēc salience mērena.', 0.65, 'https://x.com/AndrisKulbergs/status/2060403273304084533', '2026-05-29 00:00:00', '2026-05-29 20:35:19', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521053, 10, 45504, 'Valsts pārvalde', 'Iebilst pret sasteigtu ministriju likvidēšanu vai apvienošanu ierobežotajā četru mēnešu termiņā — uzskata, ka reformām vajag laiku un uzmanību, lai nepieļautu kļūdas, un ka enerģija jāvelta drošībai (militārai, civilajai, ekonomikas), nevis griešanai griešanas pēc.', 'Četru mēnešu limitētā laikā likvidēt vai apvienot ministrijas nav prāta darbs, ja enerģija un uzmanība ir jāvelta drošībai - militārai, civilajai, ekonomikas. Reformām vajag laiku un uzmanību, lai nepieļautu kļūdas griezt tikai griešanas pēc.', 0.8, 'Jauna, skaidra nostāja par ministriju optimizāciju — premjers noraida sasteigtu strukturālo reformu īsajā termiņā. Nav dublēta esošajos claims. Tiešs citāts no X, ko atspoguļo NRA.', 0.6, 'https://nra.lv/politika/522306-vai-latvija-gaidama-ministriju-optimizacija-kulberga-viedoklis.htm', '2026-05-29 00:00:00', '2026-05-29 20:35:19', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521059, 10, 45695, 'Koalīcija un partijas', 'Apņemas mainīt valdības darba kultūru: visus 100 Saeimas deputātus uzskata par tautas ievēlētiem (mazinot pozīcija-opozīcija dalījumu) un pieprasa ministriem un koalīcijas partijām priekšvēlēšanu laikā nolikt malā savstarpējās domstarpības un strādāt ar konkrētiem darbiem, nevis priekšvēlēšanu retoriku.', 'jaunajā amatā vēlas mainīt līdzšinējo politisko kultūru, kurā pārāk asi tiek dalīta pozīcija un opozīcija', 0.75, 'Kulbergs pats intervijā TV24 (2026-05-30, neilgi pirms apstiprināšanas balsojuma) izsaka nodomu mainīt politisko kultūru. Pirmās personas pozīcija par to, kā viņš plāno vadīt valdību un veidot attiecības ar opozīciju. Nav ceremoniāls, nav trešās puses, nav retorisks jautājums. Žurnālista parafrāze ar daļēju citātu, tāpēc confidence 0.7.', 0.55, 'https://www.la.lv/kadreiz-uzrakstisu-gramatu-ka-razo-politiskas-desas-kulbergs-neilgi-pirms-balsojuma-sniedzis-pavisam-cilvevigu-interviju', '2026-05-30 00:00:00', '2026-05-30 22:58:01', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521060, 72, 45697, 'Imigrācija', 'Iekšlietu ministrijas uzticēšana NA dod iespēju pastiprināt imigrācijas kontroli un risināt civilās aizsardzības jautājumus kā ilgtermiņa izaicinājumu.', 'NA bija vēlējusies pārvaldīt kādu no drošības jomas ministrijām, un iekšlietu ministrijas uzticēšana partijai esot gan liela atbildība, gan iespēja.', 0.8, 'Pirmās personas pozīcija TV24 intervijā. Indriksone kā NA valdes priekšsēdētāja iezīmē iekšlietu jomas prioritātes — civilā aizsardzība un imigrācijas kontroles pastiprināšana. Saskan ar viņas iepriekšējo imigrācijas-kā-drošības-jautājuma nostāju (#1529, #20849), tagad izpildvaras kontekstā.', 0.8, 'https://www.la.lv/ne-visi-sanem-visu-ko-velejusies-indriksone-par-nacionalajai-apvienibai-pieskirtajam-ministrijam', '2026-05-30 00:00:00', '2026-05-30 22:58:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521061, 72, 45697, 'Izglītība', 'Iekšlietu, kultūras un izglītības jomu apvienošana vienā NA politiskā atbildībā ļauj risināt izglītības sistēmas attīstību un augstākās izglītības jautājumus vienotā skatījumā.', 'līdz ar iekšlietu jomu NA pārraudzībā nonāk arī kultūras un izglītības jautājumi, kas parasti reti tiek apvienoti vienā politiskā atbildībā', 0.7, 'Pirmās personas pozīcija — Indriksone formulē, kā NA izmantos apvienoto izglītības/kultūras/iekšlietu portfeli izglītības sistēmas un augstākās izglītības attīstībai. Distinkta no imigrācijas pozīcijas.', 0.65, 'https://www.la.lv/ne-visi-sanem-visu-ko-velejusies-indriksone-par-nacionalajai-apvienibai-pieskirtajam-ministrijam', '2026-05-30 00:00:00', '2026-05-30 22:58:17', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521062, 15, 45718, 'Droni', 'Pozicionē Latvijas militāro poligonu kā centrālu NATO dronu inovācijas un attīstības vietu', 'In Latvia''s pine forests, #NATO drone future takes shape. How a remote military range is becoming central to @NATO innovation.', 0.65, 'Pirmpersonas tvīts (nav RT) ar pašas formulētu tekstu, kas izceļ Latvijas militāro poligonu kā NATO dronu inovācijas centru. Promocionāls ietvars, kas atbalsta Latvijas lomu NATO dronu attīstībā — saskanīgs ar viņas aizsardzības/dronu nostādni, nevis pretruna. Nav asas politikas saistības, tādēļ vidēja pārliecība.', 0.6, 'https://x.com/Braze_Baiba/status/2060435882088259996', '2026-05-29 00:00:00', '2026-05-30 23:08:55', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521063, 182, 45835, 'Ukraina un Krievija', 'Atbalsta Īpašā tribunāla izveidi par agresijas noziegumu pret Ukrainu un uzsver, ka kara izraisītājiem jānes personiska atbildība — ilgstošs miers nav iespējams bez taisnīguma.', 'They must be held accountable. Because lasting peace is impossible without justice – and aggression must never remain without consequences.', 0.8, 'Pirmās personas atbalsts tribunālam ar nepārprotamu apstiprinošu ietvaru ("They must be held accountable"), ne tikai MFA Ukraine pārstāsts. Konkrēta nostāja par starptautisko taisnīgumu un Krievijas agresijas atbildību.', 0.85, 'https://x.com/OttoOzols/status/2060439354120585665', '2026-05-29 00:00:00', '2026-05-30 23:12:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521064, 182, 45837, 'Vēlēšanas', 'Aicina rudens vēlēšanās diskvalificēt nevis atsevišķus politiķus, bet ikvienu partiju, kas krāpusi vēlētājus, noraidot "mazākā ļaunuma" loģiku, un ieviest Ziemeļeiropas stila neiecietību pret korumpētiem un melīgiem politiķiem.', 'Šādas komandas ir vienkārši jādiskvalificē, viņas ir jāpadzen no laukuma vispār!', 0.85, 'Garš pirmās personas op-ed ar konkrētu vēlēšanu nostāju: visu krāpušo partiju noraidīšana, sistēmas maiņa, anti-korupcija. Atkārto 521051 tēmu, bet citā tvītā/URL — idempotence pēc URL atļauj, nav pretruna (konsekventa nostāja).', 0.85, 'https://x.com/OttoOzols/status/2060413950882201951', '2026-05-29 00:00:00', '2026-05-30 23:12:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521065, 182, 45833, 'Koalīcija un partijas', 'Vēlēšanu gadā iebilst pret tiesāta oligarha atgriešanu aktīvajā politikā, raksturo zatleriešu rīcību (oligarha atgriešanu apritē) kā vēlētāju krāpšanu un kritizē mediju pārstāstu par šo personu lomas noklusēšanu.', 'Tā ir krāpšana, piedevām prezidents izrādījies viens no centrālajiem blēžiem.', 0.6, 'Galvenokārt mediju pārstāsta kritika, bet ar iegultu pirmās personas nostāju: oligarhu atgriešana politikā ir krāpšana, vēlēšanu gadā tas ir aktuāli. Pazemināta confidence, jo daļēji meta-kritika par raksta ietvaru.', 0.55, 'https://x.com/OttoOzols/status/2060667965566046227', '2026-05-30 00:00:00', '2026-05-30 23:12:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521068, 30, 45729, 'Koalīcija un partijas', 'Iebilst pret partiju finansēšanas ierobežojumiem — uzskata tos par instrumentu, kas aizcementē esošo aktīvo partiju sarakstu, kavē jaunu partiju rašanos un rada lieku inspektoru aparātu; norāda, ka ierobežojumi cilvēkus dzen dibināt biedrības (kurām var ziedot arī juridiskas personas).', 'Partiju finansēšanas ierobežojumi ir viens no veiksmīgākajiem instrumentiem, kā šodienas pasīvajā sabiedrībā reizi par visām reizēm aizcementet aktīvo partiju sarakstu (t.i. nepieļaut jaunu rašanos, izņemot populistiskus grupējumus)', 0.8, 'Pirmpersonas nostāja tvītā: Baško sarkastiski, bet nepārprotami iebilst pret partiju finansēšanas ierobežojumiem, argumentējot, ka tie kalpo esošo partiju aizsardzībai un birokrātijas pieaugumam. Konkrēta politikas pozīcija par partiju finansēšanas regulējumu. Saskan ar viņa iepriekšējo partiju plurālisma/decentralizācijas nostāju (nav pretrunas).', 0.6, 'https://x.com/JazepsBasko/status/2060605522336793046', '2026-05-30 00:00:00', '2026-05-30 23:15:23', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521069, 6, 45705, 'Aizsardzība un drošība', 'Izvirza civilo aizsardzību par savu un komandas prioritāti — attīstīs robežsardzes spējas, iespējams pielietojot modernas dronu detekcijas un notriekšanas sistēmas, lai atbalstītu nacionālos bruņotos spēkus uz robežas.', 'Attīstīsim robežsardzes spējas, iespējams pat pielietojot modernas dronu detekcijas un notriekšanas sistēmas, tādā veidā sniedzot efektīvu atbalstu mūsu nacionālajiem bruņotajiem spēkiem uz robežas.', 0.85, 'Pirmās personas politikas nostāja — izteic savas un komandas prioritātes civilās aizsardzības jomā, ar konkrētiem pasākumiem (dronu detekcija/notriekšana, robežsardzes spējas). Konkrēta nostāja, ne empātisks sabiedrības motīva apraksts.', 0.85, 'https://x.com/janisdombrava/status/2060626255444083056', '2026-05-30 00:00:00', '2026-05-30 23:15:39', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521070, 189, 45783, 'Budžets un finanses', 'Uzskata, ka konkurence banku sektorā ir nepietiekama', 'Konkurence banku sektorā nepietiekama.', 0.6, 'Pūce pirmajā personā formulē vērtējumu par banku sektora konkurenci kā nepietiekamu. Tvīts īss, pievienots ārējs saturs (links), tāpēc nostāja skaidra, bet bez detalizēta politikas priekšlikuma — vidēja pārliecība.', 0.55, 'https://x.com/pucej/status/2060640866792776092', '2026-05-30 00:00:00', '2026-05-30 23:15:55', 'position', NULL);
INSERT INTO claims (id, opponent_id, document_id, topic, stance, quote, confidence, reasoning, salience, source_url, stated_at, created_at, claim_type, speaker_id) VALUES (521072, 26, 45720, 'Korupcija un KNAB', 'Aicina ministru prezidentu Kulbergu nekavējoties izdot ministru prezidenta rezolūciju zemkopības ministram publiskot LVM finanšu dokumentus un naudas plūsmas, lai pārbaudītu Švinkas izvirzītās aizdomas par iespējamiem pārkāpumiem Zemkopības ministrijā un LVM.', 'kaut vai tūlīt izdot ministru prezidenta rezolūciju zemkopības ministram publiskot LVM finanšu dokumentus un naudas plūsmas, kas parādītu zemkopības ministrijas “savas kabatas” saimniekošanas ceļus un apmērus', 0.8, 'Pirmās personas konkrēts politisks aicinājums/pieprasījums — Švinka skaidri formulē rīcību, ko premjeram būtu jāveic (rezolūcija par LVM dokumentu publiskošanu). Saskan ar Progresīvo iepriekšējo nulles tolerances nostāju kokrūpnieku lietā (claim #20472). Nav retorisks jautājums — pats sniedz atbildi (Jā, kaut vai tūlīt...).', 0.75, 'https://x.com/atis_svinka/status/2060734516826608102', '2026-05-30 00:00:00', '2026-05-30 23:16:29', 'position', NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4713, 'Ja gribat redzēt spilgtu piemēru kā valsts aparāts/ministrijas locās kā zuši no atbildības, tad noskataties Tautsaimniecības Komisijas sēdes (vakar un šodien), kur ir atnākusi augstākā ierēdniecība ar munīciju apbruņojumu un šauj ārā visus argumentus, kapēc mūsu #RailBaltica PIK izmeklēšanas komisijas iesniegtie grozījumi ielikt katras ministrijas atbildību un konkrēti PREMJERA virsvadību un nederīgs, nevajadzīgs un traucējošs. Piebildīšu - neviens piedāvājums kā uzlabot esošo regulējumu (izņemot SatMin)

Augstākās tiesas praksē ir noteikts, ka atšķirībā no privāto tiesību principa „atļauts viss, kas nav aizliegts” publiskajās tiesībās darbojas princips „atļauts ir tikai tas, kas ir noteikts ar tiesību normu”.

Šajā gadījumā ministrijas ļoti pretojas, lai tām ar likumu uzliktu konkrētus uzdevumus un konkrētas atbildības Rail Baltica projektā. 
Tautsaiimniecības komisijas sēde spilgti izgaismoja Ministru prezidenta un ministru atbildības neesamības problemātiku - neviens neko negrib darīt un neviens negrib uzņemties neko darīt. Tik cik - jau šobrīd pildām likumā noteiktos uzdevumus. Jā, bet likums šobrīd īsti nenoteic nekādus uzdevumus citām ministrijām, tādēļ tās droši turpina neko nedarīt. 
Kā saka - nekļūdās tas, kas neko nedara. Tikai mūsu gadījumā - nekā nedarīšana ir tā lielākā kļūda. Spilgti izgaismojas @Jauna_Vienotiba  pretošanās uzdevumiem un atbildībai, kas, zinot PIK secinājumus un ielaisto projekta gaitu, ir saprotama kā apzināta projekta sabotāža nepalīdzot Satiksmes ministrijai.', '0dd6102e02d26c30183864ca6cbfa08295c8f49dfc56c5a4a9e5a89c52bdfdcb', 6626781960047074296, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/AndrisKulbergs/status/2034184765021012358', NULL, '2026-04-01 20:01:53', 203, 'lv', '2026-03-18T08:26:55.963000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4720, 'Šodien liela diena @partijaMMN organizācijā. Vienas dienas laikā piecas darba grupu sapulces, dažas no tām vienlaicīgi. Un viens biedrs partijas vārdā uzstājās konferencē. Plus, no rīta viens pieprasījums ministrijai. Mēs augam.

Latvijā jēdziens "darba grupa", protams, ir kļuvis par lamu vārdu. Ne mazums ļautiņu ar politiku saprot tikai tikšanu pie varas "UN TAD". Un tad būs lielās lietas no zila gaisa. Tad pēkšņi pirmajā dienā pēc vēlēšanām vienas partijas biedri iemācīsies sastrādāties, iemācīsies strīdēties, iemācīsies būt konstruktīvi. Mācēs meklēt kompromisus, mācēs uzklausīt un savaldīt putnus un zilus brīnumus. Tad pēkšņi vienā dienā no lielākajiem tukšmuldētājiem kandidāti kļūs par lielākajiem darītājiem. Bet tā nav. Tā var tikai vēl vienu Kaimiņa vai Gobzema brigādi noformēt. Un mēs to ceļu neejam.

Mēs neejam arī kaut kādu formālu ceļu, kur kādi īstie varas devēji būtu satikušies un nolēmuši, ka demokrātiski jānoformē taciņa līdz Saeimai. Jāsarīko skaists kongresiņš, jānoalgo viss minimālais partijas aparāts, jāuzstellē fons un saukļi, un kaut kāds balsotāju vilcieniņš jāievirza Saeimā naskai uzdevumu izpildei.

Nē, mēs te ejam to grūto ceļu, kad tikšanai Saeimā no mūsu vidus vistālāk gājējiem būs līdz rudenim jāiemācās vai jāpierāda varēšana demokrātijas praktikā. Nevis regulējumu rakstīšanā, bet satiekoties ar savu neadekvāto līdzcilvēku, ar savu piecreiz par tevi kompetentāko vai attiecīgajā vietā piemērotāko biedru un ceļa došana viņam. Sava labākā pielikšanas punkta atrašana. Demokrātijas praktika ir sastapšanās ar savu emocionālo pretstatu. Izaicinājumi, ar kuriem saskaras tad, kad riktē partiju vai gribas tādai pievienoties, vai kad virza savu ģeniālo priekšlikumi, ir tieši tie izaicinājumi, kuru dēļ politikā ir tik grūti kaut ko izdarīt. Nav kaut kāds politikas uzgaidāmajā telpā izdomātu problēmu kopums, kuru var vienkārši paslaucīt malā, neierodoties uz tikšanos ar visu, kas neesi tu pats, un ietrāpīt tai Saeimā rudenī UN TAD sākt mācēt politiku. Ir jāiet tieši cauri visam tam. Un mēs ejam.

Te ir līdzības ar pirms daudziem gadiem populāro padarīšanu, kad visādi veikli operatori jauniem vīriešiem mācīja uz ielas iepazīties ar meitenēm. Jāpasaka šitās lietas, jāpasaka tās un meitene būs iegūta. Pēdējo desmitgažu pieeja politikai ar retiem izņēmumiem ir bijusi tieši tāda. Un mēs to pieeju mainām. Ja tevi interesē tikai dabūt to meiteni uz randiņu, tad meitene tev vajadzīga nav un Visums salieksies vienpadsmit līkumos, lai tas nenotiktu. Un tāpat ir ar to mācēšanu būt Saeimā. Var jau iemānīties iekšā, bet Latvijai no tā labāk nekļūs. Tad tu četrus gadus tur mācīsies to, ko varēja pa vienu vasaru apgūt vai saprast, ka tas nav tavējais. Realitāti nevar apmānīt.

Mēs mainām noteikumus. Vai ir kādas garantijas, ka izdosies? Nav nekādas. Bet mums nevajag garantiju cienītājus. Ar tādiem, lokomotīvēm līdzi ieslīdējušiem, ir jau pilna Saeima.', '50703f999cb28aeb6ad229edb60a0c95fd0f9ef07db0e757c767d9b1066f203a', 6349291566323877672, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2039401650025030024', NULL, '2026-04-01 20:01:54', 429, 'lv', '2026-04-01T17:56:58.273000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4723, 'Nav īsti svarīgi, vai jūs jau esat mūsējie, vai arī pieslēgsities vēlāk. Tāpēc ka tas, ko mēs grasāmies darīt, nav par mūsējie versus ne mūsējie. Tas, uz ko es aicinu kopš Kodokas un Demos palaišanas, ir pāriešana nākamajā politiskās apziņas līmenī. Atšķirība ir nevis cilšu piederībā, bet tajā, vai jūs ejat uz arvien vairāk redzošu, zinošu un kontrolējošu valsti, kas pārveido cilvēku pēc centrālā plānotāja prāta, vai arī jūs ejat brīvības un individuālās atbildības virzienā, kuram galapunktu neviens nezina un nedrīkst zināt?

Abi divi virzieni ir līdz zināmai pakāpei vērtīgi un vajadzīgi, tie viens otru papildina un aptur otra galējības. Taču šie virzieni savas labākās īpašības apliecina tikai tad, ja to pārstāvji atsakās no cilšu būšanas jeb tribālisma. Tas ir, ja to pārstāvji patiešām apzinās, ka virziens un patiesība pastāv neatkarīgi no viņu būšanas vienā vai otrā pusē.

Patiesībai ir vienalga, kuri ir darītāja savējie un kuri tādi nav. Ja tas, ko darītājs dara, ir realitātē balstīts un maina realitāti uz labāku, tad darītājs varēs būt bijis arī citādi pats pēdējais sūdabrālis. Ja jūs esat ideoloģiski mūsējais, mēs atradīsim kopīgu ceļu. Bet, ja esat ideoloģiski ne mūsējais, jums ir jābūt otrā pusē un tur es jums novēlu visu labāko. Kreisajiem nevajag vājus labējos un labējiem nevajag vājus kreisos. Un nevienam nevajag tribālistus, izņemot tos, kuriem gribas palikt bedrē un turpināt izmisīgi meklēt savus 0,001% identiski domājošos tumsklonus.', '5021eafd2b3c19f7617761ca29ab2a37bb4a0f8ef65c2ddf9f3c6bdd05de1942', 6798858800202186661, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2039038479183585788', NULL, '2026-04-01 20:01:54', 227, 'lv', '2026-03-31T17:53:51.597000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4725, 'Un pats labākais, ka ātrgaitas šoseja būtu izmantojama un nestu labumu no pirmā pabeigtā kilometra, ko nevar teikt par pirmo pabeigto betona angāru Mārupes pļavās, pāli Daugavā vai pabeigtu velotiltiņu uz nekurieni, kuriem pirmo augļu nešanai jāsagaida 22. gadsimts.', '6964f4e002d1749c42d7acb3e27b2f887a50d3cdf3e129b91121ad03048be849', 2317989335566434509, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2038321765164679479', NULL, '2026-04-01 20:01:54', 39, 'lv', '2026-03-29T18:25:53.659000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4726, 'Kādas konkrētas valsts funkcijas jūs samazināsiet?

Svarīgāk par konkrētu funkciju vai iestāžu nosaukšanu ir saprast motivāciju un principus, pēc kādiem tas notiks. Ja es nosaukšu tagad iestādi X, vai nebūs iespējams atrast racionālus argumentus iestādes vai funkcijas saglabāšanai? Būs un ļoti daudz. Izdevumu pozīcijas pamatojums neeksistē ārpus konteksta. Ārpus konteksta pamatot var jebko, kam ir labs mērķis. Bet vai to var atļauties? Ja nedara neko citu, tad var. Kas jādara, lai noteiktu, vai to var atļauties kopā ar visām citām lietām, kas ir labas un svarīgas?

Ja vienas funkcijas izvērtēšanai pieiet galēji racionāli, tad jāsarindo visas valsts funkcijas pēc to svarīguma, pēc to savstarpējām atkarībām. Cerams, ka vairumam ir skaidrs, ka tas nav iespējams. Pat t.s. mākslīgajam intelektam tas nav pa spēkam. Kaut vai tāpēc, ka intelekts nezina, kā katrs no mums vērtē dažādās funkcijas. Politika sākas tajā brīdī, kad eksistē dažādi uzskati par dažādu lietu svarīgumu jeb dažādas vērtības. Beigu galā tā ir patvaļīga politiķu izšķiršanās, ko atstāt un ko neatstāt. Kāds ir pamatojums? Ka visu nevaram atļauties. Un kaut kas jāvērtē augstāk par citu ko. Un to politiķi arī izdara.

Kā pieiet šim uzdevumam iespējami taisnīgi? Viens veids ir pateikt, ka visās pozīcijās vai visās iestādēs izdevumi jāsamazina par noteiktu skaitu procentu. Un konkrēto izšķiršanos atstāt jomas speciālistu ziņā, protams, ar ideoloģisku ievirzi no politiķiem, kas norāda, kas tad ir pats svarīgākais. Mums pats svarīgākais ir vairot brīvību (mazināt ierobežojumus, piespiešanu), atstāt vai stiprināt mehānismus individuālajai atbildībai. Ja jāizvēlas, piemēram, vai saglabāt Antidopinga aģentūru, vai arī Konkurences padomi, mēs saglabāsim to iestādi, kas nenodarbojas ar pieaugušo hobija atbalsta funkciju, bet gan ar ekonomiskās vides uzturēšanu kārtībā.
 
Citiem vārdiem, ja vēlētājs sapratīs mūsu ideoloģiju, pārsteigumu nebūs.', '1ee30d18386a473bd460ad15635ac9bc30cb19c1ffa8b7d44443a746d2ee8374', 1931976635850406499, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2038206061673365699', NULL, '2026-04-01 20:01:54', 277, 'lv', '2026-03-29T10:46:07.797000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4727, 'Tādas lietas kā trešdienas KNL sakārtotā valstī notiktu ministra kabinetā un Domburs būtu ministrs vai ministra nozīmēts atbildīgais. Kas ir ministrs šodienas Latvijā? Kaut kāds trīsdimensionāls čatdžipitijs bez interneta pieslēguma.', '67ab0b22f51d8b1b3f02d34109dba920dcef56aaa121e7de538ce0ec85314340', 6756629881277792396, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2037901651424546986', NULL, '2026-04-01 20:01:54', 30, 'lv', '2026-03-28T14:36:30.738000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
