📜 Appeal to the Peoples of Europe: The Patriots’ Budapest Proclamation https://t…', '0630d8ba13ac98ead772d9761a7796ff1839deabf6f248a406bdf0fb23d7a2a7', 2318734736883936390, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2036316403351908701', NULL, '2026-04-01 20:01:54', 20, 'en', '2026-03-24T05:37:18.145000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4731, 'Aizvakar biju uzaicināts piedalīties @tv24_lv raidījumā "Kārtības rullis", kur kopā ar vēl dažiem runājām par birokrātijas apkarošanu. Var noskatīties go3 platformā vai arī pēc kādas nedēļas gan jau arī TV24 mājaslapā.

Ierakstā noteikti redzēsiet, ka es runāju pavisam ne tajā valodā, kurā divi pašreizējie Saeimas deputāti. Kā jau teicu raidījuma beigās, @partijaMMN atgriezīs Latvijā politiku. Pēdējos gados ar politiku saprot tādu kā vairāku saimniecības daļas vadītāju sanāksmi (skatīt tipisko "Kas notiek Latvijā"), kur visus sabiedrības organizācijas izaicinājumus uzlūko kā racionāli atrisināmus, tehniskus uzdevumus. Pat noslīkuši savu tehnisko risinājumu risinājumos viņi neievēro, ka ir jau zem ūdens. Jo arī ūdens pārliešana zem ūdens viņiem sagādā profesionālu gandarījumu.

Bet sistēmiskās problēmas nevar atrisināt ar tām pašām metodēm, kuras rada šīs problēmas. Nevar uzrakstīt birokrātisku recepti birokrātijas apkarošanai. Jo recepte prasa nevis atbildību par rezultātu, bet gan atbildību par receptes izpildi. Stingri nokodēta recepte praksē nozīme liegumu pielāgoties mainīgiem apstākļiem un īpašiem gadījumiem — nokodēta recepte nozīmē liegumu evolucionāri adaptēties.

Valsts samazināšana, savstarpējas uzticēšanās vairošana (tai skaitā ar sabiedrības neformālo institūciju stiprināšanu) un individuālas atbildības likšana pāri procesa reglamentēšanai ir vienīgās zāles pret birokrātijas pārmērībām.

Ja esat spējīgs izkāpt no acu priekšā esošā saimnieciskā uzdevuma risināšanas un spriest par uzdevuma cēloņiem, tad jums būs vieta arī politikas atpakaļuznācienā. Pievienojieties @partijaMMN!', '2ccf54ba580ad1c6a114f4c944bb718af92bb2ac42df15449185572479797557', -2668850282538583771, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2034140240122941853', NULL, '2026-04-01 20:01:55', 207, 'lv', '2026-03-18T05:30:00.400000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4732, 'MĒS MAINĀM NOTEIKUMUS statūtos viens no partijas mērķiem ir politiskās pārvaldības atjaunošana Latvijā. Tas nozīmē arī pretstāvi mēģinājumiem padarīt Satversmes tiesu par pozitīvu likumdevēju, kā tas notiek ar šādām lietām, kuru iesniedzēji izliekas, ka visiem nodrošinājumiem, ko kāds ielasa Satversmē, jābūt strikti garantētiem likumos. Tāda pieeja jebkuru valsti ved uz morālu un finansiālu bankrotu.

https://t.co/tvlfPYy8wX', 'cab02931d7c94494f873622d9a6d39f9e3d39585b11b287d5fd22078db21e544', -4478419159829394087, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2033940124984074703', NULL, '2026-04-01 20:01:55', 55, 'lv', '2026-03-17T16:14:49.233000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4733, 'Kad raksta "Es nesaprotu", svarīgi ir apstāties pie "nesaprotu" un padomāt. Jaunajai Vienotībai šobrīd Saeimā ir trīs Zariņi, kuriem visiem ir vairāk svītrojumu nekā plusiņu. Vēlētājs Pūpols gan jau jūtas gandarīts par savas tiesības izmantošanu.

"Tiesības" ampelēties ar plusiņiem un mīnusiem tik tiešām ir. Tāpat kā tiesības tviterī rakstīt muļķības.

Plusiņi un svītrojumi faktiski bremzē partiju sarakstu sistēmas galveno pozitīvo aspektu, proti, partijas spēju demokrātiski iekšienē sagatavot savu labāko komandu parlamentam. Tā vietā parlamentā nonāk iekšējo izrēķināšanos pārpalikumi. Plusiņu un svītrojumu sistēma rada ilūziju, ka kādi kandidāti tiek neatbalstīti, bet neviens strīpojums neatsver to plusu, ko ir devusi jau paša saraksta izvēle.

Kāds tam ir rezultāts? Rezultāts ir tāds, ka partijās šodien nevar būt ideoloģisku spārnu. Partijās, ja tās grib būt ideoloģiskas, nevar būt īstas demokrātijas — jebkurš spārns, kurš ir vairākumā, izspiedīs otru spārnu. Tāpēc valdošais spārns laicīgi apspiedīs jebkuru apdraudējumu. Un pareizi darīs. Jo citādāk partija nevarēs realizēt savu programmu.', '035aafe42aa7ea6388f56c106a46df03bcf902022fa55879a65af7ae780948a8', -3265920552442140671, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2031062184785272916', NULL, '2026-04-01 20:01:55', 152, 'lv', '2026-03-09T17:38:54.820000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (4734, 'RT @LRZinas: Partija "Mēs mainām noteikumus" cer uz 51 vietu Saeimā, un domubiedri būs vēlēšanu sistēmas maiņas atbalstītāji – tā raidījumā…', '24ccac02dee26f9294a5c5bf18148b93d401fb7a4d20ad9a8ca72bbfe5088808', 2836344730710208689, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2030913615553786281', NULL, '2026-04-01 20:01:55', 21, 'lv', '2026-03-09T07:48:33.155000+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (5475, 'Kopš iepriekšējā mērījuma mūsu reitings ir pieaudzis par 2,1 procentpunktu, kamēr JV tas nokrities par 2,4 procentpunktiem. (LABOTS, pārpratu diagrammu)', 'a35cc9686359ac2aac263186ea552a4bab65de95240805c5ad7fbd903aaa66da', 5249010528534962090, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2039805487206543393', NULL, '2026-04-03 10:25:14', 20, 'lv', '2026-04-02T20:41:40+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (6244, 'MĒS ESAM TIK NABAGI, KĀ VĒL NEKAD IEPRIEKŠ.

Sabiedrības labklājības rādītājs ir nevis dzīves ērtību pieejamība, bet gan īpatsvars tādiem sabiedrības locekļiem, kas var un ir gatavi nozīmīgu laiku sava nomoda simtprocentīgi veltīt sabiedriskām aktivitātēm, par kurām viņi nesaņem no padarītā vai no pavadītajām stundām atkarīgu atalgojumu. Tie var būt gan paši savu materiālo iztiku iepriekš nodrošinājušie, gan viņu bērni, sievas vai vīri, vai stipendiāti. Ja tādu cilvēku sabiedrībā nav, sabiedrība kļūst par bezsmadzeņu izdzīvošanas un ražošanas mašīnu.

Taču valsts nevar kļūt par šāda slāņa uzturētāju. Valsts nevar padarīt par nodrošinātu tādu cilvēku kopumu, kurš garīgi tāds nejūtas un nav. Kas valsts mēģinājumu viņu atbrīvot izmantos materiālās iedzīvošanās nodrošināšanā, tam nekad nebūs gana, un tas iznīcinās pašu sistēmu, kura viņam nodrošināja brīvību.', '22419df3099d1d321900006d4eed7ac0f464c55a0886f52b2e3eb52199cde75e', 6130248752093053871, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2040313656437625264', NULL, '2026-04-04 11:35:51', 122, 'lv', '2026-04-04T06:20:57+00:00', 0, NULL, NULL, '2026-04-09 18:53:40', NULL, NULL, NULL);
