INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (13852, 'NĀKSIES IET PA KLAJU LAUKU

Atbildības uzņemšanās nesākas tad, kad iegūst amatu. Tā sākas brīdī, kad jūs piesakāties uz konkursu par amatu un pieļaujat iespēju, ka amatu neiegūsit. Tajā brīdī jūs izpildāt pienākumu piedāvāt sabiedrībai savu veltīšanos tās kopīgajā lietā. Ar pieteikšanos uz konkursu, kurā jūs varat ne tikai nevinnēt, bet arī kaut ko zaudēt, jūs, pirmkārt, atzīstat, ka tas patiešām ir konkurss un nevis dāvinājums vai algota darba uzņemšanās. Otrkārt, jūs uzņematies atbildību par savas zemes likteni, ciktāl tas skar tiešu, jūsu paša politisku iedarbību. Jo tā var gadīties, ka Latvijai salīdzinājumā ar citām zemēm iet tik grūti tieši tāpēc, ka jūs ar saviem talantiem un pieredzi, kas citiem sabiedrības locekļiem gājuši secen, joprojām sēžat dīvānā, skatāties Panorāmu un gaidāt uzaicinājumu pa sarkanu paklāju iesoļot parlamentā. Bet zvana nebūs. Būs jāiet pa klaju lauku un jāatstāj iespēja lielam kritienam.

Ko nozīmē mazināt regulējumu slogu, kā to sola @partijaMMN? Tas nozīmē palielināt riskus, atstāt lielāku iespēju negadījumiem. Jo tikai tā var cilvēkiem dāvāt izvēles iespēju. Tā ir cena, kas jāmaksā par brīvību. Kas nav gatavs palielināt riskus un uzņemties individuālu atbildību par iznākumiem neatrunātās situācijās, tas nevar būt mūsu idejiskais ceļabiedrs.

Es partijas “Mēs mainām noteikumus” birojā pašlaik strādāju algotu darbu. Mana vieta sarakstā ir atkarīga nevis no kāda svētības, bet no tā, cik saraksta pretendentu lokā būs tādu cilvēku, kuri bauda lielāku sabiedrības uzticību un tādējādi var nest lielāku ieguldījumu “Mēs mainām noteikumus” plāna realizācijā un kuriem tāpēc vieta sarakstā ir virs manis. Tieši tādi paši noteikumi, ciktāl man ir teikšana, attiecas uz visiem pārējiem, kas ir atsaukušies Alvja Hermaņa uzsaukumam politiski rīkoties, lai atliktu mūsu valsts un tautas bojāeju par vēl kādu paaudzi.', '80c78cb510fcd31f4aba5464fbee85c0c212ffe3d6c5025d81030e2ff29c9fd0', -2064893208394642676, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2042330357853524175', NULL, '2026-04-10 10:56:21', 275, 'lv', '2026-04-09T19:54:36+00:00', 0, NULL, NULL, '2026-04-10 11:09:32', NULL, NULL, NULL);
