INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (15723, 'Vakar partijas “Mēs mainām noteikumus” lekciju cikla 4. vakarā izskanēja jautājums par to, kāpēc konservatīvie Latvijā katrs taisa savu partiju. To pašu Tomsons vakar arī vaicā Zeltītam raidījumā “Krustpunktā”. Ļoti vienkārši — konservatīvie zina, kas ir viņu vērtības, viņi tic absolūtai patiesībai, taču nesaprot, kas ir politika. Politika nav par sava priekšstata par absolūto patiesību uzspiešanu visiem. Politika ir savā ziņā arī spēle, lai saglabātu brīvības telpu, kurā cilvēku grupa var dzīvot saskaņā ar savām vērtībām. Politika mobilizē vienkopus uz līdzīgas konstrukcijas brīvības telpu cerošos. Ja šai spēlei pieiet ar domu panākt, lai visi seko viena paša lēmēja precīzām vērtībām, tad rezultāts ir daudz sliktāks, nekā tad, ja konservatīvie respektētu sava despotisma ietekmes robežas un apvienotos pulciņos. Atstājot domas manevra un domas attīstības (izlabošanās) iespēju arī savā domubiedru pulciņā, konservatīviem ir vislielākās izredzes pulcināt gana lielu savējo loku, lai iegūtu pietiekami lielu mandātu konkurēšanai uz varu ar visu relatīvistu pulciņiem, kuriem, protams, vienoties par kaut ko, kam neviens no viņiem galīgi netic, nav nekādu problēmu.', 'e1a76d3a23d8ab99ccea86d5bd33378574a04d3939f69d52ee99708538d6fdc4', 5489613927590582193, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2043930139226952191', NULL, '2026-04-14 10:13:22', 165, 'lv', '2026-04-14T05:51:34+00:00', 0, NULL, NULL, '2026-04-14 10:27:59', NULL, NULL, NULL);
