INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (23136, 'Viens termiņš ar Rail Baltica iluzoro pabeigšanu - tas tā kā speciāli?', '0136addf072c35dc63e9d687427ba355703376a65b80312366d7ffdd6acf0660', 1075838666921043333, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Lato_Lapsa/status/2046635102298337444', NULL, '2026-04-21 20:52:02', 12, 'lv', '2026-04-21T17:00:07+00:00', 0, NULL, NULL, '2026-04-21 20:57:07', 1, 1, 6);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (23359, 'Krievijai nav kapacitātes īstenot militāru uzbrukumu NATO valstīm, tostarp Baltijas valstīm, ko apliecina gan Latvijas, gan sabiedroto izlūkošanas dienestu dati, aģentūrai LETA uzsvēra ārlietu ministre Baiba Braže (JV), komentējot Ukrainas prezidenta Volodimira Zelenska izteikumus par interneta piekļuves ierobežojumu Krievijā iespējamo saistību ar mobilizāciju uzbrukumam Baltijas valstīm.
Ārlietu ministre atzīmēja, ka visas Krievijas militārās spējas ir pilnībā pavērstas pret Ukrainu, kur Krievija cieš lielus cilvēkresursu zaudējumus. Viņa pieminēja, ka Krievijas spēku kopējie zaudējumi tiek lēsti ap 1,3 miljoniem nogalināto un ievainoto, kas arvien vairāk ierobežo militāro kapacitāti un rada papildu slogu valsts sociālekonomiskajai sistēmai ilgtermiņā.
Braže secināja, ka palēninās arī Krievijas ekonomikas izaugsme. Starptautiskais valūtas fonds Krievijai prognozē tikai 0,8% iekšzemes kopprodukta pieaugumu 2026. gadā, salīdzinot ar vairāk nekā 4% iepriekšējos divos gados. Tāpat ārlietu ministre skaidroja, ka kopš pilna mēroga agresijas sākuma Krievijai nācies tērēt papildu 130 miljardus ASV dolāru, lai iegādātos rietumvalstu sankcijām pakļautās preces, kā arī tā zaudējusi vairāk nekā 150 miljardu ASV dolāru naftas eksporta ieņēmumos. Pēc Bražes paustā, arī inflācija Krievijā turpina nekontrolējami augt. Atbilstoši sabiedroto izlūkdienestu aplēsēm, šogad tā varētu būt tuvu 15%.
"Lai gan šobrīd Krievija vēl ir spējīga uzturēt savu kara mašīnu, tās ekonomikas ilgtermiņa perspektīva ir negatīva - līdzekļu rezerves sarūk, inflācija saglabājas, un valdība gatavo sabiedrību "stingrākiem laikiem"," norādīja ārlietu ministre.
Taujāta, kā Latvijas sabiedrībai interpretēt šādus publiskus paziņojumus, vai tie būtu uzskatāmi par brīdinājumu vai drīzāk hipotētisku scenāriju bez tūlītēja riska, Braže norādīja, ka jebkurš viedoklis no jebkura avota ir jāvērtē kontekstā ar faktiem. Ārlietu ministre uzsvēra, ka patlaban fakti ir tādi, ka Krievija jaunus militārus uzbrukumus nevar atļauties, tāpēc ir jāturpina vājināt Krieviju un jākāpina sankciju spiediens.
Runājot par to, vai šādu retoriku var izmantot Krievijas informatīvajā telpā, ārlietu ministre akcentēja, ka Krievija konsekventi īsteno dezinformācijas kampaņas un informatīvas operācijas, kas cita starpā vērstas uz NATO sabiedroto uzticības graušanu savām aizsardzības spējām, sabiedroto šķelšanu un atbalsta mazināšanu Ukrainai.
"Krievija jebkuru publiskajā vidē izskanējušo informāciju vai viedokli var nolemt izmantot melu un propagandas radīšanai. Taču Krievijai dezinformācijas kampaņām nav obligāti nepieciešami fakti," uzsvēra Braže.
Viņa atzīmēja, ka to apliecina, piemēram, šomēnes Krievijas īstenotā dezinformācijas kampaņa pret Baltijas valstīm, kur Krievija izplatīja melus par Baltijas valstu gaisa telpas izmantošanu Ukrainas veiktajiem bezpilota lidaparātu uzbrukumiem pret mērķiem Krievijā.
Jau rakstīts, ka, ņemot vērā Krievijas ieviestos ierobežojumus piekļuvei sociālajiem tīkliem, Ukrainas prezidents Zelenskis paudis uzskatu, ka Kremlis to dara, lai novērstu nekārtības gadījumā, ja tiktu izsludināta vispārējā mobilizācija jaunam liela mēroga uzbrukumam Ukrainai vai uzbrukumam vienai no Baltijas valstīm.
Igaunijas politiķi šonedēļ kritizēja Zelenska izteikumus, ka interneta piekļuves ierobežojumi Krievijā varētu būt saistīti ar mobilizāciju uzbrukumam Baltijas valstīm, un norādīja, ka Ukrainas prezidents, tos atkārtojot, izplata Kremļa naratīvu, kas apgrūtina sadarbību.
Igaunijas ārlietu ministrs Marguss Cahkna raidorganizācijai ERR atgādināja, ka Ukraina kopš Krievijas atkārtotā iebrukuma 2022. gadā ir vairākkārt norādījusi, ka Krievija var uzbrukt arī citiem, tostarp Baltijas valstīm. Viņaprāt, šādi sabiedrotā paziņojumi nekādā veidā nepadara sadarbību vieglāku. Turklāt ministrs piebilda, ka Zelenska vārdos nav nekādas patiesības.
Savukārt Lietuvas premjerministre Inga Ruginiene uzsvēra, ka patlaban nekas neliecina, ka Krievija gatavotu uzbrukumu Baltijas valstīm.', 'fc62642c43e969ce9ac0075eabadb923d10dc1b5d4c09f6618ff64d94cbd119b', 7173766517523748664, 7, 'web', 0, NULL, 'nra.lv', 'https://nra.lv/baltija/519432-krievijai-nav-kapacitates-uzbrukumam-baltijas-valstim.htm', NULL, '2026-04-22 17:43:10', 500, 'lv', '2026-04-22T17:15:00+03:00', 0, NULL, '"Lai gan šobrīd Krievija vēl ir spējīga uzturēt savu kara mašīnu, tās ekonomikas ilgtermiņa perspektīva ir negatīva - līdzekļu rezerves sarūk, inflācija saglabājas, un valdība gatavo sabiedrību "stingrākiem laikiem"," norādīja ārlietu ministre.', '2026-04-22 17:54:00', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (23378, '“Krievija jaunus militārus uzbrukumus nevar atļauties.” Visi spēki vērsti pret Ukrainu, uzskata ārlietu ministre 0
Krievija šobrīd nav spējīga īstenot militāru uzbrukumu NATO valstīm, tostarp Baltijas reģionam, uzsver ārlietu ministre Baiba Braže, atsaucoties uz Latvijas un sabiedroto izlūkdienestu vērtējumu.
Viņa norāda, ka šāds secinājums balstīts faktos, komentējot Ukrainas prezidenta Volodimira Zelenska izteikumus par iespējamu saikni starp interneta ierobežojumiem Krievijā un potenciālu mobilizāciju plašākam uzbrukumam.
Ārlietu ministre atzīmēja, ka visas Krievijas militārās spējas ir pilnībā pavērstas pret Ukrainu, kur Krievija cieš lielus cilvēkresursu zaudējumus.
Viņa pieminēja, ka Krievijas spēku kopējie zaudējumi tiek lēsti ap 1,3 miljoniem nogalināto un ievainoto, kas arvien vairāk ierobežo militāro kapacitāti un rada papildu slogu valsts sociālekonomiskajai sistēmai ilgtermiņā.
Tāpat ārlietu ministre skaidroja, ka kopš pilna mēroga agresijas sākuma Krievijai nācies tērēt papildu 130 miljardus ASV dolāru, lai iegādātos Rietumvalstu sankcionētās preces, kā arī tā zaudējusi vairāk nekā 150 miljardu ASV dolāru naftas eksporta ieņēmumos.
Pēc Bražes paustā, arī inflācija Krievijā turpina nekontrolējami augt. Atbilstoši sabiedroto izlūkdienestu aplēsēm, šogad tā varētu būt tuvu 15%.
Taujāta, kā Latvijas sabiedrībai interpretēt šādus publiskus paziņojumus, vai tie būtu uzskatāmi par brīdinājumu vai drīzāk hipotētisku scenāriju bez tūlītēja riska, Braže norādīja, ka jebkurš viedoklis no jebkura avota ir jāvērtē kontekstā ar faktiem.
Runājot par to, vai šādu retoriku var izmantot Krievijas informatīvajā telpā, ārlietu ministre akcentēja, ka Krievija konsekventi īsteno dezinformācijas kampaņas un informatīvas operācijas, kas cita starpā vērstas uz NATO sabiedroto uzticības graušanu savām aizsardzības spējām, sabiedroto šķelšanu un atbalsta mazināšanu Ukrainai.
Viņa atzīmēja, ka to apliecina, piemēram, šomēnes Krievijas īstenotā dezinformācijas kampaņa pret Baltijas valstīm, kur Krievija izplatīja melus par Baltijas valstu gaisa telpas izmantošanu Ukrainas veiktajiem bezpilota lidaparātu uzbrukumiem pret mērķiem Krievijā.
Jau rakstīts, ka, ņemot vērā Krievijas ieviestos ierobežojumus piekļuvei sociālajiem tīkliem, Ukrainas prezidents Zelenskis paudis uzskatu, ka Kremlis to dara, lai novērstu nekārtības gadījumā, ja tiktu izsludināta vispārējā mobilizācija jaunam liela mēroga uzbrukumam Ukrainai vai uzbrukumam vienai no Baltijas valstīm.
Igaunijas ārlietu ministrs Marguss Cahkna raidorganizācijai ERR atgādināja, ka Ukraina kopš Krievijas atkārtotā iebrukuma 2022. gadā ir vairākkārt norādījusi, ka Krievija var uzbrukt arī citiem, tostarp Baltijas valstīm.
Viņaprāt, šādi sabiedrotā paziņojumi nekādā veidā nepadara sadarbību vieglāku. Turklāt ministrs piebilda, ka Zelenska vārdos nav nekādas patiesības.
Savukārt Lietuvas premjerministre Inga Ruginiene uzsvēra, ka patlaban nekas neliecina, ka Krievija gatavotu uzbrukumu Baltijas valstīm.', 'dad8cc730148c2cf2ba19d36c165999491fda4420f2cbf35710bb744dd462fdf', 7101427327981590322, 16, 'web', 0, NULL, 'www.la.lv', 'https://www.la.lv/krievija-jaunus-militarus-uzbrukumus-nevar-atlauties-visi-speki-versti-pret-ukrainu-uzskata-arlietu-ministre', NULL, '2026-04-22 17:44:04', 376, 'lv', '2026-04-22T13:51:18.000000Z', 0, NULL, '“Krievija jaunus militārus uzbrukumus nevar atļauties.” Visi spēki vērsti pret Ukrainu, uzskata ārlietu ministre', '2026-04-22 17:54:00', NULL, NULL, NULL);
