INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (28062, 'Trîs gadus Pro ir valdībā un ar šīs, it kā taču zaļās partijas gādību nav sperts pat viens solis, lai mazinātu Latvijas atkarību no dabasgāzes.', '477406f5a0c322a28ebe09cde23d3b4c47b39901923c6d9896d45d303cba6dad', -1243086834084251312, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/pucej/status/2046830035454071211', NULL, '2026-04-30 01:36:06', 25, 'lv', '2026-04-22T05:54:43+00:00', 0, NULL, NULL, '2026-04-30 01:44:42', 4, 3, 19);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (28563, '"Vājuma parādīšana tikai izaicina agresiju. Ja mēs vēlamies, lai mūsu valstis būtu drošībā, mums ir jāturpina stiprināt Eiropas gatavību aizsargāties," ceturtdien, 30. aprīlī, preses konferencē pēc Baltijas un Ziemeļvalstu ārlietu ministru tikšanās sacīja ES Augstā pārstāve ārlietās un drošības politikas jautājumos Kaja Kallasa.
Viņa uzsvēra, ka agresora atturēšana darbojas, ja tā ir ticama. Aizsardzības stiprināšana nozīmē – palielināt aizsardzības izdevumus, novērst esošos trūkumus, kā arī stiprināt Eiropas militāro ražošanu.
"Ar ES 90 miljonu eiro aizdevumu un 20 sankciju paketēm mēs sūtam skaidru ziņu – mēs nodrošināsim Ukrainu ar nepieciešamo savas zemes aizstāvēšanai, kamēr Putins nesapratīs, ka viņa karš nekur neved. Ukraina mums ir daudz svarīgāka nekā Krievijai. Krievijas kara mērķi netiek sasniegti un tas arvien vairāk ir redzams," uzrunā sacīja Kallasa.
"Pirmo reizi vairāku gadu laikā Maskavas Uzvaras dienas parāde notiks bez nekāda smagā militārā aprīkojuma. Tas daudz liecina par to, kā karā veicas Krievijai," viņa piebilda.
Tāpat viņa atgādināja, ka nav iespējams atgriezties pie iepriekš zināmā biznesa ar Krieviju. Pat, ja Maskava pārtrauks šo karu Ukrainā.
Baltijas un Ziemeļvalstu ministri vienoti
Šā gada 29. un 30. aprīlī Latvijas ārlietu ministre Baiba Braže piedalījās ikgadējā Baltijas valstu un Ziemeļvalstu (NB8) ārlietu ministru sanāksmē. Tās fokusā bija atbalsts Ukrainai, Eiropas drošības un NATO spēju stiprināšana, kā arī sankciju pret Krieviju stiprināšana.
Kā "Delfi" informēja Ārlietu ministrijā (ĀM), ministri bija vienoti, ka brīva, aizsargāta un demokrātiska Ukraina ir Eiropas drošības garantija un pauda apņemšanos turpināt sniegt Ukrainai visaptverošu militāro un praktisko atbalstu, atbalstu eirointegrācijas procesā, kā arī pēckara Ukrainas drošības stiprināšanā. Līdztekus Ukrainas atbalsta pasākumiem, kur NB8 valstis ir starp lielākajiem palīdzības sniedzējiem, tika atzīmēts arī pašas Ukrainas ieguldījums Eiropas un globālajā drošībā ar savu ekspertīzi un militārajām tehnoloģijām.
Amatpersonas izteica gandarījumu par spēcīgas ES 20. sankciju kārtas apstiprināšanu, paužot nepieciešamību turpināt darbu pie 21. sankciju kārtas sagatavošanas. Braže uzsvēra, ka jāturpina nepārtraukts spiediens Krievijai un izolācija gan politiski starptautiskajās organizācijās, gan lielos sporta un kultūras pasākumos, jo tikai tā varam veicināt pārmaiņas un stiprināt globālo drošību.
Ministre akcentēja nepieciešamību Eiropai uzņemties lielāku atbildību pār savu drošību un aizsardzību, visām ES valstīm būtiski palielinot aizsardzības izdevumus, kur NB8 valstis jau sevi demonstrē kā labu piemēru. Vienlaikus uzsverot, ka ASV un cieša transatlantiskā sadarbība ir neaizstājams Eiropas drošības pamats. ES aizsardzības centieniem tādējādi jābūt papildinošiem un NATO spējas stiprinošiem, uzsvēra Braže.
NB8 sadarbības formātā ietilpst Dānija, Igaunija, Islande, Latvija, Lietuva, Norvēģija, Somija un Zviedrija. 2026. gadā NB8 sadarbību ārlietu jomā koordinē Igaunija. Igaunija savā NB8 koordinācijas gadā noteikusi šādas prioritātes: 1) sekmēt NB8 kā primāro Baltijas valstu un Ziemeļvalstu sadarbības ietvaru viedokļu koordinēšanā par starptautiskās un reģiona darba kārtības jautājumiem; 2) NB8 kā līdzīgi domājošu valstu tēla starptautiskās nozīmes un redzamības stiprināšana; 3) NB8 reģiona konkurētspējas palielināšana un sadarbības sekmēšana nozarēs ar uzsvaru uz aizsardzību, digitālajiem jautājumiem, ekonomiku, izglītību un kultūru.', '5c74478a47fe1e808202c6215ead6e4f77774d783fc49437e1d1d06e491daa82', -2987779760730385992, 4, 'web', 0, NULL, 'www.delfi.lv', 'https://www.delfi.lv/46713439/arzemes/120116708/vajuma-paradisana-izaicina-agresiju-par-eiropas-aizsardzibas-stiprinasanu-saka-kallasa', NULL, '2026-04-30 18:42:11', 458, 'lv', '2026-04-30T13:54:06.000Z', 0, NULL, '"Vājuma parādīšana izaicina agresiju", par Eiropas aizsardzības stiprināšanu saka Kallasa', '2026-04-30 18:59:11', NULL, NULL, NULL);
