INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (29033, 'Today, on 1 May, we must remember that the most dangerous conspiracy theory and scientific charlatanism of the 20th century was the doctrine of Marxism itself. Even today, scientifically unfounded myths about Karl Marx’s “contribution” continue to be repeated. This, of course, is a myth deliberately created by Soviet propaganda. In reality, he laid the toxic ideological foundations that red tyrants used to justify the mass murder of tens of millions of people.', '4f7fd68c704048d521899faae8256943f0bef1b1711a24e107ca4b9ad13b1951', 2580963848948119683, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2050192671126217215', NULL, '2026-05-01 20:04:37', 73, 'en', '2026-05-01T12:36:38+00:00', 0, NULL, NULL, '2026-05-01 20:15:10', 0, 0, 0);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (29149, 'Prātam neaptverami cinisks politiskais PR.
Sāksim to, ka @Braze_Baiba  pārstāv tieši to politisko spēku, kas ir atbildīgs par melošanu NATO. Latvija bija apsolījusies investēt aizsardzībā 2% no IKP. Līdz pat kritiskajam 2014. gadam šis rādītājs bija zem 1% un zemākais Baltijā.

Bražes izrādīšanās ar zemessargu formu ir atbaidošs cinisms - tieši viņas pārstāvētā "Vienotība" ir politiski atbildīga par to, ka 2014. gadā, kad Latvijai reāli draudēja Krievijas uzbrukums, Zemessardze bija novesta līdz bankrotam, katastrofāli trūka pat piemērotas formas, ieroču un infrastruktūras, to visu katrs bija spiests pirkt par saviem līdzekļiem. Atbildīgie par šo situāciju bija toreiz un tagad valdošie "Vienotības" politbiroja spices politiķi - Baibas Bražes domu biedru grupējums. Bezatbildīgs un Latvijas drošības intereses apdraudošs.

Tāpat par Braži mēs varam jautāt — kāpēc viņa piespieda Latvijas valdību piešķirt finansējumu ANO Palestīniešu bēgļu aģentūrai (UNRWA — United Nations Relief and Works Agency for Palestine Refugees in the Near East)? Bija labi zināms fakts, ka caur šo organizāciju esot notikusi terora organizācijas atbalstīšana (Ozola apgalvojums), jo viņi pilnībā kontrolēja šīs piegādes plūsmas. Un paši organizācijas dalībnieki bija iesaistīti terora aktos. Tas bija labi zināms gan NATO, gan pašai Bražei, bet viņa izvēlējās izplatīt, pēc Ozola apgalvojuma, nepatiesu informāciju, ka tas ir paredzēts civiliedzīvotāju palīdzībai. Pēc Ozola apgalvojuma, Braže rīkojusies pretēji Latvijas interesēm. Kāpēc - to vajadzētu saprast un noskaidrot.

Un, par Pudānu runājot, - viņš nesen pārkāpa vissvarīgāko demokrātiskas valsts principu un iesaistīja armiju politiskajās intrigās. Un, protams, atkal "Vienotības" vajadzībām. Armiju nekad un nekādā gadījumā nedrīkst izmantot politiskiem mērķiem un intrigām.', 'dddf555158de3b7a3ba1c5951d6ad9338ab16d3f23b8406b3d79dce47a660d26', -3233774059795086413, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2050433051847467074', NULL, '2026-05-02 09:25:39', 251, 'lv', '2026-05-02T04:31:49+00:00', 0, NULL, NULL, '2026-05-02 09:36:05', 2, 4, 10);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (29150, 'Legendary French actor Jean Reno has written a novel about Ukrainian children abducted by Russia 📷📷
His new book, “The Escape” (L’Évasion), centres on this issue. The story follows Emma, who goes undercover and travels to Siberia to get inside a facility where abducted Ukrainian children are held and “re-educated,” and to document what’s really happening there.

Reno has said he was deeply shocked by the scale of these crimes after learning from the news about the abduction of around 20,000 Ukrainian children. That’s when the idea for the book first came to him.

Grateful for this support!', '2437a8d29c4cbcf5fd237b67dc8c536a6baeb985c83633477ed7f8acb797f637', -6832448815623102921, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2050310948125045173', NULL, '2026-05-02 09:25:39', 98, 'en', '2026-05-01T20:26:37+00:00', 0, NULL, NULL, '2026-05-02 09:36:05', 0, 0, 0);
