INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (30057, 'Ne tik senos laikos virsnieks ar virsnieka godu drīzāk būtu šāvies, nekā parakstītu ko šādu. Taču, protams, kāds @nbskomandieris Kasparam Pudānam pēc publiskās melošanas par krievu dronu sakars ar virsnieka godu… https://t.co/ULSHpL5mDm', '04353e1d5ab71e05cded00ee6971fd974bab2b696fcd885860965e1a7911b699', -2598712816707038755, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Lato_Lapsa/status/2051545786224091401', NULL, '2026-05-05 20:57:01', 32, 'lv', '2026-05-05T06:13:25+00:00', 0, NULL, NULL, '2026-05-05 21:06:49', 5, 9, 37);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (30076, 'Būtisks jautājums, ko vajadzētu pārdomāt 5. maijā - dienu pēc 4. maija svinībām.

Tieši cik Rietumu sabiedroto valstu steidza atzīt Baltijas valstu neatkarības atjaunošanu 1990. gadā? Pirms kāda laika LTV Ziņu dienestā bija skatāma intervija ar bijušo Islandes ārlietu ministru Jonu Baldvinu Hanibalsonu. Viņš vienīgais centās mūs atbalstīt. Hanibalsons liecināja, ka 1990. gadā Eiropas valstu diplomātu un augstāko politiķu tikšanās laikā viņam tika stingri pieteikts klusēt. Tieši tā - paklusēt par atbalstu Baltijas valstu neatkarības centieniem.

1991. gada 1. augustā Kijivā ASV prezidents Džordžs Bušs aicināja atbalstīt Mihaila Gorbačova „reformēto PSRS” un neļauties „nacionālistiem-separātistiem”.

Attēlā redzams 1990. gada spāņu laikraksts „El Mundo”, kurā tiek ziņots par Rietumvācijas un Francijas valdību aicinājumu Lietuvai atturēties no neatkarības prasībām', '8be4d699ceb7f3849f36b56a56603e9cf5f34149468cd73f66c20741ff03a434', -3346802863315064656, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2051679201640501669', NULL, '2026-05-05 20:57:02', 116, 'lv', '2026-05-05T15:03:34+00:00', 0, NULL, NULL, '2026-05-05 21:07:00', 0, 13, 15);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (30078, 'Kāda ir Jurēviča vārdu pievienotā vērtība - pirms kāda laika viņam tieši šeit jautāju (ko viņš arī bija izlasījis), kā JV vadība un viņš pats vērtē faktu, ka Siliņas valdības tieslietu ministre ir pieķerta tīšā un publiskā melošanā sabiedrībai? Tas notika studijas intervijā @ltvzinas. 

Vēlāk LSM un Re:Check analītiķi pārbaudīja viņas teikto un noskaidroja, ka Lībiņa-Egnere bija tīši teikusi nepatiesību, proti, melojusi, acīs skatīdamās. Žurnālisti nosūtīja Tieslietu ministrijai jautājumu par šo situāciju - Lībiņas-Egneres birojs atsūtīja oficiālu atbildi, kas bija apzināti birokrātiskā valodā sacerēts absurds teksts, kura patiesais vēstījums bija nepārprotams: "Atšujieties, ejiet...." (viss šis gadījums ir atrodams @lsmlv  publiskajos avotos, ar precīzi pamatotiem faktiem un avotiem - melošana ir skaidri pierādīta).

Šim stāstam ir dziļāks simbolisms, nekā pirmajā brīdī varētu šķist. Te ir runa par tieslietu ministri (!!!), kas būtībā sniedz tīšu nepatiesu liecību. Politiķe, kuras tiešais uzdevums un solījums sabiedrībai ir darīt visu, lai valstī būtu godprātīga tiesiskā un politiskā vide. Papildus tas, kas to visu padara īpaši nepatīkamu, ir attieksme pret sabiedrību kā pret muļķiem, kuri varētu nesaprast melošanu vai arī ir spiesti to norīt.

Un tieši Jurēvica gadījums ir spilgti raksturojošs - viņš, tieši jautāts, izvēlas vienkārši neatbildēt, ignorēt jautājumu. Un pati partijas vadība tam vispār nepievērš uzmanību: nu, samelojās - nu un? Ak, tieslietu ministre samelojās pilsoņiem - ak, jā, kāds interesants simbolisms.

Vienvārdsakot, tīša nepatiesas informācijas sniegšana un vēlētāju muļķošana ir pieņemta kā pilnīgi pašsaprotama lieta. Un tieši JV politiskās vadības, Siliņas partijas līmenī. Pilsoņi tik parausta plecus, pieraduši. Arī tagad, lasot šīs rindas, piemēram, Ikstens varētu būt neizpratnē - ko tas Otto Ozols par šo ikdienišķo parādību te cepas... ?

Tikai tad nu saņemsimies un pajautāsim paši sev principiāli svarīgu jautājumu - ar ko mēs principā atšķiramies no putlerstānas, kur pilsoņus uzskata tieši par tādiem pašiem stulbeņiem, kuriem var tīši melot, acīs skatoties, un pēc tam birokrātiski pasūtīt uz vienu vietu? Žurnālisti, pat Sabiedriskais medijs ir kaut kādi fona kvaukšķi, kurus neņemt vērā.

Vai Jurēvics un viņa biedri ir spējīgi, gana drosmīgi atzīt, ka te kaut kas ir pilnīgi garām? Nē. Viņš uz to nav spējīgs. Tam ir vajadzīga izglītota, atbildīga, demokrātiskas sabiedrības pilsoņa un gluži vienkārši kārtīga cilvēka attieksme. Viņam un pārējiem JV biedriem tas nepiemīt.', '95d98e6b2a69d0d7689fe12d32b52c4a06202a8adbb65513fed516289ea9ba12', 5804325240112269854, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2051639901255340248', NULL, '2026-05-05 20:57:03', 364, 'lv', '2026-05-05T12:27:24+00:00', 0, NULL, NULL, '2026-05-05 21:07:00', 1, 8, 20);
