Happy #Europe day! 
 https://t.co/mgFfU0pomP', 'ba87e0a65f51e4bf07db604e11f321e75b840f775124b1003e9011ddd25a23e3', 8020458473436730100, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Braze_Baiba/status/2053074173119877263', NULL, '2026-05-10 07:23:29', 28, 'en', '2026-05-09T11:26:41+00:00', 0, NULL, NULL, '2026-05-10 07:29:23', 2, 27, 49);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (32111, 'Kāds uzrakstīja kategorisku prasību, lai viņa iepriekš iesniegtās idejas netiktu izmantotas. Tā kā idejas bija iesniegtas video formātā ar linku uz failu Google diskā, ar priekšlikumiem nebiju nemaz iepazinies, vien biju norādījis, ka jāiesniedz teksta formātā. Bet tas nemaina šīs kategoriskās prasības nesavietojamību ar politisko procesu.

Politikā priekšlikumu autorībai ir nulle nozīmes. Politisku ideju autortiesības nav vispār savietojamas ar demokrātisku politiku, jo idejai politikā jēga ir tikai tad, ja tā ir brīvi izmantojama, brīvi modificējama un brīvi atmetama bez saskaņojuma ar “autoru”.

Tieši tā arī realizējas ietekme uz politiskajiem procesiem, tieši tā politiķi nezaudē saķeri ar sabiedrību — ieklausīdamies virmojošajās idejās. Ja kāds ir “nozadzis” “jūsu ideju”, tas nozīmē, ka jūs ietekmējāt politiku. Kas ir politiskās līdzdalības pati būtība!

Ja MMN neko nesasniegs, bet atsevišķas “mūsu” idejas vai piegājieni sekmīgi atspoguļosies nobijušos konkurentu darbos, ļoti labi! Mēs būsim panākuši Latvijai kaut ko no pašu iecerētā.', 'aef9d72995044da72718c171d1b597b6fa2bb24252dcde0ea6c92ca7f7643454', 6995539672510153033, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2052990388273627261', NULL, '2026-05-10 07:23:31', 145, 'lv', '2026-05-09T05:53:45+00:00', 0, NULL, NULL, '2026-05-10 07:30:56', 2, 3, 23);
