INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (33288, 'Gada laikā Sprūda Aizsardzības ministrijā nomainījusies sestā daļa darbinieku. Mja… https://t.co/ys50MrrKL1', '48a1259e48339a6689b4a89f71409c4e49d769fdadf3e7777de484288ec6add4', 6763503241334010354, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Lato_Lapsa/status/2053856388628009155', NULL, '2026-05-11 20:16:52', 11, 'lv', '2026-05-11T15:14:56+00:00', 0, NULL, NULL, '2026-05-17 08:51:00', 5, 10, 23);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (33387, 'Indriksone norādīja, ka, viņasprāt, valdība spēs "nesagāzties" un nostrādāt līdz termiņa beigām, tomēr nespēs pieņemt lielus un būtiskus lēmumus, jo starp koalīcijas partijām ir savstarpēji strīdi.
"Premjeres uzruna par labu kopīgu darbu ir virsraksts. Patiesībā redzam, ka savstarpējā disciplinēšana, savstarpējā norāšana un kritizēšana, un sistemātiski koalīcijas līguma pārkāpumi noteikti nav fons, kas spēs teikt, ka valdība strādā kopējā redzējumā par valdības nākotni un izaugsmi. Vairāk tā ir reakcija uz krīzēm," komentējot pirmdien valdībā skatīto ziņojumu par pērn paveikto, sacīja Indriksone.
NA līdere vērtēja, ka arī sociālajā jomā, uz laiku paceļot mājokļa pabalstu, valdība tikai reaģējusi uz krīzi, bet tā vietā būtu vajadzīgs ilgtermiņa redzējums, kā uzlabot situāciju taisnīguma ziņā.
"Cilvēki Latvijā dzīvo un veido ģimenes tad, ja viņi redz drošību, paļāvību, stabilitāti un garantētu atbalstu, ka nepasliktināsies viņu situācija tuvākajā laikā," sprieda Indriksone.
Viņa norādīja, ka Nacionālā apvienība nav valdībā tāpēc, ka partijai dažādos jautājumos ir pretrunas ar "Progresīvajiem". "Un tā bija pareiza izvēle, redzot, kā šobrīd valdība strādā," sacīja Indriksone.
"Tā, manuprāt, ir lielākā šīs valdības problēma, ka viņi strādā katrs par sevi, katrs savā ministrijā," pauda Indriksone.
KONTEKSTS:
Evikas Siliņas ("Jaunā Vienotība") vadīto valdību apstiprināja 2023. gada 15. septembrī. Neskatoties uz ministru rokādēm un acīmredzamām domstarpībām koalīcijas partneru vidū dažādos jautājumos, valdība ir spējusi noturēties. Tiesa, tai ik pa laikam ir grūtības Saeimā nodrošināt deputātu kvorumu, ko izmanto opozīcija.', 'fdb10f0e584b00010f1d04f7b3a3d061eaa28f7a027b4c89cc5e79814a941de8', 1184871132528021609, NULL, 'web_scraper', 0, NULL, 'www.lsm.lv', 'https://www.lsm.lv/raksts/zinas/latvija/03.03.2026-nacionalas-apvienibas-lidere-indriksone-sis-valdibas-lielaka-problema-katrs-strada-par-sevi.a637101/', NULL, '2026-05-11 23:26:24', 221, 'lv', '2026-03-03T00:00:00', 0, NULL, 'Nacionālās apvienības līdere Indriksone: Šīs valdības lielākā problēma – katrs strādā par sevi', '2026-05-11 23:33:39', NULL, NULL, NULL);
