INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (35371, 'Brīnumainais KNAB. Jauna politiskā cirka izrāde. Kamēr komunistu kolaboranta Lemberga kabatas partija ZZS bija valdībā un bija izdevīga Evikas Siliņas kabinetam, tikmēr KNAB viņus neaiztika. Brīdī, kad "PROgresīvie" nogāza valdību, KNAB brīnumainā kārtā "pēkšņi" pamodās un ķērās klāt ZZS.

Te jāatceras agrākās dīvainības KNAB un JV ciešajā tuvībā.

Pirms pāris gadiem KNAB ar lielu pompu  sarīkoja priekšvēlēšanu šovu vēlētāju apkrāpšanas recidīvistam Artusam Kaimiņam. Viņu padarīja teju vai par mocekli, kuru "ļaunā elite" un tās karakalpi velk pa Saeimas kāpnēm uz saplosīšanu. Tiesa, beigās Kaimiņš netika saplosīts - pēc nakts cietuma kamerā ar slapjām biksēm un noraudātu seju viņš TV kameru tiešraidē tika palaists brīvībā. Bet cietēja un opozicionāra tēls bija gatavs, un oligarha Meroni mauka atkal tika Saeimā. Te man šausmīgi jāatvainojas, jo esmu jums samelojies - Artuss Kaimiņš izrādījās pilnīgi nevainīgs, jo nebija pārdevis ne savu godu, ne sirdsapziņu, ne arī kādu citu ķermeņa daļu starptautiskajam naudas atmazgātājam Rūdolfam Meroni. Ja vēlētāju apkrāpšanas recidīvists Artuss Kaimiņš par šo tekstu jūtas apvainots - tad pazemīga un personīga atvainošanās! Viņš nav un nekad nav bijis politiskā prostitūta! 

Kā cīnītājs par taisnību un toreiz KNAB organizētā mediju cirka izrādes galvenais varonis A. Kaimiņš iekļuva Saeimā. Tā nu sagadījās, ka "Vienotībai" toreiz pietrūka dažas balsis, lai apstiprinātu privātlidmašīnu cienītāja Krišjāņa Kariņa (ne)vadīto valdību. Un te lieti noderēja Artusa Kaimiņa balss - lielais opozicionārs brīnumainā kārtā pēkšņi kļuva par varas atbalstītāju. Viņš nobalsoja par Kariņa valdības apstiprināšanu un "pēkšņi" tika pie dāsni apmaksātām komisiju vietām Saeimā. Bet brīnumi ar to nebeidzās - KNAB apsūdzība drīz vien izčākstēja. 

Tā lūk - JēVienotības valdībai bija nepieciešams, lai Artuss sēž Saeimā, nevis cietumā. Un KNAB padevīgi un saprotoši nostājās miera stājā! Kaimiņš izrādījās nevainīgs kā zīdaina jēriņa asara! Nekādu šaubu, ko Jūs... ?! 

Tiesiskums, atbildība, skaļi sludinātie antioligarhu pricipi un vērtības - visi lepni karogi ar ko vienmēr dižojās JēVienotība izrādījās iemesti podā.

Pavisam neliela, bet svarīga atkāpe - Pirms kāda laika Ukrainā izvērsās pamatīgs skandāls, kad valdība centās pārņemt kontroli pār pretkorupcijas biroju. Pēc asiem sabiedrības un starptautisko partneru iebildumiem Ukrainas valdība atteicās no mēģinājumiem pakļaut savai kontrolei viņu KNAB analogu.

Kam Latvijā kalpo un kā tiek izmantots KNAB? Vai viņi nodarbojās ar patiesu korupcijas apkarošanu vai apkalpo varas partijas JēVienotības intereses - uzbrūk konkurentiem tikai tad kad viņi vairs nav vajadzīgi un saudzē, tad vajadzīgi.', 'f7673e1fb9a5ef5064c773ee8d91ae7cfc591f3207643f840efa9c5c4e4e9d0c', -1713810281164455620, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2054913299658015087', NULL, '2026-05-14 22:18:29', 380, 'lv', '2026-05-14T13:14:43+00:00', 0, NULL, NULL, '2026-05-17 08:52:49', 0, 6, 18);
