INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (35803, 'Teorētiski iespējami varianti: var līdz novembrim turpināt demisionējušais MK, Saeima var iecelt aizstājējus līdz jaunajam MK, var ātri izveidot jaunu MK. Situācijai atbilstoši būtu ātri izveidot jaunu valdību. Vajadzēs pieņemt ātrus un svarīgus lēmumus un “klibas pīles” nederēs.', 'dd5c75fa1733f007f52e8f17d075d2a352caaa6892116260c9144b55849e130f', -6888749897112845896, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/pucej/status/2055241289654780113', NULL, '2026-05-15 17:30:41', 38, 'lv', '2026-05-15T10:58:02+00:00', 0, NULL, NULL, '2026-05-15 22:45:47', 1, 1, 11);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (35859, 'I utterly reject the notion that Gerhard Schröder is a Russian agent, or Putin’s man in the West. Plain logic suggests the exact opposite: it is Putin who is an agent recruited by Schröder. He represents a powerful anti-Russian organisation whose objective is to dismantle Russia, reducing it to a destitute, backward, and thoroughly discredited state. And Putin is successfully carrying out the mission of Schröder and his clandestine anti-Russian cabal.

It is no coincidence that Putin has maintained the Mausoleum in the heart of Moscow, where Vladimir Lenin - the 20th century’s pre-eminent Russophobe - lies in state. He held the Russian people in contempt and often voiced this publicly. Regarding the Russians, he wrote: "A slave who is not only unaware of his slave condition but who justifies and embellishes his slavery - such a slave is a lackey and a boor who arouses a legitimate feeling of indignation, contempt, and loathing."

Subsequently, Lenin orchestrated mass terror against the Russians, exiled their finest scientists, and oversaw the execution of countless others. Putin continues to glorify this mass murderer and hater of the Russian people. Just like Lenin before him, he serves forces that loathe both Russians and Russia itself', '95bbc782a16dd716b54cbd09f48499e43280f93f2961d3c2fe2217286f97a405', -9140947202016469417, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2055261754779726160', NULL, '2026-05-15 17:30:46', 201, 'en', '2026-05-15T12:19:21+00:00', 0, NULL, NULL, '2026-05-17 08:52:49', 0, 1, 1);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (35999, 'Situācija Tuvo Austrumu reģionā tiešā veidā ietekmē globālo drošību, uzsvēra Latvijas prezidents Edgars Rinkēvičs, piektdien Rīgas pilī tiekoties ar Jordānijas premjerministra vietnieku un ārlietu ministru Aimanu Safadi.
Kā aģentūru LETA informēja prezidenta padomnieks Mārtiņš Drēģeris, tikšanās laikā amatpersonas pārrunāja valstu divpusējās attiecības, kā arī apmainījās viedokļiem par situāciju Tuvajos Austrumos un Ukrainā.
Rinkēvičs apliecināja Latvijas intereses padziļināt politisko un ekonomisko sadarbību ar Jordāniju, kā arī stiprināt sadarbību drošībā un aizsardzībā.
Pārrunājot aktuālo drošības situāciju Tuvo Austrumu reģionā un starptautiskos centienus tās stabilizēšanai, kā arī nepieciešamību risināt situāciju Hormuza šaurumā, Latvijas prezidents pauda, ka nedrīkst pieļaut, ka Irāna turpina izvērst agresiju un apdraudēt starptautiskos tirdzniecības ceļus.
Latvijas prezidents novērtēja Jordānijas atbalstu Ukrainai, tai skaitā starptautiskajās organizācijās. Rinkēvičs arī izteica atzinību par Jordānijas un Ukrainas sākto sadarbību drošības jomā, kas apliecina, ka Ukraina ir kļuvusi par drošības nodrošinātāju Tuvo Austrumu valstīm, kamēr pati iesaistīta aktīvā karadarbībā.
Ar Jordānijas ārlietu ministru tikās arī Latvijas ārlietu ministre Baiba Braže (JV). Kā aģentūru LETA informēja ministres padomnieks Toms Sadovskis, tikšanās laikā puses apliecināja gatavību strādāt pie divpusējās sadarbības attīstīšanas, tostarp ekonomikas nozarēs ar augstu pievienoto vērtību.
Sarunā amatpersonas izcēla sadarbību lauksaimniecības nozarē. Jordānija viens no lielākajiem kālija minerālmēslojuma ražotājiem pasaulē, tādēļ Latvija ir ieinteresēta attīstīt sadarbību pārtikas drošības un lauksaimniecības piegāžu ķēžu noturības jomā. Savukārt Jordānijas puse izrādīja interesi par sadarbības attīstīšanu farmācijas, aizsardzības, informācijas un komunikācijas tehnoloģiju industrijās.
Latvijas ārlietu ministre informēja par Latvijas prioritātēm drošības un aizsardzības jomās, atbalstu Ukrainai, Krievijas ierobežošanu un darbu ANO Drošības padomē. Braže pateicās Jordānijai par tās atbalstu balsojumā par ANO Ģenerālās asamblejas rezolūciju par taisnīgu un ilgstošu mieru Ukrainā.
Braže akcentēja, ka Krievijas spēka un agresijas politika nav tikai Eiropas drošības jautājums, bet gan globāls drauds. Viņa arī skaidroja, ka Krievija brutāli maldina un vervē citu valstu pilsoņus tās karam pret Ukrainu, tajā skaitā no Tuvo Austrumu un Āfrikas valstīm.
Pārrunājot aktuālo situāciju Tuvajos Austrumos, Braže novērtēja Jordānijas ieguldījumu Tuvo Austrumu situācijas stabilizēšanā, kā arī tās atbalstu bēgļu problēmas risināšanai reģionā. Abi ārlietu ministri nosodīja Irānas agresīvo rīcību reģionā, pārrunāja Hormuza šauruma slēgšanas ietekmi uz reģiona un globālo drošību un ekonomiku, kā arī novērtēja starptautiskos centienus situācijas risināšanai.
Braže novērtēja Eiropas Savienības ciešo sadarbību ar Jordāniju, īpaši cīņā pret terorismu, vardarbīgo ekstrēmismu, organizēto noziedzību un nelegālo migrāciju.
Vizītes laikā tika parakstīts saprašanās memorands par politisko konsultāciju mehānisma izveidi starp abu valstu ārlietu ministrijām, kā arī līgums par vīzu prasības atcelšanu diplomātisko pasu turētājiem, kas kļūs par pirmo spēkā esošo starpvaldību līgumu starp Latviju un Jordāniju.
Jau rakstīts, ka Irāna kopš 28. februāra atrodas karastāvoklī ar ASV un Izraēlu. Kopš 8. aprīļa ir spēkā trausls pamiers.
Irāna kopš kara sākuma faktiski ir nobloķējusi Hormuza šaurumu. ASV sāka bloķēt Irānas ostas pēc neveiksmīgajām ASV un Irānas sarunām Pakistānā.', '25d234ed7a2c16e5fc68f1cdb7a1b12c4c8e7b4c8b948e815a97c1657e18eb40', 75524507116860056, 7, 'web', 0, NULL, 'nra.lv', 'https://nra.lv/politika/521229-edgars-rinkevics-rigas-pili-uznemis-augstus-viesus-no-jordanijas.htm', NULL, '2026-05-15 21:23:25', 449, 'lv', '2026-05-15T18:45:00+03:00', 0, NULL, 'Edgars Rinkēvičs atkāj, kas tiešā veidā ietekmē drošību visā pasaulē', '2026-05-17 02:29:16', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (36105, 'My message at #LennartMeriConference - saying Russia’s army moves at a snail’s pace is an insult to snails. If a snail started in Avdiivka in Feb. 2022 and moved west, it would now be in Czechia. Russia is still stuck in Donbas.

🇺🇦 has the momentum, we must step up our support. https://t.co/VjQrP72LMf', '40b0b5983cdef989525e2c7aa375e1f7867d58563bec50dad2694eceac65fe18', 18401976709721846, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Braze_Baiba/status/2055579132528914500', NULL, '2026-05-16 13:47:29', 53, 'en', '2026-05-16T09:20:30+00:00', 0, NULL, NULL, '2026-05-16 14:48:24', 0, 15, 39);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (36119, 'Cilvēks paņem rokās mačeti, novicinās pie audekla un nolemj, ka sagraizītais audekls ir patiesības vēstījums. Kad izrādās, ka nav, tad saka, ka mačete halucionē. Mākslīgais intelekts nehalucionē. Vienīgā halucinācija ir, ka MI kaut ko “domā”, un tā rodas MI lietotāja galvā.', '14d7a3ce7fb22f694af47432e6b58e042b04a7cc262dea4ac6b7976aa9a5e65a', 7401858689996526100, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2055553661032411639', NULL, '2026-05-16 13:47:31', 41, 'lv', '2026-05-16T07:39:17+00:00', 0, NULL, NULL, '2026-05-16 14:47:00', 0, 0, 1);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (36120, 'Valstij nevar būt mērķa. Mērķtiecīga valsts mērķu vārdā izmantos piespiedu varu, lai pakļautu tos, kas neparakstās uz nosprausto mērķi. Mērķtiecīga valsts bez aizturēm upurēs cilvēka brīvību un pašu cilvēku kā radības kroni. Tieši mērķtiecīgā valstī plaukst birokrātija, jo birokrātija ir mehānisms, ar kuru var vienotam mērķim mobilizēt liela izmēra cilvēku kolektīvu.

Brīvu cilvēku valsts funkcija, pretstatā mērķtiecīgas valsts funkcijai, ir nodrošināt apstākļus, kuros cilvēki katrs var mēģināt sasniegt savus individuālos, stipri mainīgos un savās vērtībās balstītos mērķus. Valsts mērķim, ja tādu var identificēt, ir vairāk kopīga ar basketbola noteikumu mērķiem, nekā ar basketbola komandu vai spēlētāju individuālajiem mērķiem.

Basketbola noteikumi nav paredzēti, lai kāda komanda vienmēr uzvarētu vai lai kāds spēlētājs vai treneris vienmēr gūtu no tā labumu. Basketbola noteikumiem ir jābūt tādiem, lai basketbolu vēl kāds spēlētu. Lai basketbola spēle nekad nebeigtos. Valstij ir jābūt tādai, lai to veidojošie cilvēki turpinātu to “spēlēt”. Valstij vēl papildu prasība ir, ka tā, atšķirībā no basketbola spēles organizatora, nevar pateikt: ja nepatīk, ej spēlēt citā turnīrā.

Valsts mērķi īslaicīgi var būt tikai ārpolitiski un saistīti ar valsts pastāvēšanas nodrošināšanu. Tiklīdz valsts mērķis paredz upurēt to radību, kuras dēļ valsts vispār pastāv, valstij nav leģitīma pamata.

Politiķu pienākums ir piedāvāt vīziju un, jā, savas iedarbības mērķus, uz kuriem viņi modina pievienoties citus, bet tos nedrīkst vienādot ar valsts mērķiem. Ja vien negribas turpināt savus līdzpilsoņus pakāpeniski ieslodzīt mērķtiecīgajā birokrātijas cietumā.', '2f6cc279e402f0c23c952fbc288edc91531e9b66accb67de36b6dc3c8d90314a', 5069170957012698357, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2055363230059614392', NULL, '2026-05-16 13:47:31', 227, 'lv', '2026-05-15T19:02:35+00:00', 0, NULL, NULL, '2026-05-16 14:47:00', 4, 1, 9);
