INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (36792, 'Kopumā prezidenta argumentācija kandidāta izvēlē ļoti loģiska. Liela atbildība tagad @AndrisKulbergs un @Apvienotais_ , jo Latvija šajos smagajos apstākļos nedrīkst ilgi būt bez valdîbas.', '52551819278beec00a866bbe16cb0633af2b5fa2de708ad16449aaf9740c683c', -6148989049302382091, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/pucej/status/2055662674487173310', NULL, '2026-05-17 10:16:24', 24, 'lv', '2026-05-16T14:52:28+00:00', 0, NULL, NULL, '2026-05-18 12:11:05', 5, 1, 65);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (36981, 'Politiskas partijas uzdevums ir nevis piedāvāt visus labākos risinājumus visām problēmām (tas ir idiotisks piedāvājums — tas paredz, ka politiskā sacensība ir par viskompetentākajiem risinājumiem — tehnokrātijas un vēstures beigu ideja; risinājuma “labums” ir atkarīgs no katra vērtībām), bet piedāvāt paredzamai ideoloģijai atbilstošus risinājumus.

Neesmu nekad veidojis kori, bet iedomājos, ka tauta ir kaut kas līdzīgs kormeistaram, kurš savā korī grib redzēt pa bišķiņai no visa komplekta, jo tikai viss komplekts kopā būs saprātīgs. Tātad, ja kormeistars jūs uzņem korī kā tenoru, tad dziedāšanu spalgā soprānā no jums īsti negaida. Tas būtu ne tikai negaidīts, bet arī diezgan nepatīkams pārsteigums. Soprānos jau jūsu vietā tika uzņemti tie, kas to pieprot daudz labāk.

Politiķēt gribētājiem jāapzinās, vai viņi iet soprānos, tenoros vai kora biroja darbiniekos. Tajā brīdī, kad jūs kā soprānu pulciņa dalībnieks uz savu galvu cenšaties tenorā nodziedāt to, kas jums tajā brīdī šķiet vissvarīgāk nodziedamais, jūs jaucat kori, kuru tauta ir veidojusi vai vismaz cerējusi, ka veido. Tajā pašā laikā neviens neatceļ pienākumu lemt saskaņā ar savu sirdsapziņu. Tāpēc ir tik svarīgi pirms stāšanās politiskā partijā saprast, vai jūs stājaties jums īstajā, piemērotajā partijā, kur dziedāšana partijas balsī būs saskaņā ar jūsu sirdsapziņu.', '4f10e212277d3538ed0302f747bba89c4742cec4d8894917ca885b835109680b', 43715079662443110, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2055977457447018511', NULL, '2026-05-17 18:30:08', 194, 'lv', '2026-05-17T11:43:18+00:00', 0, NULL, NULL, '2026-05-17 18:59:00', 0, 2, 11);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (37022, 'Vienotības un progresīvo vaukšķu skatījumā Loginovs, loģiski, ir izsmiekla vērts - kur nu tādam ar Linkaitiem, Briškeniem un Švinkām līdzināties. Ne simtus miljonu, ne miljardus nav izpļekarējis un izzagt palīdzējis, pat ne ostu līdz bankrotam nav novedis. Nožēlojamais amatieris.', 'fd4bbf2812cfbf2333f8d417ec9a4da5ed81cd50824526a34a3ac29353b03979', 1154616878799465573, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Lato_Lapsa/status/2055987512468807722', NULL, '2026-05-17 18:30:14', 39, 'lv', '2026-05-17T12:23:16+00:00', 0, NULL, NULL, '2026-05-18 12:12:17', 1, 6, 29);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (37029, 'Meli un priekšvēlēšanu PR manipulācijas - E. Siliņas valdības "krišanas" iestudētais farss.

Interesanti, ka Latvijas mediji un eksperti ar vienu izņēmumu (@JanisIkstens to pamanīja) izvairās saredzēt acīmredzamo - E. Siliņas valdības "krišana" ir iestudēts farss. Dronu nokrišana bija nevis patiesais iemesls, bet gan apzināti dramatizēts iegansts. Cilvēki, kuri seko līdzi notikumiem Eiropā, labi zina, ka šobrīd droni ik pa brīdim nokrīt teju visās apkārtējās valstīs - Lietuvā, Igaunijā, Somijā un citur. Diemžēl tā ir reālā situācija Putina Krievijas izraisītā kara dēļ. Un nevienā no šīm valstīm šie incidenti nav izraisījuši valdības krīzes.

Godprātīgi eksperti zina, ka pasaulē neeksistē hermētiskas dronu aizsardzības sistēmas. Var, protams, uzstādīt apmēram 500 miljonus eiro dārgo "Dzelzs kupola" analogu, bet pat tas negarantētu pilnīgu aizsardzību. Tātad - jums var patikt vai nepatikt bijušais aizsardzības ministrs Sprūds ar savu padomnieku kolhozu, bet, objektīvi skatoties - pieprasīt viņam atbildību par šo incidentu ir neadekvāta un tīši pārspīlēta reakcija. Kā jau minēju - tā notiek arī citās valstīs, bet no tā netiek veidota apzināti uzpūsta drāma, valdības nekrīt.

Tad kādēļ bija vajadzīgs šis iestudētais farss? 

Acīmredzot JV politbirojs saprata, ka iet uz vēlēšanām ar galēji nepopulāro, augstprātīgo Siliņu un viņas komandu, kas pieķerta tīšā melošanā un izšķērdībā - tas būtu pārāk riskanti. Tāpēc tika meklēts un atrasts ērts iegansts, lai nogāztu valdību. Arī pašai Siliņai tas bija labs iemesls, jo tagad aktīvi tiek veidots viņas mocekles un cīnītājas tēls. Ārkārtīgi ērta poza priekšvēlēšanu laikā.

Līdzīgs aprēķins noteikti varēja būt izdevīgs Progresīvajiem. Esot valdošajā koalīcijā, viņiem bija grūti kritizēt valdību, jo paši barojās pie šīs siles. (pametot tiks saņemts ļoti treknas kompensācijas) Tagad viņi atkal varēs uz pilnu tvaiku ieslēgt protesta un populisma bazūnes, kas ir tik svarīgas viņu elektorātam - radikāliem un paštaisniem jauniešiem.

Tātad - prokremliskā Jaunā Vienotība un Progresīvie izmantoja dronu incidentu, lai priekšvēlēšanu laikā nebūtu saistīti ar melos, izšķērdībā un nekompetencē iestigušo valdību. Tā vietā viņi tagad tēlos cīnītājus par taisnību un šķiedīs dubļus uz opozīciju.

Latvijas sabiedrība atkal un atkal tiek pataisīta par muļķi, kuram var iebarot kārtējos melus.', '971c6e8765b391c878e85bae25e112260ec163923206edbe8767985f7638b9ad', 5832454131374785337, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2056026978046660649', NULL, '2026-05-17 18:30:15', 334, 'lv', '2026-05-17T15:00:05+00:00', 0, NULL, NULL, '2026-05-18 12:11:18', 0, 0, 2);
