INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (37209, 'Kas ir apbrīnojamākais - tā iekšējā puvuma pakāpe, kas šiem vienotības vēža rotbergiem ļauj bez mazākā mulsuma sašust par bezgala noziedzīgi izmantotiem desmitiem tūkstošu un ne vārdu nepieminēt savu politkompanjonu un labuma guvēju izzagtos miljardus.', '7823bfe458196e7aac88f558d187c5e641243455a3f5f807a8079cb2909f9655', 5881164720796064608, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Lato_Lapsa/status/2056082677703274895', NULL, '2026-05-18 12:47:00', 35, 'lv', '2026-05-17T18:41:25+00:00', 0, NULL, NULL, '2026-05-26 21:43:22', 0, 19, 55);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (37596, 'Krievijas Ārējās izlūkošanas dienests (SVR) apgalvo, ka Ukraina gatavojot triecienus Krievijas aizmugures reģioniem no Baltijas valstu teritorijas un ka uz Latviju jau esot nosūtīti ukraiņu karavīri.
SVR apgalvo, ka Ukrainas varasiestādēm it kā esot izdevies pārliecināt Rīgu dot piekrišanu operācijām pret Krieviju un ka uz Latviju jau esot nosūtīti Ukrainas bezpilota lidaparātu spēku karavīri.
SVR min piecas Latvijas armijas bāzes - Ādaži, Sēlija, Lielvārde, Daugavpils un Jēkabpils, kur izvietoti ukraiņu karavīri.
SVR arī draud Latvijai ar "taisnīgu atriebību", no kā neglābšot dalība NATO.
Ārlietu ministre Baiba Braže, reaģējot uz šo ziņu, norāda: "Krievija atkal melo. Šoreiz dezinformācijas kampaņu pret Latviju īsteno Krievijas Ārējās izlūkošanas dienests (SVR). FAKTS: Latvija neļauj izmantot savu gaisa telpu uzbrukumiem Krievijas teritorijā. Tas Krievijas pārstāvjiem ir skaidrots jau vairākkārt."
Valsts prezidents Edgars Rinkēvičs paziņojis, ka Krievija melo par to, ka Latvija ļauj jebkurai valstij izmantot Latvijas gaisa telpu un teritoriju, lai veiktu uzbrukumus Krievijai vai jebkurai citai valstij.
Demisionējusī Ministru prezidente Evika Siliņa (JV) skaidro, ka Krievija izvērš kārtējo dezinformācijas kampaņu pret Latviju, izplatot melus, ka Ukraina plāno izmantot Latviju kā vietu uzbrukumiem Krievijas teritorijai.
"Latvija nekad nav devusi Ukrainai atļauju izmantot savu teritoriju vai gaisa telpu pašaizsardzības triecieniem pret Krieviju vai jebkuru citu valsti," akcentēja premjere, uzsverot, ka Krievija ir agresors un Ukrainai ir visas tiesības sevi aizstāvēt.
