INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38267, 'Jūtu līdzi Latgales un nu jau arī Vidzemes iedzīvotājiem - incidenti ar droniem satrauc un rada apdraudējuma sajūtu. Tas parāda tos darbus, kas vēl jāveic aizsardzības un citiem resoriem gan praktiskajā aizsardzības darbā, gan arī komunikācijā ar iedzîvotājiem.', 'de7faeded4597f4088a0835df83d80cad5d3305ea9d31fd34e5ba783e6aeef82', -2994534405413627615, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/pucej/status/2056704404653318149', NULL, '2026-05-19 15:41:51', 38, 'lv', '2026-05-19T11:51:56+00:00', 0, NULL, NULL, '2026-05-19 16:10:51', 2, 4, 17);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38311, '❗️Iespējams apdraudējums Latvijas gaisa telpā.

Krāslavas, Preiļu, Ludzas un Rēzeknes novados.

Nato gaisa telpas patrulēšanas misijas iznīcinātāji ir aktivizēti Baltijas gaisa telpā.

Kopā ar NATO sabiedrotajiem pastāvīgi monitorē gaisa telpu, lai nodrošinātu spēju nekavējoši reaģēt uz potenciālu apdraudējumu. Esam pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības.

Kamēr norisinās krievijas agresija Ukrainā, tādu gadījumu atkārtošanās, kad Latvijas gaisa telpā ielido vai tai pietuvojas ārvalstu bezpilota lidaparāts ir iespējama.

Iedzīvotāju ievērībai!

Meklējiet patvērumu telpās, aizveriet logus un durvis - ievērojiet divu sienu principu. Ja pamanāt zemu lidojošu, aizdomīgu vai bīstamu objektu, netuvojieties tam un zvaniet 112. Par apdraudējuma beigām informēsim.', '5418887166d3702c2392c2e139da8011859ab27654029aee5d0fd05592093b00', 5072114772160492457, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Latvijas_armija/status/2056662162303574408', NULL, '2026-05-19 15:41:56', 101, 'lv', '2026-05-19T09:04:05+00:00', 0, NULL, NULL, '2026-05-19 16:10:12', 19, 96, 150);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38316, '“Crystal Arrow 2026” laikā Sauszemes spēku Mehanizētā kājnieku brigāde trenēja koordināciju, izlūkošanu un darbību modernā kaujas vidē 💪🏻

Mācībās tika izmantoti gan gaisa, gan sauszemes droni, kas palīdz ātrāk iegūt informāciju, samazināt riskus un efektīvāk atbalstīt karavīrus uzdevumu izpildē 🛡️', 'e6297d0b96df465a5466286f77f67b0d840c31cb49a5bce59d1b07a5d54ea1fb', 6175858841971936047, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Latvijas_armija/status/2056620914540679560', NULL, '2026-05-19 15:41:57', 40, 'lv', '2026-05-19T06:20:10+00:00', 0, NULL, NULL, '2026-05-19 16:10:12', 0, 4, 28);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38317, 'Šodien, 17. maijā, ap plkst. 06.00 Nacionālie bruņotie spēki informēja par iespējamu apdraudējumu Latvijas gaisa telpā Alūksnes, Balvu, Krāslavas, Ludzas, Rēzeknes novados.
Nacionālie bruņotie spēki nekavējoties aktivizēja reģionā izvietotās pretgaisa aizsardzības vienības, kas izvirzījās uz noradīto vietu un ieņēma pozīcijas. Tika aktivizēti NATO Baltijas gaisa telpas patrulēšanas misijas iznīcinātāji.

Nacionālie bruņotie spēki apstiprina, ka Latvijas gaisa telpā ielidoja un no tās izlidoja viens bezpilota lidaparāts. Ap plkst. 08.00 Nacionālie bruņotie spēki informēja, ka apdraudējums Latvijas gaisa telpā Alūksnes, Balvu, Krāslavas, Ludzas, Rēzeknes novados ir noslēdzies.

Nacionālie bruņotie spēki kopā ar NATO sabiedrotajiem pastāvīgi monitorē gaisa telpu, lai nodrošinātu spēju nekavējoši reaģēt uz potenciālu apdraudējumu. Nacionālie bruņotie spēki ir pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības.  

Kamēr norisinās krievijas agresija Ukrainā, tādu gadījumu atkārtošanās, kad Latvijas gaisa telpā ielido vai tai pietuvojas ārvalstu bezpilota lidaparāts ir iespējama.', '9f1afbe91e1bfef3d3ee7600a721b2f87dc5f972c4d2a640e675064592b8f7a5', 7201409336724854712, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Latvijas_armija/status/2055916095106609611', NULL, '2026-05-19 15:41:57', 139, 'lv', '2026-05-17T07:39:28+00:00', 0, NULL, NULL, '2026-05-19 16:10:12', 8, 9, 47);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38406, 'Delighted to welcome my friend, Canada’s Foreign Minister Anita Anand to Riga🇱🇻🇨🇦. 

