INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38463, 'Mēs esam nonākuši tiktāl, ka stulbene ārlietu ministra amatā izplata kremļa paziņojumus pilnā apmērā.', '705e83b5ffdbe293386c97ff17873d75d836102f53d0625620433fdf6e52afa4', -4798876703979667553, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Lato_Lapsa/status/2056728003271417999', NULL, '2026-05-19 20:41:36', 14, 'lv', '2026-05-19T13:25:42+00:00', 0, NULL, NULL, '2026-05-26 21:43:22', 0, 1, 11);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (38543, 'Pēc vairāk kā četriem gadiem pilna mēroga kara, ko krievija izvērš pret Ukrainu, ar katru mēnesi aizvien vairāk mainās kara aina, krievija vairs nedominē kara laukā.

Ukraina aizvien biežāk veic ļoti efektīvus triecienus pa mērķiem dziļi krievijas teritorijā, tostarp Latvijas, Igaunijas un Somijas pievārtē.

Tā kā krievijas politiskā elite nespēj savai sabiedrībai paskaidrot kā tas iespējams, tad tā ir pievērsusies tradicionālai melu taktikai - melot un mēģināt visiem iestāstīt, ka pie viņu problēmām ir vainīgs kāds cits.

Latvija nav atvērusi savu gaisa telpu Ukrainas droniem, lai veiktu triecienus pret krieviju, taču Latvija turpina sniegt maksimālu atbalstu Ukrainas bruņotajiem spēkiem.

Latvija nav atļāvusi Ukrainas bruņotajiem spēkiem veikt triecienus pa krieviju no mūsu teritorijas, taču Latvija turpinās mācīties no pasaulē labākajiem ekspertiem dronu pielietošanā savas valsts aizsardzībā.

Pret tiem, kuri izplata šos krievijas melus ir jāvēršas ar vislielāko likumā noteikto bardzību.', 'b8744b0bcce11144768b318a0db27685c7fcbad4194c2e692f869b22311575db', 6962515215507855293, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Latvijas_armija/status/2056730796140995058', NULL, '2026-05-19 20:41:45', 139, 'lv', '2026-05-19T13:36:48+00:00', 0, NULL, NULL, '2026-05-19 20:50:39', 12, 26, 76);
