The detained activists must be released and their safe return ensured.', '8b2ea8c1a8c57d629541fe1df46efaddcd67cba0bb656cc41353c9478e96b6de', -4711780726358453787, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/Braze_Baiba/status/2057336278274769372', NULL, '2026-05-21 14:49:17', 35, 'en', '2026-05-21T05:42:46+00:00', 0, NULL, NULL, '2026-05-21 15:04:36', 3, 17, 57);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (39370, 'Un vēl. Iespējams, ka tukšruna rodas no bailēm neatbildēt uz nesakarīgiem jautājumiem. Sabiedriskā medija klausītājiem tiktu aiztaupīts laiks un nervi, ja intervētāji raidījuma sākumā dotu katram politiķim vārdu pateikt galveno vēstījumu. Un tad jautājumi sekotu par visiem dzirdēto. Jo pašlaik tie raidījumi lielākoties sākas ar “Vai ir taisnība, ka pirms jūs pasaucāt Anniņu uz dzimšanas dienas ballīti, jums bija doma saukt Ilzīti, un vai jūs vēlētos komentēt ziņās izskanējušo, ka jums vakar krekls bija izlīdis laukā no biksēm?” Kāda ballīte, kāds Jānītis, es neko nezinu, es tikko ieslēdzu radio. Krekls no biksēm laukā, labi, bet tā taču nav lietas būtība. Un var jau saprast politiķi, kad viņam šitā pajautā. Tad tur ir grūti nerunāt tukšu. Bet nu štrunts, vajag jau arī deputātam atcerēties, ka viņš ir ievēlēts un dienaskārtību var noteikt arī viņš. Tabloīda jautājumus žurnālistiņš var vēlāk iestarpināt. Nav jau tā, ka galīgi nekā tiem politiķiem nav ko teikt. Viņi valdību veido. Un vispār ar visām amatpersonām vajag uzreiz tā — cik jūs daudz varat šodien izstāstīt par aktuālo? 10min? Labi, pēc desmit minūtēm tad laižam mūziku un tauta varēs mierīgi pusdienas paēst. Bet nekā. Atnāk, kā daudzās citās reizēs, dikti svarīga amatpersona, kas neko nevar pastāstīt, un tad stundu tīksminās, kā žurnālisti viņu apčamda, meklēdami kādu bez izģērbšanas sataustāmu informācijas drupaču.', '5db19a40ac261782ce341057b1711a4d90c120e6cbafccc2450577fc0b7ad55c', 2291498985711348502, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2057189635646709879', NULL, '2026-05-21 14:49:20', 213, 'lv', '2026-05-20T20:00:04+00:00', 0, NULL, NULL, '2026-05-21 15:07:23', 2, 0, 10);
