INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (42824, 'Kulberga valdības apstiprināšanas gadījumā būtiski mainīsies Saeimas sastāvs
Rīga, 26. maijs, LETA. Ja Saeima apstiprinās "Apvienotā saraksta" (AS) politiķa Andra Kulberga piedāvāto valdību, parlamentā gaidāmas būtiskas deputātu sastāva izmaiņas, tostarp mandātus varētu iegūt vairāki pašvaldību pārstāvji, liecina aģentūras LETA apkopotā informācija.
No "Jaunās vienotības" (JV) ministriem un līdzšinējai premjerministrei Evikai Siliņai atgriežoties darbā Saeimā, no tā dēvētajiem mīkstajiem mandātiem būs jāatvadās Jānim Zariņam, Viesturam Zariņam, Gatim Liepiņam un Ingrīdai Circenei. Parlamentā atgriezīsies līdzšinējais finanšu ministrs Arvils Ašeradens, tieslietu ministre Inese Lībiņa-Egnere un viedās administrācijas un reģionālās attīstības ministrs Raimonds Čudars.
Vienlaikus satiksmes ministram Atim Švinkam ("Progresīvie" (P)) atgriežoties parlamentā, deputāta mandātu zaudēs Līga Rasnača. Savukārt Zaļo un zemnieku savienības (ZZS) politiķa Ulda Auguļa, kurš varētu ieņemt zemkopības ministra amatu, vietā Saeimā uz laiku atgriezīsies Ģirts Štekerhofs. Viņš mandātu iepriekš zaudēja pēc Auguļa aiziešanas no labklājības ministra amata.
Kā liecina Centrālās vēlēšanu komisijas (CVK) mājaslapā pieejamā informācija, ja deputātu mandātus izvēlēsies nolikt arī Nacionālās apvienības (NA) deputāti, kas virzīti ministru amatiem - Ilze Indriksone, Nauris Puntulis, Jānis Dombrava un Jānis Vitenbergs -, tā dēvētie mīkstie mandāti pienāksies attiecīgi Normundam Dzintaram, Ģirtam Lapiņam, Jānim Iesalniekam un Arnoldam Jātniekam. Politiķi gan vēl nav komentējuši, vai noliks deputātu mandātus.
Būtiskas izmaiņas gaidāmas arī AS frakcijā. Kā aģentūrai LETA apstiprināja frakcijas vadītājs Edgars Tavars, neviens no AS politiķiem, kas strādās valdībā, neplāno saglabāt deputāta mandātu, tādēļ Saeimas darbā uz laiku iesaistīsies četri jauni deputāti - Ieva Brante, Inga Priede, Raivis Kalējs un Dāvis Melnalksnis.
Paredzēts, ka pēc valdības apstiprināšanas Kulberga vietā parlamentā stāsies Brante, topošā tieslietu ministra Edvarda Smiltēna vietā - Melnalksnis, Tavara vietā, kurš varētu vadīt viedās administrācijas un reģionālās attīstības ministriju, - Priede, bet finanšu ministra amatam virzītā Māra Kučinska vietā - Kalējs. Tāpat, ņemot vērā Smiltēna darbu Saeimas Prezidijā, varētu mainīties arī Prezidija sastāvs.
Brante, kā arī Limbažu novada domes deputāts un viedās administrācijas un reģionālās attīstības ministrijas Teritoriju attīstības izvērtēšanas nodaļas vadītājs Melnalksnis ("Latvijas Reģionu apvienība" (LRA)) pēc jaunās valdības apstiprināšanas ir gatavi doties uz Saeimu, pieņemot tā saukto mīksto deputāta mandātu, aģentūrai LETA apstiprināja politiķi.
Savukārt Tukuma novada domes deputāte un Talsu novada pašvaldības Sabiedrisko attiecību nodaļas vadītāja Priede ("Latvijas Zaļā partija" (LZP)) un Liepājas domes deputāts un Dienvidkurzemes novada Nīcas un Otaņķu pagastu apvienības pārvaldes vadītājs Kalējs (LRA) norādīja, ka patlaban vēl nav saņemts oficiāls uzaicinājums no CVK, taču neoficiāli zināms par iespējamu deputāta mandāta iegūšanu. Gan Priede, gan Kalējs norādīja, ka viņiem ir jāpārdomā savs lēmums, vai atstāt esošos amatus, lai dotos uz darbu Saeimā. Kalējs atzina, ka viņam ir jāvienojas arī ar ģimenes locekļiem, vai pieņemt jaunus profesionālos izaicinājumus, un jāpārdomā tas, kāds varētu būt viņa pienesums Saeimā.
Brante aģentūrai LETA apstiprināja, ka pēc pozitīva Saeimas lēmuma par valdības izveidi un vairāku deputātu kļūšanas par ministriem viņa stāsies deputāta amatā.
Brante piebilda, ka uz Rīgas domes vēlēšanām bija iestājusies partijā "Latvijas attīstībai", taču pašlaik nav partijas biedre. Arī Saeimā viņa plāno saglabāt savu neatkarību.
Aģentūra LETA jau ziņoja, ka Kulberga valdībā ir iezīmējies pilns ministru sastāvs, liecina aģentūras LETA rīcībā esošā neoficiālā informācija.
No Kulberga pārstāvētā AS finanšu ministra amatam varētu tikt virzīts Kučinskis, tieslietu ministra amatam - Smiltēns, savukārt Viedās administrācijas un reģionālās attīstības ministriju varētu vadīt Tavars, liecina neoficiālā informācija.
Šīs trīs ministrijas jaunajā valdībā nonāks AS pārziņā, lai gan līdz šim tās vadījuši redzami JV politiķi.
Savukārt no JV jaunajā Ministru kabinetā amatus saglabās ārlietu ministre Baiba Braže un veselības ministrs Hosams Abu Meri. Aizsardzības ministra amatam paredzēts virzīt Nacionālo bruņoto spēku pulkvedi Raivi Melni, bet par satiksmes ministru kļūtu līdzšinējais iekšlietu ministrs Rihards Kozlovskis, noskaidroja aģentūra LETA.
NA jaunajā valdībā vadītu Izglītības un zinātnes, Kultūras, Iekšlietu, kā arī Klimata un enerģētikas ministriju. Partijas valde ministru amatiem izvirzījusi attiecīgi Saeimas deputātus Ilzi Indriksoni, Nauri Puntuli, Jāni Dombravu un Jāni Vitenbergu.
Savukārt no ZZS valdībā amatus varētu saglabāt ekonomikas ministrs Viktors Valainis un labklājības ministrs Reinis Uzulnieks, bet zemkopības ministra amatam plānots virzīt Saeimas deputātu, bijušo labklājības ministru Uldi Auguli.
Amatu saglabās pašreizējā Saeimas priekšsēdētāja Daiga Mieriņa.
Četras partijas - AS, NA, ZZS un JV - Kulberga vadībā ir vienojušās par atbildības jomu sadalījumu jaunajā valdībā, bet patlaban turpinās sarunas par konkrētu darāmo darbu programmu.
Valsts prezidents pēc Siliņas valdības krišanas uzticēja jaunās valdības veidošanu AS politiķim Kulbergam, nosakot ierobežotu laiku politiskajām konsultācijām. Potenciālie koalīcijas partneri jau parakstījuši pamata vienošanos, kas kalpos kā pamats turpmākajām sarunām par jaunās valdības prioritātēm un darbiem.
https://infogram.com/andra-kulberga-ministru-kabinets-1h984wvwy9y9z2p
- Publicēta: 26.05.2026 14:00', 'f2e858eb51f0adb3f26c6f496ee51002d717cbdc70f38c821686e38564677bda', 6700707538606391960, 6, 'web', 0, NULL, 'www.leta.lv', 'https://www.leta.lv/home/important/3283CB13-35FA-404B-B33C-8745A5BEE6F2', NULL, '2026-05-26 20:32:16', 722, 'lv', NULL, 0, NULL, 'Kulberga valdības apstiprināšanas gadījumā būtiski mainīsies Saeimas sastāvs', '2026-05-26 20:51:21', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (42862, 'Kozlovskis satiksmes ministra amatā kā prioritātes izceļ “airBaltic” un “Rail Baltica”
Potenciālajam satiksmes ministram Rihardam Kozlovskim (JV) prioritātes amatā būs jautājumi par Latvijas nacionālo aviokompāniju "airBaltic", dzelzceļa projektu "Rail Baltica", ceļu satiksmes drošību un viedās infrastruktūras izbūvi uz robežas, otrdien žurnālistiem pastāstīja Kozlovskis.
Viņš sacīja, ka divas lietas, kas ir ieliktas dienaskārtībā un kuras netiks noņemtas, ir "Rail Baltica" un "airBaltic". Viņš uzsvēra, ka grozījumi "Rail Baltica" projekta īstenošanas likumā, kas tika pieņemti pagājušajā nedēļā, nosaka, ka "Rail Baltica" projekta īstenošana ir valdības kopīgs uzdevums.
"Tas nozīmē, ka ne tikai satiksmes ministrs mēģina izdarīt visu un atrast naudu, bet, cerams, ka tagad tas būs koleģiāls valdības lēmums, protams, Satiksmes ministrijai (SM) izdarot galveno," norādīja Kozlovskis.
Vienlaikus viņš pauda uzskatu, ka Latvijai ir jābūt šādai kompānijai kā "airBaltic". "No vienas puses "airBaltic" ir mūsu rūpju bērns, bet no otras puses dārgums. Es darīšu visu, lai "airBaltic" lidotu, bet ir kaut kāda robeža šīm vēlmēm un iespējām," norādīja topošais ministrs.
Viņš arī uzsvēra, ka nekur nav pazudis robežas jautājums, tostarp Latvijas Valsts radio un televīzijas centrs (LVRTC) turpina viedo tehnoloģiju ieviešanu gar Latvijas-Baltkrievijas un Latvijas-Krievijas robežu, lai visa sauszemes robeža būtu pilnībā aprīkota līdz 2026. gada beigām.
"Tāpat nevaram nolikt malā ceļu satiksmes drošības jautājumu, kas ir SM kompetence. Šajā jautājumā man nāk klāt pieredze arī no iekšlietu ministra amata," piebilda Kozlovskis.
Viņš vērtēja, ka ar līdzšinējo satiksmes ministru Ati Švinku (P) sadarbība bija laba, un pauda uzskatu, ka nedarīs kaut ko radikāli citādāk kā Švinka.
Ministru prezidente Evika Siliņa (JV) 14. maijā paziņoja par atkāpšanos no valdības vadītājas amata. Šāds lēmums pieņemts pēc nesaskaņām ar koalīcijā ietilpstošajiem "Progresīvajiem", kuri 13. maijā aicināja Valsts prezidentu sākt konsultācijas par jaunas valdības izveidi.
"Progresīvie" paziņoja, ka valdība faktiski zaudējusi rīcībspēju, un šādā situācijā pastāv divas iespējas - Ministru prezidentes demisija vai balsojums Saeimā par valdības turpmāko uzticību.
Tāpat ziņots, ka četras partijas, kuras "Apvienotā saraksta" (AS) politiķa Andra Kulberga vadībā mēģina veidot jauno valdību, ir sadalījušas atbildības jomas.
Konkrētus ministru kandidātu vārdus Kulbergs solīja nosaukt otrdien, bet atsevišķas partijas jau tos atklājušas.
No Kulberga pārstāvētā AS finanšu ministra amatam varētu tikt virzīts Māris Kučinskis, tieslietu ministra amatam - Edvards Smiltēns, savukārt Viedās administrācijas un reģionālās attīstības ministriju varētu vadīt Edgars Tavars, liecina neoficiālā informācija.
Šīs trīs ministrijas jaunajā valdībā nonāks AS pārziņā, lai gan līdz šim tās vadījuši redzami "Jaunās vienotības" (JV) politiķi.
Savukārt no JV jaunajā Ministru kabinetā amatus saglabās ārlietu ministre Baiba Braže un veselības ministrs Hosams Abu Meri. Aizsardzības ministra amatam paredzēts virzīt Nacionālo bruņoto spēku pulkvedi Raivi Melni, bet par satiksmes ministru kļūtu līdzšinējais iekšlietu ministrs Kozlovskis.
Nacionālā apvienība (NA) jaunajā valdībā vadītu Izglītības un zinātnes, Kultūras, Iekšlietu, kā arī Klimata un enerģētikas ministriju. Partijas valde ministru amatiem izvirzījusi attiecīgi Saeimas deputātus Ilzi Indriksoni, Nauri Puntuli, Jāni Dombravu un Jāni Vitenbergu.
Savukārt no Zaļo un zemnieku savienības (ZZS) valdībā amatus varētu saglabāt ekonomikas ministrs Viktors Valainis un labklājības ministrs Reinis Uzulnieks, bet zemkopības ministra amatam plānots virzīt Saeimas deputātu, bijušo labklājības ministru Uldi Auguli.
Amatu saglabās pašreizējā Saeimas priekšsēdētāja Daiga Mieriņa.', '7d0ad0592b185dcde0f98729cc6a86b6668298fd7e1daff403f5ffb9e1d6de51', 6268046414540456860, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711130-kozlovskis-satiksmes-ministra-amata-ka-prioritates-izcel-airbaltic-un-rail-baltica', NULL, '2026-05-27 17:00:58', 501, 'lv', '2026-05-26T10:12:04.000000Z', 0, NULL, 'Kozlovskis satiksmes ministra amatā kā prioritātes izceļ “airBaltic” un “Rail Baltica”', '2026-05-26 20:48:30', NULL, NULL, NULL);
