INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44321, 'Grozījumi Ministru kabineta 2025. gada 7. oktobra noteikumos Nr. 598 "Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.1. pasākuma "Dzelzceļa infrastruktūras attīstība un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos" pirmās projektu iesniegumu atlases kārtas īstenošanas noteikumi"

Ministru kabineta noteikumi: Šajā laidienā 21 Pēdējās nedēļas laikā 32 Visi
Ministru kabineta noteikumi Nr. 303
Rīgā 2026. gada 26. maijā (prot. Nr. 29 41. §)
Grozījumi Ministru kabineta 2025. gada 7. oktobra noteikumos Nr. 598 "Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.1. pasākuma "Dzelzceļa infrastruktūras attīstība un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos" pirmās projektu iesniegumu atlases kārtas īstenošanas noteikumi"
Izdoti saskaņā ar Eiropas Savienības fondu
2021.–2027. gada plānošanas perioda vadības likuma
19. panta 6. un 13. punktu
Izdarīt Ministru kabineta 2025. gada 7. oktobra noteikumos Nr. 598 "Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.1. pasākuma "Dzelzceļa infrastruktūras attīstība un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos" pirmās projektu iesniegumu atlases kārtas īstenošanas noteikumi" (Latvijas Vēstnesis, 2025, 195. nr.) šādus grozījumus:
1. Izteikt noteikumu nosaukumu šādā redakcijā:
"Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.1. pasākuma "Dzelzceļa infrastruktūras attīstība un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos" īstenošanas noteikumi".
2. Izteikt 1.1. apakšpunktu šādā redakcijā:
"1.1. kārtību, kādā īsteno Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.1. pasākumu "Dzelzceļa infrastruktūras attīstība un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos" (turpmāk – pasākums);".
3. Papildināt ar 3.1 punktu šādā redakcijā:
"3.1 Pasākuma ietvaros tiek īstenoti:
3.11. Eiropas Savienības struktūrfondu un Kohēzijas fonda 2014.–2020. gada plānošanas perioda posmotie projekti Nr. 3.1.1.3/1/24/I/001 "Dzelzceļa pasažieru infrastruktūras modernizācija, 2. posms" un Nr. 3.1.1.3/1/24/I/002 "Dzelzceļa infrastruktūras modernizācija vilcienu kustības ātruma paaugstināšanai, 2. posms ";
3.12. Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam plānošanas perioda projekti."
4. Izteikt 4. punktu šādā redakcijā:
"4. Šo noteikumu 3.11. apakšpunktā norādītajos projektos līdz 2029. gada 31. decembrim ir sasniedzami šādi uzraudzības rādītāji:
4.1. iznākuma rādītājs: rekonstruēto vai modernizēto dzelzceļa līniju kopējais garums – 100 km;
4.2. iznākuma rādītājs: staciju skaits, kurās uzbūvēti paaugstinātie peroni, – 45 stacijas un pieturas;
4.3. rezultāta rādītājs: vilcienu kustības ātruma palielināšanās modernizētajā līnijā – līdz 140 km/h;
4.4. rezultāta rādītājs: modernizētās dzelzceļa pasažieru infrastruktūras īpatsvars – 49 %."
5. Papildināt ar 4.1 punktu šādā redakcijā:
"4.1 Šo noteikumu 3.12. apakšpunktā norādītajos projektos līdz 2029. gada 31. decembrim ir sasniedzami šādi uzraudzības rādītāji:
4.11. iznākuma rādītājs: jaunu vai modernizētu dzelzceļa sliežu garums TEN-T – 40 km;
4.12. iznākuma rādītājs: jaunas vai modernizētas dzelzceļa stacijas un pieturas, kurās izbūvēti paaugstinātie peroni, – 20 stacijas un pieturas;
4.13. rezultāta rādītājs: jaunuzbūvēto, jaunināto, rekonstruēto vai modernizēto sliežu ceļu lietotāju skaits gadā – 11 189 574 pasažieri;
4.14. nacionālais rādītājs: izbūvēto dzelzceļa mobilo 5G sakaru bāzes staciju skaits – 20 bāzes stacijas."
6. Papildināt ar 4.2 punktu šādā redakcijā:
"4.2 Šo noteikumu 4.1., 4.2., 4.11. un 4.12. apakšpunktā minētais iznākuma un 4.14. apakšpunktā minētais nacionālais rādītājs ir sasniegts, kad tiek pabeigti projektā paredzētie būvdarbi, objekti ir nodoti ekspluatācijā, finansējuma saņēmējs iesniedzis sadarbības iestādē noslēguma maksājuma pieprasījumu, kurā pamatota rādītāja sasniegšana, un sadarbības iestāde to apstiprinājusi."
7. Papildināt ar 4.3 punktu šādā redakcijā:
"4.3 Šo noteikumu 4.3., 4.4. un 4.13. apakšpunktā minētais rezultāta rādītājs ir sasniegts, kad finansējuma saņēmējs iesniedzis sadarbības iestādē noslēguma maksājuma pieprasījumu, kurā pamatota rādītāja sasniegšana, un sadarbības iestāde to apstiprinājusi. Rezultāta rādītāja vērtība ir attiecināma, ja tā ir radusies viena kalendāra gada laikā pēc projekta noslēguma maksājuma veikšanas. Ja finansējuma saņēmējs rezultāta rādītāja vērtību sasniedz, sadarbības iestāde turpmāko projekta rezultāta rādītāja izpildi nekontrolē."
8. Izteikt II nodaļas nosaukumu šādā redakcijā:
"II. Pasākumam pieejamais finansējums".
9. Izteikt 10. punktu šādā redakcijā:
"10. Pasākuma ietvaros plānotais un pieejamais kopējais finansējums ir 180 301 281 euro, tai skaitā Kohēzijas fonda finansējums – 153 256 088 euro un valsts budžeta līdzfinansējums – 27 045 193 euro."
10. Izteikt 11. punktu šādā redakcijā:
"11. Sadarbības iestāde, saskaņojot to ar atbildīgo iestādi, pasākuma ietvaros var pārdalīt Kohēzijas fonda finansējumu starp 3.11. un 3.12. apakšpunktā minētajiem projektiem, pārliecinoties, ka netiek ietekmēta šo noteikumu 4. un 4.1 punktā minēto rādītāju sasniegšana."
11. Izteikt 12. punktu šādā redakcijā:
"12. Pasākuma ietvaros atbalstāmās darbības ir publiskās lietošanas dzelzceļa infrastruktūras būvniecība, pārbūve un atjaunošana, kas nodrošina pilnvērtīgu integrēšanos TEN-T tīklā, un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos, tai skaitā Eiropas transporta tīklā esošās dzelzceļa infrastruktūras modernizācija un jaunas izveide, dzelzceļa pasažieru infrastruktūras modernizācija, kā arī drošības, dzelzceļa sakaru un informācijas sistēmu nodrošināšana."
12. Izteikt 14.16. apakšpunktu šādā redakcijā:
"14.16. indeksācijas izmaksas, nepārsniedzot 15 % no attiecīgā būvniecības līguma izmaksām;".
13. Papildināt ar 14.17. apakšpunktu šādā redakcijā:
"14.17. ar klimatisko risku izvērtējumu un nepieciešamo darbību un materiālu izvēli šo risku mazināšanai saistītās izmaksas, lai nodrošinātu pielāgošanos klimata pārmaiņām."
14. Izteikt 18. punktu šādā redakcijā:
"18. Neparedzētie izdevumi nepārsniedz 5 % no projekta plānotajām kopējām tiešajām attiecināmajām izmaksām. Finansējuma saņēmējs saskaņo neparedzēto izdevumu izlietošanu ar sadarbības iestādi pirms izdevumu veikšanas."
15. Izteikt 28.1. apakšpunktu šādā redakcijā:
"28.1. ievērot principu "Vienlīdzība, iekļaušana, nediskriminācija un pamattiesību ievērošana" un uzkrāt datus par projekta ietekmi uz horizontālā principa rādītāju "Objektu skaits, kuros Kohēzijas fonda ieguldījumu rezultātā ir nodrošināta vides un informācijas pieejamība" (ja attiecināms);".
16. Papildināt ar V nodaļu šādā redakcijā:
"V. Noslēguma jautājums
32. Atzīt par spēku zaudējušiem Ministru kabineta 2024. gada 23. jūlija noteikumus Nr. 507 "Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.3. pasākuma "Eiropas transporta tīklā esošās dzelzceļa infrastruktūras attīstība" pirmās projektu iesniegumu atlases kārtas īstenošanas noteikumi" (Latvijas Vēstnesis, 2024, 148. nr.)."
Ministru prezidente,
aizsardzības ministra pienākumu izpildītāja E. Siliņa
Satiksmes ministrs A. Švinka', '38495334975e7d85b3501f682190ac32a23826b936a914d09b813b78f8ebe2f1', 6650513461637373369, 19, 'vestnesis', 0, NULL, 'www.vestnesis.lv', 'https://www.vestnesis.lv/ta/id/368628', NULL, '2026-05-28 10:13:36', 1004, 'lv', '2026-05-28T00:00:00', 0, NULL, 'Grozījumi Ministru kabineta 2025. gada 7. oktobra noteikumos Nr. 598 "Eiropas Savienības kohēzijas politikas programmas 2021.–2027. gadam 3.1. prioritātes "Ilgtspējīga TEN-T infrastruktūra" 3.1.1. specifiskā atbalsta mērķa "Attīstīt ilgtspējīgu, pret klimatu izturīgu, inteliģentu, drošu un vairākveidu TEN-T infrastruktūru" 3.1.1.1. pasākuma "Dzelzceļa infrastruktūras attīstība un energoefektivitātes uzlabošana sabiedriskajos pasažieru pārvadājumos" pirmās projektu iesniegumu atlases kārtas īstenošanas noteikumi"', NULL, NULL, NULL, NULL);
