INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44330, 'Par apropriācijas pārdali no budžeta resora "74. Gadskārtējā valsts budžeta izpildes procesā pārdalāmais finansējums" programmas 24.00.00 "Valsts aizsardzības un drošības fonds"

Ministru kabineta rīkojumi: Šajā laidienā 18 Pēdējās nedēļas laikā 24 Visi
Ministru kabineta rīkojums Nr. 298
Rīgā 2026. gada 26. maijā (prot. Nr. 29 39. §)
Par apropriācijas pārdali no budžeta resora "74. Gadskārtējā valsts budžeta izpildes procesā pārdalāmais finansējums" programmas 24.00.00 "Valsts aizsardzības un drošības fonds"
1. Pamatojoties uz likuma "Par valsts budžetu 2026. gadam un budžeta ietvaru 2026., 2027. un 2028. gadam" 73. pantu, atbalstīt apropriācijas pārdali 54 500 000 euro apmērā no budžeta resora "74. Gadskārtējā valsts budžeta izpildes procesā pārdalāmais finansējums" programmas 24.00.00 "Valsts aizsardzības un drošības fonds" uz Aizsardzības ministrijas budžeta apakšprogrammu 22.12.00 "Nacionālo bruņoto spēku uzturēšana", lai nodrošinātu Nacionālo bruņoto spēku kaujas spēju palielināšanu.
2. Aizsardzības ministrijai normatīvajos aktos noteiktajā kārtībā sagatavot un iesniegt Finanšu ministrijā pieprasījumu par šā rīkojuma 1. punktā minēto apropriācijas pārdali atbilstoši faktiski nepieciešamajam apmēram.
3. Finanšu ministram normatīvajos aktos noteiktajā kārtībā informēt Saeimas Budžeta un finanšu (nodokļu) komisiju par šā rīkojuma 1. punktā minēto apropriācijas pārdali un, ja Saeimas Budžeta un finanšu (nodokļu) komisija piecu darbdienu laikā pēc attiecīgās informācijas saņemšanas nav izteikusi iebildumus, veikt apropriācijas pārdali.
Ministru prezidente,
aizsardzības ministra pienākumu izpildītāja E. Siliņa
Aizsardzības ministra vietā –
finanšu ministrs A. Ašeradens', 'd5a753576b1314f4036a52e0c64a4d85df413d9d356d665cc2ed17dba94d4d1d', 1503503544081846665, 19, 'vestnesis', 0, NULL, 'www.vestnesis.lv', 'https://www.vestnesis.lv/ta/id/368641', NULL, '2026-05-28 10:13:44', 215, 'lv', '2026-05-28T00:00:00', 0, NULL, 'Par apropriācijas pārdali no budžeta resora "74. Gadskārtējā valsts budžeta izpildes procesā pārdalāmais finansējums" programmas 24.00.00 "Valsts aizsardzības un drošības fonds"', NULL, NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44333, 'Par nekustamā īpašuma atsavināšanu Nacionālo bruņoto spēku Aviācijas bāzes paplašināšanai

Ministru kabineta rīkojumi: Šajā laidienā 18 Pēdējās nedēļas laikā 24 Visi
Ministru kabineta rīkojums Nr. 301
Rīgā 2026. gada 26. maijā (prot. Nr. 29 96. §)
Par nekustamā īpašuma atsavināšanu Nacionālo bruņoto spēku Aviācijas bāzes paplašināšanai
1. Saskaņā ar Sabiedrības vajadzībām nepieciešamā nekustamā īpašuma atsavināšanas likuma 9. panta pirmo daļu atļaut Aizsardzības ministrijai pirkt nekustamo īpašumu "Klintis" (nekustamā īpašuma kadastra Nr. 7484 003 0054) – zemes vienību (zemes vienības kadastra apzīmējums 7484 003 0054) 0,21 ha platībā un zemes vienību (zemes vienības kadastra apzīmējums 7484 003 0055) 1,59 ha platībā – Rembates pagastā, Ogres novadā, kas nepieciešams Nacionālo bruņoto spēku Aviācijas bāzes paplašināšanai.
2. Aizsardzības ministrijai:
2.1. normatīvajos aktos noteiktajā kārtībā īpašuma tiesības uz šā rīkojuma 1. punktā minēto nekustamo īpašumu nostiprināt zemesgrāmatā uz valsts vārda Aizsardzības ministrijas personā;
2.2. izdevumus, kas saistīti ar šā rīkojuma 1. punktā minētā nekustamā īpašuma pirkšanu un nostiprināšanu zemesgrāmatā, segt no Aizsardzības ministrijas budžeta programmā 33.00.00 "Aizsardzības īpašumu pārvaldīšana" 2026. gadā paredzētajiem līdzekļiem.
