INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44393, 'Vācija un Nīderlande izveidos NATO komandcentru Baltijas valstīs
Berlīne, 28. maijs, LETA--AFP. Vācija un Nīderlande šogad Baltijas valstīs izveidos kopīgu taktisko štābu, lai komandētu spēkus NATO austrumu flangā un palīdzētu atturēt Krieviju, ceturtdien paziņoja Berlīne.
Vācijas un Nīderlandes kopīgais komandcentrs, kas pazīstams kā 1GNC, tuvākajos mēnešos "uzņemsies komandējošo lomu NATO austrumu flangā, īpaši Igaunijas un Latvijas reģionā", teikts Vācijas Aizsardzības ministrijas paziņojumā.
"Papildu taktiskā štāba izvietošana reģionā stiprina NATO vienotību un atbalsta Krievijas atturēšanu," norādīja ministrija.
1GNC ir komandcentrs, kas vajadzības gadījumā var kontrolēt līdz pat 50 000 karavīru.
Tā uzdevumos ietilpst militāro mācību plānošana un vadīšana, plānošana iespējamiem konfliktiem un spēku vadīšana kara izcelšanās gadījumā.
Savukārt Latvijas Aizsardzības ministrija aģentūru LETA informēja, ka NATO plāno oficiāli apstiprināt Vācijas un Nīderlandes korpusa jauno lomu jau šovasar. Līdz šim šīs funkcijas pildīja Ziemeļaustrumu daudznacionālais korpuss.
Izmaiņas ir daļa no NATO komandvadības reformas, kas tika ieviesta pēc 2023. gada Viļņas samita ar mērķi nodrošināt ātrāku un efektīvāku sabiedroto spēku mobilizāciju. Atsaucoties NATO aicinājumam, Vācija un Nīderlande piedāvāja savu kopīgo korpusu kā taktisko štābu Baltijas reģiona aizsardzības plāniem.
"Īsā laikā Vācijas un Nīderlandes korpuss ir izveidojis ciešu un profesionālu sadarbību ar Nacionālajiem bruņotajiem spēkiem, apliecinot spēju efektīvi koordinēt kopīgus uzdevumus reģiona drošības stiprināšanai," uzsver Latvijas Aizsardzības ministrija.
Vienības - Vācijas un Nīderlandes korpusa - štābs atrodas Minsterē, Vācijā, un no turienes tā vajadzības gadījumā tiek nosūtīta uz NATO misijām.
Jaunais komandštābs ir paredzēts, lai nodrošinātu NATO lielāku kapacitāti un spēju ātrāk reaģēt.
"Izveidojot otru korpusa štābu reģionā, Vācija kopā ar Nīderlandi demonstrē savu vēlmi un spēju uzņemties atbildību par NATO austrumu flanga atturēšanu un aizsardzību," norādīja ministrija.
Nīderlande un Vācija rotācijas kārtībā vada 1GNC, kas tika izveidota 1995. gadā. Vācija vada vienību līdz 2028. gada sākumam.
Papildus Nīderlandei un Vācijai štāba personālu pašlaik nodrošina vēl 14 NATO valstis.
Aģentūra "Reuters" šonedēļ vēstīja, ka NATO stiprinās sava austrumu flanga aizsardzību un nodrošinās, lai alianses spēki kara gadījumā ar Krieviju tiktu ātri pārsviesti uz Latviju un Igauniju.
Šobrīd NATO kontingenti Baltijas valstīs un Polijā pakļauti vienam komandpunktam, kas atrodas Ščecinā, bet plānotas komandstruktūras izmaiņas atbilstoši Baltijas valstu stratēģiskajai nozīmei.
Vēl viena korpusa izveide ļaus risināt problēmas, ko rada šī reģiona ierobežotais stratēģiskais dziļums un apdraudētība, norādījusi kāda militārpersona.
Korpusa sastāvā pilnā komplektācijā ir no 40 000 līdz 60 000 vīru, taču miera laikā tas sastāv no komandstruktūras un īpašajiem tehniskajiem dienestiem, lai ko kara gadījumā var ātri izvērst.
- Publicēta: 28.05.2026 13:53
