INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44401, 'Kas sagaida skolotājus, skolu direktorus un Izglītības un zinātnes ministrijas ierēdņus līdz ar jaunās izglītības un zinātnes ministres stāšanos amatā– nra.lv saruna ar izglītības un zinātnes ministri Ilzi Indriksoni (NA).
Vai ministrijas ierēdņiem atkal jāsāk baidīties tikt atlaistiem no darba; kā apbalvot pedagogus par izcilu darbu - ar prēmijām algu celšanu vai labu vārdu un atzinības paušanu; kā tiks veidotas attiecības ar Latvijas izglītības un zinātnes darbinieku arodbiedrību; kā apturēt skolu slēgšanu reģionos; kā skolniekiem nokļūt skolās no Dundagas, Kolkas vai Pitraga; vai bērniem pamatskolās atkal jāsāk dzīvot internātos; kādas izmaiņas gaidāmas izglītības saturā; kā Nacionālie bruņotie spēki varētu ciešāk sadarboties ar skolām militāro prasmju mācīšanā; kad aizliegsim skolās izmantot mobilās lietotnes; vai skolniekiem ir cerības atgūt tiesības labot pārbaudes darbus; vai norādīt uz kļūdām un neļaut tās labot ir laba prakse - par šiem un citiem ar izglītību saistītiem jautājumiem saruna ar izglītības un zinātnes ministri Ilzi Indriksoni.

