INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44423, 'Saeimas partijas paraksta Kulberga valdības deklarāciju
Jauno valdību veidojošās koalīcijas partijas trešdien parakstījušas sadarbības līgumu un Andra Kulberga (AS) vadītā Ministru kabineta deklarāciju, tā iezīmējot jaunās ...
Topošā kultūras ministra Puntuļa labā roka būs Rīgas domes deputāts Jansons
Topošā kultūras ministra Naura Puntuļa (NA) biroja vadītājs būs Rīgas domes deputāts Ritvars Jansons, apstiprināja topošais ministrs.
Kā liecina informācija LETA arhīvā, Saeima 2019. gadā ārkārtas sēdē par kultūras ministru apstiprināja Nauri Puntuli, jo šīs amats bija atbrīvojies pēc toreizējās ministres Daces Melbārdes (NA) ievēlēšanas par Eiropas Paralmenta deputātu. Savukārt 2020. gadā par Kultūras ministrijas parlamentāro sekretāru kļuva Ritvars Jansons (NA).
Arī pēc 14. Saeimas vēlēšanām Puntulis saglabāja kultūras ministra amatu un darbu KM parlamentārā sekretāra amatā turpināja Jansons (NA).
2009. gadā Jansons ieguvis vēstures doktora zinātnisko grādu Latvijas vēsturē Latvijas Universitātes Vēstures un filozofijas fakultātes doktora studiju programmā. 2003. gadā iegūts sociālo zinātņu maģistra grāds politikas zinātnē Latvijas Universitātes Sociālo zinātņu fakultātes politikas zinātnes maģistratūrā.
Saeimā šodien plānota Ministru prezidenta amata kandidāta Andra Kulberga (AS) izveidotās valdības apstiprināšana, liecina parlamenta darba kārtība.
Valsts prezidents pēc Evikas Siliņas (JV) valdības krišanas jaunas valdības veidošanu uzticējis AS politiķim Kulbergam, partiju sarunām atvēlot ierobežotu laiku. Jauno valdību apņēmušies veidot "Apvienotais saraksts" (AS), Nacionālā apvienība (NA), Zaļo un zemnieku savienība (ZZS) un "Jaunā vienotība" (JV).
No Kulberga pārstāvētā AS finanšu ministrs būs Māris Kučinskis, tieslietu ministra amatam izvirzīts Edvards Smiltēns, savukārt Viedās administrācijas un reģionālās attīstības ministriju varētu vadīt Edgars Tavars, liecina neoficiālā informācija.
Iepriekš parakstīta potenciālās jaunās valdības pamata vienošanās, kas kalpo kā pamats turpmākajām sarunām par darbiem.
No "Jaunās vienotības" (JV) jaunajā valdībā amatus saglabās ārlietu ministre Baiba Braže un veselības ministrs Hosams Abu Meri, uz aizsardzības ministra amatu tiek virzīts pulkvedis Raivis Melnis, bet par satiksmes ministru tiek virzīts līdzšinējais iekšlietu ministrs Rihards Kozlovskis.
Plānots, ka AS politiķi Kulberga valdībā vadītu Finanšu, Tieslietu un Viedās administrācijas un reģionālās attīstības ministrijas, kuras pašlaik vada redzami JV politiķi.
Nacionālā apvienība (NA) vadīs Izglītības un zinātnes, Kultūras, Iekšlietu un Klimata un enerģētikas ministrijas. NA valde kā jaunās valdības ministru amata kandidātus virza Saeimas deputātus Ilzi Indriksoni, Jāni Dombravu, Puntuli un Jāni Vitenbergu. Indriksone virzīta izglītības un zinātnes ministra amatam, Dombravas pārraudzībā būs Iekšlietu ministrija, Puntuļa - Kultūras ministrija, bet klimata un enerģētikas ministra amata kandidāts ir Vitenbergs.
Plānots, ka no Zaļo un zemnieku savienības (ZZS) jaunajā valdībā amatus saglabās ekonomikas ministrs Viktors Valainis un labklājības ministrs Reinis Uzulnieks, bet zemkopības ministra amatu ieņems bijušais labklājības ministrs, Saeimas deputāts Uldis Augulis.
Tāpat amatu saglabās esošā Saeimas priekšsēdētāja Daiga Mieriņa (ZZS).', 'b512072a4c284ede92b95c700402fa002569214e66520abadd5580d6e67cf555', 6121941660182553528, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711572-toposa-kulturas-ministra-puntula-laba-roka-bus-rigas-domes-deputats-jansons', NULL, '2026-05-28 20:41:55', 414, 'lv', '2026-05-28T13:45:43.000000Z', 0, NULL, 'Topošā kultūras ministra Puntuļa labā roka būs Rīgas domes deputāts Jansons', '2026-05-29 19:15:57', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44425, 'Kulberga valdībai priekšā drošības un ekonomikas eksāmens
Jaunajai valdībai jākoncentrējas uz drošības stiprināšanu, ekonomisko attīstību, kā arī skaidra ārpolitiskā kursa saglabāšanu.
Deputāte Zanda Kalniņa-Lukaševica (JV) pirms parlamentāriešu balsojuma par uzticības izteikšanu Andra Kulberga (AS) valdībai uzsvēra nepieciešamību stiprināt drošību, ievērot budžeta disciplīnu un saglabāt skaidru ārpolitisko kursu.
Deputāte akcentēja Eiropas Savienības nozīmi un nepieciešamību politiku balstīt cilvēkcentrētā pieejā, vienlaikus turpinot atbalstu Ukrainai un iestājoties par stingru Eiropas drošības politiku. Tāpat viņa norādīja uz nepieciešamību nodrošināt stabilitāti un uzticēšanos valsts pārvaldē.
Kalniņa-Lukaševica uzsvēra, ka aizsardzības nozarei jānovirza 5% no iekšzemes kopprodukta, šo apņemšanos nostiprinot arī normatīvajā regulējumā. Vienlaikus viņa pievērsās likuma varas stiprināšanai un nepieciešamībai nodrošināt atbildīgu politisko rīcību.
Deputāte arī akcentēja, ka valsts attīstībai būtiska ir skaidra rīcība un spēja īstenot iecerēto, uzsverot politiskās atbildības nozīmi sabiedrības priekšā. Viņa akcentēja, ka "Jaunā vienotība" ir gatava strādāt valdībā, lai katru dienu ar saviem darbiem stiprinātu valsti.
Savukārt topošā izglītības un zinātnes ministre Ilze Indriksone (NA) sacīja, ka Nacionālā apvienība (NA) jaunajā valdībā strādās, lai Latvija saglabātos kā nacionāla valsts, vienlaikus stiprinot ekonomiku, drošību un ieviešot skaidru imigrācijas politiku.
Viņa uzsvēra, ka NA valdības veidošanā iesaistījusies ar augstu atbildību, akcentējot nepieciešamību reālistiski vērtēt drošības situāciju un plānot rīcību ilgtermiņā. Politiķe norādīja, ka nacionālās intereses aptver ne tikai valodu un kultūru, bet arī ekonomiku un budžeta ilgtspēju.
Indriksone kritizēja līdzšinējo, viņasprāt, uz patēriņu balstīto izaugsmes pieeju, aicinot veicināt attīstību bez masveida imigrācijas no trešajām valstīm, lielāku uzsvaru liekot uz tehnoloģijām, investīcijām un vietējā darbaspēka iesaisti.
Viņa arī uzsvēra nepieciešamību stiprināt sadarbību ar uzņēmējiem, paātrināt attīstības plānošanu un pievērst lielāku uzmanību demogrāfijai, vienlaikus saglabājot latviešu valodas lomu un starptautisko sadarbību.
Drošības jomā politiķe atzīmēja 5% no iekšzemes kopprodukta finansējumu aizsardzībai un nepieciešamību nodrošināt lielāku budžeta caurspīdīgumu, kā arī iestājās par stingrāku imigrācijas kontroli un skaidri definētiem uzturēšanās nosacījumiem.
Jaunas valdības izveide īsā laikā apliecina politisko spēku spēju vienoties un koncentrēties uz valsts interesēm, Saeimas sēdē, kurā tiek lemts par Kulberga vadītās valdības apstiprināšanu, sprieda Saeimas priekšsēdētāja Daiga Mieriņa (ZZS).
Pēc Ministru prezidentes Evikas Siliņas (JV) demisijas Valsts prezidents Edgars Rinkēvičs uzticēja jaunu Ministru kabinetu veidot Kulbergam, kura pārstāvētā frakcija līdz šim strādāja parlamenta opozīcijā.
Kulberga vadībā tika panākta vienošanās valdībā sadarboties četriem politiskajiem spēkiem - "Apvienotajam sarakstam" (AS), Nacionālajai apvienībai, "Jaunajai vienotībai" (JV) un Zaļo un zemnieku savienībai.', '67ca6fba461ce7235c2b867dd065848a26f5a90648ec7736112efdf668dd0471', 2674013081575840, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711545-kulberga-valdibai-prieksa-drosibas-un-ekonomikas-eksamens', NULL, '2026-05-28 20:41:56', 374, 'lv', '2026-05-28T11:55:34.000000Z', 0, NULL, 'Kulberga valdībai priekšā drošības un ekonomikas eksāmens', '2026-05-29 19:12:50', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44426, '“Neko nedarīt nav izeja” - Kulbergs Saeimā sola ātru un atbildīgu valdību
"Apvienotā saraksta" (AS) politiķa Andra Kulberga durvis labām idejām vienmēr būšot atvērtas ikvienam Saeimas deputātam, viņš uzsvēra šodienas Saeimas ārkārtas sēdē, kurā lemj par viņa apstiprināšanu Ministru prezidenta amatā.
Viņš atzina, ka pirms četriem gadiem viņam nav bijis nojausmas, ka varētu kļūt par Saeimas deputātu, bet pirms divām nedēļām - ka varētu kļūt par premjeru. Kulbergs pateicās Valsts prezidentam Edgaram Rinkēvičam par izvirzīšanu premjera amatam un kolēģiem par uzticību.
Kulbergs izcēla, ka divu nedēļu laikā valstī ir atrisināta politiskā krīze. Viņš esot lepns, ka politiķi spējuši vienoties un rast kopīgo arī jūtīgos jautājumos. Viņš arī piebilda, ka šīs valdības veidošanas process Latvijas apstākļiem ir bijis neraksturīgi ātrs - 10 dienu laikā izveidota strādātspējīga valdība.
Ātrumu prasot arī sabiedrība. "Gumijas vilkšana tagad neder," teica Kulbergs, uzsverot, ka Latvijai vajadzīga efektīva un profesionāla valdība, kas ir reāli darīt griboša un spējīga.
Kulbergs uzsvēra, ka valdības pienākums ir rūpēties par Latvijas drošību - ārējo, ekonomisko, enerģētisko - un arī par cilvēku drošību savā valstī. Premjera amata kandidāts gribot, lai viņa vadīto valdību atceras ar vārdiem "ātrums un atbildība".
Tāpat Kulbergs uzsvēra, ka valsts ekonomika iet roku rokā ar drošību. "Bez drošības nebūs ekonomikas, un bez ekonomikas nebūs drošības," teica viņš. Ukraina tam esot labs piemērs - valsts kara apstākļos ir spējīga ražot, inovēt un eksportēt. "Vērts pamācīties," teica Kulbergs.
Politiķis arī uzsvēra, ka valsts vairs nevar dzīvot uz parāda. Tā neesot laba finanšu pārvaldība. Šādi turpinot, pēc Kulberga teiktā, ir divi varianti - vai nu celt nodokļus, vai pelnīt vairāk. "Neko nedarīt nav izeja no situācijas," atzina Kulbergs.
Viņš uzsvēra, ka "sūri nopelnītā nauda" ir jāizmanto gudri un izšķērdībai jāpieliek punkts. Kā piemērus izšķērdībai viņš minēja nepamatotas naudas balvas, liekus komandējumus un iepirkumus.
Kulbergs apgalvoja, ka nebaidās uzņemties atbildību. Viņš esot gatavs pievērst lielu uzmanību no savas puses jautājumiem, kas saistīti ar "airBaltic", "Rail Baltica" un vēlēšanu norisi.
Tāpat viņš izcēla, ka jāizbeidz lēmumu nepieņemšanas mode. Būšot jāpieņem smagi lēmumi, kas godīgi jāskaidro arī sabiedrībai.
Kulbergs solīja, ka no viņa varēs dzirdēt atvērtu valodu un netiks doti dekoratīvi solījumi. Viņš atzina, ka viņam nebūs risinājumu visām esošajām un nākotnes problēmām, nebūs atbilžu uz visiem jautājumiem, valdība nevarēs izvērtēt pilnīgi visas prioritātes. Tāpat būšot arī kļūdas, ko pieļaus arī Kulbergs. "Bet tās ir jāatzīst, jālabo un jāmācās no tām," uzsvēra politiķis.
Tas, ka šī valdība strādās priekšvēlēšanu laikā, nebūs viegli, atzina Kulbergs, tomēr tā būšot laba mēraukla, ar kuru tauta ļoti labi pateiks, vai valdība dara labu vai sliktu darbu.
Kubergs politiķu kašķus aicināja atstāt priekšvēlēšanu debatēm, jo tie nepalīdzēs sasniegt galveno.
Viņš atzina, ka, ienākot politikā, viņam bijis grūti sadzīvot ar dalījumu pozīcija un opozīcija. "Apsolu, ka labām idejām un risinājumiem manas durvis vienmēr būs atvērtas visiem Saeimas deputātiem," teica Kulbergs.
Politiķis neaicināšot citus būt iecietīgiem pret viņu vai kādu īpašu saudzības režīmu, jo asa kritika valdību turot modru.
Kulbergs pauda, ka Latvijas tauta ir pierādījusi, ka ar smagu darbu var panākt galvu reibinošus panākumus dažādās nozarēs. Viņš jautāja, kādēļ Latvija nevarētu būt pirmajā vietā arī politikā. "Domāju, ka mēs varam," uzsvēra premjera amata kandidāts.
Viņš pauda pārliecību, ka Latvija var kļūt par labāko vietu pasaulē bērniem, un, ja tā notiktu, tā kļūtu par labāko vietu pasaulē arī citiem iedzīvotājiem. Pēc Kulberga domām, Latvijā varētu būt arī ātrākā valsts pārvalde Eiropā. "Mēs to varam, ja gribam," sacīja Kulbergs.
Jau vēstīts, ka Valsts prezidents pēc Siliņas valdības krišanas jaunas valdības veidošanu uzticējis Kulbergam.
Kulberga pārstāvētais AS finanšu ministra amatam virza Māri Kučinski, tieslietu ministra amatam izvirzīts Edvards Smiltēns, savukārt Viedās administrācijas un reģionālās attīstības ministriju gatavs vadīt Edgars Tavars.
No "Jaunās vienotības" jaunajā valdībā amatus saglabās ārlietu ministre Baiba Braže un veselības ministrs Hosams Abu Meri, uz aizsardzības ministra amatu tiks virzīts Nacionālo bruņoto spēku pulkvedis Raivis Melnis, bet par satiksmes ministru - līdzšinējais iekšlietu ministrs Rihards Kozlovskis.
Nacionālā apvienība (NA) vadīs Izglītības un zinātnes, Kultūras, Iekšlietu un Klimata un enerģētikas ministrijas. NA valde kā jaunās valdības ministru amata kandidātus attiecīgi virza Saeimas deputātus Ilzi Indriksoni, Nauri Puntuli, Jāni Dombravu un Jāni Vitenbergu.
No Zaļo un zemnieku savienības (ZZS) jaunajā valdībā amatus saglabās ekonomikas ministrs Viktors Valainis un Reinis Uzulnieks, bet zemkopības ministra amatu ieņems bijušais labklājības ministrs, Saeimas deputāts Uldis Augulis.
Tāpat no ZZS amatu saglabās Saeimas priekšsēdētāja Daiga Mieriņa.
Valsts kanceleja skaidrojusi, ka Siliņas valdības pilnvaras beigsies tajā brīdī, kad Saeima apstiprinās jauno Ministru kabinetu.', '3abf73e20e0baad227b42eb195cb22d51c344b76ed1249e4d5f7cbe1f52a91a3', 1508566379578049448, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711534-neko-nedarit-nav-izeja-kulbergs-saeima-sola-atru-un-atbildigu-valdibu', NULL, '2026-05-29 18:13:05', 725, 'lv', '2026-05-28T11:25:09.000000Z', 0, NULL, '“Neko nedarīt nav izeja” - Kulbergs Saeimā sola ātru un atbildīgu valdību', '2026-05-29 18:28:23', NULL, NULL, NULL);
