INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44472, 'Ja atskaita tos, kas darbojas enerģētikā, tad uz šo cilvēku pleciem gulstas Zemes klimats nākamajā tūkstošgadē. Vai miljongadē?', 'a0bafaf202bf7b62b87240c0e0596366c75793ab431e34273b01f1651dfad254', -8607361758006667370, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2059981896923107652', NULL, '2026-05-28 20:48:38', 18, 'lv', '2026-05-28T12:55:31+00:00', 0, NULL, NULL, '2026-05-29 19:15:58', 0, 0, 7);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44473, 'Kāpēc ir jārunā pirms balsojuma tā, it kā jau būtu nobalsots?', 'a28583a7f71973735c51cdb7c7a35a7f9294bffbf3d3175a7a969f17c517679d', 7259858124990137064, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2059947443337281924', NULL, '2026-05-28 20:48:38', 11, 'lv', '2026-05-28T10:38:37+00:00', 0, NULL, NULL, '2026-05-29 19:15:58', 3, 0, 7);
