INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44512, 'Būtu gribējies MK apstiprināšanas brīdī kaut drusku konkrētības, ko tad tā darīs šī brīža izaicinājumos:
1) kas un kad būs labāk ar pretdronu aizsardzību?
2) ko valdība darīs ar AirBaltic?
