INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44917, 'Kulbergs gatavojas rīkot valdības izbraukuma sēdi Latgalē — Jaunais Ministru prezidents Andris Kulbergs (AS) vēlas drīzumā sarīkot valdības izbraukuma sēdi Latgalē, kur pēdējā laikā piedzīvoti vairāki dronu incidenti.', '3744da51ba884a761547251708537ab5d1d9e20912097768c6d4a8e03a5b7f5e', 5511670786729142840, 13, 'web', 0, NULL, 'www.diena.lv', 'https://www.diena.lv/raksts/latvija/politika/kulbergs-gatavojas-rikot-valdibas-izbraukuma-sedi-latgale-14352497?utm_source=rss&utm_campaign=rss&utm_medium=links', NULL, '2026-05-29 18:09:37', 28, 'lv', '2026-05-28T21:51:00', 0, NULL, 'Kulbergs gatavojas rīkot valdības izbraukuma sēdi Latgalē', '2026-05-29 18:28:23', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44921, 'Jaunā iekšlietu ministra prioritātes – ierobežot imigrāciju, stiprināt iekšlietu dienestus un pilnveidot civilo aizsardzību — Jaunveidotās valdības iekšlietu ministrs Jānis Dombrava (Nacionālā apvienība) apņēmies likt uzsvaru uz imigrācijas ierobežošanu, iekšlietu dienestu stiprināšanu un civilās aizsardzības pilnveidošanu. Viņš arī uzskata, ka iekšlietu un aizsardzības dienesti var vairāk sadarboties, to Dombrava ceturtdien pauda intervijā Latvijas Televīzijas raidījumā "Šodienas jautājums".', '974a739ea0d3274f3e01a188a7f69af5fe1d99ab855fdc5f705806469bfbb2d8', 1668800410589737766, 11, 'web', 0, NULL, 'www.lsm.lv', 'https://www.lsm.lv/raksts/zinas/latvija/28.05.2026-jauna-iekslietu-ministra-prioritates-ierobezot-imigraciju-stiprinat-iekslietu-dienestus-un-pilnveidot-civilo-aizsardzibu.a649222/?utm_source=rss&utm_campaign=rss&utm_medium=links', NULL, '2026-05-29 18:09:39', 57, 'lv', '2026-05-28T19:42:00', 0, NULL, 'Jaunā iekšlietu ministra prioritātes – ierobežot imigrāciju, stiprināt iekšlietu dienestus un pilnveidot civilo aizsardzību', '2026-05-29 18:27:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44937, 'Saeimas deputāts (pie frakcijām nepiederošs), Latvijas armijas rezerves pulkvedis Igors Rajevs TV24 raidījumā “Kārtības rullis” daļēji atklāja iemeslus, kādēļ atstājis darbu Iekšlietu ministrijā, kur savulaik pildīja parlamentārā sekretāra amata pienākumus.
I. Rajevs uzskata, ka mēs vēl joprojām dzīvojam pirms 2022. gada mentalitātē, un viens no iemesliem, kāpēc viņš atstājis darbu Iekšlietu ministrijā, bijis tas, ka mēs nepieļaujami lēni ieviešam nepieciešamās izmaiņas, kuras vajag izdarīt.
Tam, viņaprāt, traucē sistēma. Tā pati šūnu apraide, tai bija jābūt uzliktai uz papīra, saprogrammētai un ieviestai dzīvē gadus pirms tam, kad mēs to izdarījām, ir pārliecināts I. Rajevs. Savukārt krīzes vadības centram bija jābūt izveidotam un ieviestam divus gadus pirms tā, kad mēs to izdarījām, piebilda I. Rajevs.
Lai gan sistēma ir cilvēki, I. Rajevs uzskata, ka sistēmu var mainīt tikai no augšas. Vaicāts, ka viņš taču ir augšā, kāpēc nav izmainījis, I. Rajevs atbildēja, “ka nevajag pārspīlēt parlamentārā sekretāra pilnvaras”. Savukārt kā Saeimas deputāts viņš var teikt, ka likumdošanas iniciatīvas prasa ilgāku laiku.
“Mums ir jāsaprot, ka mēs šobrīd esam kritiskā situācijā. Mūsu darbībām ir jābūt būtiski ātrākām un būtiski straujākām, mums ir jāvirzās uz priekšu, jāpieņem lēmumi un, pats galvenais, jāievieš lēmumi dzīvē līdz tam brīdim, kad sistēma darbotos tā, kā mēs gribētu,” sacīja I. Rajevs.', 'd15a5455717235d3b3c171933261d5aef6365468455fda8c81b738d7aacb6706', -7759333593048381938, 7, 'web', 0, NULL, 'nra.lv', 'https://nra.lv/latvija/522255-igors-rajevs-atklaj-iemeslus-aiziesanai-no-darba-iekslietu-ministrija.htm', NULL, '2026-05-29 18:11:32', 203, 'lv', '2026-05-29T08:45:00+03:00', 0, NULL, 'Igors Rajevs atklāj iemeslus aiziešanai no darba Iekšlietu ministrijā', '2026-05-29 18:33:49', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44941, 'Jaunais iekšlietu ministrs Jānis Dombrava (NA) ir izraudzījies sava biroja vadību un vairākus padomniekus, aģentūru LETA informēja Iekšlietu ministrijā (IeM).
IeM parlamentārā sekretāra amata pienākumus pildīs Saeimas deputāts Edvīns Šnore (NA).
Ministra biroju vadīs līdzšinējais Nacionālās apvienības (NA) jauniešu organizācijas vadītājs Edgars Kristaps Rupeika. Viņš bijis vairāku deputātu palīgs 14. Saeimā un NA Saeimas frakcijas administrators. Tāpat viņš bija Dombravas vadītās Saeimas parlamentārās izmeklēšanas komisijas tehniskais sekretārs.
Par iepirkumu uzraudzības jautājumiem konsultēs Jānis Ratkevičs, kuram esot pieredze publisko iepirkumu jomā pašvaldībās.
Par sadarbību ar pašvaldībām atbildēs padomnieks un Nacionālo bruņoto spēku (NBS) rezerves pulkvežleitnats Vilmārs Vecvagaris (NA), kurš ir Liepājas domes Drošības komisijas vadītājs un civilās aizsardzības eksperts Liepājas pašvaldībā.
Savukārt civilās aizsardzības jautājumos ministra ārštata padomnieka pienākumus pildīs Rīgas domes Drošības, kārtības un korupcijas novēršanas komitejas vadītājs Ģirts Lapiņš (NA).
Par sadarbību ar NBS civilās aizsardzības jomā atbildēs ārštata padomnieks Roberts Sipenieks.
Par Eiropas Komisijas jautājumiem un valsts nacionālo pozīciju ministru ārštatā konsultēs Eiropas Parlamenta deputāts Rihards Kols (NA).', '96361f252b6d2e319f02b2bef7532a9bab96b20b44af7793fbabc0b4990c6c2a', 5157754154730033872, 7, 'web', 0, NULL, 'nra.lv', 'https://nra.lv/politika/522299-kas-stradas-jana-dombravas-komanda.htm', NULL, '2026-05-29 18:11:33', 160, 'lv', '2026-05-29T17:46:00+03:00', 0, NULL, 'Ministrs Dombrava izvēlas komandu', '2026-05-29 18:27:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44943, 'Izglītības un zinātnes ministres Ilzes Indriksones (NA) biroju vadīs līdzšinējais Vispārējās izglītības departamenta vadītājs Rūdolfs Kalvāns, liecina informācija Izglītības un zinātnes ministrijas (IZM) tīmekļvietnē.
Par pārējo ministres biroja sastāvu IZM vēl nav sniegusi informāciju.
Jau rakstīts, ka Saeima ceturtdien apstiprināja jauno valdību, kuru vada Ministru prezidents Andris Kulbergs (AS).
Par Kulberga valdību nobalsoja 66 deputāti, pret balsoja 25 deputāti.
Jauno valdību veido "Apvienotais saraksts" (AS), Nacionālā apvienība (NA), "Jaunā vienotība" (JV) un Zaļo un zemnieku savienība (ZZS).
Savukārt IZM parlamentārā sekretāre būs Ieva Siliņa. IZM norāda, ka Siliņa ir bijusi Valsts prezidenta ārštata padomniece zinātnes un izglītības politikas jautājumos, ekonomikas ministres padomniece digitalizācijas jautājumos, kā arī Rīgas domes deputāte, Rīgas domes Izglītības, kultūras un sporta komitejas priekšsēdētāja vietniece. Tāpat viņa piecus gadus ir vadījusi Latvijas Jauno zinātnieku apvienību. Siliņa ir doktora grāda kandidāte vadībzinātnē Latvijas Universitātē.', 'ee7de43226772f2305bac71331543f05d6c5c85dc2fec3d59e926fddd0a271ea', 6319538960013655032, 7, 'web', 0, NULL, 'nra.lv', 'https://nra.lv/latvija/izglitiba-karjera/522281-rudolfs-kalvans-klust-par-indriksones-biroja-vaditaju.htm', NULL, '2026-05-29 18:11:34', 136, 'lv', '2026-05-29T14:15:00+03:00', 0, NULL, 'Izglītības un zinātnes ministrei jauns biroja vadītājs [papildināts]', '2026-05-29 18:28:23', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44948, 'FOTO. Jaunais premjers sirsnīgi pasakās pieciem īpašiem cilvēkiem: Ja viņi man nebūtu palīdzējuši, es nevarētu uzņemties šo godu 0
28.05. valdības apstiprināšana
“Mans tēvs man vienmēr teica – nav neiespējamu lietu, ja tu no sirds to vēlies un dari. Tieši tāpēc tēva grāmata šo domu īpaši uzsver, un viņš pats ir pierādījums tam, ka neiespējamais var kļūt iespējams. Tas ir iespējams tad, ja mēs visi kopā gribam sasniegt mērķi un strādājam vienoti,” tā savā 28. maija valdības apstiprināšanas runā sacīja jaunais Ministru prezidents Andris Kulbergs (AS).
Runas noslēgum viņš atklāja, ka vēlas pateikt vislielāko paldies savai ģimenei – sievai Annai, mūsu trim bērniem un mammai. “Bez viņu atbalsta es šodien šeit nestāvētu un nevarētu uzņemties šo lielo godu un atbildību – kļūt par Latvijas Ministru prezidentu. Paldies jums visiem!”
Kulbergs: Mums atvēlēts īss laika posms, kas būs darba pilns
Jaunajai valdībai atvēlēts īss laika posms, taču tas būs darba pilns, savā pirmajā preses konferencē žurnālistiem teica nupat amatā apstiprinātais Ministru prezidents Andris Kulbergs (AS).
Premjers uzsvēra, ka jaunajai valdībai būs jāstrādā bez ierastā ieskriešanās perioda, koncentrējoties uz tūlītēju rezultātu sasniegšanu un intensīvu darba tempu.
Kulbergs norādīja, ka valdības darbs sāksies nekavējoties ar konkrētiem uzdevumiem un saspringtu grafiku, tostarp starptautiskām tikšanām un valdības sēdēm jau tuvākajā laikā. Viņš akcentēja, ka galvenais uzsvars tiks likts uz praktisku darbu, nevis diskusijām, paredzot skaidrus termiņus un izmērāmus rezultātus.
Topošais valdības vadītājs pauda ieceri mainīt līdzšinējo politisko kultūru, stiprinot ētikas un atbildības standartus, kā arī ieviešot citādu pieeju valsts pārvaldē. Viņš norādīja, ka krīzes apstākļos nepieciešama koncentrēta un mērķtiecīga rīcība, kas ļautu sasniegt labākus rezultātus.
Atbildot uz jautājumiem par komandas veidošanu, Kulbergs atzina, ka tās sastāvs vēl nav pilnībā nostiprināts, uzsverot nepieciešamību ierobežotā laika periodā piesaistīt pēc iespējas spēcīgākus kandidātus. Aģentūrai LETA zināms, ka uz ceturtdienas vakarā gaidāmo sanāksmi par Kulberga biroju piedalīties aicināts arī bijušais Centrālās finanšu un līgumu aģentūras (CFLA) vadītājs Mārtiņš Brencis.
Vienlaikus Kulbergs pauda viedokli, ka lēmumu pieņemšanas procesā svarīga ir efektivitāte un pilnvērtīga diskusija, akcentējot nepieciešamību pēc formālas lēmumu apstiprināšanas valdības sēdēs, vienlaikus izvairoties no neproduktīvām debatēm.
Komentējot paredzamo koalīcijas darbu kopumā un to, ka pret viņa valdību nobalsoja arī koalīcijas deputāts Dāvis Mārtiņš Daugavietis (JV), Kulbergs uzsvēra, ka jaunajai valdībai būs stabils vairākums Saeimā, kas ļaus pieņemt lēmumus pārliecinošāk un izvairīties no situācijām, kad balsojumi tiek apdraudēti nepietiekama deputātu skaita dēļ.
Viņš norādīja, ka valdības darba intensitāte saglabāsies arī vasaras periodā, neizslēdzot nepieciešamību sasaukt ārkārtas Saeimas sēdes, lai virzītu būtiskus lēmumus.
Kulbergs uzsvēra nepieciešamību mainīt valsts finanšu pārvaldības pieeju, lielāku uzmanību pievēršot izdevumu lietderībai un ilgtermiņa atdevei.
Tāpat premjers norādīja, ka Latvijā daudzās jomās vērojama neefektīva līdzekļu izmantošana, tostarp publiskajos iepirkumos, infrastruktūras projektos un informācijas tehnoloģiju risinājumos. Politiķis kritizēja līdzšinējo praksi koncentrēties uz Eiropas Savienības fondu apguvi kā pašmērķi, nepietiekami izvērtējot šo investīciju ietekmi uz tautsaimniecību un to spēju radīt pievienoto vērtību.
Valdības vadītājs uzsvēra, ka nepieciešams pāriet uz pieeju, kur prioritāte ir Latvijas intereses un spēja ar ieguldījumiem radīt ekonomisku atdevi nākotnē. Viņš arī norādīja uz risku, ka valsts pārāk paļaujas uz ārējo finansējumu, un uzsvēra nepieciešamību stiprināt spēju pašai pelnīt un veidot ilgtspējīgu izaugsmi.
Jaunais premjers akcentēja, ka būtiskas ietaupījumu iespējas paveras publisko iepirkumu jomā, kā arī pārskatot ar augstākā līmeņa ierēdniecību saistītos izdevumus, tostarp atalgojumu un papildu bonusus. Tāpat viņš norādīja uz sezonāliem tēriņu pieaugumiem, kas, viņaprāt, bieži nav pamatoti.
Vienlaikus Kulbergs uzsvēra, ka valsts budžetā vienmēr iespējams rast ietaupījumus, ja izdevumi tiek rūpīgi salāgoti ar ienākumiem un izvērtēti pēc to efektivitātes.
Jau ziņots, ka par Kulberga valdību nobalsoja 66 deputāti, pret balsoja 25 deputāti. Pret Kulberga valdību balsoja deputāti no “Progresīvajiem”, “Stabilitātes”, un partijas “Latvija pirmajā vietā”. Tāpat pret Kulberga valdību nobalsoja “Jaunās vienotības” (JV) deputāts Daugavietis.
Par Kulberga valdību nebalsoja Jānis Patmalnieks (JV), kā arī izjukušās “Stabilitātei” Saeimas frakcijas deputāti Igors Judins un Amils Saļimovs.
Līdz ar to ir beigušās demisionējušās premjeres Evikas Siliņas (JV) valdības pilnvaras. Valsts kancelejā aģentūrai LETA skaidroja, ka tās beidzās brīdī, kad Saeima apstiprina jauno Ministru kabinetu.
Jauno valdību veido “Apvienotais saraksts” (AS), Nacionālā apvienība (NA), JV un Zaļo un zemnieku savienība (ZZS).
AS pārziņā valdībā ir Finanšu, Tieslietu un Viedās administrācijas un reģionālās attīstības ministrijas. Finanšu ministra amatā apstiprināts Māris Kučinskis, tieslietu ministra amatā – Edvards Smiltēns, bet viedās administrācijas un reģionālās attīstības ministra amatā – Edgars Tavars.
No JV valdībā amatus saglabājuši ārlietu ministre Baiba Braže un veselības ministrs Hosams Abu Meri. Par aizsardzības ministru apstiprināts Raivis Melnis, savukārt satiksmes ministra amatā iecelts līdzšinējais iekšlietu ministrs Rihards Kozlovskis.
NA vada Izglītības un zinātnes, Kultūras, Iekšlietu, kā arī Klimata un enerģētikas ministrijas. Par izglītības un zinātnes ministri kļuvusi Ilze Indriksone, iekšlietu ministrs būs Jānis Dombrava, kultūras ministrs – Nauris Puntulis, bet klimata un enerģētikas ministra amatā apstiprināts Jānis Vitenbergs.
Savukārt no ZZS valdībā amatus saglabājuši ekonomikas ministrs Viktors Valainis un labklājības ministrs Reinis Uzulnieks, bet zemkopības ministra amatā apstiprināts Uldis Augulis.
Amatu saglabājusi arī Saeimas priekšsēdētāja Daiga Mieriņa (ZZS).
Valsts prezidents Edgars Rinkēvičs Kulbergam uzticēja veidot jaunu valdību pēc tam, kad demisionēja līdzšinējā premjere Siliņa.', 'ebae22d50f482f61f75bffb1b7fa4608f064874e8ecda0de7ee412bef2118a9a', -7717618206930058440, 16, 'web', 0, NULL, 'www.la.lv', 'https://www.la.lv/foto-jaunais-premjers-sirsnigi-pasakas-pieciem-ipasiem-cilvekiem-ja-vini-man-nebutu-palidzejusi-es-nevaretu-uznemties-so-godu', NULL, '2026-05-29 18:12:28', 817, 'lv', '2026-05-29T14:09:58.000000Z', 0, NULL, 'FOTO. Jaunais premjers sirsnīgi pasakās pieciem īpašiem cilvēkiem: Ja viņi man nebūtu palīdzējuši, es nevarētu uzņemties šo godu', '2026-05-29 18:28:23', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44950, 'Vai “Nacionālā apvienība” apzināti izvēlējās Jāni Dombravu iekšlietu ministra amatam? 0
Nacionālās apvienības valdes priekšsēdētāja, Saeimas deputāte un bijusī ekonomikas ministre Ilze Indriksone TV24 raidījumā “Ziņu TOP” skaidro, ka lēmums virzīt Jāni Dombravu iekšlietu ministra amatam esot bijis apzināts solis, nevis nejauša izvēle.
Viņa norāda, ka iekšlietu ministra amats ir īpaši nozīmīgs un sarežģīts, tāpēc arī jaunajam kandidātam būs jāpaļaujas uz spēcīgu profesionāļu komandu, kas palīdzēs nodrošināt efektīvu nozares darbu.
Indriksone uzsver, ka Dombravam ir pieredze Saeimas līmenī, kur viņš strādājis ar drošības politikas un likumdošanas jautājumiem. Tāpat viņš esot bijis aktīvi iesaistīts aizsardzības nozares un imigrācijas politikas jautājumos.
Viņa piebilst, ka kandidātam ir arī personiska pieredze kā zemessargam, kas, pēc viņas teiktā, sniedz papildu izpratni par civilās aizsardzības jomu.
Politiķe arī norāda, ka skatījums no malas var būt ieguvums, jo tas palīdzot sistēmai kļūt elastīgākai un ātrāk reaģēt uz vajadzībām, salīdzinot ar gadījumiem, kad ministri nāk tikai no nozares iekšienes.
Indriksone uzsver, ka Dombrava esot pierādījis spēju strādāt pie sarežģītu jautājumu risināšanas, īpaši imigrācijas politikas jomā, kur viņa sagatavotie priekšlikumi guvuši plašu politisko atbalstu koalīcijā.', 'c6d8b290295bea464ffac6149f1f7b42e40d33a102321da23fb124f9849d89bf', 1605958920936493964, 16, 'web', 0, NULL, 'www.la.lv', 'https://www.la.lv/vai-nacionala-apvieniba-apzinati-izvelejas-jani-dombravu-iekslietu-ministra-amatam', NULL, '2026-05-29 18:12:29', 176, 'lv', '2026-05-29T15:09:29.000000Z', 0, NULL, 'Vai “Nacionālā apvienība” apzināti izvēlējās Jāni Dombravu iekšlietu ministra amatam?', '2026-05-29 18:27:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44954, 'Dombrava biroju vadīs NA jauniešu organizācijas vadītājs Rupeika
Jāņa Domravas (NA) vadītajā Iekšlietu ministrijā (IeM) parlamentārā sekretāra pienākumus pildīs Saeimas deputāts Edvīns Šnore (NA), bet par biroja vadītāju izraudzīts NA jauniešu organizācijas vadītājs Edgars Kristaps Rupeiks.
Rupeiks bijis vairāku deputātu palīgs 14. Saeimā un NA Saeimas frakcijas administrators. Tāpat viņš bija Dombravas vadītās Saeimas parlamentārās izmeklēšanas komisijas tehniskais sekretārs.
Par iepirkumu uzraudzības jautājumiem konsultēs Jānis Ratkevičs, kuram esot pieredze publisko iepirkumu jomā pašvaldībās.
Par sadarbību ar pašvaldībām atbildēs padomnieks un Nacionālo bruņoto spēku (NBS) rezerves pulkvežleitnats Vilmārs Vecvagaris (NA), kurš ir Liepājas domes Drošības komisijas vadītājs un civilās aizsardzības eksperts Liepājas pašvaldībā.
Savukārt civilās aizsardzības jautājumos ministra ārštata padomnieka pienākumus pildīs Rīgas domes Drošības, kārtības un korupcijas novēršanas komitejas vadītājs Ģirts Lapiņš (NA).
Par sadarbību ar NBS civilās aizsardzības jomā atbildēs ārštata padomnieks Roberts Sipenieks.
Par Eiropas Komisijas jautājumiem un valsts nacionālo pozīciju ministru ārštatā konsultēs Eiropas Parlamenta deputāts Rihards Kols (NA).
LETA jau ziņoja, ka Saeima ceturtdien apstiprināja jauno valdību, kuru vadīs Andris Kulbergs (AS), bet iekšlietu ministra amatu tajā ieņēms Dombrava, nomainot iepriekšējo iekšlietu ministru Rihardu Kozlovski (JV), kurš tagad kļuvis par satiksmes ministru.
Jauno valdību veido "Apvienotais saraksts", Nacionālā apvienība, "Jaunā vienotība" un Zaļo un zemnieku savienība.', '48e4a0434a1b3cbb925bae69069dd1831c3e23d0461f99ae10d282c38c28c42f', 5752229234673881936, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711764-dombrava-biroju-vadis-na-jauniesu-organizacijas-vaditajs-rupeika', NULL, '2026-05-29 18:13:02', 200, 'lv', '2026-05-29T14:12:32.000000Z', 0, NULL, 'Dombrava biroju vadīs NA jauniešu organizācijas vadītājs Rupeika', '2026-05-29 18:27:40', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44958, 'Evika Siliņa pasniedz pateicības ministriem
Ministru prezidenete Evika Siliņa pasniedz pateicības rakstus un piemiņas veltes ministriem.
FOTO: medaļas par demisiju? Siliņa pēdējā valdības sēdē ministriem dala atzinības rakstus un piemiņas veltes
Lai gan demisionējušās Evikas Siliņas ("Jaunā vienotība") valdības darbs sabiedrībā vērtēts neviennozīmīgi un tās krišana saistīta ar politisko krīzi, aizejošā Ministru prezidente savā pēdējā valdības sēdē neskopojās ar uzslavām savas valdības ministriem, izsniedzot pateicības rakstus un īpašas piemiņas zīmes.
Otrdien, 26. maijā, vadot savu pēdējo valdības sēdi, demisionējusī Ministru prezidente Evika Siliņa atzina, ka līdzšinējā valdība ir daudz kritizēta, un daudz kur "droši vien pamatoti".
Neraugoties uz to, premjere uzsvēra, ka paveiktā ir daudz, jo pieņemti daudzi un svarīgi lēmumi.
Siliņa sēdes atklātās daļas sākumā pateicās visiem ministriem, valsts sekretāriem un viņu vietniekiem, kā arī sadarbības partneriem par kopīgo darbu. Politiķe kārtējo reizi uzsvēra, ka šajā laikā pieņemti ļoti daudzi un svarīgi lēmumi. Ministriem, kuri paliks arī nākamajā valdībā, Siliņa novēlēja saglabāt savus prioritāros jautājumus augstu.
Par "sekmīgu sadarbību"
Kā liecina publiski pieejamā informācija no valdības sēdes, atvadīšanās noritēja uz izteikti pozitīvas un pat svinīgas nots. Jauns.lv novēroja, ka demisionējusī premjere ministriem pasniedza īpašus pateicības rakstus, uz kuriem lasāms, ka tie piešķirti par "sekmīgu sadarbību un pašaizliedzīgu darbu Latvijas izaugsmei". Spriežot pēc fotogrāfijām, līdz ar atzinības rakstiem tika pasniegtas arī īpašas piemiņas veltes.
Ņemot vērā sabiedrības interesi par valsts pārvaldes caurskatāmību un līdzekļu izlietojumu, Jauns.lv ir vērsies Valsts kancelejā, lai noskaidrotu, cik lieli valsts budžeta līdzekļi izlietoti šo dāvanu un atzinību izgatavošanai. Tāpat lūgts skaidrot, vai Latvijas politiskajā praksē ir ierasts, ka premjers, kurš pats atkāpies no amata politiskas krīzes dēļ, atalgo savus ministrus ar šādām atzinībām. Valsts kancelejas atbilde vēl tiek gaidīta un tiks publicēta līdzko tā tiks saņemta.
Cīņa "Jaunajā vienotībā"
Vērtējot šo žestu, bijušais Saeimas deputāts, politiķis Andrejs Panteļējevs portālam Jauns.lv norāda, ka publiska apbalvošana demisionējušas valdības gadījumā ir visai netipiska. "Tas nav tā ļoti tradicionāli. Cita lieta, ja tas būtu saistīts ar vēlēšanām, tad tas ir vairāk pieņemts. Bet, ja runā par valdību, kas atkāpusies, tad parasti tā pateikšanās notika tādā intīmākā, savstarpējā gaisotnē," viņš skaidro.
Panteļējevs vērš uzmanību uz bijušās premjeres pēdējā laika pastiprināto aktivitāti. "Viena lieta – es nesaku, ka tas ir labi vai slikti, bet pēdējā laikā Evika Siliņa bieži parādās dažādos medijos un sabiedriskajā telpā. Es domāju, ka tas nedaudz atspoguļo to nosacīto priekšvēlēšanu cīņu, kas pašlaik notiek pašā "Jaunajā vienotībā". Proti, jautājumā par to, kas būs partijas premjera kandidāts gaidāmajās vēlēšanās," analizē eksperts.
Viņa vērtējumā, politiķe ar šādu žestu mēģina sabiedrības acīs spodrināt aizejošās valdības tēlu, uzturot stāstu par it kā labi padarītu darbu. Panteļējevs prognozē, ka saistībā ar šo iekšējo politisko konkurenci sabiedrība vēl redzēs dažādas līdzīgas publiskās izpausmes.
Ministri neskopojas ar uzslavām
Pateicību par kopīgo darbu valdībā Siliņai pauda arī vairāki ministri. Veselības ministrs Hosams Abu Meri ("Jaunā vienotība") uzsvēra, ka šīs valdības laikā izdevies pieņemt ļoti daudz veselības nozarei svarīgu lēmumu un īpaši izcēla premjeres "stipro plecu".
Savukārt satiksmes ministrs Atis Švinka ("Progresīvie") pauda, ka Siliņas personīgais ieguldījums esot ļāvis navigēt un virzīt ļoti grūtus jautājumus satiksmes nozarē. Paldies par kopīgo darbu teica arī ekonomikas ministrs Viktors Valainis (ZZS), kurš atvadu sēdē politiķei pasniedza ziedus.
Portāls Jauns.lv jau vēstīja, ka 14. maijā Evika Siliņa paziņoja par atkāpšanos no amata. Siliņa paziņojumā medijiem uzsvēra, ka tagad un vienmēr viņai svarīgākais ir bijis iedzīvotāju labklājība un drošība. Tā vienmēr esot bijusi atbildība pret katru Latvijas iedzīvotāju. "Šobrīd Latvijas iedzīvotājiem vairāk nekā jebkad ir vajadzīga drošības sajūta nevis partiju ķīviņi, nevis amatu dalīšanas vai partiju pozicionēšanās," teica Siliņa.', 'fc8ed5aad5d057de27d85dcb1a85eb1cd0533ad917ae7652dd9d5a1a7d9cadae', 6555290552409529128, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711481-foto-medalas-par-demisiju-silina-pedeja-valdibas-sede-ministriem-dala-atzinibas-rakstus-un-pieminas-veltes', NULL, '2026-05-29 18:13:03', 578, 'lv', '2026-05-29T03:03:03.000000Z', 0, NULL, 'FOTO: medaļas par demisiju? Siliņa pēdējā valdības sēdē ministriem dala atzinības rakstus un piemiņas veltes', '2026-05-29 18:30:26', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44959, 'Kulbergs: mums atvēlēts īss laika posms, kas būs darba pilns
Jaunajai valdībai atvēlēts īss laika posms, taču tas būs darba pilns, savā pirmajā preses konferencē žurnālistiem teica nupat amatā apstiprinātais Ministru prezidents Andris Kulbergs (AS).
Jau ziņots, ka par Kulberga valdību nobalsoja 66 deputāti, pret balsoja 25 deputāti. Pret Kulberga valdību balsoja deputāti no "Progresīvajiem", "Stabilitātes", un partijas "Latvija pirmajā vietā". Tāpat pret Kulberga valdību nobalsoja "Jaunās vienotības" (JV) deputāts Daugavietis.
Par Kulberga valdību nebalsoja Jānis Patmalnieks (JV), kā arī izjukušās "Stabilitātei" Saeimas frakcijas deputāti Igors Judins un Amils Saļimovs.
Jauno valdību veido "Apvienotais saraksts" (AS), Nacionālā apvienība (NA), JV un Zaļo un zemnieku savienība (ZZS).
AS pārziņā valdībā ir Finanšu, Tieslietu un Viedās administrācijas un reģionālās attīstības ministrijas. Finanšu ministra amatā apstiprināts Māris Kučinskis, tieslietu ministra amatā - Edvards Smiltēns, bet viedās administrācijas un reģionālās attīstības ministra amatā - Edgars Tavars.
NA vada Izglītības un zinātnes, Kultūras, Iekšlietu, kā arī Klimata un enerģētikas ministrijas. Par izglītības un zinātnes ministri kļuvusi Ilze Indriksone, iekšlietu ministrs būs Jānis Dombrava, kultūras ministrs - Nauris Puntulis, bet klimata un enerģētikas ministra amatā apstiprināts Jānis Vitenbergs.
Amatu saglabājusi arī Saeimas priekšsēdētāja Daiga Mieriņa (ZZS).', 'c85f1732c130d5d9dd90417a8813be1aedf33b4151d488d0b97726bd4dadc984', 1510820790884387770, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711611-kulbergs-mums-atvelets-iss-laika-posms-kas-bus-darba-pilns', NULL, '2026-05-29 18:13:03', 190, 'lv', '2026-05-28T20:08:48.000000Z', 0, NULL, 'Kulbergs: mums atvēlēts īss laika posms, kas būs darba pilns', '2026-05-29 18:33:22', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44961, 'Koalīcijas deputāts Patmalnieks nokavējis balsojumu par Kulberga valdību
Koalīcijas deputāts Jānis Patmalnieks (JV) ceturtdien Saeimas sēdē nokavējis balsojumu par Ministru prezidenta Andra Kulberga (AS) valdību.
Patmalnieks vērsīšoties ar iesniegumu Saeimas Prezidijā un norādīs, ka būtu balsojis par jauno valdību.
Par Kulberga valdību nobalsoja 66 deputāti, pret balsoja 25 deputāti. Pret Kulberga valdību balsoja deputāti no "Progresīvajiem", "Stabilitātes", un partijas "Latvija pirmajā vietā". Tāpat pret Kulberga valdību nobalsoja "Jaunās vienotības" (JV) deputāts Dāvis Mārtiņš Daugavietis.
Par Kulberga valdību nebalsoja arī Patmalnieks un izjukušās "Stabilitātei" Saeimas frakcijas deputāti Igors Judins un Amils Saļimovs.
Daugavietis, kurš līdz šim ieņēmis arī Izglītības un zinātnes ministrijas parlamentārā sekretāra amatu, norādīja, koalīcija uz viņa atbalstu varēs paļauties jautājumos, kurus viņš uzskatīs par valstij būtiskiem.
Runājot par balsojumu Kulberga valdībai un koalīcijai kopumā, deputāts pauda piesardzīgu vērtējumu par jaunās valdības spēju pārliecināt sabiedrību un parlamentu par efektīvāku darbu nekā iepriekš.
Vienlaikus Daugavietis uzsvēra, ka īpaši svarīgos drošības jautājumos, ņemot vērā arī savu saistību ar Nacionālajiem bruņotajiem spēkiem, viņš atbalstīs lēmumus, kas, viņaprāt, nepieciešami valsts interesēs.
Gadījumos, kad priekšlikumi neatbildīs viņa pārliecībai, viņš balsos neatkarīgi, atstājot atbildību par šādiem lēmumiem to virzītājiem.
Deputāts sacīja, ka pats neplāno pamest JV Saeimas frakciju vai turpināt darbu kā neatkarīgais deputāts, norādot, ka joprojām ir partijas "Vienotība" valdes loceklis un neplāno mainīt savu politisko piederību. Vienlaikus viņš atzina, ka turpmākā atrašanās partijā būs atkarīga arī no kolēģu un partijas vadības lēmumiem.
Jauno valdību veido "Apvienotais saraksts" (AS), Nacionālā apvienība (NA), JV un Zaļo un zemnieku savienība (ZZS).
AS pārziņā valdībā ir Finanšu, Tieslietu un Viedās administrācijas un reģionālās attīstības ministrijas. Finanšu ministra amatā apstiprināts Māris Kučinskis, tieslietu ministra amatā - Edvards Smiltēns, bet viedās administrācijas un reģionālās attīstības ministra amatā - Edgars Tavars.
No JV valdībā amatus saglabājuši ārlietu ministre Baiba Braže un veselības ministrs Hosams Abu Meri. Par aizsardzības ministru apstiprināts Raivis Melnis, savukārt satiksmes ministra amatā iecelts līdzšinējais iekšlietu ministrs Rihards Kozlovskis.
NA vada Izglītības un zinātnes, Kultūras, Iekšlietu, kā arī Klimata un enerģētikas ministrijas. Par izglītības un zinātnes ministri kļuvusi Ilze Indriksone, iekšlietu ministrs būs Jānis Dombrava, kultūras ministrs - Nauris Puntulis, bet klimata un enerģētikas ministra amatā apstiprināts Jānis Vitenbergs.
Savukārt no ZZS valdībā amatus saglabājuši ekonomikas ministrs Viktors Valainis un labklājības ministrs Reinis Uzulnieks, bet zemkopības ministra amatā apstiprināts Uldis Augulis.
Amatu saglabājusi arī Saeimas priekšsēdētāja Daiga Mieriņa (ZZS).
Valsts prezidents Edgars Rinkēvičs Kulbergam uzticēja veidot jaunu valdību pēc tam, kad demisionēja līdzšinējā premjere Siliņa.', '9b887f18e9bdb5504f7a0b23cb042d11724944342e848f1829d486560df4d75a', -7587013956249023560, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711600-koalicijas-deputats-patmalnieks-nokavejis-balsojumu-par-kulberga-valdibu', NULL, '2026-05-30 22:45:25', 398, 'lv', '2026-05-28T18:48:17.000000Z', 0, NULL, 'Koalīcijas deputāts Patmalnieks nokavējis balsojumu par Kulberga valdību', '2026-05-29 18:28:09', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (44962, 'Koalīcijas deputāts Daugavietis turpmāk Saeimā balsos pēc sirdsapziņas
Koalīcijas deputāts Dāvis Mārtiņš Daugavietis (JV), kurš bija vienīgais koalīcijas deputāts, kurš nobalsoja pret Ministru prezidenta Andra Kulberga (AS) valdību, turpmāk Saeimas balsojumos rīkosies pēc savas sirdsapziņas.
Komentējot savu balsojumu, Daugavietis, kurš līdz šim ieņēmis arī Izglītības un zinātnes ministrijas parlamentārā sekretāra amatu, aģentūrai LETA norādīja, koalīcija uz viņa atbalstu varēs paļauties jautājumos, kurus viņš uzskatīs par valstij būtiskiem.
Runājot par balsojumu Kulberga valdībai un koalīcijai kopumā, deputāts pauda piesardzīgu vērtējumu par jaunās valdības spēju pārliecināt sabiedrību un parlamentu par efektīvāku darbu nekā iepriekš.
Vienlaikus Daugavietis uzsvēra, ka īpaši svarīgos drošības jautājumos, ņemot vērā arī savu saistību ar Nacionālajiem bruņotajiem spēkiem, viņš atbalstīs lēmumus, kas, viņaprāt, nepieciešami valsts interesēs.
Gadījumos, kad priekšlikumi neatbildīs viņa pārliecībai, viņš balsos neatkarīgi, atstājot atbildību par šādiem lēmumiem to virzītājiem.
Deputāts sacīja, ka pats neplāno pamest "Jaunās vienotības" Saeimas frakciju vai turpināt darbu kā neatkarīgais deputāts, norādot, ka joprojām ir partijas "Vienotība" valdes loceklis un neplāno mainīt savu politisko piederību. Vienlaikus viņš atzina, ka turpmākā atrašanās partijā būs atkarīga arī no kolēģu un partijas vadības lēmumiem.
Jau ziņots, ka par Kulberga valdību nobalsoja 66 deputāti, pret balsoja 25 deputāti. Pret Kulberga valdību balsoja deputāti no "Progresīvajiem", "Stabilitātes", un partijas "Latvija pirmajā vietā". Tāpat pret Kulberga valdību nobalsoja "Jaunās vienotības" (JV) deputāts Daugavietis.
Par Kulberga valdību nebalsoja Jānis Patmalnieks (JV), kā arī izjukušās "Stabilitātei" Saeimas frakcijas deputāti Igors Judins un Amils Saļimovs.
Līdz ar to ir beigušās demisionējušās premjeres Evikas Siliņas (JV) valdības pilnvaras. Valsts kancelejā skaidroja, ka tās beidzās brīdī, kad Saeima apstiprina jauno Ministru kabinetu.
Amatu saglabājusi arī Saeimas priekšsēdētāja Daiga Mieriņa (ZZS).', 'ba5b438075a8df53ed9b3385b0b2bf246694d1ea1583db4e964e21dda5b17e46', -9029295034241588295, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711599-koalicijas-deputats-daugavietis-turpmak-saeima-balsos-pec-sirdsapzinas', NULL, '2026-05-29 18:13:04', 267, 'lv', '2026-05-28T18:11:53.000000Z', 0, NULL, 'Koalīcijas deputāts Daugavietis turpmāk Saeimā balsos pēc sirdsapziņas', '2026-05-29 18:28:09', NULL, NULL, NULL);
