INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45011, 'Laiks tiešām ir limitēts un darīšu visu, kas manos spēkos, lai ieviestu citu politisko kultūru Latvijā. Ne viss sanāks, ne visu paspēšu, bet 100% darīšu, lai būtu mērāms rezultāts', '6f88c7e12389d58361388efd666601286d94b4407ad5044884d0e92180ec443e', -8764128202419186951, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/AndrisKulbergs/status/2060314683186242025', NULL, '2026-05-29 18:19:51', 29, 'lv', '2026-05-29T10:57:53+00:00', 0, NULL, NULL, '2026-05-29 18:28:23', 15, 6, 91);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45019, 'Valdības maiņā vissvarīgākā man šķiet pilnvaru svinīgā nodošana, kas apliecina, ka Latvijā ir demokrātija. Vara var nomainīties. Vai varas maiņa ir ceremoniāla, vai pēc būtības — tas ir atkarīgs no mums, bet ceremonija ir pirmais solis.

Ceremonija ir vārds, tā ir apņemšanās. Viens saka: "Es nolieku pilnvaras", otrs saka: "Es uzņemos atbildību". Ne no viena tajā brīdī nevar prasīt neko vairāk, nevienam tajā brīdī nevar neko pārmest. Viens dara svētu lietu, atsacīdamies no varas. Otrs dara svētu lietu, paņemot to, ko viņam dod.

Paldies Evikai Siliņai par drosmi vadīt valsti, kad veči, acīmredzot, nejaudāja uzņemties atbildību, bet Andrim Kulbergam vēlu lēnprātību, uzticamus padomniekus un nepazaudēt saķeri ar zemi!

https://t.co/oCEZNpoMBj', '2b7e676d068dba479ff6f5b53392ce80071ad099a9b0b8943e699d4b8a0163dd', 70720476373275087, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2060055113230917717', NULL, '2026-05-29 18:19:52', 109, 'lv', '2026-05-28T17:46:27+00:00', 0, NULL, NULL, '2026-05-29 18:33:01', 1, 0, 21);
