INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45504, 'Jaunais Latvijas Ministru prezidents Andris Kulbergs sociālajā platformā "X" komentē ministriju samazināšanas iespējamību. Vai viņš ķersies klāt ministriju optimizācijai?
"Četru mēnešu limitētā laikā likvidēt vai apvienot ministrijas nav prāta darbs, ja enerģija un uzmanība ir jāvelta drošībai - militārai, civilajai, ekonomikas. Reformām vajag laiku un uzmanību, lai nepieļautu kļūdas griezt tikai griešanas pēc," scenāriju iezīmē Kulbergs.
