INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45674, 'Izglītības ministrijas biroja vadītājs atteicies no Saeimas deputāta mandāta — Izglītības un zinātnes ministres Ilzes Indriksones (NA) biroja vadītājs Rūdolfs Kalvāns ir atteicies no tā dēvētā "mīkstā" deputāta mandāta Saeimā, bet NA Saulkrastu nodaļas vadītāja vietnieks Jānis Eglīts savu lēmumu pagaidām vēl neatklāj, noskaidroja aģentūra LETA.', '7c27b8a572a58afd346786d081240c065c24cb1aa7878f71249edbd43e77845d', 1846390365115579080, 8, 'web', 0, NULL, 'tvnet.lv', 'https://pmo.ee/8481032', NULL, '2026-05-30 22:42:04', 46, 'lv', '2026-05-30T13:39:26', 0, NULL, 'Izglītības ministrijas biroja vadītājs atteicies no Saeimas deputāta mandāta', '2026-05-30 22:58:17', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45684, 'Teātra darbinieku savienības vadītājs no jaunās valdības nesagaida lielas izmaiņas nozarē, ja vien negrozīs budžetu
Rīga, 30. maijs, LETA. Kultūras nozarē četru mēnešu laikā līdz Saeimas vēlēšanām nekas nemainīsies bez budžetu pārskatīšanas, tādu viedokli aģentūrai pauda Latvijas Teātra darbinieku savienības (LTDS) valdes priekšsēdētājs Ojārs Rubenis.
Lūgts komentēt, ko nozare sagaida no jaunā kultūras ministra Naura Puntuļa (NA), Rubenis uzsvēra, ka apmēram ir skaidras ministra nostādnes, kurās viņš virzīs darbu uz priekšu. Rubenis pieminēja, ka Puntulis ir nacionāli noskaņots ministrs, kamēr iepriekšējā kultūras ministre Agnese Lāce (P) bija noskaņota progresīvāk.
"Manuprāt, četros mēnešos nekas būtiski nevar mainīties, ja vien neķersies klāt budžetiem un tie netiks kaut kādā veidā vēl samazināti. Tas arī neatstās nekādu iespaidu šajā pusgadā uz šī gada kultūras finansējumu," sacīja LTDS valdes priekšsēdētājs.
Viņš piebilda, ka kultūras nozarē problēmas ar finansējumu ir bijušas ilgstoši, tas nekad nav bijis pietiekams, taču kultūras darbinieki ar to ir samierinājušies. Pēc viņa domām, ir pilnīgi skaidrs, ka Puntulis aktīvi iesaistīsies jaunās Rīgas filharmonijas būvniecībā.
"Līdz ar to ir pilnīgi skaidrs, atklāts jautājums paliks par vairāku gadu laikā izstrādāto projektu Latvijas Nacionālā teātra piebūvei. Par projektu ir samaksāts, taču nešķiet, ka šis virzīsies uz priekšu," teica Rubenis.
LTDS valdes priekšsēdētājs uzsvēra, ka Puntulis "ir buks ar pieredzi, kurš zina, uz kurām pogām, kurā brīdī un kā nospiest". Rubenis atzina, ka uz šiem jautājumiem skatās mierīgi. Tāpat viņš uzdeva retorisku jautājumu, vai kaut kas mainīsies, piemēram, Kultūras ministrijas nostādnēs, taču tas esot jāprasa ministrijas darbiniekiem un katrai nozarei atsevišķi.
Rubenis teica, ka par visu, kas attiecas uz teātra nozari, viņam nekādu jautājumu nav, jo nebūs nekāda milzīga pārsteiguma. Viņš skaidroja, ka kultūras jomā ir pietiekami daudz jautājumu, kuri laika gaitā būs jāpārskata.
"Piemēram, muzejnieki, kuru atalgojumu nevar salīdzināt ar citām nozarēm. Man ir sveškauns par to, ka šiem cilvēkiem ir tāds atalgojums par tādu ieguldīto darbu," sacīja LTDS valdes priekšsēdētājs.
Viņš atzīmēja, ka arī šogad tika samazināts budžets teātriem, kas nozīmē dažādu pārmaiņu ieviešanu. Rubenis secināja, ka kopējās tendencēs nekas ievērojami nevar mainīties. Viņaprāt, interesants varētu būt jautājums par to, kā Puntulis skatīsies uz sabiedrisko mediju un masu mediju attīstību turpmāk un kādas būs viņa nostādnes, jo Lācei bija mazliet citādāks skatījums.
Viņaprāt, laba sadzīvošana un cieņpilna attieksme vienam pret otru ir galvenais uzdevums vasarā laikā, kad lido droni un Latvijai jāstiprina savas aizsardzības spējas. Rubenis uzskata, ka visi kultūras ļaudis to labi saprot - primārais ir nosargāt savu valsti, un tas ir jāņem vērā arī kultūras jautājumu risināšanā.
Jau rakstīts, ka Saeima ceturtdien, 28. maijā, apstiprināja jauno valdību, kuru vada Ministru prezidents Andris Kulbergs (AS).
Jauno valdību veido "Apvienotais saraksts" (AS), Nacionālā apvienība (NA), "Jaunā vienotība" (JV) un Zaļo un zemnieku savienība (ZZS).
- Publicēta: 30.05.2026 17:08', '9fd6b6976bf798125faa70c82468ee17dbfddcf47349a6b61146d4d96ee7c5e9', -3389310326977946714, 6, 'web', 0, NULL, 'www.leta.lv', 'https://www.leta.lv/home/important/1F7E147C-A176-4DEB-8E60-6A0D80142C77', NULL, '2026-05-30 22:43:26', 444, 'lv', NULL, 0, NULL, 'Teātra darbinieku savienības vadītājs no jaunās valdības nesagaida lielas izmaiņas nozarē, ja vien negrozīs budžetu', '2026-05-30 23:12:00', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45695, '“Kādreiz uzrakstīšu grāmatu, kā ražo politiskās desas!” Kulbergs neilgi pirms balsojuma sniedzis pavisam cilvēcīgu interviju 0
Andris Kulbergs, kurš nule kļuvis par Ministru prezidentu, intervijā TV24 speciālizlaidumā atzina, ka jaunajā amatā vēlas mainīt līdzšinējo politisko kultūru, kurā pārāk asi tiek dalīta pozīcija un opozīcija. Viņaprāt, Saeimā ir 100 tautas ievēlēti deputāti, kuri visi devuši solījumu strādāt Latvijas labā.
Īpaši spilgti Kulbergs izteicās par valdības darbu priekšvēlēšanu laikā. Viņš uzsvēra, ka ministriem un koalīcijas partijām būs jānoliek malā “duncīši un nazīši”, jo valdībā jābūt nevis priekšvēlēšanu retorikai, bet konkrētiem darbiem. Pēc viņa domām, vēlētāji daudz vairāk novērtēs padarīto, nevis tukšu runāšanu.
Viens no personiskākiem brīžiem intervijā bija jautājums par motociklu. Kulbergs līdz šim uz intervijām bieži braucis ar moci, un viņam tika vaicāts, vai pēc kļūšanas par premjeru tas turpināsies. Viņš atzina, ka vēl nav pārrunājis šo jautājumu ar drošības dienestiem, bet labprāt nevēlētos būt “apkarināts ar miesargiem”. Viņaprāt, ja darbs tiek darīts labi, pārmērīga apsardze nav nepieciešama.
Kulbergs arī nenoliedza, ka pēdējās dienās gulējis ļoti maz. Viņš jokoja, ka reiz varētu uzrakstīt grāmatu par to, “kā ražo politiskās desas”, jo valdības veidošanas aizkulises bijušas ļoti intensīvas.', '5bae06bbbff6a4775f4eb6eabf63914600c26750ef9f28ae3bf14cd6680d3ccf', 2086758333403024184, 16, 'web', 0, NULL, 'www.la.lv', 'https://www.la.lv/kadreiz-uzrakstisu-gramatu-ka-razo-politiskas-desas-kulbergs-neilgi-pirms-balsojuma-sniedzis-pavisam-cilvevigu-interviju', NULL, '2026-05-30 22:44:50', 186, 'lv', '2026-05-30T16:59:01.000000Z', 0, NULL, '“Kādreiz uzrakstīšu grāmatu, kā ražo politiskās desas!” Kulbergs neilgi pirms balsojuma sniedzis pavisam cilvēcīgu interviju', '2026-05-30 22:58:01', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45697, 'Ne visi saņem visu, ko vēlējušies: Indriksone par “Nacionālajai apvienībai” piešķirtajām ministrijām 0
TV24 raidījumā “Ziņu TOP” Saeimas deputāte, Nacionālās apvienības valdes priekšsēdētāja un bijusī ekonomikas ministre (2022-2023) Ilze Indriksone komentēja valdības veidošanas sarunas un ministriju sadalījumu starp politiskajiem spēkiem.
Viņa norādīja, ka sarunās, kurās piedalās vairākas puses, nav iespējams, ka visi politiskie spēki iegūst visas sev vēlamās jomas, tāpēc vienmēr tiek panākts kompromiss. Pēc viņas teiktā, arī Nacionālā apvienība ir saņēmusi gan sev vēlamos, gan arī neplānotus pārvaldības sektorus.
Indriksone uzsvēra, ka NA bija vēlējusies pārvaldīt kādu no drošības jomas ministrijām, un iekšlietu ministrijas uzticēšana partijai esot gan liela atbildība, gan iespēja. Viņa norādīja, ka šajā jomā aktuāli ir civilās aizsardzības jautājumi, imigrācijas kontrole un tās pastiprināšana, kas tiek skatīti kā ilgtermiņa izaicinājums.
Viņa arī piebilda, ka līdz ar iekšlietu jomu NA pārraudzībā nonāk arī kultūras un izglītības jautājumi, kas parasti reti tiek apvienoti vienā politiskā atbildībā. Tas, pēc viņas teiktā, dod iespēju risināt vairākus jautājumus vienotā skatījumā, tostarp izglītības sistēmas attīstību un augstākās izglītības jautājumus.
Komentējot NA vēsturisko pozīciju valdībās, Indriksone norādīja, ka ilgstoši partijai nav bijusi pieeja Iekšlietu un Izglītības un zinātnes ministrijām, taču šobrīd situācija esot mainījusies. Viņa to raksturoja kā pozitīvu pavērsienu, kas ļauj partijai īstenot savas politiskās prioritātes.
Indriksone arī uzsvēra, ka valsts attīstībā būtiski ir nodrošināt nacionālo interešu ievērošanu visās jomās – gan drošībā, gan ekonomikā, gan izglītībā, lai ilgtermiņā Latvija saglabātu savu valsts un sabiedrības attīstības kursu.', '5cb727d7cca54ded5500ecfa4b8d3d87a632535f3ae800abf2386d309ce8eaa6', 1340260776308523492, 16, 'web', 0, NULL, 'www.la.lv', 'https://www.la.lv/ne-visi-sanem-visu-ko-velejusies-indriksone-par-nacionalajai-apvienibai-pieskirtajam-ministrijam', NULL, '2026-05-30 22:44:51', 235, 'lv', '2026-05-30T19:13:18.000000Z', 0, NULL, 'Ne visi saņem visu, ko vēlējušies: Indriksone par “Nacionālajai apvienībai” piešķirtajām ministrijām', '2026-05-30 22:58:17', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45698, '“Mums nav tiesību pagurt” – Slaidiņš par sabiedrības nogurumu no kara Ukrainā 0
Latvija kopumā – gan no valsts budžeta, gan sabiedrības ziedojumiem – Ukrainai līdz šim sniegusi palīdzību vairāk nekā viena miljarda eiro apmērā. Šajā atbalstā būtisku ieguldījumu devusi arī Latvijas sabiedrība ar individuāliem ziedojumiem.
Nacionālo bruņoto spēku majors un Zemessardzes štāba virsnieks Jānis Slaidiņš TV24 raidījumā “Uz līnijas” uzsvēra, ka, lai arī sabiedrībā jūtams nogurums no ilgstošā kara Ukrainā, Latvijai un tās iedzīvotājiem nevajadzētu pagurt.
Runājot par sabiedrības iesaisti, viņš atzina, ka viņa paša ieguldījums kopējā atbalstā ir neliels, tomēr uzsvēra, ka Latvijas sabiedrība kopumā izceļas ar izpratni par notiekošo Ukrainā.
Slaidiņš norādīja, ka nogurums no kara ir saprotams, un vienlaikus uzsvēra – kaut mazākā palīdzība Ukrainas karavīriem ceļ morāli. Viņš atgādināja, ka Ukrainā joprojām notiek intensīvi uzbrukumi, un civiliedzīvotāji un karavīri ik dienu atrodas apdraudējumā.
Viņš arī atklāja, ka pats nesen nosūtījis dronus Ukrainas karavīriem, uzsverot, ka šāda palīdzība, pat ja tā neietekmē kara gaitu globāli, sniedz nozīmīgu morālu atbalstu karavīriem frontē.
Pēc Slaidiņa teiktā, pat neliels atbalsts var būt būtisks, jo tas palīdz stiprināt Ukrainas karavīru motivāciju turpināt aizsardzību pret Krievijas uzsākto karu.', 'd8d60472b6ffb6d3729fd5740034402ddc6087faa1487ff4286817c1ee349edd', -3528404689511130231, 16, 'web', 0, NULL, 'www.la.lv', 'https://www.la.lv/mums-nav-tiesibas-pagurt-slaidins-par-sabiedribas-nogurumu-no-kara-ukraina', NULL, '2026-05-30 22:44:51', 187, 'lv', '2026-05-30T18:47:48.000000Z', 0, NULL, '“Mums nav tiesību pagurt” – Slaidiņš par sabiedrības nogurumu no kara Ukrainā', '2026-05-30 22:57:41', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45701, 'Rūdolfs Kalvāns atteicies no Saeimas deputāta mandāta, bet Jānis Eglīts savu lēmumu pagaidām neatklāj
Izglītības un zinātnes ministres Ilzes Indriksones (NA) biroja vadītājs Rūdolfs Kalvāns ir atteicies no tā dēvētā "mīkstā" deputāta mandāta Saeimā, bet NA Saulkrastu nodaļas vadītāja vietnieks Jānis Eglīts savu lēmumu pagaidām vēl neatklāj, noskaidroja aģentūra LETA.
Kalvāns sacīja, ka viņš strādās kā izglītības un zinātnes ministres biroja vadītājs, tāpēc Saeimas deputāta mandātu nepieņems.
Savukārt Eglīts, kuram mandāts pienākas kā nākamajam, skaidroja, ka lēmums jau ir pieņemts, taču to atklās pirmdien.
Jau vēstīts, ka no "mīkstā" mandāta atteicies bijušais Saeimas deputāts Jānis Iesalnieks, kā arī Rīgas domes deputāts Ģirts Lapiņš (NA).
Kā liecina Centrālās vēlēšanu komisijas dati, Lapiņam atsakoties no piedāvātā parlamentārieša mandāta, ceļš uz Saeimu paveras Rīgas vicemēram Edvardam Ratniekam. Ja Ratnieks atteiksies no mandāta, uz amatu varēs pretendēt Rīgas Valsts 1. ģimnāzijas un Rīgas Mākslas un mediju tehnikuma vēstures skolotājs, Vēstures un sociālo zinību skolotāju biedrības valdes loceklis un "Latvijaspieminekli.lv" veidotājs Roberts Ķipurs.
Ratnieks teica, ka piedāvājumu vērtēs tad, kad to būs oficiāli saņēmis.
Līdz ar līdzšinējās opozīcijas pārstāvja Andra Kulberga (AS) valdības apstiprināšanu būtiski mainās Saeimas sastāvs, jo vairāki līdzšinējie deputāti kļūst par ministriem, bet citi līdzšinējie ministri atgriežas parlamentā.
No Nacionālās apvienības Saeimas deputātiem par ministriem kļuvuši Ilze Indriksone, Jānis Dombrava, Puntulis un Jānis Vitenbergs. Indriksone kļuvusi par izglītības un zinātnes ministri, Dombrava - par iekšlietu ministru, Nauris Puntulis - par kultūras ministru, bet Vitenbergs - par klimata un enerģētikas ministru.
Saeimas deputāta "mīksto" mandātu piekrituši pieņemt Liepājas Valsts 1. ģimnāzijas latviešu valodas un literatūras skolotājs Normunds Dzintars un Bauskas novada domes deputāts Arnolds Jātnieks.', 'b7f9670ae26322c252ab124f2b44548751b800cb8aa2d2e7d94f7da8c4f1b2ba', -8580035950182346104, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711842-rudolfs-kalvans-atteicies-no-saeimas-deputata-mandata-bet-janis-eglits-savu-lemumu-pagaidam-neatklaj', NULL, '2026-05-30 22:45:23', 262, 'lv', '2026-05-30T11:36:49.000000Z', 0, NULL, 'Rūdolfs Kalvāns atteicies no Saeimas deputāta mandāta, bet Jānis Eglīts savu lēmumu pagaidām neatklāj', '2026-05-30 23:12:00', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45702, 'Arī Lapiņš atteicies no Saeimas deputāta mandāta; zināms, kam nākamajam ir iespēja
Rīgas domes deputāts Ģirts Lapiņš (NA) ir atteicies no tā dēvētā "mīkstā" mandāta parlamentā, kas viņam tika piedāvāts, jo par ministru kļuvis līdzšinējais deputāts Nauris Puntulis.
Lapiņš tviterī raksta, ka ir rūpīgi pārdomājis un pieņēmis lēmumu, ka nepieņems Saeimas deputāta mandātu uz atlikušajiem četriem parlamenta pilnvaru mēnešiem.
Viņš uzsver, ka šobrīd svarīgākais ir drošība Latvijā un Rīgā, tāpēc viņš turpinās vadīt Rīgas domes Drošības, kārtības un korupcijas novēršanas komiteju, kā arī būs iekšlietu ministra Jāņa Dombravas (NA) ārštata padomnieks civilās aizsardzības jautājumos, par ko atlīdzību nesaņems.
Kā liecina Centrālās vēlēšanu komisijas dati, Lapiņam atsakoties no piedāvātā parlamentārieša mandāta, ceļš uz Saeimu paveras Rīgas vicemēram Edvardam Ratniekam.
Ja Ratnieks atteiksies no mandāta, uz amatu varēs pretendēt Rīgas Valsts 1. ģimnāzijas un Rīgas Mākslas un mediju tehnikuma vēstures skolotājs, Vēstures un sociālo zinību skolotāju biedrības valdes loceklis un "Latvijaspieminekli.lv" veidotājs Roberts Ķipurs.
Ratnieks teica, ka piedāvājumu vērtēs tad, kad to būs oficiāli saņēmis. Līdz ar līdzšinējās opozīcijas pārstāvja Andra Kulberga (AS) valdības apstiprināšanu būtiski mainās Saeimas sastāvs, jo vairāki līdzšinējie deputāti kļūst par ministriem, bet citi līdzšinējie ministri atgriežas parlamentā.
No Nacionālās apvienības Saeimas deputātiem par ministriem kļuvuši Ilze Indriksone, Jānis Dombrava, Puntulis un Jānis Vitenbergs. Indriksone kļuvusi par izglītības un zinātnes ministri, Dombrava - par iekšlietu ministru, Puntulis - par kultūras ministru, bet Vitenbergs - par klimata un enerģētikas ministru.
Saeimas deputāta "mīksto" mandātu piekrituši pieņemt Liepājas Valsts 1. ģimnāzijas latviešu valodas un literatūras skolotājs Normunds Dzintars un Bauskas novada domes deputāts Arnolds Jātnieks.
Tikmēr no "mīkstā" mandāta bez Lapiņa atteicies arī bijušais Saeimas deputāts Jānis Iesalnieks.
Kā liecina Centrālās vēlēšanu komisijas dati, Iesalniekam atsakoties no piedāvātā parlamentārieša mandāta, ceļš uz Saeimu paveras līdzšinējam Izglītības un zinātnes ministrijas Vispārējās izglītības departamenta vadītājam Rūdolfam Kalvānam, kurš tikko kļuva par jaunās izglītības un zinātnes ministres Ilzes Indriksones (NA) biroja vadītāju. Aģentūrai LETA vēl nav izdevies noskaidrot, vai viņš mandātu pieņems.', '940d16d2af8d4dd0a2850eeac7c9e1f7bcdb3c973370b92f55b648928815346e', -7282999257498594424, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711819-ari-lapins-atteicies-no-saeimas-deputata-mandata-zinams-kam-nakamajam-ir-iespeja', NULL, '2026-05-30 22:45:24', 319, 'lv', '2026-05-30T07:52:23.000000Z', 0, NULL, 'Arī Lapiņš atteicies no Saeimas deputāta mandāta; zināms, kam nākamajam ir iespēja', '2026-05-30 23:12:00', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45703, 'Bijušais Saeimas deputāts Jānis Iesalnieks atteicies no deputāta mandāta
Bijušais Saeimas deputāts Jānis Iesalnieks (NA) atteicies no tā saucamā "mīkstā" mandāta parlamentā, kas viņam tika piedāvāts pēc tam, kad daļa Nacionālās apvienības (NA) deputātu kļuva par ministriem jaunajā valdībā.
Iesalnieks vietnē "X" norādīja, ka par savu lēmumu piektdien informējis Saeimu. Tāpat viņš esot noraidījis piedāvājumu kandidēt rudenī gaidāmajās Saeimas vēlēšanās un neplāno atgriezties aktīvajā politikā.
Iesalnieks norāda, ka viņam patīk darbs, kuru patlaban veic, un arī savu profesionālo nākotni saredzot šajā nozarē. Bijušais politiķis gan piebilst - tas nenozīmē, ka viņš neizmantos savas pilsoniskās tiesības dalīties ar domām par sabiedriskajiem procesiem Latvijā un pasaulē.
Kopš 2023. gada beigām Iesalnieks strādāja SIA "Eiropas dzelzceļa līnijas", kas atbild par "Rail Baltica" izbūvi Latvijas teritorijā, pildot Projekta ieviešanas un vadības departamenta būvdarbu līgumu vadītāja pienākumus.
Kā liecina Centrālās vēlēšanu komisijas dati, Iesalniekam atsakoties no piedāvātā parlamentārieša mandāta, ceļš uz Saeimu paveras līdzšinējam Izglītības un zinātnes ministrijas Vispārējās izglītības departamenta vadītājam Rūdolfam Kalvānam, kurš tikko kļuva par jaunās izglītības un zinātnes ministres Ilzes Indriksones (NA) biroja vadītāju.
Jau ziņots, ka līdz ar līdzšinējās opozīcijas pārstāvja Andra Kulberga (AS) valdības apstiprināšanu būtiski mainās Saeimas sastāvs, jo vairāki līdzšinējie deputāti kļūst par ministriem, bet citi līdzšinējie ministri atgriežas parlamentā.
No Nacionālās apvienības Saeimas deputātiem par ministriem kļuvuši Indriksone, Jānis Dombrava, Nauris Puntulis un Jānis Vitenbergs. Indriksone kļuvusi par izglītības un zinātnes ministri, Dombrava - par iekšlietu ministru, Puntulis - par kultūras ministru, bet Vitenbergs - par klimata un enerģētikas ministru.', 'b7cb77d3a6f92a2b8a355ba0df3902907d4bfbb2220d956043d7af20cc4b1e1e', -7860018284678552696, 18, 'web', 0, NULL, 'jauns.lv', 'https://jauns.lv/raksts/zinas/711791-bijusais-saeimas-deputats-janis-iesalnieks-atteicies-no-deputata-mandata', NULL, '2026-05-30 22:45:24', 244, 'lv', '2026-05-29T19:15:49.000000Z', 0, NULL, 'Bijušais Saeimas deputāts Jānis Iesalnieks atteicies no deputāta mandāta', '2026-05-30 23:12:00', NULL, NULL, NULL);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45705, '▪️Par civilo aizsardzību atbildīgie ministrijas darbinieki dosies strādāt pierobežas pašvaldībās▪️

Starp manām un manas komandas prioritātēm būs civilā aizsardzība. Attīstīsim robežsardzes spējas, iespējams pat pielietojot modernas dronu detekcijas un notriekšanas sistēmas, tādā veidā sniedzot efektīvu atbalstu mūsu nacionālajiem bruņotajiem spēkiem uz robežas.

Sabiedrībai jāzina, ka gaisa apdraudējuma brīdinājums nostrādās laikā un cilvēkiem būs skaidrība, kur patverties un kā ātri novērst postījumus. Pārliecība, ka kritiskā infrastruktūra nebūs viegls mērķis, ko pretinieks var iznīcināt.

Par civilo aizsardzību atbildīgie ministrijas darbinieki tiks nosūtīti ilgākā komandējumā uz pierobežas pašvaldībām, lai ne tikai iepazītos ar situāciju, bet uz vietas kopā ar atbildīgajiem dienestiem un pašvaldībām praktiski risinātu problēmas civilās drošības kontekstā.', '7f4766cb76e0733fcdeb7271c88f14599a48f7804a16ab26d9b6844c6f9fc9de', 1465025178342955488, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/janisdombrava/status/2060626255444083056', NULL, '2026-05-30 22:51:58', 106, 'lv', '2026-05-30T07:35:58+00:00', 0, NULL, NULL, '2026-05-30 23:15:39', 16, 36, 250);
