INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45720, 'Stājoties ministru prezidenta amatā, daudz kas ir solīts. Pieminēšu divas lietas, ko @AndrisKulbergs teicis:
1) Iesildīšanās laiks būs viena diena;
2) Cīņa pret korupciju.

Par Kulberga patieso vēlmi cīnīties pret korupciju (un milzīgiem riskiem pašam tikt ievilktam tās valgos), rādīs Andra spēja nekavējoties rīkoties Zemkopības ministrijas un LVM afēras lietā.

Jautāsiet - vai premjers var kaut ko darīt? Jā, kaut vai tūlīt izdot ministru prezidenta rezolūciju zemkopības ministram publiskot LVM finanšu dokumentus un naudas plūsmas, kas parādītu zemkopības ministrijas “savas kabatas” saimniekošanas ceļus un apmērus. Nosaukt visas organizācijas un pakļautības iestādes, kas barojušās no LVM neuzrādītās un uzkrātās naudas. Uzdevumam ir jābūt pietiekoši plašam un konkrētam, lai sabiedrībai pārbaudītu Švinkas izvirzītās aizdomas par iespējamiem pārkāpumiem.

Visu atstājot kā ir, ZZS ar @uldisaugulis vadību, turpinās izsaimniekot LVM un ZM finanses.', 'c8ef2e7306eb3c380f2e318f2c6164db46a346b83ae411ca4e4f36b3cedb0404', 1501126950758945464, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/atis_svinka/status/2060734516826608102', NULL, '2026-05-30 22:52:00', 126, 'lv', '2026-05-30T14:46:10+00:00', 0, NULL, NULL, '2026-05-30 23:16:29', 39, 7, 25);
