INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45729, 'Partiju finansēšanas ierobežojumi ir viens no veiksmīgākajiem instrumentiem, kā šodienas pasīvajā sabiedrībā reizi par visām reizēm aizcementet aktīvo partiju sarakstu (t.i. nepieļaut jaunu rašanos, izņemot populistiskus grupējumus) un kā palīdzēt stiprināt sajūtu, ka par pilsonisko līdzdalību nauda pienākas. Tas arī dod darbu bariņam inspektoru, kas pa santīmam skaita, kā nodokļu maksatāju nauda tiek tērēta, un normalizē sociālistiskā komentariāta bakstīšanos ap vistaisnīgāko svešas naudas sadalījumu. Tagad politiķēt gribētāji dibina biedrības, jo biedrībām var ziedot arī juridiskas personas. Mums tagad premjers arī no biedrības, ne no partijas. Cepuri nost visiem vienpartijas sistēmā uzaugušajiem partiju stiprinātājiem!', 'cadd87e172d0a1a1e8eb32fab896917ba1adcb1f18e09c9b190a2bfeda949d27', 8072724423907182644, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/JazepsBasko/status/2060605522336793046', NULL, '2026-05-30 22:52:01', 93, 'lv', '2026-05-30T06:13:35+00:00', 0, NULL, NULL, '2026-05-30 23:15:23', 2, 7, 22);
INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45730, 'Cita starpā, ļoti simboliski, ka tieši Progresīvie ir tie, kas nodzēsuši Latvijas politikā “sarkano līniju” konceptu. Tas noticis vienkārši, aizejot pagājušajā valdībā ar visādi līdz tam iesarkanoto ZZS tikai, lai būtu prasti pie varas un algām, jo ļoti tak gribējās. Rezultātā šobrīd vispār vairs nerezonē, ka tas pats Kulbergs vēl pagājušonedēļ gribēja Progresīvos ievilkt valdībā, lai būtu stabilāka premjerēšana, neskatoties uz to, ka vēl pirms mēneša visa Kulberga frakcija Saeimā kliedza, ka ar Pro nekad un nekad. Un arī iristu un rečekistu vaimaniņas vispār neviens tagad nedzird un nedzirdēs, ka priekš Apvienotā saraksta vēl pavisam nesen arī ZZS un Lembergs bija sarkanā līnija.. Jauna realitāte. Paldies Progresīvajiem.', '8ba1b26f39749fe21aa4dda01bdf02d64aa7deb8dc49ddc84a69b5ae10ec95c5', 7508159907723138857, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/jaunups/status/2060731085621768417', NULL, '2026-05-30 22:52:01', 107, 'lv', '2026-05-30T14:32:32+00:00', 0, NULL, NULL, NULL, 3, 1, 21);
