INSERT INTO documents (id, content, content_hash, simhash, source_id, platform, is_auto_caption, near_dupe_of, source_domain, source_url, archive_path, scraped_at, word_count, language, published_at, is_paywall, summary, title, reviewed_at, reply_count, retweet_count, favorite_count) VALUES (45833, 'Labs pārstāsts, bet tieši tā - tikai @lasilvportals  pārstāsts. Ar diezgan glupām vietām - "esot atruna, ka Lembergs nemaisīšoties politikā". Nuja, apbrīnojami ticami! Kaut gan, reāli ņemot, zatlerieši, kuri ienāca politikā ar oligarhu apkarošanas karogu, faktiski uzmeta vēlētājus - atgrieza politiskajā apritē vienu no pretīgākajiem. Tā ir krāpšana, piedevām prezidents izrādījies viens no centrālajiem blēžiem. Šī situācija šajā pārstāstā ir apieta.

Arī tēma, ka Šķēle ir aizgājis, ir visai apšaubāma. Briškena "apbrīnojamā" karjera, kad viņš, teju nepilngadīgs būdams, darbojās visnaudīgāko uzņēmumu padomēs, protams, var tikt uzskatīta par brīnumu. Protams, neviens mums nevar aizliegt ticēt arī Zobu fejām un citiem pasaku tēliem.

Un visbeidzot - Dailes teātra izrāde. Atvainojiet, bet šis ir vēlēšanu gads, un stāsts ir par personām, kas joprojām ir aktīvajā politikā. Jā, protams, vecais, labais stāsts par cīņu ar pūķi, kas draud apēst visu Latviju, joprojām ir gana efektīvs, un šī emocija noteikti dos savus punktus. Un, protams, lai dejotu tango, vajag divus - arī Šleseram šī publicitāte lieti noderēs.

Arī šī tēma pārstāstā ir jauki apieta.
Viss kā jau tas pie "lablatviešiem" pieņemts', 'b8a130617e1c8c161354debf43579722d2f4adbe481632ca27da903e0158a733', 3048691775896780092, NULL, 'twitter', 0, NULL, 'x.com', 'https://x.com/OttoOzols/status/2060667965566046227', NULL, '2026-05-30 22:52:16', 176, 'lv', '2026-05-30T10:21:43+00:00', 0, NULL, NULL, '2026-05-30 23:12:39', 0, 0, 0);
