INSERT INTO contradictions (id, opponent_id, claim_old_id, claim_new_id, topic, summary, severity, salience, reviewed, confirmed, detected_at) VALUES (32, 72, 18183, 18104, 'Koalīcija un partijas', '03.03.2026 Indriksone (NA līdere) publiski prognozēja: Siliņas valdība ''spēs nesagāzties un nostrādās līdz termiņa beigām'' — neskatoties uz savstarpējiem strīdiem koalīcijā un nespēju pieņemt būtiskus lēmumus. 69 dienas vēlāk (11.05.2026), pēc Sprūda atkāpšanās 10.05, Indriksone pieprasīja Siliņas valdības atkāpšanos un pasludināja gatavību veidot nacionālās drošības valdību. Lai gan Sprūda krīze ir kontekstuāls trigeris, 03.03 Indriksone jau bija paredzējusi ''reakciju uz krīzēm'' scenāriju un tomēr prognozēja valdības izdzīvošanu — tāpēc 11.05 pozīcija ir kvalitatīva reversal: no prognozes par stabilitāti uz aktīvu pieprasījumu krišanai. Modalitātes piezīme: 03.03 izteikums ir prognoze (funkcionāli implicīts pieļāvums), nevis kategorisks atbalsts.', 'reversal', 0.7, 0, 1, '2026-05-11 23:41:05');
INSERT INTO contradictions (id, opponent_id, claim_old_id, claim_new_id, topic, summary, severity, salience, reviewed, confirmed, detected_at) VALUES (37, 10, 225, 20837, 'Rail Baltica', '18.03.2026 (X): Kulbergs (AS) JV pretošanos Rail Baltica atbildības uzdevumiem nosauca par "apzinātu projekta sabotāžu" un kritizēja JV vadīto Finanšu ministriju par izvairīšanos no atbildības par finansējumu. 25.05.2026 (jauns.lv) Kulbergs kā topošais premjers pamato Satiksmes ministrijas (kuras pārziņā ir Rail Baltica) atstāšanu JV pārziņā ar to, ka JV ir bijusi "vairāk klātesošā" gan finanšu viedoklī, gan lēmumu pieņemšanā nekā jebkurš cits politiskais spēks. Vienlaikus norāda, ka Rail Baltica turpmāk uzraudzīs premjers (nevis tikai SatMin). Pretrunīgums starp marta retoriku un maija portfeļu sadalījuma pamatojumu.', 'reversal', 0.65, 1, 1, '2026-05-26 10:45:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (21, 6, '2026-03-25', '2026-03-25', -0.15, '["drosiba", "imigracija", "LTRK", "drona krize"]', '[]', NULL, 'Ļoti aktīvs sociajos medijos -- trīs tviti viena dienā. Divējāda stratēģija: (1) drošības eksperts -- pieprasīja ārkārtas komisijas sēdi par dronu incidentiem, publicēja NBS informāciju; (2) anti-imigrācijas -- uzbruka LTRK par masu imigrācijas lobēšanu. Pozicinejas ka NA galvenā balss drošības un imigrācijas jautājumos.', 0.85, '2026-03-25 20:37:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (25, 10, '2026-03-25', '2026-03-25', -0.2, '["Rail Baltica", "valdibas kritika"]', '[]', NULL, 'Viens bet ass tvīts -- atklāti uzbrūk premjerei Siliņai par Rail Baltica projekta vadību. Apvienotais saraksts pozicinejas ka valdības kritiķi no iekšpuses (bijušie koalīcijas partneri).', 0.75, '2026-03-25 20:37:01');
