INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (91, 6, '2026-03-26', '2026-03-26', -0.2, '["drošība", "dronu incidenti", "imigrācija", "LTRK kritika"]', '["Droni nebija mērķēti pa Latviju, bet ietekmēti no elektroniskās karadarbības", "LTRK vadība atklāti lobē masu imigrāciju"]', NULL, 'Divējāda stratēģija turpinās: (1) Drošības eksperts — detalizēti komentē dronu incidentu, publicē NBS informāciju, pieprasīja ārkārtas komisijas sēdi. Pozicionējas kā informatīvāks par valdību. (2) Anti-imigrācijas — uzbrūk LTRK par imigrācijas lobēšanu. Trīs tvīti vienā periodā — augsta aktivitāte. Koordinējas ar Šņori un Krištopanu anti-imigrācijas frontē.', 0.85, '2026-03-26 08:57:39');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (94, 10, '2026-03-26', '2026-03-26', -0.25, '["Rail Baltica", "valdības kritika", "Siliņa"]', '["aizej tur, nezin kur — paņem to, nezin ko — uzliec tā, nezin kā"]', NULL, 'Ass tvīts ar latviešu folkloras parafrāzi — kritizē Siliņas Rail Baltica valdības uzdevumu kā haotisku un bezjēdzīgu. AS pozicionējas kā valdības kritiķi no iekšpuses (bijušie koalīcijas partneri). Rail Baltica var kļūt par nozīmīgu vēlēšanu tēmu ja opozīcija turpina koordinēti uzbrukt.', 0.8, '2026-03-26 08:57:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (98, 15, '2026-03-26', '2026-03-26', 0.15, '["aizsardzība", "dronu koalīcija", "ES budžets", "Rail Baltica"]', '["Latvia co-leads the Drone coalition and provides to NATO an enabling innovation and test environment", "Latvia backs a fair and ambitious MFF"]', NULL, 'Aktīva starptautiskā arēnā — divi angliski tvīti. (1) Latvija-Norvēģija dronu forums — 20+ LV un 40+ NO aizsardzības uzņēmumi. Latvija līdzvada NATO dronu koalīciju. (2) ES budžeta prioritātes: drošība, CAP maksājumi, Rail Baltica, mazāk birokrātijas. Pozicionējas kā JV starptautiskā balss aizsardzības un ES jautājumos.', 0.85, '2026-03-26 08:58:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (106, 26, '2026-03-26', '2026-03-26', 0.0, '["ceļu satiksme", "ātruma kontrole", "satiksmes drošība"]', '["kontroles mehānismi nav par sodīšanu, bet drošību"]', NULL, 'Dubulto ātruma kontroles posmus no 16 uz 33. Aizstāvas ar drošības argumentu, bet sabiedrībā šādi lēmumi bieži tiek uztvērti negatīvi. Kā satiksmes ministrs jau bija zem spiediena (demisijas balsojums) — papildu nepopulāri lēmumi var pastiprināt kritiku.', 0.8, '2026-03-26 09:00:03');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (114, 6, '2026-03-27', '2026-03-27', -0.4, '["dronu incidents", "aizsardzības ministrija"]', '[]', NULL, 'Dombrava kā opozīcijas politiķis (NA) kritizē AM politisko vadību par reakciju uz dronu incidentu Latvijas gaisa telpā. Pieprasa aizsardzības ministra atbildību par to, ka Krievijas drons netika savlaicīgi notriects.', 0.8, '2026-03-27 07:10:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (115, 10, '2026-03-27', '2026-03-27', -0.1, '["degvielas akcīze"]', '[]', NULL, 'Kulbergs piedalās debatēs par degvielas cenu ierobežošanas likumu. Saeima galīgajā lasījumā pieņēma likumu, kas samazina akcīzi tikai dīzeļdegvielai uz 3 mēnešiem (no 467 uz 396 EUR/1000l). Benzīns un LPG netika iekļauti.', 0.75, '2026-03-27 07:10:22');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (133, 10, '2026-03-28', '2026-03-28', 0.0, '["SiltumSāga", "sistēmiska korupcija"]', '["tas viss 1:1 mats matā, vārds vārdā ir izbaudīts uz ādas 6x mokošus mēnešus preparējot #RailBaltica stāstu"]', NULL, 'Kulbergs sasaista Rīgas Siltums izmeklēšanu ar Rail Baltica pieredzi — tā pati shēma: ierēdņi, valsts uzņēmumu vadītāji un politiķi ar savstarpēju saskaņošanu organizē melošanu un naudu iznešanu no valsts. Stiprina sistēmiskās korupcijas naratīvu.', 0.9, '2026-03-28 00:52:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (134, 15, '2026-03-28', '2026-03-28', 0.0, '["drošība", "Krievijas draudi"]', '["Kara draudu nav — cīņas par cilvēku prātiem"]', NULL, 'Braže Polijas TV intervijā kategoriski noliedza Krievijas iebrukuma draudus Baltijā līdz 2027. gadam. Aicina sabiedrību saglabāt vēsu prātu un paļauties uz pārbaudītu informāciju. Intervija izraisīja plašu rezonansi sociālajos medijos.', 0.85, '2026-03-28 00:52:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (136, 15, '2026-03-28', '2026-03-28', 0.0, '["Baltijas ekonomika"]', '[]', NULL, 'Braže pieminēta Baltijas valstu parādu un politikas apskatā — Igaunijas parāds, Lietuvas attiecības ar Baltkrieviju. Nav jauna personīga pozīcija.', 0.5, '2026-03-28 07:18:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (142, 26, '2026-03-28', '2026-03-28', 0.0, '["transports", "airBaltic", "valsts kapitālsabiedrības"]', '["IPO nav vienīgais veids, kā piesaistīt kapitālu"]', NULL, 'Satiksmes ministrs Švinka komentē airBaltic finansiālo situāciju — IPO apturēts, nepieciešami 100-150M EUR, dots plašs mandāts kapitāla piesaistei ar dažādiem instrumentiem.', 0.85, '2026-03-28 09:18:21');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (154, 6, '2026-03-31', '2026-03-31', 0.0, '["imigrācija", "dubultpilsonība", "drošība"]', '["trešo valstu pilsoņu veselības aprūpei, pabalstiem un juridiskajam atbalstam ik gadu tiek tērēti aptuveni 100 miljoni eiro"]', NULL, 'Dombrava kā imigrācijas komisijas vadītājs publisko konkrētus skaitļus: 100M+ EUR gadā trešo valstu pilsoņu atbalstam. Piedalās arī drošības apakškomisijā par Latvijas-Krievijas dubultpilsoņu skaita četrkāršošanos kopš 2014. gada.', 0.9, '2026-03-31 21:16:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (157, 26, '2026-03-31', '2026-03-31', 0.0, '["aviācija", "airBaltic"]', '[]', NULL, 'Švinka kā satiksmes ministrs ierosina valdībā airBaltic 30M EUR aizdevumu degvielas cenu kāpuma dēļ.', 0.85, '2026-03-31 21:24:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (166, 26, '2026-04-01', '2026-04-01', 0.0, '["airBaltic", "ZZS", "Saeima", "koalīcija"]', '["Tas, ka frakcija nezina, rada manī apmulsumu par to, kāda ir komunikācijas kvalitāte starp ZZS frakciju un tās ministriem", "Apmulsums, apjukums, citiem apvainošanās. Man ir daudz jautājumu, kā viss notiek apvienības iekšienē", "Šis aizdevums nav valsts injekcija vai atbalsta instruments"]', NULL, 'Švinka pēc slēgtās Budžeta komisijas sēdes paziņoja, ka ZZS iebildumu dēļ balsojums par airBaltic 30M EUR aizdevumu atlikts uz 14. aprīli, un pauda neizpratni par ZZS komunikāciju starp frakciju un tās ministriem. Vienlaikus uzsvēra, ka aizdevums nav valsts injekcija — aviokompānijai jāturpina strādāt pie biznesa plāna un kapitāla piesaistes.', 0.88, '2026-04-01 17:17:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (167, 26, '2026-04-01', '2026-04-01', 0.0, '["airBaltic", "valsts atbalsts"]', '["Šis aizdevums nav valsts injekcija vai atbalsta instruments"]', NULL, 'Švinka precizē 30M EUR aizdevuma raksturu: tas nav valsts palīdzība, bet pagaidu instruments degvielas cenu stabilizācijai. Kompānijai jāturpina strādāt pie biznesa plāna un kapitāla piesaistes.', 0.85, '2026-04-01 17:17:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (171, 15, '2026-04-01', '2026-04-01', 0.0, '["Irāna", "drošība"]', '["Irānas asimetriskās spējas radīt ietekmi uz pasauli joprojām pastāv"]', NULL, 'Braže turpina uzsvērt Irānas asimetriskos draudus kā ārpolitikas prioritāti. Claim [151] jau reģistrēts šodien — jaunu pozīciju nav.', 0.8, '2026-04-01 17:32:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (182, 26, '2026-04-01', '2026-04-01', 0.0, '["airBaltic", "degvielas cenas", "ceļu satiksme", "Rail Baltica", "sankcijas pret Krieviju", "aviācija"]', '["Sankciju mīkstināšana pret krieviju un tās naftu ir fundamentāla, stratēģiska kļūda.", "Priekšlikums ir piešķirt īstermiņa aizdevumu – ''tilta'' finansējumu airBaltic.", "Kontroles mehānismi nav par sodīšanu, bet drošību."]', NULL, '## Atis Švinka — 2026-04-01

Satiksmes ministrs koncentrējas uz airBaltic krīzes pārvaldību — rosina 30M EUR īstermiņa aizdevumu, ko ZZS pagaidām bloķē Budžeta komisijā. Aktīvi komunicē par degvielas cenu krīzi Tuvo Austrumu kara dēļ un tās ietekmi uz aviāciju, transportu, ekonomiku. Iestājas pret Krievijas sankciju mīkstināšanu. Arī ceļu satiksmes drošības jomā — dubulto ātruma kontroles posmus, ietves gājējiem. Rail Baltica iepirkumu dienesta pārbaude.', 0.9, '2026-04-01 20:10:38');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (184, 15, '2026-04-01', '2026-04-01', 0.0, '["Ukrainas atbalsts", "Bučas gadadiena", "Krievijas agresija", "Irāna", "Singapūras vizīte", "ES sankcijas"]', '["Russia''s war of aggression in Ukraine is failing, while its support for Iran is creating a global crisis.", "Ukraine proposed ceasefire for the Easter. Russia''s response - bombing civilian facilities."]', NULL, 'Braže aktīvi darbojās Kijivā Bučas atbrīvošanas 4. gadadienā kopā ar Baltijas kolēģiem un ES augsto pārstāvi Kaju Kallasu. Tikās ar Ukrainas militārās izlūkošanas vadītāju Budanovu — uzsvēra ka Krievijas agresija izgāžas un nepieciešams lielāks spiediens uz Krieviju. Norādīja uz Ukrainas pamiera priekšlikumu Lieldienām un Krievijas atbildi ar bombardēšanu. Uzņēma Singapūras ārlietu ministru — pirmā vizīte Latvijā, apsprieda drošības izaicinājumus un ANO Hartas principus. Retweetoja par ES sankcijām, Krievijas aktīvu iesaldēšanu un ceļošanas brīdinājumu uz Krieviju/Baltkrieviju.', 0.9, '2026-04-01 20:11:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (186, 10, '2026-04-01', '2026-04-01', 0.0, '["Rail Baltica", "valsts kapitālsabiedrības", "AirBaltic", "degvielas cenas", "Rīgas Siltums", "IT iepirkumi"]', '["Esošās kroplās pārvaldības labošana ir kā beigtu zirgu spārdīt.", "Es jums apsolu, šai bezatbildībai tiks pielikts trekns punkts."]', NULL, 'Andris Kulbergs ļoti aktīvs ar saturīgiem, detalizētiem ierakstiem. Galvenās tēmas: (1) Rail Baltica — turpina prasīt premjeres atbildes par projekta vadību, budžetu un ietekmi; kritizē ministriju izvairīšanos no atbildības; (2) AirBaltic — aprēķina 150M EUR dotējamu caurumu, prasa publiski atzīt AB kā subsidējamu pārvadātāju; (3) Rīgas Siltums/siltuma tarifi — PIK sēdes, kritizē bezatbildību valsts kapitālsabiedrībās; (4) Valsts pārvalde — apsola restartēt kapitālsabiedrību pārvaldību; (5) IT iepirkumi — bažas par vēlēšanu drošību.', 0.9, '2026-04-01 20:12:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (197, 15, '2026-04-02', '2026-04-02', 0.0, '["Ukraina un Krievija", "Ārpolitika"]', '["Rinkēvičs devis atļauju Bražei publiski nēsāt Ukrainas valsts apbalvojumu"]', NULL, 'Braže turpina stiprināt pro-Ukrainas tēlu. Saņēmusi atļauju publiski nēsāt Ukrainas II pakāpes ordeni "Par nopelniem" — simbolisks žests, kas apliecina Latvijas ārpolitikas kontinuitāti Ukrainas atbalstā. Saeimā virzīts likumprojekts par pievienošanos Starptautiskajai prasījumu komisijai.', 0.8, '2026-04-02 06:48:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (204, 30, '2026-04-02', '2026-04-02', 0.0, '["Imigrācija"]', '[]', NULL, 'Baško dalās ar rakstu par Latvijas muftiju Zufaru Zainuļļinu: "Nevajag baidīties — vajag saprast, kas ir islāms". Signalizē atvērtību pret reliģisko daudzveidību — kontrastā ar nacionālistu retoriku par imigrāciju.', 0.6, '2026-04-02 06:50:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (207, 15, '2026-04-02', '2026-04-02', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija"]', '["Krievija saglabā savu stratēģisko mērķi vājināt Rietumu vienotību"]', NULL, 'Braže turpina aktīvu ārpolitikas pozicionēšanu — dalās ar MIDD drošības novērtējumu, retweetoja par Krievijas iejaukšanos Bulgārijā.', 0.8, '2026-04-02 11:49:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (217, 15, '2026-04-02', '2026-04-02', 0.0, '["Test"]', '[]', NULL, 'Braže turpina aktīvu ārpolitikas pozicionēšanu — dalās ar MIDD drošības novērtējumu, retweetoja par Krievijas iejaukšanos Bulgārijā.', 0.8, '2026-04-02 11:50:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (220, 15, '2026-04-03', '2026-04-03', 0.0, '["Aizsardzība un drošība", "Droni", "Ārpolitika", "Tieslietas"]', '["Latvia is the only country which has improved and is the only one in hard workers category"]', NULL, 'Braže aktīvi tvīto par drošības tēmām — dronu draudi Baltijā, Ukrainas bezpilotu operācijas Krimā, dezinformācijas apkarošana. Izceļ Latvijas tiesiskuma progresu (vienīgā ES valsts ar konsekventu uzlabojumu). Aktīva diplomātiskā darba nedēļa — tikšanās ar Grieķijas, Bahreinas, AAE ministriem. ANO Drošības padomes rezolūcija par navigācijas brīvību.', 0.85, '2026-04-03 07:29:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (224, 30, '2026-04-03', '2026-04-03', 0.0, '["Vēlēšanas", "MMN"]', '["Kopš iepriekšējā mērījuma mūsu reitings ir pieaudzis par 2,1 procentpunktu"]', NULL, 'Baško publicē SKDS reitingu salīdzinājumu — MMN pieaudzis par 2,1pp, kamēr JV nokrities par 2,4pp. Pozicionē MMN kā augošu spēku pret valdošo partiju.', 0.9, '2026-04-03 07:30:43');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (227, 26, '2026-04-03', '2026-04-03', 0.0, '["Valsts pārvalde"]', '["Augstu novērtēju Ievas Šmites ieguldījumu un aktīvo darbu, stiprinot godīgu konkurenci"]', NULL, 'Švinka tikās ar Konkurences padomes vadību, novērtē Šmites darbu godīgas konkurences stiprināšanā un caurspīdīgākas uzņēmējdarbības vides veidošanā.', 0.8, '2026-04-03 07:31:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (232, 6, '2026-04-03', '2026-04-03', 0.0, '["Sociālā politika", "Mežsaimniecība", "Ukraina un Krievija", "Imigrācija", "Tieslietas", "Vide"]', '[]', NULL, 'Jānis Dombrava (NA) piedalījās 20 balsojumos 1.aprīļa Saeimas sēdē. Balsoja PAR 18 jautājumos, tostarp likumprojektu gala lasījumos (Fizisko personu reģistrs, Konsulārā palīdzība, Rīgas filharmonija, Kapsētu likums) un Ukrainas Starptautiskās prasību komisijas konvencijā. Balsoja PRET abiem pensiju 2.līmeņa kolektīvajiem iesniegumiem — gan par brīvprātīgu izņemšanu (34:33), gan par brīvprātīgumu un nodokļu samazināšanu (38:44). Šī pozīcija sakrīt ar NA partijas līniju. Atbalstīja Meža likuma grozījumu nodošanu komisijām (noraidīts 34:40) — opozīcijas iniciātu, ko koalīcija nobloķēja. Kopumā aktīvs dalībnieks ar konsekventu opozīcijas pozīciju.', 0.95, '2026-04-03 17:29:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (233, 15, '2026-04-03', '2026-04-03', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "Tieslietas", "Ārpolitika", "Droni"]', '["Latvia is the only country which has improved and is the only one in hard workers category", "Man nav ne jausmas, kāpēc Ukrainas amatpersonas ko tādu saka. Tā vienkārši nav taisnība"]', NULL, 'Bražes 8 dokumenti (7 tvīti + 1 Delfi apkopojums) turpina viņas konsekventu līniju aizsardzības un ārpolitikas jomā. Galvenās tēmas: (1) Ukrainas dronu operācijas Krimā (RT LTV ziņas), (2) MIDD apdraudējuma novērtējums — Krievija galvenais drauds, (3) Latvija vienīgā ES valsts ar tiesiskuma progresu ("hard workers" kategorija), (4) ANO Drošības padomes navigācijas rezolūcija, (5) diplomātiskās tikšanās ar Grieķiju, Bahreinu, AAE, (6) Krievijas dezinformācijas kampaņas pret Ukrainu. Delfi raksts (1043 vārdi) apkopo Baltijas drošības situāciju — dronu incidentus, Mežvieta dramatiskos brīdinājumus, Diehl Defence/IRIS-T apkopes centru Latvijā, un NATO Innovation Range testēšanu Sēlijā. Braže tajā citēta, noliedzot Krievijas iebrukuma draudus līdz 2027.g. Lielākā daļa pozīciju jau fiksētas iepriekšējās analīzēs — jaunas atsevišķas pozīcijas nav, bet turpinās konsekventa pro-Ukrainas, pro-NATO, pro-tiesiskuma līnija.', 0.85, '2026-04-03 17:29:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (244, 57, '2026-04-04', '2026-04-04', 0.0, '["Aizsardzība un drošība", "Sabiedriskie mediji"]', '["Nabadzīte atklājusi, ka ne visi ir lastovski, spalvēni, spolīši, pakrāni un tv3, ko var korumpēt ar valsts naudu un ietekmi", "Kā atpazīt kremļa un vienotības vēža vaukšķus? Pēc kopējo kuratoru iemācītā argumenta - viss nav tik viennozīmīgi"]', NULL, 'Lapsa aktīvi izplata Stoltenberga memuāru skandāla materiālus (14 tvīti/RT). Oriģinālajā saturā apsūdz Jaunās Vienotības "propagandas mašīnu" un mediju korupciju — apgalvo, ka Braže nevar kontrolēt visus medijus ar valsts naudu. Pielīdzina JV un Kremļa retoriku.', 0.85, '2026-04-04 05:56:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (247, 15, '2026-04-04', '2026-04-04', 0.0, '["Ukraina un Krievija", "Aizsardzība un drošība"]', '[]', NULL, 'Braže šodien aktīvi RT Zelenskyy par Krievijas zaudējumiem, NATO attiecību uzturēšanu (kaybaileyhutch/Newsmax), un Stoltenberga aizstāvību (LungescuOana). Visa komunikācija fokusēta uz Stoltenberga skandāla apslāpēšanu — izplata NATO ierēdņu versiju par notikumiem.', 0.8, '2026-04-04 05:57:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (251, 30, '2026-04-04', '2026-04-04', 0.0, '["Sociālā politika"]', '["Sabiedrības labklājības rādītājs ir nevis dzīves ērtību pieejamība, bet gan īpatsvars tādiem sabiedrības locekļiem, kas var veltīt laiku sabiedriskām aktivitātēm"]', NULL, 'Baško argumentē, ka Latvija ir nabadzīgāka nekā jebkad — mēra to nevis ar ērtībām, bet ar spēju piedalīties sabiedriskās aktivitātēs bez atlīdzības. Spēcīgs MMN naratīvs par sistēmisku nabadzību.', 0.85, '2026-04-04 08:39:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (256, 15, '2026-04-04', '2026-04-04', 0.0, '[]', '[]', NULL, 'Refresh: RT Stoltenberga aizstāvēšana — jau analizēts rītā', 0.5, '2026-04-04 08:41:47');
