INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (282, 15, '2026-04-04', '2026-04-04', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija"]', '["šajā grāmatas recenzijā pausto traktē kā dezinformācijas uzbrukumu NATO"]', NULL, 'Braže aktīvi aizstāv NATO un Stoltenberga mantojumu. Kritizē Baltic Sentinel recenziju par Stoltenberga grāmatu kā dezinformācijas uzbrukumu NATO. Svin NATO 77. gadadienu. Nosoda Krievijas uzbrukumus Ukrainā Lieldienu laikā.', 0.9, '2026-04-04 14:15:38');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (283, 57, '2026-04-04', '2026-04-04', 0.0, '["Aizsardzība un drošība"]', '["Pat šo politisko mūmiju nabaga Braže sazvanījusi"]', NULL, 'Lapsa asi kritizē Braži par mēģinājumu apklusināt Stoltenberga grāmatas atklājumus. Nosauc Bražes mobilizētos atbalstītājus par politiskām mūmijām. Iesaka lasīt Stoltenberga grāmatu.', 0.85, '2026-04-04 14:16:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (287, 30, '2026-04-04', '2026-04-04', 0.0, '["Sociālā politika"]', '["Mēs esam tik nabagi, kā vēl nekad iepriekš"]', NULL, 'Baško argumentē ka sabiedrības nabadzība mērāma nevis ar dzīves ērtībām, bet ar cilvēku spēju veltīt laiku sabiedriskām aktivitātēm bez atalgojuma. Valsts nevar mākslīgi radīt šādu slāni.', 0.85, '2026-04-04 14:17:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (317, 15, '2026-04-05', '2026-04-05', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija"]', '["Nav neviena NATO lēmuma,kas būtu pasliktinājis Baltijas valstu drošību."]', NULL, 'Braže turpina aktīvu NATO aizsardzības kampaņu pret buferzonas naratīvu, izplatot amatpersonu atspēkojumus. Paralēli izceļ Krievijas kara zaudējumus.', 0.83, '2026-04-05 01:43:45');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (320, 57, '2026-04-05', '2026-04-05', 0.0, '["Aizsardzība un drošība"]', '["Baisi, kādi personāži darbojas diplomātiskajā dienestā."]', NULL, 'Lapsa turpina kritizēt Latvijas diplomātisko dienestu NATO kontekstā.', 0.8, '2026-04-05 01:45:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (324, 57, '2026-04-05', '2026-04-05', 0.0, '["airBaltic"]', '["AirBaltika eksperts sajutis gaisā jaunu iespēju"]', NULL, 'Lapsa turpina RTs par NATO un koalīcijas kritiku, oriģināls saturs — sarkastisks komentārs par airBaltic.', 0.7, '2026-04-05 09:17:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (326, 15, '2026-04-05', '2026-04-05', 0.0, '[]', '[]', NULL, 'Lieldienu sveicieni un NASA RT, nav politiskā satura.', 0.5, '2026-04-05 09:18:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (342, 72, '2026-04-05', '2026-04-05', 0.0, '["Budžets un finanses", "Imigrācija", "Inovācijas", "Valsts pārvalde", "Ukraina un Krievija", "Sociālā politika"]', '["Ja izdevumi aug ātrāk nekā ekonomika, tā nav attīstība – tā ir stagnācija ar skaistu nosaukumu.", "Migrācijas jautājums nav tikai par ekonomiku vai darbaspēku. Tas ir par valsts drošību.", "Mēs nevaram atļauties budžetu, kuru neviens līdz galam nesaprot."]', NULL, 'Indriksone fokusējas uz budžeta caurspīdīgumu, ekonomiskās izaugsmes nepietiekamību, stingru imigrācijas kontroli un MI izmantošanu valsts pārvaldē. Kritizē koalīciju par slepenību Krievijas tirdzniecības jautājumā.', 0.85, '2026-04-05 15:35:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (355, 6, '2026-04-06', '2026-04-06', 0.0, '["Saeimas balsojumi"]', '[]', NULL, 'Pārskatīti 20 dokumenti (Saeimas balsojumi no 26.03.2026). Visi 20 balsojumi jau ir reģistrēti esošajās pozīcijās — jaunu pozīciju nav.', 0.9, '2026-04-06 12:46:58');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (356, 15, '2026-04-06', '2026-04-06', 0.0, '["Ukraina un Krievija", "Ārpolitika", "Irāna"]', '["Butcher in kremlin murdering children, women, elderly on the Easter day, night, every day. russia''s world and values in action.", "We discussed the ongoing negotiations in the UN SC and importance of restoring freedom of navigation, and stability in the Middle East. I expressed solidarity with the victims of Iran''s attacks."]', NULL, 'Baiba Braže 2026-04-05/06: Divi saturīgi oriģinālie tvīti. (1) Nosoda Krieviju par civiliedzīvotāju nogalināšanu Lieldienās, aicina palielināt atbalstu Ukrainai un pastiprināt sankcijas pret Krieviju. (2) Saruna ar Saūda Arābijas ĀM par ANO DP sarunām, navigācijas brīvību un Tuvo Austrumu stabilitāti, solidaritāte ar Irānas uzbrukumu upuriem. Pārējie 18 dokumenti — retweetoti bez komentāriem vai svinību apsveikumi.', 0.85, '2026-04-06 12:48:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (362, 10, '2026-04-06', '2026-04-06', 0.0, '[]', '[]', NULL, 'Visi 20 dokumenti ir Saeimas balsojumi no 26.03.2026, kas jau ir reģistrēti kā pozīcijas. Nav jaunu saturīgu dokumentu.', 0.9, '2026-04-06 12:55:14');
