INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (392, 57, '2026-04-06', '2026-04-06', -0.4, '["Aizsardzība un drošība", "Koalīcija un partijas", "Valsts pārvalde", "Sabiedriskie mediji"]', '["Nosaukt autentiska primārā avota analīzi par dezinformāciju nozīmē likt uz spēles visu, ko Latvija ir uzbūvējusi dezinformācijas cīņā", "Glupais un arogantais ministres izstrādājums varētu paskaidrot - kā izpaužas solidarizēšanās ar uzbrukumu upuriem"]', NULL, 'Intensīvs retweetu un komentāru periods. Galvenās tēmas: Stoltenberga buferzonu debates turpinās — RT Pietiek, Liepnieks. Kritizē JV iepirkumu reformu kā korupciju veicinošu. Kritizē ministri par nekompetenci. Rinkēvičs dodas atvaļinājumā skandāla laikā.', 0.7, '2026-04-06 13:03:35');
