INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (424, 57, '2026-04-08', '2026-04-08', 0.0, '[]', '[]', NULL, 'Nav saturīgu politisku pozīciju — galvenokārt RT vai nesaturīgi ieraksti.', 0.5, '2026-04-08 14:46:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (436, 10, '2026-04-08', '2026-04-08', 0.0, '["Valsts kapitālsabiedrības"]', '["valsts kapitālsabiedrības iepirkuos uzvarētu laulātā dzīvesbiedra uzņemums un es saglabātu amatu"]', NULL, 'Kulbergs turpina Rīgas Siltums izmeklēšanu — pēc komandējumu izdevumu atklāšanas (doc 12939), tagad norāda uz iespējamiem interešu konfliktiem RS iepirkumos (laulātā uzņēmums uzvar iepirkumā). Doc 12938 — raidījuma anons, nav politiskas pozīcijas.', 0.7, '2026-04-08 14:49:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (440, 26, '2026-04-08', '2026-04-08', 0.0, '["Transports", "Degviela un enerģētika"]', '["Valstij ir jāpalīdz iedzīvotājiem Tuvo Austrumu kara izraisītās degvielas cenu kāpuma ietekmes mazināšanā", "Samazinot vilciena abonementu cenu par 50% uz trim mēnešiem, mērķis ir palielināt 30 dienu abonementu skaitu par 100 000 līdz 200 000"]', NULL, 'Švinka konkretizē vilciena mēnešbiļešu 50% samazinājuma mērķi — 100-200 tūkst. jaunu abonentu. Pamato ar degvielas krīzes sociālo ietekmi un 12M EUR iespējamo iedzīvotāju ietaupījumu.', 0.85, '2026-04-08 14:51:03');
