INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (881, 26, '2026-04-08', '2026-04-08', 0.0, '["airBaltic", "Transports", "Koalīcija un partijas", "Droni"]', '["Ir būtiski nodrošināt uzņēmuma nepārtrauktu operacionālo darbību laikā, kad ārējie faktori aviācijas nozari ietekmē īpaši spēcīgi"]', NULL, 'Svinka iesniedza airBaltic aizdevuma jautājumu MK sēdē. Paziņoja par drona nokrišanu Krāslavas novadā. Tika apstrīdēts ZZS demisijas balsojumos, bet paliek amatā.', 0.88, '2026-04-09 13:49:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (883, 30, '2026-04-03', '2026-04-03', 0.0, '["MMN", "Vēlēšanas", "Ārpolitika"]', '["Mēs augam", "MMN cer uz 51 vietu Saeimā"]', NULL, 'Baško signalizē aktīvu MMN partijas veidošanu. RT Orbāna "Budapest Proclamation" - ievērojams ģeopolitiskais signāls. Kritizē "zinātniski balstīto" domu virzienu.', 0.8, '2026-04-09 13:51:19');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (899, 15, '2026-04-10', '2026-04-10', 0.0, '["Ārpolitika"]', '[]', NULL, '7 retvīti bez komentāriem — Serbija, Zviedrijas Archer, Liepāja kultūras galvaspilsēta, Kosova UNSC, bērnu pēcpusdiena ĀM, Memorial likvidēšana Krievijā, EU Conversations atklāšana.', 0.3, '2026-04-10 08:07:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (902, 6, '2026-04-10', '2026-04-10', 0.0, '["Ukraina un Krievija", "Tieslietas"]', '["Tas ir labi, ka Rosļikovs ir devies prom."]', NULL, 'Dombrava atbalsta Rosļikova aizbraukšanu no Latvijas un aicina citus Kremļa atbalstītājus sekot.', 0.75, '2026-04-10 08:07:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (908, 30, '2026-04-10', '2026-04-10', 0.0, '["Vēlēšanas"]', '["Atbildības uzņemšanās nesākas tad, kad iegūst amatu. Tā sākas brīdī, kad jūs piesakāties uz konkursu"]', NULL, 'Baško eseja par atbildības uzņemšanos kandidējot uz amatiem — vispārīgs pilsoniskais pārdomājums.', 0.5, '2026-04-10 08:09:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (912, 57, '2026-04-10', '2026-04-10', 0.0, '["Tieslietas", "Koalīcija un partijas", "Valsts pārvalde"]', '["Tiešām kāds domāja, ka \"Vienotības\" vēzim un tā @edgarsrinkevics ir kaut mazākā nojēga - kas tas Neikens tāds?", "Iesaku izlasīt tiem, kuri cerēja, ka līdz gļēvā noziedznieka Stukāna vietā nāks ģenerālprokurors, kurš rūpēsies par tiesiskumu un likuma varu", "Prokuratūras āksts un apkaunojums, kurš pats neko nezina, neko nevar izskaidrot, neko nespēj aprēķināt", "Šitas ir no tiem, kuri arī 1949.gada 26.martā aplaudēja staļiniskajiem bendēm un vēstīja - valsts pārvaldīšana ir sarežģīta lieta"]', NULL, 'Lapsa turpina kritiku pret jauno ģenerālprokuroru Meisteru un prokuratūras darbu konkrētās lietās. Papildus retoriski uzbrukumi Vienotībai un prezidentam Rinkēvičam. Liela daļa dokumentu ir RT bez komentāra vai humora tvīti bez politiska satura.', 0.8, '2026-04-10 09:39:43');
