INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1056, 15, '2026-04-10', '2026-04-10', 0.0, '["Ukraina un Krievija"]', '["Tikpat svarīgi kā situācija frontē, ka Ukraina nezaudē... tikpat svarīgi ir parādīt Ukrainai, ka atbalsts taisnīgumam, ka Krievijas agresija nepaliks nesodīta"]', NULL, 'Bučas gadadienā uzsver saukšanu pie atbildības par Krievijas kara noziegumiem kā vienlīdz svarīgu militārajam atbalstam', 0.8, '2026-04-10 20:04:59');
