INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1285, 15, '2026-04-11', '2026-04-11', 0.0, '["Ukraina un Krievija", "Aizsardzība un drošība", "Ārpolitika"]', '["Russia should accept it and get serious to end the war.", "Canada''s leadership of NATO''s Multinational brigade in Latvia is outstanding."]', NULL, 'Braže turpina konsekventu pro-Ukraina/anti-Krievijas līniju: kopīgs Baltijas ĀM paziņojums par Krievijas dezinformācijas kampaņu, atbalsts Ukrainas pamieram, darbs pie Īpašā tribunāla praktiskās izveides ANO DP ietvaros. Aizsardzības jomā — padziļināta sadarbība ar Kanādu un NATO brigādi Latvijā.', 0.85, '2026-04-11 08:26:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1286, 57, '2026-04-11', '2026-04-11', 0.0, '[]', '[]', NULL, 'Lato Lapsa 16 dokumenti 2026-04-11: lielākā daļa ir retweets bez komentāra (10), pārējie ir personīgi/literāri ieraksti par viņa grāmatu par latviešu strēlniekiem, triviāli joki un sarkastiskas piezīmes bez skaidras politiskas pozīcijas. Nav ekstrahējamu pozīciju.', 0.5, '2026-04-11 08:26:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1302, 26, '2026-04-11', '2026-04-11', 0.0, '["Transports"]', '["Strādājam pie vienotas un caurskatāmas taksometru pārvadājumu sistēmas visā Latvijā."]', NULL, 'Švinka virza vienotu taksometru pārvadājumu sistēmu — samazināt sadrumstalotību, birokrātiju, uzlabot cenas pasažieriem.', 0.85, '2026-04-11 08:27:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1306, 10, '2026-04-11', '2026-04-11', 0.0, '["Transports", "Degviela un enerģētika"]', '["Lūk, kas notiek, kad savā arogancē jūs nerunājat ar sabiedrību.", "atpakaļ cenas tādā līmenī, kādā tās bija un kādā mēs gribētu, neatgriezīsies"]', NULL, 'Kulbergs kritizē Satiksmes ministrijas (Progresīvo/Švinkas) jaunos grozījumus, jo tie neparedzot izņēmumus mobilitātes palīglīdzekļiem, uzskatot to par arogantas komunikācijas sekām. Atsevišķā TV24 raidījumā prognozē, ka degvielas cenas neatgriezīsies iepriekšējā līmenī un nākamajā ziemā sagaidāmas augstākas elektrības un siltuma cenas. Tvīts par airBaltic vadītāja Cālīša zaudējumu un retvīts par Rail Baltica Iecavas posmu ir bez politiskas pozīcijas.', 0.75, '2026-04-11 08:28:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1311, 57, '2026-04-11', '2026-04-11', 0.0, '["Aizsardzība un drošība"]', '["Interesanti - tieši kā (ņemot vērā, ka krievi ukraiņus iznīcina akurāt tāpat) Latvijas karavīrus pasargās koruptā Sprūda un kompānijas sapirktās dārgās konservbundžas, pārējā modernajam karam nederīgā draza un investīcijas kazarmu betonā?"]', NULL, 'Lapsa turpina kritizēt aizsardzības ministru Sprūdu — šoreiz par iepirkumu prioritātēm, kas, pēc viņa domām, neatbilst modernā kara prasībām (atsauces uz Ukrainas pieredzi). Pārējie 14 dokumenti ir RT, personiski komentāri vai vispārīga retorika bez konkrētām politiskām pozīcijām.', 0.75, '2026-04-11 18:24:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1312, 15, '2026-04-11', '2026-04-11', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "Ārpolitika"]', '[]', NULL, 'Dienas saturs dominē ar ceremoniāliem ierakstiem par diplomāta Oļģerta Pavlovska nāvi (pašas tvīts + RT + mediju atstāsti) un NATO Parlamentārās asamblejas uzrunu Rīgā, kurā atkārtoti tiek pausta jau iepriekš dokumentētā pozīcija par NATO vienotību un 5% IKP aizsardzības finansējumu. Jaunu, atšķirīgu politikas pozīciju nav. Pārējie dokumenti ir retweeti bez komentāriem (Ukrainas sankcijas, Ungārijas ĀM, UNIFIL Libānā, airBaltic). Tie nav Bražes pašas pozīcijas.', 0.7, '2026-04-11 18:24:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1323, 30, '2026-04-11', '2026-04-11', 0.0, '[]', '[]', NULL, 'RT no partijaMMN — nepilna citata.', 0.3, '2026-04-11 18:26:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1334, 15, '2026-04-12', '2026-04-12', 0.0, '[]', '[]', NULL, 'Trīs tvīti: divi retweeti (NATO PA vizīte Ādažos, UNIFIL/Izraēla) un Lieldienu sveiciens Ukrainas ĀM. Nav pirmās personas pozīciju.', 0.0, '2026-04-12 19:13:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1340, 10, '2026-04-12', '2026-04-12', 0.0, '[]', '[]', NULL, 'Doc 14811 ir trešās personas tvīts par Siliņas IT projektu. Doc 14812 ir citas personas atbilde Kulbergam. Nav Kulberga pirmās personas pozīciju.', 0.0, '2026-04-12 19:13:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1348, 26, '2026-04-12', '2026-04-12', 0.0, '["Valsts kapitālsabiedrības"]', '["Tiek virzīts risinājums par deleģējuma līgumu ar LVRTC nākamajiem 10 gadiem. Atbalstu šo un uzsveru, ka attiecīgais lēmums jāpieņem tuvākajās valdības sēdēs"]', NULL, 'Švinka publiski atbalsta LVRTC turpināt e-Paraksta pakalpojuma pārvaldīšanu ar 10 gadu deleģējuma līgumu un aicina valdību ātri pieņemt lēmumu, norādot uz pakalpojuma drošību un LVRTC pierādīto kompetenci.', 0.85, '2026-04-12 19:14:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1353, 57, '2026-04-12', '2026-04-12', 0.0, '["Koalīcija un partijas", "Sabiedriskie mediji"]', '["\"Vienotības\" vēža nekauņas ir nosprieduši, ka viņiem šajā valstī ir atļauts viss. Būs jāatbild, @Braze_Baiba.", "Ķirmis grib būt kopā ar koku. Pelējuma sēne grib būt kopā ar ievārījumu. Vienotības vēzis grib būt kopā ar ungāru tautu.", "Būs jāpalūdz ltvzinas, lai nopublicē pilnu ombuda atbildi uz manu iesniegumu.", "Vai Jūs šeit saskatāt \"sabiedriskās\" Latvijas Televīzijas Ziņu dienesta vadītājas godīgas un atklātas atbildes uz uzdotajiem jautājumiem?"]', NULL, 'Lato Lapsa turpina asu Vienotības kritiku — pārmet Baibai Bražei nomelnošanu un formas tērpa ļaunprātīgu izmantošanu, salīdzina partiju ar parazītu. Paralēli turpina publisku spiedienu uz LTV Ziņu dienestu, pieprasot ombuda atbildes pilnu publiskošanu un apšaubot LTV Ziņu vadītājas Ivetas Elksnes godīgumu.', 0.75, '2026-04-12 19:20:58');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1354, 15, '2026-04-12', '2026-04-12', 0.0, '["ES politika"]', '["Ungārija izdarīja izvēli un tā noteikti ir eiropeiskāku un mazāk proKrievijas. Apsveikumi ungāriem un visiem eiropiešiem!"]', NULL, 'Braže apsveic ungārus ar vēlēšanu rezultātu, uzsverot, ka Ungārija izvēlējusies eiropeiskāku un mazāk prokrievisku ceļu. Pārējie dokumenti ir retweeti bez komentāriem vai ziņu raksti, kas atkārto to pašu pozīciju.', 0.8, '2026-04-13 06:00:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1355, 57, '2026-04-12', '2026-04-12', 0.0, '["Transports", "Vēlēšanas", "Sabiedriskie mediji", "Tieslietas"]', '["Kad progresīvo sarkanās sērgas vadītā Satiksmes ministrija sola, ka tā izveidos vienotu un caurskatāmu taksometru pārvadājumu sistēmu, pilnīgi drošas ir trīs lietas.", "Ungārijas Vienotība ar visu savu administratīvo resursu, ar saviem balsu skaitītājiem un ar savām sabiedrisko mediju prostitūtām nav spējusi nozagt vēlēšanas. Atcerieties to oktobrī.", "Ombuda atzinums: premjerministre intervijā pasaka aplamību, bet sabiedriskais medijs teikto slepus labo un maldina sabiedrību", "Klausoties Latvijas sabiedrisko mediju propagandonu skaļajā līksmībā, varu derēt, ka viņiem garām paslīdējuši divi zīmīgi punkti no Ungārijas vēlēšanu uzvarētāja priekšvēlēšanu solījumiem"]', NULL, 'Lapsa 2026-04-12: 14 tvīti, 8 retvīti bez komentāra (izlaisti). No 6 oriģinālajiem tvītiem — 5 satur politiskas pozīcijas. Kritizē Progresīvo vadīto Satiksmes ministriju par taksometru reformu, salīdzina Vienotību ar Ungārijas Fidesz kontekstā par vēlēšanu godīgumu, kritizē sabiedriskos medijus par PM Siliņas aizsargāšanu un propagandu, norāda uz korupciju policijā.', 0.75, '2026-04-13 06:00:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1358, 10, '2026-04-12', '2026-04-12', 0.0, '["airBaltic"]', '["Aviācijas degviela tiktiešām ir milzu problēma", "Lūk šeit es gribu zināt patieso AB stāstu, cik simtus miljonu tam v"]', NULL, 'Kulbergs norāda uz aviācijas degvielas cenu trīskāršošanos un prasa pilnīgu airBaltic finanšu caurskatāmību.', 0.8, '2026-04-13 06:01:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1376, 6, '2026-04-13', '2026-04-13', 0.0, '["Imigrācija", "Sabiedriskie mediji"]', '["Publiski iebilstu pret masveida imigrāciju un latviešu aizstāšanu ar imigrantiem.", "Valsts policija sniedz skaidru brīdinājumu Saeimas Imigrācijas izmeklēšanas komisijā"]', NULL, 'Dombrava aizstāvēja savu anti-imigrācijas pozīciju pēc Re:Baltica publikācijas un dalījās ar Valsts policijas brīdinājumu par etnisku noziedzīgu grupu veidošanās riskiem.', 0.85, '2026-04-13 19:50:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1377, 15, '2026-04-13', '2026-04-13', 0.0, '["ES politika"]', '["Atklāju Ārlietu semināru ar Eiropas Komisijas DG Growth vadību Latvijas uzņēmējiem, pētniekiem, NVO, publisko sektoru par nākamo ES Daudzgadu budžetu un tā Konkurētspējas fondu"]', NULL, 'Braže atklāja ĀM semināru ar EK DG Growth par ES Daudzgadu budžetu un Konkurētspējas fondu. Pārējie dokumenti ir RT bez personīga komentāra.', 0.7, '2026-04-13 19:50:57');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1386, 26, '2026-04-13', '2026-04-13', 0.0, '["Transports"]', '["Nozares attīstību uztveru nopietni, un jau pagājušajā nedēļā iesniedzu konkreetus priekšlikumus jomas sakārtošanai"]', NULL, 'Švinka iesniedza konkrētus priekšlikumus taksometru nozares sakārtošanai un piedalās airBaltic diskusijā ka satiksmes ministrs.', 0.8, '2026-04-13 20:01:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1397, 57, '2026-04-13', '2026-04-13', 0.0, '[]', '[]', NULL, '19 dokumenti: visi RT bez personīga komentāra vai sarkastiski izteikumi bez skaidras politiskas pozīcijas. Nav ekstrahējamu pozīciju.', 0.5, '2026-04-13 20:08:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1404, 57, '2026-04-13', '2026-04-13', 0.0, '["Koalīcija un partijas", "Tieslietas"]', '["Mans šīrīta iesniegums ģenerālprokuroram Meisteram par Vienotības braucienu uz Komo ezeru.", "jātērē savs laiks, lai uzrakstītu dažus iesniegumus par šiem Vienotības vēža agonējošajiem politsprāgoņām un viņu saņemto dāvaniņu"]', NULL, 'Lapsa turpina kampaņu pret Jauno Vienotību — iesniedz ģenerālprokuroram materiālus par JV braucienu uz Komo ezeru pie Adenauera fonda un raksta iesniegumus par JV politiķu saņemtajām dāvanām. Pārējie tvīti ir retvīti bez komentāriem vai personiski uzbrukumi.', 0.75, '2026-04-14 07:20:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1406, 15, '2026-04-13', '2026-04-13', 0.0, '["Aizsardzība un drošība"]', '["French Rafale have landed at Lielvarde airbase in Latvia at #NATO air policing mission."]', NULL, 'Braže atzīmē Francijas Rafale iznīcinātāju ierašanos Lielvārdes aviobāzē NATO gaisa telpas patrulēšanas misijā. Pārējie tvīti ir retvīti.', 0.6, '2026-04-14 07:21:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1411, 10, '2026-04-13', '2026-04-13', 0.0, '["airBaltic"]', '["šeit Siliņai jāliek galdā skaidrs 380milj EUR parāda restrukturizācijas plāns. Ja tāda nav, tad mēs visi zinam ar ko šī atkarība beigsies."]', NULL, 'Kulbergs pieprasa no premjeres Siliņas skaidru airBaltic 380M EUR parāda restrukturizācijas plānu. Kritizē airBaltic kā hronisku nodokļu naudas atkarībnieku.', 0.9, '2026-04-14 07:24:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1418, 30, '2026-04-13', '2026-04-13', 0.0, '["Koalīcija un partijas"]', '["konservatīvie zina, kas ir viņu vērtības, viņi tic absolūtai patiesībai, taču nesaprot, kas ir politika"]', NULL, 'Baško skaidro, kāpēc konservatīvie Latvijā nevar apvienoties — politika nav par absolūtas patiesības uzspiešanu, bet par brīvības telpas saglabāšanu. Konservatīvajiem jārespektē sava despotisma robežas.', 0.7, '2026-04-14 07:27:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1424, 57, '2026-04-14', '2026-04-14', 0.0, '["Koalīcija un partijas"]', '["Palīdzēsim partijai ievērot visaugstākos ētikas standartus bez neaizrīšanās, neapvemšanās un siekalošanās."]', NULL, 'Lato Lapsa turpina sarkastiski kritizēt JV ētikas standartus saistībā ar Itālijas semināra skandālu un KNAB izmeklēšanu.', 0.65, '2026-04-14 21:04:49');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1431, 10, '2026-04-14', '2026-04-14', 0.0, '["airBaltic", "Valsts kapitālsabiedrības"]', '["AirBaltic lielākā problēma, tas, kas noteiks dzīvot/nedzīvot, ir 380 miljonu EUR aizņēmums par plēsonīgu aizņēmuma likmi", "Es aicinu Eviku Siliņu nākt pie likumdevēja ar šādu skaidru risinājumu, nevis ielāpu uz pāris mēnešiem"]', NULL, 'Kulbergs pieprasa airBaltic parāda restrukturizāciju kā priekšnoteikumu valsts finansējumam. Aicina premjeri nākt ar ilgtermiņa risinājumu. Arī informē par Rīgas Siltums izmeklēšanas komisijas sēdi.', 0.75, '2026-04-14 21:05:49');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1432, 15, '2026-04-14', '2026-04-14', 0.0, '[]', '[]', NULL, 'Visas 17 Bražes dokumenti ir retivīti bez komentāra — nav izvelkamu pozīciju.', 0.0, '2026-04-14 21:06:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1441, 6, '2026-04-14', '2026-04-14', 0.0, '["Imigrācija"]', '["Darbošanās ap šādiem imigrantiem mēdz izmaksāt vairākus desmitus tūkstošus eiro", "Latviešiem nav jāsamierinās ar to, ka tiekam aizstāti ar imigrantiem"]', NULL, 'Dombrava turpina konsekventu anti-imigrācijas pozīciju. Norāda uz patvēruma meklētāju cirkulācijas problēmu starp Baltijas valstīm un Poliju un tās izmaksām. Otrajā tvītā iebilst pret imigrāciju kā latviešu aizstāšanu.', 0.75, '2026-04-14 21:07:25');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1458, 26, '2026-04-15', '2026-04-15', 0.0, '[]', '[]', NULL, 'Pieminējums Valainis intervijā — Švinkas pozīcija nav tieši citēta.', 0.5, '2026-04-15 07:29:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1460, 30, '2026-04-15', '2026-04-15', 0.0, '[]', '[]', NULL, 'Sarkastisks komentārs — nav politiskas pozīcijas.', 0.5, '2026-04-15 07:29:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1464, 57, '2026-04-15', '2026-04-15', 0.0, '["Tieslietas"]', '["Kāds aizkustinošs stulbums - Meistera prokuratūra jau kopš vakardienas cenšas izlikties, ka nav saņēmusi iesniegumu par Komo ezera braucienu."]', NULL, 'Lapsa kritizē prokuratūru par Komo ezera iesnieguma ignorēšanu. Pārējie 19 tvīti ir RT par Citskovska/Siliņas skandālu un JV kritiku.', 0.85, '2026-04-15 07:30:25');
