INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1529, 15, '2026-04-17', '2026-04-17', 0.0, '["Ukraina un Krievija"]', '["Latvia’s continued military and humanitarian support for Ukraine"]', NULL, 'Ārlietu ministre Baiba Braže 16.-17. aprīlī publiski aktīva — viens pirmās personas izteikums (tikšanās ar Ukrainas ĀM vietnieci Mariana Betsa Rīgā, apstiprinot militāro/humanitāro atbalstu Ukrainai, sadarbību ANO DP, atbildību par Krievijas noziegumiem) un 16 retvīti (RT @) bez pievienotiem komentāriem — saturs par Ukrainu, Krievijas uzbrukumiem, VIP zāļu jautājumu, AirBaltic balsojumu. Retvīti nav atsevišķas pozīcijas.', 0.85, '2026-04-17 07:46:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1536, 10, '2026-04-17', '2026-04-17', 0.0, '["airBaltic", "Budžets un finanses", "Koalīcija un partijas"]', '["MANA NEBALSOŠANA ir apzināts protests pret pēdējā minūtē uz galda uzmestiem, nesaprotamiem, neinformētiem lēmumiem.", "Kādā sakarā Parlamentam ir jābalso uz aklo par 30mil € injekciju AB = tā ir totāla valdības neizdarība"]', NULL, 'Kulbergs 17. aprīlī turpināja savu konsekvento airBaltic līniju: apzināti nebalsoja Saeimā par 30 miljonu eiro injekciju kā protestu pret valdības pēdējā brīža pieeju bez restrukturizācijas plāna. Tribīnes runā sniedza detalizētu argumentāciju — 30M€ esot nepietiekami, vajagot 300M€, lai risinātu 380M€ obligāciju slogu (53M€ gadā procentos). Vaino Siliņas valdību par atbildības pārlikšanu uz Parlamentu.', 0.9, '2026-04-17 07:47:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1546, 30, '2026-04-17', '2026-04-17', 0.0, '["Vēlēšanas"]', '["Trīsdesmit gadus \"stiprinām\" partiju sistēmu un partijas kļūst arvien švakākas, jo ar plusiņiem un mīnusiem nekas cits nav gaidāms"]', NULL, 'Kritizē pašreizējo proporcionālo vēlēšanu sistēmu ar plusiņiem un mīnusiem kā iemeslu partiju sistēmas 30 gadu pavājināšanos. Implicēts atbalsts MMN sistēmas maiņas piedāvājumam. Atkārto esošo pozīciju (claim 6841) ar vēsturisku framing.', 0.8, '2026-04-17 08:01:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1547, 57, '2026-04-17', '2026-04-17', 0.0, '["Tieslietas", "Koalīcija un partijas", "Imigrācija"]', '["Aizliegums saukt lietas īstajos vārdos ir tikai veids, kā aizsargāt zagli un prokuratūru", "Cilvēkiem ir bail, bet mums liek turēt muti migrantu jautājumos", "Un šis progresīvo idiots tagad ielikts vadīt Saeimas Tautsaimniecības komisiju."]', NULL, 'Lato Lapsa 17.04. turpina agrāko retorisko līniju: asa kritika tiesībsargājošām iestādēm (policija, prokuratūra — "mentu zaņķis"), JV un Progresīvo politiķu izsmiešana ("sarkanā varza", "idiots"), un Pietiek.com redakcionālās līnijas pastiprināšana par migrācijas diskursa ierobežošanu. Lielākā daļa dienas aktivitātes ir trešo pušu retvīti bez personiskiem komentāriem.', 0.75, '2026-04-17 08:01:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1548, 6, '2026-04-17', '2026-04-17', 0.0, '["Imigrācija"]', '["Imigrācijas izmeklēšanas komisijā konstatējām šīs un vairākas citas problēmas, kas rada problēmas ar trešvalstnieku nodarbinātību LV."]', NULL, 'Atbildē Nepareizajam apstiprina, ka Imigrācijas izmeklēšanas komisija ir konstatējusi problēmas ar trešvalstnieku nodarbinātību Latvijā. Norāda uz gaidāmo gala ziņojumu ar secinājumiem par nepieciešamajām izmaiņām nodarbinātības jomā.', 0.85, '2026-04-17 08:01:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1563, 26, '2026-04-17', '2026-04-17', 0.0, '["Valsts kapitālsabiedrības"]', '[]', NULL, 'Švinka 17. aprīļa LTV "Rīta Panorāmā" — dienu pēc Saeimas apstiprinātā airBaltic 30M aizdevuma un Siliņas paziņojuma par SM reorganizāciju — izvirza ideju par centralizētu valsts kapitālsabiedrību pārvaldību, sadarbojoties vairākām ministrijām. Tas parādās kontekstā, kurā premjere pieprasa airBaltic rentabilitātes nodrošināšanu un SM reorganizāciju. Papildus 16.04. Delfi publicēta ministra VID deklarācija (ienākumi 169 938 EUR 2025. gadā) — ne politiska pozīcija.', 0.8, '2026-04-17 08:02:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1566, 57, '2026-04-17', '2026-04-17', 0.0, '[]', '[]', NULL, 'Intraday pārskats (2026-04-17 pēcpusdiena): 16 jauni dokumenti, visi no X/Twitter. 14 ir tīri retviti bez Lapsas paša komentāra (citu balsis par Švinkas ieroča lidošanas epizodi, airBaltic, KNAB, Vienotības ministriem, suņu kakām Lielajos kapos u.c.). 2 ir Lapsas paša īsie ieraksti — 21134 (''Progresīvo sērgai Briškena pālis un Kotello strīpas'') ir ironiska kritika, bet bez konkrētas politikas pozīcijas; 21127 (''Nu tiešām nav, kur citur sēdēt'') ir kriptisks memes ieraksts ar attēla saiti. Stingri piemēroju noteikumu: retviti bez autora komentāra nav Lapsas pozīcija, un snark bez konkrēta policy stance netiek ekstraģēts. Nekādas jaunas pozīcijas šajā intraday refresh; visi 16 dokumenti marķēti kā pārskatīti.', 0.7, '2026-04-17 17:40:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1569, 26, '2026-04-17', '2026-04-17', 0.0, '["airBaltic", "Rail Baltica", "Transports", "Valsts pārvalde"]', '["Jā, mēs atpaliekam, sportistu terminoloģijā, par vairākiem apļiem", "Es nesu politisko atbildību par katru lēmumu, ko virzu un parakstu"]', NULL, 'Intraday atjauninājums 2026-04-17: Švinka atzīst Rail Baltica atpalicību aiz Lietuvas/Igaunijas un sola paātrinājumu + finansējuma skaidrību. Precizē, ka airBaltic IPO 2026. gadā nenotiks, bet ilgtermiņā ir mērķis. Saeimā aizstāv 30M EUR aizdevumu kā ''kontrolētu pārejas mehānismu'' un uzņemas pilnu politisko atbildību. Nav informēts par SM reorganizāciju, ko paziņoja premjere. Skaidro mikromobilitātes regulējuma drošības mērķus.', 0.82, '2026-04-17 17:41:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1570, 15, '2026-04-17', '2026-04-17', 0.0, '["Ukraina un Krievija", "Ārpolitika", "Irāna", "Aizsardzība un drošība"]', '["Tā vienkārši nav taisnība", "steidzami apstiprinot ES sankciju 20. kārtu"]', NULL, 'Braže intraday: ES Ārlietu padomē (13.04) aicina apstiprināt 20. sankciju kārtu un vērsties pret Krievijas ēnu floti; noraida Ukrainas izlūkdienestu apgalvojumu par Krievijas plāniem okupēt Baltiju līdz 2027. gadam; pauž gatavību Latvijai izvērtēt palīdzību sabiedrotajiem Hormuza šauruma jautājumā; BBC intervijā aicina izolēt Krieviju no Venēcijas biennāles un starptautiska sporta.', 0.85, '2026-04-17 17:41:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1586, 6, '2026-04-17', '2026-04-17', 0.0, '["Imigrācija"]', '["Latvija jau ir pārsniegusi savu kapacitāti imigrantu uzņemšanai"]', NULL, 'Dombrava publiski koncentrējas uz imigrācijas kontroles pastiprināšanu: kritizē LDDK un ministrijas par bezdarbību, pauž, ka Latvija sasniegusi uzņemšanas kapacitātes robežu, un iebilst pret publisku islāma lūgšanu.', 0.85, '2026-04-17 17:50:39');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1606, 72, '2026-04-17', '2026-04-17', 0.0, '[]', '[]', NULL, 'Nav ekstrahējamu pozīciju: vienīgais mediju dokuments ir retvīts bez komentāra.', 0.3, '2026-04-17 17:56:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1613, 30, '2026-04-17', '2026-04-17', 0.0, '[]', '[]', NULL, 'Dokumentā Baško netiek pieminēts — pārklāšanās ar Baškortostānas reģiona nosaukumu.', 0.2, '2026-04-17 18:00:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1632, 57, '2026-04-18', '2026-04-18', 0.0, '["Aizsardzība un drošība", "Koalīcija un partijas"]', '["Nu tak nevarētu būt, ka ģenerālis uzspļauj virsnieka godam un glābj \"Vienotības\" stulbenes ādu"]', NULL, 'Lato Lapsa 18.aprīlī aktivitāte galvenokārt RT formā — atbalsta sekotāju komentārus par Bražes formas tērpa lietu, NBS skaidrojumiem, airBaltic nodokļiem, Liepājas cietumu, ekonomikas ministra komentāriem. Vienīgais oriģinālais ieraksts tieši kritizē NBS ģenerāli par to, ka armijas vadība esot devusi Bražei aizsegošu skaidrojumu, kas, pēc Lapsas, pārkāpj virsnieka ētiku. Visi RT konsekventi turpina Lapsas iepriekšējās tendences — kritisks pret Vienotību, tiesībsargājošām iestādēm un valsts pārvaldi.', 0.7, '2026-04-18 08:11:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1636, 10, '2026-04-18', '2026-04-18', 0.0, '[]', '[]', NULL, 'Divi tvīti — abi tīri retvīti bez personīga komentāra. Pirmais (RT @Elina_Treija) par Raivja Kronberga un Rīgas satiksmes padomes lomu; otrais (RT @LA_lv) par rakstu, kurā ziņots par paša Kulberga jautājumu par slēpto elektrības nodokli un Latvenergo lomu. Tā kā Kulbergs nav pievienojis personīgu komentāru, no šiem retvītiem nav iespējams ekstrahēt jaunu pozīciju, kas atšķirtos no jau esošā ieraksta.', 0.5, '2026-04-18 08:11:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1639, 15, '2026-04-18', '2026-04-18', 0.0, '["Ukraina un Krievija", "Ārpolitika", "Aizsardzība un drošība"]', '["Great to sit down with Ukraine''s Foreign Minister @andrii_sybiha for a longer conversation on next steps in Euroatlantic integration, containing Russia, getting to a last and sustainable peace in Ukraine.", "Latvia welcomes 10-day ceasefire between Israel and Lebanon, as well as direct talks between them, both brokered by the U.S. This is a chance to agree lasting security and peace between them. It requires the disarmament of Hezbollah and full respect for Lebanon''s sovereignty.", "Will highlight Latvia''s decision to enshrine in law 5% of GDP for defence, in accordance with NATO Hague Summit decisions, and our commitment to contribute to keeping Hormuz straits open."]', NULL, 'Baiba Braže 2026-04-18: aktīva ārpolitiska komunikācija ADF2026 forumā un divpusējās tikšanās. Tikšanās ar Ukrainas ĀM Sibiha — uzsver Eiroatlantisko integrāciju, Krievijas savaldīšanu, ilgstošu mieru. Atbalsta Izraēlas-Libānas 10 dienu pamieru un ASV mediāciju, prasa Hezbollah atbruņošanu un Libānas suverenitātes ievērošanu. ADF2026 panelī uzsvērs Latvijas lēmumu likumā nostiprināt 5% IKP aizsardzībai un apņemšanos sniegt ieguldījumu Hormuza šauruma atvērtības saglabāšanā. Trīs RT bez komentāriem — atzīmēti kā tukši.', 0.8, '2026-04-18 08:11:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1647, 30, '2026-04-18', '2026-04-18', 0.0, '["Vēlēšanas"]', '[]', NULL, 'Partijas MMN konts retvīto Baško izteikumu par vēlēšanu sistēmas maiņu — Baško apgalvo, ka pretēji valsts radio vēstījumam vēlēšanu sistēmas maiņa nesīs pozitīvas pārmaiņas. Tvīta saturs ir nogriezts, tāpēc detalizēti argumenti nav redzami; pozīcija atbilst Baško jau iepriekš paustajai nostājai par proporcionālās sistēmas reformu.', 0.6, '2026-04-18 08:12:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1649, 57, '2026-04-18', '2026-04-18', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-04-18: 19 dokumenti, galvenokārt retweets bez komentāriem un sarkastiskas īsas atsauksmes bez konkrētas politiskas pozīcijas. Nav ekstrahējamu pozīciju šajā dienā.', 0.7, '2026-04-18 20:42:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1657, 10, '2026-04-18', '2026-04-18', 0.0, '["Valsts pārvalde", "airBaltic", "Koalīcija un partijas"]', '["man nav pieņemama šī Saeimas kā augstākās valsts instances padarīšanu par totālu miskasti un ākstiem, kur var nest lēmumus bez seguma, informācijas un uzskatīt par balsošanas mašīnu"]', NULL, 'Kulbergs aizstāv savu rīcību airBaltic 30M EUR balsojumā, norādot, ka nav konceptuāli pret, bet iebilst pret Saeimas pārvēršanu par balsošanas mašīnu bez informācijas un seguma. Apsūdz Jauno Vienotību (JV) Saeimas kā augstākās valsts instances nicināšanā. Pārējie 4 dokumenti — trešo personu atbildes vai nepolitisks kurioza stāsts par Vecrīgu — bez atsevišķas pozīcijas.', 0.85, '2026-04-18 20:44:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1659, 15, '2026-04-18', '2026-04-18', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "Ārpolitika"]', '["It was Russia’s choice to launch an unprovoked war against Ukraine.", "Latvia is the first ally to enshrine [5% for defence] into law.", "Latvia is committed to help U.S. keeping Hormuz straits open."]', NULL, 'Braže (18.04.2026.) Antaljas Diplomātiskajā forumā #ADF2026 izteica trīs būtiskas pozīcijas: (1) prasa visām NATO sabiedrotajām uzrādīt progresu ceļā uz 5% IKP aizsardzībai Ankaras samitā, uzsverot, ka Latvija to jau nostiprinājusi likumā; (2) apstiprina Latvijas gatavību palīdzēt ASV Hormuzas šaurumā; (3) tieši noraida Krievijas naratīvu par NATO draudiem un pauž, ka Krievija Ukrainu nepakļaus. Papildus — Latvijas nosodījums Francijas UNIFIL miera uzturētāja nogalināšanai Libānā.', 0.85, '2026-04-18 20:45:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1677, 15, '2026-04-19', '2026-04-19', 0.0, '["Ārpolitika", "ES politika"]', '["I thanked Jordan for its support for the @UN resolution for lasting peace in Ukraine.", "We support Albania''s EU integration path."]', NULL, 'Braže 2026-04-19 turpina aktīvu diplomātisko darbu Antaljas forumā: tikšanās ar Jordānijas ĀM (Hormuza šaurums, atbalsts ANO rezolūcijai par Ukrainu) un Albānijas ĀM (ES integrācijas atbalsts, NATO MNB partnerība). Abas pozīcijas saskan ar iepriekšējo ārpolitikas līniju.', 0.8, '2026-04-19 10:50:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1679, 57, '2026-04-19', '2026-04-19', 0.0, '["Aizsardzība un drošība", "Sabiedriskie mediji", "Izglītība"]', '["Vai Jums nešķiet, ka nabaga ģenerālmajoram nāksies sākt nožēlot savu \"pretimnākšanu\"? Un varbūt šo to pārdomāt par tēmu \"Latvijas armijas virsnieka gods\"?", "šie jau atkal ir neizglītotie parazīti no \"sabiedriskā\" medija, kuri pat savu dzimto valodu nejēdz", "Nu, labi, biedrenes učenes, kam vai nu slinkums, vai vienkārši bailes no šīs nesaprotamās strēlnieku tēmas - ka tik nedabū rājienu no cekas… Iztiksim bez Jūsu starpniecības."]', NULL, '19. aprīlī Lapsa publicēja 17 tvītus X platformā, no kuriem 14 ir retvīti bez paša komentāra (Pietiek portāls, citu lietotāju kritika par JV, kaķīši un suņi). Trīs oriģinālie tvīti turpina viņa pastāvīgās kritikas līnijas: (1) NBS ģenerālmajora sarkastisks aizrādījums par virsnieka godu Bražes kontekstā, (2) sabiedriskā medija darbinieku nosaukšana par ''parazītiem'' un valodas nejēgām, (3) skolu/skolotāju apsūdzība par bailēm vai slinkumu izplatīt informāciju par grāmatu ''Pret likteni stāvēdami''.', 0.75, '2026-04-19 10:51:13');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1690, 57, '2026-04-19', '2026-04-19', 0.0, '["Koalīcija un partijas"]', '["Treknais \"Vienotības\" Hosams Lindu Meri par nodokļu maksātāju naudu aizlidinājās uz Kipru un atpakaļ... Tā arī notiek likumīgā zagšana."]', NULL, 'Lapsa turpina kritizēt JV par korupciju — šodienas fokuss uz ministru Abu Meri un Kipras braucienu. 17 retvīti bez komentāriem par IT korupciju, airBaltic, veselības politiku, Rīgas pašvaldību (atspoguļo sekotāju viedokļus, bet nav paša pozīcijas).', 0.85, '2026-04-19 18:46:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1692, 15, '2026-04-19', '2026-04-19', 0.0, '["Ārpolitika", "Ukraina un Krievija"]', '["Latvia is ready to contribute to the international mission for the Strait of Hormuz.", "Kamēr KF veic agresiju Ukrainā, neatvieglosim ceļu uz kara propagandas pasākumiem tur.", "A stronger Ukraine on the battlefield gives us a better chance for lasting peace."]', NULL, 'Braže 2026-04-19: (1) ADF2026 tikšanās ar Türkiye ĀM Fidanu — Latvija gatava pievienoties Hormuza šauruma starptautiskajai misijai; (2) paziņo, ka Latvija neizsniegs pārlidojuma atļaujas uz 9. maija Maskavas kara propagandas pasākumu; (3) TVP World intervijā uzsver, ka spēcīgāka Ukraina kaujas laukā = labāks ceļš uz mieru.', 0.85, '2026-04-19 18:47:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1708, 15, '2026-04-20', '2026-04-20', 0.0, '["Ukraina un Krievija"]', '["Russia systematically manipulates data to fool Ukraine’s allies into believing its economy has withstood the strain of its war spending and sanctions."]', NULL, 'Baiba Braže 20. aprīlī pārpublicē FT rakstu, kas norāda, ka Krievijas ekonomika vājinās un ka Krievija manipulē ar datiem par kara izmaksām — signāls par sankciju efektivitāti. Pārējie ziņojumi: līdzjūtība ASV pēc šaušanas Luiziānā un trīs retweet bez komentāriem (Satversmes tiesa, Francijas vēstniecība, Ārlietu ministrija).', 0.75, '2026-04-20 13:15:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1710, 26, '2026-04-20', '2026-04-20', 0.0, '["Valsts kapitālsabiedrības", "Aizsardzība un drošība"]', '["Plānotais akciju piedāvājums dos iespēju arī Latvijas iedzīvotājiem kļūt par LAU Infra Grupa investoriem ... vienlaikus tam saglabājot valsts kontrolējošo lomu (vismaz 75,01%)", "Arī citviet militārā mobilitāte nav iespējama bez kvalitatīvas ceļu infrastruktūras, tāpēc ir būtiski virzīties uz plašāku militārās mobilitātes finansējuma ieguldījumu autoceļu attīstībā"]', NULL, 'Švinka publiski atbalsta LAU Infra Grupa IPO kā pirmo Latvijas valsts kapitālsabiedrības IPO, ar valsts kontrolējošo lomu vismaz 75,01%. Paralēli apmeklē Sēlijas poligona pievedceļa būvniecību un argumentē par plašāku militārās mobilitātes finansējuma izmantošanu autoceļu attīstībā — divējādā pielietojuma projekti kā modelis. Abi izteikumi paplašina iepriekšējās pozīcijas par valsts uzņēmumu kapitalizāciju un transporta-aizsardzības saiti.', 0.85, '2026-04-20 13:16:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1711, 57, '2026-04-20', '2026-04-20', 0.0, '["Koalīcija un partijas", "Tieslietas"]', '["glumais Tumes Staķis jau skatās pēc jaunas partijas...kopā ar “Vienotības” vēzi padarījusi Latviju par Eiropas nabadzīgāko nomali", "Viens likums, viena taisnība visiem? Hehe, noteica Meisters - Stukānam bija savi īpašie klienti, man savi.", "Neikens? Kāds vēl Neikens? Braukt uz kaut kādu čuhņu..."]', NULL, 'Lato Lapsa 2026-04-20: 17 dokumenti (lielākoties RT bez komentāra). Trīs substantīvas pozīcijas: (1) apsūdz Progresīvos+Vienotību par Latvijas ekonomisko postu; (2) sarkastiski par prokuroru Neikenu; (3) apsūdz ģenerālprokuroru Meisteru divkāršos standartos, turpinot Stukāna selektīvo praksi. Visas pozīcijas saskan ar Lapsa iepriekšējo naratīvu par sistēmisko korupciju un JV/Progresīvo nekompetenci.', 0.72, '2026-04-20 13:16:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1731, 10, '2026-04-20', '2026-04-20', 0.0, '["Valsts kapitālsabiedrības", "Pašvaldības"]', '["RS valde iepērk akcionāra gaidu vēstules rakstīšanu kā ārpakalpojumu no SIA CIVITTA par 9 890€"]', NULL, 'Kulbergs kritizē Rīgas Siltuma pārvaldību — norāda, ka valde par gandrīz 10 tūkstošiem eiro iepērk ārpakalpojumā akcionāra gaidu vēstules rakstīšanu (darbu, kas pēc OECD korporatīvās pārvaldības principiem būtu jādara Ekonomikas ministrijai un Rīgas domei), vienlaikus apšaubot SPRK regulatora darbību tarifu akceptēšanā. Saista to ar faktu, ka Rīgā ir dārgākais siltuma tarifs Baltijā.', 0.8, '2026-04-20 13:24:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1732, 57, '2026-04-21', '2026-04-21', 0.0, '["Sociālā politika", "Budžets un finanses"]', '["Sekos iesnu izskaušanas likumprojekts… Kur tad Stambulas konvencija, āksti?", "Degvielas, siltuma, pārtikas cenas jau salauzis… Titulētais caurkritušais oberis."]', NULL, 'Lato Lapsa 2026-04-21 aktivitāte: pārsvarā retweeti bez komentāra (14 RT) un grāmatu popularizēšana (strēlnieku grāmatas). Divi izvelkamie viedokļi: (1) sarkastiska Stambulas konvencijas noraidīšana, to pielīdzinot simboliskam/nevajadzīgam likumprojektam; (2) apsūdzība anonīmam ''titulētam'' politiķim par degvielas, siltuma un pārtikas cenu pieaugumu.', 0.6, '2026-04-21 12:35:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1738, 6, '2026-04-21', '2026-04-21', 0.0, '["Imigrācija"]', '["Atbalstu Valsts policiju un dienestus, kuri ikdienā rūpējas par drošību, nevis imigrācijas lobētājus!"]', NULL, 'Dombrava aizstāv Valsts policiju un kritizē Rebaltica par to, ka žurnālistika vēršas pret politiķiem un dienestiem, kuri norāda uz masu imigrācijas drošības riskiem.', 0.85, '2026-04-21 12:36:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1740, 10, '2026-04-21', '2026-04-21', 0.0, '["Valsts kapitālsabiedrības", "Valsts pārvalde"]', '["stratēģijas rakstīšana ir uzņēmuma padomes un valdes kopdarbs - par to viņiem maksā tās lielās algas!"]', NULL, 'Kulbergs turpina intensīvu Rīgas Siltuma pārvaldības kritiku — NRA intervijā un X izvērš stāstu par Gaidu vēstuļu iepirkumu CIVITTA par 9 890€ un stratēģijas ārpakalpojuma iepirkumu par kopumā ~159 550€ (E&Y + KPMG + veicināšana). Apstrīd OECD korporatīvās pārvaldības ieviešanu RS un aicina SPRK regulatoru atbildēt par tarifa akceptu. Arī paziņo par VK gala ziņojuma prezentāciju PIK sēdē.', 0.88, '2026-04-21 12:37:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1743, 15, '2026-04-21', '2026-04-21', 0.0, '["Inovācijas", "Aizsardzība un drošība"]', '["Šodien @dacemelbarde Latvijas vārdā parakstīja pievienošanos @NASAArtemis memorandam par sadarbību kosmosā.", "As long as nuclear weapons exist, #NATO will remain a #nuclear alliance."]', NULL, '2026-04-21 Baiba Braže publicēja 12 X ierakstus un 1 la.lv op-ed viņu piemin. Lielākā daļa tvītu ir retvīti bez komentāra (EU Council sankcijas Krievijai, UNSC Ukrainas brīfings, Vācijas AA par Krievijas draudiem, Putin-Bush transkripts, bērnu deportācija). Divas pašas Bražes publikācijas: (1) Latvijas pievienošanās NASA Artemis Accords starptautiskajai sadarbībai kosmosā (kopā ar kolēģi Daci Melbārdi); (2) NATO kodolalianses lomas citāts bez komentāra. la.lv op-ed ir trešās puses kritika par JV — Braže nav izteicēja, tikai pieminēta. Dienas fokuss — kosmosa diplomātija un vispārēja Ukrainas/Krievijas amplifikācija, konsekventi ar Bražes ilgtermiņa NATO/atturēšanas pozīciju.', 0.75, '2026-04-21 12:37:13');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1766, 26, '2026-04-21', '2026-04-21', 0.0, '["Valsts kapitālsabiedrības"]', '["Valsts kapitālsabiedrībām varētu būt Somijas modelis – holdingu sabiedrība, kas pārvalda valsts kapitālsabiedrības"]', NULL, 'Švinka publiski atbalsta Somijas modeļa ieviešanu valsts kapitālsabiedrību pārvaldībā — vienu holdingu sabiedrību, kas pārvaldītu valsts kapitālsabiedrības. Tas ir konkrētāks ierosinājums nekā iepriekšējā vispārīgā pozīcija par centralizētu pārvaldību. Pārējie šīs dienas ieraksti (LAU Infra IPO, airBaltic rentabilitātes TV diskusija, Sēlijas poligona pievedceļš) atkārto jau zināmās pozīcijas vai ir faktu paziņojumi bez jaunas substances.', 0.75, '2026-04-21 12:39:43');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1768, 30, '2026-04-21', '2026-04-21', 0.0, '[]', '[]', NULL, 'Baško šajā dienā tikai retvīto MMN un Liepnieka ierakstus par TV24 debatēm bez paša komentāra vai patstāvīgas pozīcijas.', 0.3, '2026-04-21 12:40:08');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1775, 15, '2026-04-21', '2026-04-21', 0.0, '["Ukraina un Krievija"]', '["Latvia''s government has approved supplies of electricity generators to Ukraine, total value 1.2 million EUR."]', NULL, 'Braže paziņo par Latvijas valdības apstiprinātu 1,2 miljonu EUR vērtu elektroenerģijas ģeneratoru piegādi Ukrainai (Čerņihivas reģionam, civilajām iestādēm pēc Krievijas triecieniem). Pārējais X saturs ir RT bez pašas komentāra.', 0.85, '2026-04-21 17:56:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1776, 57, '2026-04-21', '2026-04-21', 0.0, '["Rail Baltica"]', '["Viens termiņš ar Rail Baltica iluzoro pabeigšanu - tas tā kā speciāli?"]', NULL, 'Lato Lapsa 2026-04-21 publicēja 13 tvītus, no kuriem lielākā daļa bija retvīti bez komentāriem vai ļoti īsi ironiski apgalvojumi. Vienīgā skaidri izvelkamā pozīcija — skepse par Rail Baltica pabeigšanas termiņu, dēvējot to par iluzoru.', 0.7, '2026-04-21 17:56:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1778, 10, '2026-04-21', '2026-04-21', 0.0, '["Valsts kapitālsabiedrības", "airBaltic", "Degviela un enerģētika"]', '["RS ir 100% pienākums veidot tirgus modeli, bet to gadiem nedarīja", "tālāk par Jāņiem neizvilks, ja vien nenotiks kāds brīnums"]', NULL, 'Kulbergs aktīvi kritizē valsts kapitālsabiedrību pārvaldību (RS, airBaltic, Rail Baltica), raksturojot to kā ''legalizēto korupciju''. Par airBaltic prognozē finanšu sabrukumu līdz 2026. gada vasarai un aicina uz obligāciju pārstrukturizāciju.', 0.85, '2026-04-21 17:57:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1794, 26, '2026-04-21', '2026-04-21', 0.0, '["Aizsardzība un drošība"]', '["Šodien valdībā pieņemtais 100 000 eiro finansējums aviācijas drošības pasākumu īstenošanai ir mērķēts ieguldījums mūsu drošībā."]', NULL, 'Švinka atbalsta valdības lēmumu par 100 000 eiro finansējumu aviācijas drošības pasākumiem Rīgas un Liepājas lidostās — to pozicionē kā ieguldījumu kritiskajā infrastruktūrā valsts drošībai un starptautisko saistību izpildei.', 0.85, '2026-04-21 18:04:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1795, 72, '2026-04-21', '2026-04-21', 0.0, '[]', '[]', NULL, 'Viens tvīts par darba vizīti Eiropas Parlamentā pēc ECR ielūguma; bez konkrētas politiskas pozīcijas.', 0.3, '2026-04-21 18:04:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1803, 57, '2026-04-22', '2026-04-22', 0.0, '[]', '[]', NULL, '18 dokumenti apskatīti — 16 retvīti bez komentāra (trešo pušu saturs, nav Lato Lapsas pozīcija), 2 oriģinālie tvīti (23481, 23484) ir īsi sarkastiski personas apvainojumi bez konkrētas politiskas pozīcijas vai politikas priekšlikuma. Neviens jauns claim netiek ekstrahēts.', 0.8, '2026-04-22 14:52:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1806, 15, '2026-04-22', '2026-04-22', 0.0, '["Ukraina un Krievija", "Ārpolitika", "ES politika", "Aizsardzība un drošība"]', '["Krievija jaunus militārus uzbrukumus nevar atļauties, tāpēc ir jāturpina vājināt Krieviju un jākāpināt sankciju spiedienu", "90 billion EUR loan to meet Ukraine''s urgent financial and battlefield needs. 20th sanctions package against Russia."]', NULL, 'Braže 22. aprīlī dominē divās līnijās: (1) atbildes rīcība pret Zelenska brīdinājumiem par Krievijas iespējamo mobilizāciju Baltijai — ārlietu ministre noraida tūlītēju militāro risku, atsaucoties uz izlūkdienestu datiem par Krievijas kapacitāti, un akcentē Krievijas ekonomisko vājumu (1,3 milj zaudējumi, 150 mljrd USD naftas ieņēmumu iztrūkums, 15% inflācija); (2) ES drošības arhitektūras atbalsts — 90 mljrd EUR aizdevums Ukrainai un 20. sankciju pakete. Paralēli — bilaterālais memorands ar Azerbaidžānu par konsulāro sadarbību. Pozīcijas saskanīgas ar iepriekšējām tendencēm (Krievijas ekonomikas vājināšana, sankciju kāpināšana, Ukrainas atbalsts).', 0.88, '2026-04-22 14:53:48');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1810, 10, '2026-04-22', '2026-04-22', 0.0, '["Valsts pārvalde", "Valodu politika"]', '["Ir jāmet ārā visi šie svešvārdi un jāsauc lietas visiem saprotamā valodā - virzīšu tos nomainīt"]', NULL, 'Kulbergs iebilst pret svešvārdu un birokrātisku terminu lietošanu valsts pārvaldē, apsolot virzīt to nomaiņu uz saprotamāku valodu.', 0.85, '2026-04-22 14:54:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1811, 6, '2026-04-22', '2026-04-22', 0.0, '["Imigrācija", "Izglītība", "Transports"]', '["Lai nebūtu jāieved imigranti, kuri strādā transporta un loģistikas uzņēmumos, Satiksmes un Izglītības ministrijai ir jāsakārto izglītības sistēma, lai daudz lielākā skaitā tiktu sagatavoti profesionāli kravas un autobusu šoferi."]', NULL, 'Dombrava uzsver, ka risinājums darbaspēka trūkumam transporta nozarē ir izglītības sistēmas reforma, nevis imigrantu ievešana. Pieprasa Satiksmes un Izglītības ministrijām sagatavot vairāk profesionālu šoferu.', 0.85, '2026-04-22 14:54:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1818, 26, '2026-04-22', '2026-04-22', 0.0, '["Valsts kapitālsabiedrības", "Transports"]', '["Latvijas Pasts dibina meitassabiedrības Igaunijā un Lietuvā. @Pasts_lv darbības izvēršana Baltijā nostiprina Latvijas kā uzticama un ambicioza loģistikas partnera pozīciju."]', NULL, 'Švinka publiski atbalsta Latvijas Pasta paplašināšanos Baltijā ar meitassabiedrību dibināšanu Igaunijā un Lietuvā — raksturo to kā stratēģisku soli e-komercijas biznesā un loģistikas partnera pozīcijas nostiprināšanai.', 0.85, '2026-04-22 14:55:57');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1848, 10, '2026-04-22', '2026-04-22', 0.0, '["Sociālā politika", "Valsts kapitālsabiedrības"]', '["PRO atrod 30mil AB nedēļas laikā, 90k € no tās pašas SatMin neatrod 3+ Goda Ģimenei. PRO vadītajā Saeimas Komisijā mūsu 3+ Goda Ģimenes likumprojekts piešķirt statusu ne no vecākā bērna, bet jaunākā bērna pilngadības stāv atvilknē jau gadu", "Rīgas Siltums pasaku 4.sējums: Ja jums nepietika ar @RSiltums \"Gaidu Vēstule\" iepirkšanu, \"Stratēģijas\" iepirkšanu, tad izrādas ir iespējams iepirkt arī \"Stratēģijas veicināšana\" pakalpojumu par 40 750€! Atgādinu, ka viss šis nonāk jūsu Rīgas siltumtarifā. Vai vēl ir jautājumi kāpēc tas ir dārgākais Baltijā?"]', NULL, 'Kulbergs 22. aprīlī turpina divas saturiskās līnijas: (1) Rīgas Siltuma iepirkumu kritika — atklāj vēl vienu ārpakalpojumu ''Stratēģijas veicināšana'' par 40 750 €, tieši sasaistot to ar siltumtarifa augstumu Baltijā; (2) kritika PRO koalīcijas partnerim un Satiksmes ministrijai par dubultiem standartiem — kamēr airBaltic 30 miljoni atrodas nedēļas laikā, Goda Ģimenes 3+ likumprojekts stāv PRO vadītajā Saeimas komisijā gadu.', 0.87, '2026-04-22 21:06:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1850, 57, '2026-04-23', '2026-04-23', 0.0, '[]', '[]', NULL, 'Bare retweet bez komentāra — nav ekstraktējamas pozīcijas.', 0.2, '2026-04-22 21:06:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1851, 57, '2026-04-22', '2026-04-22', 0.0, '[]', '[]', NULL, 'Doc 23773: bare retvīts no @EndoLapsa bez Lapsas paša komentāra. Nav ekstraktējamas pozīcijas.', 0.2, '2026-04-22 21:06:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1852, 57, '2026-04-22', '2026-04-22', 0.0, '[]', '[]', NULL, 'Nav ekstraktējamas pozīcijas — bare retvīts bez komentāra, turklāt RT atbilde, kas adresēta Lapsam (nevis viņa paša izteikums). Saturs par grāmatas novietojumu plauktā, nav politiskas substances.', 0.2, '2026-04-22 21:06:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1853, 57, '2026-04-22', '2026-04-22', 0.0, '["Valsts pārvalde"]', '[]', NULL, 'Sarkastisks tvīts par kāda valsts sekretāra atkāpšanās paziņojumu — apvaino Sprūdu Kremļa ietekmes aģentēšanā un zobojas par Siliņas taisnošanās prasmēm. Nav konkrētas politiskas pozīcijas — tikai insinuācijas un mockery bez policy substance.', 0.2, '2026-04-22 21:06:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1854, 57, '2026-04-22', '2026-04-22', 0.0, '[]', '[]', NULL, 'Bare retvīts no @LapinsGirts par airBaltic/Lufthansa — nav paša Lapsas komentāra vai pozīcijas.', 0.2, '2026-04-22 21:06:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1855, 57, '2026-04-22', '2026-04-22', 0.0, '[]', '[]', NULL, 'Retvīts bez komentāra — nav paša pozīcijas.', 0.2, '2026-04-22 21:06:48');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1857, 57, '2026-04-23', '2026-04-23', 0.0, '[]', '[]', NULL, 'Doc 23779 ir bare retweet no @incaustum par Aizsardzības ministrijas valsts sekretāra atlūgumu — Lapsa pats nav pievienojis komentāru, nav ekstraktējamas pozīcijas.', 0.2, '2026-04-22 21:07:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1858, 57, '2026-04-22', '2026-04-22', 0.0, '["Aizsardzība un drošība"]', '["Ir parasti meli, ir stulbi meli, un tad vēl ir kremļa ietekmes aģenta Sprūda skaidrojumi, kāpēc Aizsardzības ministriju pamet jau otrs valsts sekretārs."]', NULL, 'Lapsa publiski apsūdz aizsardzības ministru Andri Sprūdu par Kremļa ietekmes aģenta lomu un kritizē viņa skaidrojumus par otrā valsts sekretāra aiziešanu no Aizsardzības ministrijas.', 0.8, '2026-04-22 21:07:01');
