INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1863, 15, '2026-04-22', '2026-04-22', 0.0, '["Ārpolitika"]', '["Vērtīga tikšanās Baku ar Azerbaidžānas ārlietu ministru Džeihunu Bairamovu, kurā apspriedām…"]', NULL, 'Braže amplificē MFA ierakstu ar savu tiešo citātu par tikšanos Baku ar Azerbaidžānas ārlietu ministru Bairamovu — tiek turpināta Latvijas–Azerbaidžānas divpusējā dialoga līnija. Pārējie seši (faktiski pieci) raksti ir tīri retvīti bez viņas pašas komentāra.', 0.6, '2026-04-22 21:07:25');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1869, 15, '2026-04-23', '2026-04-23', 0.0, '["Ārpolitika", "ES politika"]', '["An in-depth first call with Hungary''s Foreign Minister-designate Anita Orbán", "no aprīļa Latvija ir starp ES valstīm, kuras drīkst eksportēt olas un gaļas produktus uz Singapūru"]', NULL, 'Braže ziņo par pirmo sarunu ar Ungārijas ārlietu ministra amata kandidāti Anitu Orbán — divpusējās attiecības, ES un NATO sadarbība, Ukrainas atbalsts. Atsevišķi paziņo par Latvijas iekļūšanu ES valstu sarakstā, kam atļauts eksportēt olas un gaļas produktus uz Singapūru.', 0.85, '2026-04-23 10:59:25');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1872, 10, '2026-04-23', '2026-04-23', 0.0, '["Valsts kapitālsabiedrības"]', '["Aizmirsu pateikt - protams, ka “veicināšanas pakalpojums” ir iepirkts bez konkursa no viena cilvēka SIA Energise"]', NULL, 'Kulbergs turpina Rīgas siltuma iepirkumu ķēdes atklāšanu — precizē, ka ''veicināšanas pakalpojuma'' iepirkums notika bez konkursa no viencilvēka SIA Energise.', 0.85, '2026-04-23 11:00:22');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1880, 6, '2026-04-23', '2026-04-23', 0.0, '["Imigrācija"]', '["Latvijā būtu nepieciešams liegt ārvalstu studentiem strādāt ar pašnodarbinātā statusu"]', NULL, 'Dombrava Saeimas parlamentārās izmeklēšanas komisijā rosina liegt ārvalstu studentiem strādāt ar pašnodarbinātā statusu platformās (Bolt, Wolt), paredzot uzņēmumiem ievērojamus sodus par pārkāpumiem.', 0.85, '2026-04-23 11:07:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1886, 26, '2026-04-23', '2026-04-23', 0.0, '["airBaltic", "Transports"]', '[]', NULL, 'Švinka precizē airBaltic aizdevuma nosacījumus (divciparu %, atmaksa no maija/jūnija, rentabilitāte 1-2 gados) un Hamburgā pauž atbalstu ostu digitalizācijai.', 0.82, '2026-04-23 11:14:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1900, 57, '2026-04-23', '2026-04-23', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-04-23 pirmā partija (12 dokumenti): 11 bareti retvīti (@PietiekPortals, @AnitaDreika, @artis_dobrajs, @jautaa_veel, @katrinailjinska, @Heinrih5, @Aigars1972) bez paša komentāra + 1 personisks paziņojums par strēlnieku grāmatas izplatīšanu (24110) — nav politiskas pozīcijas. Ekstraktējamu pozīciju nav.', 0.9, '2026-04-23 16:25:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1905, 57, '2026-04-23', '2026-04-23', 0.0, '["Budžets un finanses"]', '["Finanšu pratību citiem cilvēkiem māca Čakša no \"Vienotības\" vēža, kurš pagājušogad ir rijis zefīriņus tā, ka Latvijas parāds palielinājies par 1,4 miljardiem eiro…"]', NULL, 'Lato Lapsa kritizē finanšu ministres Čakšas (Vienotība) finanšu pratības lekcijas, norādot uz Latvijas valsts parāda pieaugumu par 1,4 miljardiem eiro pagājušajā gadā.', 0.6, '2026-04-23 16:26:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1912, 15, '2026-04-24', '2026-04-24', 0.0, '[]', '[]', NULL, 'Visi 8 dokumenti ir vai nu retvīti bez komentāra (7 gab.: ltvzinas par Venēcijas biennāli, ksfopenukraine par Pudānu, Arlietas x3 par sankcijām/Azerbaidžānu/Tomskas memoriālu, FrenchResponse par Irānu, LVembRussia par Tomsku) vai ceremoniālas (apsveikums Ivetai Derkusovai par LNMM direktores amatu). Nav ekstraktējamu personisko pozīciju.', 0.9, '2026-04-24 09:50:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1914, 26, '2026-04-24', '2026-04-24', 0.0, '["Transports", "Vide"]', '["Šajā nedēļā valdībā apstiprinājām jaunu atbalsta programmu videi draudzīgu transportlīdzekļu iegādei – ar kopējo finansējumu 40 miljoni eiro."]', NULL, 'Švinka kā satiksmes ministrs paziņo par valdībā apstiprinātu 40M eiro atbalsta programmu videi draudzīgiem transportlīdzekļiem, ar SM panāktiem priekšlikumiem mikromobilitātei, plug-in hibrīdu izvērtēšanai un lietoto auto kritēriju paplašināšanai.', 0.85, '2026-04-24 09:50:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1919, 10, '2026-04-24', '2026-04-24', 0.0, '["Valsts kapitālsabiedrības", "Ukraina un Krievija"]', '["Valsts kontroles sledziens ir, ka visas puses siltuma izšķērdēšanas lietā rāda viena otra ar pirkstu un izvairās no atbildības.", "Izrādās valde ir tik nespējīga, ka pat ir jāiepērk Microsoft Powerpoint valdes prezentācijas sagatavošana padomei"]', NULL, 'Kulbergs turpina Rīgas Siltuma kritiku — uzsver pēc-VK atbildības izvairīšanos un atklāj jaunu iepirkumu absurdu (PowerPoint 12 440€). Atsevišķi izsaka bažas par Latvijas sabiedrības Krievijas-vainības identificēšanas līmeni (63%).', 0.85, '2026-04-24 09:51:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1935, 30, '2026-04-24', '2026-04-24', 0.0, '[]', '[]', NULL, 'Bez ekstraktējamām pozīcijām: bare retvīts no @Lato_Lapsa bez paša komentāra vai politiskās substances.', 0.2, '2026-04-24 09:58:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1938, 72, '2026-04-24', '2026-04-24', 0.0, '["Ukraina un Krievija"]', '["Tie paši, kas gadiem stāstīja, ka to “neļauj likums”, pēkšņi pirms vēlēšanām iesniedz nekvalitatīvus grozījumus."]', NULL, 'Indriksone par Saeimas 1. lasījumā virzītajiem grozījumiem, kas ļaus publiskot uzņēmumus ar eksportu/importu uz agresorvalstīm: atbalsta virzību, bet kritizē koalīciju par “absolūtu haosu” un nekvalitatīviem grozījumiem, kas iesniegti pirms vēlēšanām pēc gadiem ilgas pretošanās.', 0.75, '2026-04-24 09:58:16');
