INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (1980, 15, '2026-04-24', '2026-04-24', 0.0, '["Ukraina un Krievija", "Ārpolitika"]', '[]', NULL, 'Baiba Braže 2026-04-24 aktivitāte: pārsvarā retvīti bez komentāra (FrancijaLatvija par Francijas prezenci Baltijā, EUCouncil par ES samitu, Trade_EU par ES-ASV kritisko izejvielu MoU, LRZinas par ES reakciju uz Irānu, ksfopenukraine par 5% IKP aizsardzībai, ltvzinas par VIP zālēm, Arlietas pārpublicē viņas uzrunu Kijivas drošības forumā). Viens pašas tvīts — Locked Shields 2026 sveiciens Latvijas/Singapūras komandai (ceremoniāls). Diena.lv/pmo.ee raksti (RSS teaseri) atkārto iepriekšējā dienā (2026-04-22) jau fiksēto pozīciju par ES finansiālo atbalstu Ukrainai un 20. sankciju paketi (skat. pretenziju #11246) — nav jaunu pozīciju satura.', 0.8, '2026-04-24 19:42:36');
