INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2002, 57, '2026-04-25', '2026-04-25', 0.0, '[]', '[]', NULL, 'Lato Lapsa: 12 dokumenti pārskatīti, neviens nesatur ekstraktējamu pirmpersonas politisku pozīciju. 9 ir tukši retvīti bez paša komentāra (komunisma kritika, Vārnu iela, RAKUS finansējums, drošības VIP režīms, grāmatu uzslavas). 3 ir paša Lapsas īsi izteikumi bez konkrētas politikas: sarkastiska insinuācija par neidentificētu ''apdauzīto komunistieni'' (25761), abstrakta retorika ''Sarkanā sērga... tikai viena efektīva metode'' bez nosaukta mērķa vai priekšlikuma (25763), un pašreklāmas paziņojums par strēlnieku grāmatas tirāžu (25767). 1 dokuments (25758) atstāts nākamajai sesijai - 12-doku circuit breaker.', 0.6, '2026-04-25 08:03:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2008, 26, '2026-04-25', '2026-04-25', 0.0, '["airBaltic"]', '[]', NULL, 'Komentē airBaltic situāciju Delfi TV — apgalvo, ka masveida lidojumu atcelšana vasarā netiek plānota, taču atsevišķu nerentablu reisu pārskatīšana nav izslēdzama.', 0.75, '2026-04-25 08:04:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2022, 57, '2026-04-25', '2026-04-25', 0.0, '[]', '[]', NULL, 'Wave 2: 1 leftover dokuments (25758) — bezklusas retvīts (RT @AijaLynx) par Rīgas vēsturiskā centra seguma maiņu, nav pievienota neviena Lapsas atbilde vai pozīcija. Atbilst Wave 1 modelim (0/12 ar saturu).', 0.9, '2026-04-25 08:11:31');
