INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2032, 57, '2026-04-25', '2026-04-25', 0.0, '[]', '[]', NULL, 'Lapsa Wave 3: 12 dokumenti caurskatīti, neviens nesatur ekstraktējamu pirmpersonas pozīciju. 7 retvīti bez komentāra (doc 1, 2, 3, 6, 7, 9, 10, 12), 5 īsi sarkastiski komentāri bez konkrētas politikas pozīcijas (doc 4, 5, 8, 11). Doc 5 (Hermanis) un doc 11 (sabiedriskais medijs) tematu jau aptver iepriekšējās pozīcijas (id=10973, id=11130) bez jaunas substances. Doc id=26019 (13. dokuments) atlikts uz nākamo sesiju.', 0.7, '2026-04-25 14:23:20');
