INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2045, 6, '2026-04-25', '2026-04-25', 0.0, '[]', '[]', NULL, 'Tvīts ir tikai anonss sarunai ar E.Ratnieku par Imigrācijas izmeklēšanas komisiju — paši secinājumi netiek atklāti tvīta tekstā. Konkrēta pozīcija no šī tvīta nav ekstraktējama.', 0.2, '2026-04-25 14:24:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2056, 182, '2026-04-26', '2026-04-26', 0.0, '["Koalīcija un partijas"]', '["Atcerēsimies, ka tieši pateicoties PRO Latvijas valdībā atgriezās Magņicka sarakstā iekļautā oligarha kabatas partijas. ... PRO draugi no JV sadarbojušies un atbalstījuši Krieviju vairāk nekā LPV."]', NULL, 'Otto Ozols X tvītā 2026-04-26 publicē trīskāršu retorisku kritiku par Progresīvajiem (PRO): apgalvo, ka PRO ļāvuši oligarhu partijām atgriezties valdībā, ka iepriekš sadarbojušies ar APar, un ka PRO partneri no JV vairāk atbalstījuši Krieviju nekā LPV.', 0.75, '2026-04-26 11:24:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2060, 15, '2026-04-26', '2026-04-26', 0.0, '["Ukraina un Krievija"]', '["As we commemorate the victims and survivors of Chornobyl, Russia continues to poses a grave risk to nuclear security in occupied Zaporizhzhia."]', NULL, 'Braže 26.04.: viens pirmās personas tvīts par Černobiļas 40. gadadienu un Krievijas radīto kodoldrošības risku Zaporižjas AES; pārējie 15 dokumenti — bare retvīti bez komentāra (Aliyev/Zelenskyy, Dombrovskis par Černobiļu, Siliņa, Rinkevičs par WhiteHouse incidentu, ZelenskyyUa, talka, ANZAC Day u.c.).', 0.85, '2026-04-26 12:00:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2076, 10, '2026-04-26', '2026-04-26', 0.0, '["Pilsētvide"]', '["Tagad dēļ katru 100 cilvēku sūdzības un iegribām cietīs 15 000 apkaimes iedzīvotāji"]', NULL, 'Kulbergs kritizē “modālā filtra” terminoloģiju un, plašāk, Progresīvo (PRO) pieeju — pārmet infrastruktūras (ceļi, airBaltic, Rail Baltica) bloķēšanu mazākuma sūdzību dēļ.', 0.7, '2026-04-26 12:01:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2077, 57, '2026-04-26', '2026-04-26', 0.0, '["Koalīcija un partijas"]', '["Progresīvo sarkanā sērga. Ja ļausiet, viņi to izdarīs ar visu valsti."]', NULL, 'Lato Lapsa publicēja 13 ierakstus, no kuriem 12 ir bareri retvīti bez paša komentāra (par dzīvnieku meklēšanu, atsaucēm uz citiem komentētājiem, oligarhu kritiku, Bražes karogu skandāla pieminējumiem). Vienīgā pirmpersonas pozīcija — īss brīdinājums par Progresīvajiem kā ''sarkano sērgu''.', 0.7, '2026-04-26 12:02:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2079, 182, '2026-04-26', '2026-04-26', 0.0, '["Degviela un enerģētika", "Valsts pārvalde", "Koalīcija un partijas"]', '[]', NULL, 'Otto Ozols 15 dokumentu analīze: 3 substantīvas pozīcijas (degvielas cenu regulējums Izraēlas modelī, VIP tēriņu kritika ar Somijas paralēli, PRO/Šuvajeva liekulība par ZZS/Šleseru). 12 docs tukši — pārsvarā retweeti bez komentāra un Bauhaus mākslas izglītojošs posts.', 0.8, '2026-04-26 12:02:31');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2081, 30, '2026-04-26', '2026-04-26', 0.0, '[]', '[]', NULL, 'Tvīts ir filozofiska refleksija par MI aģentu ģenerētiem tekstiem un autora atbildību — nav konkrētas politiskas pozīcijas vai politikas priekšlikuma.', 0.3, '2026-04-26 12:02:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2084, 26, '2026-04-26', '2026-04-26', 0.0, '["Rail Baltica", "airBaltic"]', '["Es esmu teicis – ja vajadzēs, es pats sliedes aiznesīšu uzlikšu, lai redzētu sabiedrību, kad virs šiem uzbērumiem ir ne tikai pievadceļa paralēlie ceļa savienojumi uzbērums, bet arī fiziski sliedes."]', NULL, 'Satiksmes ministrs Atis Švinka Delfi TV intervijās: Rail Baltica virzās gausi un nepieciešams restarts; pirmās sliedes pamattrasē līdz vēlēšanām rudenī diez vai būs redzamas; airBaltic vasarā nerentablus reisus var atcelt, bet masveida atcelšana netiekot plānota.', 0.85, '2026-04-26 12:03:10');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2094, 57, '2026-04-27', '2026-04-27', 0.0, '[]', '[]', NULL, 'Lato Lapsa (žurnālists, @Lato_Lapsa). 20 dokumenti pārskatīti — 13 bare retvīti bez komentāra, 5 pirmās personas tvīti ar sarkasmu/insinuācijām/retoriskiem jautājumiem bez konkrētas politikas pozīcijas (ministra apsaukšana par "sabotieri", LTV "propagandoni", NA invektīva, Ragozina retoriskais jautājums, strēlnieku grāmatas reklāma), 2 raksti par "Lapsu mājas siers" un "Lapsu ciems" — uzvārda-vietas sakritība, NAV par Lato Lapsu. Nav ekstraktējamu pozīciju.', 0.4, '2026-04-27 20:08:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2101, 15, '2026-04-27', '2026-04-27', 0.0, '["Ukraina un Krievija", "Ārpolitika"]', '["Esmu lēmusi LR nevēlamo personu (persona non grata) sarakstā iekļaut 3 KF pilsoņus un aizliegt Mihailam Švidkojam, Anastasijai Karnejevai, Jekaterinai Vinokurovai ieceļot 🇱🇻 uz nenoteiktu laiku, saskaņā ar Imigrācijas likuma 61.p. 2.d.", "The decisions on the 90 billion loan and 20th sanctions package show that Europe is united in supporting Ukraine. Russia''s war is going nowhere. It is becoming weaker every day."]', NULL, 'Braže 2026-04-27: konkrēts persona non grata lēmums pret 3 Krievijas pilsoņiem saistībā ar Venēcijas biennāli (realizē iepriekš pausto principiālo pozīciju ar administratīvu darbību) un Kijivas drošības foruma paziņojums par ES atbalsta vienotību Ukrainai (90 mljrd aizdevums + 20. sankciju pakete). Lielākā daļa dokumentu — RT bez komentāra vai ceremoniāli paziņojumi.', 0.92, '2026-04-27 20:10:28');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2106, 182, '2026-04-27', '2026-04-27', 0.0, '["Ārpolitika"]', '["NATO member state Spain has extensive experience collaborating with the Russian military and intelligence services"]', NULL, 'Otto Ozols 27.04.2026 publicē apjomīgu X-vītni par Spānijas uzticamību NATO, atsaucoties uz 2014.–2015. gada sadarbību ar Krievijas un Sīrijas Asada režīma militāro loģistiku caur Seūtas ostu.', 0.8, '2026-04-27 20:12:58');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2120, 30, '2026-04-27', '2026-04-27', 0.0, '["Vēlēšanas", "Valsts pārvalde", "Koalīcija un partijas"]', '[]', NULL, 'Baško divos tvītos: (1) kritika pret JV kā ''Lēnāk un paga!'' kursu un piedāvājums radikāli samazināt deputātu skaitu (8 Saeimā ar procentu balsu svaru, 30 Rīgas domē); (2) vēlas premjeru, kura motīvs ir atbildība pret dzimteni, ne personīgais statuss vai karjeras kāpšļa.', 0.75, '2026-04-27 20:19:03');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2121, 10, '2026-04-27', '2026-04-27', 0.0, '["Valsts kapitālsabiedrības", "Korupcija un KNAB", "Degviela un enerģētika"]', '["Šāda amatpersonu bezdarbība ir krimināli sodāms noziegums par ko es ziņošu ģenerālprokuroram.", "Sasteigtas rezerves maksā dārgi!"]', NULL, 'Kulbergs eskalē Rīgas Siltuma lietu — paziņo par ziņošanu ģenerālprokuroram par EM bezdarbību (180M EUR subsīdijas, 2023. janv. neatbildēts RS lūgums); politisko atbildību piesaista Valainim/ZZS. Atsevišķi skaidro stratēģisko naftas rezervju izmaksu pārsniegumu (3,5–5 vs 1,5 EUR/t Lietuvā) kā sasteigtas politikas un infrastruktūras trūkuma sekas.', 0.85, '2026-04-27 20:20:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2134, 6, '2026-04-27', '2026-04-27', 0.0, '["Imigrācija"]', '["Šī shēma vistuvākajā laikā ir jāslēdz. To arī panāksim!"]', NULL, 'Dombrava paziņo, ka imigrācijas izmeklēšanas komisija atklājusi shēmu, caur kuru imigranti ieguvuši uzturēšanās atļaujas un Latvijā ienākusi netīra nauda; apņemas to slēgt.', 0.85, '2026-04-27 20:55:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2139, 57, '2026-04-27', '2026-04-27', 0.0, '[]', '[]', NULL, '2026-04-27 ekstraktora sesija (Lato Lapsa, pid=57): pārskatīti 12 augstas prioritātes dokumenti — visi role=subject (Lapsas paša X konts). 11 no 12 ir bare retvīti bez paša komentāra (PietiekPortals/Mikipele6/Tas_es_Pats/MarisKaminskis/Ulubele/u.c.) vai sarkastiska invektīva par Progresīvajiem (sarkana serga, naida runa, Waze) bez konkrētas politikas pozīcijas. Pārējie 47 šodienas mention_target/mentioned dokumenti ir trešo personu tvīti, kuros Lapsa tikai pieminēts (talked about, not speaking) — tie nav pirmpersonas runas dokumenti un netiek apstrādāti claim ekstraktorā. 0 claims saglabātas; Lapsa stila konteksts apstiprināts (publicistika ar uzturētu sarkasma stilu, bez konkrētiem likumdošanas vai politikas piedāvājumiem).', 0.5, '2026-04-28 05:31:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2140, 15, '2026-04-28', '2026-04-28', 0.0, '[]', '[]', NULL, 'Abi RSS dokumenti (Diena, pmo.ee) ir īsi paziņojumi par Bražes 2025. gada algas deklarāciju (108 644 EUR no Valsts kancelejas). Ne politiķes citāts, ne pozīcija — tikai amatpersonas deklarācijas fakts. Nav ekstraktējamas pozīcijas.', 0.2, '2026-04-28 19:24:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2149, 26, '2026-04-28', '2026-04-28', 0.0, '["Transports"]', '["esmu daļa no jums", "cīnīsimies kopīgi"]', NULL, 'Satiksmes ministrs Atis Švinka LVC konferencē Jūrmalā 22.-23. aprīlī pauda atbalstu ceļu būves līgumu cenu indeksācijai naftas/bitumena cenu kāpuma kontekstā. Satiksmes ministrija valdībā iesniegusi noteikumu projektu; pirmajā sēdē projekts netika apstiprināts, Švinka sagaida pieņemšanu 28. aprīļa sēdē.', 0.75, '2026-04-28 19:25:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2152, 57, '2026-04-28', '2026-04-28', 0.0, '[]', '[]', NULL, 'Lato Lapsa ir demoted komentētājs (relay feed_type). Visi 17 dokumenti 2026-04-28 ir vai nu retvīti bez komentāra (12 gab.), vai paša Lapsas sarkastiski vienrindnieki / insinuācijas bez konkrētas politikas pozīcijas (5 gab.). Per Step 3b (DEPRECATED 2026-04-25) un skip rules — nav ekstraktējamu first-party pozīciju.', 0.2, '2026-04-28 20:52:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2154, 15, '2026-04-28', '2026-04-28', 0.0, '["Ukraina un Krievija"]', '["Latvia’s military support to Ukraine was 0.3% of GDP in ‘25."]', NULL, 'Braže 2026-04-28: viens pirmās personas paziņojums (angļu val.) par papildu CVR(T) bruņutehnikas nodošanu Ukrainai un Latvijas militārā atbalsta apjomu (0,3% no IKP 2025). Pārējie 17 dokumenti — bare retvīti bez paša komentāra (Ārlietu min., Brīvības 36, Dombrovskis, NATO, ltvzinas u.c.), nav ekstraktējamas pirmās personas pozīcijas.', 0.9, '2026-04-28 20:52:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2155, 30, '2026-04-28', '2026-04-28', 0.0, '[]', '[]', NULL, 'Divi īsi tvīti — viens kails RT bez komentāra, otrs sarkastiska piezīme par LTV studijas runāšanas stilu (rētoriska, bez konkrētas pozīcijas). Ekstraktējamu pozīciju nav.', 0.3, '2026-04-28 20:53:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2163, 26, '2026-04-28', '2026-04-28', 0.0, '["Digitālā politika"]', '["Zvanot uz 112, atrašanās vietas dati dienestiem tiks nodoti 1 sekundes laikā, izmantojot arī GPS un Wi-Fi datus."]', NULL, 'Atis Švinka publiski atbalsta jauno 112 izsaukumu GPS/Wi-Fi atrašanās vietas datu automātiskās pārsūtīšanas risinājumu, uzsverot tā nozīmi avārijās un veselības krīzēs, kad cilvēks pats nevar norādīt atrašanās vietu.', 0.8, '2026-04-28 20:54:10');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2168, 6, '2026-04-28', '2026-04-28', 0.0, '["Imigrācija", "Aizsardzība un drošība"]', '["Kamēr esmu komandējumā, tikmēr Aizsardzības komisijā ir noraidīti virkne priekšlikumi, kuri stiprinātu uzņēmēju un augstskolu atbildību par pārkāpumiem attiecībā uz ārzemnieku piesaisti. Vai tiešām Aizsardzības komisijas deputātiem pirmajā vietā nebūtu jābūt drošības interesēm?"]', NULL, 'Dombrava kritizē Aizsardzības komisiju par to, ka noraidīti priekšlikumi par uzņēmēju un augstskolu atbildības stiprināšanu attiecībā uz ārzemnieku piesaisti. Saskan ar viņa konsekvento līniju par stingrāku darba imigrācijas regulējumu un drošības prioritāti.', 0.75, '2026-04-28 20:54:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2180, 10, '2026-04-28', '2026-04-28', 0.0, '["Pilsētvide", "Degviela un enerģētika"]', '[]', NULL, 'Kulbergs 2026-04-28: iebilst pret Progresīvo modālajiem filtriem ap Teikas skolu (Pilsētvide); aicina valstisku regulējumu vēja turbīnu utilizēšanai (Degviela un enerģētika).', 0.82, '2026-04-28 20:55:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2183, 10, '2026-04-28', '2026-04-28', 0.0, '["Pilsētvide", "Degviela un enerģētika"]', '[]', NULL, 'Kulbergs 2026-04-28: iebilst pret Progresīvo modālajiem filtriem ap Teikas skolu (Pilsētvide); aicina valstisku regulējumu vēja turbīnu utilizēšanai (Degviela un enerģētika).', 0.82, '2026-04-28 20:56:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2190, 57, '2026-04-29', '2026-04-29', 0.0, '["Budžets un finanses", "Tieslietas"]', '["Padomāt tik, kā šie nabadzīgie somi apskauž Latvijas veiksmes stāstu", "Mentu zaņķim atkal kreņķis, hiēnu bandai atkal izdevumi mentu zaņķa pakalpojumu apmaksai"]', NULL, 'Lato Lapsa 2026-04-29 publicēja 7 tvītus, no kuriem 5 ir bare retvīti bez paša komentāra (Grok par premjeru algām, Krišjānis_K par naudas izgaišanu, Anita Dreika par medicīnas piekļuvi, axe_lv par drošības pieredzi, RudensLapaVeeja par zāļu kompensēšanu). Divos pirmpersonas tvītos Lapsa: (1) sarkastiski izsmej Latvijas "veiksmes stāsta" naratīvu salīdzinājumā ar Somijas ekonomisko stāvokli, un (2) atkārto savu "mentu zaņķis" naratīvu par tiesībsargājošo iestāžu korupciju. Abi izteikumi pastiprina jau iepriekš pausto kritisko nostāju pret Latvijas valdošo eliti un valsts institūciju darbu, bez jaunas konkrētas politikas pozīcijas.', 0.6, '2026-04-29 06:28:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2196, 15, '2026-04-29', '2026-04-29', 0.0, '["Ārpolitika"]', '["After 1860 days of unjust imprisonment, Polish-Belarusian hero and Sakharov Prize laureate Andrzej Poczobut is released. We commend the efforts of the US administration."]', NULL, 'Braže atzinīgi novērtē Saharova prēmijas laureāta Andžeja Počobuta atbrīvošanu pēc 1860 ieslodzījuma dienām un izsaka pateicību ASV administrācijai. Vienlaikus norāda, ka Lukašenko režīma represijas turpinās — vairāk nekā 800 politieslodzīto joprojām atrodas apcietinājumā.', 0.9, '2026-04-29 06:31:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2199, 6, '2026-04-29', '2026-04-29', 0.0, '["Aizsardzība un drošība", "Imigrācija"]', '["Polijā dažādu līmeņu tikšanās pārrunājām vēl ciešāku sadarbību militārā un drošības jomā, lai atturētu potenciālu Krievijas agresiju un efektīvāk cīnītos pret nelegālo imigrāciju. Tikmēr Aizsardzības komisija bez manas klātbūtnes izskatīja un noraidīja priekšlikumus, kas paredz lielāku atbildību augstskolām un uzņēmumiem, kas ir iesaistīti dažādās imigrācijas shēmās. Esmu atpakaļ, aicināšu komisiju vēlreiz iedziļināties priekšlikumos."]', NULL, 'Dombrava no Polijas: pārrunāta militārā un drošības sadarbība pret Krievijas draudiem un nelegālo imigrāciju; pēc atgriešanās aicinās Aizsardzības komisiju atkārtoti izskatīt noraidītos priekšlikumus par augstskolu un uzņēmumu atbildību imigrācijas shēmās.', 0.85, '2026-04-29 06:32:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2202, 30, '2026-04-29', '2026-04-29', 0.0, '[]', '[]', NULL, 'Baško 2026-04-29: vienīgais dokuments ir tiešs retvīts no @partijaMMN par TV raidījumu pie Jāņa Dombura 8. maijā — nav Baško paša pievienota komentāra, nav ekstraktējamas pirmās personas pozīcijas.', 0.2, '2026-04-29 06:34:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2220, 57, '2026-04-29', '2026-04-29', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-04-29 dokumenti: 17 no 18 ir tīri retvīti bez Lapsas paša komentāra (RT @handle: ...). Viens (id=27941) ir Lapsas paša ieraksts, bet bez politiskas substances — sarkastisks aforisms par attēliem, neformulē nevienu pozīciju. Komentāra (commentary) ceļš pēc 2026-04-25 deprekcijas vairs negenerē jaunus commentary claims; trešo personu izteikumi retvītos paliek tikai kā saturs feedā, ne pozīcija. Visi 18 dokumenti atzīmēti pārskatīti bez claim ekstrakcijas.', 0.9, '2026-04-29 16:19:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2225, 15, '2026-04-29', '2026-04-29', 0.0, '["Ukraina un Krievija", "Ārpolitika"]', '[]', NULL, 'Visi 4 šodienas dokumenti ir bare retweets bez Bražes paša komentāra: RT @vonderleyen par ES sankcijām, RT @business par Krievijas 9. maija parādi, RT @LVembRussia par diasporas pasākumu vēstniecībā, un RT @Arlietas (MFA) ar saīsinātu Bražes paziņojumu par Počobuta atbrīvošanu — pēdējais ir relay duplikāts pirmpartijas tvītam (status 2049361127746773272), kas jau ekstraktēts kā claim 14417 šajā pašā dienā. Nav jaunas pozīcijas.', 0.5, '2026-04-29 16:19:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2227, 26, '2026-04-29', '2026-04-29', 0.0, '["Valsts kapitālsabiedrības", "Transports"]', '["Šī ir lieliska valsts kapitālsabiedrību sadarbība, par ko liels prieks.", "Patlaban tiek precizēts un sagatavots informatīvais ziņojums un protokollēmums, lai to varētu pieņemt."]', NULL, 'Švinka 2026-04-29 publiski piedalās Vivi vilcienu nosaukumu piešķiršanas iniciatīvā (PV+LVM sadarbība), pozicionējot to kā pozitīvu valsts kapitālsabiedrību sadarbības piemēru. Tajā pašā dienā komentē LETA jautājumus par ceļu būves nozares krīzi — apsola, ka SM informatīvais ziņojums ar atbalsta mehānismiem (cenu pārrēķina metodika) tuvākajā laikā tiks iesniegts MK izskatīšanai pēc Latvijas ceļu būvētāju biedrības publiskās kritikas.', 0.8, '2026-04-29 16:19:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2233, 6, '2026-04-29', '2026-04-29', 0.0, '["Imigrācija"]', '["Šodien Aizsardzības komisija lēma slēgt uzturēšanās atļauju izsniegšanu par to, ka ārzemnieks nopērk īpašumu Latvijā."]', NULL, 'Dombrava ziņo par Aizsardzības komisijas lēmumu slēgt NĪ-iegādes uzturēšanās atļaujas; pamato ar naudas atmazgāšanas riskiem un NĪ cenu pieaugumu vietējiem.', 0.9, '2026-04-29 16:20:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2249, 182, '2026-04-29', '2026-04-29', 0.0, '[]', '[]', NULL, 'Doc 27824 — TVNet raksts par Rīgas 825 gadu jubilejas koncertu, kurā piedalās mākslinieks Ozols (no grupas konteksta — nav saistīts ar Otto Ozolu, žurnālistu/kolumnistu). Vārda kolīzija: matcher saistīja, jo saturs piemin uzvārdu Ozols, bet tas attiecas uz citu personu (mūziķi). Nav ekstraktējamas politiskas pozīcijas.', 0.9, '2026-04-29 16:22:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2253, 10, '2026-04-29', '2026-04-29', 0.0, '["Pilsētvide"]', '["Vadīt Rīgu un valsti nenozīmē domāt tikai par PRO vēlētāju, ja uzņematies līderību un vadīšanu, tad jānoliek politiskās PRO ambīcijas un jādomā par visu iedzīvotāju interesēm tās sabalansējot"]', NULL, 'Kulbergs turpina kritizēt PRO virzīto Teikas skolas ielu slēgšanu — šoreiz fokusā vecāku konsultācijas leģitimitāte (norāda, ka balsošanā nav alternatīvu, vecāku viedoklis pretējs) un plašāka iesaistīto pušu (klīnika, uzņēmumi, iedzīvotāji) aptaujāšanas trūkums.', 0.85, '2026-04-29 16:22:43');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2259, 189, '2026-04-30', '2026-04-30', 0.0, '["Koalīcija un partijas", "Budžets un finanses", "Pensijas", "Aizsardzība un drošība", "Degviela un enerģētika"]', '["ir nepieciešama Satiksmes ministrijas reorganizācija, šī nedēļa pierādījusi, ka arī valdība un koalīcija ir jāreorganizē", "MK atlika nākamā gada budžeta izstrādāšanas grafika apstiprināšanu. 5 no 14 grafikā iekļautiem termiņiem jau ir pagājuši. Formālisma uzvaras gājiens.", "kura valdība nespējas savākt budžeta deficītu dēļ nolēma visiem nākotnes pensionāriem nozagt daļu no tā? Varbūt tāpēc populisti jūtas tik droši grābstīties ap 2.līmeni?", "savu personisko ķibeļu dēļ nekautrējas pagrūst priekšā VDD, lai tie amatpersonu iegribu dēļ tagad taisnojas. Tas mazina valsts drošības iestāžu ticamību daudz daudzreiz svarīgākos jautājumos.", "Risinājums būtu noteikt pienākumu kreditētājiem (visiem, arī bankām) nodot info par izsniegtu kredītu kredîtbirojiem reālajā laikā (nevis pēc dienas) un kredītbirojiem - pienākumu reālā laikā info darīt pieejamu.", "Ministrs tik \"labs\", ka 3 gadu laikā jau divi valsts sekretāri ir pametuši Aizsardzības ministriju.", "Trîs gadus Pro ir valdībā un ar šīs, it kā taču zaļās partijas gādību nav sperts pat viens solis, lai mazinātu Latvijas atkarību no dabasgāzes."]', NULL, 'Pūce kā ''Latvijas attīstībai'' priekšsēdētājs aktīvi opozicionē pašreizējo koalīciju — aicina to reorganizēt airBaltic strīda kontekstā, kritizē valdības budžeta darba tempu, aizsardzības ministra vadības spējas un Progresīvo bezdarbību enerģētikā. Aizstāv pensiju 2.līmeni un piedāvā konkrētus risinājumus kredītu informācijas apritē.', 0.8, '2026-04-29 22:44:31');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2271, 15, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, '5 dokumenti pārskatīti, neviens nesatur ekstraktējamu politisku pozīciju: 3 bare retweets (NB8/MFA/NHL), 1 NB8 tikšanās paziņojums Saaremā (ceremoniāls/faktu konstatācija bez policy stance), 1 sporta uzmundrinājums hokejam.', 0.9, '2026-04-30 08:40:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2272, 57, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, 'Lato Lapsa — 12 dokumenti pārskatīti; visi ir vai nu bāri retvīti bez komentāra, sarkastiski one-liner par citiem politiķiem, vai paša grāmatas (Strēlnieki) reklāma. Nevienā nav pirmrindas policy stance no Lapsa, ko varētu ekstraktēt kā pozīciju. Tipisks žurnālista/komentētāja feed pattern.', 0.3, '2026-04-30 08:40:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2281, 72, '2026-04-30', '2026-04-30', 0.0, '["Ukraina un Krievija"]', '["Piektajā kara gadā ikviens darījums ar Krieviju ir asiņains. Tā vairs nav nejaušība, bet gan apzināta nostāja."]', NULL, 'Indriksone (NA priekšsēdētāja) 30.04.2026 publiski spiež valdību publicēt to Latvijas uzņēmumu sarakstu, kuri turpina darījumus ar Krieviju, un kritizē, ka LIAA eksporta atbalsta saņēmēji netiek pārbaudīti. Pozīcija ir konsekventa ar 26.03.2026 Saeimas balsojumu, kurā viņa atbalstīja MK uzdevumu publicēt šādu sarakstu.', 0.9, '2026-04-30 08:41:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2286, 30, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, '2026-04-30: 1 dokuments apskatīts. Sarkastisks tvīts pret @tomsons (Latvijas Radio) par apgalvojumu, ka MMN plāno pāreju uz 4 ministrijām — Baško noliedz to ar ironisku 3 izdomātu ministriju uzskaitījumu (Faktu interpretācijas, dezinformācijas apkarošanas, iztēles reformu). Nav konkrētas politikas pozīcijas — tikai aizstāvība pret žurnālista interpretāciju ar sarkasmu. Marķēts kā empty.', 0.3, '2026-04-30 08:43:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2290, 26, '2026-04-30', '2026-04-30', 0.0, '["Valsts pārvalde"]', '["Satiksmes ministrijas (SM) reorganizācijas jautājumā šobrīd nav plānota darbinieku atlaišana"]', NULL, 'Satiksmes ministrs Atis Švinka apliecina, ka SM reorganizācijas ietvaros pašlaik nav paredzēta darbinieku atlaišana.', 0.85, '2026-04-30 08:43:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2300, 10, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, 'Viens tvīts (id=28251) ar sarkastisku komentāru par kaut kādu plānu (atkritumu auto vārtrūmēs). Bez redzama avota tvīta vai konteksta nav konkrēta pozīcija — tikai sarkastiska vienrindā piezīme. Atzīmēts kā empty.', 0.2, '2026-04-30 08:44:10');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2304, 57, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, '12 dokumenti pārskatīti — visi ir vai nu tīri retvīti bez komentāra (28264, 28265, 28089-28095), vai sarkastiski izteikumi/insinuācijas par politiskiem oponentiem (Progresīvie, Suvajevs, Naglis) bez konkrētas Lapsas paša policy pozīcijas (28262, 28263, 28088). Lapsa kā žurnālists/komentētājs šajā partijā darbojas opinion-rhetoric režīmā, ne pirmrindas policy stance režīmā. Nav ekstraktējamu pozīciju.', 0.85, '2026-04-30 09:28:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2305, 57, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, 'Lato Lapsa sesija 3/3 (2026-04-30): apstrādāti atlikušie 7 dokumenti no 2026-04-29 vakara. Visi RT bez paša komentāra (5 gab.) vai personīgs grāmatas update (1 gab. par strēlnieku grāmatas fotogrāfijām) — nav ekstraktējamas politiskas pozīcijas. 0 claims.', 0.9, '2026-04-30 09:29:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2317, 57, '2026-04-30', '2026-04-30', 0.0, '[]', '[]', NULL, 'Lato Lapsa (žurnālists) — 18 dokumenti 2026-04-30. 12 ir tīri retvīti bez komentāra (Andrislov, TomassFinks, Rodzha, Murr_berg, Heinrih5, maris_spruds, remicentrs, freemans05, DzabKepa, saabish_, Azlems). 6 paša tvīti, bet tie ir vai nu sarkastiski izteikumi bez konkrētas policy pozīcijas (sarkasms par koalīciju ar Lembergu, vulgāri salīdzinājumi, metaforas par čupu), vai paša pašcitāti uz vecākiem rakstiem bez šeit pārformulētām tēzēm. Nav ekstraktējamu pirmpersonas policy pozīciju.', 0.3, '2026-04-30 15:56:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2322, 189, '2026-04-30', '2026-04-30', 0.0, '["Degviela un enerģētika", "Pilsētvide", "Pašvaldības"]', '["Kopā - virs 30% no Latvijas patēriņa.", "Uzlikt betona norobežojumus ielai un tikai tad pārbaudīt, vai ugunsdzēsēju mašīna var izbraukt - “fantastisks” pilsētas pārvaldības piemērs.", "Arī pēdējais (vai priekšpēdējais?) ATR solis ir pārbaudīts tiesā un atzīts par Satversmei atbilstošu."]', NULL, 'Pūce 2026-04-30: kontekstualizē MK apstiprinātos vēja parku projektus (2 projekti = 17% LV elektrības patēriņa, kopā ar atlikto >30%), kritizē pilsētas pārvaldības piemēru ar betona norobežojumiem bez ugunsdzēsēju piekļuves pārbaudes, un atzīmē ATR pēdējā soļa Satversmes tiesas apstiprinājumu.', 0.75, '2026-04-30 15:56:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2338, 15, '2026-04-30', '2026-04-30', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "ES politika"]', '["Vājuma parādīšana tikai izaicina agresiju. Ja mēs vēlamies, lai mūsu valstis būtu drošībā, mums ir jāturpina stiprināt Eiropas gatavību aizsargāties", "Together, the #NB8 form a community of closest likeminded allies. We build a secure and prosperous Nordic-Baltic region, reinforce a strong NATO, and sustain unwavering support for Ukraine."]', NULL, 'Braže NB8 ārlietu ministru sanāksmē Sāremā 29.-30. aprīlī izvirzīja trīs pamatprasības — Eiropai jāuzņemas lielāka atbildība par drošību, palielinot aizsardzības izdevumus; jāturpina spiediens uz Krieviju (21. sankciju kārta + politiskā/sporta/kultūras izolācija); ASV un transatlantiskā sadarbība paliek neaizstājams pamats, ES centieniem jābūt NATO papildinošiem.', 0.85, '2026-04-30 15:58:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2349, 57, '2026-05-01', '2026-05-01', 0.0, '[]', '[]', NULL, 'Visi 5 dokumenti ir tīri retvīti (RT @...) bez Lapsas paša pievienotā komentāra. Nav pirmpersonas pozīciju, ko ekstraktēt. Saturs amplificē citu lietotāju izteikumus (Tuksumsz, E_Stendzenieks, DzabKepa, Ulddi, drikssdrikss), bet pats Lapsa neformulē savu nostāju.', 0.9, '2026-05-01 07:22:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2357, 15, '2026-05-01', '2026-05-01', 0.0, '["Ukraina un Krievija"]', '[]', NULL, '2026-04-30 X plūsma: pārsvarā retvīti par Ukrainas atbalstu, Krievijas sankciju apiešanu (A7), DPRK draudiem ANO DP, NB8 ārlietu ministru sanāksmi un Zemessardzes likuma grozījumiem. Viens pirmās personas ieraksts par Krievijas militārās intervences neveiksmi Sahārā/Mali (FT). Ceremoniāls ieraksts par NATO MND-N komandiera maiņu.', 0.6, '2026-05-01 07:24:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2362, 189, '2026-05-01', '2026-05-01', 0.0, '[]', '[]', NULL, 'Abi 30. aprīļa tvīti nesatur ekstraktējamu pirmās personas pozīciju: viens ir sarkastisks viena teikuma atsauces uz LTV7 satīrisko sēriju "Jā, ministra kungs" bez konkrētas politikas stāvokļa, otrs ir bare retvīts (RT @PuuchuksJ) bez pievienota komentāra.', 0.3, '2026-05-01 07:25:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2368, 30, '2026-05-01', '2026-05-01', 0.0, '[]', '[]', NULL, 'Nav ekstraktējamas politiskās pozīcijas — tvīts ir kultūras komentārs par sieviešu varoņfilmu žanru un feminisma vilni, bez konkrētas politikas nostājas.', 0.2, '2026-05-01 07:27:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2378, 15, '2026-05-01', '2026-05-01', 0.0, '[]', '[]', NULL, '1. maijā Braže publicē tikai ceremoniālus ES dalības 22. gadadienai un Satversmes sapulces 106. gadadienai veltītus ierakstus, kā arī bezkomentāra retvītus (Ārlietas, Sybiha, Silina, euronews, gideonrachman). Nav ekstraktējamas pirmās personas politikas pozīcijas.', 0.5, '2026-05-01 17:13:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2382, 57, '2026-05-01', '2026-05-01', 0.0, '[]', '[]', NULL, '2026-05-01: 6 dokumenti (visi tvīti), no kuriem nav ekstraktējamas pirmās personas pozīcijas — 5 ir tīri retvīti bez komentāra (29025, 29021, 29022, 29023, 29024) un 1 ir miglains sarkastiks vienliņeris bez konkrēta referenta vai politikas nostājas (29020 — "Vienīgais, uz ko šie te ir spējīgi un vienmēr gatavi.").', 0.7, '2026-05-01 17:14:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2385, 182, '2026-05-01', '2026-05-01', 0.0, '["Ārpolitika"]', '["the most dangerous conspiracy theory and scientific charlatanism of the 20th century was the doctrine of Marxism itself"]', NULL, 'Ozols 1. maijā publicē tvītu, kurā marxismu kvalificē kā 20. gadsimta bīstamāko ''sazvērestības teoriju un zinātnisku šarlatānismu'' un Marksu — par toksiska ideoloģiskā pamata licēju masu slepkavībām.', 0.85, '2026-05-01 17:14:57');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2403, 57, '2026-05-02', '2026-05-02', 0.0, '[]', '[]', NULL, 'Visi 5 dokumenti ir vai nu kaili retvīti bez paša komentāra (29135, 29137, 29138, 29139), vai sarkastisks vienrindas izteikums bez konkrētas politiskas pozīcijas (29136 — "Fubļa. Vēl viens."). Nav ekstraktējamas pirmās personas politiskas pozīcijas.', 0.2, '2026-05-02 06:32:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2413, 15, '2026-05-02', '2026-05-02', 0.0, '[]', '[]', NULL, 'Nav ekstraktējamas pozīcijas — vienīgais dokuments ir bare retvīts no @Arlietas par 4. maija svētku GIF, bez paša komentāra.', 0.2, '2026-05-02 06:35:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2417, 182, '2026-05-02', '2026-05-02', 0.0, '["Aizsardzība un drošība", "Ārpolitika", "Ukraina un Krievija"]', '[]', NULL, 'Otto Ozola 2 tvīti — asas kritikas pret Baibu Braži/Vienotību par Zemessardzes vēsturisku underfinancing un UNRWA finansēšanu, un par armijas politizēšanu (Pudāns); kā arī atbalsts starptautiskai uzmanībai Krievijas Ukrainas bērnu nolaupīšanai.', 0.8, '2026-05-02 06:35:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2422, 189, '2026-05-02', '2026-05-02', 0.0, '[]', '[]', NULL, 'Vienīgais šodien ievāktais dokuments ir bez komentāra retvīts (J_Pleps par 1. maija nozīmi) — nav paša Pūces formulētas pozīcijas.', 0.5, '2026-05-02 06:37:31');
