INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2447, 57, '2026-05-03', '2026-05-03', 0.0, '[]', '[]', NULL, 'Lato Lapsa (žurnālists) 8 X dokumenti 2026-05-03: 3 bare retweets (Krišjānis_K politiska kritika, 2 dzīvnieku labdarība), 2 sarkastiski oneliner-i bez konkrēta mērķa (āpšperson-, suga, kura jāneitralizē), 1 vēsturiska refleksija par 1917. gadu un Strēlnieku grāmatām (nav patreizēja politikas pozīcija), 1 dziesmas citāts par siltām caurulēm, 1 sarkastisks komentārs par žurnālistu asociāciju (mockery bez politikas pozīcijas). Nevienā dokumentā nav izsekojama pirmpersonas politikas pozīcija — saskaņā ar žurnālistu strictness rule visi dokumenti marķēti kā empty.', 0.9, '2026-05-03 08:07:19');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2448, 15, '2026-05-03', '2026-05-03', 0.0, '[]', '[]', NULL, 'Abi dokumenti ir tīri retvīti bez Braže pievienota komentāra: 29389 RT @USAmbNATO par Latvijas NATO izdevumiem (Braže ir objekts, ne runātāja), 29388 RT @Arlietas par Demokrātijas nedēļu. Nav pirmpersonas pozīcijas ekstrakcijai.', 0.5, '2026-05-03 08:07:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2464, 57, '2026-05-03', '2026-05-03', 0.0, '["Mediji"]', '[]', NULL, 'RT-stack and casual commentary, no extractable first-party positions today.', 1.0, '2026-05-03 15:33:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2470, 15, '2026-05-03', '2026-05-03', 0.0, '["Sabiedriskie mediji"]', '["Journalism is not a crime. Latvia''s anti-SLAPP law takes effect this month, protecting journalists from being silenced through litigation."]', NULL, 'Pasaules preses brīvības dienā Brāže uzsver, ka kvalitatīva žurnālistika ir labas pārvaldības, tiesiskuma un demokrātijas priekšnoteikums, un atzīmē, ka šomēnes stājas spēkā Latvijas anti-SLAPP likums, kas aizsargā žurnālistus no apklusināšanas ar tiesvedību. Pārējie 4 dokumenti — bāzi retvīti bez komentāra (Budanovs, MFA Polijai, Media Freedom Coalition, Ārlietu ministrija) — pozīcija nav ekstraktējama.', 0.85, '2026-05-03 15:35:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2472, 30, '2026-05-03', '2026-05-03', 0.0, '[]', '[]', NULL, 'Vienīgais dokuments — bare retvīts no @SteveSkojec bez paša komentāra. Nav ekstraktējamas pozīcijas.', 0.2, '2026-05-03 15:35:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2489, 15, '2026-05-04', '2026-05-04', 0.0, '["Ukraina un Krievija", "Ārpolitika"]', '["the work continues to support a strong, democratic, Ukraine, fully integrated in the Euroatlantic community. Freedom is never free."]', NULL, 'Neatkarības atjaunošanas dienā Braže uzsver, ka brīvība nav pašsaprotama un ka Latvija turpina darbu, atbalstot stipru, demokrātisku Ukrainu pilnībā integrētu eiroatlantiskajā kopienā.', 0.85, '2026-05-04 11:48:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2490, 57, '2026-05-04', '2026-05-04', 0.0, '["Kultūra"]', '["atšķirībā no daudziem citiem 4. maija \"varoņiem\" Dainis Īvāns nebija nekāds komunistu mēsls", "Latvijas neatkarības atjaunošanas dienas nosaukums ir liekulīgākais un ciniskākais"]', NULL, 'Lato Lapsa 2026-05-04 X plūsmā: 16 retvīti (Pietiek, citi konti) + 2 pirmpersonas izteikumi par 4. maiju — atzinīgi par Daini Īvānu (pretstats ''komunistu mēsliem''), kritisks par svētku oficiālo nosaukumu kā ''liekulīgu un cinisku''. Pārējie tvīti — bāzas retvīti vai sarkastiska vienrindiņa bez konkrētas politikas pozīcijas.', 0.7, '2026-05-04 11:48:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2501, 182, '2026-05-04', '2026-05-04', 0.0, '["Ukraina un Krievija"]', '["French actor Jean Reno has released a detective novel largely inspired by the tragic accounts of Ukrainian children abducted by Russia"]', NULL, 'Otto Ozols turpina pievērst uzmanību Krievijas īstenotajai Ukrainas bērnu nolaupīšanai no okupētajām teritorijām, šoreiz uzsverot, ka franču aktieris Žans Reno atzinis šo nodarījumu mērogu un cietsirdību par iemeslu sava jaunā detektīvromāna sarakstīšanai.', 0.8, '2026-05-04 11:51:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2524, 189, '2026-05-04', '2026-05-04', 0.0, '[]', '[]', NULL, 'Pārskatīts 1 dokuments — bare retvīts par tikšanos ar Lidiju Lasmani-Doroņinu, nav paša Pūces formulētas pozīcijas.', 0.2, '2026-05-04 11:54:21');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2533, 57, '2026-05-04', '2026-05-04', 0.0, '["Ukraina un Krievija"]', '["Progresīvajam Kleinbergam, pašam to negribot, ir sanācis perfekts 4.maija Latvijas Republikas 2026.gada portrets."]', NULL, 'Pēcpusdienas pass: Lapsa turpina 4. maija vēsturiskās atmiņas naratīvu — kritizē Progresīvo (Kleinbergs) kā mūsdienu "4. maija Republikas" simbolu. Pārējie 11 docs ir bare RT vai terse caption bez ekstraktējamas pozīcijas.', 0.6, '2026-05-04 16:21:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2543, 72, '2026-05-04', '2026-05-04', 0.0, '[]', '[]', NULL, '4. maija svētku retvīts — bez paša komentāra; nav ekstraktējamas pozīcijas.', 0.2, '2026-05-04 16:23:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2550, 15, '2026-05-05', '2026-05-05', 0.0, '["Ukraina un Krievija", "Ārpolitika"]', '["Russia launched missiles and drones at Ukraine, while pretending to offer \"ceasefire\" for their war propaganda event. […] Actions, not words, matter.", "Latvia strongly condemns Iran''s illegal and unjustified attacks against the #UAE and stands in our solidarity with our partners in the Gulf. We fully support diplomatic efforts to ensure de-escalation and safeguard freedom of navigation.", "Today Latvia allocated €100,000 to support Ukraine: \"Save Ukraine\", the UN Human Rights Monitoring Mission, and the UN ILC Fund. […] Latvia supports the return of Ukrainian children and promotes accountability for Russia."]', NULL, 'Braže 2026-05-05: trīs pirmpersonas pozīcijas — Krievijas pamiera retorika kā propaganda, Latvijas nosodījums Irānas uzbrukumiem AAE, un 100K eiro atbalsts Ukrainai. 11 dokumenti bija RT bez komentāra vai ceremoniāli (atbalvojumi, līdzjūtība Leipcigai).', 0.85, '2026-05-05 18:05:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2555, 26, '2026-05-05', '2026-05-05', 0.0, '["Degviela un enerģētika", "Transports", "Rail Baltica"]', '[]', NULL, 'Švinka 5. maijā komentē trīs satiksmes/enerģētikas tēmas: aviācijas degvielas piegāde no Norvēģijas (STEN ARNOLD, 12 000 t) kā ASV piegādes turpinājums un piegāžu drošības stiprināšana, LVCeļiem dotā iespēja pārrēķināt bitumenu saturošu darbu cenas (kompensējot izmaksu pieaugumu Tuvo Austrumu krīzes dēļ), un publiska virzība uz Eiropas standarta 1435 mm dzelzceļa sliežu pakāpenisku ieviešanu visā Latvijā kā kopprojektu ar Igauniju un Lietuvu.', 0.85, '2026-05-05 18:06:03');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2559, 57, '2026-05-05', '2026-05-05', 0.0, '["Aizsardzība un drošība"]', '["Ne tik senos laikos virsnieks ar virsnieka godu drīzāk būtu šāvies, nekā parakstītu ko šādu. Taču, protams, kāds @nbskomandieris Kasparam Pudānam pēc publiskās melošanas par krievu dronu sakars ar virsnieka godu…"]', NULL, '2026-05-05: Lapsa pārsvarā retvīto citu kritiķu izteikumus (Heinrih5, OttoOzols, JurgisLiepnieks, AlvisHermanis u.c.). Pirmajā personā vienīgā substanciālā pozīcija — asa NBS komandiera Kaspara Pudāna kritika par apgalvotu publisku melošanu saistībā ar krievu droniem un par dokumenta parakstīšanu, ko atbildīgs virsnieks neparakstītu. Saskan ar 2026-04-18 NBS ģenerāļa virsnieka goda kritiku.', 0.8, '2026-05-05 18:06:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2563, 30, '2026-05-05', '2026-05-05', 0.0, '[]', '[]', NULL, 'Trīs dokumenti pārskatīti, neviens nesatur ekstraktējamu pirmpersonas politikas pozīciju: viens bare retvīts no @tv24_lv par vēlēšanu drošības raidījumu, viens aforistisks vienrindis ("Izglītības industrija nav tas pats, kas izglītība") bez konkrēta politikas piedāvājuma, un viens NRA raksts par latviskām pēdām Krievijas frontē, kurā Baško netiek citēts un viņa pozīcija neparādās — iespējams matcher kļūdains links.', 0.7, '2026-05-05 18:06:49');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2564, 182, '2026-05-05', '2026-05-05', 0.0, '["Koalīcija un partijas", "Ārpolitika"]', '["Te ir runa par tieslietu ministri (!!!), kas būtībā sniedz tīšu nepatiesu liecību.", "Tieši cik Rietumu sabiedroto valstu steidza atzīt Baltijas valstu neatkarības atjaunošanu 1990. gadā?"]', NULL, 'Ozols kritizē JV vadību par Lībiņas-Egneres apzinātās melošanas ignorēšanu un atgādina, ka Rietumu sabiedrotie 1990. gadā neatbalstīja Baltijas neatkarību.', 0.8, '2026-05-05 18:06:49');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2590, 6, '2026-05-05', '2026-05-05', 0.0, '["Imigrācija"]', '["Gala ziņojumā ir ietverti vairāk kā simts ierosinājumi normatīvo aktu grozījumiem, ministriju un kompetento iestāžu darba pilnveidei, lai novērstu nelegālo imigrāciju, izbeigtu shēmas caur kurām tiek legalizēti ārzemnieki"]', NULL, 'Dombrava (Imigrācijas parlamentārās izmeklēšanas komisijas dalībnieks) paziņo, ka deputātiem apspriešanai nodots gala ziņojuma projekts ar vairāk nekā 100 ierosinājumiem — normatīvo aktu grozījumi, ministriju darba pilnveide, naudas atmazgāšanas un terorisma risku mazināšana, nelegālās imigrācijas novēršana. Līdz maija beigām komisijai jāvienojas par gala tekstu un jāvirza Saeimā.', 0.85, '2026-05-05 18:09:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2591, 10, '2026-05-05', '2026-05-05', 0.0, '["Valsts kapitālsabiedrības"]', '["Saeimas PIK Rīgas Siltums izmeklēšanas komisijas darbs strauji virzās uz finālu un lielajiem secinājumiem"]', NULL, 'Kulbergs (Saeimas Rīgas Siltuma PIK vadītājs) paziņo, ka izmeklēšanas komisijas darbs tuvojas finālam un lielajiem secinājumiem; tiek norādīts uz uzklausāmajām tēmām — siltuma iepirkšanas modelis, atlikumsiltuma izpūšana gaisā, šaubīgi iepirkumi, interešu konflikti, valdes personālvadība, rentabilitāte. Turpina iepriekšējo Rīgas Siltuma kritikas līniju.', 0.8, '2026-05-05 18:10:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2593, 15, '2026-05-06', '2026-05-06', 0.0, '["Ārpolitika", "Kultūra"]', '["Latvia is commited to practically supporting Armenia’s closer partnership with the EU. We must use the current momentum to implement meaningful reforms.", "Our bilateral ties and the EU-Armenia partnership are growing deeper. We must use the momentum to support Armenia’s reform agenda.", "Latvijas un partneru rīcība un spiediens nes rezultātus. Žūrija atkāpusies, ES finansējums apturēts, notiek pārbaude, un arī EK ir daudz neatbildētu jautājumu par to, kā @la_Biennale ir nodrošinājusi Krievijas dalību tajā."]', NULL, 'Ārlietu ministres Bražes 6. maija fokuss: darba vizīte Armēnijā, kur veicina Armēnijas-ES partnerības padziļināšanu un reformu atbalstu, kā arī Latvijas pretdarbības rezultāti pret Krievijas dalību Venēcijas Biennālē.', 0.85, '2026-05-06 18:19:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2613, 26, '2026-05-06', '2026-05-06', 0.0, '["Aizsardzība un drošība"]', '["Drošu valsti veidojam mēs katrs."]', NULL, 'Satiksmes ministrs Švinka 2026-05-06 X ierakstā informē par tikšanos ar Zemessardzes komandieri Aivaru Krjukovu un satiksmes nozares kapitālsabiedrībām — atbalsta praksi veidot Zemessardzes vienības no kritisko infrastruktūras objektu darbiniekiem (riga_airport, LVRTC; nākotnē LVceli, LDz, autoceli).', 0.8, '2026-05-06 18:41:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2615, 6, '2026-05-06', '2026-05-06', 0.0, '["Imigrācija"]', '["noteikt kvotas (maksimālo skaitu), cik trešo valstu pilsoņi var saņemt uzturēšanās atļaujas", "aptur jaunu uzturēšanās atļauju un ilgtermiņa vīzu izsniegšana trešo valstu pilsoņiem, ja šo pilsoņu skaits ir pārsniedzis 5% no valstī dzīvojošā Latvijas pilsoņu skaita"]', NULL, 'Dombrava (NA) 2026-05-06 X ierakstā un Delfi atspoguļojumā par Saeimas Aizsardzības komisijas sēdi par Imigrācijas likumu — kritizē komisijas lēmumu noraidīt viņa priekšlikumus: (1) kvotas trešo valstu pilsoņu uzturēšanās atļaujām un (2) jaunu uzturēšanās atļauju apturēšanu, ja trešo valstu pilsoņu skaits pārsniedz 5% no Latvijas pilsoņu skaita. Brīdina par drošības riskiem, ja imigrantu skaits turpinās pieaugt.', 0.85, '2026-05-06 18:41:57');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2619, 30, '2026-05-06', '2026-05-06', 0.0, '[]', '[]', NULL, 'Tvīts ar saiti uz raidījuma "Runāsim atklāti" video ierakstu — bez paša komentāra vai pozīcijas izklāsta.', 0.2, '2026-05-06 18:44:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2636, 182, '2026-05-06', '2026-05-06', 0.0, '[]', '[]', NULL, 'Pārskatīts 1 raksts (30304) — la.lv izklaides ziņa par satura veidotājām Sendiju un Danuti Ozolām (uzvārda kolīzija ar Otto Ozolu, off-domain false-link). Ozols nav ne runātājs, ne pieminēts politiskā kontekstā. Nav ekstraktējamas pozīcijas.', 0.9, '2026-05-06 18:54:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2642, 57, '2026-05-06', '2026-05-06', 0.0, '[]', '[]', NULL, 'Pārskatīti 12 tvīti — 11 pilni retvīti bez Lapsas paša komentāra (30444-30446, 30435-30442). Doks 30443 ir paša īss zobgalību ieraksts ("Vienotības vaukšķis saņēmis metoģičku un nu atstrādā") — sarkastiska insinuācija bez konkrētas politiskas pozīcijas par Vienotību. Skip-list: sarcastic one-liners.', 0.9, '2026-05-06 18:56:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2653, 15, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, '2026-05-07 Braže: 3 dokumenti, visi bez ekstraktējamas pirmpersonas pozīcijas. Visi trīs ir tīri retvīti bez paša komentāra (Ārlietu ministrijas LV+EN paziņojumi par Erevānas vizīti — saturs jau fiksēts vakardienas claim id=17877/17878 — un Latvijas armijas paziņojums par gaisa telpas apdraudējuma noslēgumu, kas nav Brāzes pozīcija).', 0.5, '2026-05-07 07:22:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2668, 57, '2026-05-07', '2026-05-07', 0.0, '["Aizsardzība un drošība", "Tieslietas"]', '["Ar katru nedēļu karš pienāk tuvāk Latvijai, un katra diena, kuru amatos paliek āksts Sprūds, savtīgais nelietis Rinkēvičs un pārējā varza, briesmas tikai tuvina.", "Jaunumi Levita-Vonsoviča pasūtījuma lietā: prokuratūrā sameklētais lielākais kretīns sarakstījis jau trešo apsūdzības variantu."]', NULL, 'Lapsa pieprasa Sprūda un Rinkēviča atstādināšanu pieaugošā kara draudu kontekstā un kritizē prokuratūras kompetenci Levita-Vonsoviča lietā. Pārējie 8 dokumenti — bare retvīti vai sarkastisks vispārējs uzbrukums bez konkrētas politikas pozīcijas.', 0.75, '2026-05-07 07:23:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2669, 6, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Vienīgais doc ir bare RT no @EdvinsSnore par Saeimas Aizsardzības komisijas balsojumu — nav paša Dombravas formulētas pozīcijas, tikai viņa priekšlikums tiek pieminēts trešās personas tekstā.', 0.2, '2026-05-07 07:24:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2677, 26, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Švinkas dokumentos 2026-05-07 nav ekstraktējamu pirmpersonas pozīciju. Doc 30657 (nra.lv) ir trešās puses kritisks komentāra raksts par satiksmes nozares krīzi — Švinka tiek pieminēts kā subjekts, bet tieši necitēts; raksta autori vērtē viņa rīcību, nevis viņš pats formulē pozīciju. Doc 30632 (delfi.lv) galvenokārt par Ašeradenu; Švinkas citāts par airBaltic aizdevumu ir retrospektīva atsauce (''iepriekš sacīja'') uz iepriekšēju izteikumu, kas jau atspoguļots 2026-04-25 pozīcijās. Pēc indirect-reference noteikuma — neekstraktēju.', 0.6, '2026-05-07 07:26:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2681, 57, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-07 X feed (top 12 docs pa scraped_at DESC) — 11 bare retweet bez paša komentāra (RT @AndrisVelps, @maris_spruds, @Reinisceplis, @tikaicilveks, @EDGE_I, @SirupsP, @Heinrih5, @Krisjanis_K, @rolis_g, @Tas_es_Pats, @maris_spruds atkārtots) + 1 paša sarkastiska vienrindas piezīme (id=31004) bez konkrētas politikas pozīcijas, zem Step 3 skip rules. Atlikušie 7 dokumenti (31008-31014) atstāti nākamajai sesijai pēc 12-doc circuit breaker.', 0.5, '2026-05-07 12:50:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2683, 6, '2026-05-07', '2026-05-07', 0.0, '["Aizsardzība un drošība", "Koalīcija un partijas"]', '["Šādā brīdī valsts aizsardzības nozari nevar vadīt cilvēks, kurš dod tukšus solījumus, kurus nepiepilda ar darbiem. Opozīcija virzīs Sprūda demisiju."]', NULL, 'Dombrava paziņo, ka opozīcija virzīs aizsardzības ministra Andra Sprūda demisiju pēc Nacionālās drošības komisijas sēdes par drona incidentu.', 0.9, '2026-05-07 12:51:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2688, 10, '2026-05-07', '2026-05-07', 0.0, '["Aizsardzība un drošība"]', '["Droni lido, bet cilvēkiem nav kur dronu uzbrukuma gadijumā droši paslēpties. Kur ir Krīzes Centrs?"]', NULL, 'Kulbergs kritizē patvertņu ierīkošanas trūkumu Latvijā, jautā, kur ir Krīzes Centrs, saistot ar drona incidentu.', 0.85, '2026-05-07 12:52:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2697, 182, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Sarkastisks vienrindiņas tvīts (''Kā sauc diagnozi ar personības dalīšanos?'') ar saiti, bez konkrētas politikas pozīcijas.', 0.2, '2026-05-07 12:53:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2701, 30, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Bare retvīts no @partijaMMN bez paša Baško komentāra. Tvīta saturs apcērpts, bet sākotnēji tas ir partijas video apraksts par Baško izteiksmi par vēlēšanu sistēmas maiņu — nav pirmpersonas formulējums šajā tvītā.', 0.2, '2026-05-07 12:53:48');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2704, 189, '2026-05-07', '2026-05-07', 0.0, '["Budžets un finanses"]', '["Pēdējo 4 gadu laikā vienīgā pozīcija, kas IKP augusi ievērojami, ir valsts budžeta izdevumi."]', NULL, 'Pūce apgalvo, ka pēdējo 4 gadu laikā IKP pieaugums Latvijā galvenokārt nāk no valsts budžeta izdevumiem, NEVIS no aizsardzības izdevumu pieauguma.', 0.8, '2026-05-07 12:54:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2726, 57, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Lato Lapsas 2026-05-07 X plūsmā 20 dokumenti — 17 ir tīri retvīti bez paša komentāra (galvenokārt par 7. maija dronu incidentu pie Goliševas/Ludzas, Sprūda kritika, parakstu vākšana par pensijām, Staķa sods, Saeimas ģimeņu interešu pārstāvība). 3 paša Lapsas tvīti ir vai nu sarkastiski vienrindas izteikumi bez konkrētas politiskas pozīcijas (Silenieks kā dronu eksperts; svara pieaugums) vai pašreferenciāli (par savas grāmatas rakstīšanu). Nav ekstraktējamas pirmās personas politiskas pozīcijas šajā partijā.', 0.85, '2026-05-07 17:38:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2734, 15, '2026-05-07', '2026-05-07', 0.0, '["Ukraina un Krievija"]', '["Latvia will continue to provide weapons, training, and other comprehensive assistance to meet Ukraine’s urgent battlefield and other needs."]', NULL, 'Braže apmeklē NATO Drošības palīdzības un apmācības štābu Ukrainai (NSATU) Vīsbādenē, Vācijā, un apstiprina Latvijas turpinātu militāro un apmācības atbalstu Ukrainai.', 0.85, '2026-05-07 17:39:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2748, 189, '2026-05-07', '2026-05-07', 0.0, '[]', '[]', NULL, 'Sarkastisks komentārs par Progresīvo ētikas standartiem saistībā ar apgalvotu karteli. Insinuācija bez konkrētas politikas pozīcijas.', 0.3, '2026-05-07 17:40:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2751, 6, '2026-05-07', '2026-05-07', 0.0, '["Aizsardzība un drošība", "Droni"]', '["Par bezdarbību trešdaļa Saeimas iesniedz demisijas pieprasījumu aizsardzības ministram"]', NULL, 'Dombrava 7. maija tvītā strukturētā hronoloģiskā secībā uzskaita Latgales dronu incidenta norises gaitu — beidzot ar to, ka aizsardzības ministrs (Sprūds, Progresīvie) dodas atvaļinājumā. Pati uzskaitījuma struktūra ir kritisks vēstījums: bezdarbība → demisijas pieprasījums (no NA, LPV, AS — trešdaļa Saeimas) → NBS pārstāj meklēt pazudušo dronu → ministrs atvaļinājumā. Implicītā pozīcija — kritisks pret Sprūda rīcību krīzes brīdī un atbalsts demisijai.', 0.7, '2026-05-07 17:41:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2754, 57, '2026-05-08', '2026-05-08', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-07: 5 X dokumenti (3 RT bez papildu komentāra, 1 vāgs teaser ar saiti, 1 saites apraksts). Neviens nesatur konkrētu pirmās personas politikas pozīciju.', 0.5, '2026-05-07 22:02:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2760, 15, '2026-05-08', '2026-05-08', 0.0, '[]', '[]', NULL, 'Abi 2026-05-07 tvīti ir bare retweeti (RT @IZM_gov_lv par Baltkrievijas sportistiem; RT @janis_sarts par dronu incidenta informācijas telpu) bez paša komentāra — netiek ekstraktētas pozīcijas.', 0.5, '2026-05-07 22:03:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2780, 15, '2026-05-08', '2026-05-08', 0.0, '["Ārpolitika", "Droni", "ES politika"]', '[]', NULL, 'Braže 2026-05-08: trīs pirmpersonas pozīcijas — atbalsts Bahreinas/ASV UNSC Hormuza rezolūcijai, publiska Krievijas dezinformācijas atspēkošana par Baltijas gaisa telpu UA droniem, dalība ES līdzīgi domājošo formātā Vācijā pirms NATO Zviedrijas un Ankaras samita. Pārējie 17 dokumenti — bare RT vai duplicate.', 0.85, '2026-05-08 17:48:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2781, 57, '2026-05-08', '2026-05-08', 0.0, '["Korupcija un KNAB", "Sabiedriskie mediji"]', '["Šis ir interesants atjautības uzdevums - ja beztautības progresīvajam Andrim Sprūdam ir šādi deklarēti ģimenes locekļi (mazgadīgie bērni nav jādeklarē), kas ir viņa bērnu vectēvs?", "Pārkrievotajam Ivetas Elksnes vadītajam ''sabiedriskās'' televīzijas ziņu dienestam ir ''jānes atbildība''.", "Labrīt, stulbie nodokļu maksātāji. Āksts par Jūsu naudu dienesta auto dodas tūrisma braucienā uz Rēzekni - ''apmeklēt drona nokrišanas vietu''."]', NULL, 'Lapsa 2026-05-08 publicē trīs substantīvas pozīcijas: (1) apšauba Andra Sprūda VID deklarācijas integritāti, (2) prasa atbildību LTV ziņu dienesta vadībai (Iveta Elksne), (3) kritizē neidentificētu amatpersonu par dienesta auto izmantošanu personīgam braucienam uz Rēzekni. Pārējie 9 dokumenti — bare retvīti vai vispārīgas metaforas bez konkrētas politiskās pozīcijas.', 0.75, '2026-05-08 17:48:39');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2787, 57, '2026-05-08', '2026-05-08', 0.0, '[]', '[]', NULL, 'Round 2: 7 atlikušie dokumenti — 6 bare RT (31620, 31608, 31609, 31610, 31611, 31612) bez paša komentāra; 1 sarkastisks vienliņas tvīts (31619) bez konkrētas politikas pozīcijas. Nav ekstraktējamu paša pozīciju.', 0.5, '2026-05-08 17:51:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2788, 15, '2026-05-08', '2026-05-08', 0.0, '[]', '[]', NULL, 'Round 2: 3 atlikušie X dokumenti — 2 bare retvīti (Rīgas lidostas pasažieru statistika; EPP Group pasākums Rīgā) bez komentāra un 1 ceremoniāls apsveikuma posts jaunajai Bulgārijas ārlietu ministrei. Apsveikumā minēta sadarbība ES/NATO un atbalsts Ukrainai, taču formulējumi ir diplomātiskā ceremoniālā ietvarā bez jaunas politiskas pozīcijas.', 0.6, '2026-05-08 17:52:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2795, 10, '2026-05-08', '2026-05-08', 0.0, '["Valsts kapitālsabiedrības", "Korupcija un KNAB"]', '["Likvidēsim šīs politiskās padomes ieviešot centralizēt valsts kapitālsabiedrību profesionālu pārvaldību zem Latvijas Attīstības Fonda, lai investētu un pelnītu naudu"]', NULL, 'Kulbergs publicē Rīgas Siltuma izmeklēšanas 6. sējumu — kritizē 376 000 EUR Sintētiskā Metāna pētījumu kā absurdu un nesaimniecisku, vēršas pret RS padomi, EM ministra rīcību un izceļ Apvienotā saraksta programmas elementu — politisko padomju likvidāciju un valsts kapitālsabiedrību centralizāciju zem Latvijas Attīstības Fonda.', 0.85, '2026-05-08 17:53:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2802, 26, '2026-05-08', '2026-05-08', 0.0, '["Transports"]', '["Diskusijā īpaši aktualizējām dzelzceļa attīstību, sausās ostas un reģionālo sabiedrisko transportu."]', NULL, 'Švinka 2026-05-08: tikšanās ar Tet (telesakari) un LTRK Vidzemes nodaļu Valmierā — nozares attīstība, dzelzceļš, sausās ostas, reģionālais transports. Lidostas statistikas paziņojums (2 milj. pasažieru, kravas +95%). Vienu pozīciju ekstraktēju (reģionālais transports); divi tvīti (lidostas statistika, Tet tikšanās) ir atskaites bez pozīcijas — empty.', 0.6, '2026-05-08 17:55:51');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2815, 182, '2026-05-08', '2026-05-08', 0.0, '["Ukraina un Krievija"]', '["It is crucial not to conflate two fundamentally distinct concepts: Russian culture and Putlerism."]', NULL, 'Ozols nodala krievu kultūru no Putinisma — kultūru un māksliniekus nedrīkst pielīdzināt Kremļa noziedzniekiem.', 0.75, '2026-05-08 17:59:57');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2829, 72, '2026-05-08', '2026-05-08', 0.0, '["Budžets un finanses"]', '["Imports aug strauji, eksports stagnē. Izaugsmi balstām uz ārējo finansējumu un patēriņu. Šāds modelis Latviju nepadarīs ne bagātāku, ne konkurētspējīgāku."]', NULL, 'Indriksone kritizē Finanšu ministrijas tautsaimniecības stabilitātes naratīvu, norādot uz strukturālu problēmu — imports aug, eksports stagnē, izaugsme balstās ārējā finansējumā un patēriņā. Turpina viņas iepriekšējo (2026-03-17) līniju par to, ka pašreizējais izaugsmes modelis nav ilgtspējīgs.', 0.8, '2026-05-08 18:01:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2836, 57, '2026-05-10', '2026-05-10', 0.0, '["Koalīcija un partijas"]', '["Šlesers… iegrūda Parex… Šie kabatas vaukšķi jēkabsoni uzskata Jūs par nožēlojamiem idiotiem"]', NULL, 'Lato Lapsa 9. maijā galvenokārt aktīvs ar retvītiem (kritika par Sprūdu, Siliņu, kā arī dzīvnieku patversmju atbalsts). Pati izteiktā jaunā politiskā pozīcija ir tieša apsūdzība pret Aināru Šleseru — saistīta ar Parex bankas vēsturi un apsūdzība par vēlētāju maldināšanu.', 0.65, '2026-05-10 04:28:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2842, 15, '2026-05-10', '2026-05-10', 0.0, '["Kultūra"]', '["Culture cannot become a shelter for those who destroy it"]', NULL, 'Eiropas dienā (9. maijā) ārlietu ministre Braže publicēja viedokļa rakstu Kyiv Independent, kurā argumentē, ka kultūra nedrīkst kalpot par patvērumu tiem, kuri to iznīcina — Eiropas vērtību aizstāvēšana nozīmē stāvēt kopā ar Ukrainu. Pārējie 9. maija tvīti ir RT (Eiropas dienas sveicieni, paša raksta retranslācijas, sabiedroto pateicības) bez papildu pirmpersonas pozīcijas.', 0.85, '2026-05-10 04:29:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2846, 72, '2026-05-10', '2026-05-10', 0.0, '["Budžets un finanses"]', '["Latvijas ekonomikai nav vajadzīga atlikšana uz vēl četriem gadiem"]', NULL, 'Indriksone kritizē valdību par cilvēkkapitāla attīstības stratēģijas trūkumu trīs gadu laikā un saista labklājību ar gudru ekonomiku, kvalitatīvu izglītību un cienīgu atalgojumu.', 0.7, '2026-05-10 04:30:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2847, 6, '2026-05-10', '2026-05-10', 0.0, '["Aizsardzība un drošība", "Koalīcija un partijas"]', '["Būtiski, lai viņa vietā nenonāk nākamais progresīvais, kas turpinās bremzēt Latvijas armijas attīstību."]', NULL, 'Dombrava 9. maijā tvīto par gaidāmo aizsardzības ministra maiņu — iebilst pret vēl viena Progresīvo pārstāvja iecelšanu šajā amatā, apgalvojot, ka partija bremzē Latvijas armijas attīstību. Otrais tvīts ir sarkastisks komentārs par Krievijas V-Day svētkiem.', 0.8, '2026-05-10 04:30:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2856, 182, '2026-05-10', '2026-05-10', 0.0, '[]', '[]', NULL, '2026-05-09: 1 tvīts ar krievvalodīga eksperta Sergeja Auslendera ieteikumu kā analītiķi par Maskavas pasākumu. Eksperta rekomendācija, nevis paša politiskā pozīcija par Krieviju vai militārām/ārpolitikas tēmām.', 0.7, '2026-05-10 04:30:33');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2859, 30, '2026-05-10', '2026-05-10', 0.0, '["Koalīcija un partijas"]', '["Politikā priekšlikumu autorībai ir nulle nozīmes"]', NULL, 'Baško aizstāv principu, ka politiskām idejām nav un nedrīkst būt ''autortiesības'' — idejas politikā ir efektīvas tikai tad, ja citi tās brīvi izmanto un modificē; pat ja MMN nesasniegs varu, sekmīgu ideju pārņemšana no konkurentiem skaitīsies kā ieguldījums Latvijai.', 0.85, '2026-05-10 04:30:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2872, 189, '2026-05-10', '2026-05-10', 0.0, '["Aizsardzība un drošība", "Koalīcija un partijas"]', '["Skaidrs, ka @AndrisSpruds bija jāatlaiž. Ne tik daudz par 2 droniem Rēzeknē, cik par 3 nomuļļātiem gadiem Aizsardzības ministrijā."]', NULL, 'Pūce 2026-05-10 X tvītos: skaidri atbalsta Sprūda atlaišanu, motivējot ar 3 gadu nesakārtotu Aizsardzības ministrijas darbu (ne tikai droniem Rēzeknē); paplašina kritiku uz Siliņas kadru izvēles standartiem (Kozlovska piemērs). Pārējie divi tvīti — RT ar sarkastisku komentāru par Puriņa atlūgumu un retoriska aptauja par PRO palikšanu valdībā — bez pirmpersonas pozīcijas. Pozīcija konsistenti turpina iepriekšēju AM kritiku (#14465, 2026-04-22 par valsts sekretāriem).', 0.85, '2026-05-10 20:24:33');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2881, 15, '2026-05-11', '2026-05-11', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "Droni"]', '["Premjere @EvikaSilina uzskata, ka valsts aizsardzībai nepieciešama cita, profesionāla, pieeja.", "The stronger Ukraine is on the battlefield, the stronger its position at the negotiating table"]', NULL, 'Braže 2026-05-10/11: pēc Sprūda atkāpšanās publiski atbalsta Siliņas izvirzīto Raivi Melni AiM vadībai (profesionāla, ārpus priekšvēlēšanu retorikas pieeja). Briselē tiekas ar Ukrainas ĀM Sibihu, atkārto ''peace through strength'' formulu. Apstiprina, ka Rēzeknes droni Latvijā nokļuva Krievijas elektroniskās karadarbības dēļ.', 0.8, '2026-05-11 13:26:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2884, 72, '2026-05-11', '2026-05-11', 0.0, '["Koalīcija un partijas"]', '["Valdībai ir jāatkāpjas. Esmu gatava veidot nacionālās drošības valdību.", "Nepietiek nomainīt vienu ministru, ja visa valdība ir zaudējusi spēju vadīt valsti.", "Esošā valdība ir sevi izsmēlusi, tāpat kā Vienotība savu iespēju to vadīt."]', NULL, 'Pēc aizsardzības ministra Andra Sprūda (P) demisijas 2026-05-11, NA priekšsēdētāja Ilze Indriksone X tvīta sērijā un Delfi paziņojumā pieprasa visas Siliņas valdības atkāpšanos un piedāvā NA vadīt nacionālās drošības valdību kopā ar AS, ZZS un JV. Konkrēti pasaka, ka Vienotība ir ''izsmēlusi iespējas'' vadīt valdību. Sprūda nomaiņu ar pulkvedi Raivi Melni viņa atzīst par nepietiekamu — vajag pilnu valdības maiņu.', 0.92, '2026-05-11 13:27:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2886, 189, '2026-05-11', '2026-05-11', 0.0, '["Koalīcija un partijas", "Sabiedriskie mediji"]', '["Divas valdības partijas sacenšas, kura ātrāk X-ā paziņos - vai Sprūds ir atlaists vai pats atkāpies.", "Par ko nebija sižets @ltvdefacto? Par to, ka kartelī ir iesaistīts uzņēmums, kura PLG ir Progresīvo populārākais politiķis..."]', NULL, 'Pūce 2026-05-11 turpina Sprūda demisijas tematiku: kritizē JV+PRO par publisku komunikācijas sacensību (32936), uzdod retoriskus jautājumus par Siliņas procesu (32938) un sarkastiski apzīmē koalīciju kā ''Muldēšanas čempioni'' (32932). Atsevišķi 2026-05-10 vakara tvīts kritizē LTV De facto par Staķa (Progresīvie) saistību ar karteļa uzņēmumu nesižetēšanu (32937). Trīs RT bez komentāra netika ekstraktēti.', 0.8, '2026-05-11 13:28:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2898, 10, '2026-05-11', '2026-05-11', 0.0, '["Degviela un enerģētika"]', '["Visām iesaistītajām pusēm ir jāierodas ar piedāvājumu risinājumam"]', NULL, 'Kulbergs izziņo pēdējo siltuma PIK izmeklēšanas sēdi 12.maijā 14:00 Saeimā, sasaucot SPRK, Latvenergo, Rīgas siltumu, EM, KEM, Rīgas domi un KP. Definē piecus risinājuma virzienus tarifu samazināšanai un siltumsaimniecības sakārtošanai.', 0.85, '2026-05-11 13:33:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2908, 6, '2026-05-11', '2026-05-11', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība"]', '["NA ir gatava veidot un vadīt nacionālās drošības valdību darbam līdz gaidāmajām Saeimas vēlēšanām. \"Vienotība\" ir izsmēlusi iespējas vadīt valdību.", "9.maijā policija un drošības dienests strādāja ļoti labi. Netika pieļauts, ka tiek publiski slavināta Krievija vai PSRS."]', NULL, 'Dombrava (NA) pēc Sprūda demisijas paziņo, ka ''Vienotība'' izsmēlusi iespējas vadīt valdību un NA ir gatava veidot un vadīt nacionālās drošības valdību līdz Saeimas vēlēšanām. Atsevišķā tvītā uzteic policijas un drošības dienesta darbu 9. maijā un norāda uz Latvijā dzīvojošiem agresorvalstij lojāliem cilvēkiem kā saglabājušos problēmu.', 0.9, '2026-05-11 13:33:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2914, 30, '2026-05-11', '2026-05-11', 0.0, '[]', '[]', NULL, '', 0.0, '2026-05-11 13:34:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2916, 26, '2026-05-11', '2026-05-11', 0.0, '["Ukraina un Krievija"]', '["Pateicības pasākumā @RigasDome izteicām sirsnīgu pateicību 11 autobusu vadītājiem, kuri ar lielu atbildības sajūtu nogādāja mūsu @Rigassatiksme_ lietotos sabiedriskā transporta autobusus Ukrainā."]', NULL, 'Švinka (Progresīvie, satiksmes ministrs) ziņo par Rīgas satiksmes lietoto autobusu nogādāšanu Ukrainai — 11 autobusu vadītāji nogādāja autobusus kā praktisks atbalsts. Atsevišķā tvītā sveic Guntu Anču ar ievēlēšanu European Disability Forum prezidentes amatā (ceremoniāls).', 0.75, '2026-05-11 13:35:08');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2919, 15, '2026-05-11', '2026-05-11', 0.0, '["Ukraina un Krievija", "Aizsardzība un drošība", "Ārpolitika"]', '["Šodien ES Padomē pieņēmām jaunas sankcijas pret 16 personām un 7 organizācijām...", "Vērtīga tikšanās ar NATO Ģenerālsekretāru Marku Ruti par praktiskiem soļiem NATO atturēšanas un aizsardzības stiprināšanai..."]', NULL, 'Otrais 2026-05-11 cikls (11 dokumenti): 4 pirmās personas pozīcijas (ES sankcijas pret Krievijas bērnu deportāciju, NATO austrumu flanga aizsardzība ar Rutti, Kanādas FM tikšanās, Bosnijas Deitonas atbalsts), 7 bare retvīti bez komentāra.', 0.85, '2026-05-11 17:23:45');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2923, 26, '2026-05-11', '2026-05-11', 0.0, '["Transports"]', '["Visam Rīgas apvedceļam jākļūst par drošu un ātru maģistrāli."]', NULL, 'Švinka X tvītā atbalsta Rīgas apvedceļa pārveidi par drošu maģistrāli, paziņojot, ka A4 posmam Baltezers–Salaspils drīzumā plāno iepirkt projektēšanas darbus, un norādot, ka nākamajā ES fondu periodā šim nepieciešams piešķirt finansējumu.', 0.85, '2026-05-11 17:24:43');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2930, 189, '2026-05-11', '2026-05-11', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība"]', '["Gribētos dzirdēt no premjeres, kā viņa praktiski iedomājas koalīcijas darbu. Piemēram, vai ir balsis Meļņa apstiprināšanai? Vai ir balsis tām valdibas iniciatīvām, kas jau ir Saeimā vai ir ceļā uz to?", "2025.gadā no AizsM aizgājuši 54 ierēdņi un 2026.gadā jau 20 ierēdņi. Kopā pusotra gada laikā 74 no 311(318). Brinums, ka tā iestāde vēl vispār funkcionē."]', NULL, 'Pūce 11.05. tvītos pauž skepsi par koalīcijas darbspēju pēc Sprūda demisijas — pieprasa premjerei skaidrību par balsīm Meļņa apstiprināšanai, iepirkumu likumam un pašvaldību likumam — un izceļ AizsM personāla aizplūdumu (74 ierēdņi 1,5 gada laikā no 311) kā ministrijas pārvaldības problēmu.', 0.85, '2026-05-11 17:25:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2945, 72, '2024-12-05', '2024-12-05', 0.0, '["Koalīcija un partijas"]', '["Ja šī valdība krīt, mēs neesam gatavi kļūt par tādu kā stuti esošās valdības izmaiņu gadījumā... Mēs esam gatavi veidot jaunu valdību, ja šī valdība kritīs"]', NULL, 'Indriksone pirms partijas vadības pārņemšanas paziņo: NA gatava veidot jaunu valdību, ja Siliņas valdība krīt, sadarbībā ar Apvienoto sarakstu.', 0.9, '2026-05-11 20:29:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2946, 72, '2024-12-05', '2024-12-05', 0.0, '["Koalīcija un partijas"]', '["Šobrīd ir laiks gatavoties Saeimas vēlēšanām, lai varam nonākt situācijā, ka Nacionālā apvienība var vadīt valdību"]', NULL, 'Indriksone par NA vadības maiņu: tas ir solis virzienā uz to, lai NA kļūtu par vadošo partiju Latvijā; šķelšanos partijā neredz.', 0.9, '2026-05-11 20:30:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2947, 72, '2024-12-15', '2024-12-15', 0.0, '["Koalīcija un partijas"]', '["Es ļoti centīšos šo, šobrīd vēl teikšu - avansā doto, uzticības mandātu attaisnot", "mēs plānojam pastiprināt tieši ekonomiskās drošības un ekonomiskās izaugsmes jautājumu pievienošanu programmai vēl daudz vairāk nekā līdz šim"]', NULL, 'Indriksone, pārņemot NA vadību 2024-12-15, sola turpināt Dzintara virzienu un pastiprināt ekonomiskās drošības un izaugsmes jautājumus partijas programmā.', 0.85, '2026-05-11 20:31:08');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2948, 72, '2025-12-13', '2025-12-13', 0.0, '["Koalīcija un partijas"]', '["Šis gads partijas vadībā man lika piekrist un kļūt par partijas premjera amata kandidāti. Mēs nekad nebūsim tie, kas darīs kaut ko, lai visiem patiktu", "mūsu valsts būs latviska savā būtībā, droša savā spēkā, turīga savās iespējās un plaukstoša savā tautas ataudzē"]', NULL, 'Indriksone NA kongresā 2025-12-13 pieņem premjera amata kandidāta statusu; iezīmē četrus uzstādījumus — latviska, droša, pārtikusi Latvija ar atbalstītām ģimenēm.', 0.9, '2026-05-11 20:31:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2949, 72, '2026-01-28', '2026-01-28', 0.0, '["Imigrācija", "Izglītība"]', '["Lēta darbaspēka ievešana lielos apjomos Latvijas ekonomikai nekādu labumu nesniedz", "tās valstis, kas ir bijušajā NVS [Neatkarīgo valstu sadraudzības] grupā, nebūtu mūsu prioritāte, un arī terorisma nedrošās, potenciāli bīstamās valstis noteikti nebūtu prioritāte"]', NULL, 'Indriksone (raidījums Labrīt, 2026-01-28): iebilst pret lēta darbaspēka masveida ievešanu, jo tas palielina drošības riskus; trešo valstu studentiem nepieciešami starptautiski iestājeksāmeni, prioritāte ne-NVS un ne-terorisma valstis.', 0.9, '2026-05-11 20:32:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2950, 72, '2026-03-03', '2026-03-03', 0.0, '["Koalīcija un partijas"]', '["valdība spēs \"nesagāzties\" un nostrādāt līdz termiņa beigām, tomēr nespēs pieņemt lielus un būtiskus lēmumus", "Nacionālā apvienība nav valdībā tāpēc, ka partijai dažādos jautājumos ir pretrunas ar \"Progresīvajiem\". Un tā bija pareiza izvēle, redzot, kā šobrīd valdība strādā", "lielākā šīs valdības problēma, ka viņi strādā katrs par sevi, katrs savā ministrijā"]', NULL, 'Indriksone 2026-03-03 vērtē Siliņas valdību: nesagāzīsies, bet būtiskus lēmumus pieņemt nespēs; NA bija pareiza izvēle nepalikt valdībā ar Progresīvajiem; lielākā problēma – katrs ministrs strādā par sevi.', 0.9, '2026-05-11 20:33:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2975, 15, '2026-05-12', '2026-05-12', 0.0, '["Ukraina un Krievija", "Droni", "ES politika", "Aizsardzība un drošība"]', '["Russia''s mass kidnapping and deportation of Ukrainian children is a crime under the Genocide Convention. Latvia supports all practical efforts to #BringThemHome", "Ukrainas droni, kas mērķēti Krievijas militārajiem objektiem, apzinātas Krievijas rīcības rezultātā ir novirzīti uz Latviju, kur nokrita.", "Support for Ukraine: security guarantees, military aid & progress towards EU; Pressure on Russia & work on the EU''s 21st sanctions package", "Paldies drošības dienestiem un Valsts policijai par rūpēm par mūsu drošību un sabiedrisko kārtību, lai Krievijas kara propagandas pasākumi Latvijā nenotiktu."]', NULL, 'Braže 2026-05-08–12: Ukrainas atbalsts (bērnu atgriešana = ģenocīds), Krievijas apzināta dronu novirzīšana uz Latviju, ES 21. sankciju pakete, drošības dienestu pateicība par propagandas novēršanu.', 0.85, '2026-05-12 09:01:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2978, 72, '2026-05-12', '2026-05-12', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība"]', '["Esmu gatava veidot nacionālās drošības valdību.", "Mūsu pieprasītā demisija ir īstenota divkārt!"]', NULL, 'NA frakcijas vadītāja Ilze Indriksone pieprasa visas Siliņas valdības atkāpšanos pēc Sprūda demisijas un piedāvā veidot ''nacionālās drošības valdību'' kopā ar AS, ZZS un JV; norāda, ka Vienotība esot izsmēlusi savu iespēju vadīt valdību.', 0.85, '2026-05-12 09:03:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (2985, 30, '2026-05-12', '2026-05-12', 0.0, '[]', '[]', NULL, 'RT, TV laika atgādne un sarkastisks komentārs bez konkrētas politikas pozīcijas.', 0.5, '2026-05-12 09:04:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3006, 26, '2026-05-12', '2026-05-12', 0.0, '[]', '[]', NULL, 'Vēstnesis komandējuma rīkojums un LSM raksts, kurā Švinka pieminēts kā ZZS prasības mērķis, bet pats nerunā — Siliņa un ZZS ir runātāji.', 0.5, '2026-05-12 09:07:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3008, 6, '2026-05-12', '2026-05-12', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība", "Imigrācija"]', '["Nacionālā apvienība ir gatava izveidot un vadīt jaunu, rīcībspējīgu valdību", "Cik ilgi mēs gaidīsim dažādus incidentus no Krievijas puses, lai šādu lēmumu pieņemtu?"]', NULL, 'Dombrava izsaka NA gatavību veidot un vadīt jaunu valdību pēc Sprūda demisijas un Siliņas valdības krīzes. 2025. gada septembrī viņš pārstāvēja NA priekšlikumu slēgt Latvijas robežu ar Krieviju un Baltkrieviju, reaģējot uz dronu incidentiem Polijā un gaidāmajām militārajām mācībām.', 0.9, '2026-05-12 09:07:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3017, 15, '2026-05-12', '2026-05-12', 0.0, '[]', '[]', NULL, 'Braže papildu 8 Vēstnesis/twitter dokumenti — administratīvie MK rīkojumi (komandējumi, parakstītas iemaksas) un trešo personu pieminējumi. Bez ekstraktējamas pirmās personas pozīcijas.', 0.5, '2026-05-12 09:08:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3029, 10, '2026-05-12', '2026-05-12', 0.0, '["Valsts kapitālsabiedrības", "Korupcija un KNAB"]', '["Jebkurā civilizētā Eiropas valstī amatpersonas publiska pieķeršana melos nozīmē tās atkāpšanos. Bez jebkādām diskusijām.", "Droši vien tikai nevainīga sagadīšanās ir, ka šāds vērtīgs kadrs vaiga sviedros vienlaikus izpildās triju publisku kapitālsabiedrību padomēs, kas ir vienas politiskās partijas pārraudzībā."]', NULL, 'Kulbergs (AS) 2026-05-12 X tvītā pieprasa Jevgenija Belezjaka atkāpšanos no Rīgas siltuma padomes, ņemot vērā melu pieķeršanu, un kritizē viņa vienlaicīgu sēdēšanu triju publisko kapitālsabiedrību padomēs (Rīgas siltums, Getliņi Eko, Latvijas Autoceļu Uzturētājs), kas, viņaprāt, ir vienas politiskās partijas pārraudzībā.', 0.85, '2026-05-12 09:15:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3030, 189, '2026-05-12', '2026-05-12', 0.0, '[]', '[]', NULL, 'Dokuments 33727 pārskatīts, bet nav ekstraktējamas politiķa pozīcijas: Vestnesis Inčukalna detālplānojums — Pūce nav minēts, surname collision ar J. Zilversu (komitejas priekšsēdētājs)', 0.2, '2026-05-12 09:16:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3044, 15, '2026-05-12', '2026-05-12', 0.0, '["Ukraina un Krievija"]', '["The only obstacle to peace is the butcher in kremlin, who wants his imperialistic war to continue to subjugate Ukraine"]', NULL, 'Braže publiski nostāda Putinu kā vienīgo šķērsli mieram — Ukraina, ASV un Eiropa vēlas mieru', 0.9, '2026-05-12 17:46:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3049, 15, '2026-05-13', '2026-05-13', 0.0, '["Ārpolitika"]', '[]', NULL, 'Bražes 12 X-platformas dokumenti 2026-05-12/13 logā ir 11 bare retweets (LSM, Zelenskyy, Arlietas, Daces Melbārdes, Canada FP, LTV, Latvia UN, @PuukjisIN par balsojumu pret Melni) un 1 ceremoniāls apsveikums Anitai Orbānai par stāšanos Ungārijas ārlietu ministres amatā. Nevienā doc nav Bražes pievienota komentāra vai pirmpersonas pozīcijas, kas izietu Step 3 skip-list (retvīti bez komentāra, apsveikumi). Visi 12 doc → empty.', 0.9, '2026-05-13 09:03:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3053, 57, '2026-05-13', '2026-05-13', 0.0, '[]', '[]', NULL, 'Lato Lapsas 12 vecāko 2026-05-12/13 dokumentu apstrāde: visi tukši ekstrakcijai. 11 ir tīri retvīti bez komentāra (galvenokārt @PietiekPortals virsraksti par valdību, Bunkus, SmartX, tramvaju, airBaltic, kā arī @E_Stendzenieks, @AnceAV, @jautaa_veel, @vellapasts par Brēmaņa/banku tēmām). Viens (34212) ir paša vienrindas sarkasms — ''''Nu padomājiet paši, ko var izdarīt nieka divarpus gados'''' — bez konkrētas politikas pozīcijas vai adresāta; klauna emoji norāda, ka tas ir tipisks Lapsas izsmiekls par esošās valdības darba periodu, taču bez ekstraktējamas pozīcijas. 6 jaunākie dokumenti (34196-34201) atstāti nākamajai sesijai pēc sesijas plāna.', 0.9, '2026-05-13 09:03:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3063, 30, '2026-05-13', '2026-05-13', 0.0, '[]', '[]', NULL, 'Abi dokumenti nav ekstraktējami: 34142 — sarkastiska atbilde uz anonīmu "nekonservatīvu politiķi" televīzijā, bez konkrētas politikas pozīcijas; 34143 — anonimizēta sistēmiska argumentācija ("Partija X", "pasažieris Y"), atsakās no konkrētiem subjektiem, tāpēc nav identificējama pozīcija pret konkrētu politiku vai personu.', 0.3, '2026-05-13 09:04:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3079, 57, '2026-05-13', '2026-05-13', 0.0, '["Aizsardzība un drošība"]', '["Kur tad sabiedrības spiediens palika?🤡 ... vai tiešām Aizsardzības ministrijai vajag galveno ierēdni, kurš nule ir prasti melojis sabiedrībai un sevi parādījis kā pagļēvu bezprincipu konformistu?"]', NULL, 'Lapsa turpina kritisku AM personāla līniju — pieprasa atstādināt AM galveno ierēdni (valsts sekretāra līmenī) par publisku melošanu un bezprincipu konformismu. Pārējie 5 dok šajā partijā ir bare retweets (#34196, 34197, 34198, 34200) un retorisks jautājums bez konkrētas nostājas (#34199).', 0.7, '2026-05-13 13:22:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3083, 182, '2026-05-13', '2026-05-13', 0.0, '[]', '[]', NULL, 'vestnesis platform — administratīvs publikācijas žurnāls (tiesu nolēmumi, MP rīkojumi, teritorijas plānojumi, konkursi, reģistru ziņas); netiek apstrādāts caur claim-extractor pipeline (sk. analyze.py:193).', 0.2, '2026-05-13 13:22:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3087, 15, '2026-05-13', '2026-05-13', 0.0, '["Koalīcija un partijas"]', '["Diemžēl t.s. progresīvo rīcība ir pretēja valsts aizsardzības un drošības pamatinteresēm, savus ego liekot tām pāri."]', NULL, 'Braže (JV ārlietu ministre) 13.05 X tvītā kritizē Progresīvos par rīcību, ko vērtē kā pretēju valsts aizsardzības un drošības pamatinteresēm, apgalvojot, ka partija savu ego liek pāri šīm interesēm. Konteksts: dienu pēc Sprūda (PRO) atkāpšanās aizsardzības ministra amatā un JV ultimāta koalīcijas turbulencei.', 0.85, '2026-05-13 13:48:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3090, 189, '2026-05-13', '2026-05-13', 0.0, '["Koalīcija un partijas"]', '["Progresīvie Siliņai vairs neuzticas, bet Švinka un Lāce turpinās strādāt Siliņas vadītā valdībā.", "Latvijai ir gandrīz Šrēdingera koalīcija — kamēr neskatās virsū, nekādi nevar pateikt — dzīva vai mirusi."]', NULL, 'Pūces 2026-05-13 X-aktivitāte koncentrējas uz koalīcijas turbulenci pēc Sprūda demisijas — sarkastiski norāda uz Progresīvās partijas nekonsekvenci (uzticības atsaukums premjerei kombinēts ar ministru palikšanu valdībā) un raksturo koalīciju kā de facto neesošu (''Šrēdingera koalīcija'', ''mirušās koalīcijas partneri atliek bēres''). Pozīcijas turpina viņa 11.05 paustās šaubas par valdības darbspēju.', 0.65, '2026-05-13 13:48:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3091, 57, '2026-05-13', '2026-05-13', 0.0, '[]', '[]', NULL, '2026-05-13 sesija #57 round 3 — 7 jauni unreviewed dokumenti, visi tukši: 5 bare retvīti bez Lapsas pievienota komentāra (34472 @E_Stendzenieks par betona klučiem; 34474 @Tas_es_Pats sarkasms par NBS; 34475 @andrislov sarkasms par Robinhood; 34476 @maris_spruds par helikopteriem; 34471 @Heinrih5 par LTV/TV3 izmaksām). 2 paša Lapsas tvīti ar ārēju saiti, bet bez konkrētas politiskas pozīcijas tekstā: 34470 (''Zaudējumu summa — puse no apgrozījuma. Pārliecinoša piramīda.'') — bez nosaukta subjekta tekstā, atsauce uz t.co attēlu, ko nevar atrisināt; 34473 (''Aizvien saticīgāk un saticīgāk.🦡🦊🐱'') — bez nosauktas tēmas vai subjekta, tikai sarkastisks vienrindas komentārs ar dzīvnieku emoji. Step 3 skip-list piemērojams (sarkastiski vienrindas bez konkrētas politiskās pozīcijas) + Step 3b self-check (nav pašam ekstraktējamas pirmpersonas pozīcijas).', 0.2, '2026-05-13 13:49:03');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3098, 72, '2026-05-13', '2026-05-13', 0.0, '["Koalīcija un partijas", "Imigrācija", "Budžets un finanses"]', '["Drošību, ekonomiku un budžetu nevar atlikt \"pēc vēlēšanām\".", "Latvijai ir vajadzīga drosme pieņemt lēmumus."]', NULL, 'Indriksone (NA līdere) izklāsta trīs prioritāšu programmu — imigrācijas lēmumi tagad, ekonomikā jāatceļ birokrātija/saskaņošana, budžeta caurspīdīgums. Politiska kampaņas formulējums uz vēlēšanu sliedēm.', 0.85, '2026-05-13 13:50:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3111, 182, '2026-05-13', '2026-05-13', 0.0, '[]', '[]', NULL, 'Doc 34487: Ozols (žurnālists, first_party) — sarkastiska kritika ar netiešu insinuāciju par Latvijas tieslietu mīkstumu pret kontrabandistiem; nav konkrētas politikas pozīcijas (Step 3 skip — sarkastiska viena rinda bez nostājas).', 0.5, '2026-05-13 13:51:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3121, 189, '2026-05-14', '2026-05-14', 0.0, '["Koalīcija un partijas"]', '["Vienotība un Progresīvie kopīgiem spēkiem atdeva valdību Nacionālajai apvienībai, Apvienotajam sarakstam un ZZS", "katrs, kas vēlēšanu gadā gāž valdību, dabū smagi ciest par to"]', NULL, 'Pēc Siliņas demisijas Pūce komentē koalīcijas sabrukumu — JV un PRO kopā ir atdevuši valdību NA-AS-ZZS centram, un vēsturiski tie, kas vēlēšanu gadā gāž valdību, cieš politiski.', 0.75, '2026-05-14 10:37:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3123, 72, '2026-05-14', '2026-05-14', 0.0, '["Koalīcija un partijas"]', '[]', NULL, 'NA valdes priekšsēdētāja Indriksone apstiprināja, ka Nacionālā apvienība uz 14. maija sarunu par jaunas valdības veidošanu aicinājusi līdzšinējās koalīcijas dalībnieci ZZS un opozīcijā esošo AS.', 0.7, '2026-05-14 10:38:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3129, 182, '2026-05-14', '2026-05-14', 0.0, '[]', '[]', NULL, '1 dokuments — ironisks tvīts ar 2006. gada citātu salīdzinājumu (''Jādod iespēja Šleseram''/''Nav jāšūpo Siliņa valdību''). Bez tiešas pirmās personas politiskās pozīcijas — sarkastisks vēstures piesaucens, ne politikas paziņojums.', 0.3, '2026-05-14 10:39:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3138, 6, '2026-05-14', '2026-05-14', 0.0, '["Imigrācija", "Koalīcija un partijas"]', '["Drošības interesēs ir jāaptur masu imigrācija", "Siliņas valdība ir beigusi darbu"]', NULL, 'Dombrava (NA) pēc Siliņas demisijas atkārto divus galvenos NA vēstījumus: (1) masu imigrācijas apturēšana drošības iemeslu dēļ; (2) jaunas, rīcībspējīgas valdības bez JV nepieciešamība.', 0.85, '2026-05-14 10:41:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3153, 10, '2026-05-14', '2026-05-14', 0.0, '["Degviela un enerģētika", "Korupcija un KNAB"]', '["Lēnām un negribīgi PIK iesaistītās institūcijas atzīst kļūdas", "Tā saimniekot nevar. Ir nepieciešama jauna politiķu paaudze"]', NULL, 'Kulbergs (AS) ziņo, ka PIK Saeimas izmeklēšanas komisija un Valsts Kontroles ziņojums apstiprina viņa ilgstoši paustās kritikas par Rīgas Siltuma un Latvenergo siltuma iepirkuma sistēmu — TEC atlikumsiltums tiek izšķērdīgi izlaists, Latvenergo tarifa metodika ir nepareiza un sadārdzināta, RS iepirkuma tirgus ir nepilnīgs, RS pārvaldība ir slikta. Aicina uz politiķu paaudžu maiņu.', 0.85, '2026-05-14 10:44:33');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3164, 30, '2026-05-14', '2026-05-14', 0.0, '["Valsts pārvalde"]', '["Aizliegt decentralizēti pasūtīt un finansēt \"pētījumus\"... Tā vietā uzdod vienam valsts kantorītim, kas uzģenerē tādas blēņas pēc pasūtījuma VISIEM un par grašiem."]', NULL, 'Jāzeps Baško (MMN, ģenerālsekretārs) 2026-05-13 X tvītā piedāvā centralizēt valsts pasūtīto "pētījumu" anketēšanu vienā kantorī, lai novērstu decentralizētus zemas kvalitātes pasūtījumus par desmitiem un simtiem tūkstošu eiro.', 0.85, '2026-05-14 10:44:38');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3169, 15, '2026-05-14', '2026-05-14', 0.0, '[]', '[]', NULL, 'Visi 12 ingestoti dokumenti ir bare retvīti (Ārlietu ministrija, Rinkēvičs, Siliņa, Zviedrijas vēstniecība, MFA, LSM, LTV, Yarotrof, Daugavietis) vai ceremoniāls komentārs (Andreja Rītiņa mūžībā). Šajā vilnī ārlietu ministrei nav pirmpersonas politikas pozīciju.', 0.2, '2026-05-14 10:45:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3174, 57, '2026-05-14', '2026-05-14', 0.0, '["Koalīcija un partijas"]', '["Ir kritusi viskremliskākā, Latvijai visiznīcinošākā valdība."]', NULL, '20 dokumenti — Lapsa kā opozicionārs žurnālists. Lielākā daļa ir kaili retvīti par valdības krīzi (Krauzes/Kronberga aizturēšana, Šļesera komentāri, Stakja kafijas karteļa skandāls) vai sarkastiski komentāri bez konkrētas politikas pozīcijas. Viens substanciāls vērtējuma izteikums Siliņas valdības adresē — kritisks gala vērtējums kā ''viskremliskākā, Latvijai visiznīcinošākā''.', 0.65, '2026-05-14 10:46:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3182, 15, '2026-05-15', '2026-05-15', 0.0, '[]', '[]', NULL, 'Visi trīs 2026-05-15 dokumenti (35515, 35516, 35517) ir bare retweets bez Bražes pašas komentāra — divi par Krievijas uzbrukumu Kijevai (SESU_UA, UNReliefChief), viens par humāno palīdzību Hersonā (OCHA_Ukraine). Tā kā nav pievienota teksta, tās nav pirmās personas pozīcijas pēc skip-list noteikuma.', 0.9, '2026-05-15 04:47:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3192, 30, '2026-05-15', '2026-05-15', 0.0, '["Valodu politika"]', '["Paldies tiem, kas gādāja, lai otro gadu pēc kārtas sūtām dziesmu latviešu valodā."]', NULL, 'Baško atbalsta latviešu valodas izvēli Eirovīzijas konkursā un kritizē iepriekšējos gadus, kad Latvija sūtīja dziesmas svešvalodā.', 0.85, '2026-05-15 04:49:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3194, 57, '2026-05-15', '2026-05-15', 0.0, '[]', '[]', NULL, 'Abi dokumenti ir tīri retvīti bez Lapsas paša komentāra — viens @christiansvsl par kafijas aparātu karteļa lietu, otrs @Astridamains par prokuratūru/tiesām/korupciju. Lapsa neizteic savu pozīciju, tikai pārpublicē citus.', 0.9, '2026-05-15 04:50:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3195, 182, '2026-05-15', '2026-05-15', 0.0, '[]', '[]', NULL, 'Visi 2 dokumenti tukši: doc#35550 ir tīrs retvīts (RT @sofiafonsoferre par Hamas/Izraēlu, bez Ozola komentāra); doc#35551 ir triviāla piezīme par Euronews drukas kļūdu Siliņas uzvārdā (Sili vietā Siliņa) — nav politiskas pozīcijas.', 0.9, '2026-05-15 04:50:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3200, 72, '2026-05-15', '2026-05-15', 0.0, '["Koalīcija un partijas"]', '["Nacionālās apvienības (NA), \"Apvienotā saraksta\" (AS) un Zaļo un zemnieku savienības (ZZS) pārstāvji vienojušies par sadarbību, veidojot potenciālās nākamās koalīcijas kodolu", "pagaidām uz sarunām netika aicināta \"Jaunā vienotība\", bet sarunas gaidāmas arī ar šo politisko spēku"]', NULL, '14.05 Indriksone kā NA valdes priekšsēdētāja un premjerministres amata kandidāte publiski apstiprina, ka NA, AS un ZZS konceptuāli vienojušies par sadarbību jaunas koalīcijas kodola veidošanā. Sarunas ar JV plānotas vēlāk. Trīs partiju kopā ir 41 balss, JV 25 — koalīcijai nepieciešama JV piedalīšanās lai sasniegtu Saeimas vairākumu.', 0.85, '2026-05-15 07:06:25');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3206, 6, '2026-05-15', '2026-05-15', 0.0, '[]', '[]', NULL, 'Tikai paziņojums par dalību LTV1 raidījumā par nākamo valdību — bez konkrētas pozīcijas formulējuma. Atzīmēts kā tukšs.', 0.2, '2026-05-15 07:07:10');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3213, 10, '2026-05-15', '2026-05-15', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība", "Budžets un finanses"]', '["Esmu pārliecināts, ka šis ir brīdis, kad jāuzņemas atbildība, nevis jānoraugās, kā valsts arvien dziļāk grimst neizlēmībā un stagnācijā.", "Tehniska valdība vai valdība, kura tikai formāli eksistē līdz Saeimas vēlēšanām, mums nav pieņemams redzējums."]', NULL, 'Apvienotais saraksts 15.05.2026 izvirzīja Kulbergu par premjera amata kandidātu gan sarunās par jaunu koalīciju šajā Saeimas sasaukumā, gan rudens vēlēšanās. Kulbergs paziņoja gatavību uzņemties amatu un noraidīja tehnisku/pārejas valdību kā iespējamu risinājumu. AS galvenais uzdevums — trīskārša drošība (militāra, ekonomiska, pilsoniska) un kārtība valsts finansēs.', 0.85, '2026-05-15 19:42:49');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3216, 26, '2026-05-15', '2026-05-15', 0.0, '["Aizsardzība un drošība", "Vēlēšanas", "Sociālā politika"]', '["valsts drošības un aizsardzības stiprināšanu; drošu un uzticamu nākamo Saeimas vēlēšanu procesa nodrošināšanu; dzīves dārdzības mazināšanu"]', NULL, 'Sarunā ar Valsts prezidentu Švinka uzsver Progresīvo trīs prioritātes — drošību, vēlēšanu integritāti un dzīves dārdzības mazināšanu.', 0.85, '2026-05-15 19:43:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3223, 189, '2026-05-15', '2026-05-15', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība"]', '["Šajos apstākļos īstermiņa valdību 3 nedēļu laikā jāspēj salikt. Ja partijas to nespēj, tad demonstrē savu bezatbildību.", "Situācijai atbilstoši būtu ātri izveidot jaunu valdību. Vajadzēs pieņemt ātrus un svarīgus lēmumus un ''klibas pīles'' nederēs."]', NULL, 'Pūce 15.05.2026 piecos tvītos par valdības krīzi: prasa īstermiņa valdību salikt 3 nedēļās ar konkrētu uzdevumu sarakstu (5-6 valstij, 2-3 katram ministram); noraida ''klibas pīles'' jeb tehnisku valdību; piedāvā prioritātes — pretdronu aizsardzība, taupības pasākumi.', 0.85, '2026-05-15 19:45:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3233, 57, '2026-05-16', '2026-05-16', 0.0, '[]', '[]', NULL, 'Lato Lapsas 12 jaunāko tvītu apskats 2026-05-15/16. 11 no 12 ir bare RT bez Lapsas pievienotā komentāra (Vienotības/Sprūda komentāri, Dzintars, DzabKepa suņu adopcija, AmiSkywalker, Jenotsons, JanisVoins, Krišjānis_K). 1 first-party tvīts (#36156) ir sarkastisks one-liner par Stukāna sarunu biedra nāvi bez konkrētas politikas pozīcijas. Nav ekstraktējamu pirmās personas pozīciju šajā partijā.', 0.85, '2026-05-16 11:44:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3238, 189, '2026-05-16', '2026-05-16', 0.0, '[]', '[]', NULL, 'Divi bare-RT bez komentāra (telco darījums hansa_lv, krāpnieku īsziņas DPD vārdā elnormous). Nav ekstraktējamu pozīciju.', 0.2, '2026-05-16 11:45:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3250, 30, '2026-05-16', '2026-05-16', 0.0, '["Valsts pārvalde"]', '["Valstij nevar būt mērķa. Mērķtiecīga valsts mērķu vārdā izmantos piespiedu varu, lai pakļautu tos, kas neparakstās uz nosprausto mērķi."]', NULL, 'Baško publicē izvērstu ideoloģisku eseju par valsts mērķiem — apgalvo, ka valstij nedrīkst būt savu mērķu, jo tie nenovēršami noved pie piespiedu varas un birokrātijas pārākuma pār individuālo brīvību. Valsts funkcija pielīdzināma basketbola noteikumiem: nodrošināt apstākļus, kuros cilvēki var sasniegt savus mainīgos mērķus, nevis uzspiest kolektīvu mērķi.', 0.85, '2026-05-16 11:46:45');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3251, 6, '2026-05-15', '2026-05-15', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība"]', '["Nacionālai apvienībai ir spēcīga komanda un plāns kā strauji sakārtot aizsardzības resoru un pretdronu sistēmu. ... Esam gatavi vadīt spēka ministrijas, lai padarītu Latviju par drošāku valsti."]', NULL, 'Dombrava (NA) pēc Siliņas demisijas konteksta atkārto NA pretenziju vadīt valdību ar konkrētu akcentu uz spēka ministrijām (Aizsardzība, IeM), kritizē Progresīvo/JV koalīciju par drošības laika pazaudēšanu un piesauc imigrācijas + civilās aizsardzības + pretdronu sistēmas sakārtošanu kā NA platformu.', 0.85, '2026-05-16 11:47:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3260, 182, '2026-05-16', '2026-05-16', 0.0, '[]', '[]', NULL, 'Otto Ozols 2026-05-16: 3 dokumenti — visi trīs ir bare retweets bez Ozola pievienota komentāra (RT @RudensLapaVeeja par satrauktu pilsoni, RT @DakdaR22 par Ukrainas karu, RT @DakdaR22 par miera nosacījumu). Step 3 skip-list: retvīti bez komentāra nav personīga pozīcija. Nav ekstraktējamu pirmpersonas nostāju.', 0.9, '2026-05-16 11:47:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3265, 15, '2026-05-16', '2026-05-16', 0.0, '["Ukraina un Krievija"]', '["Russia is still stuck in Donbas. 🇺🇦 has the momentum, we must step up our support."]', NULL, 'Lennart Meri konferencē Tallinā Braže paziņo, ka Krievija militāri stagnē Donbasā un aicina pastiprināt atbalstu Ukrainai. Pārējie šīs dienas tvīti ir vai nu RT-i bez komentāra, vai ceremoniāli vizītes paziņojumi.', 0.85, '2026-05-16 11:48:10');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3269, 72, '2026-05-16', '2026-05-16', 0.0, '["Koalīcija un partijas", "Sociālā politika"]', '["Latvijai ir nepieciešama jauna, rīcībspējīga valdība pēc iespējas ātrāk.", "NA piedāvā palielināt ģimenes valsts pabalstu... palielināt bērnu kopšanas pabalstu līdz 600 eiro."]', NULL, '2026-05-15 NA priekšvēlēšanu paziņojumi: Indriksone Rīgas saraksta līdere un NA premjera kandidāte, partijas programma akcentē latvisku, augošu, drošu un ģimenēm draudzīgu Latviju ar konkrētiem ģimenes politikas pasākumiem (€600 bērnu kopšanas pabalsts, hipotekārā kredīta dzēšana). Pēc Rinkēviča tikšanās uzsver jaunas valdības steidzamību un pauž NA elastību strādāt arī zem cita partneru vadības.', 0.78, '2026-05-16 14:56:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3271, 72, '2026-05-16', '2026-05-16', 0.0, '["Koalīcija un partijas", "Sociālā politika"]', '["Latvijai ir nepieciešama jauna, rīcībspējīga valdība pēc iespējas ātrāk.", "NA piedāvā palielināt ģimenes valsts pabalstu... palielināt bērnu kopšanas pabalstu līdz 600 eiro."]', NULL, '2026-05-15 NA priekšvēlēšanu paziņojumi: Indriksone Rīgas saraksta līdere un NA premjera kandidāte, partijas programma akcentē latvisku, augošu, drošu un ģimenēm draudzīgu Latviju ar konkrētiem ģimenes politikas pasākumiem (€600 bērnu kopšanas pabalsts, hipotekārā kredīta dzēšana). Pēc Rinkēviča tikšanās uzsver jaunas valdības steidzamību un pauž NA elastību strādāt arī zem cita partneru vadības.', 0.78, '2026-05-16 14:57:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3273, 10, '2026-05-16', '2026-05-16', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība", "Budžets un finanses", "Valsts pārvalde"]', '["Tai ir jābūt rīcības koalīcijai, kur emocijas un strīdi jāliek pie malas pilnīgi visiem.", "Pirmo reizi šajā Saeimā es ceru, ka mums izdosies izveidot plašu koalīciju.", "Drošība ir acīmredzama prioritāte – nauda tai ir piešķirta, tikai ir atbildīgi jārīkojas."]', NULL, '2026-05-16: Prezidents Rinkēvičs uzticējis Kulbergam jaunās valdības veidošanu pēc Siliņas demisijas. Kulbergs preses konferencē pavēstī par ''plašās koalīcijas'' ambīciju ar AS+NA+ZZS+PRO+JV (LPV atvirzīts), ''rīcības koalīcijas'' modeli, vasaras darba režīmu, jūnija budžeta pārskatu, drošības kā ''acīmredzamas prioritātes'' (nauda jau piešķirta — atbildīgi jārīkojas) un ministru atlasi pēc ''strādātāju'' kritērija. Saņēmis prezidenta apstiprinājumu par pilnu atbalstu. 25. maijā jāziņo prezidentam par koalīcijas aprisēm un valdības deklarācijas uzmetumu.', 0.88, '2026-05-16 15:00:33');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3280, 10, '2026-05-17', '2026-05-17', 0.0, '["Degviela un enerģētika", "Digitālā politika"]', '["Nekādas AER jaudas nespēj pastāvēt bez modernām kontrolēti ģenerējošām jaudām - tā ir realitāte.", "Šī ir mūsu iespēja būt visefektīvākajiem, ātrākajiem, gudrākajiem birokrātijas un izmaksu samazināšanā"]', NULL, 'Kulbergs (AS) post-Siliņas demisijas un pirms premjera kandidāta uzdevuma pieņemšanas pauž divus jaunus uzsvarus: (1) enerģētikas drošības brīdinājums par kontrolējamo jaudu iztrūkumu (Latvenergo TEC, Imantas TEC), kas papildina viņa ilgstošo Rīgas siltuma līniju ar plašāku stratēģisku rāmējumu; (2) MI valsts pārvaldē kā ekonomiskās efektivitātes svira. 22369 (NRA intervija) tikai ievads bez jaunas pozīcijas — saturs jau pārklāts ar 2026-04-21 X-thread claim sēriju. 33853 ceremoniāls paziņojums par komisijas sēdi.', 0.85, '2026-05-16 23:25:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3282, 57, '2026-05-17', '2026-05-17', 0.0, '["Tieslietas", "Sabiedriskie mediji"]', '["koruptā Bunkus prāvas tiesnese, pildot mentu zaņķa saimnieku vēlmes, ir bijusi gatava uz visu", "kāds ir partiju finansējums no valsts budžeta un kāds ir mediju finansējums no SIF/MAF"]', NULL, 'Lato Lapsas 2026-05-11..16 X aktivitāte fokusēta uz tiesu sistēmas un mediju kritiku: konkrēta apsūdzība Bunkus prāvas tiesnesei, Lembergu prāvas liecību noklusēšana, un Progresīvo nekompetences kritika par mediju/partiju valsts finansēšanu (SIF/MAF).', 0.7, '2026-05-16 23:26:25');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3289, 15, '2026-05-17', '2026-05-17', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "Ārpolitika"]', '[]', NULL, 'Braže nedēļas darba kārtība: NATO Austrumu flanga pretgaisa aizsardzība + Ukrainas aizsardzības inovāciju pārņemšana NATO līmenī, Jordānijas pirmā vēsturiskā vizīte ar starpvaldību MoU, CTBTO Floida tikšanās ar pozīciju par Krievijas kodolretoriku, Īpašā tribunāla izveide Agresijas nozieguma izmeklēšanai pret Ukrainu, kā arī Krievijas globālā ietekme caur ārvalstu pilsoņu vervēšanu karam.', 0.85, '2026-05-16 23:29:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3301, 57, '2026-05-17', '2026-05-17', 0.0, '["Aizsardzība un drošība", "Degviela un enerģētika"]', '["Un šī ir tikai mazmazītiņa kripatiņa no visa tā, kas nāks dienas gaismā par Sprūda un \"progresīvo\" saimniekošanu uz valsts drošības finansējuma rēķina.", "Gada laikā Sprūda Aizsardzības ministrijā nomainījusies sestā daļa darbinieku. Mja…", "Vai pastāstīt, kādas astronomiskas summas par gāzi Jūs samaksājāt šīs ekonomikas ministres amatā panikā kritušās muļķes dēļ?", "\"Es atkāpjos no aizsardzības ministra amata, lai pasargātu Latvijas armiju no ieraušanas politiskā kampaņā,\" teica Andris Sprūds. Nekas jauns. Komunisti melo vienmēr. Vienmēr."]', NULL, 'Lato Lapsa turpina aso līniju pret Aizsardzības ministru Andri Sprūdu un Progresīvo partiju: agregētā statistika (1/6 AM darbinieku gada laikā), atkāpšanās paskaidrojuma noraidīšana kā melu un solījums par turpmākiem atklājumiem par budžeta saimniekošanu. Atsevišķs aspekts — vēsturiska apsūdzība ekonomikas ministrei (visticamāk Indriksonei) par augstām gāzes cenām.', 0.7, '2026-05-17 05:50:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3302, 15, '2026-05-17', '2026-05-17', 0.0, '["Ukraina un Krievija"]', '[]', NULL, 'Subject-queue 7 dokumenti (round 2 leftover). 1 jauna pozīcija (#35246 ANO OCHA personāla uzbrukumi), 6 atzīmēti tukši: 35247 dup ar #20439 (19.05 sēdes pieprasījums), 35251 vispārīgs unwavering support pārklājas ar #18100/#10945, 35220 la.lv/Euronews pārskats bez Bražes jaunas tiešas pozīcijas, 32447/31479/31450 Sibihas paziņojumi (Braže tikai pieminēta kā saziņas partnere — viņas dronu pozīcija jau #18101).', 0.85, '2026-05-17 05:51:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3305, 72, '2026-05-17', '2026-05-17', 0.0, '["Koalīcija un partijas", "Budžets un finanses"]', '[]', NULL, 'Indriksone turpina 2026-05-11 sāktās valdības atkāpšanās prasības eskalāciju — LTV intervijā (12.05) valdību raksturo kā "aprēķina laulību pirms prezidenta vēlēšanām", kritizē FM/EM iekšējās nesaskaņas par fiskālo stabilitāti. X tvītā tajā pašā dienā Siliņas pirms gada solīto "restartu" raksturo kā "valdības sabrukumu tiešraidē".', 0.85, '2026-05-17 05:51:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3307, 26, '2026-05-17', '2026-05-17', 0.0, '["Korupcija un KNAB", "Aizsardzība un drošība", "Koalīcija un partijas", "Transports"]', '["Latvijas politikā kopumā un nākamajās valdībās jānodrošina nulles tolerance un pilnīga norobežošanās pret šāda veida lietu kārtošanu un 90. gadu “vērtībām”, ko atklāj kokrūpnieku lieta.", "Valsts drošības jautājumos katrs nepārdomāts, nepatiess paziņojums var palīdzēt tiem, kas vēlas pārbaudīt un vājināt Latvijas drošību.", "ZZS rindās jau vairāk kā pusgadu valda acīmredzams haoss un panika"]', NULL, 'Švinka šajā periodā: (1) atbalsta nulles toleranci kokrūpnieku lietā un atgādina, ka Progresīvie jau 2025-11 vērsa uzmanību uz ZM nelikumībām; (2) iebilst pret nepatiesu apgalvojumu par AM 40% kadru mainību, akcentē atbildīgu drošības komunikāciju; (3) kritizē ZZS haosu koalīcijā, taču aizstāv kopā veidotās koalīcijas pareizību; (4) paplašina SM mēnešbiļešu atlaižu piedāvājumu uz reģionālajiem autobusiem.', 0.85, '2026-05-17 05:52:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3309, 182, '2026-05-17', '2026-05-17', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija", "Korupcija un KNAB"]', '[]', NULL, 'Ozola 4 X-tvītu pārskats 2026-05-12..16: Trampa-NATO geopolitiskā dāvana Ķīnai+Krievijai; satīriska Putin-kā-Šrēdera-aģenta inversija ar Ļeņina-rusofobijas paralēli; KNAB selektīvas politiskās kalpošanas JV interesēm apsūdzība (ZZS+Kaimiņa lieta). 1 tvīts (Stubb "Agree?" citāts) bez paša pozīcijas — empty.', 0.78, '2026-05-17 05:52:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3317, 57, '2026-05-17', '2026-05-17', 0.0, '[]', '[]', NULL, 'Final round (Lato Lapsa pid=57): subject-queue 10 tweets, visi sarkastiski vienrindi, retoriski jautājumi vai personiski apvainojumi bez konkrētas politiskas pozīcijas. Atbilstoši Step 3 skip-listei (sarcastic one-liners and insinuations without a concrete policy stance; rhetorical questions with no stated answer), nevienu nesaglabāju.', 0.5, '2026-05-17 06:29:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3323, 6, '2026-05-17', '2026-05-17', 0.0, '["Koalīcija un partijas"]', '["Trīs politiskie spēki ir gatavi iztikt bez politiskiem strīdiem, lai strauji izveidotu funkcionēt spējīgu valdību"]', NULL, 'Dombrava (NA) 15.05.2026 valdības krīzes vidū paziņo, ka nav iespējams ilgstoši strādāt ar demisionējušo Siliņas valdību, un aicina trīs politiskos spēkus ātri izveidot jaunu funkcionētspējīgu valdību ar prioritātēm imigrācijā, pretgaisa aizsardzībā un valsts izdevumu efektivizācijā.', 0.85, '2026-05-17 06:40:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3325, 189, '2026-05-17', '2026-05-17', 0.0, '[]', '[]', NULL, '', 0.5, '2026-05-17 06:40:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3337, 10, '2026-05-17', '2026-05-17', 0.0, '[]', '[]', NULL, 'Pārskatīti 5 dokumenti (1 tvīts + 4 web raksti par premjera kandidāta nominēšanu 16.05). Nevienā nav ekstraktējamas pirmpersonas pozīcijas: 36764 ir ceremoniāls pateicības tvīts par Rinkēviča uzticēšanos; 36707/36708 ir LSM un Diena ziņu lediji par paša nominēšanu (Kulbergs minēts kā subjekts, nav citēts); 36709 ir politoloģes Kažokas komentārs; 36711 ir Rinkēviča izteikums par AM kandidāta profilu. Substantīvās Kulberga pozīcijas no 16.05 jau saglabātas vakarā (#20391-20395).', 0.85, '2026-05-17 07:26:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3350, 30, '2026-05-17', '2026-05-17', 0.0, '["Koalīcija un partijas"]', '["Politiskas partijas uzdevums ir nevis piedāvāt visus labākos risinājumus visām problēmām, bet piedāvāt paredzamai ideoloģijai atbilstošus risinājumus"]', NULL, 'Baško formulē ideoloģisku politikas izpratni — partijas loma nav piedāvāt "objektīvi labāko" risinājumu, bet ideoloģijai atbilstošu.', 0.8, '2026-05-17 15:58:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3357, 15, '2026-05-18', '2026-05-18', 0.0, '["Ārpolitika"]', '["Tiekoties ar Filipīnu Republikas ārlietu ministri Terēzu P. Lazaro, mēs apspriedām nākamos soļus divpusējo attiecību un tirdzniecības, sadarbības ANO, kā arī ES un ASEAN partnerības padziļināšanā."]', NULL, '2026-05-17 dienā Braže X timeline dominē retvīti (Zeļenskis × 2, Ārlietu ministrija × 2, Iltalehti) un pateicības ziņojumi (NBS, ugunsdzēsēji) — visi bez pievienota komentāra. Vienīgais ekstraktējamais pirmās personas pozīcijas signāls ir 16.05 tikšanās ar Filipīnu ārlietu ministri par divpusējās un ES–ASEAN sadarbības padziļināšanu.', 0.75, '2026-05-18 09:09:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3364, 10, '2026-05-18', '2026-05-18', 0.0, '["Koalīcija un partijas"]', '[]', NULL, 'Delfi raksts (2026-05-17) ir politologa Jāņa Ikstena komentārs par Andra Kulberga (AS) izredzēm izveidot AS+NA+ZZS mazākuma valdību ar LPV atbalstu vai plašāku koalīciju ar JV. Kulbergs šajā dokumentā tieši netiek citēts — viņa nostājas (drošība/vēlēšanas/budžets kā prioritātes; mazākuma valdības noraidījums) ir trešās personas parafrāze un jau ekstraktētas no 2026-05-15/16 pirmsmandāta preses konferences (claims #20169-20171, #20391-20395). Bez papildu ekstraktējamām pirmpersonas pozīcijām.', 0.85, '2026-05-18 09:10:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3365, 189, '2026-05-18', '2026-05-18', 0.0, '["Koalīcija un partijas"]', '["Kopumā prezidenta argumentācija kandidāta izvēlē ļoti loģiska. Liela atbildība tagad @AndrisKulbergs un @Apvienotais_ , jo Latvija šajos smagajos apstākļos nedrīkst ilgi būt bez valdības."]', NULL, 'Pūce 2026-05-16 publiski atbalsta prezidenta izvēli jaunajam premjera kandidātam un aicina Apvienoto sarakstu (Kulbergu) uzņemties atbildību par ātru valdības izveidi — Latvija ilgi nedrīkstot palikt bez valdības.', 0.8, '2026-05-18 09:10:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3368, 182, '2026-05-18', '2026-05-18', 0.0, '["Koalīcija un partijas"]', '["E. Siliņas valdības \"krišana\" ir iestudēts farss. Dronu nokrišana bija nevis patiesais iemesls, bet gan apzināti dramatizēts iegansts."]', NULL, 'Ozols 17.05 tvītā kvalificē Siliņas valdības atkāpšanos pēc dronu incidenta kā iestudētu priekšvēlēšanu farsu, ko izmantoja JV un PRO, lai pirms vēlēšanām distancētos no nepopulārās valdības. Saukā JV par "prokremlisko". Pārējie trīs tvīti šajā logā — bare RT (vācu, norvēģu) un Katalāņu valodā par karoga simbolu — nav ekstraktējamas pozīcijas.', 0.85, '2026-05-18 09:11:05');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3372, 6, '2026-05-18', '2026-05-18', 0.0, '["Vēlēšanas"]', '["Nacionālā apvienība mani ir izvirzījusi par saraksta līderi Vidzemē. Paldies par izrādīto uzticību! Man būs gods vest NA komandu. Par stipru un latvisku Latviju!"]', NULL, 'Jānis Dombrava paziņo, ka Nacionālā apvienība viņu izvirzījusi par saraksta līderi Vidzemē 2026. gada Saeimas vēlēšanās, un apliecina gatavību vadīt NA komandu reģionā.', 0.9, '2026-05-18 09:11:31');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3377, 57, '2026-05-18', '2026-05-18', 0.0, '["Korupcija un KNAB"]', '["Vienotības un progresīvo vaukšķu skatījumā Loginovs, loģiski, ir izsmiekla vērts - kur nu tādam ar Linkaitiem, Briškeniem un Švinkām līdzināties. Ne simtus miljonu, ne miljardus nav izpļekarējis un izzagt palīdzējis, pat ne ostu līdz bankrotam nav novedis."]', NULL, 'Lapsa sarkastiskā formā apsūdz JV/Progresīvo politiķus Linkaitu, Briškenu un Švinku liela mēroga publisko līdzekļu izšķērdēšanā un izzagšanas atbalstīšanā (simtu miljonu/miljardu līmenī), kā arī apsūdz Švinku (kā ostas pārvaldītāju) ostas novešanā bankrotā.', 0.7, '2026-05-18 09:12:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3380, 15, '2026-05-18', '2026-05-18', 0.0, '[]', '[]', NULL, '12 dokumenti (2026-05-17/18 X tvīti no @Braze_Baiba) — visi vai nu RT bez komentāra (AizsardzibasMin, EvikaSilina, Latvian_MFA, ltvzinas, Arlietas, CanadaFP, haynesdeborah, urotbergs), vai ceremoniāli/sporta izteikumi par Latvijas hokeja izlasi. Nav neviena pirmpersonīga politikas formulējuma.', 0.9, '2026-05-18 10:09:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3392, 6, '2026-05-18', '2026-05-18', 0.0, '[]', '[]', NULL, 'Nav ekstraktējamu pozīciju: visi 5 x_mention dokumenti ir trešo personu (liana_langa, SpicyGaullism) sarakste, kurā @janisdombrava parādās tikai kā atbildes ķēdes handle vai kā Langa parafrazēts citāts. Dombrava pats nav runātājs nevienā dokumentā (role=''mention_target''). Step 3 indirektā atsauce — pozīcijas par 3. valstu pilsoņu izmaksām un NA balsojumu par SK/partnerattiecību likumu pieder Langai un SpicyGaullism, ne Dombravam.', 0.2, '2026-05-18 10:11:19');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3398, 10, '2026-05-18', '2026-05-18', 0.0, '["Koalīcija un partijas", "Valsts pārvalde", "Budžets un finanses", "Rail Baltica"]', '["Jo plašāka koalīcija veidos līdz vēlēšanām strādājošo valdību, jo labāk.", "AS Kulberga veidotajā valdībā noteikti pretendējot uz Finanšu ministrijas vadīšanu.", "Gatavs virzīt arī bezpartejiskus ministra amata kandidātus, izvērtējot katras jomas vajadzības."]', NULL, 'Pirmā pilnā darba diena pēc premjera kandidatūras saņemšanas (16.05.). Plaša mediju intervija TV3 + LTV ''Rīta panorāma'' atklāj sešas konkrētas pozīcijas: (1) RB+airBaltic personīga atbildība un SaM pārstrukturēšanas piedāvājums ar īpašo uzdevumu ministru tikai RB jomai; (2) AS pretendē uz Finanšu ministrijas vadīšanu, jūnijā jau pārskatāms budžets; (3) ministriju optimizācija līdz vēlēšanām nav paveicama; (4) taupīt valsts pārvaldē — izšķērdīgos iepirkumos, NEVIS veselībā/izglītībā; (5) gatavs virzīt bezpartejiskus ministrus; (6) MK darbu dalītu divās sēdēs — budžeta un tehniskajā. Pretrunu ar prior claim''iem nav konstatētas — saturs paplašina #20391-20395 ar konkrētiem ministru/portfeļu līmeņa solījumiem.', 0.85, '2026-05-18 10:11:38');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3400, 72, '2026-05-18', '2026-05-18', 0.0, '["Koalīcija un partijas"]', '["Saprātīgākais risinājums jaunajā koalīcijā būtu ietvert \"Apvienoto sarakstu\" (AS), Nacionālo apvienību (NA), Zaļo un zemnieku savienību (ZZS) un \"Jauno vienotību\" JV"]', NULL, 'Indriksone (NA) 18.05 TV3 "900 sekundēs" konkrēti nosauc AS+NA+ZZS+JV kā saprātīgāko koalīcijas kompozīciju. Atjaunina 11.05 "nacionālās drošības valdības" formulu pēc-demisijas kontekstā; konsekventi ar 14.05 ziņojumu par NA+AS+ZZS kodolu.', 0.85, '2026-05-18 10:11:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3403, 26, '2026-05-18', '2026-05-18', 0.0, '["Rail Baltica", "Aizsardzība un drošība"]', '["Rail Baltica pabeigšana 2030. gada termiņā ir izaicinoša.", "Manā skatījumā ir nepieciešama reorganizācija, atstājot tikai informācijas koordinācijas un saziņas ar Eiropas Komisiju funkcijas, būtiski samazinot darbinieku skaitu."]', NULL, 'Pirms Tallinas Baltijas valstu satiksmes ministru tikšanās (19.05.2026) Švinka publiski formulē Latvijas pozīciju Rail Baltica jautājumā: 2030. termiņš izaicinošs ierobežotā budžeta dēļ (paralēli aizsardzībai >5% IKP); pieprasa RB Rail kopuzņēmuma reorganizāciju ar darbinieku skaita samazināšanu un funkciju ierobežošanu līdz koordinācijai/EK saziņai, atsaucoties uz Polijas un Somijas modeli. Dokumentā nav minēta dienas Lapsa apsūdzība ostu bankrotā — Švinka šeit nereaģē uz to.', 0.92, '2026-05-18 10:12:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3410, 26, '2026-05-18', '2026-05-18', 0.0, '["Valsts kapitālsabiedrības"]', '["Manā skatījumā ir nepieciešama reorganizācija, atstājot tikai informācijas koordinācijas un saziņas ar Eiropas Komisiju funkcijas."]', NULL, 'Papildinājums analīzei 3403: RB Rail kopuzņēmuma reorganizācijas pozīcija klasificēta atsevišķi kā Valsts kapitālsabiedrības, lai izvairītos no idempotency dedup pret Rail Baltica topic.', 0.95, '2026-05-18 10:13:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3412, 15, '2026-05-19', '2026-05-19', 0.0, '["Ukraina un Krievija"]', '["Krievija atkal melo. Šoreiz dezinformācijas kampaņu pret Latviju īsteno Krievijas Ārējās izlūkošanas dienests (SVR). FAKTS: Latvija neļauj izmantot savu gaisa telpu uzbrukumiem Krievijas teritorijā."]', NULL, 'Ārlietu ministre Braže 19.05 reaģēja uz Krievijas SVR dezinformācijas kampaņu, kas apgalvoja, ka Latvija atļauj Ukrainas spēkiem izmantot savu teritoriju uzbrukumiem Krievijai. Braže atkārtoja Latvijas pozīciju — gaisa telpa netiek izmantota uzbrukumiem Krievijas teritorijā; pozīcija paziņota arī premjeres Siliņas un prezidenta Rinkēviča vārdā.', 0.85, '2026-05-19 10:07:22');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3415, 57, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, '12 jaunākie tvīti (2026-05-19, ID 37760-37771) — 11 bare RT bez pievienota komentāra; 1 paša grāmatas promo (37765); 1 nenosaukta personiska insinuācija (37761); 1 fragmentēts citāts-komentārs ''Nē,…'' (37770). Nevienā nav Lapsa pirmpersonas konkrētas politikas nostājas — visi atbilst Step 3 skip-list (bare RT / sarcastic insinuation / promotional / rhetorical without stated answer).', 0.2, '2026-05-19 10:08:50');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3416, 10, '2026-05-19', '2026-05-19', 0.0, '["Koalīcija un partijas", "Budžets un finanses"]', '["Jaunajai vienotībai vairs nevarēs būt tik dominējoša loma valdībā un tā vairs nevarēs būt tik aroganta"]', NULL, '19.05 Kulbergs ieskicē jaunās valdības struktūru: JV lomu mazinās, pats nav pret PRO bet ņem NA veto, retoriku piezemē, budžetu pārskatīs jūnijā. 18.05 paziņojums par 4-partiju formātu (AS+NA+ZZS+JV, bez PRO).', 0.8, '2026-05-19 10:08:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3422, 182, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, 'Otto Ozols 2026-05-19 logā: 6 dokumenti, no kuriem 5 ir bare retvīti (NAP komentārs no @Elina_Treija, Kaja Kallas ASV-ES, @realMaalouf, Moldovas Sandu par Krieviju, Krimas tatāru deportācijas 1944). 1 dokuments (37794) ir Ozola paša angļu valodā raksts par Krišjāņa Salmana pretfašisma plakātu Rīgā pret Krievijas vēstniecību — apraksts, bez politiskās nostājas. Nav ekstraktējamu pozīciju.', 0.4, '2026-05-19 10:14:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3423, 189, '2026-05-19', '2026-05-19', 0.0, '["Aizsardzība un drošība"]', '["Es esmu dziļi pārliecināts, ka NBS un civilās aizsardzības institūcijas to ļoti labi zina. Ko ar šo prezidents gribēja teikt?"]', NULL, 'Juris Pūce 2026-05-19 logā: 6 dokumenti — 1 pozīcija (kritika par Valsts prezidenta paziņojumu Preiļos par slimnīcu un uzņemšanas nodaļu apzināšanu), 2 bare RT (Satori, NakotnesForums), 1 valdības formēšanas spekulācija (37737), 1 procedūras precizējums LTV (37740, vairākuma noteikšana — bez politiskās substances), 1 sarkastisks vienrindiņa par Progresīvo nekonsekvenci (37741 — dublē 2026-05-13 pozīciju).', 0.55, '2026-05-19 10:14:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3444, 6, '2026-05-19', '2026-05-19', 0.0, '["Imigrācija"]', '["Patvēruma meklētāji rupji melo mūsu Robežsardzei, lai iegūtu labvēlīgāku attieksmi.", "Stingra imigrācijas politika ir mūsu tautas izdzīvošanas jautājums."]', NULL, 'Divi anti-imigrācijas tvīti 18.05 — apsūdzība par patvēruma meklētāju melošanu Robežsardzei un eksistenciāls ietvars stingrai imigrācijas politikai. Saskanīgi ar pastāvīgo Dombravas pozīciju.', 0.85, '2026-05-19 10:22:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3445, 30, '2026-05-19', '2026-05-19', 0.0, '["Valsts pārvalde", "Valodu politika"]', '["Bez demokrātijas, bez vārda brīvības mēs beigsimies. Mēs, tas ir, Latvija.", "Politiķi, kas par savas valsts politiku savā zemē publiski runā angliski, ir tādi paši pāķi, kā tie, kas to dara krieviski."]', NULL, 'Divi tvīti 18.05 — gara apoloģija demokrātijai, decentralizācijai un vārda brīvībai kā eksistenciāliem priekšnoteikumiem; un asa nostāja pret politiķiem, kas savā zemē publiski runā angliski par Latvijas politiku.', 0.82, '2026-05-19 10:22:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3453, 15, '2026-05-19', '2026-05-19', 0.0, '["Ārpolitika"]', '["I emphasised the fundamental importance of defending the core principles of the UN Charter"]', NULL, 'Braže backfill 2026-05-19: viens reāls claim par tikšanos ar ANO ģen.sek. kandidāti Grinšpanu (ANO Statūtu princips, reforma). Citi 6 docs: 5 bare RTs (TikTok/NIRI/Kanāda/UN/Latvian_MFA) — ne pozīcijas. LETA dokuments par SVR dezinfo dublētu rīta #20537 — empty.', 0.75, '2026-05-19 11:44:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3456, 10, '2026-05-19', '2026-05-19', 0.0, '["Koalīcija un partijas"]', '["valsts finanšu glābšana", "sabiedrības uzticības atjaunošana", "drošību, kas esot pirmajā vietā", "līdz piektdienai mums ir jātiek galā ar šo jautājumu"]', NULL, 'Kulbergs trīspusējās sarunās ar NA un ZZS 18.05 izklāsta jaunās valdības trīs pamatprincipus un piektdienas deadline.', 0.85, '2026-05-19 11:45:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3457, 57, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, 'Lato Lapsa 18.05: trīs tvīti — divi sarkastiski one-liners (skrējēji, Saeimas deputātu ortogrāfija) un viens bare retweet par Progresīvajiem; bez ekstraktējamas paša pozīcijas.', 0.3, '2026-05-19 11:45:21');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3458, 15, '2026-05-19', '2026-05-19', 0.0, '["Ārpolitika"]', '["Latvia and Finland are close and trusted allies. Together, we defend the Eastern Flank of the EU and NATO, and lead support for Ukraine''s self-defence."]', NULL, 'Braže 2026-05-19 uzņem Somijas parlamenta priekšsēdētāju Jussi Halla-aho Rīgā un publiski apstiprina Latvijas–Somijas sabiedroto saikni: kopīgi aizstāvēt ES un NATO Austrumu flangu un vadīt Ukrainas pašaizsardzības atbalstu. Pārējie 11 dokumenti pamatā ir bāri retvīti vai jau saglabātās SVR-dezinformācijas pozīcijas (#20537) atkārtojums LA.lv izdevumā — kvalitatīvi jaunu nostāju nesatur.', 0.8, '2026-05-19 13:09:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3460, 204, '2026-05-19', '2026-05-19', 0.0, '["Aizsardzība un drošība", "Droni"]', '["Esam pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības.", "Nacionālie bruņotie spēki apstiprina, ka Latvijas gaisa telpā ielidoja un no tās izlidoja viens bezpilota lidaparāts."]', NULL, 'NBS pirmā oficiālā reakcija dronu apdraudējuma kontekstā (14.-19.05.2026). 19. maija incidentā (09:04-10:46) NBS aktivizēja NATO patrulēšanas iznīcinātājus un pretgaisa aizsardzību Latgalē; apdraudējums noslēdzās pakāpeniski. NBS apstiprina, ka pastiprināta pretgaisa aizsardzība uz austrumu robežas. 17.05.2026 incidentā NBS publiski atzina, ka viens UAV ielidoja un izlidoja no Latvijas gaisa telpas. Crystal Arrow 2026 mācībās izmantoti gan gaisa, gan sauszemes droni. Status-update tweets (4) un mediju raksti (5) atzīmēti kā empty — nav NBS pirmpersonas pozīcijas vai nav extractable stance.', 0.85, '2026-05-19 13:09:57');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3462, 10, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, 'Pēcpusdienas docs: TV3 sižeta titra misēkļa humoristisks komentārs (nav politiska pozīcija) + LSM atskaite par tikšanos ar Latvijas Bankas prezidentu Kazāku (runātājs ir Kazāks, ne Kulbergs). Nav jaunu pirmās personas pozīciju virs rīta saglabātajām #20538-41, #20578.', 0.6, '2026-05-19 13:10:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3465, 57, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, 'Lato Lapsa first-party žurnālists — 2 tvīti. 38270 ir retorisks jautājums ("Un tieši kādā ziņā pašreizējā valdība ir funkcionētnespējīgāka nekā pirms demisijas?") bez paša formulētas atbildes — Step 3 skip rule: retoriski jautājumi bez stated nostājas nav pozīcija. 38271 ir bare RT no @DzabKepa par laikapstākļiem, bez Lapsa papildu komentāra — Step 3 skip rule: retvīts bez komentāra. Nevienai pozīcijai nav ekstraktējams saturs.', 0.5, '2026-05-19 13:10:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3466, 189, '2026-05-19', '2026-05-19', 0.0, '["Aizsardzība un drošība"]', '["Jūtu līdzi Latgales un nu jau arī Vidzemes iedzīvotājiem - incidenti ar droniem satrauc un rada apdraudējuma sajūtu."]', NULL, 'Pūce 2026-05-19 komentē Latgales/Vidzemes dronu incidentus — norāda, ka tie atklāj aizsardzības un citu resoru praktiskā darba un komunikācijas trūkumus.', 0.75, '2026-05-19 13:10:38');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3470, 26, '2026-05-19', '2026-05-19', 0.0, '["airBaltic"]', '["Baltijas valstu satiksmes ministru sanāksmē rosināju apsvērt plašāku reģionālu pieeju airBaltic attīstībai un finansēšanai", "Solidārs Baltijas valstu atbalsts dotu iespēju saglabāt vienu spēcīgu reģionālu aviokompāniju"]', NULL, 'Baltijas satiksmes ministru sanāksmē Švinka rosina trīspusēju (Latvija/Lietuva/Igaunija) pieeju airBaltic atbalstam un finansēšanai. Argumentē, ka uzņēmums jau faktiski ir Baltijas aviokompānija ar ~80 tiešajiem lidojumiem un ka Tuvo Austrumu krīze izgaismoja aviosavienojamības nozīmi. Ministri pauduši gatavību turpināt diskusiju pēc aktualizētā biznesa plāna.', 0.9, '2026-05-19 13:11:03');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3485, 15, '2026-05-19', '2026-05-19', 0.0, '["Ārpolitika"]', '["Canada is Latvia’s trusted #NATO ally and friend. We are deepening our defence and economic partnership, and ensuring steadfast support for Ukraine."]', NULL, 'Vakara klasteris: Kanādas ārlietu ministres Anitas Anandes vizīte Rīgā — Latvijas un Kanādas aizsardzības un ekonomiskās partnerības padziļināšana, kopēja Ukrainas atbalsta saglabāšana NATO ietvarā.', 0.85, '2026-05-19 17:49:51');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3486, 204, '2026-05-19', '2026-05-19', 0.0, '["Ukraina un Krievija", "Droni", "Aizsardzība un drošība"]', '[]', NULL, '19.05.2026 vakara ingestā 12 dokumenti par 19.05 dronu/gaisa telpas incidentu Latvijā un Igaunijā. Trešās puses ziņu rakstos (NRA, LSM, LA, TVNet) atstāstīta NBS preses konference — nav pirmpersonas pozīciju ekstrakcijai (jau pārklāti claim #20581-83 no rīta). Divi @Latvijas_armija tvīti (#38541 trauksme, #38542 noslēgums) ir operacionāli statusi un atkārto #20581 stiprinājumu. Viens jauns doktrināls paziņojums (#38543) par Latvijas gaisa telpas politiku Ukrainas triecieniem pret Krieviju — saglabāts.', 0.9, '2026-05-19 17:50:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3487, 57, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-19: 12 dokumenti — pārsvarā retvīti bez komentāra (8) un sarkastiski vienrindes bez konkrētas politikas pozīcijas (4). Trūkst pirmpersonas ekstraktējamas nostājas: rakstiet vai retorisks jautājums ("Kas par steigu?"), zobgalīga piezīme par dronu sēriju ("Tagad tie droni beidzot vellu redzēs! Nožēlojamie āksti"), apvainojuma izteikums ārlietu ministrei ("stulbene ārlietu ministra amatā izplata kremļa paziņojumus") bez konkrētas politikas alternatīvas, vispārīga sūdzība par politiķiem, kas izplata nepārbaudītas ziņas. Per Step 3: sarkasms bez konkrētas politikas stājas + retorisks jautājums bez atbildes = nav pozīcija.', 0.7, '2026-05-19 17:50:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3488, 26, '2026-05-19', '2026-05-19', 0.0, '["Transports", "Koalīcija un partijas"]', '["Tikmēr Latvijā koalīcijas partneri @Progresivie ierosinājumu par 50% atlaidēm vilcienu abonementiem neatbalstīja.", "Baltijas valstīm ir nepieciešama vienota pieeja, jo, piemēram, Valka un Valga nevar eksistēt divās dažādās laika zonās."]', NULL, 'Švinka 19. maijā uzsver Lietuvas 56% pasažieru pieaugumu pēc 50% vilcienu atlaidēm un kritizē koalīcijas partneri Progresīvos, kas Latvijas analoģisko priekšlikumu neatbalstīja. Baltijas ministru sanāksmē rosina vienotu pāreju uz pastāvīgu vasaras laiku un paraksta memorandu par autonomiem transportlīdzekļiem.', 0.85, '2026-05-19 17:51:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3490, 10, '2026-05-19', '2026-05-19', 0.0, '["Koalīcija un partijas", "Budžets un finanses", "Korupcija un KNAB"]', '["sarunās iesaistītas četras partijas un tuvākajā laikā tām jāvienojas par galvenajiem valdības darba principiem, tostarp stabilitāti, drošību, finanšu pārvaldību un cīņu ar karteļiem", "līdz trešdienas rītam jābūt sagatavotai kopīgā rīcības dokumenta versijai", "jaunās valdības darba centrā būs tuvāko 100 dienu laikā paveicamie uzdevumi", "nepieciešamību ievērot fiskālo disciplīnu un izvairīties no finansiāli nepamatotām iniciatīvām"]', NULL, '19.05 vakarā pēc tikšanās ar JV pārstāvjiem Kulbergs (AS) pauda LETA, ka topošās koalīcijas (4 partneri) sarunās būtisku domstarpību nav un līdz trešdienas (20.05) rītam jābūt sagatavotam kopīgam rīcības dokumentam; vērtējumu par koalīcijas izveidi gaida dienas gaitā. Centrālās prioritātes: stabilitāte, drošība, finanšu pārvaldība, cīņa ar karteļiem; 100 dienu darbi ar fokusu uz finanšu stabilizāciju un drošības stiprināšanu; fiskālā disciplīna. Amatu sadale vēl nav sākta — tas ir nākamais solis pēc pamatprincipu vienošanās.', 0.85, '2026-05-19 17:51:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3503, 72, '2026-05-19', '2026-05-19', 0.0, '["Imigrācija"]', '["Darba tirgus problēmas nav iespējams atrisināt ar vienkāršu atbildi – vairāk darbaspēka no ārvalstīm."]', NULL, '2026-05-19: Indriksone (NA) atkārto pozīciju pret vienkāršu ārvalstu darbaspēka risinājumu darba tirgus problēmām — uzsver, ka ilgtermiņā jārisina gudri ar maksimālu ieguvumu Latvijai. Konsekventi ar #18181 (2026-01-28).', 0.85, '2026-05-19 17:51:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3507, 189, '2026-05-19', '2026-05-19', 0.0, '[]', '[]', NULL, '19. maijā Pūce publicē tikai retorisku jautājumu par koalīcijas sarunu pirmo punktu un divus bare RT no @attistibai partijas konta (Pabriks par valdības obligātajiem uzdevumiem; partijas paziņojums par koalīcijas neatbildētiem jautājumiem). Bez paša komentāra nav ekstraktējamu pozīciju.', 0.7, '2026-05-19 17:52:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3513, 57, '2026-05-20', '2026-05-20', 0.0, '[]', '[]', NULL, '2026-05-20 X plūsma: 13 retvīti bez komentāra + 5 pirmpersonas sarkastiski viensliekņi/retoriski jautājumi (par Vaidakovu, Latvijas armiju, Sprūdu, Braži, nodokļu maksātājiem) bez konkrētas policy nostājas. Nav ekstraktējamu pozīciju — Step 3 skip-list pārklāj visu plūsmu.', 0.5, '2026-05-20 17:34:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3514, 204, '2026-05-20', '2026-05-20', 0.0, '["Aizsardzība un drošība", "Droni"]', '["Esam pastiprinājuši pretgaisa aizsardzības spējas uz austrumu robežas, nosūtot papildu vienības."]', NULL, 'NBS 20.05.2026 otro dienu pēc kārtas izsludināja gaisa telpas apdraudējumu Latgalē (Ludza, Krāslava, Rēzekne), apstiprinot pretgaisa pastiprināšanu un NATO koordināciju. Paralēli norisinājās mācības "Zibens 2026" Rīgā par urbāno sakaru spējām.', 0.85, '2026-05-20 17:34:20');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3517, 15, '2026-05-20', '2026-05-20', 0.0, '["Aizsardzība un drošība"]', '["Kanāda investēs 64 miljonus eiro militārās infrastruktūras attīstībā Latvijā."]', NULL, 'Bražes 20.05 satura plūsma — galvenokārt amplificēšana (bare RT) ap diviem tematiem: (1) Krievijas SVR dezinformācijas noliegšana un (2) NATO/sabiedroto solidaritāte ar Baltiju. Jauna pirmpersonu pozīcija: Kanādas paziņojums par 64M eiro militārās infrastruktūras investīciju Latvijā — turpinājums 19.05 Anandes vizītei. SVR temats jau pilnībā nosegts ar #20537 (19.05).', 0.85, '2026-05-20 17:35:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3519, 10, '2026-05-20', '2026-05-20', 0.0, '["Koalīcija un partijas", "Budžets un finanses"]', '["Es uzskatu, ka ilgtermiņā svarīgākā prioritāte ir ekonomiskā drošība", "sabiedrība nesaprastu citādu rīcību"]', NULL, 'Kulberga 20.05 aktivitāte koncentrējās uz koalīcijas vienošanās parakstīšanu (AS+JV+NA+ZZS, katram 4 amati) un personīgo akcentu uz ekonomisko drošību kā ilgtermiņa prioritāti. JV pieņēma lēmumu piedalīties, vienošanās parakstīta vakarā. Lielākā daļa 18-19.05 pozīciju jau ekstraktētas (id ~20525-20601).', 0.85, '2026-05-20 17:36:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3528, 26, '2026-05-20', '2026-05-20', 0.0, '["Transports", "ES politika"]', '["Regionu mobilitatei tiks pieskirti vairak neka 113 milj. eiro"]', NULL, 'Pazino par regionalas mobilitates investiciju paketi 113+ milj. eiro apjoma (75% ES Sociala klimata fonds, 25% LV).', 0.9, '2026-05-20 17:49:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3554, 30, '2026-05-20', '2026-05-20', 0.0, '[]', '[]', NULL, 'Vienīgais dokuments — saites publikācija uz trīs gadus vecu interviju par mākslīgo intelektu, bez paša komentāra vai pozīcijas. Nav ekstraktējamas politiskās pozīcijas.', 0.2, '2026-05-20 17:54:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3559, 182, '2026-05-20', '2026-05-20', 0.0, '["Ārpolitika"]', '["Te jāpiebilst, ka ideju par HAMAS ''valsti'' jeb \"brīvu Palestīnu\" sludina arī vairāki partijas \"Progresīvie\" biedri."]', NULL, 'Ozols, atsaucoties uz Salmana Rušdi interviju Bild, apgalvo, ka ''brīvas Palestīnas''/HAMAS valsts ideju Latvijā sludina vairāki Progresīvo biedri, un norāda, ka šādās valstīs Progresīvo pašu sludinātās idejas tiktu apspiestas, bet to pamatā ir reāli spīdzināti, izvaroti un pazemoti cilvēki.', 0.75, '2026-05-20 17:54:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3572, 6, '2026-05-20', '2026-05-20', 0.0, '["Imigrācija"]', '["Latvijai ir jāievieš ļoti stingra imigrācijas politika!", "Imigrācijas parlamentārās izmeklēšanas komisija ir atbalstījusi komisijas gala ziņojumu, kas ļaus izveidot ļoti stingru un kontrolētu imigrācijas politiku"]', NULL, 'Dombrava 20.05 paziņo, ka Imigrācijas parlamentārās izmeklēšanas komisija ir akceptējusi gala ziņojumu ar 100+ rekomendācijām (kvotas trešo valstu pilsoņiem, augstskolu atbildība par studentu imigrācijas shēmu, Bolt/Wolt platformu kontrole).', 0.85, '2026-05-20 17:56:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3575, 204, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'NBS relay pass — institucionāli paziņojumi un trešo pušu raksti, mention matcher routes uz konkrētiem subjektiem.', 0.5, '2026-05-21 11:58:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3576, 57, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'Lapsas 2026-05-21 dienas tvīti — 10 no 12 ir bare retvīti bez paša komentāra (Egriks, mazputns, ubinators, Liepnieks, Heinrih5 ×2, kr_klavins, Kurare123, karlwithanl), 1 sarkastisks apvainojums Progresīvajiem bez konkrētas politikas nostājas, 1 retorisks jautājums par sabiedrisko mediju selektivitāti VK atzinuma kontekstā (bez tiešas atbildes formulējuma). Nevienā nav ekstraktējama pirmpersonas pozīcija. 5 papildu dokumenti atstāti nākamajai sesijai 12-doc limita dēļ.', 0.6, '2026-05-21 11:59:30');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3590, 10, '2026-05-21', '2026-05-21', 0.0, '["Koalīcija un partijas"]', '["partneri vienojušies turpināt sarunas, mērķējot līdz 25. maijam panākt pilnu vienošanos par koalīciju, ministriju sadali un politikas prioritātēm"]', NULL, 'Kulbergs kā Ministru prezidenta amata kandidāts pēc 20.05 pamatvienošanās parakstīšanas paziņo, ka koalīcijas sarunu mērķis ir līdz 25.05 panākt pilnu vienošanos par koalīciju, ministriju sadali un politikas prioritātēm. Saeimas priekšsēdētāja Mieriņa (ZZS) intervijā LTV apliecina, ka Saeima par jauno Ministru kabinetu varētu balsot jau nākamajā ceturtdienā.', 0.8, '2026-05-21 12:03:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3594, 15, '2026-05-21', '2026-05-21', 0.0, '["Aizsardzība un drošība", "Droni", "Ārpolitika", "Ukraina un Krievija"]', '["The humiliating and degrading treatment of detainees, as seen in the footage from Ashdod, is unacceptable.", "Latvia''s National Security Council met to consult on the drone incidents in our airspace.", "Our focus is on reinforcing NATO''s Eastern Flank, preparations for the Ankara Summit, and providing critical support for Ukraine."]', NULL, 'Braže 21.05 publicē trīs pozīcijas: (1) nosoda izturēšanos pret Ašdodā aizturētajiem flotiles aktīvistiem un pieprasa to atbrīvošanu; (2) ziņo, ka NDP brīdināja par iespējamu dronu incidentu atkārtošanos Latvijas gaisa telpā Krievijas agresijas dēļ; (3) iezīmē Latvijas prioritātes NATO ārlietu ministru sanāksmei Helsingborgā — Austrumu flangs, Ankaras samita gatavošanās, atbalsts Ukrainai. 17 dokumenti bez ekstraktējamas pozīcijas (retvīti bez komentāra, ceremoniālas zīmes).', 0.7, '2026-05-21 12:04:22');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3599, 189, '2026-05-21', '2026-05-21', 0.0, '["Budžets un finanses"]', '["jaunā koalīcija nekādus taupības pasākumus neplāno. Tā vietā sola palielināt izdevumus"]', NULL, 'Pūce 21.05 norāda, ka parakstītajā jaunās koalīcijas vienošanās dokumentā taupības pasākumi nav paredzēti — tā vietā plānots palielināt izdevumus.', 0.8, '2026-05-21 12:04:48');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3603, 26, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'Vizītes pārskats Mērsraga ostā bez ekstraktējamas politiskās pozīcijas — apraksta ostas pārvaldnieka investīcijas un zivju pārstrādes rūpnīcas plānus, kas nav paša runātāja politikas lēmums.', 0.3, '2026-05-21 12:05:16');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3618, 30, '2026-05-21', '2026-05-21', 0.0, '["Sabiedriskie mediji"]', '["Sabiedriskā medija klausītājiem tiktu aiztaupīts laiks un nervi, ja intervētāji raidījuma sākumā dotu katram politiķim vārdu pateikt galveno vēstījumu."]', NULL, 'Baško 20.05 tvītu pavedienā kritizē sabiedriskā radio (Krustpunkti) intervēšanas stilu — politiķi runā tukši, jo intervētāji uzdod tabloīdu jautājumus. Piedāvā konkrētu formāta maiņu: katram politiķim dot 10 min pateikt galveno vēstījumu raidījuma sākumā, tad jautājumi sekot.', 0.7, '2026-05-21 12:07:10');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3624, 57, '2026-05-21', '2026-05-21', 0.0, '["Tieslietas"]', '["Jaunais ģenerālprokurors Meisters sadomājies, ka dzīvo 1937.gadā un ka visādiem lumpeņiem domātais tiesiskums uz viņu neattiecas."]', NULL, 'Lato Lapsas X publikāciju sweep 2026-05-21: viens substantiāls personīgs uzbrukums ģenerālprokuroram Juris Stukāns Meisteram, pārējie ir bare RT vai sarkastiska vēsturiska insinuācija bez konkrētas politiskas pozīcijas.', 0.7, '2026-05-21 12:11:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3628, 57, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-21: 12 dokumenti caurskatīti; ekstraktējamu pirmā lokā pozīciju nav. 8 no 12 ir bare retvīti bez paša komentāra (Heinrih5, E_Stendzenieks, andrislov, MasterYodaMB, DzenisTomass, Krisjanis_K, DzSimpson, maris_spruds). 2 ir kultūras/grāmatas konkursa promocija (strēlnieku grāmata). 2 ir sarkastiski viensētu izteikumi bez konkrētas politikas nostājas (Meļķa vārdspēle, Meistera PSR-ģenerālprokurora ironija — pēdējais saturiski pārklājas ar jau esošu pretrunu #20712, bet bez jaunas politiskas substances).', 0.7, '2026-05-21 16:38:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3629, 15, '2026-05-21', '2026-05-21', 0.0, '["Ukraina un Krievija"]', '["Starting #NATO ministerial in Helsingborg, Sweden, by meeting Ukraine''s Foreign Minister @andrii_sybiha to discuss ramping up support for Ukraine self defence against Russia''s aggression."]', NULL, '21.05. Helsingborgā NATO ārlietu ministru sanāksmes kontekstā Braže pirmā tikšanās bija ar Ukrainas ĀM Andriju Sibihu, lai apspriestu Ukrainas pašaizsardzības atbalsta pastiprināšanu pret Krievijas agresiju, kā arī nesenos dronu incidentus Baltijas gaisa telpā. Pārējie 8 ingestētie ieraksti — bare retweets (Rutte, sabiedroto ĀM, eksperti) bez Bražes papildkomentāra.', 0.75, '2026-05-21 16:39:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3639, 204, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'NBS ir ''organization + relay'' slot — preses ziņojumi par dronu incidentu un gaisa telpas apdraudējumu. Pirmpersonā pozīciju nav; institucionālā informācija reaģējoša, ne politikas pozīcija. Per Step 3c — default empty_doc_ids; tracked politiķi tiks linkoti caur text-scan.', 0.3, '2026-05-21 16:41:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3642, 26, '2026-05-21', '2026-05-21', 0.0, '["Transports"]', '["Šis ir viens no vērienīgākajiem Latvijas dzelzceļa īstenotajiem infrastruktūras modernizācijas projektiem"]', NULL, 'Švinka publiski atbalsta Jūrmalas dzelzceļa posma elektrifikācijas/modernizācijas pabeigšanu (Rīga–Tukums maršruts atjaunots pilnā apmērā). Tikšanās ar Vivi un VAS LDz Slokas stacijā. Pozicionē projektu kā vienu no vērienīgākajiem Latvijas dzelzceļa modernizācijas darbiem (>100 km elektrificēta tīkla).', 0.8, '2026-05-21 16:41:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3643, 30, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'Tikai retvīts no @JurgisLiepnieks par ģenerālprokurora izteikumiem — Baško paša komentārs vai pozīcija nav pievienota. Saskaņā ar bare-retweet skip noteikumu — nav ekstraktējamas pozīcijas.', 0.3, '2026-05-21 16:41:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3649, 10, '2026-05-21', '2026-05-21', 0.0, '[]', '[]', NULL, 'Visi 3 dokumenti (jauns.lv, LETA, pmo.ee mirror) atspoguļo to pašu 21.05 koalīcijas sarunu pauzes ziņu. Vienīgais tiešais Kulberga citāts par ''visi četri partneri vienojušies turpināt sarunas'' jau ekstrahēts šodien (claim ''Kā topošās valdības veidotājs paziņo...''). Substantīvais saturs ir 20.05 parakstītā vienošanās dokumenta žurnālistu pārstāsts, nevis Kulberga šodienas pirmpersonas pozīcija — arī šis jau ekstrahēts 20.05.', 0.75, '2026-05-21 16:41:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3656, 204, '2026-05-22', '2026-05-22', 0.0, '["Aizsardzība un drošība"]', '[]', NULL, 'NBS organizācijas slots: 8 dokumenti — visi trešo pušu mediju ziņojumi par NBS operacionālajām darbībām (jaunā divlīmeņu šūnu apraides brīdinājumu sistēma no 23.05., ceturtdienas drona nepiefiksēšana izlidošanā). Nav pirmpersonas stratēģiskas politiskas pozīcijas — informatīvi/procedurāli paziņojumi, kas nav ekstraktējami kā pozīcijas. Konsekventi ar Step 3c operating rule organizāciju slotam.', 0.9, '2026-05-22 15:14:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3657, 15, '2026-05-22', '2026-05-22', 0.0, '["Aizsardzība un drošība", "Ukraina un Krievija"]', '["At today''s @NATO Foreign Ministers meeting, I thanked our allies for the support. Together, we are strengthening counter-drone capabilities and defence of the Eastern Flank."]', NULL, 'Pēc Helsingborgas NATO ārlietu ministru sanāksmes Braže apstiprina, ka sabiedrotie kopīgi stiprina pretdronu spējas un NATO Austrumu flanga aizsardzību, un pateicas par atbalstu pret Krievijas dezinformāciju. 11 pārējie 22.05. tvīti ir tieši retvīti bez paša komentāra (NATO, ASV, ES, Latvian_MFA balsis), kas turpina iepriekšējās dienas (21.05.) komunikācijas līniju.', 0.8, '2026-05-22 15:14:45');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3660, 57, '2026-05-22', '2026-05-22', 0.0, '["Korupcija un KNAB"]', '["Par ko metīsies taisnoties progresīvais Mārtiņš Staķis @MStakis - par spīdīgo grabuli uz rokas vai par iesaisti ''kafijas kartelī''?"]', NULL, 'Lato Lapsa 2026-05-22 fokusējas uz Progresīvo deputāta Mārtiņa Staķa kritiku — sasaista dārga pulksteņa (Rolex) valkāšanu ar apgalvotu iesaisti ''kafijas kartelī''. Sarkastisks aicinājums nebalsot par PRO.', 0.75, '2026-05-22 15:15:45');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3671, 10, '2026-05-22', '2026-05-22', 0.0, '["Tieslietas", "Mežsaimniecība"]', '["Ģenerālprokuratūra ir neatkarīga institūcija. Tieši tāpēc es neiesaistīšos publiskās diskusijās ar ģenerālprokuroru Armīnu Meisteru.", "Koku, kā Latvijas un LVM resurssa, pieejamība ir obligāti jāsakārto tā, lai tas ir pieejams visiem komersantiem uz godīgiem, atvērtiem, saprotamiem nosacījumiem."]', NULL, 'Topošais MP kandidāts Kulbergs 22.05 tvītā formulē divas pozīcijas: (1) atsakās publiski iesaistīties diskusijās ar ģenerālprokuroru Armīnu Meisteru — uzsver Ģenerālprokuratūras neatkarību un tiesas galavārdu; (2) LVM koksnes resurss obligāti jādara pieejams visiem komersantiem uz godīgiem un atvērtiem nosacījumiem, lai attīstītu augstas pievienotās vērtības pārstrādi. Pārējie 3 dokumenti (LSM 21.05 par atbildības jomu sadali, Šlesera intervija, Voļska op-ed) ir par Kulbergu, nevis viņa pašreizēja nostāja.', 0.9, '2026-05-22 15:25:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3676, 26, '2026-05-22', '2026-05-22', 0.0, '["Korupcija un KNAB", "Transports"]', '["vai publiskā valsts un pašvaldības nauda ir plānota kāda privātā uzņēmēja interesēs?"]', NULL, 'Švinka publiski izaicina ekonomikas ministru Valaini par Rīgas brīvostas teritoriju un to saistību ar Šlesera bijušajiem lēmumiem; vienlaikus atbalsta ostas infrastruktūras modernizāciju kruīza kuģu uzņemšanai.', 0.85, '2026-05-22 15:29:47');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3682, 30, '2026-05-22', '2026-05-22', 0.0, '[]', '[]', NULL, 'Vienīgais 24h dokuments ir tukšs retvīts @partijaMMN reitinga paziņojumam bez paša Baško komentāra — nav ekstraktējamas pozīcijas.', 0.2, '2026-05-22 15:30:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3701, 182, '2026-05-22', '2026-05-22', 0.0, '[]', '[]', NULL, 'Bare retweet (RT @InsiderEng) par Austrijas spiegošanas lietu angļu valodā, bez Ozola paša komentāra. Atbilst skip-list ''Retweets without commentary''.', 0.2, '2026-05-22 15:32:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3704, 15, '2026-05-22', '2026-05-22', 0.0, '["Aizsardzība un drošība", "Ārpolitika", "Ukraina un Krievija"]', '["Vienota, spēcīga NATO ir labākā atbilde Krievijas un citiem draudiem"]', NULL, 'Baiba Braže (JV) 2026-05-22 piedalījās NATO ārlietu ministru sanāksmē Helsingborgā un publiski uzsvēra, ka vienota, spēcīga NATO ir labākā atbilde Krievijas un citiem draudiem. Lielāko daļu dienas tvītu plūsmas veido bezkomentāru retvīti (NATO, sabiedroto un Latvian_MFA paziņojumi) — tie neiekļaujas pozīciju ekstrakcijā. Saturiski pozīcija sakrīt ar iepriekšējo dienu nostājām par Austrumu flanga stiprināšanu un atbalstu Ukrainai, kas jau ir reģistrētas (claim 20690, 20725).', 0.85, '2026-05-22 18:16:31');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3705, 57, '2026-05-22', '2026-05-22', 0.0, '[]', '[]', NULL, '6 jauni dokumenti (2026-05-22 pēcpusdienas pulse): visi seši ir tīri retvīti (RT @...) bez Lapsas pievienota teksta. Nav pirmpersonas pozīcijas, ko ekstraktēt. Doc #40465 ir RT par Staķa Rolex pulksteni (sasaucas ar šodien agrāk apstrādāto #20727 anti-PRO un #20726 Staķis kafijas kartelis kontekstu), bet Lapsa pats nepievieno komentāru — tikai pārpublicē trešās puses repliku. Pārējie 5 RT: JV ordeņu kritika (#40466), nezināms (#40467), algoritma piezīme par mājdzīvniekiem (#40468), ironija par Maskavu (#40469), retorisks jautājums VDD (#40470). Skip-list: "Retweets without commentary (bare RT of another account, no added text)".', 0.85, '2026-05-22 18:16:51');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3709, 26, '2026-05-22', '2026-05-22', 0.0, '["Transports", "Digitālā politika"]', '["Latvijai ir jābūt atvērtai jauno tehnoloģiju izmantošanai, un vēl labāk ir iesaistīties inovāciju izstrādē."]', NULL, 'Švinka komentē Lietuvas atļauju Tesla Full Self-Driving (Supervised) sistēmai un formulē divus principus Latvijai: (1) uz publiskajiem ceļiem jālieto pārbaudītas, ekspertu atzītas tehnoloģijas konkrētā vidē; (2) Latvijai jābūt atvērtai jauno tehnoloģiju izmantošanai un iesaistei inovāciju izstrādē. Min, ka jau šobrīd Latvijā darbojas testa vide autonomo sistēmu attīstīšanai.', 0.8, '2026-05-22 18:17:11');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3712, 182, '2026-05-22', '2026-05-22', 0.0, '[]', '[]', NULL, 'Abi tvīti ir bare retvīti svešvalodās (katalāņu, vācu) bez paša komentāra; saturs ārpus LV politikas konteksta.', 0.9, '2026-05-22 18:18:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3713, 30, '2026-05-22', '2026-05-22', 0.0, '[]', '[]', NULL, 'Vakar kāds prasīja: ''Ko jūs darīsiet ar 5%?'' atbilde — ''Dubultosim. Un pēc tam vēlreiz dubultosim.'' Sarkastiska/brašs vienlīnijnieks bez konkrētas policy substances; bez konteksta nav skaidri, vai runa par partijas reitingu, vēlēšanu rezultātu vai konkrētu likuma slieksni. Nav ekstraktējamas pozīcijas.', 0.3, '2026-05-22 18:19:38');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3720, 15, '2026-05-23', '2026-05-23', 0.0, '[]', '[]', NULL, '9 dokumenti caurskatīti — visi ceremoniāli vai bez personīgas pozīcijas (5 bare RT bez komentāra, 1 hokeja sveiciens, 1 fragments bez konteksta, 1 ceremoniāla pateicība Zviedrijai pēc NATO Helsingborgas sanāksmes — substantīvās pozīcijas no tās sanāksmes jau noformētas claims #20690, #20725, #20762).', 0.7, '2026-05-23 16:23:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3725, 57, '2026-05-23', '2026-05-23', 0.0, '[]', '[]', NULL, 'Lato Lapsa 18 dokumenti pēdējās 3 dienās — 16 retvīti bez komentāra, 2 sarkastiski one-liners ("šķiņķpaurīgie progresīvie rokpakaļi", "progresīvo sērgai ierādīta atbilstoša vieta") bez konkrētas politikas pozīcijas. Nav ekstraktējamu first-party pozīciju. Saskaņā ar Step 3 (skip retweets without commentary + sarcastic one-liners).', 0.5, '2026-05-23 16:25:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3734, 30, '2026-05-23', '2026-05-23', 0.0, '[]', '[]', NULL, 'Bare retweet par Rietumu civilizāciju (angļu valodā) bez komentāra. Nav paša pozīcija.', 0.2, '2026-05-23 16:27:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3740, 189, '2026-05-23', '2026-05-23', 0.0, '["Koalīcija un partijas", "Aizsardzība un drošība"]', '["Tagad der Siliņa. Visi vārdi viņu paziņojumos ir tikai frāzes. Liekulības gadatirgus.", "Cienījams profesionālis tika izmests politiskā laukā, lai nedaudz ar viņu paķircinātos un izmantotu īstermiņa vajadzībām. Tā stipru Latviju neuzbūvēt."]', NULL, 'Pūce kritizē Vienotības principu maiņu aizs.min. atlasē — pirms 2 nedēļām prasīja profesionāli (Melni), tagad pieņem Siliņu. Sauc to par liekulību.', 0.85, '2026-05-23 16:28:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3741, 204, '2026-05-23', '2026-05-23', 0.0, '[]', '[]', NULL, 'NBS (organization slot): 5 dokumenti, visi tukši. 40930 ir NBS pašu tvīts ar procedurālu sensoru fakta paziņojumu (nav politiska nostāja). 40744/40742/40739/40719 ir LA.lv/NRA/PMO raksti par dronu incidentu Dridža ezerā, kur NBS ir minēts kā informācijas avots vai trešās puses subjekts (Glena Granta intervija, Valsts policijas paziņojumi) — nav NBS autorēti, matcher pielinkojis tos NBS slotā vārda pieminējuma dēļ. Reālie runātāji nav tracked vai jau tiek apstrādāti citu slotu pasēs.', 0.9, '2026-05-23 16:29:04');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3742, 26, '2026-05-23', '2026-05-23', 0.0, '["Aizsardzība un drošība"]', '["Sabiedriskā transporta pasažieri netiks atstāti uz ceļa! Jauni reisi netiks uzsākti, un ne vilciens, ne autobusi apdrautētajās teritorijās neiebrauks."]', NULL, 'Švinka paskaidro divu līmeņu (dzeltens/oranžs) šūnapraides protokolu sabiedriskajam transportam gaisa telpas apdraudējuma gadījumā.', 0.85, '2026-05-23 16:29:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3759, 15, '2026-05-23', '2026-05-23', 0.0, '[]', '[]', NULL, 'Vēstnesis-only sweep — formāli juridiski dokumenti (MK noteikumi, rīkojumi, izsludināti likumi, Saeimas paziņojumi). Politiķa vārds parādās kā institucionāla amatpersona, nevis personiska politiska pozīcija.', 0.2, '2026-05-23 16:36:01');
