INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3798, 57, '2026-05-24', '2026-05-24', 0.0, '["Pensijas"]', '["Šitie abi nolēmuši atņemt Sprūdam visstulbākā meļa titulu? Viens melo par karteli un pulksteni, otrs mantojumu uzdod par pensiju…"]', NULL, 'Lato Lapsa 24.05 X-aktivitāte: 1 oriģināls tvīts (sarkastisks uzbrukums Šuvajevam par mantojuma nosaukšanu par pensiju) + 11 retvīti bez komentāra (galvenokārt par to pašu debati — citu lietotāju kritika Šuvajevam un Stakim). Ekstraktēta 1 pozīcija no #41296.', 0.6, '2026-05-24 13:05:15');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3799, 189, '2026-05-24', '2026-05-24', 0.0, '[]', '[]', NULL, 'Pūces vienīgais pieejamais 24h dokuments (ID 41274) ir bare retvīts no @Liepkalns par Lietuvas cigarešu kontrabandas aizturēšanām (27 personas, t.sk. 13 policijas/muitas darbinieki) bez paša komentāra. Saskaņā ar claim-extractor skip-listu (bare RT bez komentāra) nav ekstraktējamas pozīcijas. 23.05. "Liekulības gadatirgus" tvīts (doc 40828) jau analizēts iepriekšējā sesijā (claim #20778, reviewed_at=2026-05-23 19:28:59).', 0.9, '2026-05-24 13:05:34');
