INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3814, 15, '2026-05-24', '2026-05-24', 0.0, '["Ukraina un Krievija"]', '["Latvia with Ukraine and other partners will call an emergency meeting of the UN Security Council."]', NULL, 'Braže paziņo, ka Latvija kopā ar Ukrainu un citiem partneriem sasauks ANO Drošības padomes ārkārtas sēdi.', 0.85, '2026-05-24 17:12:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3824, 15, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, 'Tukša pārskata sesija — 4 bare retweets bez komentāra (RT @AnitaAnandMP par Kanādas karavīriem Latvijā, RT @Znotina par Latvijas vasarlaika ranžējumu, RT @MFA_Ukraine par Krievijas karogu sportā, RT @donis777 par airBaltic). Nav ekstraktējamas pirmpersonas pozīcijas.', 0.9, '2026-05-24 21:07:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3825, 57, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, 'Wave 4: 12 docs reviewed, 0 extractable. 10 bare RTs without commentary, 2 first-party sarkastiski one-liners (Doc 6 Kozlovskis ministra kritika, Doc 12 Šuvajeva mantojuma meta-komentārs) bez konkrētas policy pozīcijas.', 0.7, '2026-05-24 21:07:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3835, 10, '2026-05-24', '2026-05-24', 0.0, '["Koalīcija un partijas"]', '["Es esmu mērķtiecīgs cilvēks un es paredzu, ka partneri nepievils, tāpēc, ka līdz šim tas ir konstruktīvs dialogs... es uzskatu, ka izpildīšu visus trīs prezidenta Darba uzdevumus. Liekot viņam galdā… Varbūt vēl nebūs garantēti ar pildspalvu viss tā kā viņš arī lūdza... Es domāju par uzvārdiem un vārdiem, bet nozares un darāmie darbi būs salikti."]', NULL, '', 0.85, '2026-05-24 21:10:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3836, 26, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, '', 0.0, '2026-05-24 21:10:41');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3840, 15, '2026-05-25', '2026-05-25', 0.0, '["Aizsardzība un drošība"]', '["#NATO works. Our committment to the Alliance is rooted in our shared values, the will to defend them, and investment in capabilities."]', NULL, 'Brāze 25.05 publicē vienu pirmpersonas NATO-saturīgu tvītu (NATO Field School uzņemšana ar Latvijas apņemšanās formulējumu); pārējie 6 dokumenti ir bare RT (Arlietas/Latvian_MFA ceremonialie, Sybiha vēstnieku vizīte Kijivā, jarinovska mention-only) bez ekstraktējamas pozīcijas.', 0.75, '2026-05-25 14:00:55');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3844, 72, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, '', 0.0, '2026-05-25 14:01:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3848, 10, '2026-05-25', '2026-05-25', 0.0, '["Koalīcija un partijas", "Valsts pārvalde", "Rail Baltica", "Aizsardzība un drošība"]', '["Plānots, ka \"Apvienotā saraksta\" (AS) politiķi Kulberga vadītajā valdībā vadīs Finanšu, Tieslietu un Viedās administrācijas un reģionālās attīstības ministrijas.", "Uzskatu, ka bija nekoleģiāla rīcība vienā no mirkļiem.", "lielie projekti kā \"airBaltic\" un \"Rail Baltica\" ir premjera līmeņa un visas valdības jautājumi, nevis vienas ministrijas ziņā kā tas bijis līdz šim.", "tajā jābūt elementārām, praktiski izdarāmām lietām, kuras var paveikt līdz vēlēšanām.", "Kulbergs atkārtoti kā jaunās valdības prioritātes nosauca drošību un gaidāmo vēlēšanu norisi.", "portfeļi tika dalīti atbilstoši \"partiju DNS\" un interesēm", "neviens cits neesot bijis vairāk klātesošs gan no finanšu viedokļa, gan lēmumu pieņemšanā kā JV"]', NULL, 'Kulbergs 25.05.2026 paziņo topošās valdības ministriju sadalījumu un satiekas ar prezidentu Rinkēviču. Galvenās nostājas: ministrijas dalītas pēc ''partiju DNS'' un interesēm priekšvēlēšanu kontekstā; AS vadīs Finanšu/Tieslietu/VARAM; NA iegūst lielāko ietekmi; JV samazināts portfelis ar Aizsardzību un Satiksmi kā ''apgrūtinājumiem''. Norāda uz nekoleģiālu rīcību sarunās. Lielie projekti (Rail Baltica, airBaltic) jāuzņem premjera līmenī. Valdības deklarācija — īsa, praktiska, līdz vēlēšanām. Prioritātes — drošība un vēlēšanu norise.', 0.85, '2026-05-25 14:02:14');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3850, 6, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, 'Visi 3 dokumenti šodien — wire-copy par NA valdes lēmumu virzīt Dombravu Iekšlietu ministra amatam Kulberga vadītajā valdībā. Indriksone tiek citēta par KEM, Dombrava pats nav citēts nevienā no rakstiem (jauns.lv, nra.lv, leta.lv). Indirect-reference — kandidatūras paziņojums ≠ paša pozīcija.', 0.2, '2026-05-25 14:02:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3851, 204, '2026-05-25', '2026-05-25', 0.0, '["Aizsardzība un drošība", "Droni"]', '["Nopietnāki ieguldījumi Latvijas pretgaisa aizsardzībā ir sākti vien pēdējo gadu laikā", "Pretgaisa aizsardzības vienības Latvijā vairāk izvietotas ar domu par lielāko pilsētu sargāšanu"]', NULL, 'NBS komandieris Kaspars Pudāns Latvijas Radio intervijās 25.05. atzīst, ka nopietnāki ieguldījumi pretgaisa aizsardzībā uzsākti vien pēdējo gadu laikā un ka esošās pretgaisa vienības izvietotas, prioritizējot lielākās pilsētas — tādēļ detekcijas nosegums nav vienāds visā teritorijā un Drīdža ezera tipa incidenti ir iespējami.', 0.85, '2026-05-25 14:02:32');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3855, 26, '2026-05-25', '2026-05-25', 0.0, '["Valsts kapitālsabiedrības", "Transports"]', '["Tuvojas liels brīdis Latvijas kapitāla tirgum - LAU Infra grupa (@autoceli) jau pēc divām nedēļām dodas uz biržu. Pirmais valsts uzņēmums ceļā uz IPO, ar ambīcijām augt Baltijā un Skandināvijā.", "Šodien Stividoru asociācija kopā ar @Sat_Min tikās ar @EM_gov_lv , lai apzinātu situāciju un sagatavotu iespējamos risinājumus."]', NULL, 'Švinka kā satiksmes ministrs publiski atbalsta LAU Infra grupas (autoceli) IPO procesu — pirmais valsts uzņēmums, kas dodas uz biržu. Atsevišķi paziņo par Satiksmes ministrijas un Stividoru asociācijas tikšanos ar Ekonomikas ministriju saistībā ar Krievijas dzelzceļa tranzīta tarifu vairāk nekā divkāršu palielinājumu Latvijas, Igaunijas un Somijas virzienā; uzsver ministrijas iepriekšējo darbu ostu darbības stiprināšanā un kravu pārorientācijā.', 0.85, '2026-05-25 14:03:08');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3861, 10, '2026-05-25', '2026-05-25', 0.0, '["Transports"]', '["neviens cits neesot bijis vairāk klātesošs gan no finanšu viedokļa, gan lēmumu pieņemšanā kā JV"]', NULL, 'Papildinājums 25.05 analīzei: Kulberga oficiālais pamatojums Satiksmes ministrijas uzticējumam JV — re-saved under Transports topic, jo Koalīcija-un-partijas slots bija jau aizņemts ar ministriju sadalījuma claim no tā paša source_url.', 0.8, '2026-05-25 14:04:28');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3877, 189, '2026-05-25', '2026-05-25', 0.0, '["Pašvaldības"]', '["Rīgas pašvaldība ies pilnīgi aplamu ceļu - pašvaldības dārziņu nepietiekama noslodze viņiem svarīgāka par bērnu interesēm."]', NULL, 'Pūce kritizē Rīgas pašvaldību par bērnudārzu politikas izvēli, kurā pašvaldības dārziņu noslodze priekšroka pār bērnu interesēm; norāda uz neizpētītu paradoksu — pašvaldības dārziņi tukši, privātie pilni.', 0.85, '2026-05-25 14:11:35');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3880, 57, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-25: 15 dokumentu (visi tvīti). 14 bare RT bez paša komentāra (suņu meklēšana, citu lietotāju viedokļi par robežu/dronu/ārlietām/NA/Dombravu/pensiju 2.līmeni/iepirkumiem/pilsētvidi/koalīciju). 1 paša tvīts (#42106) ir sarkastiska insinuācija par neidentificētu personu un ķīniešiem bez konkrētas politiskās nostājas. Nav saglabājamu pozīciju.', 0.2, '2026-05-25 14:14:58');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3884, 10, '2026-05-25', '2026-05-25', 0.0, '["Koalīcija un partijas"]', '[]', NULL, 'Round 2 ekstrakcija: 1 jauna pozīcija par sabiedrību šķeļošu jautājumu necilāšanu (Stambulas konvencija); 3 docs ir RSS lede stubs par valdības sastāva paziņojumu — dublē jau eksistējošas pozīcijas #20822/#20826.', 0.7, '2026-05-25 18:35:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3885, 72, '2026-05-25', '2026-05-25', 0.0, '["Imigrācija"]', '["Latvijai nevajag lētāko un ātrāko ''risinājumu'' darbaspēka trūkumam. Latvijai vajag gudru izaugsmi. Masveida imigrācija nav attīstības plāns."]', NULL, 'Indriksone tvītu pavedienā par 2025. gada zemo dzimstību iebilst pret masveida imigrāciju kā risinājumu darbaspēka trūkumam, aicina balstīties uz produktivitāti un uzņēmējdarbību.', 0.85, '2026-05-25 18:36:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3886, 15, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, 'Round 2 ekstrakcija: 6 docs, visi empty. 4 X tweets ir bare RT bez Braže paša komentāra (RT @USEmbassyKyiv, @Arlietas x2, @APildegovics); 2 web raksti (LSM+pmo.ee Diena) ziņo, ka JV virza Braži amata saglabāšanai, bet Braže pati nav citēta.', 0.6, '2026-05-25 18:36:34');
