INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3891, 6, '2026-05-25', '2026-05-25', 0.0, '[]', '[]', NULL, 'Round 2 ekstrakcija: 1 doc (jauns.lv) ziņo, ka NA valde virza Dombravu Iekšlietu ministra amatam jaunajā Kulberga valdībā. Dombrava pats NAV citēts kā runātājs — par viņu runā, viņš nerunā. Empty.', 0.6, '2026-05-25 18:36:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3900, 6, '2026-05-26', '2026-05-26', 0.0, '["Imigrācija"]', '[]', NULL, 'Dombrava (NA) Saeimas parlamentārās izmeklēšanas komisijas vadītāja statusā apņemas sākt ieviest komisijas vairāk nekā 100 priekšlikumus imigrācijas kontroles pastiprināšanai. 2026-05-26 Dombrava virzīts iekšlietu ministra amatam Kulberga valdībā.', 0.65, '2026-05-26 17:46:13');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3901, 10, '2026-05-26', '2026-05-26', 0.0, '["Aizsardzība un drošība", "Korupcija un KNAB", "Valsts pārvalde"]', '["Ja dara labas lietas, apsardzi nevajag"]', NULL, '2026-05-26: Kulbergs kā PM amata kandidāts iezīmē jaunās valdības programmu — drošība un 5% IKP aizsardzībai kā galvenā prioritāte, stingra disciplīna un nulles tolerance pret pārkāpumiem koalīcijā, kā arī personisks viedoklis par PM apsardzes ierobežotu lomu.', 0.8, '2026-05-26 17:46:56');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3902, 15, '2026-05-26', '2026-05-26', 0.0, '["Koalīcija un partijas", "Ārpolitika"]', '[]', NULL, 'Braže 2026-05-26: JV uzticības pieņemšana Kulberga valdības veidošanas kontekstā. Pārējie 15 docs — bare RTs (NATO, Eiropas solidaritāte, Ukrainas atbalsts), līdzjūtība Beļģijas traģēdijai, hokeja sveiciens, ģenerisks NATO ASG tikšanās apraksts — bez ekstraktējamas pirmpersonas pozīcijas.', 0.65, '2026-05-26 17:47:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3907, 57, '2026-05-26', '2026-05-26', 0.0, '["Korupcija un KNAB"]', '["Pērn progresīvo sērgas Šuvajevs no nodokļu maksātāju naudas izrija 89 000 eiro."]', NULL, 'Lapsas 26.05 X plūsma: 1 pirmpersonas pozīcija (Šuvajeva 89k EUR pašreklāmas apsūdzība, Korupcija un KNAB) + 14 docs bez ekstrahējamas pozīcijas (12 bare RT-i bez komentāra, 1 sarkastisks one-liner par Vienotību bez konkrēta referenta, 1 personīga ceļmalu skrējēja piezīme bez policy substances). Iekļaujas Lapsas iepriekšējā PRO/Šuvajeva finanšu kritikas līnijā (sk. #20799, #20515).', 0.5, '2026-05-26 17:48:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3909, 72, '2026-05-26', '2026-05-26', 0.0, '[]', '[]', NULL, '2026-05-26: Tikai viens pending doc (ID=42776) — 2022. gada LSM raksts par Vitenberga atteikumu no EM parlamentārā sekretāra amata. Indriksone tikai pieminēta kā tobrīd jaunieceltā ekonomikas ministre; birojs parafrāzēts ("diskusija arvien atklāta"), nav viņas pašas formulēta pozīcija. Trešās personas konteksts — nevis pirmās personas pozīcija.', 0.9, '2026-05-26 17:50:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3914, 189, '2026-05-26', '2026-05-26', 0.0, '[]', '[]', NULL, 'Trešo personu atbildes Pūces tvītam par privāto bērnudārzu līdzfinansējumu (2026-05-25). Nav paša Pūces pozīciju — visi 6 dokumenti ir citu X lietotāju replies, kur Pūce ir pieminēts, nevis runātājs.', 0.9, '2026-05-26 17:51:46');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3926, 204, '2026-05-26', '2026-05-26', 0.0, '[]', '[]', NULL, 'NBS oficiālais kanāls — organization slot. 3 dokumenti: (1) NBS Twitter paziņojums par sabiedroto virsskaņas lidojumiem Latgalē — publisks brīdinājums, ne pozīcija; (2) la.lv raksts ar NBS majora Slaidiņa komentāru par Krievijas mācību grāmatu — NBS institūcijai nav ekstraktējamas pozīcijas, runā nosauks virsnieks; (3) nra.lv raksts par IZM noteikumu grozījumiem skolēnu atbrīvošanai no eksāmeniem — NBS nav subjekts. Visi 3 atbilstoši organization+relay tipam — slots pastāv lai dokumenti ienāktu korpusā un matched citus tracked politikus.', 0.9, '2026-05-26 18:35:33');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3930, 26, '2026-05-26', '2026-05-26', 0.0, '[]', '[]', NULL, '2 docs reviewed, neviena ekstraktējama pozīcija. RIX tweets (42907) ir ceremoniāls labvēlīgs komentārs par lidostas finanšu rezultātiem bez politiskas nostājas. Diena raksts (42807) ir paywall-saīsināts līdz lede, kas tikai uzskaita Švinkas nosauktās tēmas (Ostu likums, sabiedriskais transports) kā nepadarītus darbus, bez konkrētas politiskas nostājas par to, kā tie risināmi.', 0.3, '2026-05-26 18:35:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3931, 30, '2026-05-26', '2026-05-26', 0.0, '["Valsts pārvalde", "Aizsardzība un drošība"]', '["Parastais politiskais piedāvājums Latvijā ir Mēs mainām sejas. Mēs piedāvāsim mainīt ko citu — noteikumus.", "Drošības darba grupas piedāvājumā figurē Civilās aizsardzības dienests, kuru veidotu nevis instrukciju rakstītāji, bet uz vietas krīzes situācijā atbildību uzņemties un lēmumus pieņemt spējīgi cilvēki bez ieročiem."]', NULL, 'Baško 25.05 ieskicē topošās partijas programmas asi: nevis personu maiņa, bet noteikumu maiņa. Iebilst pret plānu un instrukciju multiplicēšanos kā risinājumu krīzēm — uzsver, ka mazā Latvijā atbildīgs vietējais cilvēks ir efektīvāks par detalizētu plānu. Konkrēts piemērs: drošības darba grupa piedāvā Civilās aizsardzības dienestu, kurā strādātu atbildību uzņemties spējīgi cilvēki bez ieročiem, nevis instrukciju rakstītāji. 26.05 retvīts (Vilgerts par nogalinātajām idejām) bez komentāra — netiek ekstraktēts.', 0.75, '2026-05-26 18:35:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3951, 204, '2026-05-26', '2026-05-26', 0.0, '[]', '[]', NULL, 'Latvijas armijas (NBS) organization slot — institucionāls kanāls, ne first-party speaker. Visi 18 historic backlog dokumenti (LETA wire, NBS X retvīti, ziņu raksti par NBS aktivitātēm) ir trešās puses pieminējumi vai oficiāli paziņojumi bez ekstraktējamas politiskas nostājas. Per claim-extractor Step 3c organization+relay rule → empty.', 0.2, '2026-05-26 18:41:18');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3958, 57, '2026-05-26', '2026-05-26', 0.0, '["Budžets un finanses", "Ārpolitika", "Korupcija un KNAB"]', '["Viens no komuņaku mīļākajiem vārdiem - virspeļņa. Šādi sarkanie meļņi, kas trekni dzīvo uz Jūsu rēķina, vairāk par visu pasaulē grib regulēt to, ko Jūs darāt, cik Jūs pelnāt, ko Jūs darāt ar savu naudu.", "Mēs esam nonākuši tiktāl, ka stulbene ārlietu ministra amatā izplata kremļa paziņojumus pilnā apmērā.", "Kas ir apbrīnojamākais - tā iekšējā puvuma pakāpe, kas šiem vienotības vēža rotbergiem ļauj bez mazākā mulsuma sašust par bezgala noziedzīgi izmantotiem desmitiem tūkstošu un ne vārdu nepieminēt savu politkompanjonu un labuma guvēju izzagtos miljardus."]', NULL, 'Lato Lapsa 17.-25.05 X korpusa atlikušais loks: trīs ekstraktējamas pozīcijas (pret virspeļņas regulējumu kā komunistisku; ārlietu ministres B.Bražes apsūdzība Kremļa paziņojumu izplatīšanā; selektīvas korupcijas sašutuma apsūdzība JV figūrām ''rotbergi''). Četri dokumenti tukši — divi promo (Latviešu strēlnieku grāmatas konkurss), viens sarkastisks vienteikuma izsmiekls bez konkrētas politikas, viens vāji konkretizēts PRO deputātu apzīmējums ar netiešu atsauci.', 0.7, '2026-05-26 18:43:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3962, 57, '2026-05-27', '2026-05-27', 0.0, '["Tieslietas", "Sabiedriskie mediji"]', '["Viena no pamatpazīmēm - viņiem nospļauties uz \"ko tur kāds likums neļauj\", jo galvenais ir revolucionārā pārliecība.", "Noklausījos oriģinālu. Izrādās, viss ir vēl smieklīgāk - propagandoni atkal ir ķēkšu izlabojuši."]', NULL, 'Lato Lapsa 2026-05-27 X aktivitāte koncentrējas uz divām tēmām: (1) sabiedriskā medija "propagandonu" kritika par Siliņas gramatiskās kļūdas izteikuma selektīvu rediģēšanu ("ideoloģija liek pa priekšu sabiedrības intereses"), apgalvojot, ka oriģinālā bijis "ideoloģijU" un medijs to mainījis, lai paslēptu premjeres kļūdu; (2) personisks uzbrukums ierēdnim Mikiņam ar tēzi par komuņisku ideoloģisku pārliecību pār likuma normām. 15 retvīti bez komentāra (galvenokārt no paša Pietiek portāla — emigrācija, drons, govju emisijas, LTV diskusija) — netiek ekstraktēti kā paša pozīcijas.', 0.6, '2026-05-27 14:21:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3963, 15, '2026-05-27', '2026-05-27', 0.0, '["Droni", "Aizsardzība un drošība"]', '["nepieciešama agrīnā brīdināšana, identificēšana un elastīga reakcija"]', NULL, 'Drone Summit 2026 Rīgā: Braže atzīst, ka nesenie dronu incidenti Latvijas gaisa telpā radīja izaicinājumus bruņotajiem spēkiem un pašvaldībām. Uzsver, ka nepieciešama agrīnā brīdināšana, identificēšana un elastīga reakcija, un ka atbildība par reaģēšanu nevar būt tikai bruņoto spēku pārziņā — jāiesaistās robežsardzei un citiem dienestiem. Pārējie 12 dokumenti dienā ir RT no MFA/Arlietas/ārvalstu ministriju kanāliem bez paša komentāra, vai ceremoniāli divpusēji sveicieni (Beikons/Keiss).', 0.85, '2026-05-27 14:22:06');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3968, 10, '2026-05-27', '2026-05-27', 0.0, '["Valsts pārvalde", "Koalīcija un partijas"]', '["Nedrīkst teikt hop, pirms nav apstiprinājuma."]', NULL, '2026-05-27 doc-baseline: 8 dokumenti dienā pirms 28.05 Saeimas valdības apstiprināšanas balsojuma. 1 ekstrakcija — procesuāla atruna par biroja sastāvu (jauns.lv tiešs citāts). 7 dokumenti tukši: 4 satur deklarācijas/īpašumu faktus bez politikas pozīcijām (43475, 43463, 43427), 1 ekspertu parafrāze (43431), 2 trešās puses aprēķini par 66-deputātu vairākumu (43424, 43419), 1 LETA wire dublikāts jau ekstrahētajam citātam (43453). Iepriekš jau ekstrahētās 25-26.05 pozīcijas (valdības deklarācija, prioritātes, koalīcijas līgums) paliek autoritatīvas — šodienas RSS plūsma galvenokārt deklarācijas attēlojums + procesa atruna.', 0.85, '2026-05-27 14:27:51');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3979, 204, '2026-05-27', '2026-05-27', 0.0, '[]', '[]', NULL, '', 0.2, '2026-05-27 14:35:27');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3986, 6, '2026-05-27', '2026-05-27', 0.0, '["Imigrācija", "Aizsardzība un drošība"]', '["Iekšlietu nozarē gaidāmas kardinālas pārmaiņas - stingra imigrācijas politika, iekšlietu dienestu stiprināšana un cilvēku drošība."]', NULL, 'Dombrava kā Kulberga valdības iekšlietu ministra kandidāts iezīmē trīs prioritātes: stingru imigrācijas politiku, iekšlietu dienestu stiprināšanu un cilvēku drošību. Saskan ar viņa konsekvento NA pozīciju imigrācijas jautājumā (sk. #20664, #18343, #17900).', 0.8, '2026-05-27 14:36:45');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3995, 30, '2026-05-27', '2026-05-27', 0.0, '[]', '[]', NULL, 'Sarkastisks tvīts par neidentificētiem "konkurentiem", kas sistemātiski ziņo par MMN video sociālajos medijos — bez konkrētas politikas nostājas; sūdzība par platformu moderāciju, nevis pozīcija.', 0.2, '2026-05-27 14:38:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (3997, 182, '2026-05-27', '2026-05-27', 0.0, '[]', '[]', NULL, 'Ozols retvīto katalāņu valodā tvītu ("Bon dia i visca la terra") bez paša komentāra. Bare retweet bez pievienota teksta un ārpus Latvijas politikas konteksta — nav ekstraktējama pirmās personas pozīcija.', 0.5, '2026-05-27 14:38:42');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4007, 57, '2026-05-27', '2026-05-27', 0.0, '["Sabiedriskie mediji"]', '["Sabiedriskais medijs. 72 miljoni eiro nodokļu maksātāju naudas gadā. Nespēj pat septiņus vārdus pareizi uzrakstīt."]', NULL, 'Lato Lapsa turpina LSM/sabiedriskā medija kritikas līniju — saista 72 miljonu eiro gada finansējumu ar redakcionālās kvalitātes problēmām (gramatikas kļūdas).', 0.65, '2026-05-27 17:55:43');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4017, 204, '2026-05-27', '2026-05-27', 0.0, '[]', '[]', NULL, 'LSM raksts par NBS pretmobilitātes šķēršļu (pūķa zobu) izvietošanu Austrumu pierobežā. Operatīvs paziņojums par notiekošu izbūvi, nevis NBS doktrināla vai politiska nostāja. Latvijas armija šeit ir runas objekts, nevis runātājs — saskaņā ar Step 3c (organization + relay) un Step 3 skip-list (talked about, not speaking).', 0.3, '2026-05-27 17:57:39');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4018, 10, '2026-05-27', '2026-05-27', 0.0, '["Valsts kapitālsabiedrības"]', '["TAS IR PAVEIKTS! Visā valdības veidošanas trakumā man bija jāpaspēj vēl pabeigt PIK Siltuma izmeklēšanas komisijas Gala Ziņojums uz rītdienas Saeimas sēdi 28.maijā."]', NULL, 'Kulbergs paziņo, ka 27.05 pabeidzis PIK Saeimas izmeklēšanas komisijas par Rīgas centralizētās siltumapgādes Gala Ziņojumu; iesniegs to 28.05 Saeimas sēdei pirms iespējamā apstiprinājuma par MP, kas automātiski atņemtu viņa deputāta mandātu.', 0.85, '2026-05-27 17:57:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4019, 30, '2026-05-27', '2026-05-27', 0.0, '[]', '[]', NULL, 'Baško tikai pārtweeto MMN partijas ziņu par Tamaņa darba grupu Īrijā — nav paša pievienots komentārs vai pozīcija.', 0.7, '2026-05-27 17:58:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4023, 15, '2026-05-27', '2026-05-27', 0.0, '[]', '[]', NULL, 'Bare retweet no @Arlietas (Ārlietu ministrijas) konta par ES Padomes prezidentūras sekretariāta 16. jūnija pasākumu uzņēmējiem; nav pievienots Bražes komentārs vai personīga pozīcija.', 0.2, '2026-05-27 17:59:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4027, 57, '2026-05-28', '2026-05-28', 0.0, '[]', '[]', NULL, '2026-05-28 partija: 9 dokumenti pārskatīti, 0 ekstraktējamu pozīciju. 6 bare RT bez komentāra (43963, 43964, 43965, 43966, 43967, 43969), 2 ne-politiski pirmā lielā tvīti (43962 par kaķiem, 43968 par strēlnieku grāmatas saturu — kultūras/vēsturisks komentārs), 1 sarkastisks ad hominem pret Melbārdi/Siliņu bez konkrēta politiska sastāva (43961 — "stulbāka ķēkša" apvainojums, bez policy substance per Step 3 skip-list).', 0.5, '2026-05-28 07:18:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4028, 15, '2026-05-28', '2026-05-28', 0.0, '[]', '[]', NULL, 'Visi 4 dokumenti ir bare retweets bez Brāzes pievienota komentāra (Reuters EN par anti-drone aizsardzību, Cen4infoRes EN par UK A7 sankcijām, Melbārdes IZM noslēgums, DefensieMin NL par Rīgas drone-top). Saskaņā ar skip-list Step 3, bare RT bez pievienota teksta nav ekstraktējamas pozīcijas.', 0.2, '2026-05-28 07:18:53');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4036, 10, '2026-05-28', '2026-05-28', 0.0, '[]', '[]', NULL, '2026-05-28 dokumentu kopa (7 dok.) sedz Kulberga valdības deklarācijas + sadarbības līguma parakstīšanas ceremoniju un biroja vadītāja iecelšanu (Mareks Gruškevics). Nav jaunu pirmpersoniski formulētu pozīciju — sustantīvās deklarācijas tēzes (5%IKP aizsardzībai, koalīcijas disciplīna, drošības prioritāte) jau ekstrahētas 26.05 (claims #22991-22993, #520853). Tvīts par ''pēdējie privātās brīvības metri'' ir personīga sentimentāla piezīme bez polītiskās substances. Visi 7 dok. atzīmēti kā ''empty_doc_ids''.', 0.85, '2026-05-28 07:21:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4037, 72, '2026-05-28', '2026-05-28', 0.0, '[]', '[]', NULL, '1 dokuments (pmo.ee wire par amatpersonu deklarāciju) — Indriksone ir subject, nevis runātāja; nav ekstraktējamas pozīcijas.', 0.2, '2026-05-28 07:21:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4041, 26, '2026-05-28', '2026-05-28', 0.0, '["Valsts pārvalde"]', '["Pirms galīgā lēmuma pieņemšanas par to, ka Baltijas valstis kā jauno standarta laiku atbalsta pāreju uz pastāvīgu vasaras laiku, ir nepieciešama plašāka diskusija sabiedrībā."]', NULL, 'Švinka uzsver, ka pirms galīgā lēmuma par Baltijas valstu pāreju uz pastāvīgu vasaras laiku kā jauno standarta laiku nepieciešama plašāka sabiedrības diskusija.', 0.75, '2026-05-28 07:21:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4052, 30, '2026-05-28', '2026-05-28', 0.0, '[]', '[]', NULL, 'Viens tvīts (id=43929) — filozofiska refleksija par mākslīgo intelektu un cilvēka apziņu, bez konkrētas politiskās pozīcijas.', 0.3, '2026-05-28 07:23:34');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4055, 204, '2026-05-28', '2026-05-28', 0.0, '[]', '[]', NULL, 'NBS organization slot sweep — 2 LA.lv/NRA.lv raksti ar Jāņa Slaidiņa (NBS majors, Zemessardzes štāba virsnieks) personīgo analīzi TV24 raidījumā par Krievijas/Ukrainas kara scenārijiem. Tie nav NBS institucionālas pozīcijas — Slaidiņš te runā kā militārs eksperts/komentētājs, ne kā NBS oficiāls pārstāvis. Per Step 3c organization+relay rule: NBS slot defaults to empty; trešās puses preses pārklājums tracked politiķiem (ja kāds) sasniedz subjektus caur text-scan, ne caur šo slot.', 1.0, '2026-05-28 07:23:49');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4059, 57, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-29: 18 dokumenti (visi tvīti/x_mention). Visi ir vai nu retvīti bez paša komentāra (RT @...), vai sarkastiski personiski apvainojumi un insinuācijas bez konkrētas politikas nostājas (piem. "Šai kucei derētu ekskursija mentu zaņķī", "Lētajām politkucēm izsniegta bildīte"). Neviens neformulē pirmās personas konkrētu politikas atbalstu vai iebildumu. Saskaņā ar strict skip-list (sarkastiski one-liner-i un insinuācijas bez nostājas + bare retweets) visi 18 atzīmēti kā empty.', 0.2, '2026-05-29 15:26:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4060, 15, '2026-05-29', '2026-05-29', 0.0, '["Ukraina un Krievija", "Ārpolitika", "ES politika"]', '["We condemn Russian drones striking Romanians, at home, at night. The aggressor Russia must be stopped through mighty sanctions and sustained help to Ukraine.", "it will be my honour and pleasure to continue working with for the future of Europe that is safe, secure and prosperous with Ukraine fully integrated in the Euroatlantic community."]', NULL, 'Braže 29.05: nosoda Krievijas dronu triecienu Rumānijai (Galacā), prasa spēcīgas sankcijas un atbalstu Ukrainai; apņemas turpināt darbu par Ukrainas pilnīgu eiroatlantisko integrāciju. Pārējie 18 dokumenti — retvīti bez komentāra vai ceremoniāli (hokejs, promo).', 0.8, '2026-05-29 15:26:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4061, 6, '2026-05-29', '2026-05-29', 0.0, '["Valodu politika", "Imigrācija", "Aizsardzība un drošība"]', '["Latvijā valsts valoda ir latviešu! Mans pirmais rīkojums ir uzdot visiem iekšlietu sistēmā strādājošajiem darba pienākumu izpildē un savstarpējā saskarsmē ar iedzīvotājiem un kolēģiem lietot tikai un vienīgi valsts valodu!"]', NULL, 'Dombrava pirmajā darba dienā iekšlietu ministra amatā izdod pirmo rīkojumu par valsts valodas obligātu lietošanu iekšlietu sistēmā un intervijā nosauc prioritātes: imigrācijas ierobežošana, iekšlietu dienestu stiprināšana, civilās aizsardzības pilnveidošana un ciešāka iekšlietu–aizsardzības dienestu sadarbība.', 0.85, '2026-05-29 15:27:26');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4064, 10, '2026-05-29', '2026-05-29', 0.0, '["Budžets un finanses", "Valsts pārvalde", "Rail Baltica", "Koalīcija un partijas", "Droni", "Degviela un enerģētika"]', '["Neko nedarīt nav izeja no situācijas", "Gumijas vilkšana tagad neder", "Ja nav ekonomikas, nebūs drošība"]', NULL, 'Andris Kulbergs (AS) apstiprināts par Ministru prezidentu (28.05, 66 par / 25 pret). Premjera apstiprināšanas runā un preses konferencē pauda fiskālās disciplīnas nostājas (valsts nedrīkst dzīvot uz parāda; izšķērdībai punkts; ES fondu apguve nedrīkst būt pašmērķis), pārvaldes kultūras maiņu (''ātrums un atbildība'', citu politisko kultūru ar mērāmu rezultātu), personīgu atbildību par airBaltic/Rail Baltica/vēlēšanām, kā arī aicinājumu veidot vienotu Baltijas enerģētikas stratēģiju.', 0.78, '2026-05-29 15:28:09');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4073, 30, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Ceremoniāls/filozofisks tvīts par varas nodošanu valdības maiņā; pateicība Siliņai un novēlējumi Kulbergam. Nav ekstraktējamas pirmās personas politikas pozīcijas.', 0.2, '2026-05-29 15:33:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4083, 26, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Satiksmes ministrs ziņo faktus: airBaltic atmaksājusi pirmos 6,4 milj. eiro no valsts aizdevuma, ciešā sadarbībā ar Satiksmes ministriju, biznesa plāns jāiesniedz līdz nedēļas beigām. Statusa ziņojums bez paša formulētas atbalsta/iebildes nostājas — nav ekstraktējamas pozīcijas.', 0.2, '2026-05-29 15:33:21');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4087, 189, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Abi tvīti ir īsi, vāji formulēti komentāri. Pirmais (idejas un enerģija) ir vispārīgs bez politikas satura. Otrais atsaucas uz iepriekš publicētu budžeta deficīta risinājumu, bet pašā tvītā konkrēta nostāja nav formulēta — tikai meta-atsauce. Nav ekstraktējamas pozīcijas.', 0.2, '2026-05-29 15:33:36');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4091, 204, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Latvijas armijas (NBS) organizācijas slots. Dokuments 45203 ir informatīvs/pateicības tvīts par sabiedroto iznīcinātāju zemo pārlidojumu virs Lielvārdes un pateicība iedzīvotājiem par atbalstu. Nav konkrētas pirmās personas institucionālas politikas nostājas — ceremoniāls/informatīvs paziņojums.', 0.2, '2026-05-29 15:34:03');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4103, 57, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Lato Lapsas 2026-05-28 papildsanāksmes pārskats (17 dokumenti): visi tukši. Divpadsmit kaili retvīti bez komentāra (RT @Mantrausis, @JurgisLiepnieks, @Ievaqwertyu, @christiansvsl, @remicentrs, @Heinrih5 divreiz, @n_karklinz, @AZvejsalnieks, @Vents_Zvaigzne divreiz, @ieva_w) un pieci paša sarkastiski viena teikuma izteikumi bez konkrētas politikas nostājas: piesaukumi par "okupācijas kolaboracionistu varu", Briškena, Švinkas un Sprūda vārdu pieminēšana ar apvainojumiem, kā arī personiski apvainojumi. Neviens dokuments nesatur ekstraktējamu pirmās personas politikas pozīciju.', 0.2, '2026-05-29 16:11:48');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4104, 10, '2026-05-29', '2026-05-29', 0.0, '["Korupcija un KNAB", "Imigrācija"]', '["Es gribētu, ka tiek biežāk lietota frāze \"KNAB konstatē\", pamatoti skatot lietas par miljoniem nevis par sīkumiem"]', NULL, '28.05 backlog: divas jaunas pozīcijas (KNAB kritika, imigrācijas kontrole); pārējais dublē jau saglabātās PM apstiprināšanas/koalīcijas pozīcijas vai ir trešo personu kritika/ceremoniāls saturs.', 0.75, '2026-05-29 16:12:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4105, 15, '2026-05-29', '2026-05-29', 0.0, '["Digitālā politika", "Ārpolitika"]', '["MI, datu analītika, jauno tehnoloģiju apmācības jāintegrē izglītības sistēmā jau no pamatiem."]', NULL, 'Braže 2026-05-28 backlog: divas jaunas pozīcijas — jauno tehnoloģiju integrācija izglītībā un ārpolitikas prioritātes jaunajā Kulberga valdībā. Pārējie 11 dokumenti ir retvīti bez komentāra vai dublē jau esošās pozīcijas.', 0.8, '2026-05-29 16:12:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4113, 189, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Trīs tvīti par jaunās Kulberga valdības apstiprināšanu: retoriski jautājumi par konkrētību (pretdronu, airBaltic, Rail Baltica, budžeta taupība), analītisks novērojums par to, kas palīdzēja izveidot valdību, un sarkastisks vienrindis. Nav ekstraktējamas pirmās personas pozīcijas.', 0.2, '2026-05-29 16:14:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4115, 182, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Visi 3 dokumenti ir tukši retvīti (RT @Gerashchenko_en, RT @RakMakkabi, RT @InsiderEng) bez paša komentāra — nav ekstraktējamas pirmās personas pozīcijas.', 0.2, '2026-05-29 16:14:52');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4117, 26, '2026-05-29', '2026-05-29', 0.0, '["Rail Baltica"]', '["Tiltam pār Daugavu arī tika rasts risinājums un pieņemts spēcīgs lēmums - nebūvēt tiltu par 800 milj Euro."]', NULL, 'Satiksmes ministrs Švinka precizē Rail Baltica projekta gaitu: lēmums nebūvēt 800 milj. tiltu pār Daugavu, optimizācija līdz 280 milj.; projektu pilnā apjomā nav iespējams pabeigt līdz 2030. gadam.', 0.85, '2026-05-29 16:14:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4120, 6, '2026-05-29', '2026-05-29', 0.0, '["Imigrācija"]', '["Apjomīgais gala ziņojums par problēmām imigrācijas jomā ir pieņemts Saeimā. Tagad ir jāuzsāk darbs pie rekomendāciju ieviešanas likumos un iestāžu darbībā."]', NULL, 'Dombrava 28.05 tvītā paziņo, ka Saeimā pieņemts gala ziņojums par imigrācijas problēmām, un aicina uzsākt rekomendāciju ieviešanu likumos un iestāžu darbībā. Web raksts par Puntuļa biroju Dombravu tikai piemin kā topošo ministru.', 0.75, '2026-05-29 16:15:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4121, 30, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Divi tvīti: sarkastiska piezīme par klimatu/enerģētiku un retorisks jautājums par runāšanu pirms balsojuma. Nav ekstraktējamas politikas pozīcijas.', 0.2, '2026-05-29 16:15:58');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4124, 204, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Organizācijas slots. Tvīts ar sabiedrības izglītošanu par divu sienu principu (info, ne politikas pozīcija); NRA raksts par Robežsardzes/IeM helikopteru iegādi (trešās puses saturs, NBS minēta tikai kā nākotnes lietotājs). Nav pirmpersonas institucionālas politikas pozīcijas.', 0.2, '2026-05-29 16:15:58');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4147, 72, '2026-05-29', '2026-05-29', 0.0, '["Izglītība"]', '[]', NULL, 'Indriksone (NA) kā jaunā izglītības ministre intervijā NRA pauž nodomu dot skolu direktoriem un pedagogiem lielākas lemšanas tiesības (pozīcija no virsraksta; pamatteksts ir video anonss).', 0.6, '2026-05-29 16:21:12');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4150, 10, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Kulbergs 28.05 backlog tail: trešās puses/ceremoniāls — nav paša pozīcijas', 0.2, '2026-05-29 16:22:29');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4152, 57, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-29: 4 dokumenti, 0 ekstraktējamas pozīcijas. Trīs tukši retvīti bez komentāra (RB iepirkums, Ežu Hospitālis ziedojumi, VID tālruņa laiki) un viens pirmās personas tvīts ar lūgumu palīdzēt identificēt vēsturisku strēlnieku grāmatai — nav politiskas nostājas.', 0.2, '2026-05-29 17:33:59');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4154, 182, '2026-05-29', '2026-05-29', 0.0, '["Vēlēšanas"]', '["Rudenī būs vēlēšanas - mums vajadzīga pilnīgi cita komanda."]', NULL, 'Ozols rudens vēlēšanu kontekstā aicina diskvalificēt katru partiju, kas krāpusi vēlētājus, un ieviest Ziemeļeiropas modeļa neiecietību pret korumpētiem politiķiem.', 0.8, '2026-05-29 17:34:37');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4158, 15, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, '1 dokuments: līdzjūtība bojāgājušo alpīnistu tuviniekiem Makkinlija kalna traģēdijā. Ceremoniāls/līdzjūtības izteikums — nav politiskas pozīcijas.', 0.2, '2026-05-29 17:34:54');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4160, 10, '2026-05-29', '2026-05-29', 0.0, '["Aizsardzība un drošība", "Valsts pārvalde"]', '["Šīs valdības prioritāte ir drošība, tāpēc kā pirmo satieku jauno aizsardzības ministru Melni", "Četru mēnešu limitētā laikā likvidēt vai apvienot ministrijas nav prāta darbs, ja enerģija un uzmanība ir jāvelta drošībai"]', NULL, 'Kulberga pirmā darba diena premjera amatā: konkrēta rīcība drošības stiprināšanai (tikšanās ar aizsardzības ministru Melni) un nostāja pret sasteigtu ministriju optimizāciju ierobežotajā 4 mēnešu termiņā.', 0.7, '2026-05-29 17:35:02');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4164, 72, '2026-05-29', '2026-05-29', 0.0, '[]', '[]', NULL, 'Ziņa par to, ka izglītības un zinātnes ministres Indriksones biroju vadīs Rūdolfs Kalvāns. Indriksone ir tikai subjekts, nevis runātāja — nav viņas formulētas pozīcijas. Administratīva personāla ziņa.', 0.2, '2026-05-29 17:36:51');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4167, 10, '2026-05-30', '2026-05-30', 0.0, '["Koalīcija un partijas"]', '["ministriem un koalīcijas partijām būs jānoliek malā “duncīši un nazīši”"]', NULL, 'Kulbergs pirms apstiprināšanas balsojuma (TV24 intervija) izsaka divas pirmās personas nostājas par valdības vadību: politiskās kultūras maiņa (mazināt pozīcija-opozīcija dalījumu) un prasība koalīcijai priekšvēlēšanu laikā strādāt ar konkrētiem darbiem, ne retoriku. Ceremoniālais amata pārņemšanas dokuments (44960) bez ekstraktējamas pozīcijas.', 0.72, '2026-05-30 19:57:44');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4168, 72, '2026-05-30', '2026-05-30', 0.0, '["Imigrācija", "Koalīcija un partijas", "Izglītība"]', '[]', NULL, 'Indriksone (NA valdes priekšsēdētāja) TV24 raidījumā komentē jaunās Kulberga valdības ministriju sadalījumu — NA saņem Iekšlietu ministriju ar civilās aizsardzības un imigrācijas kontroles prioritātēm, kā arī kultūras un izglītības jomas.', 0.8, '2026-05-30 19:58:01');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4169, 204, '2026-05-30', '2026-05-30', 0.0, '[]', '[]', NULL, 'Dok. 45698 (la.lv) ir TV24 raidījuma "Uz līnijas" intervija ar NBS majoru un Zemessardzes štāba virsnieku Jāni Slaidiņu par sabiedrības nogurumu no kara Ukrainā. Tas ir individuāla virsnieka personisks viedoklis un personiska rīcība (pats nesen nosūtījis dronus Ukrainas karavīriem; uzsver, ka viņa paša ieguldījums ir neliels) — NEVIS Latvijas armijas (NBS) kā iestādes pirmās puses institucionāla pozīcija. Slaidiņš pats nav atsevišķi izsekots politiķis. NBS organizācijas slots dokumentu saņēma tikai tāpēc, ka NBS ir pieminēts, nevis tāpēc, ka iestāde būtu izteikusi nostāju. Lai izvairītos no individuāla viedokļa misatribūcijas iestādei, dokuments atzīmēts kā tukšs (bez pozīcijas).', 0.2, '2026-05-30 19:58:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4170, 57, '2026-05-30', '2026-05-30', 0.0, '[]', '[]', NULL, 'Lato Lapsa (@Lato_Lapsa) 2026-05-30: 12 dokumenti apskatīti. 9 kaili retvīti bez paša komentāra (45804,45805,45806,45807,45808,45810,45811,45812,45813,45815), 1 sarkastisks vienrindis bez konkrētas politikas nostājas (45809 par Gunti Svariņu), 1 ceremoniāla pateicība (45814). Nevienā nav ekstraktējamas pirmās personas politikas pozīcijas.', 0.2, '2026-05-30 20:08:17');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4171, 15, '2026-05-30', '2026-05-30', 0.0, '["Droni"]', '["In Latvia''s pine forests, #NATO drone future takes shape. How a remote military range is becoming central to @NATO innovation."]', NULL, 'Braže pirmpersonas tvītā pozicionē Latvijas militāro poligonu kā centrālu NATO dronu inovācijas attīstības vietu. Pārējie 10 dokumenti ir tukši (kaili retvīti bez komentāra vai ceremoniāli/kultūras apsveikumi).', 0.65, '2026-05-30 20:08:40');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4176, 10, '2026-05-30', '2026-05-30', 0.0, '[]', '[]', NULL, 'Divi tvīti — rallija humors un līdzjūtība; bez politikas pozīcijas.', 0.2, '2026-05-30 20:12:00');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4180, 182, '2026-05-30', '2026-05-30', 0.0, '["Ukraina un Krievija", "Vēlēšanas", "Koalīcija un partijas"]', '[]', NULL, 'Ozols: tribunāls Ukrainai, vēlēšanu sistēmas maiņa, anti-oligarhu nostāja.', 0.8, '2026-05-30 20:12:24');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4197, 30, '2026-05-30', '2026-05-30', 0.0, '["Koalīcija un partijas"]', '["Partiju finansēšanas ierobežojumi ir viens no veiksmīgākajiem instrumentiem, kā šodienas pasīvajā sabiedrībā reizi par visām reizēm aizcementet aktīvo partiju sarakstu"]', NULL, 'Baško kritizē partiju finansēšanas ierobežojumus.', 0.8, '2026-05-30 20:15:07');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4198, 6, '2026-05-30', '2026-05-30', 0.0, '["Aizsardzība un drošība"]', '["Attīstīsim robežsardzes spējas, iespējams pat pielietojot modernas dronu detekcijas un notriekšanas sistēmas, tādā veidā sniedzot efektīvu atbalstu mūsu nacionālajiem bruņotajiem spēkiem uz robežas."]', NULL, 'Dombrava izklāsta civilo aizsardzību kā savu un komandas prioritāti — robežsardzes spēju attīstība, dronu detekcijas un notriekšanas sistēmas, gaisa apdraudējuma brīdinājumi un kritiskās infrastruktūras aizsardzība.', 0.85, '2026-05-30 20:15:23');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4199, 189, '2026-05-30', '2026-05-30', 0.0, '["Budžets un finanses"]', '["Konkurence banku sektorā nepietiekama."]', NULL, 'Pūce tvītā norāda, ka konkurence Latvijas banku sektorā ir nepietiekama — pirmās personas nostāja par finanšu tirgus struktūru.', 0.6, '2026-05-30 20:15:39');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4201, 26, '2026-05-30', '2026-05-30', 0.0, '["Korupcija un KNAB"]', '["kaut vai tūlīt izdot ministru prezidenta rezolūciju zemkopības ministram publiskot LVM finanšu dokumentus un naudas plūsmas"]', NULL, 'Švinka aicina premjeru Kulbergu nekavējoties rīkoties LVM/Zemkopības ministrijas lietā — izdot ministru prezidenta rezolūciju zemkopības ministram publiskot LVM finanšu dokumentus un naudas plūsmas, lai sabiedrībai izgaismotu ZZS shēmas.', 0.8, '2026-05-30 20:16:13');
INSERT INTO analyses (id, opponent_id, period_start, period_end, sentiment_score, key_topics, notable_quotes, position_shifts, brief_markdown, confidence, created_at) VALUES (4207, 57, '2026-05-30', '2026-05-30', 0.0, '[]', '[]', NULL, 'Lato Lapsa 2026-05-30 round-2 (3 atliktie tvīti no 12-dokumentu vāka): visi trīs nav ekstraktējami. 45816 = lūgums retvītot ziņu par dzīvnieku/kukaiņu mājām (nav politiska nostāja). 45817 = sludinājums par mantas atdošanu Dzelzavas ielā (nav nostāja). 45818 = kails retvīts @JazepsBasko par partiju finansēšanas ierobežojumiem, bez Lapsas paša komentāra (bare RT, satura autors ir Baško, nevis Lapsa).', 0.2, '2026-05-30 20:19:24');
INSERT INTO context_notes (id, opponent_id, topic, note_type, content, source, expires_at, created_at, visual_brief_json) VALUES (215, 26, 'Rail Baltica', 'context', 'Švinka RB Rail kritikas eskalācija 2,5 mēnešos. Mar-10: ierosina dienesta pārbaudi par sliežu pārmiju iepirkumiem (claim #208). Mar-17: publiski atzīst, ka Latvija atpaliek ''par vairākiem apļiem'' (#11005). Apr-26: pieprasa kopuzņēmuma restartu — līdz vēlēšanām sliedes nebūs (#14331). May-18: konkrēts strukturāls priekšlikums pirms Tallinas tikšanās — atstāt tikai informācijas koordinācijas un EK saziņas funkcijas, būtiski samazināt darbinieku skaitu; norāda uz Polijas/Somijas modeli bez RB Rail līdzīga uzņēmuma (#20536). Konsekventa pesimistiska trajektorija — eskalācija, ne reversal. 2030. termiņa pabeigšana paziņota kā ''izaicinoša'' ierobežotā budžeta dēļ (#20534).', 'contradiction-hunter 2026-05-18 (Švinka)', NULL, '2026-05-18 13:47:58', NULL);
INSERT INTO context_notes (id, opponent_id, topic, note_type, content, source, expires_at, created_at, visual_brief_json) VALUES (226, NULL, 'dienas pārskats 2026-05-25', 'daily_brief', '# Dienas analīze — 2026-05-25

## Galvenais

<!-- DIENAS STATS (iekšēja piezīme aģentam; nav renderēta publikai): 849 dokumenti (107 web + 742 Twitter/X) · 29 pozīcijas · 0 pretrunas -->

- **Kulberga valdības kontūras:** premjera kandidāts Kulbergs (AS) atklāj ministriju sadalījumu — AS pārņem Finanses, Tieslietas un VARAM; NA — Izglītību, Kultūru, Iekšlietas un Klimatu/enerģētiku; ZZS saglabā trīs portfeļus; JV samazināta līdz Ārlietām un Veselībai, papildus uzņemoties Aizsardzību un Satiksmi.
- **Iekšējās spriedzes atzīšana:** Kulbergs publiski apstiprina "nekoleģiālu rīcību" vienā no koalīcijas sarunu mirkļiem un apņemšanos necilāt Stambulas konvenciju, savukārt Šuvajevs (PRO) pieprasa izņemt ZZS no Zemkopības ministrijas pēc Valsts kontroles revīzijas.
- **LPV alternatīva:** Mežals (LPV) divos atsevišķos ierakstos iebilst pret JV atgriešanos koalīcijā un piedāvā trīs partiju modeli bez JV un PRO līdz oktobra vēlēšanām.
- **Pretgaisa aizsardzība divos lasījumos:** NBS komandieris Pudāns atzīst, ka nopietni ieguldījumi sākušies vien pēdējos gados un pārklājums nav vienāds, kamēr Sprūds (PRO) aizstāv vairāk nekā 1 mljrd. eiro investīcijas kopš 2023. gada kā savu portfeļa veikumu.
- **NA un ZZS jaunie ministri:** Vitenbergs (NA) iezīmē klimata mērķu pārskatīšanu par labu enerģētiskajai drošībai, bet Indriksone (NA) noraida masveida imigrāciju kā darbaspēka risinājumu.

