INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (1, 15, 16, 'Aizsardzība un drošība', 'Braže saka ''kara draudu nav'' bet Sprūds tērē miljardus aizsardzībai — koalīcijas ministri sūta pretrunīgus signālus par drošības situāciju', 'spriedze', 'https://nra.lv/politika/517412-baiba-braze-kara-draudu-nav-cinas-par-cilveku-pratiem.htm', '2026-03-28 08:48:30', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (2, 6, 16, 'Aizsardzība un drošība', 'Dombrava pieprasa Sprūda demisiju par neadekvātu reakciju uz dronu incidentu — opozīcijas tiešs uzbrukums aizsardzības ministram', 'uzbrukums', 'https://x.com/janisdombrava/status/2037498980364370385', '2026-03-28 08:48:30', NULL);
