INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (11, 57, 15, 'Aizsardzība un drošība', 'Lapsa nosauc Bražes mobilizētos atbalstītājus par politiskām mūmijām un izsaka aizdomu par robežbūves sabotēšanas tiesvedību', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2040415925111804214', '2026-04-04 14:19:24', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (12, 51, 15, 'Aizsardzība un drošība', 'Pūpols apsūdz Braži un Rinkēviču par propagandas mašīnas izmantošanu lai apklusinātu Stoltenberga grāmatas atklājumus', 'uzbrukums', 'https://x.com/AnsisPupols/status/2040169195371950587', '2026-04-04 14:19:24', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (14, 61, 15, 'Aizsardzība un drošība', 'Liepnieks apstrīd Bražes dezinformācijas apzīmējumu, argumentējot ka Stoltenberga buferzonu apspriešana ir fakts nevis dezinformācija', 'uzbrukums', 'https://x.com/JurgisLiepnieks/status/2040364728644460880', '2026-04-04 14:19:24', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (19, 10, 2, 'Degviela un enerģētika', 'Kulbergs publiski prasa Siliņai atbildēt — kur ir Krīzes Vadības Centra sēde degvielas piegādes krīzes laikā? Pārmet valdībai bezdarbību svētku laikā.', 'uzbrukums', 'https://x.com/AndrisKulbergs/status/2041151592842309737', '2026-04-07 10:12:24', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (20, 10, 1, 'Degviela un enerģētika', 'Kulbergs prasa Rinkēvičam — kur ir aicinājums valdību rīkoties? Pārmet prezidentam izlikšanos ka ārpasaules notikumi Latviju neietekmē.', 'uzbrukums', 'https://x.com/AndrisKulbergs/status/2041151592842309737', '2026-04-07 10:12:24', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (21, 10, 25, 'Degviela un enerģētika', 'Kulbergs izsmiež Valaini par virspeļņas nodokļa ideju — salīdzina ar PSRS plānošanas ministru, apšauba virspeļņas esamību degvielas tirdzniecībā', 'uzbrukums', 'https://x.com/AndrisKulbergs/status/2041750384503599526', '2026-04-08 06:22:42', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (24, 64, 15, 'Aizsardzība un drošība', 'Vītols kritizē Bražes ''histēriju'' kas rezultējās aviācijas pacelšanā gaisā — norāda uz pārmērīgu reakciju', 'uzbrukums', 'https://x.com/guntarsv/status/2041446062351683786', '2026-04-08 15:38:31', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (25, 10, 26, 'Transports', 'Kulbergs apsūdz Švinku par Ecolines aiziešanu no Latvijas tirgus — valdība parādā 800 000 EUR un nepilda likumu', 'spriedze', 'https://x.com/AndrisKulbergs/status/2041872902904025292', '2026-04-08 16:59:37', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (31, 29, 10, 'Valsts pārvalde', 'Hermanis (MMN) publiski norobežojas no Kulberga (AS) reformu pieejas — viņa partija grib nomainīt sistēmu pašos pamatos, nevis cīkstēties esošajā sistēmā. "MĒS MAINĀM NOTEIKUMUS."', 'spriedze', 'https://x.com/AlvisHermanis1/status/2042495874559856804', '2026-04-10 08:18:34', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (36, 10, 26, 'Transports', 'Kulbergs (AS) kritizē Satiksmes ministrijas (Švinka/Progresīvie) grozījumus, jo tie neparedz izņēmumus mobilitātes palīglīdzekļiem; pārmet arogantu komunikāciju', 'uzbrukums', 'https://x.com/kurkaspars/status/2042469512923029555', '2026-04-11 08:29:52', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (37, 57, 15, 'Koalīcija un partijas', 'Lapsa pieprasa atbildību no Bražes par nomelnošanu un formas tērpa ļaunprātīgu izmantošanu', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2043276956825715119', '2026-04-12 19:22:44', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (45, 57, 2, 'Tieslietas', 'Lapsa iesniedz ģenerālprokuroram materiālus par JV Komo braucienu — iespējama korupcija', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2043565376273838366', '2026-04-14 07:30:56', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (47, 57, 2, 'Tieslietas', 'Lapsa kritizē prokuratūru par Komo ezera iesnieguma ignorēšanu — netieši apsūdz Siliņu', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2044314435167134020', '2026-04-15 07:32:36', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (51, 61, 15, 'Arlietas', 'Liepnieks kritizē Braži par nekompetenci — ignorē ārvalstu līderu izteikumus, bet komentē tikai tvīterus.', 'uzbrukums', 'https://x.com/JurgisLiepnieks/status/2044388439877943620', '2026-04-16 06:50:13', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (53, 10, 2, 'airBaltic', 'Kulbergs Saeimas tribīnē pārmet Siliņas valdībai, ka tā prasa "aklu balsojumu" par 30 miljonu aizdevumu airBaltic bez restrukturizācijas plāna un pārliek atbildību uz Saeimu. Viņš demonstratīvi nepiedalās balsošanā kā protests, aprēķinot, ka uzņēmumam faktiski nepieciešami 300 miljoni, lai segtu 380 miljonu obligāciju slogu.', 'uzbrukums', 'https://x.com/AndrisKulbergs/status/2044862124309066032', '2026-04-17 07:48:51', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (54, 25, 26, 'airBaltic', 'Valainis (ZZS) LTV intervijā apgalvo, ka Satiksmes ministrijas pārvaldība "neved ne uz ko labu" un ministrija jānodod citiem. Kritika saistīta ar airBaltic 30 miljonu aizdevuma balsojumu, kur ZZS iebilst pret valdības pieeju.', 'uzbrukums', 'https://x.com/ViktorsValainis/status/2044853700062003305', '2026-04-17 07:49:32', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (58, 57, 161, 'Koalīcija un partijas', 'Lapsa apsūdz JV veselības ministru Hosamu Abu Meri par nodokļu maksātāju naudas izmantošanu privātam Kipras braucienam (divas papildu atpūtas dienas), komandējuma saturs — ierobežotas pieejamības informācija. Dēvē par "likumīgu zagšanu".', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2045819639851061393', '2026-04-19 19:03:43', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (60, 57, 16, 'Koalīcija un partijas', 'Lapsa apsūdz Progresīvos un Jauno Vienotību par Latvijas nogrūšanu par Eiropas nabadzīgāko nomali — kopumā kritizē koalīcijas darbību kā sistēmisku problēmu.', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2046173548578763036', '2026-04-20 13:27:01', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (61, 10, 165, 'Valsts kapitālsabiedrības', 'Kulbergs kritizē Rīgas domes (Ķirša vadības) pārvaldīto Rīgas Siltumu par "gaidu vēstules" iepirkumu no CIVITTA par 9 890 eiro — apgalvo, ka akcionārs pats nespēj formulēt savu nostāju un izkropļo OECD korporatīvās pārvaldības principu.', 'uzbrukums', 'https://x.com/AndrisKulbergs/status/2046086204697829774', '2026-04-20 13:27:01', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (63, 65, 26, 'Sociālā politika', 'Treija (NA) publiski kritizē Satiksmes ministriju (Švinka, PRO) par nespēju atrast 89 148 EUR/gadā Goda ģimeņu atlaidēm sabiedriskajā transportā', 'uzbrukums', 'https://x.com/Elina_Treija/status/2046912539913593139', '2026-04-22 15:04:19', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (64, 57, 16, 'Aizsardzība un drošība', 'Lato Lapsa apsūdz aizsardzības ministru Andri Sprūdu par Kremļa ietekmes aģenta darbību un noraida viņa skaidrojumus par otrā AM valsts sekretāra atkāpšanos kā melus.', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2047000088027824537', '2026-04-22 21:10:37', 'https://x.com/AndrisSpruds/status/2046965431945032111');
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (71, 57, 66, 'Budžets un finanses', 'Lato Lapsa kritizē finanšu ministri Andu Čakšu (Vienotība) un koalīcijas fiskālo politiku, norādot uz Latvijas valsts parāda pieaugumu par 1,4 mljrd EUR pagājušogad.', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2047226893930213805', '2026-04-23 16:38:39', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (72, 57, 16, 'Aizsardzība un drošība', 'Lato Lapsa apsūdz aizsardzības ministru Andri Sprūdu par Kremļa ietekmes aģenta darbību un noraida viņa skaidrojumus par AM valsts sekretāra atkāpšanos.', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2047000088027824537', '2026-04-23 16:38:39', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (85, 10, 178, 'Pilsētvide', 'Kulbergs kritizē Kotello/PRO ieviesto modālā filtra konceptu Grīziņkalnā — apgalvo, ka 100 sūdzību iesniedzēju dēļ apgrūtina 15 000 apkaimes iedzīvotāju, un plašāk pārmet Progresīvajiem infrastruktūras bremzēšanu (airBaltic, Rail Baltica, Satiksmes ministrija). Atbilde uz Kotello 2026-04-25 koncepta aizstāvību ("Kas ir modālais filtrs? Modālais filtrs ir efektīvs risinājums").', 'uzbrukums', 'https://x.com/AndrisKulbergs/status/2048084235815182419', '2026-04-26 12:12:17', 'https://x.com/MartaKotello/status/2047923878341599354');
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (86, 126, 26, 'airBaltic', 'Rokpelnis (ZZS frakcijas vadītājs) pieprasa, lai satiksmes ministrs Atis Švinka uzņemas pilnu personīgo atbildību par airBaltic finansēšanas risinājumu; ja ministra solījumi netiks izpildīti, Švinkam jāatkāpjas no amata. Vienlaikus ZZS apliecina, ka neredz šķēršļus turpināt darbu koalīcijā.', 'uzbrukums', 'https://jauns.lv/raksts/zinas/705123-juris-puce-ir-jareorganize-si-koalicija-un-valdiba', '2026-04-29 06:53:00', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (95, 189, 16, 'Degviela un enerģētika', 'Pūce (Latvijas attīstībai) kritizē Progresīvos (Sprūda partiju) par bezdarbību Latvijas atkarības no dabasgāzes mazināšanā.', 'uzbrukums', 'https://x.com/pucej/status/2046830035454071211', '2026-04-30 09:06:40', NULL);
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (96, 65, 10, 'Valsts pārvalde', 'Treija (NA) reaģējot uz Kulberga nominēšanu premjera amatā 16.05 aicina nekavējoši rotēt visu ministriju galvenās amatpersonas — tieša pretsignāls Kulberga publiski paustajam "strādātāju" kritērijam, ka jaunajā valdībā varētu turpināt strādāt esošie ministri, kuri ir gatavi strādāt vasarā.', 'spriedze', 'https://x.com/Elina_Treija/status/2055690541904392305', '2026-05-17 19:06:01', 'https://www.delfi.lv/193/politics/120118669/bus-jastrada-vasara-kulbergs-jaunaja-valdiba-redz-kadu-no-esosajiem-ministriem');
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (98, 30, 10, 'Koalīcija un partijas', 'Baško (MMN) X-pavedienā iezīmē ideoloģisku noraidījumu Kulberga "strādātāju kabineta" tehnokrātiskajam vēstījumam, argumentējot, ka politiskās partijas uzdevums nav piedāvāt "labākos" risinājumus visām problēmām, bet gan piedāvāt paredzamai ideoloģijai atbilstošus risinājumus — netiešs MMN apliecinājums, ka tehnokrātiska valdība bez ideoloģiska pamata partijas neatbalstīs.', 'spriedze', 'https://x.com/JazepsBasko/status/2055977457447018511', '2026-05-17 19:06:01', 'https://www.delfi.lv/193/politics/120118669/bus-jastrada-vasara-kulbergs-jaunaja-valdiba-redz-kadu-no-esosajiem-ministriem');
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (100, 57, 2, 'Sabiedriskie mediji', 'Lapsa sarkastiski izsmej Siliņu ("stulbo ķēkšu") un sabiedriskos medijus ("propagandonus") par gramatikas kļūdu falsifikāciju un Siliņas izteikuma sagrozīšanu — kritizē LTV/LSM redakcionālo kvalitāti uz cilvēka pamata.', 'uzbrukums', 'https://x.com/Lato_Lapsa/status/2059623011087429830', '2026-05-27 19:00:24', 'https://jauns.lv/raksts/zinas/711261-koalicijas-sairsana-sakas-ar-meginajumu-denonset-stambulas-konvenciju-atklaj-silina');
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (101, 51, 6, 'Imigrācija', 'Pūpols publiski endorsē Dombravu kā Kulberga valdības iekšlietu ministra kandidātu un kā galveno NA imigrācijas politikas virzītāju — apraksta Dombravas uzstājīgumu kā piemēru.', 'atbalsts', 'https://x.com/AnsisPupols/status/2059516741798027368', '2026-05-27 19:00:25', 'https://x.com/janisdombrava/status/2059581224868344087');
INSERT INTO political_tensions (id, source_pid, target_pid, topic, description, tension_type, source_url, created_at, target_url) VALUES (102, 85, 10, 'Koalīcija un partijas', 'Daugavietis (JV) balsoja pret Kulberga valdības apstiprināšanu, norādot, ka sirdsapziņa neļāva atbalstīt veidu, kā jaunā valdība tika veidota. Vienīgais JV frakcijas deputāts, kurš balsoja "pret".', 'spriedze', 'https://x.com/DDaugavietis45/status/2060008874711588951', '2026-05-29 15:41:08', NULL);
