INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (1, '1288/Lp14', 'Lp14', 'Grozījums Saeimas vēlēšanu likumā', 'Nosaka, ka 2026. gada Saeimas vēlēšanās balsu skaitīšana notiek manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un to iespējamo ietekmi uz vēlēšanu procesu.', 'Vēlēšanas', 'saeimas-velesanu-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:38', '2026-05-27 00:34:01', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (3, '1233/Lp14', 'Lp14', 'Grozījumi Civilprocesa likumā', 'Ievieš jaunu Civilprocesa likuma nodaļu par kopīpašuma dalīšanas lietām tiesā, nosakot prasības pieteikuma saturu, piekritību un kārtību, kā arī paredz tiesas deponēto līdzekļu izmantošanu zemesgrāmatas un Valsts zemes dienesta izdevumu segšanai.', 'Valsts pārvalde', 'civilprocesa-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 10:29:38', '2026-05-27 00:34:02', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (4, '1269/Lp14', 'Lp14', 'Grozījumi Vides aizsardzības likumā', 'Grozījumi Vides aizsardzības likumā (2. lasījums, steidzams); pielāgo Latvijas regulējumu ES prasībām par vides aizsardzību, pilnveidojot pārraudzības mehānismus, vienbalsīgi pieņemts par likumu.', 'Vide', 'vides-aizsardzibas-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:38', '2026-05-27 00:34:02', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (7, '1153/Lp14', 'Lp14', 'Grozījumi Dzīvokļa īpašuma likumā', 'Grozījumu Dzīvokļa īpašuma likumā 3. lasījums — vienprātīgi pieņemts (77/0/0). Maksātnespējas kontroles dienesta likvidēšanas pakešakta daļa.', 'Valsts pārvalde', 'dzivokla-ipasuma-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:38', '2026-05-27 00:34:02', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (12, '1278/Lp14', 'Lp14', 'Grozījumi Izglītības likumā', 'Paredz pedagogiem iespēju brīvprātīgi doties pensijā no 60 gadu vecuma ar 35 gadu darba stāžu; iesniegts pēc aptuveni 12 000 parakstu petīcijas. Saeima noraidīja likumprojekta nodošanu komisijām.', 'Izglītība', 'izglitibas-likums', NULL, 'nezināms', 'noraidīts', '2026-04-27 10:29:38', '2026-05-27 00:34:02', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (15, '1136/Lp14', 'Lp14', 'Grozījums Imigrācijas likumā', 'Paredz iespēju anulēt termiņuzturēšanās atļauju ārzemniekam, kurš viena kalendāra gada laikā izdarījis trīs administratīvos pārkāpumus sabiedriskās kārtības, pārvaldes vai ceļu satiksmes jomā.', 'Imigrācija', 'imigracijas-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:38', '2026-05-27 00:34:02', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (19, '1273/Lp14', 'Lp14', 'Grozījumi Ķīmisko vielu likumā', 'Grozījumi Ķīmisko vielu likumā (2. lasījums, steidzams); harmonizē ķīmisko vielu aprites kontroli ar ES regulējumu; pieņemts par likumu.', 'Vide', 'kimisko-vielu-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:38', '2026-05-27 00:34:02', '2026-04-27 07:29:38');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (23, '1242/Lp14', 'Lp14', 'Grozījums Valsts aizsardzības finansēšanas likumā', 'Paaugstina valsts aizsardzības finansējuma mērķi no 3% līdz 5% no IKP, sākot ar 2027. gadu, lai paātrinātu Nacionālo bruņoto spēku attīstību saistībā ar ģeopolitiskajām izmaiņām pēc Krievijas iebrukuma Ukrainā.', 'Aizsardzība un drošība', 'valsts-aizsardzibas-finansesanas-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (25, '1165/Lp14', 'Lp14', 'Grozījumi Kredītiestāžu likumā', 'Transponē ES Direktīvu 2024/1619, nosakot kredītiestādēm papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, uzlabojot administratīvo pasākumu piemērošanas mehānismus un nodrošinot efektīvāku uzraudzību.', 'Valsts pārvalde', 'kreditiestazu-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (26, '1163/Lp14', 'Lp14', 'Grozījumi Ieguldījumu brokeru sabiedrību likumā', 'Transponē ES Direktīvu 2024/1619 un Direktīvu 2019/2034, nosakot ieguldījumu brokeru sabiedrībām papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, kā arī kapitāla un likviditātes pietiekamības novērtēšanu.', 'Valsts pārvalde', 'ieguldijumu-brokeru-sabiedribu-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (27, '1277/Lp14', 'Lp14', 'Grozījumi Sugu un biotopu aizsardzības likumā', 'Grozījumi Sugu un biotopu aizsardzības likumā (2. lasījums, steidzams); pilnveido aizsargājamo sugu un dabisko biotopu saraksta veidošanu un ierobežojumu kārtību; pieņemts par likumu.', 'Vide', 'sugu-un-biotopu-aizsardzibas-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (28, '1097/Lp14', 'Lp14', 'Grozījumi Sociālā uzņēmuma likumā', 'Pilnveido sociālo uzņēmumu regulējumu — pagarina pārskatu iesniegšanas periodu no 2 līdz 3 gadiem, paplašina dividenžu sadales iespējas līdz 50% no peļņas, precizē uzraudzības un ziedojumu nodokļu normas.', 'Sociālā politika', 'sociala-uznemuma-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (29, '1283/Lp14', 'Lp14', 'Grozījumi Ceļu satiksmes likumā', 'Deputātu (Rokpelnis, Brigmanis, Bērziņš, Burovs, Ceļapīters) ierosinātie grozījumi Ceļu satiksmes likumā, nodoti Tautsaimniecības un Aizsardzības komisijām izskatīšanai.', 'Transports', 'celu-satiksmes-likums', NULL, 'nezināms', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (31, '1180/Lp14', 'Lp14', 'Grozījumi Imigrācijas likumā', 'Pārņem ES direktīvu 2024/1233 par vienotu uzturēšanās un darba atļauju trešo valstu valstspiederīgajiem un precizē Imigrācijas likuma normas par vīzu izsniegšanu, dokumentu pieņemšanu (atļaujot deleģēt ārpakalpojumu sniedzējiem) un termiņuzturēšanās atļauju anulēšanu. Iesniedzējs - Ministru kabinets (IeM).', 'Imigrācija', 'imigracijas-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (32, '1072/Lp14', 'Lp14', 'Grozījumi Gaisa kuģu pasažieru datu apstrādes likumā', 'Ievieš uz riska novērtējumu balstītu pieeju gaisa kuģu pasažieru datu glabāšanai -- valsts drošības nolūkiem datus glabā 5 gadus, bet terorisma/smagu noziegumu novēršanai ES iekšējiem un ārējiem reisiem -- 6 mēnešus ar iespēju pagarināt. Izslēdz epidemioloģisko datu apstrādes mērķi un paplašina reģistru salīdzināšanas loku (izraidīto personu, izceļošanas liegumu reģistri).', 'Valsts pārvalde', 'gaisa-kugu-pasazieru-datu-apstrades-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (33, '1154/Lp14', 'Lp14', 'Grozījumi Zinātniskās darbības likumā', 'Nosaka kartību jaunizveidotu valsts zinātnisko institūtu (atvasinātu publisku personu) pārvaldībai pēc reorganizācijas -- direktora pienākumu izpildītāja iecelšanu, pilnsapulces sasaukšanu un reģistrāciju. Izslēdz no likuma FEI, BMC un OSI nosaukumus saistībā ar to konsolidāciju EDI un jaunā Nacionālā pētniecības un inovāciju institūta izveidošanu.', 'Valsts pārvalde', 'zinatniskas-darbibas-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (34, '1164/Lp14', 'Lp14', 'Grozījumi Latvijas Bankas likumā', 'Paplašina Latvijas Bankas padomes locekļu kvalifikācijas prasības (pieļauj arī bakalaura grādu ar starptautisku sertifikātu), ievieš interešu konflikta novēršanas pilnvaras, precizē statistisko datu apstrādes tiesības un administratīvo sankciju piemērošanas termiņus finanšu tirgus uzraudzībā.', 'Budžets un finanses', 'latvijas-bankas-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (35, '1248/Lp14', 'Lp14', 'Grozījums Lauksaimniecības un lauku attīstības likumā', 'Pagarina Krievijas un Baltkrievijas lauksaimniecības un lopbarības produktu importa aizliegumu par vienu gadu — no 2026. gada 1. jūlija līdz 2027. gada 1. jūlijam.', 'Lauksaimniecība', 'lauksaimniecibas-un-lauku-attistibas-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:02', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (36, '1279/Lp14', 'Lp14', 'Grozījumi Saeimas vēlēšanu likumā', 'Paredz pagarināt vēlēšanu zīmju uzglabāšanas termiņu līdz tiesas nolēmuma spēkā stāšanās dienai un noteikt manuālu balsu skaitīšanu visos 2026. gada Saeimas vēlēšanu iecirkņos bez tehnisku palīglīdzekļu starpniecības.', 'Vēlēšanas', 'saeimas-velesanu-likums', NULL, 'nezināms', 'noraidīts', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (37, '1185/Lp14', 'Lp14', 'Grozījumi Farmācijas likumā', 'Farmācijas likuma 3. lasījums — pieņemts vienprātīgi (82/0/0). Pakešakts virzīts kopā ar Maksātnespējas kontroles dienesta likvidēšanu un saistīto institucionālo pārstrukturēšanu.', 'Veselības aprūpe', 'farmacijas-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (39, '1275/Lp14', 'Lp14', 'Grozījumi Ūdens apsaimniekošanas likumā', 'Grozījumi Ūdens apsaimniekošanas likumā (2. lasījums, steidzams); uzlabo ūdensobjektu kvalitātes pārraudzību un upju baseinu apsaimniekošanas plānošanu; pieņemts par likumu.', 'Vide', 'udens-apsaimniekosanas-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (40, '1289/Lp14', 'Lp14', 'Grozījumi Saeimas vēlēšanu likumā', 'Grozīt vēlēšanu zīmju uzglabāšanas termiņu un nodrošināt pēcvēlēšanu audita iespēju. LPV deputātu iniciatīva.', 'Vēlēšanas', 'saeimas-velesanu-likums', NULL, 'nezināms', 'noraidīts', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (45, '1257/Lp14', 'Lp14', 'Grozījums Bērnu tiesību aizsardzības likumā', 'Aizliedz pilngadīgām personām, kuras atrodas uzraudzības, aprūpes, izglītošanas vai citas profesionālas autoritātes pozīcijā attiecībā pret bērnu, veidot ar šo bērnu intīmas vai seksuāla rakstura attiecības — mērķis ir aizsargāt 16–17 gadus vecus jauniešus no varas pozīcijas izmantošanas.', 'Sociālā politika', 'bernu-tiesibu-aizsardzibas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (46, '1301/Lp14', 'Lp14', 'Grozījumi Būvniecības likumā', 'Ievieš būvniecības ieceres realizāciju pa posmiem (var sākt pamatu būvdarbus, kamēr turpinās augšējo stāvu projektēšana), atceļ novecojušo būvkomersantu klasifikācijas sistēmu un vienkāršo militāro objektu būvniecību — ļauj atkāpties no civilajiem būvnormatīviem bez saskaņošanas, lai paātrinātu modulāro būvju izvietošanu.', 'Pašvaldības', 'buvniecibas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (51, '1027/Lp14', 'Lp14', 'Grozījumi Konsulārās palīdzības un konsulāro pakalpojumu likumā', 'Konsulārās palīdzības un konsulāro pakalpojumu likuma grozījumu galīgā pieņemšana.', 'Ārpolitika', 'konsularas-palidzibas-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:39', '2026-05-27 00:34:03', '2026-04-27 07:29:39');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (53, '1270/Lp14', 'Lp14', 'Grozījumi Atkritumu apsaimniekošanas likumā', 'Ievieš obligātu elektronisko smēķēšanas ierīču (e-cigarešu) depozīta sistēmu ar atpakaļpieņemšanu un depozīta maksu, pārņem ES Direktīvas 2024/884 prasības par elektroiekārtu atkritumiem un ES Bateriju regulas 2023/1542 normas, kā arī aktualizē institucionālo regulējumu pēc Enerģētikas un vides aģentūras pievienošanas Valsts vides dienestam.', 'Vide', 'atkritumu-apsaimniekosanas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 10:29:40', '2026-05-27 00:34:03', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (55, '1291/Lp14', 'Lp14', 'Grozījums Meža likumā', 'ZZS deputātu (Augulis, Maslovskis, Zemmers, Ceļapīters, Burovs) iniciatīva grozīt Meža likumu - paredzēta nodošanai Tautsaimniecības, agrārās, vides un reģionālās politikas komisijai. Saeima noraidīja jau nodošanas stadijā (par=34, pret=40, atturas=2) - koalīcija (JV/NA/PRO) iebilda pret opozīcijas piedāvāto meža apsaimniekošanas regulējuma izmaiņu virzību.', 'Mežsaimniecība', 'meza-likums', NULL, 'nezināms', 'noraidīts', '2026-04-27 10:29:40', '2026-05-27 00:34:03', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (57, '1033/Lp14', 'Lp14', 'Grozījumi Fizisko personu reģistra likumā', 'Papildina Fizisko personu reģistru ar ziņām par personu apbedīšanu, kremāciju, pārapbedīšanu un urnas pārvietošanu; nosaka kapsētu īpašniekiem un kremācijas pakalpojumu sniedzējiem pienākumu aktualizēt šīs ziņas reģistrā (saistīts ar jauno Kapsētu likumu).', 'Tieslietas', 'fizisko-personu-registra-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:40', '2026-05-27 00:34:03', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (58, '56/Lp14', 'Lp14', 'Par priekšlikumu iesniegšanas termiņa pagarināšanu likumprojekta “Imigrācijas likums”', 'Termiņa pagarināšana priekšlikumu iesniegšanai Imigrācijas likuma grozījumiem.', 'Imigrācija', 'imigracijas-likums', NULL, 'procesuāls', 'procesā', '2026-04-27 10:29:40', '2026-05-27 00:34:03', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (59, '1292/Lp14', 'Lp14', 'Grozījumi Saeimas vēlēšanu likumā', 'LPV deputātu iniciatīva aizliegt kandidēt Saeimas vēlēšanās personām ar dubultpilsonību (Latvija un cita valsts), nosakot pārejas periodu līdz 2026. gada 1. oktobrim; koalīcija noraidīja nodošanu komisijām.', 'Vēlēšanas', 'saeimas-velesanu-likums', NULL, 'nezināms', 'noraidīts', '2026-04-27 10:29:40', '2026-05-27 00:34:03', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (67, '1300/Lp14', 'Lp14', 'Grozījumi Latvijas Bankas likumā', 'LPV iniciatīva aizliegt Latvijas Bankas prezidentam, viņa vietniekiem un padomes locekļiem dubultpilsonību; noraidīta kā paketes daļa.', 'Budžets un finanses', 'latvijas-bankas-likums', NULL, 'nezināms', 'noraidīts', '2026-04-27 10:29:40', '2026-05-27 00:34:03', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (74, '1187/Lp14', 'Lp14', 'Grozījumi Civilprocesa likumā', 'Grozījumi Civilprocesa likumā (3. lasījums); tehniski procesuālie precizējumi bez priekšlikumiem; pieņemts par likumu (82 par, 1 atturas).', 'Valsts pārvalde', 'civilprocesa-likums', NULL, '3.lasījums', 'pieņemts', '2026-04-27 10:29:40', '2026-05-27 00:34:04', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (81, '1198/Lp14', 'Lp14', 'Grozījumi Civilprocesa likumā', 'Grozījumi Civilprocesa likumā (2. lasījums); 18 priekšlikumi — ievieš izmaiņas civilprocesa procedūrās, tostarp apelācijas un kasācijas jomā; pieņemts ar 86 par.', 'Valsts pārvalde', 'civilprocesa-likums', NULL, '2.lasījums', 'procesā', '2026-04-27 10:29:40', '2026-05-27 00:34:04', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (85, '1303/Lp14', 'Lp14', 'Grozījumi Izglītības likumā', 'Grozījumi Izglītības likumā (1. lasījums, steidzams); paketes daļa ar Augstskolu un Profesionālās izglītības grozījumiem — saskaņo izglītības likumdošanas sistēmu; pieņemts ar 77 par.', 'Izglītība', 'izglitibas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 10:29:40', '2026-05-27 00:34:04', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (87, '1304/Lp14', 'Lp14', 'Grozījumi Profesionālās izglītības likumā', 'Grozījumi Profesionālās izglītības likumā (1. lasījums, steidzams); izglītības reformu paketes daļa, kas modernizē profesionālās izglītības regulējumu; pieņemts ar 81 par.', 'Izglītība', 'izglitibas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 10:29:40', '2026-05-27 00:34:04', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (88, '1286/Lp14', 'Lp14', 'Par priekšlikumu Nr.1', 'Priekšlikums Nr.1 Grozījumiem Ceļu satiksmes likumā (1286/Lp14) — deputātu A.Butāna un J.Vitenberga (NA) ierosinājums: transportlīdzekļu vadītāju apmācība un eksāmeni notiek valsts valodā; CSDD drīkst piedāvāt arī ES vai EEZ dalībvalstu oficiālajās valodās. Praktiski izslēgtu krievu valodu (kas nav ES/EEZ valoda). Komisija (vad. K.Briškens, PRO) neatbalstīja; Saeima noraidīja (par 23, pret 22, atturas 37). Valodas politikas grozījums, iekļauts militārās tehnikas grozījumu likumprojektā.', 'Valodu politika', 'celu-satiksmes-likums', NULL, '2.lasījums priekšlikums', 'noraidīts', '2026-04-27 10:29:40', '2026-05-27 00:34:04', '2026-04-27 07:29:40');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (94, '949/Lm14', 'Lm14', 'Par Latgales apgabaltiesas tiesneses Ludmilas Mežales atbrīvošanu no tiesneša amata', 'Atbrīvo Latgales apgabaltiesas tiesnesi Ludmilu Mežali no tiesneša amata (saskaņā ar likumā paredzēto kārtību - parasti pēc paša lūguma vai sasniedzot pensijas vecumu).', 'Mežsaimniecība', 'meza-likums', NULL, 'tiesneša_amats', 'procesā', '2026-04-27 12:02:24', '2026-05-27 00:34:04', '2026-04-27 09:02:24');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (97, '1263/Lp14', 'Lp14', 'Grozījumi Kredītiestāžu likumā', 'Maksātnespējas kontroles dienesta likvidēšanas pakešakts: aizvieto Kredītiestāžu likumā atsauces uz Maksātnespējas kontroles dienestu ar Tieslietu ministriju (administratoru uzraudzības kontekstā) vai Tiesu administrāciju (darbinieku prasījumu garantiju fonda kontekstā). Iesniedzējs - Ministru kabinets (TM); spēkā stāsies 2026. gada 1. oktobrī.', 'Valsts pārvalde', 'kreditiestazu-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 12:02:24', '2026-05-27 00:34:04', '2026-04-27 09:02:24');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (100, '970/Lm14', 'Lm14', 'Par Saeimas deputātes Svetlanas Čulkovas atsaukšanu no Parlamentārās izmeklēšanas komisijas par problēmām nacionālā un Eiropas Savienības līmeņa imigrācijas regulējumā un izpildinstitūciju darbā, kas izraisa trešo valstu pilsoņu ...', 'Atsauc Saeimas deputāti Svetlanu Čulkovu (Stabilitātei) no Parlamentārās izmeklēšanas komisijas par problēmām imigrācijas regulējumā un izpildinstitūciju darbā.', 'Imigrācija', 'imigracijas-likums', NULL, 'procesuāls', 'procesā', '2026-04-27 12:02:24', '2026-05-27 00:34:05', '2026-04-27 09:02:24');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (105, '1310/Lp14', 'Lp14', 'Grozījumi Zinātniskās darbības likumā', 'Ievieš pētniecības karjeras ietvaru (četri posmi: zinātniskais asistents, pētnieks, vadošais pētnieks, pētniecības profesors) un pētniecības tenūras modeli ar trim pakāpēm zinātniskajos institūtos. Veido jaunu amatu kategoriju ''pētnieks ar praktisko kompetenci'' (5+ gadu nozares pieredze bez doktora grāda) un saskaņo terminoloģiju ar Augstskolu likumu. Daļa no MK akadēmiskās karjeras reformas paketes (1309/1310/1311); iesniedzējs - IZM.', 'Valsts pārvalde', 'zinatniskas-darbibas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 12:02:24', '2026-05-27 00:34:05', '2026-04-27 09:02:24');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (106, '1311/Lp14', 'Lp14', 'Grozījumi Profesionālās izglītības likumā', 'Daļa no MK akadēmiskās karjeras reformas paketes - saskaņo Profesionālās izglītības likuma normas par koledžu akadēmisko personālu ar Augstskolu likuma jauno regulējumu, aizstājot atsauces uz ''ievēlēšanu'' ar ''darbā pieņemšanu'' un nosakot, ka koledžu akadēmiskā personāla atlasi un novērtēšanu regulē Augstskolu likums. Iesniedzējs - IZM; spēkā 2026. gada 1. decembrī.', 'Izglītība', 'izglitibas-likums', NULL, '1.lasījums', 'procesā', '2026-04-27 12:02:24', '2026-05-27 00:34:05', '2026-04-27 09:02:24');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (119, '1317/Lp14', 'Lp14', 'Grozījumi Izglītības likumā', 'Izglītības, kultūras un zinātnes komisijas izstrādātais grozījums Izglītības likumā 1. lasījumā vienprātīgi pieņemts (86/0/0). Stiprina pedagogu profesionālo autonomiju (tiesības patstāvīgi izvēlēties mācību metodes), precizē vecāku tiesības caur izglītības iestādes padomi un ievieš kārtību domstarpību risināšanai starp pedagogu un ģimeni.', 'Izglītība', 'izglitibas-likums', 'Ministru kabinets', '1.lasījums', 'procesā', '2026-04-27 22:05:18', '2026-05-27 00:34:06', '2026-04-27 19:05:18');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (124, '1322/Lp14', 'Lp14', 'Grozījumi Valsts fondēto pensiju likumā', 'NA deputātu (Mitrevics, Grasbergs, Puntulis, Vitenbergs, Butāns, Indriksone) iniciēts grozījums Valsts fondēto pensiju likumā nodots komisijām (par=47, pret=8, atturas=32). Liels atturas-vairākums (32) signalizē par koalīcijas iekšējām domstarpībām par 2. pensiju līmeņa virzību.', 'Sociālā politika', NULL, NULL, 'iesniegts', 'procesā', '2026-04-27 22:05:48', '2026-05-27 00:34:05', '2026-04-27 19:05:48');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (142, '121/P14', 'P14', 'Par ministrijas publiskajiem iepirkumiem informācijas tehnoloģiju jomā', 'LPV iesniegtais paziņojuma projekts par valdības ministriju IT iepirkumiem (caurspīdīgums un izmaksu pārbaudes). Saeima noraidīja (par=41, pret=48) — koalīcija nepieņēma opozīcijas formulējumu par ministrijas atbildību.', 'Valsts pārvalde', 'izglitibas-likums', NULL, 'paziņojuma_balsojums', 'noraidīts', '2026-04-27 22:05:48', '2026-05-27 00:34:05', '2026-04-27 19:05:48');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (150, '1105/Lp14', 'Lp14', 'Grozījumi Publiskas personas kapitāla daļu un kapitālsabiedrību pārvaldības likumā', 'Grozījumu Publiskas personas kapitāla daļu un kapitālsabiedrību pārvaldības likumā 2. lasījums — pieņemts (83/1/1). Apjomīgs likumprojekts par valsts un pašvaldību kapitālsabiedrību pārvaldību.', 'Valsts pārvalde', NULL, NULL, '2.lasījums', 'procesā', '2026-04-27 22:05:48', '2026-05-27 00:34:06', '2026-04-27 19:05:48');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (151, '954/Lm14', 'Lm14', 'Par atbalstu 1. tipa diabēta pacientiem', 'Vienprātīgs Saeimas paziņojums (88/0/0) par atbalstu 1. tipa diabēta pacientiem — uzdod valdībai uzlabot kompensējamo medikamentu un medicīnisko līdzekļu pieejamību.', 'Valsts pārvalde', NULL, NULL, 'Lm14 cits', 'procesā', '2026-04-27 22:05:48', '2026-05-27 00:34:05', '2026-04-27 19:05:48');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (156, '1334/Lp14', 'Lp14', 'Grozījumi Sabiedrisko elektronisko plašsaziņas līdzekļu un to pārvaldības likumā', 'Grozījumi Sabiedrisko elektronisko plašsaziņas līdzekļu likumā nodoti komisijām (par=69, pret=4). Iesniedzējs — Ministru kabinets.', 'Degviela un enerģētika', NULL, NULL, 'iesniegts', 'procesā', '2026-04-30 21:38:52', '2026-05-27 00:34:05', '2026-04-30 18:38:52');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (167, '132/P14', 'P14', 'Ministru prezidentei Evikai Siliņai \"Par publiskajiem iepirkumiem ministrijās informācijas tehnoloģiju jomā\"', NULL, NULL, NULL, NULL, NULL, 'procesā', '2026-05-15 13:09:42', '2026-05-15 13:09:42', '2026-05-15 10:09:42');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (170, '130/P14', 'P14', 'Par Ministru kabineta rīkojuma projektu Par valsts nekustamā īpašuma Alksnāja ielā 9, Rīgā, pārdošanu', 'NA frakcijas (J.Vitenbergs, A.Butāns, U.Mitrevics u.c., 10 deputāti) pieprasījums izglītības un zinātnes ministrei D.Melbārdei (NA — savas frakcijas ministrei) par MK rīkojuma projektu Nr. 26-TA-109 — IZM plāno pārdot Latvijas Sporta muzeja ēku Vecrīgā, Alksnāja ielā 9, lai segtu IZM budžeta iztrūkumu, paredzot muzeja pārcelšanu uz komandu sporta spēļu zāli un saglabājot esošās telpas vēl 3 gadus. NA iebilst pret neapspriesto lēmumu un ēkas pārdošanas vajadzību. Saeima pieprasījumu noraidīja (30/41/1).', 'Valsts pārvalde', 'izglitibas-likums', NULL, 'paziņojuma_balsojums', 'noraidīts', '2026-05-15 13:09:42', '2026-05-27 00:34:06', '2026-05-15 10:09:42');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (181, '1358/Lp14', 'Lp14', 'Grozījums Saeimas vēlēšanu likumā', 'LPV frakcijas (Krištopans, Armaņeva, Šlesers, Liepiņa, Stobova) ierosinātais Saeimas vēlēšanu likuma grozījums noraidīts nodošanā komisijām (28:19, 30 atturas) — koalīcija bloķē vēlēšanu sistēmas izmaiņu iniciatīvu.', 'Vēlēšanas', 'saeimas-velesanu-likums', NULL, 'iesniegts', 'noraidīts', '2026-05-26 08:43:32', '2026-05-27 00:34:07', '2026-05-26 05:43:32');
INSERT INTO saeima_bills (id, document_nr, bill_type, title, summary, topic, base_law_slug, institutional_submitter, current_stage, current_status, first_seen_at, last_updated_at, created_at) VALUES (200, '970/Lp14', 'Lp14', 'Grozījumi Lauksaimniecības un lauku attīstības likumā', 'Kopsavilkums nav pieejams — historic backfill 2026-05-26', 'Lauksaimniecība', 'lauksaimniecibas-un-lauku-attistibas-likums', NULL, '3.lasījums', 'pieņemts', '2026-05-26 23:58:39', '2026-05-27 00:34:01', '2026-05-26 20:58:39');
