INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (1, NULL, 'Grozījumi Saeimas vēlēšanu likumā (1289/Lp14), nodošana komisijām', '2026-04-01', '11:16:47', 42, 47, 3, 1, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/093A10D81207553EC2258DCD000AFB27?OpenDocument', '2026-04-03 12:57:33', 'Grozīt vēlēšanu zīmju uzglabāšanas termiņu un nodrošināt pēcvēlēšanu audita iespēju. LPV deputātu iniciatīva.', '1289/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1289/Lp14', 'Vēlēšanas', 40);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (6, NULL, 'Grozījums Bērnu tiesību aizsardzības likumā (1257/Lp14), 1.lasījums', '2026-04-01', '16:49:07', 74, 0, 0, 3, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/4C9D2B288F4F6C40C2258DCD000AFBA7?OpenDocument', '2026-04-03 13:06:48', 'Aizliedz pilngadīgām personām, kuras atrodas uzraudzības, aprūpes, izglītošanas vai citas profesionālas autoritātes pozīcijā attiecībā pret bērnu, veidot ar šo bērnu intīmas vai seksuāla rakstura attiecības — mērķis ir aizsargāt 16–17 gadus vecus jauniešus no varas pozīcijas izmantošanas.', '1257/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1257/Lp14', 'Sociālā politika', 45);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (8, NULL, 'Grozījumi Būvniecības likumā (1301/Lp14), 1.lasījums', '2026-04-01', '17:00:50', 69, 0, 1, 8, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/CDEF9B23E7A6FC13C2258DCD000AFBAB?OpenDocument', '2026-04-03 13:07:57', 'Ievieš būvniecības ieceres realizāciju pa posmiem (var sākt pamatu būvdarbus, kamēr turpinās augšējo stāvu projektēšana), atceļ novecojušo būvkomersantu klasifikācijas sistēmu un vienkāršo militāro objektu būvniecību — ļauj atkāpties no civilajiem būvnormatīviem bez saskaņošanas, lai paātrinātu modulāro būvju izvietošanu.', '1301/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1301/Lp14', 'Pašvaldības', 46);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (13, NULL, 'Grozījumi Konsulārās palīdzības un konsulāro pakalpojumu likumā (1027/Lp14), 3.lasījums', '2026-04-01', '16:32:20', 74, 0, 0, 6, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/F8FDFD7E13E2E725C2258DCD000AFB92?OpenDocument', '2026-04-03 13:09:22', 'Konsulārās palīdzības un konsulāro pakalpojumu likuma grozījumu galīgā pieņemšana.', '1027/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1027/Lp14', 'Ārpolitika', 51);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (15, NULL, 'Grozījumi Atkritumu apsaimniekošanas likumā (1270/Lp14), 1.lasījums', '2026-04-01', '16:57:25', 69, 4, 0, 3, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/FFE36A67EA578A28C2258DCD000AFBA9?OpenDocument', '2026-04-03 13:09:22', 'Ievieš obligātu elektronisko smēķēšanas ierīču (e-cigarešu) depozīta sistēmu ar atpakaļpieņemšanu un depozīta maksu, pārņem ES Direktīvas 2024/884 prasības par elektroiekārtu atkritumiem un ES Bateriju regulas 2023/1542 normas, kā arī aktualizē institucionālo regulējumu pēc Enerģētikas un vides aģentūras pievienošanas Valsts vides dienestam.', '1270/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1270/Lp14', 'Vide', 53);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (18, NULL, 'Grozījums Meža likumā (1291/Lp14), nodošana komisijām', '2026-04-01', '11:30:28', 34, 40, 2, 14, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/0C639EFC3D6E8E73C2258DCD000AFB29?OpenDocument', '2026-04-03 13:10:23', 'ZZS deputātu (Augulis, Maslovskis, Zemmers, Ceļapīters, Burovs) iniciatīva grozīt Meža likumu - paredzēta nodošanai Tautsaimniecības, agrārās, vides un reģionālās politikas komisijai. Saeima noraidīja jau nodošanas stadijā (par=34, pret=40, atturas=2) - koalīcija (JV/NA/PRO) iebilda pret opozīcijas piedāvāto meža apsaimniekošanas regulējuma izmaiņu virzību.', '1291/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1291/Lp14', 'Mežsaimniecība', 55);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (20, NULL, 'Grozījumi Fizisko personu reģistra likumā (1033/Lp14), 3.lasījums', '2026-04-01', '16:26:22', 76, 0, 0, 5, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BC932E2C6DAC0099C2258DCD000AFB8C?OpenDocument', '2026-04-03 13:10:35', 'Papildina Fizisko personu reģistru ar ziņām par personu apbedīšanu, kremāciju, pārapbedīšanu un urnas pārvietošanu; nosaka kapsētu īpašniekiem un kremācijas pakalpojumu sniedzējiem pienākumu aktualizēt šīs ziņas reģistrā (saistīts ar jauno Kapsētu likumu).', '1033/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1033/Lp14', 'Tieslietas', 57);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (21, NULL, 'Par priekšlikumu iesniegšanas termiņa pagarināšanu likumprojekta “Imigrācijas likums” (Nr.56/Lp14) trešajam lasījumam līdz 2026. gada 9. aprīlim (940/Lm14)', '2026-04-01', '17:03:39', 79, 0, 0, 1, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/14A658E6CB5352BFC2258DCD000AFBC3?OpenDocument', '2026-04-03 13:10:36', 'Termiņa pagarināšana priekšlikumu iesniegšanai Imigrācijas likuma grozījumiem.', '56/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=56/Lp14', 'Imigrācija', 58);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (22, NULL, 'Grozījums Lauksaimniecības un lauku attīstības likumā (1248/Lp14), 2.lasījums, steidzams', '2026-04-01', '15:22:20', 80, 4, 0, 8, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/311CF7FDAC30C91FC2258DCD000AFB61?OpenDocument', '2026-04-03 13:11:17', 'Pagarina Krievijas un Baltkrievijas lauksaimniecības un lopbarības produktu importa aizliegumu par vienu gadu — no 2026. gada 1. jūlija līdz 2027. gada 1. jūlijam.', '1248/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1248/Lp14', 'Lauksaimniecība', 35);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (23, NULL, 'Grozījums Saeimas vēlēšanu likumā (1288/Lp14), 1.lasījums', '2026-03-26', '09:57:55', 93, 0, 0, 0, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/23D5A329E7A92AA7C2258DC700107956?OpenDocument', '2026-04-05 16:31:29', 'Paredz 2026. gada Saeimas vēlēšanās balsu skaitīšanu veikt manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un Valsts prezidenta aicinājumu nodrošināt caurspīdīgu vēlēšanu norisi.', '1288/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1288/Lp14', 'Vēlēšanas', 1);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (25, NULL, 'Grozījumi Civilprocesa likumā (1233/Lp14), 1.lasījums', '2026-03-26', '14:19:45', 55, 12, 6, 12, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/081308D417311B5AC2258DC700107A09?OpenDocument', '2026-04-05 16:39:29', 'Ievieš jaunu Civilprocesa likuma nodaļu par kopīpašuma dalīšanas lietām tiesā, nosakot prasības pieteikuma saturu, piekritību un kārtību, kā arī paredz tiesas deponēto līdzekļu izmantošanu zemesgrāmatas un Valsts zemes dienesta izdevumu segšanai.', '1233/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1233/Lp14', 'Valsts pārvalde', 3);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (27, NULL, 'Grozījumi Vides aizsardzības likumā (1269/Lp14), 1.lasījums', '2026-03-26', '16:17:59', 84, 0, 0, 6, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/12017D2D9FB4B73FC2258DC700107A6D?OpenDocument', '2026-04-05 16:39:42', 'Aizstāj visā Vides aizsardzības likumā atsauces uz Vides aizsardzības un reģionālās attīstības ministriju ar Klimata un enerģētikas ministriju, precizē Valsts vides dienesta lēmumu apstrīdēšanas kārtību un aktualizē institucionālo struktūru atbilstoši valdības reformai.', '1269/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1269/Lp14', 'Vide', 4);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (30, NULL, 'Grozījumi Dzīvokļa īpašuma likumā (1153/Lp14), 2.lasījums', '2026-03-26', '15:41:35', 78, 0, 0, 1, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/1F6D0D5DCAFE0F94C2258DC700107A51?OpenDocument', '2026-04-05 16:39:45', 'Ievieš detalizētu regulējumu par dzīvokļu kopīpašuma dalīšanu — nosaka atsevišķās lietošanas tiesības uz koplietošanas telpām, jumtu un ārsienām, atceļ pirmpirkuma tiesības autostāvvietu kopīpašumam un paredz kopīgās infrastruktūras lietošanas noteikumus.', '1153/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1153/Lp14', 'Valsts pārvalde', 7);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (35, NULL, 'Grozījumi Izglītības likumā (1278/Lp14), nodošana komisijām', '2026-03-26', '10:07:26', 36, 14, 37, 3, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/4B354EEA3B01E136C2258DC70010796E?OpenDocument', '2026-04-05 16:39:48', 'Paredz pedagogiem iespēju brīvprātīgi doties pensijā no 60 gadu vecuma ar 35 gadu darba stāžu; iesniegts pēc aptuveni 12 000 parakstu petīcijas. Saeima noraidīja likumprojekta nodošanu komisijām.', '1278/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1278/Lp14', 'Izglītība', 12);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (38, NULL, 'Grozījums Imigrācijas likumā (1136/Lp14), 3.lasījums', '2026-03-26', '13:52:42', 78, 8, 0, 1, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/6A3D5E0BE5402D02C2258DC7001079DD?OpenDocument', '2026-04-05 16:39:50', 'Paredz iespēju anulēt termiņuzturēšanās atļauju ārzemniekam, kurš viena kalendāra gada laikā izdarījis trīs administratīvos pārkāpumus sabiedriskās kārtības, pārvaldes vai ceļu satiksmes jomā.', '1136/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1136/Lp14', 'Imigrācija', 15);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (42, NULL, 'Grozījumi Ķīmisko vielu likumā (1273/Lp14), 1.lasījums', '2026-03-26', '16:21:39', 84, 0, 0, 6, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/7CEBB505429CA3DAC2258DC700107A8A?OpenDocument', '2026-04-05 16:39:52', 'Daļa no vides likumu paketes — pārskata Ķīmisko vielu likumā noteiktās iestāžu kompetences saistībā ar Enerģētikas un vides aģentūras pievienošanu Valsts vides dienestam, optimizējot administratīvo procesu un uzraudzības funkcijas.', '1273/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1273/Lp14', 'Vide', 19);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (46, NULL, 'Grozījums Valsts aizsardzības finansēšanas likumā (1242/Lp14), 1.lasījums', '2026-03-26', '16:15:44', 83, 0, 0, 9, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/A5094FACC3B8C69CC2258DC700107A57?OpenDocument', '2026-04-05 16:39:55', 'Paaugstina valsts aizsardzības finansējuma mērķi no 3% līdz 5% no IKP, sākot ar 2027. gadu, lai paātrinātu Nacionālo bruņoto spēku attīstību saistībā ar ģeopolitiskajām izmaiņām pēc Krievijas iebrukuma Ukrainā.', '1242/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1242/Lp14', 'Aizsardzība un drošība', 23);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (48, NULL, 'Grozījumi Kredītiestāžu likumā (1165/Lp14), 2.lasījums', '2026-03-26', '15:01:11', 86, 4, 0, 1, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/AE5B38151FA10F3BC2258DC700107A3A?OpenDocument', '2026-04-05 16:39:57', 'Transponē ES Direktīvu 2024/1619, nosakot kredītiestādēm papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, uzlabojot administratīvo pasākumu piemērošanas mehānismus un nodrošinot efektīvāku uzraudzību.', '1165/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1165/Lp14', 'Valsts pārvalde', 25);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (49, NULL, 'Grozījumi Ieguldījumu brokeru sabiedrību likumā (1163/Lp14), 2.lasījums', '2026-03-26', '15:38:42', 70, 4, 0, 4, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/B0D07835326BF8EFC2258DC700107A42?OpenDocument', '2026-04-05 16:39:57', 'Transponē ES Direktīvu 2024/1619 un Direktīvu 2019/2034, nosakot ieguldījumu brokeru sabiedrībām papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, kā arī kapitāla un likviditātes pietiekamības novērtēšanu.', '1163/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1163/Lp14', 'Valsts pārvalde', 26);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (50, NULL, 'Grozījumi Sugu un biotopu aizsardzības likumā (1277/Lp14), 1.lasījums', '2026-03-26', '16:26:09', 85, 0, 0, 4, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BB02128AA77F8D0DC2258DC700107AB5?OpenDocument', '2026-04-05 16:39:58', 'Pēc Enerģētikas un vides aģentūras likvidēšanas un pievienošanas Valsts vides dienestam, nosaka Dabas aizsardzības pārvaldes ģenerāldirektoru kā atbildīgo institūciju apstrīdēto lēmumu sugu introdukcijas jomā pārskatīšanai.', '1277/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1277/Lp14', 'Vide', 27);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (51, NULL, 'Grozījumi Sociālā uzņēmuma likumā (1097/Lp14), 3.lasījums', '2026-03-26', '13:54:25', 86, 0, 0, 1, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BB879E1A9F539FB2C2258DC7001079F3?OpenDocument', '2026-04-05 16:39:59', 'Pilnveido sociālo uzņēmumu regulējumu — pagarina pārskatu iesniegšanas periodu no 2 līdz 3 gadiem, paplašina dividenžu sadales iespējas līdz 50% no peļņas, precizē uzraudzības un ziedojumu nodokļu normas.', '1097/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1097/Lp14', 'Sociālā politika', 28);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (53, NULL, 'Grozījumi Ceļu satiksmes likumā (1283/Lp14), nodošana komisijām', '2026-03-26', '10:23:32', 84, 4, 0, 5, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/D1795CF4EDB5F667C2258DC700107986?OpenDocument', '2026-04-05 16:40:00', 'Deputātu (Rokpelnis, Brigmanis, Bērziņš, Burovs, Ceļapīters) ierosinātie grozījumi Ceļu satiksmes likumā, nodoti Tautsaimniecības un Aizsardzības komisijām izskatīšanai.', '1283/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1283/Lp14', 'Transports', 29);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (55, NULL, 'Grozījums Valsts aizsardzības finansēšanas likumā (1242/Lp14), 2.lasījums, steidzams', '2026-03-26', '16:16:11', 80, 0, 0, 12, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/DEE4A3E289BE0ADFC2258DC700107A6B?OpenDocument', '2026-04-05 16:40:01', 'Paaugstina valsts aizsardzības finansējuma mērķi no 3% līdz 5% no IKP, sākot ar 2027. gadu, lai paātrinātu Nacionālo bruņoto spēku attīstību saistībā ar ģeopolitiskajām izmaiņām pēc Krievijas iebrukuma Ukrainā.', '1242/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1242/Lp14', 'Aizsardzība un drošība', 23);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (56, NULL, 'Grozījums Saeimas vēlēšanu likumā (1288/Lp14), 2.lasījums', '2026-03-26', '09:58:28', 93, 0, 0, 0, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E0AE6C695FD53521C2258DC70010795A?OpenDocument', '2026-04-05 16:40:02', 'Nosaka, ka 2026. gada Saeimas vēlēšanās balsu skaitīšana notiek manuāli, reaģējot uz Eiropas Prokuratūras informāciju par iespējamiem pārkāpumiem IT iepirkumos un to iespējamo ietekmi uz vēlēšanu procesu.', '1288/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1288/Lp14', 'Vēlēšanas', 1);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (57, NULL, 'Grozījumi Imigrācijas likumā (1180/Lp14), 2.lasījums', '2026-03-26', '14:48:57', 79, 8, 1, 2, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E0E2275BD9DD2B9AC2258DC700107A11?OpenDocument', '2026-04-05 16:40:03', 'Transponē ES Direktīvu 2024/1233 par vienotu pieteikšanās procedūru trešo valstu valstspiederīgo uzturēšanās un darba atļaujām, kā arī ievieš papildu regulējumu ilgtermiņa vīzu pieteikumu deleģēšanai ārpakalpojumu sniedzējiem.', '1180/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1180/Lp14', 'Imigrācija', 31);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (58, NULL, 'Grozījumi Gaisa kuģu pasažieru datu apstrādes likumā (1072/Lp14), 3.lasījums', '2026-03-26', '13:49:39', 80, 3, 0, 4, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E2CE7526F6A766A0C2258DC7001079DB?OpenDocument', '2026-04-05 16:40:04', 'Ievieš uz riska novērtējumu balstītu pieeju gaisa kuģu pasažieru datu glabāšanai -- valsts drošības nolūkiem datus glabā 5 gadus, bet terorisma/smagu noziegumu novēršanai ES iekšējiem un ārējiem reisiem -- 6 mēnešus ar iespēju pagarināt. Izslēdz epidemioloģisko datu apstrādes mērķi un paplašina reģistru salīdzināšanas loku (izraidīto personu, izceļošanas liegumu reģistri).', '1072/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1072/Lp14', 'Valsts pārvalde', 32);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (60, NULL, 'Grozījumi Zinātniskās darbības likumā (1154/Lp14), 3.lasījums', '2026-03-26', '13:48:47', 84, 0, 0, 3, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E6C57C427736CA6AC2258DC7001079D9?OpenDocument', '2026-04-05 16:40:05', 'Nosaka kartību jaunizveidotu valsts zinātnisko institūtu (atvasinātu publisku personu) pārvaldībai pēc reorganizācijas -- direktora pienākumu izpildītāja iecelšanu, pilnsapulces sasaukšanu un reģistrāciju. Izslēdz no likuma FEI, BMC un OSI nosaukumus saistībā ar to konsolidāciju EDI un jaunā Nacionālā pētniecības un inovāciju institūta izveidošanu.', '1154/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1154/Lp14', 'Valsts pārvalde', 33);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (61, NULL, 'Grozījumi Latvijas Bankas likumā (1164/Lp14), 2.lasījums', '2026-03-26', '15:34:34', 57, 3, 0, 10, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/EAB4589DF7DE1193C2258DC700107A40?OpenDocument', '2026-04-05 16:40:06', 'Paplašina Latvijas Bankas padomes locekļu kvalifikācijas prasības (pieļauj arī bakalaura grādu ar starptautisku sertifikātu), ievieš interešu konflikta novēršanas pilnvaras, precizē statistisko datu apstrādes tiesības un administratīvo sankciju piemērošanas termiņus finanšu tirgus uzraudzībā.', '1164/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1164/Lp14', 'Budžets un finanses', 34);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (62, NULL, 'Grozījums Lauksaimniecības un lauku attīstības likumā (1248/Lp14), 1.lasījums', '2026-03-26', '15:50:04', 76, 4, 0, 5, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/EC046A9A89F640E5C2258DC700107A53?OpenDocument', '2026-04-05 16:40:06', 'Pagarina Krievijas un Baltkrievijas lauksaimniecības un lopbarības produktu importa aizliegumu par vienu gadu — no 2026. gada 1. jūlija līdz 2027. gada 1. jūlijam.', '1248/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1248/Lp14', 'Lauksaimniecība', 35);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (63, NULL, 'Grozījumi Saeimas vēlēšanu likumā (1279/Lp14), nodošana komisijām', '2026-03-26', '10:10:32', 37, 18, 30, 4, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/EF48F5BA1844E681C2258DC700107982?OpenDocument', '2026-04-05 16:40:07', 'Paredz pagarināt vēlēšanu zīmju uzglabāšanas termiņu līdz tiesas nolēmuma spēkā stāšanās dienai un noteikt manuālu balsu skaitīšanu visos 2026. gada Saeimas vēlēšanu iecirkņos bez tehnisku palīglīdzekļu starpniecības.', '1279/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1279/Lp14', 'Vēlēšanas', 36);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (64, NULL, 'Grozījumi Farmācijas likumā (1185/Lp14), 2.lasījums', '2026-03-26', '14:35:40', 82, 0, 0, 5, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/F720948B5736A3E1C2258DC700107A0D?OpenDocument', '2026-04-05 16:40:07', 'Ievieš veterinārās e-veselības informācijas sistēmu un veterināro zāļu reģistra sistēmu, nosaka Pārtikas drošības institūta BIOR lomu veterināro zāļu kontrolē, kā arī regulējumu par cilvēku zāļu lietošanu dzīvniekiem un antimikrobiālās rezistences mazināšanu.', '1185/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1185/Lp14', 'Veselības aprūpe', 37);
