INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (107, NULL, 'Grozījumi Imigrācijas likumā (1180/Lp14), 3.lasījums', '2026-04-23', '13:48:48', 72, 4, 0, 4, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/23592D639C818B76C2258DE3000AFAD4?OpenDocument', '2026-04-26 08:04:42', 'Pārņem ES direktīvu 2024/1233 par vienotu uzturēšanās un darba atļauju trešo valstu valstspiederīgajiem un precizē Imigrācijas likuma normas par vīzu izsniegšanu, dokumentu pieņemšanu (atļaujot deleģēt ārpakalpojumu sniedzējiem) un termiņuzturēšanās atļauju anulēšanu. Iesniedzējs - Ministru kabinets (IeM).', NULL, NULL, 'Imigrācija', 31);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (110, NULL, 'Grozījumi Kredītiestāžu likumā (1263/Lp14), 1.lasījums', '2026-04-23', '13:58:01', 73, 0, 1, 4, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/2E099DFC88037AECC2258DE3000AFAF5?OpenDocument', '2026-04-26 08:04:50', 'Maksātnespējas kontroles dienesta likvidēšanas pakešakts: aizvieto Kredītiestāžu likumā atsauces uz Maksātnespējas kontroles dienestu ar Tieslietu ministriju (administratoru uzraudzības kontekstā) vai Tiesu administrāciju (darbinieku prasījumu garantiju fonda kontekstā). Iesniedzējs - Ministru kabinets (TM); spēkā stāsies 2026. gada 1. oktobrī.', NULL, NULL, 'Valsts pārvalde', 97);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (115, NULL, 'Par Saeimas deputātes Svetlanas Čulkovas atsaukšanu no Parlamentārās izmeklēšanas komisijas par problēmām nacionālā un Eiropas Savienības līmeņa imigrācijas regulējumā un izpildinstitūciju darbā, kas izraisa trešo valstu pilsoņu ... (970/Lm14)', '2026-04-23', '10:22:38', 91, 0, 0, 3, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/692B7F017B2E747FC2258DE3000AFA93?OpenDocument', '2026-04-26 08:05:03', 'Atsauc Saeimas deputāti Svetlanu Čulkovu (Stabilitātei) no Parlamentārās izmeklēšanas komisijas par problēmām imigrācijas regulējumā un izpildinstitūciju darbā.', NULL, NULL, 'Imigrācija', 100);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (121, NULL, 'Grozījumi Zinātniskās darbības likumā (1310/Lp14), 1.lasījums', '2026-04-23', '14:08:38', 80, 0, 0, 2, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/A458493589F33815C2258DE3000AFB20?OpenDocument', '2026-04-26 08:05:21', 'Ievieš pētniecības karjeras ietvaru (četri posmi: zinātniskais asistents, pētnieks, vadošais pētnieks, pētniecības profesors) un pētniecības tenūras modeli ar trim pakāpēm zinātniskajos institūtos. Veido jaunu amatu kategoriju ''pētnieks ar praktisko kompetenci'' (5+ gadu nozares pieredze bez doktora grāda) un saskaņo terminoloģiju ar Augstskolu likumu. Daļa no MK akadēmiskās karjeras reformas paketes (1309/1310/1311); iesniedzējs - IZM.', NULL, NULL, 'Valsts pārvalde', 105);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (124, NULL, 'Grozījumi Profesionālās izglītības likumā (1311/Lp14), 1.lasījums', '2026-04-23', '14:10:16', 77, 0, 0, 4, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/BEA7253489F12069C2258DE3000AFB24?OpenDocument', '2026-04-26 08:05:29', 'Daļa no MK akadēmiskās karjeras reformas paketes - saskaņo Profesionālās izglītības likuma normas par koledžu akadēmisko personālu ar Augstskolu likuma jauno regulējumu, aizstājot atsauces uz ''ievēlēšanu'' ar ''darbā pieņemšanu'' un nosakot, ka koledžu akadēmiskā personāla atlasi un novērtēšanu regulē Augstskolu likums. Iesniedzējs - IZM; spēkā 2026. gada 1. decembrī.', NULL, NULL, 'Izglītība', 106);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (140, NULL, 'Grozījumi Farmācijas likumā (1185/Lp14), 3.lasījums', '2026-04-30', '11:09:50', 82, 0, 0, 5, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=00a8909b-a095-4bb2-8770-52e387c42c9e', '2026-04-30 21:43:37', 'Farmācijas likuma 3. lasījums — pieņemts vienprātīgi (82/0/0). Pakešakts virzīts kopā ar Maksātnespējas kontroles dienesta likvidēšanu un saistīto institucionālo pārstrukturēšanu.', '1185/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1185/Lp14', 'Veselības aprūpe', 37);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (144, NULL, 'Par ministrijas publiskajiem iepirkumiem informācijas tehnoloģiju jomā (121/P14)', '2026-04-30', '10:08:20', 41, 48, 0, 1, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=0fcf76a6-6405-4329-816b-65b1ff72bd69', '2026-04-30 21:43:37', 'LPV iesniegtais paziņojuma projekts par valdības ministriju IT iepirkumiem (caurspīdīgums un izmaksu pārbaudes). Saeima noraidīja (par=41, pret=48) — koalīcija nepieņēma opozīcijas formulējumu par ministrijas atbildību.', '121/P14', 'https://titania.saeima.lv/LIVS14/saeimalivs_lmp.nsf/webSasaiste?OpenView&restricttocategory=121/P14', 'Valsts pārvalde', 142);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (145, NULL, 'Par atbalstu 1. tipa diabēta pacientiem (954/Lm14)', '2026-04-30', '14:43:11', 88, 0, 0, 2, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=1bc78ac4-957b-44da-aadc-fdc8a489fe88', '2026-04-30 21:43:37', 'Vienprātīgs Saeimas paziņojums (88/0/0) par atbalstu 1. tipa diabēta pacientiem — uzdod valdībai uzlabot kompensējamo medikamentu un medicīnisko līdzekļu pieejamību.', '954/Lm14', 'https://titania.saeima.lv/LIVS14/saeimalivs_lmp.nsf/webSasaiste?OpenView&restricttocategory=954/Lm14', 'Valsts pārvalde', 151);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (148, NULL, 'Grozījumi Sabiedrisko elektronisko plašsaziņas līdzekļu un to pārvaldības likumā (1334/Lp14), nodošana komisijām', '2026-04-30', '10:25:18', 69, 4, 0, 16, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=377bb8c0-2b7f-488c-b829-56ec895b092d', '2026-04-30 21:43:37', 'Grozījumi Sabiedrisko elektronisko plašsaziņas līdzekļu likumā nodoti komisijām (par=69, pret=4). Iesniedzējs — Ministru kabinets.', '1334/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1334/Lp14', 'Degviela un enerģētika', 156);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (153, NULL, 'Grozījumi Dzīvokļa īpašuma likumā (1153/Lp14), 3.lasījums', '2026-04-30', '11:07:20', 77, 0, 0, 6, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=594fbaf0-86ee-48d2-baf7-54b0b0d1ae44', '2026-04-30 21:43:37', 'Grozījumu Dzīvokļa īpašuma likumā 3. lasījums — vienprātīgi pieņemts (77/0/0). Maksātnespējas kontroles dienesta likvidēšanas pakešakta daļa.', '1153/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1153/Lp14', 'Valsts pārvalde', 7);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (155, NULL, 'Grozījumi Valsts fondēto pensiju likumā (1322/Lp14), nodošana komisijām', '2026-04-30', '09:20:50', 47, 8, 32, 0, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=65838d69-51d4-406c-a9ab-1bd674e1ce20', '2026-04-30 21:43:37', 'NA deputātu (Mitrevics, Grasbergs, Puntulis, Vitenbergs, Butāns, Indriksone) iniciēts grozījums Valsts fondēto pensiju likumā nodots komisijām (par=47, pret=8, atturas=32). Liels atturas-vairākums (32) signalizē par koalīcijas iekšējām domstarpībām par 2. pensiju līmeņa virzību.', '1322/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1322/Lp14', 'Sociālā politika', 124);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (170, NULL, 'Grozījumi Publiskas personas kapitāla daļu un kapitālsabiedrību pārvaldības likumā (1105/Lp14), 2.lasījums', '2026-04-30', '14:04:04', 83, 1, 1, 2, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=d265c8f8-f476-4dda-a16d-32086c667823', '2026-04-30 21:43:37', 'Grozījumu Publiskas personas kapitāla daļu un kapitālsabiedrību pārvaldības likumā 2. lasījums — pieņemts (83/1/1). Apjomīgs likumprojekts par valsts un pašvaldību kapitālsabiedrību pārvaldību.', '1105/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1105/Lp14', 'Valsts pārvalde', 150);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (174, NULL, 'Grozījumi Izglītības likumā (1317/Lp14), 1.lasījums', '2026-04-30', '14:09:42', 86, 0, 0, 2, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=f92f6e4e-5496-4abf-aeaa-840033ce86c1', '2026-04-30 21:43:38', 'Izglītības, kultūras un zinātnes komisijas izstrādātais grozījums Izglītības likumā 1. lasījumā vienprātīgi pieņemts (86/0/0). Stiprina pedagogu profesionālo autonomiju (tiesības patstāvīgi izvēlēties mācību metodes), precizē vecāku tiesības caur izglītības iestādes padomi un ievieš kārtību domstarpību risināšanai starp pedagogu un ģimeni.', '1317/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1317/Lp14', 'Izglītība', 119);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (178, NULL, 'Par Ministru kabineta rīkojuma projektu Par valsts nekustamā īpašuma Alksnāja ielā 9, Rīgā, pārdošanu (26-TA-109) (130/P14)', '2026-05-14', '11:43:15', 30, 41, 1, 19, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/0C160E52D417AD4FC2258DF700345AB1?OpenDocument', '2026-05-15 13:15:17', 'NA frakcijas (J.Vitenbergs, A.Butāns, U.Mitrevics u.c., 10 deputāti) pieprasījums izglītības un zinātnes ministrei D.Melbārdei (NA — savas frakcijas ministrei) par MK rīkojuma projektu Nr. 26-TA-109 — IZM plāno pārdot Latvijas Sporta muzeja ēku Vecrīgā, Alksnāja ielā 9, lai segtu IZM budžeta iztrūkumu, paredzot muzeja pārcelšanu uz komandu sporta spēļu zāli un saglabājot esošās telpas vēl 3 gadus. NA iebilst pret neapspriesto lēmumu un ēkas pārdošanas vajadzību. Saeima pieprasījumu noraidīja (30/41/1).', NULL, NULL, 'Valsts pārvalde', 170);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (182, NULL, 'Grozījumi Ieguldījumu brokeru sabiedrību likumā (1163/Lp14), 3.lasījums', '2026-05-14', '12:19:15', 82, 4, 0, 11, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/523AE88468CA49B3C2258DF700345AE2?OpenDocument', '2026-05-15 13:15:30', 'Transponē ES Direktīvu 2024/1619 un Direktīvu 2019/2034, nosakot ieguldījumu brokeru sabiedrībām papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, kā arī kapitāla un likviditātes pietiekamības novērtēšanu.', NULL, NULL, 'Valsts pārvalde', 26);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (192, NULL, 'Grozījumi Latvijas Bankas likumā (1164/Lp14), 3.lasījums', '2026-05-14', '12:18:20', 80, 4, 0, 12, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/E5EC8D50CAF4D842C2258DF700345ADF?OpenDocument', '2026-05-15 13:16:01', 'Paplašina Latvijas Bankas padomes locekļu kvalifikācijas prasības (pieļauj arī bakalaura grādu ar starptautisku sertifikātu), ievieš interešu konflikta novēršanas pilnvaras, precizē statistisko datu apstrādes tiesības un administratīvo sankciju piemērošanas termiņus finanšu tirgus uzraudzībā.', NULL, NULL, 'Budžets un finanses', 34);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (193, NULL, 'Grozījumi Kredītiestāžu likumā (1165/Lp14), 3.lasījums', '2026-05-14', '12:16:24', 80, 4, 0, 11, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/EB3EBC09FCC0A56DC2258DF700345ACD?OpenDocument', '2026-05-15 13:16:04', 'Transponē ES Direktīvu 2024/1619, nosakot kredītiestādēm papildu prasības attiecībā uz vides, sociālo un pārvaldības risku noturību, uzlabojot administratīvo pasākumu piemērošanas mehānismus un nodrošinot efektīvāku uzraudzību.', NULL, NULL, 'Valsts pārvalde', 25);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (196, NULL, 'Grozījumi Ceļu satiksmes likumā (1286/Lp14), 2.lasījums, steidzams', '2026-05-14', '16:00:44', 83, 0, 0, 3, 'Pieņemts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/Voting?ReadForm&parentID=31e8ed7a-4756-4a16-b2a9-56338bdb6b10', '2026-05-16 09:45:50', 'Grozījumu Ceļu satiksmes likumā 2. lasījums (steidzams) — vienprātīgi pieņemts (83/0/0). Aktualizē militārās tehnikas, militārā transportlīdzekļa un militārā transportlīdzekļa piekabes definīcijas; izskatīts 21 priekšlikums. Priekšlikums Nr.1 (Butāna/Vitenberga priekšlikums par autovadītāju apmācību tikai latviešu un ES/EEZ valodās) — balsots atsevišķi pirms tam un noraidīts (sk. balsojumu 14:54).', NULL, NULL, 'Transports', 88);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (197, NULL, 'Par priekšlikumu Nr.1 (deputāti A.Butāns, J.Vitenbergs) — Grozījumi Ceļu satiksmes likumā (1286/Lp14), 2.lasījums, steidzams. Priekšlikums papildināt likuma 4. pantu ar (5)³ daļu: transportlīdzekļu vadītāju apmācība un eksāmeni notiek valsts valodā; CSDD tiesības nodrošināt arī ES vai EEZ dalībvalstu oficiālajās valodās. Komisijas atzinums: Neatbalstīts.', '2026-05-14', '14:54:02', 23, 22, 37, 8, 'Noraidīts', 'https://titania.saeima.lv/saeimalivs14.nsf/0/6A761C6C00612794C2258DF6004A0E09?OpenDocument', '2026-05-16 10:07:03', 'Priekšlikums Nr.1 Grozījumiem Ceļu satiksmes likumā (1286/Lp14) — deputātu A.Butāna un J.Vitenberga (NA) ierosinājums: transportlīdzekļu vadītāju apmācība un eksāmeni notiek valsts valodā; CSDD drīkst piedāvāt arī ES vai EEZ dalībvalstu oficiālajās valodās. Praktiski izslēgtu krievu valodu (kas nav ES/EEZ valoda). Komisija (vad. K.Briškens, PRO) neatbalstīja; Saeima noraidīja (par 23, pret 22, atturas 37). Valodas politikas grozījums, iekļauts militārās tehnikas grozījumu likumprojektā.', '1286/Lp14', 'https://titania.saeima.lv/livs14/saeimalivs14.nsf/0/6A761C6C00612794C2258DF6004A0E09/$file/1286_2.pdf', 'Valodu politika', 88);
INSERT INTO saeima_votes (id, agenda_item_id, motif, vote_date, vote_time, total_par, total_pret, total_atturas, total_nebalso, result, url, created_at, summary, document_nr, document_url, topic, bill_id) VALUES (207, NULL, 'Grozījums Saeimas vēlēšanu likumā (1358/Lp14), nodošana komisijām', '2026-05-21', '12:05:00', 28, 19, 30, 11, 'Noraidīts', 'https://titania.saeima.lv/LIVS14/SaeimaLIVS2_DK.nsf/0/433327D6910D4138C2258DFE00405080?OpenDocument', '2026-05-26 08:56:11', 'LPV frakcijas (Krištopans, Armaņeva, Šlesers, Liepiņa, Stobova) ierosinātais Saeimas vēlēšanu likuma grozījums noraidīts nodošanā komisijām (28:19, 30 atturas) — koalīcija bloķē vēlēšanu sistēmas izmaiņu iniciatīvu.', '1358/Lp14', 'https://titania.saeima.lv/LIVS14/saeimalivs14.nsf/webSasaiste?OpenView&restricttocategory=1358/Lp14', 'Vēlēšanas', 181);
